function ModuleCard({ module, onNavigate, isMobile }) {
  const m = moduleCards.find(x => x.id === module)
  if (!m) return null
  return (
    <button onClick={() => onNavigate(m.id)}
      style={{ background: 'white', border: '1px solid #f1f5f9', borderRadius: isMobile ? '12px' : '14px', padding: isMobile ? '10px' : '14px', cursor: 'pointer', textAlign: isMobile ? 'center' : 'left', transition: 'box-shadow 0.2s' }}
      onMouseEnter={e => e.currentTarget.style.boxShadow = '0 4px 16px rgba(0,0,0,0.08)'}
      onMouseLeave={e => e.currentTarget.style.boxShadow = 'none'}>
      <div style={{ width: isMobile ? '32px' : '38px', height: isMobile ? '32px' : '38px', borderRadius: '10px', background: m.color, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: isMobile ? '16px' : '18px', marginBottom: isMobile ? '6px' : '10px', ...(isMobile ? { margin: '0 auto 6px' } : {}) }}>
        {m.emoji}
      </div>
      <div style={{ fontWeight: '600', color: '#0f172a', fontSize: isMobile ? '11px' : '13px', marginBottom: isMobile ? '0' : '3px' }}>{m.name}</div>
      {!isMobile && <div style={{ color: '#94a3b8', fontSize: '11px' }}>{m.desc}</div>}
    </button>
  )
}

function Dashboard({ onNavigate, user }) {
  const days = ['søndag','mandag','tirsdag','onsdag','torsdag','fredag','lørdag']
  const months = ['januar','februar','mars','april','mai','juni','juli','august','september','oktober','november','desember']
  const d = new Date()
  const dateStr = `${days[d.getDay()]} ${d.getDate()}. ${months[d.getMonth()]} ${d.getFullYear()}`
  const { displayName } = useAuth()
  const { unread } = useNotif()
  const firstName = displayName

  // Nøkkeltall — alltid lukket som default
  const [showStats, setShowStats] = useState(false)
  const [stats, setStats] = useState(null)
  const [loadingStats, setLoadingStats] = useState(false)

  const loadStats = async () => {
    if (stats) { setShowStats(true); return } // Allerede lastet
    setLoadingStats(true)
    try {
      const now = new Date()
      const weekStart = new Date(now)
      weekStart.setDate(now.getDate() - now.getDay() + 1)
      weekStart.setHours(0,0,0,0)

      const [projRes, avvikRes, fakturaRes, timerRes] = await Promise.all([
        supabase.from('projects').select('id, status').then(r => r.data || []),
        supabase.from('deviations').select('id, status').then(r => r.data || []),
        supabase.from('invoices').select('id, status, due_date').then(r => r.data || []),
        supabase.from('timesheets').select('id, hours, date').gte('date', weekStart.toISOString().split('T')[0]).then(r => r.data || []),
      ])

      const activeProjects = projRes.filter(p => p.status === 'aktiv').length
      const openAvvik = avvikRes.filter(a => a.status === 'Åpen' || a.status === 'Under behandling').length
      const overdueInvoices = fakturaRes.filter(f => f.status === 'Sendt' && f.due_date && new Date(f.due_date) < now).length
      const weekHours = timerRes.reduce((sum, t) => sum + (parseFloat(t.hours) || 0), 0)

      setStats({ activeProjects, openAvvik, overdueInvoices, weekHours, unreadNotifs: unread })
    } catch(e) { console.error('Dashboard stats error:', e) }
    finally { setLoadingStats(false); setShowStats(true) }
  }

  const toggleStats = () => {
    if (showStats) { setShowStats(false) }
    else { loadStats() }
  }

  // Responsiv
  const [ww, setWw] = useState(typeof window !== 'undefined' ? window.innerWidth : 1200)
  React.useEffect(() => { const h = () => setWw(window.innerWidth); window.addEventListener('resize', h); return () => window.removeEventListener('resize', h) }, [])
  const mob = ww < 768

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif' }}>
      <div style={{ background: 'white', borderBottom: '1px solid #e2e8f0', padding: mob ? '16px' : '24px 32px' }}>
        <div style={{ display: 'flex', alignItems: mob ? 'flex-start' : 'center', justifyContent: 'space-between', flexDirection: mob ? 'column' : 'row', gap: mob ? '10px' : '0' }}>
          <div>
            <h1 style={{ fontSize: mob ? '18px' : '24px', fontWeight: 'bold', color: '#0f172a', margin: 0 }}>Velkommen, {firstName}</h1>
            <p style={{ color: '#64748b', marginTop: '4px', fontSize: mob ? '12px' : '14px', marginBottom: 0 }}>{dateStr}</p>
          </div>
          <button onClick={toggleStats}
            style={{ padding: mob ? '8px 12px' : '8px 16px', borderRadius: '10px', border: '1px solid #e2e8f0', background: showStats ? '#f8fafc' : 'white', cursor: 'pointer', fontSize: mob ? '12px' : '13px', fontWeight: '600', color: '#475569', display: 'flex', alignItems: 'center', gap: '6px', alignSelf: mob ? 'stretch' : 'auto', justifyContent: 'center' }}>
            {showStats ? '▲ Skjul nøkkeltall' : '▼ Vis nøkkeltall'}
          </button>
        </div>

        {/* Nøkkeltall-kort */}
        {showStats && (
          <div style={{ marginTop: mob ? '12px' : '20px', display: 'grid', gridTemplateColumns: mob ? 'repeat(2, 1fr)' : 'repeat(5, 1fr)', gap: mob ? '8px' : '12px' }}>
            {loadingStats || !stats ? (
              <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '20px', color: '#94a3b8', fontSize: '14px' }}>Laster nøkkeltall...</div>
            ) : [
              { label: 'Aktive prosjekter', value: stats.activeProjects, icon: '🏗️', color: '#059669', bg: '#ecfdf5', onClick: () => onNavigate('prosjekter') },
              { label: 'Åpne avvik', value: stats.openAvvik, icon: '⚠️', color: stats.openAvvik > 0 ? '#dc2626' : '#059669', bg: stats.openAvvik > 0 ? '#fef2f2' : '#ecfdf5', onClick: () => onNavigate('avvik') },
              { label: 'Forfalt faktura', value: stats.overdueInvoices, icon: '🧾', color: stats.overdueInvoices > 0 ? '#dc2626' : '#059669', bg: stats.overdueInvoices > 0 ? '#fef2f2' : '#ecfdf5', onClick: () => onNavigate('faktura') },
              { label: 'Timer denne uken', value: Math.round(stats.weekHours * 10) / 10, icon: '⏱️', color: '#2563eb', bg: '#eff6ff', onClick: () => onNavigate('timelister') },
              { label: 'Uleste varsler', value: unread, icon: '🔔', color: unread > 0 ? '#d97706' : '#059669', bg: unread > 0 ? '#fffbeb' : '#ecfdf5', onClick: () => onNavigate('varsler') },
            ].map((stat, i) => (
              <button key={i} onClick={stat.onClick}
                style={{ background: 'white', borderRadius: mob ? '12px' : '14px', border: '1px solid #f1f5f9', padding: mob ? '12px' : '16px', cursor: 'pointer', textAlign: 'left', transition: 'box-shadow 0.15s' }}
                onMouseEnter={e => e.currentTarget.style.boxShadow = '0 4px 16px rgba(0,0,0,0.08)'}
                onMouseLeave={e => e.currentTarget.style.boxShadow = 'none'}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: mob ? '6px' : '10px' }}>
                  <div style={{ width: mob ? '30px' : '36px', height: mob ? '30px' : '36px', borderRadius: '10px', background: stat.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: mob ? '15px' : '18px' }}>{stat.icon}</div>
                  {typeof stat.value === 'number' && stat.value > 0 && stat.color === '#dc2626' && (
                    <span style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#dc2626' }} />
                  )}
                </div>
                <div style={{ fontSize: mob ? '20px' : '26px', fontWeight: '800', color: stat.color, marginBottom: '2px' }}>{stat.value}</div>
                <div style={{ fontSize: mob ? '11px' : '12px', color: '#64748b', fontWeight: '500' }}>{stat.label}</div>
              </button>
            ))}
          </div>
        )}
      </div>
      <style>{`
        .dashboard-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(150px, 1fr)); gap: 16px; }
        @media (min-width: 1200px) { .dashboard-grid-single { grid-template-columns: repeat(auto-fill, minmax(150px, 1fr)); } }
      `}</style>
      <div style={{ padding: mob ? '16px' : '24px 32px' }}>
        <h2 style={{ fontSize: mob ? '16px' : '18px', fontWeight: '600', color: '#0f172a', marginBottom: mob ? '16px' : '24px', marginTop: 0 }}>Moduler</h2>
        <div style={{ display: 'flex', flexDirection: 'column', gap: mob ? '20px' : '28px' }}>
          {moduleSections.map((section, i) => (
            <div key={i}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: mob ? '10px' : '14px' }}>
                <span style={{ fontSize: mob ? '12px' : '13px', fontWeight: '600', color: '#64748b', letterSpacing: '0.05em' }}>{section.title}</span>
                <div style={{ flex: 1, height: '1px', background: '#e2e8f0' }} />
              </div>
              <div style={{
                display: 'grid',
                gridTemplateColumns: mob ? 'repeat(3, 1fr)' : 'repeat(auto-fill, minmax(130px, 1fr))',
                gap: mob ? '8px' : '12px'
              }}>
                {section.modules.map(id => <ModuleCard key={id} module={id} onNavigate={onNavigate} isMobile={mob} />)}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}


// ─── PROSJEKTER MODULE ────────────────────────────────────────────────────────

const statusConfig = {
  planlagt:  { label: 'Planlagt',  bg: '#eff6ff', color: '#2563eb' },
  aktiv:     { label: 'Aktiv',     bg: '#ecfdf5', color: '#059669' },
  pause:     { label: 'På pause',  bg: '#fffbeb', color: '#d97706' },
  fullfort:  { label: 'Fullført',  bg: '#f1f5f9', color: '#475569' },
  avbrutt:   { label: 'Avbrutt',   bg: '#fef2f2', color: '#dc2626' },
  arkivert:  { label: 'Arkivert',  bg: '#f5f3ff', color: '#7c3aed' },
}

function StatusBadge({ status }) {
  const cfg = statusConfig[status] || { label: status, bg: '#f1f5f9', color: '#475569' }
  return (
    <span style={{ background: cfg.bg, color: cfg.color, padding: '3px 10px', borderRadius: '999px', fontSize: '12px', fontWeight: '600' }}>
      {cfg.label}
    </span>
  )
}

function Modal({ open, onClose, title, children, size }) {
  if (!open) return null
  const maxWidth = size === 'lg' ? '720px' : size === 'xl' ? '900px' : '480px'
  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 100, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '16px' }}>
      <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.4)' }} onClick={onClose} />
      <div style={{ position: 'relative', background: 'white', borderRadius: '20px', width: '100%', maxWidth, maxHeight: '90vh', display: 'flex', flexDirection: 'column', boxShadow: '0 20px 60px rgba(0,0,0,0.2)' }}>
        <div style={{ padding: '20px 24px', borderBottom: '1px solid #f1f5f9', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0 }}>
          <h2 style={{ margin: 0, fontSize: '18px', fontWeight: '700', color: '#0f172a' }}>{title}</h2>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: '22px', cursor: 'pointer', color: '#94a3b8', lineHeight: 1 }}>x</button>
        </div>
        <div style={{ overflowY: 'auto', flex: 1 }}>{children}</div>
      </div>
    </div>
  )
}

function InfoTip({ label, info, align }) {
  const [open, setOpen] = useState(false)
  return (
    <span style={{ position:'relative', display:'inline-flex', alignItems:'center', gap:'2px' }}>
      {label}
      <span onClick={e => { e.stopPropagation(); setOpen(!open) }}
        style={{ display:'inline-flex', alignItems:'center', justifyContent:'center', width:'13px', height:'13px', borderRadius:'50%', background: open ? '#059669' : '#e2e8f0', color: open ? 'white' : '#94a3b8', fontSize:'8px', fontWeight:'800', cursor:'pointer', lineHeight:1, flexShrink:0, userSelect:'none' }}>i</span>
      {open && (
        <>
          <div style={{ position:'fixed', inset:0, zIndex:50 }} onClick={() => setOpen(false)} />
          <div style={{ position:'absolute', top:'100%', [align === 'right' ? 'right' : 'left']:0, marginTop:'4px', background:'#0f172a', color:'white', borderRadius:'8px', padding:'10px 14px', fontSize:'12px', lineHeight:1.5, width:'260px', zIndex:51, boxShadow:'0 8px 24px rgba(0,0,0,0.25)' }}>
            {info}
            <div style={{ position:'absolute', top:'-4px', [align === 'right' ? 'right' : 'left']:'10px', width:'8px', height:'8px', background:'#0f172a', transform:'rotate(45deg)' }} />
          </div>
        </>
      )}
    </span>
  )
}

// ── Gjenbrukbar ansattvelger med dropdown ──
function EmployeeSelect({ value, onChange, placeholder, style, required, allowClear }) {
  const [emps, setEmps] = useState([])
  useEffect(() => {
    supabase.from('employees').select('id, first_name, last_name, email, role, department').order('last_name').then(({ data }) => setEmps(data || []))
  }, [])
  const selStyle = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', cursor:'pointer', ...style }
  return (
    <select value={value || ''} onChange={e => onChange(e.target.value, emps.find(emp => emp.id === e.target.value))} required={required} style={selStyle}>
      <option value="">{placeholder || 'Velg ansatt...'}</option>
      {emps.map(emp => {
        const name = getEmployeeName(emp) || emp.email || 'Uten navn'
        return <option key={emp.id} value={emp.id}>{name}{emp.role ? ` (${emp.role})` : ''}</option>
      })}
    </select>
  )
}

// ── Ansattvelger som setter navn/epost/telefon fra valgt ansatt ──
// Global cache av ansatte — hentes én gang per sesjon for å unngå N fetch-er
const _employeeCache = { data: null, loading: null, subscribers: new Set() }

// Returnerer visningsnavn uansett om ansatt har first_name+last_name eller kombinert name-felt
function getEmployeeName(emp) {
  if (!emp) return ''
  if (emp.first_name || emp.last_name) return `${emp.first_name || ''} ${emp.last_name || ''}`.trim()
  if (emp.name) return emp.name
  return ''
}

function getCachedEmployees() {
  if (_employeeCache.data) return Promise.resolve(_employeeCache.data)
  if (_employeeCache.loading) return _employeeCache.loading
  _employeeCache.loading = supabase.from('employees')
    .select('*')
    .order('last_name', { nullsFirst: false })
    .then(({ data, error }) => {
      if (error) {
        console.error('[EmployeeCache] Feil ved henting av ansatte:', error)
        _employeeCache.data = []
        _employeeCache.loading = null
        _employeeCache.subscribers.forEach(fn => fn([]))
        // Ikke cache tom liste permanent — prøv på nytt neste gang
        setTimeout(() => { _employeeCache.data = null }, 5000)
        return []
      }
      _employeeCache.data = data || []
      _employeeCache.loading = null
      _employeeCache.subscribers.forEach(fn => fn(_employeeCache.data))
      console.log(`[EmployeeCache] Lastet ${_employeeCache.data.length} ansatte`)
      return _employeeCache.data
    })
    .catch(err => {
      console.error('[EmployeeCache] Exception:', err)
      _employeeCache.data = []
      _employeeCache.loading = null
      setTimeout(() => { _employeeCache.data = null }, 5000)
      return []
    })
  return _employeeCache.loading
}

function invalidateEmployeeCache() {
  _employeeCache.data = null
  _employeeCache.loading = null
}

function useEmployees() {
  const [emps, setEmps] = useState(_employeeCache.data || [])
  useEffect(() => {
    let mounted = true
    if (_employeeCache.data) {
      setEmps(_employeeCache.data)
      return
    }
    getCachedEmployees().then(data => { if (mounted) setEmps(data) })
    const sub = (data) => { if (mounted) setEmps(data) }
    _employeeCache.subscribers.add(sub)
    return () => { mounted = false; _employeeCache.subscribers.delete(sub) }
  }, [])
  return emps
}

// EmployeeNameSelect — søkbar nedtrekk for å velge ansatt
// Props:
//   value, onChange — tekstlig navn (free-text fallback)
//   onSelect — kalles med hele ansatt-objektet når bruker velger (inkl. email, phone)
//   valueAsId — hvis true: value tolkes som ansatt-id (UUID) og vises som navn i feltet
//   employees — valgfri liste (ellers bruker intern cache)
//   placeholder, style — UI
function EmployeeNameSelect({ value, onChange, onSelect, placeholder, style, valueAsId, employees: extEmps, allowFreeText = true }) {
  const cachedEmps = useEmployees()
  const emps = extEmps && extEmps.length > 0 ? extEmps : cachedEmps
  const [showDrop, setShowDrop] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [rect, setRect] = useState(null)
  const wrapperRef = React.useRef(null)

  // I id-mode: finn navn fra id
  const displayValue = valueAsId
    ? (() => {
        if (!value) return ''
        const emp = emps.find(e => e.id === value || e.user_id === value)
        return emp ? getEmployeeName(emp) : ''
      })()
    : (value || '')

  const inputVal = showDrop ? searchText : displayValue

  const filtered = emps.filter(emp => {
    const q = (searchText || '').toLowerCase().trim()
    if (!q) return true
    const name = getEmployeeName(emp).toLowerCase()
    const email = (emp.email || '').toLowerCase()
    const phone = (emp.phone || '').toLowerCase()
    const role = (emp.role || '').toLowerCase()
    return name.includes(q) || email.includes(q) || phone.includes(q) || role.includes(q)
  })

  const handleSelect = (emp) => {
    const name = getEmployeeName(emp)
    if (valueAsId) {
      onChange(emp.id)
    } else {
      onChange(name)
    }
    if (onSelect) onSelect(emp)
    setShowDrop(false)
    setSearchText('')
  }

  const openDrop = () => {
    if (wrapperRef.current) {
      const r = wrapperRef.current.getBoundingClientRect()
      setRect({ top: r.bottom + 4, left: r.left, width: r.width })
    }
    setShowDrop(true)
    setSearchText('')
  }

  // Oppdater posisjon ved scroll/resize
  useEffect(() => {
    if (!showDrop) return
    const update = () => {
      if (wrapperRef.current) {
        const r = wrapperRef.current.getBoundingClientRect()
        setRect({ top: r.bottom + 4, left: r.left, width: r.width })
      }
    }
    window.addEventListener('scroll', update, true)
    window.addEventListener('resize', update)
    return () => {
      window.removeEventListener('scroll', update, true)
      window.removeEventListener('resize', update)
    }
  }, [showDrop])

  const selStyle = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', ...style }

  const dropdown = (showDrop && rect) && (
    <div style={{
      position:'fixed',
      top: `${rect.top}px`,
      left: `${rect.left}px`,
      width: `${rect.width}px`,
      background:'white',
      border:'1px solid #e2e8f0',
      borderRadius:'10px',
      boxShadow:'0 8px 24px rgba(0,0,0,0.18)',
      zIndex: 99999,
      maxHeight:'260px',
      overflowY:'auto'
    }}>
      {emps.length === 0 ? (
        <div style={{ padding:'14px', fontSize:'12px', color:'#94a3b8', textAlign:'center' }}>
          {_employeeCache.loading ? 'Laster ansatte...' : 'Ingen ansatte funnet. Se konsollen (F12) for eventuelle feil.'}
        </div>
      ) : (
        <>
          {valueAsId && displayValue && (
            <div onMouseDown={(e) => { e.preventDefault(); onChange(''); setShowDrop(false); setSearchText('') }}
              style={{ padding:'7px 12px', cursor:'pointer', fontSize:'12px', color:'#dc2626', borderBottom:'1px solid #f1f5f9', fontWeight:'600' }}
              onMouseEnter={e => e.currentTarget.style.background='#fef2f2'} onMouseLeave={e => e.currentTarget.style.background='white'}>
              ✕ Fjern valgt
            </div>
          )}
          {filtered.length === 0 ? (
            <div style={{ padding:'12px', fontSize:'12px', color:'#94a3b8', textAlign:'center' }}>
              Ingen treff{searchText ? ` for "${searchText}"` : ''}{allowFreeText && !valueAsId ? ' — skriv fritt' : ''}
            </div>
          ) : filtered.map(emp => {
            const name = getEmployeeName(emp)
            const role = emp.role || ''
            return (
              <div key={emp.id} onMouseDown={(e) => { e.preventDefault(); handleSelect(emp) }}
                style={{ padding:'10px 14px', cursor:'pointer', fontSize:'14px', borderBottom:'1px solid #f8fafc', color:'#0f172a' }}
                onMouseEnter={e => e.currentTarget.style.background='#f0fdf4'} onMouseLeave={e => e.currentTarget.style.background='white'}>
                {name || '(uten navn)'}{role ? ` – ${role}` : ''}
              </div>
            )
          })}
        </>
      )}
    </div>
  )

  return (
    <div ref={wrapperRef} style={{ position:'relative' }}>
      <input
        value={inputVal}
        onChange={e => {
          setSearchText(e.target.value)
          if (!showDrop) openDrop()
          if (!valueAsId && allowFreeText) onChange(e.target.value)
          if (valueAsId && !e.target.value) onChange('')
        }}
        onFocus={openDrop}
        onBlur={() => setTimeout(() => setShowDrop(false), 200)}
        placeholder={placeholder || 'Skriv eller velg ansatt...'}
        style={selStyle} />
      {typeof document !== 'undefined' && dropdown ? createPortal(dropdown, document.body) : null}
    </div>
  )
}

// EmployeeChipPicker — for lister (deltakere, involverte, vitner)
// Viser allerede-valgte som chips + søkefelt for å legge til nye
function EmployeeChipPicker({ values, onChange, placeholder, style }) {
  const emps = useEmployees()
  const [searchInput, setSearchInput] = useState('')
  const [showDrop, setShowDrop] = useState(false)
  const [dropPos, setDropPos] = useState({ top: 0, left: 0, width: 0 })
  const inputRef = React.useRef(null)

  const valuesArr = Array.isArray(values) ? values : (values ? values.split(',').map(s => s.trim()).filter(Boolean) : [])

  const filtered = emps.filter(emp => {
    const name = getEmployeeName(emp)
    if (valuesArr.includes(name)) return false // skjul allerede lagt til
    if (!searchInput) return true
    const q = searchInput.toLowerCase()
    return name.toLowerCase().includes(q) ||
           (emp.email || '').toLowerCase().includes(q) ||
           (emp.phone || '').toLowerCase().includes(q) ||
           (emp.role || '').toLowerCase().includes(q)
  })

  const addPerson = (name) => {
    if (!name || !name.trim()) return
    const clean = name.trim()
    if (valuesArr.includes(clean)) return
    onChange([...valuesArr, clean])
    setSearchInput('')
    setShowDrop(false)
  }

  const removePerson = (idx) => onChange(valuesArr.filter((_, i) => i !== idx))

  const updateDropPos = () => {
    if (!inputRef.current) return
    const r = inputRef.current.getBoundingClientRect()
    setDropPos({ top: r.bottom + 4, left: r.left, width: r.width })
  }

  const openDrop = () => {
    updateDropPos()
    setShowDrop(true)
  }

  useEffect(() => {
    if (!showDrop) return
    const handler = () => updateDropPos()
    window.addEventListener('scroll', handler, true)
    window.addEventListener('resize', handler)
    return () => {
      window.removeEventListener('scroll', handler, true)
      window.removeEventListener('resize', handler)
    }
  }, [showDrop])

  const inpStyle = { flex:1, padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', ...style }

  return (
    <div style={{ position:'relative' }}>
      <div style={{ display:'flex', gap:'8px', marginBottom:valuesArr.length>0?'6px':0 }}>
        <input ref={inputRef} value={searchInput}
          onChange={e => { setSearchInput(e.target.value); openDrop() }}
          onFocus={openDrop}
          onBlur={() => setTimeout(() => setShowDrop(false), 180)}
          onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); addPerson(searchInput) } }}
          placeholder={placeholder || 'Søk eller skriv navn...'}
          style={inpStyle} />
        <button type="button" onClick={() => addPerson(searchInput)} disabled={!searchInput.trim()}
          style={{ padding:'9px 14px', background: searchInput.trim() ? '#f0fdf4' : '#f8fafc', color: searchInput.trim() ? '#059669' : '#cbd5e1', border:'none', borderRadius:'10px', cursor: searchInput.trim() ? 'pointer' : 'not-allowed', fontSize:'13px', fontWeight:'600' }}>+</button>
      </div>

      {valuesArr.length > 0 && (
        <div style={{ display:'flex', flexWrap:'wrap', gap:'6px' }}>
          {valuesArr.map((p, i) => (
            <span key={i} style={{ background:'#f0fdf4', color:'#059669', border:'1px solid #bbf7d0', borderRadius:'999px', padding:'3px 10px', fontSize:'12px', fontWeight:'600', display:'flex', alignItems:'center', gap:'5px' }}>
              {p}
              <button type="button" onClick={() => removePerson(i)} style={{ background:'none', border:'none', cursor:'pointer', color:'#059669', padding:0, fontSize:'13px' }}>×</button>
            </span>
          ))}
        </div>
      )}

      {showDrop && emps.length > 0 && typeof document !== 'undefined' && createPortal(
        <div style={{
          position:'fixed',
          top: `${dropPos.top}px`,
          left: `${dropPos.left}px`,
          width: `${dropPos.width}px`,
          background:'white',
          border:'1px solid #e2e8f0',
          borderRadius:'10px',
          boxShadow:'0 8px 24px rgba(0,0,0,0.18)',
          zIndex: 99999,
          maxHeight:'220px',
          overflowY:'auto'
        }}>
          {filtered.length === 0 ? (
            <div style={{ padding:'12px', fontSize:'12px', color:'#94a3b8', textAlign:'center' }}>
              Ingen treff — trykk + eller Enter for å legge til som fri tekst
            </div>
            ) : filtered.slice(0, 10).map(emp => {
              const name = getEmployeeName(emp)
              const role = emp.role || ''
              return (
                <div key={emp.id} onMouseDown={(e) => { e.preventDefault(); addPerson(name) }}
                  style={{ padding:'10px 14px', cursor:'pointer', fontSize:'14px', borderBottom:'1px solid #f8fafc', color:'#0f172a' }}
                  onMouseEnter={e => e.currentTarget.style.background='#f0fdf4'} onMouseLeave={e => e.currentTarget.style.background='white'}>
                  {name || '(uten navn)'}{role ? ` – ${role}` : ''}
                </div>
              )
            })}
        </div>,
        document.body
      )}
    </div>
  )
}

// ─── CUSTOMER SELECT ─────────────────────────────────────────────────────
// Søkbar nedtrekk for å velge kunde. Bruker global cache + React Portal.
// Følger samme mønster som EmployeeNameSelect.
// ─────────────────────────────────────────────────────────────────────────

const _customerCache = { data: null, loading: null, subscribers: new Set() }

// Formaterer kunde til visningstekst: "K-0023 · Ola Nordmann"
function formatCustomerLabel(c) {
  if (!c) return ''
  const nr = c.customer_number ? `${c.customer_number} · ` : ''
  return `${nr}${c.name || '(uten navn)'}`
}

// Normaliserer navn for duplikatsjekk: trimmer, collapserer whitespace, lowercaser
function normalizeCustomerName(name) {
  if (!name) return ''
  return name.trim().toLowerCase().replace(/\s+/g, ' ')
}

// Bygger et Set av normaliserte navn som har duplikater blant privatkunder.
// Returnerer et Set for O(1) oppslag senere.
function buildPrivateDuplicateNameSet(customers) {
  const counts = {}
  for (const c of customers) {
    if (c.type !== 'privat') continue
    const key = normalizeCustomerName(c.name)
    if (!key) continue
    counts[key] = (counts[key] || 0) + 1
  }
  const dups = new Set()
  for (const [key, count] of Object.entries(counts)) {
    if (count > 1) dups.add(key)
  }
  return dups
}

function getCachedCustomers() {
  if (_customerCache.data) return Promise.resolve(_customerCache.data)
  if (_customerCache.loading) return _customerCache.loading
  _customerCache.loading = supabase.from('customers')
    .select('*')
    .order('name')
    .then(({ data, error }) => {
      if (error) {
        console.error('[CustomerCache] Feil ved henting av kunder:', error)
        _customerCache.data = []
        _customerCache.loading = null
        _customerCache.subscribers.forEach(fn => fn([]))
        // Ikke cache tom liste permanent — prøv på nytt neste gang
        setTimeout(() => { _customerCache.data = null }, 5000)
        return []
      }
      _customerCache.data = data || []
      _customerCache.loading = null
      _customerCache.subscribers.forEach(fn => fn(_customerCache.data))
      console.log(`[CustomerCache] Lastet ${_customerCache.data.length} kunder`)
      return _customerCache.data
    })
    .catch(err => {
      console.error('[CustomerCache] Exception:', err)
      _customerCache.data = []
      _customerCache.loading = null
      setTimeout(() => { _customerCache.data = null }, 5000)
      return []
    })
  return _customerCache.loading
}

function invalidateCustomerCache() {
  _customerCache.data = null
  _customerCache.loading = null
}

function useCustomers() {
  const [customers, setCustomers] = useState(_customerCache.data || [])
  useEffect(() => {
    let mounted = true
    if (_customerCache.data) {
      setCustomers(_customerCache.data)
      return
    }
    getCachedCustomers().then(data => { if (mounted) setCustomers(data) })
    const sub = (data) => { if (mounted) setCustomers(data) }
    _customerCache.subscribers.add(sub)
    return () => { mounted = false; _customerCache.subscribers.delete(sub) }
  }, [])
  return customers
}

// CustomerSelect — søkbar kundevelger med duplikatadvarsel for privatkunder
// Props:
//   value — customer_id (UUID) når valueAsId=true, ellers tekst (kundenavn)
//   onChange(v) — kalles med ny verdi (id eller navn)
//   onSelect(customer) — kalles med hele kundeobjektet når bruker velger noe
//   valueAsId — om true: value tolkes som customer_id; om false: fritekst
//   allowFreeText — om true: bruker kan skrive inn navn som ikke finnes (default true, kun i non-id modus)
//   filterType — valgfri: vis kun kunder av denne typen (f.eks. 'privat' | 'bedrift' | ['ue','bedrift'])
//   placeholder, style — UI
function CustomerSelect({ value, onChange, onSelect, placeholder, style, valueAsId, allowFreeText = true, filterType }) {
  const allCustomers = useCustomers()
  const [showDrop, setShowDrop] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [rect, setRect] = useState(null)
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [highlightedIndex, setHighlightedIndex] = useState(0)
  const { user } = useAuth()
  const wrapperRef = React.useRef(null)
  const inputRef = React.useRef(null)
  const itemRefs = React.useRef({})

  // Filtrer på type hvis angitt
  const customers = React.useMemo(() => {
    if (!filterType) return allCustomers
    const types = Array.isArray(filterType) ? filterType : [filterType]
    return allCustomers.filter(c => types.includes(c.type))
  }, [allCustomers, filterType])

  // Bygg duplikatnavn-set for privatkunder (for advarsel) — alltid basert på full liste
  const duplicateNames = React.useMemo(
    () => buildPrivateDuplicateNameSet(allCustomers),
    [allCustomers]
  )

  // I id-modus: vis navn/nummer basert på id
  const displayValue = valueAsId
    ? (() => {
        if (!value) return ''
        const c = customers.find(x => x.id === value) || allCustomers.find(x => x.id === value)
        return c ? formatCustomerLabel(c) : ''
      })()
    : (value || '')

  const inputVal = showDrop ? searchText : displayValue

  // Sjekk om valgt kunde er privat med duplikat — vis advarsel over feltet
  const selectedDuplicateWarning = React.useMemo(() => {
    if (!valueAsId || !value) return null
    const c = allCustomers.find(x => x.id === value)
    if (!c || c.type !== 'privat') return null
    const key = normalizeCustomerName(c.name)
    if (!duplicateNames.has(key)) return null
    const siblings = allCustomers.filter(x => x.type === 'privat' && normalizeCustomerName(x.name) === key)
    return {
      count: siblings.length,
      siblings: siblings.map(s => ({
        customer_number: s.customer_number,
        email: s.email,
        phone: s.phone,
        id: s.id,
      }))
    }
  }, [value, valueAsId, allCustomers, duplicateNames])

  const filtered = customers.filter(c => {
    const q = (searchText || '').toLowerCase().trim()
    if (!q) return true
    return (c.name || '').toLowerCase().includes(q) ||
           (c.customer_number || '').toLowerCase().includes(q) ||
           (c.orgnr || '').toLowerCase().includes(q) ||
           (c.email || '').toLowerCase().includes(q) ||
           (c.phone || '').toLowerCase().includes(q)
  })

  // Reset til første treff hver gang søket endres eller dropdown åpnes
  useEffect(() => {
    setHighlightedIndex(0)
  }, [searchText, showDrop])

  // Auto-scroll slik at merket rad alltid er synlig
  useEffect(() => {
    if (!showDrop) return
    const highlighted = filtered[highlightedIndex]
    if (!highlighted) return
    const el = itemRefs.current[highlighted.id]
    if (el && typeof el.scrollIntoView === 'function') {
      el.scrollIntoView({ block: 'nearest', behavior: 'auto' })
    }
  }, [highlightedIndex, showDrop, filtered])

  const handleKeyDown = (e) => {
    if (!showDrop) {
      if (e.key === 'ArrowDown') {
        e.preventDefault()
        openDrop()
      }
      return
    }
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      setHighlightedIndex(i => Math.min(i + 1, Math.max(filtered.length - 1, 0)))
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      setHighlightedIndex(i => Math.max(i - 1, 0))
    } else if (e.key === 'Enter') {
      if (filtered.length > 0) {
        e.preventDefault()
        handleSelect(filtered[highlightedIndex])
      }
    } else if (e.key === 'Escape') {
      e.preventDefault()
      setShowDrop(false)
      setSearchText('')
      if (inputRef.current) inputRef.current.blur()
    }
  }

  const handleSelect = (c) => {
    if (valueAsId) {
      onChange(c.id)
    } else {
      onChange(c.name || '')
    }
    if (onSelect) onSelect(c)
    setShowDrop(false)
    setSearchText('')
  }

  const openDrop = () => {
    if (wrapperRef.current) {
      const r = wrapperRef.current.getBoundingClientRect()
      setRect({ top: r.bottom + 4, left: r.left, width: r.width })
    }
    setShowDrop(true)
    setSearchText('')
  }

  // Oppdater posisjon ved scroll/resize
  useEffect(() => {
    if (!showDrop) return
    const update = () => {
      if (wrapperRef.current) {
        const r = wrapperRef.current.getBoundingClientRect()
        setRect({ top: r.bottom + 4, left: r.left, width: r.width })
      }
    }
    window.addEventListener('scroll', update, true)
    window.addEventListener('resize', update)
    return () => {
      window.removeEventListener('scroll', update, true)
      window.removeEventListener('resize', update)
    }
  }, [showDrop])

  const selStyle = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', ...style }

  const KUNDE_TYPE_LOCAL = { // duplikat for isolasjon — ekte KUNDE_TYPE er definert senere i filen
    bedrift:  { label: 'Bedrift',      emoji: '🏢' },
    privat:   { label: 'Privat',       emoji: '👤' },
    offentlig:{ label: 'Offentlig',    emoji: '🏛️' },
    borettslag:{ label:'Borettslag',   emoji: '🏘️' },
    ue:       { label: 'Underlev.',    emoji: '🤝' },
  }

  const dropdown = (showDrop && rect) && (
    <div style={{
      position:'fixed',
      top: `${rect.top}px`,
      left: `${rect.left}px`,
      width: `${rect.width}px`,
      background:'white',
      border:'1px solid #e2e8f0',
      borderRadius:'10px',
      boxShadow:'0 8px 24px rgba(0,0,0,0.18)',
      zIndex: 99999,
      maxHeight:'300px',
      overflowY:'auto'
    }}>
      {customers.length === 0 ? (
        <div style={{ padding:'14px', fontSize:'12px', color:'#94a3b8', textAlign:'center' }}>
          {_customerCache.loading ? 'Laster kunder...' : 'Ingen kunder funnet. Opprett kunder i Kundeoversikt.'}
        </div>
      ) : (
        <>
          {valueAsId && displayValue && (
            <div onMouseDown={(e) => { e.preventDefault(); onChange(''); setShowDrop(false); setSearchText('') }}
              style={{ padding:'7px 12px', cursor:'pointer', fontSize:'12px', color:'#dc2626', borderBottom:'1px solid #f1f5f9', fontWeight:'600' }}
              onMouseEnter={e => e.currentTarget.style.background='#fef2f2'} onMouseLeave={e => e.currentTarget.style.background='white'}>
              ✕ Fjern valgt
            </div>
          )}
          {filtered.length === 0 ? (
            <div style={{ padding:'12px', fontSize:'12px', color:'#94a3b8', textAlign:'center' }}>
              Ingen treff{searchText ? ` for "${searchText}"` : ''}{allowFreeText && !valueAsId ? ' — skriv fritt' : ''}
            </div>
          ) : filtered.map((c, idx) => {
            const typeCfg = KUNDE_TYPE_LOCAL[c.type] || KUNDE_TYPE_LOCAL.bedrift
            const isDup = c.type === 'privat' && duplicateNames.has(normalizeCustomerName(c.name))
            const isHighlighted = idx === highlightedIndex
            return (
              <div key={c.id}
                ref={el => { if (el) itemRefs.current[c.id] = el; else delete itemRefs.current[c.id] }}
                onMouseDown={(e) => { e.preventDefault(); handleSelect(c) }}
                onMouseEnter={() => setHighlightedIndex(idx)}
                style={{ padding:'10px 14px', cursor:'pointer', fontSize:'14px', borderBottom:'1px solid #f8fafc', color:'#0f172a', display:'flex', flexDirection:'column', gap:'2px', background: isHighlighted ? '#dcfce7' : 'white' }}>
                <div style={{ display:'flex', alignItems:'center', gap:'8px', flexWrap:'wrap' }}>
                  {c.customer_number && <span style={{ fontFamily:'ui-monospace, monospace', fontSize:'12px', color:'#64748b', fontWeight:'600' }}>{c.customer_number}</span>}
                  <span style={{ fontWeight:'600' }}>{c.name || '(uten navn)'}</span>
                  <span style={{ fontSize:'11px', color:'#64748b' }}>{typeCfg.emoji} {typeCfg.label}</span>
                  {isDup && (
                    <span title="Flere privatkunder har dette navnet — sjekk kundenummer/e-post" style={{ fontSize:'11px', background:'#fef3c7', color:'#92400e', padding:'1px 6px', borderRadius:'8px', fontWeight:'700' }}>
                      ⚠ duplikatnavn
                    </span>
                  )}
                </div>
                {(c.email || c.phone || c.orgnr) && (
                  <div style={{ fontSize:'11px', color:'#94a3b8', display:'flex', gap:'10px', flexWrap:'wrap' }}>
                    {c.email && <span>✉️ {c.email}</span>}
                    {c.phone && <span>📞 {c.phone}</span>}
                    {c.orgnr && <span>🏛️ {c.orgnr}</span>}
                  </div>
                )}
              </div>
            )
          })}
        </>
      )}
    </div>
  )

  // Håndterer lagring fra inline-modalen: auto-velg den nye kunden
  const handleCreated = (newId, newCustomer) => {
    setShowCreateModal(false)
    if (newId && newCustomer) {
      // Auto-velg den nye kunden som om bruker klikket i lista
      if (valueAsId) {
        onChange(newId)
      } else {
        onChange(newCustomer.name || '')
      }
      if (onSelect) onSelect({ ...newCustomer, id: newId })
    }
    setShowDrop(false)
    setSearchText('')
  }

  return (
    <div ref={wrapperRef} style={{ position:'relative' }}>
      <div style={{ position:'relative', display:'flex', alignItems:'stretch' }}>
        <input
          ref={inputRef}
          value={inputVal}
          onChange={e => {
            setSearchText(e.target.value)
            if (!showDrop) openDrop()
            if (!valueAsId && allowFreeText) onChange(e.target.value)
            if (valueAsId && !e.target.value) onChange('')
          }}
          onKeyDown={handleKeyDown}
          onFocus={openDrop}
          onBlur={() => setTimeout(() => setShowDrop(false), 200)}
          placeholder={placeholder || 'Søk etter kunde (navn, nr, orgnr, e-post)...'}
          style={{ ...selStyle, paddingRight:'44px' }} />
        <button
          type="button"
          onMouseDown={(e) => { e.preventDefault(); setShowCreateModal(true); setShowDrop(false) }}
          title="Opprett ny kunde"
          style={{
            position:'absolute',
            right:'4px',
            top:'50%',
            transform:'translateY(-50%)',
            width:'32px',
            height:'32px',
            background:'#059669',
            color:'white',
            border:'none',
            borderRadius:'8px',
            cursor:'pointer',
            fontSize:'18px',
            fontWeight:'700',
            display:'flex',
            alignItems:'center',
            justifyContent:'center',
            lineHeight:1,
          }}>+</button>
      </div>
      {selectedDuplicateWarning && (
        <div style={{ marginTop:'6px', padding:'8px 10px', background:'#fef3c7', border:'1px solid #fde68a', borderRadius:'8px', fontSize:'12px', color:'#92400e', lineHeight:1.4 }}>
          <strong>⚠ OBS:</strong> {selectedDuplicateWarning.count} privatkunder har identisk navn. Sjekk at du har valgt riktig person:
          <ul style={{ margin:'4px 0 0 18px', padding:0 }}>
            {selectedDuplicateWarning.siblings.map(s => (
              <li key={s.id} style={{ fontSize:'11px' }}>
                <span style={{ fontFamily:'ui-monospace, monospace', fontWeight:'600' }}>{s.customer_number || '(uten nr)'}</span>
                {s.email ? ` · ${s.email}` : ''}
                {s.phone ? ` · ${s.phone}` : ''}
              </li>
            ))}
          </ul>
        </div>
      )}
      {typeof document !== 'undefined' && dropdown ? createPortal(dropdown, document.body) : null}
      {showCreateModal && (
        <KundeModal
          user={user}
          existingKunder={allCustomers}
          onClose={() => setShowCreateModal(false)}
          onSaved={handleCreated}
        />
      )}
    </div>
  )
}

function Field({ label, children }) {
  return (
    <div>
      <label style={{ display: 'block', fontSize: '13px', fontWeight: '600', color: '#374151', marginBottom: '6px' }}>{label}</label>
      {children}
    </div>
  )
}

function Input2({ value, onChange, type, placeholder, required, readOnly }) {
  return (
    <input type={type || 'text'} value={value || ''} onChange={onChange} placeholder={placeholder} required={required} readOnly={readOnly}
      style={{ width: '100%', padding: '9px 12px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '14px', outline: 'none', boxSizing: 'border-box', background: readOnly ? '#f8fafc' : 'white', color: '#0f172a' }} />
  )
}

function Select2({ value, onChange, options }) {
  return (
    <select value={value || ''} onChange={e => onChange(e.target.value)}
      style={{ width: '100%', padding: '9px 12px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '14px', outline: 'none', background: 'white', color: '#0f172a' }}>
      {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
    </select>
  )
}

function Textarea2({ value, onChange, placeholder, rows }) {
  return (
    <textarea value={value || ''} onChange={onChange} placeholder={placeholder} rows={rows || 3}
      style={{ width: '100%', padding: '9px 12px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '14px', outline: 'none', resize: 'none', boxSizing: 'border-box', color: '#0f172a', fontFamily: 'system-ui, sans-serif' }} />
  )
}

function ContactList({ title, items, onChange }) {
  const add = () => onChange([...items, { name: '', phone: '', email: '', company: '' }])
  const remove = (i) => onChange(items.filter((_, idx) => idx !== i))
  const update = (i, field, val) => {
    const updated = [...items]
    updated[i] = { ...updated[i], [field]: val }
    onChange(updated)
  }
  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
        <h4 style={{ margin: 0, fontSize: '14px', fontWeight: '600', color: '#0f172a' }}>{title}</h4>
        <button type="button" onClick={add} style={{ background: '#ecfdf5', color: '#059669', border: 'none', borderRadius: '8px', padding: '6px 12px', fontSize: '13px', fontWeight: '600', cursor: 'pointer' }}>+ Legg til</button>
      </div>
      {items.map((item, i) => (
        <div key={i} style={{ background: '#f8fafc', borderRadius: '12px', padding: '12px', marginBottom: '8px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '8px' }}>
            <Input2 value={item.company} onChange={e => update(i, 'company', e.target.value)} placeholder="Firma" />
            <Input2 value={item.name} onChange={e => update(i, 'name', e.target.value)} placeholder="Kontaktperson" />
            <Input2 value={item.phone} onChange={e => update(i, 'phone', e.target.value)} placeholder="Telefon" />
            <Input2 value={item.email} onChange={e => update(i, 'email', e.target.value)} placeholder="E-post" />
          </div>
          <button type="button" onClick={() => remove(i)} style={{ background: '#fef2f2', color: '#dc2626', border: 'none', borderRadius: '6px', padding: '4px 10px', fontSize: '12px', cursor: 'pointer' }}>Fjern</button>
        </div>
      ))}
      {items.length === 0 && <p style={{ color: '#94a3b8', fontSize: '13px', margin: 0 }}>Ingen lagt til</p>}
    </div>
  )
}

const emptyForm = {
  name: '', project_number: '', description: '', status: 'planlagt',
  address_street: '', address_postal: '', address_city: '',
  start_date: '', end_date: '', budget: '',
  client_name: '', client_contact: '', client_email: '', client_phone: '',
  resident_name: '', resident_phone: '', resident_email: '',
  project_manager_name: '', project_manager_email: '', project_manager_phone: '',
  subcontractors: [], architects: [], consultants: [],
}

function ProsjektForm({ initial, onSubmit, onCancel, loading }) {
  const [form, setForm] = useState(initial || emptyForm)
  const set = (field, val) => setForm(f => ({ ...f, [field]: val }))
  return (
    <form onSubmit={e => { e.preventDefault(); onSubmit(form) }} style={{ padding: '24px', display: 'flex', flexDirection: 'column', gap: '24px' }}>
      <div>
        <h3 style={{ margin: '0 0 16px', fontSize: '15px', fontWeight: '700', color: '#0f172a', borderBottom: '1px solid #f1f5f9', paddingBottom: '8px' }}>Grunnleggende</h3>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <div style={{ gridColumn: '1 / -1' }}><Field label="Prosjektnavn *"><Input2 value={form.name} onChange={e => set('name', e.target.value)} placeholder="Skriv inn prosjektnavn" required /></Field></div>
          <Field label="Prosjektnummer"><Input2 value={form.project_number} onChange={e => set('project_number', e.target.value)} placeholder="Tildeles automatisk" /></Field>
          <Field label="Status"><Select2 value={form.status} onChange={v => set('status', v)} options={[{value:'planlagt',label:'Planlagt'},{value:'aktiv',label:'Aktiv'},{value:'pause',label:'Pa pause'},{value:'fullfort',label:'Fullfort'},{value:'avbrutt',label:'Avbrutt'}]} /></Field>
          <Field label="Gateadresse"><Input2 value={form.address_street} onChange={e => set('address_street', e.target.value)} placeholder="Gatenavn og nummer" /></Field>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '8px' }}>
            <Field label="Postnr"><Input2 value={form.address_postal} onChange={e => set('address_postal', e.target.value)} placeholder="0000" /></Field>
            <Field label="Poststed"><Input2 value={form.address_city} onChange={e => set('address_city', e.target.value)} placeholder="By" /></Field>
          </div>
          <Field label="Startdato"><Input2 type="date" value={form.start_date} onChange={e => set('start_date', e.target.value)} /></Field>
          <Field label="Sluttdato"><Input2 type="date" value={form.end_date} onChange={e => set('end_date', e.target.value)} /></Field>
          <div style={{ gridColumn: '1 / -1' }}><Field label="Budsjett (NOK)"><Input2 type="number" value={form.budget} onChange={e => set('budget', e.target.value)} placeholder="0" /></Field></div>
          <div style={{ gridColumn: '1 / -1' }}><Field label="Beskrivelse"><Textarea2 value={form.description} onChange={e => set('description', e.target.value)} placeholder="Beskrivelse av prosjektet..." /></Field></div>
        </div>
      </div>
      <div>
        <h3 style={{ margin: '0 0 16px', fontSize: '15px', fontWeight: '700', color: '#0f172a', borderBottom: '1px solid #f1f5f9', paddingBottom: '8px' }}>Prosjektleder</h3>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <Field label="Navn"><EmployeeNameSelect value={form.project_manager_name} onChange={v => set('project_manager_name', v)} onSelect={emp => { set('project_manager_name', `${emp.first_name||''} ${emp.last_name||''}`.trim()); if(emp.email) set('project_manager_email', emp.email); if(emp.phone) set('project_manager_phone', emp.phone) }} placeholder="Velg eller skriv inn navn" /></Field>
          <Field label="Telefon"><Input2 value={form.project_manager_phone} onChange={e => set('project_manager_phone', e.target.value)} placeholder="+47 000 00 000" /></Field>
          <div style={{ gridColumn: '1 / -1' }}><Field label="E-post"><Input2 type="email" value={form.project_manager_email} onChange={e => set('project_manager_email', e.target.value)} placeholder="prosjektleder@bedrift.no" /></Field></div>
        </div>
      </div>
      <div>
        <h3 style={{ margin: '0 0 16px', fontSize: '15px', fontWeight: '700', color: '#0f172a', borderBottom: '1px solid #f1f5f9', paddingBottom: '8px' }}>Kunde</h3>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <div style={{ gridColumn: '1 / -1' }}><Field label="Kundenavn"><Input2 value={form.client_name} onChange={e => set('client_name', e.target.value)} placeholder="Navn pa kunde" /></Field></div>
          <Field label="Kontaktperson"><Input2 value={form.client_contact} onChange={e => set('client_contact', e.target.value)} placeholder="Navn" /></Field>
          <Field label="Telefon"><Input2 value={form.client_phone} onChange={e => set('client_phone', e.target.value)} placeholder="+47 000 00 000" /></Field>
          <div style={{ gridColumn: '1 / -1' }}><Field label="E-post"><Input2 type="email" value={form.client_email} onChange={e => set('client_email', e.target.value)} placeholder="kunde@eksempel.no" /></Field></div>
        </div>
      </div>
      <div>
        <h3 style={{ margin: '0 0 16px', fontSize: '15px', fontWeight: '700', color: '#0f172a', borderBottom: '1px solid #f1f5f9', paddingBottom: '8px' }}>Beboer / Annen kontakt</h3>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <Field label="Navn"><Input2 value={form.resident_name} onChange={e => set('resident_name', e.target.value)} placeholder="Navn" /></Field>
          <Field label="Telefon"><Input2 value={form.resident_phone} onChange={e => set('resident_phone', e.target.value)} placeholder="+47 000 00 000" /></Field>
          <div style={{ gridColumn: '1 / -1' }}><Field label="E-post"><Input2 type="email" value={form.resident_email} onChange={e => set('resident_email', e.target.value)} placeholder="beboer@eksempel.no" /></Field></div>
        </div>
      </div>
      <div>
        <h3 style={{ margin: '0 0 16px', fontSize: '15px', fontWeight: '700', color: '#0f172a', borderBottom: '1px solid #f1f5f9', paddingBottom: '8px' }}>Underleverandorer</h3>
        <ContactList title="" items={form.subcontractors || []} onChange={v => set('subcontractors', v)} />
      </div>
      <div>
        <h3 style={{ margin: '0 0 16px', fontSize: '15px', fontWeight: '700', color: '#0f172a', borderBottom: '1px solid #f1f5f9', paddingBottom: '8px' }}>Arkitekter</h3>
        <ContactList title="" items={form.architects || []} onChange={v => set('architects', v)} />
      </div>
      <div>
        <h3 style={{ margin: '0 0 16px', fontSize: '15px', fontWeight: '700', color: '#0f172a', borderBottom: '1px solid #f1f5f9', paddingBottom: '8px' }}>Radgivere / Konsulenter</h3>
        <ContactList title="" items={form.consultants || []} onChange={v => set('consultants', v)} />
      </div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px', paddingTop: '8px' }}>
        <button type="button" onClick={onCancel} style={{ padding: '10px 20px', border: '1px solid #e2e8f0', borderRadius: '10px', background: 'white', cursor: 'pointer', fontSize: '14px', fontWeight: '600', color: '#374151' }}>Avbryt</button>
        <button type="submit" disabled={loading} style={{ padding: '10px 24px', background: '#059669', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontSize: '14px', fontWeight: '600' }}>{loading ? 'Lagrer...' : 'Lagre prosjekt'}</button>
      </div>
    </form>
  )
}

// ─── DB HELPERS ───────────────────────────────────────────────────────────
const db = {
  async getProjects() {
    const { data, error } = await supabase.from('projects').select('*').order('created_at', { ascending: false })
    if (error) throw error
    return data || []
  },
  async getProject(id) {
    const { data, error } = await supabase.from('projects').select('*').eq('id', id).single()
    if (error) throw error
    return data
  },
  async createProject(data) {
    const { data: result, error } = await supabase.from('projects').insert(data).select().single()
    if (error) throw error
    return result
  },
  async updateProject(id, data) {
    const { data: result, error } = await supabase.from('projects').update({ ...data, updated_at: new Date().toISOString() }).eq('id', id).select().single()
    if (error) throw error
    return result
  },
  async deleteProject(id) {
    const { error } = await supabase.from('projects').delete().eq('id', id)
    if (error) throw error
  }
}

// ─── SEKVENSNUMMERERING ──────────────────────────────────────────────────
// Genererer neste nummer i sekvens: PREFIX-YYYY-0001, PREFIX-YYYY-0002, osv.
// For prosjekter: P-0001, P-0002 (uten årstall)
function nextSequenceNumber(existingItems, prefix, numberField, { withYear = true } = {}) {
  if (withYear) {
    const year = new Date().getFullYear()
    const fullPrefix = `${prefix}-${year}-`
    const nums = existingItems
      .map(item => item[numberField])
      .filter(n => n && n.startsWith(fullPrefix))
      .map(n => parseInt(n.replace(fullPrefix, '')) || 0)
    const next = nums.length > 0 ? Math.max(...nums) + 1 : 1
    return `${prefix}-${year}-${String(next).padStart(4, '0')}`
  } else {
    const fullPrefix = `${prefix}-`
    const nums = existingItems
      .map(item => item[numberField])
      .filter(n => n && n.startsWith(fullPrefix))
      .map(n => parseInt(n.replace(fullPrefix, '')) || 0)
    const next = nums.length > 0 ? Math.max(...nums) + 1 : 1
    return `${prefix}-${String(next).padStart(4, '0')}`
  }
}

// ─── FELLES KUNDE-OPPLØSNING FOR ØKONOMI-MODULER ────────────────────────
// Bruker i TilbudEditorModal / OrdreEditorModal / FakturaEditorModal / EndringsmeldingModal.
// Hvis bruker allerede har valgt kunde via CustomerSelect (form.customer_id satt), returnerer den id-en.
// Ellers prøver den å matche på orgnr / email / navn. Finner den ingen match, oppretter den
// en ny kunde i customers-tabellen med autogenerert K-NNNN nummer.
// Returnerer { customerId, created } der created er true hvis en ny kunde ble opprettet.
async function resolveCustomerFromForm({ form, user, initialCustomerId = null, statusOnCreate = null }) {
  // 1. Hvis kunde allerede er valgt (dropdown eller tidligere lagret), bruk den
  let customerId = form.customer_id || initialCustomerId || null
  if (customerId) return { customerId, created: false }

  // 2. Ingen kunde valgt — hvis heller ingen navn skrevet, returner null (ikke valgfritt å ha kunde)
  if (!form.customer_name?.trim()) return { customerId: null, created: false }

  // 3. Prøv å finne eksisterende kunde basert på orgnr → email → navn
  try {
    let existingCustomer = null
    if (form.customer_orgnr?.trim()) {
      const { data } = await supabase.from('customers').select('id').eq('orgnr', form.customer_orgnr.trim()).limit(1)
      if (data?.length) existingCustomer = data[0]
    }
    if (!existingCustomer && form.customer_email?.trim()) {
      const { data } = await supabase.from('customers').select('id').eq('email', form.customer_email.trim()).limit(1)
      if (data?.length) existingCustomer = data[0]
    }
    if (!existingCustomer) {
      const { data } = await supabase.from('customers').select('id').ilike('name', form.customer_name.trim()).limit(1)
      if (data?.length) existingCustomer = data[0]
    }
    if (existingCustomer) {
      // Oppdater eksisterende med ferskere kundeinfo
      const updates = { updated_at: new Date().toISOString() }
      if (form.customer_email?.trim()) updates.email = form.customer_email.trim()
      if (form.customer_address?.trim()) updates.address = form.customer_address.trim()
      if (form.customer_orgnr?.trim()) updates.orgnr = form.customer_orgnr.trim()
      await supabase.from('customers').update(updates).eq('id', existingCustomer.id)
      return { customerId: existingCustomer.id, created: false }
    }

    // 4. Ingen match — opprett ny kunde med autogenerert K-NNNN nummer
    const { data: allCust } = await supabase.from('customers').select('customer_number')
    const customer_number = nextSequenceNumber(allCust || [], 'K', 'customer_number', { withYear: false })
    const insertPayload = {
      customer_number,
      name: form.customer_name.trim(),
      email: form.customer_email?.trim() || null,
      address: form.customer_address?.trim() || null,
      orgnr: form.customer_orgnr?.trim() || null,
      type: form.customer_orgnr?.trim() ? 'bedrift' : 'privat',
      created_by: user?.id,
      notes: 'Automatisk opprettet fra økonomimodul',
    }
    if (statusOnCreate) insertPayload.status = statusOnCreate
    const { data: newCust, error: custErr } = await supabase.from('customers').insert(insertPayload).select('id').single()
    if (custErr || !newCust) {
      console.error('[resolveCustomerFromForm] Kunne ikke opprette kunde:', custErr)
      return { customerId: null, created: false }
    }
    // Cache invalideres så CustomerSelect reflekterer nye kunder umiddelbart
    invalidateCustomerCache()
    return { customerId: newCust.id, created: true }
  } catch (e) {
    console.error('[resolveCustomerFromForm] Exception:', e)
    return { customerId, created: false }
  }
}

// ─── HIERARKISK PROSJEKTSTRUKTUR ─────────────────────────────────────────
// Bygger tre-struktur fra flat prosjektliste og gir hierarkisk dropdown

function buildProjectTree(projects) {
  const map = {}
  const roots = []
  // Sorter slik at foreldre kommer først
  const sorted = [...projects].sort((a, b) => (a.depth || 0) - (b.depth || 0))
  sorted.forEach(p => { map[p.id] = { ...p, children: [] } })
  sorted.forEach(p => {
    if (p.parent_id && map[p.parent_id]) {
      map[p.parent_id].children.push(map[p.id])
    } else {
      roots.push(map[p.id])
    }
  })
  return roots
}

function flattenProjectTree(nodes, depth = 0) {
  const result = []
  for (const node of nodes) {
    result.push({ ...node, _depth: depth })
    if (node.children?.length > 0) {
      // Sorter barn alfabetisk
      const sortedChildren = [...node.children].sort((a, b) => (a.name || '').localeCompare(b.name || '', 'nb'))
      result.push(...flattenProjectTree(sortedChildren, depth + 1))
    }
  }
  return result
}

function projectOptions(projects, includeArchived = false) {
  const filtered = includeArchived ? projects : projects.filter(p => p.status !== 'arkivert')
  const tree = buildProjectTree(filtered)
  // Sorter toppnivå alfabetisk
  tree.sort((a, b) => (a.name || '').localeCompare(b.name || '', 'nb'))
  return flattenProjectTree(tree)
}

function ProjectSelect({ value, onChange, projects, required, placeholder, style, allowEmpty = true, emptyLabel }) {
  const options = React.useMemo(() => projectOptions(projects || []), [projects])
  const indent = (depth) => {
    if (depth === 0) return ''
    return '\u00A0\u00A0\u00A0\u00A0'.repeat(depth) + '└ '
  }
  return (
    <select value={value || ''} onChange={e => onChange(e.target.value)} required={required}
      style={style || { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', fontFamily:'system-ui, sans-serif' }}>
      {allowEmpty && <option value="">{placeholder || emptyLabel || 'Velg prosjekt...'}</option>}
      {options.map(p => (
        <option key={p.id} value={p.id}>
          {indent(p._depth)}{p.name}{p.project_number ? ` (${p.project_number})` : ''}
        </option>
      ))}
    </select>
  )
}

// SearchableProjectSelect — som ProjectSelect, men med søkefelt og React Portal.
// Matcher mønsteret fra EmployeeNameSelect og CustomerSelect.
// Søker på navn, prosjektnummer, kundenavn, adresse.
// Props:
//   value (project_id eller emptyValue), onChange, projects, placeholder, style,
//   allowEmpty, emptyValue (hva "ingen valgt" betyr — default '' men kan være f.eks. 'alle')
function SearchableProjectSelect({ value, onChange, projects, placeholder, style, allowEmpty = true, emptyLabel, required, emptyValue = '' }) {
  const options = React.useMemo(() => projectOptions(projects || []), [projects])
  const [showDrop, setShowDrop] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [isTyping, setIsTyping] = useState(false)
  const [highlightedIndex, setHighlightedIndex] = useState(0)
  const [rect, setRect] = useState(null)
  const wrapperRef = React.useRef(null)
  const inputRef = React.useRef(null)
  const dropdownRef = React.useRef(null)

  const isEmpty = value === emptyValue || value == null || value === ''
  const selected = !isEmpty ? options.find(p => p.id === value) : null
  const displayValue = selected
    ? `${selected.name}${selected.project_number ? ` (${selected.project_number})` : ''}`
    : ''

  // Når dropdown er åpen og brukeren aktivt skriver → vis søketekst.
  // Når dropdown nettopp ble åpnet (isTyping=false) → vis valgt prosjekt.
  // Når dropdown er lukket → vis valgt prosjekt.
  const inputVal = showDrop && isTyping ? searchText : displayValue

  const filtered = options.filter(p => {
    // Filtrer kun når brukeren faktisk skriver — ellers vis hele lista.
    if (!isTyping) return true
    const q = (searchText || '').toLowerCase().trim()
    if (!q) return true
    return (p.name || '').toLowerCase().includes(q) ||
           (p.project_number || '').toLowerCase().includes(q) ||
           (p.client_name || '').toLowerCase().includes(q) ||
           (p.address || '').toLowerCase().includes(q) ||
           (p.address_street || '').toLowerCase().includes(q)
  })

  const handleSelect = (p) => {
    onChange(p.id)
    setShowDrop(false)
    setSearchText('')
    setIsTyping(false)
    setHighlightedIndex(0)
  }

  const openDrop = () => {
    if (wrapperRef.current) {
      const r = wrapperRef.current.getBoundingClientRect()
      setRect({ top: r.bottom + 4, left: r.left, width: r.width })
    }
    setShowDrop(true)
    setSearchText('')
    setIsTyping(false)
    setHighlightedIndex(0)
    // Marker hele teksten slik at første tastetrykk overskriver valgt prosjektnavn.
    // requestAnimationFrame sikrer at select() kjører etter at input har fått fokus.
    if (inputRef.current) {
      requestAnimationFrame(() => {
        try { inputRef.current && inputRef.current.select() } catch (e) {}
      })
    }
  }

  // Keyboard-navigasjon: ArrowDown/Up bytter uthevet treff, Enter velger, Escape lukker.
  const handleKeyDown = (e) => {
    if (!showDrop) {
      if (e.key === 'ArrowDown' || e.key === 'Enter') {
        e.preventDefault()
        openDrop()
      }
      return
    }
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      setHighlightedIndex(i => Math.min(i + 1, Math.max(filtered.length - 1, 0)))
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      setHighlightedIndex(i => Math.max(i - 1, 0))
    } else if (e.key === 'Enter') {
      e.preventDefault()
      const p = filtered[highlightedIndex]
      if (p) handleSelect(p)
    } else if (e.key === 'Escape') {
      e.preventDefault()
      setShowDrop(false)
      setSearchText('')
      setIsTyping(false)
      setHighlightedIndex(0)
      if (inputRef.current) inputRef.current.blur()
    }
  }

  useEffect(() => {
    if (!showDrop) return
    const update = () => {
      if (wrapperRef.current) {
        const r = wrapperRef.current.getBoundingClientRect()
        setRect({ top: r.bottom + 4, left: r.left, width: r.width })
      }
    }
    window.addEventListener('scroll', update, true)
    window.addEventListener('resize', update)
    return () => {
      window.removeEventListener('scroll', update, true)
      window.removeEventListener('resize', update)
    }
  }, [showDrop])

  const selStyle = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', fontFamily:'system-ui, sans-serif', ...style }

  // Status-pill config (samme farger som resten av systemet)
  const statusPill = (status) => {
    const cfg = {
      planlagt: { bg:'#eff6ff', color:'#2563eb', label:'Planlagt' },
      aktiv:    { bg:'#f0fdf4', color:'#16a34a', label:'Aktiv' },
      pause:    { bg:'#fffbeb', color:'#d97706', label:'På pause' },
      fullfort: { bg:'#f8fafc', color:'#64748b', label:'Fullført' },
      avbrutt:  { bg:'#fef2f2', color:'#dc2626', label:'Avbrutt' },
      arkivert: { bg:'#f1f5f9', color:'#94a3b8', label:'Arkivert' },
    }[status] || null
    if (!cfg) return null
    return <span style={{ background: cfg.bg, color: cfg.color, fontSize:'10px', fontWeight:'700', padding:'1px 7px', borderRadius:'999px' }}>{cfg.label}</span>
  }

  const indent = (depth) => '\u00A0\u00A0\u00A0\u00A0'.repeat(depth)

  const dropdown = (showDrop && rect) && (
    <div ref={dropdownRef} style={{
      position:'fixed',
      top: `${rect.top}px`,
      left: `${rect.left}px`,
      width: `${rect.width}px`,
      background:'white',
      border:'1px solid #e2e8f0',
      borderRadius:'10px',
      boxShadow:'0 8px 24px rgba(0,0,0,0.18)',
      zIndex: 99999,
      maxHeight:'320px',
      overflowY:'auto'
    }}>
      {options.length === 0 ? (
        <div style={{ padding:'14px', fontSize:'12px', color:'#94a3b8', textAlign:'center' }}>
          Ingen prosjekter tilgjengelig
        </div>
      ) : (
        <>
          {filtered.length === 0 ? (
            <div style={{ padding:'12px', fontSize:'12px', color:'#94a3b8', textAlign:'center' }}>
              Ingen treff{searchText ? ` for "${searchText}"` : ''}
            </div>
          ) : filtered.map((p, idx) => {
            const isHighlighted = idx === highlightedIndex
            return (
            <div key={p.id}
              ref={el => { if (isHighlighted && el && dropdownRef.current) {
                const parent = dropdownRef.current
                const elTop = el.offsetTop
                const elBottom = elTop + el.offsetHeight
                if (elTop < parent.scrollTop) parent.scrollTop = elTop
                else if (elBottom > parent.scrollTop + parent.clientHeight) parent.scrollTop = elBottom - parent.clientHeight
              } }}
              onMouseDown={(e) => { e.preventDefault(); handleSelect(p) }}
              onMouseEnter={e => { setHighlightedIndex(idx); e.currentTarget.style.background='#f0fdf4' }}
              onMouseLeave={e => { e.currentTarget.style.background = isHighlighted ? '#f0fdf4' : 'white' }}
              style={{ padding:'10px 14px', cursor:'pointer', fontSize:'14px', borderBottom:'1px solid #f8fafc', color:'#0f172a', display:'flex', flexDirection:'column', gap:'2px', background: isHighlighted ? '#f0fdf4' : 'white' }}>
              <div style={{ display:'flex', alignItems:'center', gap:'8px', flexWrap:'wrap' }}>
                {p.project_number && <span style={{ fontFamily:'ui-monospace, monospace', fontSize:'12px', color:'#64748b', fontWeight:'600' }}>{p.project_number}</span>}
                <span style={{ fontWeight:'600' }}>{indent(p._depth)}{p._depth > 0 ? '└ ' : ''}{p.name || '(uten navn)'}</span>
                {statusPill(p.status)}
              </div>
              {(p.client_name || p.address_street || p.address) && (
                <div style={{ fontSize:'11px', color:'#94a3b8', display:'flex', gap:'10px', flexWrap:'wrap' }}>
                  {p.client_name && <span>👤 {p.client_name}</span>}
                  {(p.address_street || p.address) && <span>📍 {p.address_street || p.address}</span>}
                </div>
              )}
            </div>
          )})}
        </>
      )}
    </div>
  )

  return (
    <div ref={wrapperRef} style={{ position:'relative' }}>
      <input
        ref={inputRef}
        value={inputVal}
        onChange={e => {
          // Første tastetrykk → bytt til "skrive-modus". Valgt displayValue erstattes av søketekst.
          setIsTyping(true)
          setSearchText(e.target.value)
          setHighlightedIndex(0)
          if (!showDrop) openDrop()
        }}
        onFocus={openDrop}
        onClick={() => { if (!showDrop) openDrop() }}
        onKeyDown={handleKeyDown}
        onBlur={() => setTimeout(() => { setShowDrop(false); setSearchText(''); setIsTyping(false); setHighlightedIndex(0) }, 200)}
        placeholder={placeholder || emptyLabel || 'Søk etter prosjekt (navn, nummer, kunde, adresse)...'}
        required={required && !value}
        style={selStyle} />
      {typeof document !== 'undefined' && dropdown ? createPortal(dropdown, document.body) : null}
    </div>
  )
}

// ─── PROSJEKTER PAGE ──────────────────────────────────────────────────────
const statusOpts = [{value:'planlagt',label:'Planlagt'},{value:'aktiv',label:'Aktiv'},{value:'pause',label:'På pause'},{value:'fullfort',label:'Fullført'},{value:'avbrutt',label:'Avbrutt'},{value:'arkivert',label:'Arkivert'}]

// Konverterer tomme strenger til null for UUID- og DATE-kolonner før innsending til Supabase.
// Postgres UUID-kolonner avviser '' med "invalid input syntax for type uuid".
// Postgres DATE-kolonner avviser '' med "invalid input syntax for type date".
// Fanger:
//   - UUID: alle felter som slutter på _id + eksplisitte UUID-felter
//   - DATE: alle felter som slutter på _date eller er i DATE_FIELDS-lista
// Beholder felter som ikke matcher uendret. Safe å kjøre flere ganger (idempotent).
const UUID_FIELD_SUFFIX = /_id$/
const EXPLICIT_UUID_FIELDS = new Set(['created_by', 'updated_by', 'user_id'])
const DATE_FIELD_SUFFIX = /_date$|_until$|_from$|_to$/
const EXPLICIT_DATE_FIELDS = new Set([
  'deadline', 'valid_until', 'due_date', 'invoice_date', 'delivery_date',
  'start_date', 'end_date', 'birth_date', 'last_service', 'next_service',
  'neste_revisjon', 'dato', 'reminder_date',
])

function sanitizeUuidFields(obj) {
  // Bakoverkompatibelt alias — kaller den nye generelle saniteringen.
  return sanitizeDbPayload(obj)
}

function sanitizeDbPayload(obj) {
  if (!obj || typeof obj !== 'object') return obj
  const out = { ...obj }
  for (const key of Object.keys(out)) {
    const v = out[key]
    // Kun strenger kan være "", så hopp over alt annet
    if (typeof v !== 'string') continue
    const isEmpty = v.trim() === ''
    if (!isEmpty) continue
    // UUID-felter: slutter på _id eller er i eksplisitt liste
    if (UUID_FIELD_SUFFIX.test(key) || EXPLICIT_UUID_FIELDS.has(key)) {
      out[key] = null
      continue
    }
    // DATE-felter: slutter på _date/_until/_from/_to eller er i eksplisitt liste
    if (DATE_FIELD_SUFFIX.test(key) || EXPLICIT_DATE_FIELDS.has(key)) {
      out[key] = null
      continue
    }
  }
  return out
}

const emptyProsjekt = {
  name:'', project_number:'', description:'', status:'planlagt',
  parent_id:'', depth: 0,
  address_street:'', address_postal:'', address_city:'',
  start_date:'', end_date:'', budget:'',
  client_name:'', client_contact:'', client_email:'', client_phone:'',
  resident_name:'', resident_phone:'', resident_email:'',
  project_manager_name:'', project_manager_email:'', project_manager_phone:'', customer_id:'',
  subcontractors:[], architects:[], consultants:[],
}

function FLabel({ label, children }) {
  return <div><label style={{ display:'block', fontSize:'13px', fontWeight:'500', color:'#374151', marginBottom:'4px' }}>{label}</label>{children}</div>
}

function FInput({ ...props }) {
  return <input {...props} style={{ width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box' }} />
}

function FSelect({ value, onChange, options }) {
  return <select value={value} onChange={e => onChange(e.target.value)} style={{ width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', background:'white' }}>{options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}</select>
}

function FTextarea({ ...props }) {
  return <textarea {...props} style={{ width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', resize:'vertical', boxSizing:'border-box', fontFamily:'system-ui, sans-serif' }} />
}

function ContactSection({ title, items, onChange }) {
  const add = () => onChange([...items, { company:'', name:'', phone:'', email:'', trade:'', discipline:'' }])
  const remove = (i) => onChange(items.filter((_,idx) => idx !== i))
  const update = (i, k, v) => { const a=[...items]; a[i]={...a[i],[k]:v}; onChange(a) }
  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'12px' }}>
        <h3 style={{ margin:0, fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>{title}</h3>
        <button type="button" onClick={add} style={{ background:'#ecfdf5', color:'#059669', border:'none', borderRadius:'8px', padding:'6px 12px', fontSize:'13px', cursor:'pointer', fontWeight:'600' }}>+ Legg til</button>
      </div>
      {items.map((item, i) => (
        <div key={i} style={{ background:'#f8fafc', borderRadius:'12px', padding:'14px', marginBottom:'10px' }}>
          <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'8px', marginBottom:'8px' }}>
            <FInput value={item.company || item.name || ''} onChange={e => update(i, 'company', e.target.value)} placeholder="Firma" />
            <FInput value={item.trade || item.discipline || ''} onChange={e => update(i, 'trade', e.target.value)} placeholder="Fag/disiplin" />
            <FInput value={item.contact_person || ''} onChange={e => update(i, 'contact_person', e.target.value)} placeholder="Kontaktperson" />
            <FInput value={item.phone || ''} onChange={e => update(i, 'phone', e.target.value)} placeholder="Telefon" />
            <div style={{ gridColumn:'1/-1' }}>
              <FInput value={item.email || ''} onChange={e => update(i, 'email', e.target.value)} placeholder="E-post" />
            </div>
          </div>
          <button type="button" onClick={() => remove(i)} style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'6px', padding:'4px 10px', fontSize:'12px', cursor:'pointer' }}>Fjern</button>
        </div>
      ))}
      {items.length === 0 && <p style={{ color:'#94a3b8', fontSize:'13px', margin:0 }}>Ingen lagt til ennå</p>}
    </div>
  )
}

function ProsjektModal({ title, initial, onSave, onClose, saving, projects: allProjects }) {
  const [form, setForm] = useState(initial || emptyProsjekt)
  const [pnrError, setPnrError] = useState('')
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }))
  const g2 = { display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }
  const sec = (label) => <h3 style={{ margin:'8px 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a', borderBottom:'1px solid #f1f5f9', paddingBottom:'8px' }}>{label}</h3>
  // Filtrer ut seg selv fra overordnet-listen (kan ikke være sitt eget parent)
  const parentProjects = (allProjects || []).filter(p => p.id !== initial?.id)

  // Live duplikatsjekk av prosjektnummer
  const checkPnr = (val) => {
    set('project_number', val)
    if (!val || !val.trim()) { setPnrError(''); return }
    const trimmed = val.trim().toUpperCase()
    const duplicate = (allProjects || []).find(p =>
      p.project_number?.trim().toUpperCase() === trimmed && p.id !== initial?.id
    )
    setPnrError(duplicate ? `Prosjektnummer «${duplicate.project_number}» er allerede i bruk av «${duplicate.name}»` : '')
  }

  const handleSubmit = (e) => {
    e.preventDefault()
    if (pnrError) return
    onSave(form)
  }

  return (
    <>
      <div onClick={onClose} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.4)', zIndex:100 }} />
      <div style={{ position:'fixed', top:'50%', left:'50%', transform:'translate(-50%,-50%)', background:'white', borderRadius:'20px', width:'min(680px, calc(100vw - 32px))', maxHeight:'90vh', display:'flex', flexDirection:'column', zIndex:101, boxShadow:'0 20px 60px rgba(0,0,0,0.15)', fontFamily:'system-ui, sans-serif' }}>
        <form onSubmit={handleSubmit} style={{ display:'flex', flexDirection:'column', flex:1, minHeight:0 }}>
          {/* Header med lagre-knapp */}
          <div style={{ padding:'14px 20px', borderBottom:'1px solid #f1f5f9', display:'flex', alignItems:'center', justifyContent:'space-between', flexShrink:0 }}>
            <h2 style={{ margin:0, fontSize:'17px', fontWeight:'700', color:'#0f172a' }}>{title}</h2>
            <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
              <button type="button" onClick={onClose} style={{ padding:'8px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
              <button type="submit" disabled={saving || !!pnrError} style={{ padding:'8px 20px', background: (saving || pnrError) ? '#94a3b8' : '#059669', color:'white', border:'none', borderRadius:'10px', cursor: (saving || pnrError) ? 'not-allowed' : 'pointer', fontSize:'14px', fontWeight:'700' }}>{saving ? 'Lagrer...' : 'Lagre'}</button>
            </div>
          </div>
          {/* Scrollbart innhold */}
          <div style={{ overflowY:'auto', flex:1, padding:'20px 24px', display:'flex', flexDirection:'column', gap:'20px' }}>
            {sec('Grunnleggende')}
            <div style={g2}>
              <div style={{ gridColumn:'1/-1' }}><FLabel label="Prosjektnavn *"><FInput value={form.name} onChange={e => set('name', e.target.value)} placeholder="Skriv inn prosjektnavn" required /></FLabel></div>
              <FLabel label="Status"><FSelect value={form.status} onChange={v => set('status', v)} options={statusOpts} /></FLabel>
              <div>
                <FLabel label="Prosjektnummer">
                  <input value={form.project_number || ''} onChange={e => checkPnr(e.target.value)} placeholder="Tildeles automatisk"
                    style={{ width:'100%', padding:'9px 12px', border: pnrError ? '1px solid #f87171' : '1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background: pnrError ? '#fef2f2' : 'white' }} />
                </FLabel>
                {pnrError && <p style={{ margin:'4px 0 0', fontSize:'12px', color:'#dc2626', lineHeight:1.3 }}>{pnrError}</p>}
              </div>
              <div style={{ gridColumn:'1/-1' }}>
                <FLabel label="Overordnet prosjekt">
                  <ProjectSelect value={form.parent_id} onChange={v => set('parent_id', v)} projects={parentProjects} placeholder="Ingen (toppnivå-prosjekt)" />
                </FLabel>
                {form.parent_id && <p style={{ margin:'4px 0 0', fontSize:'12px', color:'#059669' }}>Dette blir et underprosjekt. Prosjektnummer genereres automatisk.</p>}
              </div>
              <div style={{ gridColumn:'1/-1' }}><FLabel label="Gateadresse"><FInput value={form.address_street} onChange={e => set('address_street', e.target.value)} placeholder="Gatenavn og nummer" /></FLabel></div>
              <FLabel label="Postnummer"><FInput value={form.address_postal} onChange={e => set('address_postal', e.target.value)} placeholder="0000" /></FLabel>
              <FLabel label="Poststed"><FInput value={form.address_city} onChange={e => set('address_city', e.target.value)} placeholder="By" /></FLabel>
              <FLabel label="Startdato"><FInput type="date" value={form.start_date} onChange={e => set('start_date', e.target.value)} /></FLabel>
              <FLabel label="Sluttdato"><FInput type="date" value={form.end_date} onChange={e => set('end_date', e.target.value)} /></FLabel>
              <div style={{ gridColumn:'1/-1' }}><FLabel label="Budsjett (NOK)"><FInput type="number" value={form.budget} onChange={e => set('budget', e.target.value)} placeholder="0" /></FLabel></div>
              <div style={{ gridColumn:'1/-1' }}><FLabel label="Beskrivelse"><FTextarea value={form.description} onChange={e => set('description', e.target.value)} placeholder="Beskrivelse..." rows={2} /></FLabel></div>
            </div>
            {sec('Prosjektleder')}
            <div style={g2}>
              <FLabel label="Navn"><EmployeeNameSelect value={form.project_manager_name} onChange={v => set('project_manager_name', v)} onSelect={emp => { set('project_manager_name', `${emp.first_name||''} ${emp.last_name||''}`.trim()); if(emp.email) set('project_manager_email', emp.email); if(emp.phone) set('project_manager_phone', emp.phone) }} placeholder="Velg eller skriv inn navn" /></FLabel>
              <FLabel label="Telefon"><FInput value={form.project_manager_phone} onChange={e => set('project_manager_phone', e.target.value)} placeholder="+47 000 00 000" /></FLabel>
              <div style={{ gridColumn:'1/-1' }}><FLabel label="E-post"><FInput type="email" value={form.project_manager_email} onChange={e => set('project_manager_email', e.target.value)} placeholder="prosjektleder@bedrift.no" /></FLabel></div>
            </div>
            {sec('Kunde')}
            <div style={g2}>
              <div style={{ gridColumn:'1/-1' }}>
                <FLabel label="Velg kunde">
                  <CustomerSelect
                    value={form.customer_id}
                    valueAsId
                    onChange={v => {
                      set('customer_id', v)
                      // Når bruker "fjerner valgt": nullstill ikke client_name — la brukeren beholde det
                      // de har skrevet tidligere (kan være manuelt inntastet)
                    }}
                    onSelect={c => {
                      // Autofyll kundedata fra valgt kunde
                      set('customer_id', c.id)
                      set('client_name', c.name || '')
                      if (c.email) set('client_email', c.email)
                      if (c.phone) set('client_phone', c.phone)
                    }}
                    placeholder="Søk etter kunde — navn, kundenr, orgnr, e-post..."
                  />
                </FLabel>
                <p style={{ margin:'4px 0 0', fontSize:'11px', color:'#94a3b8' }}>
                  Finner du ikke kunden? Opprett den først i Kundeoversikt — så vises den her.
                </p>
              </div>
              <div style={{ gridColumn:'1/-1' }}><FLabel label="Kundenavn (kan overstyres manuelt)"><FInput value={form.client_name} onChange={e => set('client_name', e.target.value)} placeholder="Navn på kunde" /></FLabel></div>
              <FLabel label="Kontaktperson"><FInput value={form.client_contact} onChange={e => set('client_contact', e.target.value)} placeholder="Navn" /></FLabel>
              <FLabel label="Telefon"><FInput value={form.client_phone} onChange={e => set('client_phone', e.target.value)} placeholder="+47 000 00 000" /></FLabel>
              <div style={{ gridColumn:'1/-1' }}><FLabel label="E-post"><FInput type="email" value={form.client_email} onChange={e => set('client_email', e.target.value)} placeholder="kunde@eksempel.no" /></FLabel></div>
            </div>
            {sec('Beboer / Annen kontakt')}
            <div style={g2}>
              <FLabel label="Navn"><FInput value={form.resident_name} onChange={e => set('resident_name', e.target.value)} placeholder="Navn" /></FLabel>
              <FLabel label="Telefon"><FInput value={form.resident_phone} onChange={e => set('resident_phone', e.target.value)} placeholder="+47 000 00 000" /></FLabel>
              <div style={{ gridColumn:'1/-1' }}><FLabel label="E-post"><FInput type="email" value={form.resident_email} onChange={e => set('resident_email', e.target.value)} placeholder="beboer@eksempel.no" /></FLabel></div>
            </div>
            {sec('Underentreprenører')}
            <ContactSection title="" items={form.subcontractors || []} onChange={v => set('subcontractors', v)} />
            {sec('Arkitekter')}
            <ContactSection title="" items={form.architects || []} onChange={v => set('architects', v)} />
            {sec('Rådgivere / Konsulenter')}
            <ContactSection title="" items={form.consultants || []} onChange={v => set('consultants', v)} />
          </div>
        </form>
      </div>
    </>
  )
}

function ProsjekterPage({ onNavigateDetail }) {
  const { user } = useAuth()
  const [projects, setProjects] = useState([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('all')
  const isMobProj = typeof window !== 'undefined' && window.innerWidth < 768
  const viewKey = isMobProj ? 'ep_proj_view_mobile' : 'ep_proj_view_desktop'
  const [viewMode, setViewModeState] = useState(() => {
    try { return localStorage.getItem(viewKey) || (isMobProj ? 'list' : 'grid') } catch(e) { return isMobProj ? 'list' : 'grid' }
  })
  const setViewMode = (v) => { setViewModeState(v); try { localStorage.setItem(viewKey, v) } catch(e) {} }
  const [sortBy, setSortBy] = useState('created_desc')
  const [showCreate, setShowCreate] = useState(false)
  const [saving, setSaving] = useState(false)
  const [showArchived, setShowArchived] = useState(false)
  const f = { fontFamily:'system-ui, sans-serif', overflowX:'clip', maxWidth:'100vw' }
  const inp = { width:'100%', padding: isMobProj ? '8px 10px' : '9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize: isMobProj ? '13px' : '14px', outline:'none', boxSizing:'border-box' }

  const load = async () => { try { setProjects(await db.getProjects()) } catch(e){console.error(e)} finally { setLoading(false) } }
  useEffect(() => { load() }, [])

  const archivedCount = projects.filter(p => p.status === 'arkivert').length
  const activeProjects = showArchived ? projects : projects.filter(p => p.status !== 'arkivert')

  const filtered = React.useMemo(() => {
    const list = activeProjects.filter(p => {
      const ms = !search || p.name?.toLowerCase().includes(search.toLowerCase()) || p.client_name?.toLowerCase().includes(search.toLowerCase())
      const mst = statusFilter === 'all' || p.status === statusFilter
      return ms && mst
    })
    // Ved hierarkisk visning (list): bruk trestruktur
    if (viewMode === 'list' && !search) {
      return projectOptions(list, showArchived)
    }
    return list.sort((a, b) => {
      switch (sortBy) {
        case 'name_asc':   return (a.name||'').localeCompare(b.name||'', 'nb')
        case 'name_desc':  return (b.name||'').localeCompare(a.name||'', 'nb')
        case 'created_asc':  return new Date(a.created_at) - new Date(b.created_at)
        case 'created_desc': return new Date(b.created_at) - new Date(a.created_at)
        default: return 0
      }
    })
  }, [activeProjects, search, statusFilter, sortBy, viewMode, showArchived])

  const handleCreate = async (form) => {
    setSaving(true)
    try {
      // Beregn depth og prosjektnummer basert på parent
      let depth = 0
      let projectNumber = form.project_number || nextSequenceNumber(projects, 'P', 'project_number', { withYear: false })
      if (form.parent_id) {
        const parent = projects.find(p => p.id === form.parent_id)
        depth = (parent?.depth || 0) + 1
        if (!form.project_number && parent?.project_number) {
          const siblings = projects.filter(p => p.parent_id === form.parent_id)
          projectNumber = parent.project_number + '-' + String(siblings.length + 1).padStart(2, '0')
        }
      }
      // Duplikatsjekk — siste forsvarslinje
      const existing = projects.find(p => p.project_number?.trim().toUpperCase() === projectNumber.trim().toUpperCase())
      if (existing) {
        // Auto-generert nummer kolliderte — legg til tidsstempel
        projectNumber = projectNumber + 'B'
      }
      await db.createProject(sanitizeUuidFields({ ...form, project_number: projectNumber, parent_id: form.parent_id || null, depth, address: [form.address_street, `${form.address_postal} ${form.address_city}`.trim()].filter(Boolean).join(', '), budget: form.budget ? parseFloat(form.budget) : null, created_by: user?.id }))
      setShowCreate(false)
      load()
    } catch(e) { alert('Feil: ' + e.message) } finally { setSaving(false) }
  }

  return (
    <div style={f}>
      <div style={{ position:'sticky', top: isMobProj ? '52px' : '56px', zIndex:20, background:'#f8fafc' }}>
        <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '16px' : '20px 32px' }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px' }}>
            <div>
              <h1 style={{ margin:0, fontSize: typeof window !== 'undefined' && window.innerWidth < 768 ? '18px' : '22px', fontWeight:'bold', color:'#0f172a' }}>Prosjekter</h1>
              <p style={{ margin:'3px 0 0', fontSize:'12px', color:'#64748b' }}>{activeProjects.length} prosjekter{archivedCount > 0 && !showArchived ? ` · ${archivedCount} arkivert` : ''}</p>
            </div>
            <button onClick={() => setShowCreate(true)} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '9px 14px' : '10px 18px', fontSize:'13px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>+ Nytt prosjekt</button>
          </div>
        </div>
        <div style={{ padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '16px 32px', background:'white', borderBottom:'1px solid #e2e8f0' }}>
          <div style={{ display:'flex', gap: typeof window !== 'undefined' && window.innerWidth < 768 ? '8px' : '12px', flexWrap:'wrap', alignItems:'center' }}>
            <div style={{ position:'relative', flex:1, minWidth:'200px' }}>
              <span style={{ position:'absolute', left:'12px', top:'50%', transform:'translateY(-50%)', color:'#94a3b8' }}>🔍</span>
              <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Søk etter prosjekt..." style={{ ...inp, paddingLeft:'36px' }} />
            </div>
            <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} style={{ ...inp, width:'160px', background:'white' }}>
              <option value="all">Alle statuser</option>
              {statusOpts.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
            </select>
            <select value={sortBy} onChange={e => setSortBy(e.target.value)}
              style={{ padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'13px', outline:'none', background:'white', cursor:'pointer', color:'#374151', fontWeight:'500' }}>
              <option value="name_asc">A → Å</option>
              <option value="name_desc">Å → A</option>
              <option value="created_desc">Nyeste først</option>
              <option value="created_asc">Eldste først</option>
            </select>
            {archivedCount > 0 && (
              <button onClick={() => setShowArchived(!showArchived)}
                style={{ padding:'8px 14px', borderRadius:'10px', border: showArchived ? '1px solid #7c3aed' : '1px solid #e2e8f0', background: showArchived ? '#f5f3ff' : 'white', cursor:'pointer', fontSize:'13px', fontWeight:'500', color: showArchived ? '#7c3aed' : '#64748b', display:'flex', alignItems:'center', gap:'6px' }}>
                📦 {showArchived ? 'Skjul arkiverte' : `Vis arkiverte (${archivedCount})`}
              </button>
            )}
            <div style={{ display:'flex', gap:'4px' }}>
              {['grid','list'].map(v => <button key={v} onClick={() => setViewMode(v)} style={{ padding:'8px 10px', borderRadius:'8px', border:'none', cursor:'pointer', background: viewMode===v ? '#ecfdf5':'transparent', color: viewMode===v ? '#059669':'#94a3b8', fontSize:'16px' }}>{v==='grid'?'⊞':'☰'}</button>)}
            </div>
          </div>
        </div>
      </div>
      <div style={{ padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '24px 32px' }}>
        {loading ? (
          <div style={{ textAlign:'center', padding:'60px', color:'#94a3b8' }}>Laster prosjekter...</div>
        ) : filtered.length === 0 ? (
          <div style={{ textAlign:'center', padding:'60px' }}>
            <div style={{ fontSize:'48px', marginBottom:'12px' }}>🏗️</div>
            <h3 style={{ color:'#0f172a', margin:'0 0 8px' }}>Ingen prosjekter</h3>
            <p style={{ color:'#64748b', margin:'0 0 20px' }}>{search ? 'Ingen matcher søket' : 'Opprett ditt første prosjekt'}</p>
            {!search && <button onClick={() => setShowCreate(true)} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding:'10px 18px', fontSize:'14px', fontWeight:'600', cursor:'pointer' }}>+ Nytt prosjekt</button>}
          </div>
        ) : viewMode === 'grid' ? (
          <div style={{ display:'grid', gridTemplateColumns: isMobProj ? '1fr' : 'repeat(auto-fill, minmax(280px, 1fr))', gap: isMobProj ? '10px' : '16px' }}>
            {filtered.map(p => {
              const childCount = projects.filter(c => c.parent_id === p.id).length
              const parentName = p.parent_id ? projects.find(pp => pp.id === p.parent_id)?.name : null
              return (
              <button key={p.id} onClick={() => onNavigateDetail(p.id)}
                style={{ background:'white', borderRadius:'16px', border:'1px solid #f1f5f9', padding:'20px', cursor:'pointer', textAlign:'left', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }}
                onMouseEnter={e => e.currentTarget.style.boxShadow='0 4px 16px rgba(0,0,0,0.08)'}
                onMouseLeave={e => e.currentTarget.style.boxShadow='0 1px 4px rgba(0,0,0,0.04)'}>
                <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'14px' }}>
                  <div style={{ width:'44px', height:'44px', borderRadius:'12px', background: p.parent_id ? '#f0fdf4' : '#ecfdf5', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px' }}>{p.parent_id ? '📂' : '🏗️'}</div>
                  <StatusBadge status={p.status} />
                </div>
                {parentName && <p style={{ margin:'0 0 4px', fontSize:'11px', color:'#059669', fontWeight:'500' }}>↳ {parentName}</p>}
                <h3 style={{ margin:'0 0 4px', fontSize:'15px', fontWeight:'600', color:'#0f172a' }}>{p.name}</h3>
                {p.project_number && <p style={{ margin:'0 0 10px', fontSize:'12px', color:'#94a3b8' }}>#{p.project_number}</p>}
                <div style={{ display:'flex', flexDirection:'column', gap:'4px', fontSize:'13px', color:'#64748b' }}>
                  {p.client_name && <span>👥 {p.client_name}</span>}
                  {p.address && <span>📍 {p.address}</span>}
                  {p.start_date && <span>📅 {new Date(p.start_date).toLocaleDateString('nb-NO')}</span>}
                  {childCount > 0 && <span style={{ color:'#059669', fontWeight:'500' }}>📁 {childCount} underprosjekt{childCount > 1 ? 'er' : ''}</span>}
                </div>
              </button>
            )})}
          </div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'4px', overflowX:'hidden', width:'100%' }}>
            {filtered.map(p => {
              const depth = p._depth || p.depth || 0
              const childCount = projects.filter(c => c.parent_id === p.id).length
              const isMob = typeof window !== 'undefined' && window.innerWidth < 768
              const indent = isMob ? Math.min(depth * 12, 24) : depth * 28
              return (
              <button key={p.id} onClick={() => onNavigateDetail(p.id)}
                style={{ background:'white', borderRadius:'12px', border:'1px solid #f1f5f9', padding: isMob ? '10px 10px' : '14px 18px', cursor:'pointer', textAlign:'left', display:'flex', alignItems:'center', gap: isMob ? '8px' : '14px', marginLeft: indent, width: isMob ? `calc(100% - ${indent}px)` : 'auto', maxWidth:'100%', overflow:'hidden', boxSizing:'border-box' }}>
                {depth > 0 && !isMob && <span style={{ color:'#d1d5db', fontSize:'14px', flexShrink:0 }}>└</span>}
                <div style={{ width: isMob ? '30px' : '38px', height: isMob ? '30px' : '38px', borderRadius:'10px', background: depth > 0 ? '#f0fdf4' : '#ecfdf5', display:'flex', alignItems:'center', justifyContent:'center', fontSize: isMob ? '14px' : '18px', flexShrink:0 }}>{depth > 0 ? '📂' : '🏗️'}</div>
                <div style={{ flex:1, minWidth:0, overflow:'hidden' }}>
                  <div style={{ display:'flex', alignItems:'center', gap:'6px' }}>
                    <span style={{ fontWeight:'600', color:'#0f172a', fontSize: isMob ? '13px' : '14px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{p.name}</span>
                    {p.project_number && !isMob && <span style={{ fontSize:'11px', color:'#94a3b8', flexShrink:0 }}>#{p.project_number}</span>}
                    {childCount > 0 && <span style={{ fontSize:'11px', color:'#059669', background:'#ecfdf5', padding:'1px 6px', borderRadius:'999px', flexShrink:0 }}>{childCount}</span>}
                  </div>
                  {isMob && p.project_number && <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'1px' }}>#{p.project_number}</div>}
                  {!isMob && (
                  <div style={{ display:'flex', gap:'12px', fontSize:'12px', color:'#64748b', marginTop:'2px' }}>
                    {p.client_name && <span>{p.client_name}</span>}
                    {p.address && <span>{p.address}</span>}
                  </div>
                  )}
                </div>
                <StatusBadge status={p.status} />
                <span style={{ color:'#cbd5e1', flexShrink:0 }}>›</span>
              </button>
            )})}
          </div>
        )}
      </div>
      {showCreate && <ProsjektModal title="Nytt prosjekt" onSave={handleCreate} onClose={() => setShowCreate(false)} saving={saving} projects={projects} />}
    </div>
  )
}

function ProsjektDetaljerPage({ projectId, onBack, onNavigateDetail, onNavigateChecklist }) {
  const { user } = useAuth()
  const isMobH = typeof window !== 'undefined' && window.innerWidth < 768
  const [project, setProject] = useState(null)
  const [allProjects, setAllProjects] = useState([])
  const [checklists, setChecklists] = useState([])
  const [checklistTemplates, setChecklistTemplates] = useState([])
  const [checklistSortBy, setChecklistSortBy] = useState('newest') // 'newest' | 'oldest' | 'alpha' | 'category'
  const [endringsmeldinger, setEndringsmeldinger] = useState([])
  const [loading, setLoading] = useState(true)
  const [showEdit, setShowEdit] = useState(false)
  const [showDelete, setShowDelete] = useState(false)
  const [saving, setSaving] = useState(false)
  const [activeTab, setActiveTab] = useState('ue')
  const [showCreateSub, setShowCreateSub] = useState(false)
  const f = { fontFamily:'system-ui, sans-serif', overflowX:'hidden', maxWidth:'100vw', boxSizing:'border-box' }
  const card = { background:'white', borderRadius: isMobH ? '12px' : '16px', border:'1px solid #f1f5f9', boxShadow:'0 1px 4px rgba(0,0,0,0.04)', padding: isMobH ? '14px' : '24px', overflow:'hidden', wordBreak:'break-word' }

  const load = async () => {
    try {
      const [proj, allProj, clRes, emRes, tmplRes] = await Promise.all([
        db.getProject(projectId),
        db.getProjects(),
        supabase.from('checklists').select('*').eq('project_id', projectId).order('created_at', { ascending: false }),
        supabase.from('endringsmeldinger').select('*').eq('project_id', projectId).order('created_at', { ascending: false }),
        supabase.from('checklist_templates').select('id, category').then(r => r.data || []),
      ])
      setProject(proj)
      setAllProjects(allProj)
      setChecklists(clRes.data || [])
      setEndringsmeldinger(emRes.data || [])
      setChecklistTemplates(tmplRes)
    } catch(e){console.error(e)} finally { setLoading(false) }
  }
  useEffect(() => { load() }, [projectId])

  const handleUpdate = async (form) => {
    setSaving(true)
    try {
      let depth = 0
      if (form.parent_id) {
        const parent = allProjects.find(p => p.id === form.parent_id)
        depth = (parent?.depth || 0) + 1
      }
      await db.updateProject(projectId, sanitizeUuidFields({ ...form, parent_id: form.parent_id || null, depth, address: [form.address_street, `${form.address_postal} ${form.address_city}`.trim()].filter(Boolean).join(', ') || form.address, budget: form.budget ? parseFloat(form.budget) : null }))
      setShowEdit(false); load()
    } catch(e) { alert('Feil: ' + e.message) } finally { setSaving(false) }
  }

  const handleDelete = async () => {
    try {
      const { error } = await supabase.from('projects').delete().eq('id', projectId)
      if (error) { alert('Feil ved sletting: ' + error.message); return }
      onBack()
    } catch(e) { alert('Feil: ' + e.message) }
  }

  const handleArchive = async () => {
    try {
      await db.updateProject(projectId, { status: 'arkivert' })
      onBack()
    } catch(e) { alert('Feil: ' + e.message) }
  }

  if (loading) return <div style={{ ...f, textAlign:'center', padding:'60px', color:'#94a3b8' }}>Laster prosjekt...</div>
  if (!project) return <div style={{ ...f, textAlign:'center', padding:'60px' }}><p>Prosjekt ikke funnet</p><button onClick={onBack} style={{ background:'none', border:'1px solid #e2e8f0', borderRadius:'10px', padding:'8px 16px', cursor:'pointer' }}>← Tilbake</button></div>

  const tabs = [{id:'ue',label: isMobH ? `UE (${project.subcontractors?.length||0})` : `Underentreprenører (${project.subcontractors?.length||0})`},{id:'ark',label: isMobH ? `Arki. (${project.architects?.length||0})` : `Arkitekter (${project.architects?.length||0})`},{id:'rad',label: isMobH ? `Rådg. (${project.consultants?.length||0})` : `Rådgivere (${project.consultants?.length||0})`}]

  const contactCards = (items, empty) => items?.length > 0 ? (
    <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
      {items.map((item,i) => (
        <div key={i} style={{ background:'#f8fafc', borderRadius:'12px', padding: isMobH ? '10px' : '14px', display:'flex', justifyContent:'space-between', flexDirection: isMobH ? 'column' : 'row', gap: isMobH ? '6px' : '0' }}>
          <div>
            <p style={{ margin:'0 0 3px', fontWeight:'600', color:'#0f172a', fontSize: isMobH ? '13px' : '14px' }}>{item.company || item.name}</p>
            {(item.trade||item.discipline) && <p style={{ margin:'0 0 3px', fontSize: isMobH ? '11px' : '13px', color:'#64748b' }}>{item.trade||item.discipline}</p>}
            {item.contact_person && <p style={{ margin:0, fontSize: isMobH ? '11px' : '13px', color:'#475569' }}>{item.contact_person}</p>}
          </div>
          <div style={{ textAlign: isMobH ? 'left' : 'right', display:'flex', flexDirection: isMobH ? 'row' : 'column', gap: isMobH ? '12px' : '4px' }}>
            {item.phone && <a href={`tel:${item.phone}`} style={{ fontSize: isMobH ? '12px' : '13px', color:'#059669', textDecoration:'none' }}>📞 {item.phone}</a>}
            {item.email && <a href={`mailto:${item.email}`} style={{ fontSize: isMobH ? '12px' : '13px', color:'#059669', textDecoration:'none', overflow:'hidden', textOverflow:'ellipsis' }}>✉️ {isMobH ? 'E-post' : item.email}</a>}
          </div>
        </div>
      ))}
    </div>
  ) : <p style={{ color:'#94a3b8', fontSize:'14px', textAlign:'center', padding:'20px', margin:0 }}>{empty}</p>

  const initEdit = { ...project, parent_id: project.parent_id||'', address_street: project.address_street||'', address_postal: project.address_postal||'', address_city: project.address_city||'', budget: project.budget||'', subcontractors: project.subcontractors||[], architects: project.architects||[], consultants: project.consultants||[] }

  const childProjects = allProjects.filter(p => p.parent_id === projectId)
  const parentProject = project.parent_id ? allProjects.find(p => p.id === project.parent_id) : null

  const handleCreateSub = async (form) => {
    setSaving(true)
    try {
      const siblings = allProjects.filter(p => p.parent_id === projectId)
      const depth = (project.depth || 0) + 1
      let projectNumber = form.project_number || (project.project_number
        ? project.project_number + '-' + String(siblings.length + 1).padStart(2, '0')
        : nextSequenceNumber(allProjects, 'P', 'project_number', { withYear: false }))
      // Duplikatsjekk
      const existing = allProjects.find(p => p.project_number?.trim().toUpperCase() === projectNumber.trim().toUpperCase())
      if (existing) {
        projectNumber = projectNumber + 'B'
      }
      await db.createProject(sanitizeUuidFields({ ...form, parent_id: projectId, depth, project_number: projectNumber, address: [form.address_street, `${form.address_postal} ${form.address_city}`.trim()].filter(Boolean).join(', '), budget: form.budget ? parseFloat(form.budget) : null, created_by: user?.id }))
      setShowCreateSub(false); load()
    } catch(e) { alert('Feil: ' + e.message) } finally { setSaving(false) }
  }

  return (
    <div style={f}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobH ? '14px' : '20px 32px' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#64748b', fontSize:'13px', marginBottom:'10px', display:'flex', alignItems:'center', gap:'6px', padding:0, fontFamily:'system-ui, sans-serif' }}>← Tilbake</button>
        {parentProject && (
          <div style={{ marginBottom:'8px', fontSize:'13px', color:'#64748b' }}>
            Overordnet: <button onClick={() => { if (onNavigateDetail) onNavigateDetail(parentProject.id) }} style={{ background:'none', border:'none', cursor:'pointer', color:'#059669', fontWeight:'600', fontSize: isMobH ? '11px' : '13px', padding:0, overflow:'hidden', textOverflow:'ellipsis', maxWidth: isMobH ? '60vw' : 'none' }}>{parentProject.name}</button>
          </div>
        )}
        <div style={{ display:'flex', alignItems: isMobH ? 'flex-start' : 'center', justifyContent:'space-between', gap: isMobH ? '10px' : '16px', flexWrap: isMobH ? 'wrap' : 'nowrap' }}>
          <div style={{ display:'flex', alignItems:'center', gap: isMobH ? '10px' : '14px', flex:1, minWidth:0 }}>
            {!isMobH && <div style={{ width:'52px', height:'52px', borderRadius:'14px', background: project.parent_id ? '#f0fdf4' : '#ecfdf5', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'24px' }}>{project.parent_id ? '📂' : '🏗️'}</div>}
            <div style={{ minWidth:0 }}>
              <div style={{ display:'flex', alignItems:'center', gap: isMobH ? '6px' : '10px', flexWrap:'wrap' }}>
                <h1 style={{ margin:0, fontSize: isMobH ? '17px' : '20px', fontWeight:'bold', color:'#0f172a' }}>{project.name}</h1>
                <StatusBadge status={project.status} />
              </div>
              {project.project_number && <p style={{ margin:'3px 0 0', fontSize: isMobH ? '11px' : '13px', color:'#94a3b8' }}>#{project.project_number}</p>}
            </div>
          </div>
          <div style={{ display:'flex', gap:'6px', width: isMobH ? '100%' : 'auto' }}>
            {project.status === 'arkivert' ? (
              <button onClick={async () => { await db.updateProject(projectId, { status: 'fullfort' }); load() }}
                style={{ padding: isMobH ? '8px 10px' : '9px 16px', border:'1px solid #7c3aed', borderRadius:'10px', background:'#faf5ff', cursor:'pointer', fontSize: isMobH ? '12px' : '14px', fontWeight:'600', color:'#7c3aed', flex: isMobH ? 1 : 'none' }}>📦 {isMobH ? 'Gjenopp.' : 'Gjenopprett'}</button>
            ) : (
              <button onClick={() => setShowCreateSub(true)} style={{ padding: isMobH ? '8px 10px' : '9px 16px', border:'1px solid #059669', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobH ? '12px' : '14px', fontWeight:'500', color:'#059669', flex: isMobH ? 1 : 'none' }}>{isMobH ? '+ Under' : '+ Underprosjekt'}</button>
            )}
            <button onClick={() => setShowEdit(true)} style={{ padding: isMobH ? '8px 10px' : '9px 16px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobH ? '12px' : '14px', fontWeight:'500' }}>✏️</button>
            <button onClick={() => setShowDelete(true)} style={{ padding: isMobH ? '8px 10px' : '9px 14px', border:'1px solid #fecaca', borderRadius:'10px', background:'white', cursor:'pointer', color:'#dc2626', fontSize: isMobH ? '12px' : '14px' }}>🗑️</button>
          </div>
        </div>
        {project.status === 'arkivert' && (
          <div style={{ marginTop:'12px', background:'#f5f3ff', border:'1px solid #e9d5ff', borderRadius:'10px', padding:'10px 16px', display:'flex', alignItems:'center', gap:'10px' }}>
            <span style={{ fontSize:'16px' }}>📦</span>
            <span style={{ fontSize: isMobH ? '11px' : '13px', color:'#7c3aed', fontWeight:'500' }}>{isMobH ? 'Prosjektet er arkivert' : 'Dette prosjektet er arkivert. Det vises ikke i dropdowns eller oversikter med mindre «Vis arkiverte» er aktivert.'}</span>
          </div>
        )}
      </div>

      <div style={{ padding: isMobH ? '12px' : '24px 32px', display:'grid', gridTemplateColumns: isMobH ? '1fr' : '2fr 1fr', gap: isMobH ? '12px' : '20px', overflowX:'hidden', maxWidth:'100%' }}>
        <div style={{ display:'flex', flexDirection:'column', gap: isMobH ? '10px' : '20px', overflow:'hidden', minWidth:0 }}>
          {/* Underprosjekter-seksjon */}
          {childProjects.length > 0 && (
            <div style={card}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'14px' }}>
                <h3 style={{ margin:0, fontSize: isMobH ? '14px' : '15px', fontWeight:'600', color:'#0f172a' }}>📁 Underprosjekter ({childProjects.length})</h3>
                <button onClick={() => setShowCreateSub(true)} style={{ background:'#ecfdf5', color:'#059669', border:'none', borderRadius:'8px', padding: isMobH ? '6px 10px' : '6px 14px', fontSize: isMobH ? '11px' : '12px', fontWeight:'600', cursor:'pointer', flexShrink:0 }}>{isMobH ? '+ Ny' : '+ Legg til'}</button>
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                {childProjects.map(cp => (
                  <div key={cp.id} style={{ background:'#f8fafc', borderRadius:'10px', padding: isMobH ? '10px' : '12px 14px', display:'flex', alignItems:'center', gap: isMobH ? '8px' : '12px', cursor:'pointer' }}
                    onClick={() => { if (onNavigateDetail) onNavigateDetail(cp.id) }}>
                    <div style={{ width:'34px', height:'34px', borderRadius:'8px', background:'#ecfdf5', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'16px', flexShrink:0 }}>📂</div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontWeight:'600', color:'#0f172a', fontSize:'14px' }}>{cp.name}</div>
                      {cp.project_number && <div style={{ fontSize:'12px', color:'#94a3b8' }}>#{cp.project_number}</div>}
                    </div>
                    <StatusBadge status={cp.status} />
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Sjekklister tilknyttet prosjektet */}
          <div style={card}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'14px', gap:'10px', flexWrap:'wrap' }}>
              <h3 style={{ margin:0, fontSize: isMobH ? '14px' : '15px', fontWeight:'600', color:'#0f172a' }}>✅ Sjekklister ({checklists.length})</h3>
              <div style={{ display:'flex', gap:'6px', alignItems:'center', flexWrap:'wrap' }}>
                {checklists.length > 1 && (
                  <select value={checklistSortBy} onChange={e => setChecklistSortBy(e.target.value)} title="Sortering"
                    style={{ padding: isMobH ? '6px 8px' : '6px 10px', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize: isMobH ? '11px' : '12px', background:'white', cursor:'pointer', color:'#475569', fontFamily:'system-ui, sans-serif' }}>
                    <option value="newest">🆕 Nyeste først</option>
                    <option value="oldest">📅 Eldste først</option>
                    <option value="alpha">🔤 Alfabetisk</option>
                    <option value="category">📂 Etter fag</option>
                  </select>
                )}
                {onNavigateChecklist && (
                  <button onClick={() => onNavigateChecklist('new', projectId)}
                    style={{ background:'#ecfdf5', color:'#059669', border:'none', borderRadius:'8px', padding: isMobH ? '6px 10px' : '6px 14px', fontSize: isMobH ? '11px' : '12px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap', flexShrink:0 }}>{isMobH ? '+ Ny' : '+ Ny sjekkliste'}</button>
                )}
              </div>
            </div>
            {checklists.length === 0 ? (
              <p style={{ color:'#94a3b8', fontSize:'13px', margin:0, textAlign:'center', padding:'16px 0' }}>Ingen sjekklister opprettet for dette prosjektet</p>
            ) : (
              <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                {(() => {
                  // Sortér etter valgt kriterium
                  const tmplCatMap = {}
                  checklistTemplates.forEach(t => { if (t.id) tmplCatMap[t.id] = t.category || 'annet' })
                  const sortedList = [...checklists]
                  switch (checklistSortBy) {
                    case 'alpha':
                      sortedList.sort((a, b) => (a.title || '').localeCompare(b.title || '', 'nb')); break
                    case 'oldest':
                      sortedList.sort((a, b) => new Date(a.created_at) - new Date(b.created_at)); break
                    case 'category': {
                      sortedList.sort((a, b) => {
                        const catA = tmplCatMap[a.template_id] || 'annet'
                        const catB = tmplCatMap[b.template_id] || 'annet'
                        const labelA = (CATEGORY_LABELS[catA]?.label || catA).toLowerCase()
                        const labelB = (CATEGORY_LABELS[catB]?.label || catB).toLowerCase()
                        if (labelA !== labelB) return labelA.localeCompare(labelB, 'nb')
                        return (a.title || '').localeCompare(b.title || '', 'nb')
                      })
                      break
                    }
                    case 'newest':
                    default:
                      sortedList.sort((a, b) => new Date(b.created_at) - new Date(a.created_at))
                  }
                  return sortedList
                })().map(cl => {
                  const items = cl.items || []
                  const total = items.length
                  const done = items.filter(i => i.checked).length
                  const pct = total > 0 ? Math.round(done / total * 100) : 0
                  const statusMap = { ikke_startet: ['#f1f5f9','#475569','Ikke startet'], påbegynt: ['#eff6ff','#2563eb','Påbegynt'], fullfort: ['#ecfdf5','#059669','Fullført'] }
                  const [sBg, sColor, sLabel] = statusMap[cl.status] || ['#f1f5f9','#475569', cl.status]
                  return (
                    <div key={cl.id}
                      onClick={() => { if (onNavigateChecklist) onNavigateChecklist(cl.id) }}
                      style={{ background:'#f8fafc', borderRadius:'10px', padding: isMobH ? '10px' : '12px 14px', cursor: onNavigateChecklist ? 'pointer' : 'default', border:'1px solid #f1f5f9', transition:'border-color 0.15s' }}
                      onMouseEnter={e => e.currentTarget.style.borderColor='#e2e8f0'}
                      onMouseLeave={e => e.currentTarget.style.borderColor='#f1f5f9'}>
                      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'8px' }}>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ fontWeight:'600', color:'#0f172a', fontSize: isMobH ? '13px' : '14px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{cl.title}</div>
                          <div style={{ fontSize: isMobH ? '11px' : '12px', color:'#94a3b8', marginTop:'2px' }}>{done}/{total} · {new Date(cl.created_at).toLocaleDateString('nb-NO')}</div>
                        </div>
                        <span style={{ background: sBg, color: sColor, padding:'2px 10px', borderRadius:'999px', fontSize:'11px', fontWeight:'600', flexShrink:0 }}>{sLabel}</span>
                      </div>
                      {/* Fremdriftsbar */}
                      <div style={{ height:'6px', background:'#e2e8f0', borderRadius:'3px', overflow:'hidden' }}>
                        <div style={{ height:'100%', borderRadius:'3px', transition:'width 0.3s',
                          width: `${pct}%`,
                          background: pct === 100 ? '#059669' : pct > 50 ? '#2563eb' : pct > 0 ? '#d97706' : '#e2e8f0'
                        }} />
                      </div>
                      <div style={{ textAlign:'right', marginTop:'4px' }}>
                        <span style={{ fontSize:'11px', fontWeight:'600', color: pct === 100 ? '#059669' : '#64748b' }}>{pct}%</span>
                      </div>
                    </div>
                  )
                })}
              </div>
            )}
          </div>

          <div style={card}>
            <h3 style={{ margin:'0 0 12px', fontSize: isMobH ? '14px' : '15px', fontWeight:'600', color:'#0f172a' }}>Prosjektinformasjon</h3>
            <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
              {project.address && <div style={{ background:'#f8fafc', borderRadius:'10px', padding: isMobH ? '10px' : '12px' }}><p style={{ margin:'0 0 3px', fontSize:'11px', color:'#94a3b8', textTransform:'uppercase' }}>Adresse</p><p style={{ margin:0, fontSize: isMobH ? '13px' : '14px', fontWeight:'500', color:'#0f172a', wordBreak:'break-word' }}>{project.address}</p></div>}
              {(project.start_date||project.end_date) && <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px' }}><p style={{ margin:'0 0 3px', fontSize:'11px', color:'#94a3b8', textTransform:'uppercase' }}>Periode</p><p style={{ margin:0, fontSize:'14px', fontWeight:'500', color:'#0f172a' }}>{project.start_date && new Date(project.start_date).toLocaleDateString('nb-NO')}{project.end_date && ` – ${new Date(project.end_date).toLocaleDateString('nb-NO')}`}</p></div>}
              {project.budget && <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px' }}><p style={{ margin:'0 0 3px', fontSize:'11px', color:'#94a3b8', textTransform:'uppercase' }}>Budsjett</p><p style={{ margin:0, fontSize:'14px', fontWeight:'500', color:'#0f172a' }}>{Number(project.budget).toLocaleString('nb-NO')} kr</p></div>}
            </div>
            {project.description && <p style={{ margin:'16px 0 0', fontSize:'14px', color:'#475569', lineHeight:1.6 }}>{project.description}</p>}
          </div>

          <div style={card}>
            <div style={{ display:'flex', borderBottom:'1px solid #f1f5f9', marginBottom:'12px', marginLeft: isMobH ? '-14px' : '-24px', marginRight: isMobH ? '-14px' : '-24px', paddingLeft: isMobH ? '10px' : '24px', overflowX:'auto', WebkitOverflowScrolling:'touch', gap:'0' }}>
              {tabs.map(t => <button key={t.id} onClick={() => setActiveTab(t.id)} style={{ padding: isMobH ? '8px 10px' : '10px 16px', border:'none', cursor:'pointer', fontSize: isMobH ? '11px' : '13px', fontWeight: activeTab===t.id ? '600':'400', background:'transparent', color: activeTab===t.id ? '#059669':'#64748b', borderBottom: activeTab===t.id ? '2px solid #059669':'2px solid transparent', fontFamily:'system-ui, sans-serif', whiteSpace:'nowrap' }}>{t.label}</button>)}
            </div>
            {activeTab==='ue' && contactCards(project.subcontractors, 'Ingen underentreprenører registrert')}
            {activeTab==='ark' && contactCards(project.architects, 'Ingen arkitekter registrert')}
            {activeTab==='rad' && contactCards(project.consultants, 'Ingen rådgivere registrert')}
          </div>
        </div>

        <div style={{ display:'flex', flexDirection:'column', gap: isMobH ? '10px' : '16px', overflow:'hidden', minWidth:0 }}>
          {/* Endringsmeldinger-sammendrag */}
          {endringsmeldinger.length > 0 && (() => {
            const godkjent = endringsmeldinger.filter(e => e.status === 'Godkjent' || e.status === 'Fakturert')
            const avventer = endringsmeldinger.filter(e => e.status === 'Sendt' || e.status === 'Under forhandling')
            const totalGodkjent = godkjent.reduce((s, e) => s + (parseFloat(e.amount) || 0), 0)
            const totalAvventer = avventer.reduce((s, e) => s + (parseFloat(e.amount) || 0), 0)
            const totalAlle = endringsmeldinger.reduce((s, e) => s + (parseFloat(e.amount) || 0), 0)
            return (
              <div style={card}>
                <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🔄 Endringsmeldinger ({endringsmeldinger.length})</h3>
                {/* Akkumulert beløp */}
                <div style={{ background:'#f0fdf4', borderRadius:'12px', padding:'14px', border:'1px solid #bbf7d0', textAlign:'center', marginBottom:'12px' }}>
                  <div style={{ fontSize:'11px', color:'#16a34a', fontWeight:'600', marginBottom:'2px' }}>GODKJENT TILLEGGSARBEID</div>
                  <div style={{ fontSize: isMobH ? '18px' : '22px', fontWeight:'800', color:'#059669' }}>{Math.round(totalGodkjent).toLocaleString('nb-NO')} kr</div>
                </div>
                {/* Avventende */}
                {totalAvventer > 0 && (
                  <div style={{ background:'#fffbeb', borderRadius:'10px', padding:'10px 12px', border:'1px solid #fde68a', marginBottom:'12px', textAlign:'center' }}>
                    <div style={{ fontSize:'10px', color:'#d97706', fontWeight:'600', marginBottom:'2px' }}>AVVENTER GODKJENNING</div>
                    <div style={{ fontSize:'16px', fontWeight:'700', color:'#d97706' }}>{Math.round(totalAvventer).toLocaleString('nb-NO')} kr</div>
                    <div style={{ fontSize:'11px', color:'#92400e', marginTop:'2px' }}>{avventer.length} endringsmelding{avventer.length !== 1 ? 'er' : ''}</div>
                  </div>
                )}
                {/* Budsjett-kontekst */}
                {project.budget && (
                  <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'10px 12px', marginBottom:'12px' }}>
                    <div style={{ display:'flex', justifyContent:'space-between', fontSize: isMobH ? '11px' : '12px', marginBottom:'4px', gap:'4px' }}>
                      <span style={{ color:'#64748b', flexShrink:0 }}>Budsjett</span>
                      <span style={{ fontWeight:'600', color:'#0f172a' }}>{Number(project.budget).toLocaleString('nb-NO')} kr</span>
                    </div>
                    <div style={{ display:'flex', justifyContent:'space-between', fontSize: isMobH ? '11px' : '12px', marginBottom:'4px', gap:'4px' }}>
                      <span style={{ color:'#059669', flexShrink:0 }}>{isMobH ? '+ Endringer' : '+ Godkjente endringer'}</span>
                      <span style={{ fontWeight:'600', color:'#059669', textAlign:'right' }}>+{Math.round(totalGodkjent).toLocaleString('nb-NO')} kr</span>
                    </div>
                    <div style={{ height:'1px', background:'#e2e8f0', margin:'6px 0' }} />
                    <div style={{ display:'flex', justifyContent:'space-between', fontSize: isMobH ? '12px' : '13px', gap:'4px' }}>
                      <span style={{ fontWeight:'700', color:'#0f172a', flexShrink:0 }}>{isMobH ? 'Justert' : 'Justert budsjett'}</span>
                      <span style={{ fontWeight:'800', color:'#0f172a', textAlign:'right' }}>{Math.round(Number(project.budget) + totalGodkjent).toLocaleString('nb-NO')} kr</span>
                    </div>
                    <div style={{ marginTop:'8px', height:'6px', background:'#e2e8f0', borderRadius:'3px', overflow:'hidden' }}>
                      <div style={{ height:'100%', borderRadius:'3px', background:'#059669', width: `${Math.min(100, (Number(project.budget) / (Number(project.budget) + totalGodkjent)) * 100)}%` }} />
                    </div>
                    <div style={{ display:'flex', justifyContent:'space-between', fontSize:'10px', color:'#94a3b8', marginTop:'4px' }}>
                      <span>Oppr.</span>
                      <span>+{(totalGodkjent / Number(project.budget) * 100).toFixed(1)}%</span>
                    </div>
                  </div>
                )}
                {/* Liste over siste EM-er */}
                <div style={{ display:'flex', flexDirection:'column', gap:'4px' }}>
                  {endringsmeldinger.slice(0, 5).map(em => {
                    const emSt = { Utkast:'#64748b', Sendt:'#2563eb', Godkjent:'#16a34a', Avvist:'#dc2626', 'Under forhandling':'#d97706', Fakturert:'#7c3aed' }[em.status] || '#64748b'
                    return (
                      <div key={em.id} style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize: isMobH ? '11px' : '12px', gap:'6px' }}>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ fontWeight:'600', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{em.title}</div>
                          <div style={{ display:'flex', gap:'6px', alignItems:'center', marginTop:'1px' }}>
                            <span style={{ color:'#94a3b8', fontSize:'11px' }}>{em.em_number}</span>
                            <span style={{ color: emSt, fontSize:'10px', fontWeight:'600' }}>{em.status}</span>
                          </div>
                        </div>
                        <span style={{ fontWeight:'700', color: emSt, fontSize: isMobH ? '11px' : '12px', flexShrink:0, marginLeft:'6px' }}>{Math.round(em.amount || 0).toLocaleString('nb-NO')}</span>
                      </div>
                    )
                  })}
                  {endringsmeldinger.length > 5 && <div style={{ fontSize:'11px', color:'#94a3b8', textAlign:'center', paddingTop:'4px' }}>+ {endringsmeldinger.length - 5} flere</div>}
                </div>
              </div>
            )
          })()}

          <div style={card}>
            <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>👷 Prosjektleder</h3>
            {project.project_manager_name ? <div style={{ display:'flex', flexDirection:'column', gap:'6px', wordBreak:'break-word' }}><p style={{ margin:0, fontWeight:'600', color:'#0f172a', fontSize: isMobH ? '13px' : '14px' }}>{project.project_manager_name}</p>{project.project_manager_email && <a href={`mailto:${project.project_manager_email}`} style={{ fontSize: isMobH ? '11px' : '13px', color:'#059669', textDecoration:'none', overflow:'hidden', textOverflow:'ellipsis', display:'block' }}>✉️ {project.project_manager_email}</a>}{project.project_manager_phone && <a href={`tel:${project.project_manager_phone}`} style={{ fontSize: isMobH ? '12px' : '13px', color:'#059669', textDecoration:'none' }}>📞 {project.project_manager_phone}</a>}</div> : <p style={{ color:'#94a3b8', fontSize:'13px', margin:0 }}>Ikke tildelt</p>}
          </div>
          <div style={card}>
            <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🏢 Kunde</h3>
            {project.client_name ? <div style={{ display:'flex', flexDirection:'column', gap:'6px', wordBreak:'break-word' }}><p style={{ margin:0, fontWeight:'600', color:'#0f172a', fontSize: isMobH ? '13px' : '14px' }}>{project.client_name}</p>{project.client_contact && <p style={{ margin:0, fontSize: isMobH ? '11px' : '13px', color:'#475569' }}>👤 {project.client_contact}</p>}{project.client_email && <a href={`mailto:${project.client_email}`} style={{ fontSize: isMobH ? '11px' : '13px', color:'#059669', textDecoration:'none', overflow:'hidden', textOverflow:'ellipsis', display:'block' }}>✉️ {project.client_email}</a>}{project.client_phone && <a href={`tel:${project.client_phone}`} style={{ fontSize: isMobH ? '12px' : '13px', color:'#059669', textDecoration:'none' }}>📞 {project.client_phone}</a>}</div> : <p style={{ color:'#94a3b8', fontSize:'13px', margin:0 }}>Ingen kundeinformasjon</p>}
          </div>
          {(project.resident_name||project.resident_phone||project.resident_email) && (
            <div style={card}>
              <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🏠 Beboer / Kontakt</h3>
              <div style={{ display:'flex', flexDirection:'column', gap:'6px', wordBreak:'break-word' }}>
                {project.resident_name && <p style={{ margin:0, fontWeight:'600', color:'#0f172a', fontSize:'14px' }}>{project.resident_name}</p>}
                {project.resident_phone && <a href={`tel:${project.resident_phone}`} style={{ fontSize:'13px', color:'#059669', textDecoration:'none' }}>📞 {project.resident_phone}</a>}
                {project.resident_email && <a href={`mailto:${project.resident_email}`} style={{ fontSize:'13px', color:'#059669', textDecoration:'none' }}>✉️ {project.resident_email}</a>}
              </div>
            </div>
          )}
        </div>
      </div>

      {showEdit && <ProsjektModal title="Rediger prosjekt" initial={initEdit} onSave={handleUpdate} onClose={() => setShowEdit(false)} saving={saving} projects={allProjects} />}
      {showCreateSub && <ProsjektModal title={`Nytt underprosjekt under ${project.name}`} initial={{ ...emptyProsjekt, parent_id: projectId, client_name: project.client_name, client_contact: project.client_contact, client_email: project.client_email, client_phone: project.client_phone }} onSave={handleCreateSub} onClose={() => setShowCreateSub(false)} saving={saving} projects={allProjects} />}
      {showDelete && (
        <>
          <div onClick={() => setShowDelete(false)} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.4)', zIndex:100 }} />
          <div style={{ position:'fixed', top: isMobH ? 'auto' : '50%', bottom: isMobH ? 0 : 'auto', left: isMobH ? 0 : '50%', right: isMobH ? 0 : 'auto', transform: isMobH ? 'none' : 'translate(-50%,-50%)', background:'white', borderRadius: isMobH ? '20px 20px 0 0' : '20px', padding: isMobH ? '20px' : '28px', width: isMobH ? '100%' : 'min(440px, calc(100vw - 32px))', zIndex:101, fontFamily:'system-ui, sans-serif', maxHeight: isMobH ? '80vh' : 'none', overflowY:'auto' }}>
            <h3 style={{ margin:'0 0 8px', fontSize:'17px', fontWeight:'700', color:'#0f172a' }}>Hva vil du gjøre med prosjektet?</h3>
            <p style={{ margin:'0 0 24px', color:'#64748b', fontSize:'14px', lineHeight:1.5 }}><strong>{project.name}</strong>{project.project_number ? ` (${project.project_number})` : ''}</p>

            <div style={{ display:'flex', flexDirection:'column', gap:'10px', marginBottom:'20px' }}>
              <button onClick={handleArchive}
                style={{ padding:'16px 18px', borderRadius:'14px', border:'1px solid #e9d5ff', background:'#faf5ff', cursor:'pointer', textAlign:'left', display:'flex', alignItems:'flex-start', gap:'14px' }}
                onMouseEnter={e => e.currentTarget.style.borderColor='#c084fc'}
                onMouseLeave={e => e.currentTarget.style.borderColor='#e9d5ff'}>
                <span style={{ fontSize:'24px', flexShrink:0, marginTop:'2px' }}>📦</span>
                <div>
                  <div style={{ fontWeight:'700', color:'#7c3aed', fontSize:'14px', marginBottom:'4px' }}>Arkiver prosjekt</div>
                  <div style={{ fontSize:'13px', color:'#64748b', lineHeight:1.4 }}>Prosjektet skjules fra oversikten og dropdowns, men all data beholdes. Du kan gjenopprette det senere.</div>
                </div>
              </button>

              <button onClick={handleDelete}
                style={{ padding:'16px 18px', borderRadius:'14px', border:'1px solid #fecaca', background:'#fef2f2', cursor:'pointer', textAlign:'left', display:'flex', alignItems:'flex-start', gap:'14px' }}
                onMouseEnter={e => e.currentTarget.style.borderColor='#f87171'}
                onMouseLeave={e => e.currentTarget.style.borderColor='#fecaca'}>
                <span style={{ fontSize:'24px', flexShrink:0, marginTop:'2px' }}>🗑️</span>
                <div>
                  <div style={{ fontWeight:'700', color:'#dc2626', fontSize:'14px', marginBottom:'4px' }}>Slett permanent</div>
                  <div style={{ fontSize:'13px', color:'#64748b', lineHeight:1.4 }}>Prosjektet og all tilknyttet data slettes permanent. Dette kan ikke angres.</div>
                </div>
              </button>
            </div>

            <div style={{ display:'flex', justifyContent:'flex-end' }}>
              <button onClick={() => setShowDelete(false)} style={{ padding:'9px 18px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            </div>
          </div>
        </>
      )}
    </div>
  )
}

// ─── PROSJEKTFILER PAGE ───────────────────────────────────────────────────
const FILE_CATEGORIES = [
  { id: 'tegninger',    name: 'Tegninger / Planer',             emoji: '📐', color: '#3b82f6', bg: '#eff6ff',
    sub: ['Arkitekttegninger', 'Konstruksjonstegninger', 'Elektrisk / VVS'], revisjon: true },
  { id: 'beskrivelser', name: 'Beskrivelser / Spesifikasjoner', emoji: '📄', color: '#10b981', bg: '#f0fdf4', sub: [], revisjon: true },
  { id: 'kontrakt',     name: 'Kontrakt / Avtaler',             emoji: '📋', color: '#f59e0b', bg: '#fffbeb', sub: [], revisjon: false },
  { id: 'okonomi',      name: 'Økonomi',                        emoji: '💰', color: '#ef4444', bg: '#fef2f2', sub: [], revisjon: false },
  { id: 'motereferater',name: 'Møtereferater / Kommunikasjon',  emoji: '📝', color: '#8b5cf6', bg: '#f5f3ff', sub: [], revisjon: false },
  { id: 'tillatelser',  name: 'Tillatelser / Sertifikater',     emoji: '🏅', color: '#06b6d4', bg: '#ecfeff', sub: [], revisjon: false },
  { id: 'bilder',       name: 'Bilder',                         emoji: '🖼️', color: '#ec4899', bg: '#fdf2f8', sub: [], revisjon: false },
  { id: 'annet',        name: 'Annet',                          emoji: '📎', color: '#6b7280', bg: '#f8fafc', sub: [], revisjon: false },
]

const formatFileSize = (bytes) => {
  if (!bytes) return ''
  if (bytes < 1024) return `${bytes} B`
  if (bytes < 1024 * 1024) return `${(bytes/1024).toFixed(1)} KB`
  return `${(bytes/(1024*1024)).toFixed(1)} MB`
}

const getFileEmoji = (name, type) => {
  const ext = name?.split('.').pop()?.toLowerCase() || type?.toLowerCase() || ''
  if (['jpg','jpeg','png','gif','webp','svg'].includes(ext)) return '🖼️'
  if (['pdf'].includes(ext)) return '📕'
  if (['doc','docx'].includes(ext)) return '📘'
  if (['xls','xlsx'].includes(ext)) return '📗'
  if (['dwg','dxf'].includes(ext)) return '📐'
  return '📄'
}

function nextRevision(existingRevisions) {
  const nums = existingRevisions.map(r => parseInt((r.revision_label||'Rev00').replace(/\D/g,''))||0)
  const max = nums.length ? Math.max(...nums) : 0
  return `Rev${String(max+1).padStart(2,'0')}`
}

function ProsjektfilerPage() {
  const { user } = useAuth()
  const [files, setFiles] = useState([])
  const [projects, setProjects] = useState([])
  const [loading, setLoading] = useState(true)
  const [uploading, setUploading] = useState(false)
  const [search, setSearch] = useState('')
  const [selectedProject, setSelectedProject] = useState('all')
  const [selectedCategory, setSelectedCategory] = useState(null)
  const [selectedSub, setSelectedSub] = useState(null)
  const [showUpload, setShowUpload] = useState(false)
  const [uploadForm, setUploadForm] = useState({ project_id: '', category: 'annet', sub: '', description: '', access_level: 'alle' })
  const [uploadFiles, setUploadFiles] = useState([])
  const [expandedCats, setExpandedCats] = useState({})
  const [showArchive, setShowArchive] = useState(false)
  const [deleteTarget, setDeleteTarget] = useState(null) // file to confirm delete
  const [isDraggingOver, setIsDraggingOver] = useState(false)
  const dragCounter = React.useRef(0)
  const isMob = typeof window !== 'undefined' && window.innerWidth < 768
  const fileInputRef = React.useRef()
  const inp = { width: '100%', padding: '9px 12px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '14px', outline: 'none', boxSizing: 'border-box' }

  // ── Drag-and-drop handlers for hele siden ──────────────────────────────
  const handleDragEnter = (e) => {
    e.preventDefault(); e.stopPropagation()
    dragCounter.current++
    if (e.dataTransfer?.types?.includes('Files')) setIsDraggingOver(true)
  }
  const handleDragLeave = (e) => {
    e.preventDefault(); e.stopPropagation()
    dragCounter.current--
    if (dragCounter.current === 0) setIsDraggingOver(false)
  }
  const handleDragOver = (e) => { e.preventDefault(); e.stopPropagation() }
  const handleDrop = (e) => {
    e.preventDefault(); e.stopPropagation()
    dragCounter.current = 0
    setIsDraggingOver(false)
    const droppedFiles = Array.from(e.dataTransfer?.files || [])
    if (droppedFiles.length === 0) return
    setUploadFiles(droppedFiles)
    // Pre-fill prosjekt og kategori hvis allerede valgt
    setUploadForm(f => ({
      ...f,
      project_id: f.project_id || (selectedProject !== 'all' ? selectedProject : ''),
      category: selectedCategory || f.category || 'annet',
      sub: selectedSub || f.sub || '',
    }))
    setShowUpload(true)
  }

  // ── Data loading ──────────────────────────────────────────────────────────
  const loadData = async () => {
    setLoading(true)
    try {
      const [filesRes, projRes] = await Promise.all([
        supabase.from('project_files').select('*').order('created_at', { ascending: false }),
        supabase.from('projects').select('id, name, parent_id, depth, project_number').order('name')
      ])
      setFiles(filesRes.data || [])
      setProjects(projRes.data || [])
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }

  useEffect(() => { loadData() }, [])

  // ── Derived data ──────────────────────────────────────────────────────────
  const projectFiles = React.useMemo(() =>
    files.filter(f => selectedProject === 'all' || f.project_id === selectedProject),
    [files, selectedProject]
  )

  const countForCat = (catId) => {
    if (selectedProject === 'all') return 0
    const active = projectFiles.filter(f => f.category === catId && !f.archived)
    const unique = new Set(active.map(f => f.document_group || f.id))
    return unique.size
  }

  const countForSub = (catId, sub) => {
    if (selectedProject === 'all') return 0
    const active = projectFiles.filter(f => f.category === catId && f.sub_folder === sub && !f.archived)
    const unique = new Set(active.map(f => f.document_group || f.id))
    return unique.size
  }

  const allPanelFiles = React.useMemo(() => {
    if (!selectedCategory) return []
    return projectFiles.filter(f => {
      if (f.category !== selectedCategory) return false
      if (selectedSub && f.sub_folder !== selectedSub) return false
      if (search && !f.name?.toLowerCase().includes(search.toLowerCase())) return false
      return true
    })
  }, [projectFiles, selectedCategory, selectedSub, search])

  // archived can be true, false, null, or undefined (if column doesn't exist yet)
  const activePanelFiles = React.useMemo(() =>
    allPanelFiles.filter(f => f.archived !== true),
    [allPanelFiles]
  )
  const archivedPanelFiles = React.useMemo(() =>
    allPanelFiles.filter(f => f.archived === true),
    [allPanelFiles]
  )

  // Group by document_group — each group shows as one document with revisions
  const fileGroups = React.useMemo(() => {
    const groups = {}
    activePanelFiles.forEach(f => {
      const key = f.document_group || f.id
      if (!groups[key]) groups[key] = []
      groups[key].push(f)
    })
    Object.values(groups).forEach(g => g.sort((a,b) => {
      const an = parseInt((a.revision_label||'Rev00').replace(/\D/g,''))||0
      const bn = parseInt((b.revision_label||'Rev00').replace(/\D/g,''))||0
      return bn - an
    }))
    return Object.values(groups)
  }, [activePanelFiles])

  const selectedCat = FILE_CATEGORIES.find(c => c.id === selectedCategory)
  const catSupportsRevision = selectedCat?.revisjon || false

  // ── Handlers ──────────────────────────────────────────────────────────────
  const handleUpload = async (e) => {
    e.preventDefault()
    if (uploadFiles.length === 0) return alert('Velg minst én fil')
    if (!uploadForm.project_id) return alert('Velg et prosjekt')
    setUploading(true)
    try {
      for (const file of uploadFiles) {
        const ext = file.name.split('.').pop()
        const path = `projects/${uploadForm.project_id}/${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`
        const { error: upErr } = await supabase.storage.from('plattform-files').upload(path, file)
        if (upErr) throw upErr
        const { error: dbErr } = await supabase.from('project_files').insert({
          name: file.name,
          project_id: uploadForm.project_id,
          file_url: path,
          file_type: ext,
          file_size: file.size,
          category: uploadForm.category,
          sub_folder: uploadForm.sub || null,
          description: uploadForm.description || null,
          access_level: uploadForm.access_level,
          uploaded_by: user?.id,
          revision_label: 'Rev01',
          archived: false,
        })
        if (dbErr) throw dbErr
      }
      setShowUpload(false)
      setUploadFiles([])
      setUploadForm({ project_id: '', category: 'annet', sub: '', description: '', access_level: 'alle' })
      await loadData()
    } catch(e) { alert('Feil ved opplasting: ' + e.message) }
    finally { setUploading(false) }
  }

  // ── Ny revisjon med endringsmerknad ─────────────────────────────────────
  const [revisionTarget, setRevisionTarget] = useState(null) // { baseFile, newFile }
  const [revisionNote, setRevisionNote] = useState('')

  const handleNewRevision = async (e, baseFile) => {
    const file = e.target.files?.[0]
    if (!file) return
    // Åpne revisjonsmerknad-modal i stedet for å laste opp direkte
    setRevisionTarget({ baseFile, newFile: file })
    setRevisionNote('')
  }

  const confirmNewRevision = async () => {
    if (!revisionTarget) return
    const { baseFile, newFile } = revisionTarget
    setUploading(true)
    try {
      const docGroup = baseFile.document_group || baseFile.id
      const allRevisions = files.filter(f => (f.document_group || f.id) === docGroup)
      const newLabel = nextRevision(allRevisions)

      // 1. Arkiver gammel revisjon
      const { error: archErr } = await supabase.from('project_files')
        .update({ archived: true, document_group: docGroup })
        .eq('id', baseFile.id)
      if (archErr) {
        alert('Feil: Kunne ikke arkivere gammel revisjon.\n\nKjør denne SQL-en i Supabase:\n\nALTER TABLE project_files ADD COLUMN IF NOT EXISTS archived boolean DEFAULT false;\nALTER TABLE project_files ADD COLUMN IF NOT EXISTS document_group text;\nALTER TABLE project_files ADD COLUMN IF NOT EXISTS revision_label text DEFAULT \'Rev01\';\nALTER TABLE project_files ADD COLUMN IF NOT EXISTS sub_folder text;\nALTER TABLE project_files ADD COLUMN IF NOT EXISTS revision_note text;\nALTER TABLE project_files ADD COLUMN IF NOT EXISTS revision_log jsonb DEFAULT \'[]\'::jsonb;')
        return
      }

      // 2. Last opp ny fil til storage
      const ext = newFile.name.split('.').pop()
      const path = `projects/${baseFile.project_id}/${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`
      const { error: upErr } = await supabase.storage.from('plattform-files').upload(path, newFile)
      if (upErr) throw new Error('Filopplasting feilet: ' + upErr.message)

      // 3. Bygg endringslogg — kopier eksisterende + legg til ny
      const existingLog = baseFile.revision_log || []
      const newLog = [
        ...existingLog,
        {
          revision: newLabel,
          previous_revision: baseFile.revision_label || 'Rev01',
          date: new Date().toISOString(),
          user_email: user?.email || 'Ukjent',
          note: revisionNote.trim() || 'Ny revisjon lastet opp',
          file_size: newFile.size,
          prev_file_size: baseFile.file_size || null,
        }
      ]

      // 4. Lagre ny revisjon i database
      const { error: insErr } = await supabase.from('project_files').insert({
        name: baseFile.name,
        project_id: baseFile.project_id,
        file_url: path,
        file_type: ext,
        file_size: newFile.size,
        category: baseFile.category,
        sub_folder: baseFile.sub_folder || null,
        description: baseFile.description || null,
        access_level: baseFile.access_level || 'alle',
        uploaded_by: user?.id,
        revision_label: newLabel,
        document_group: docGroup,
        archived: false,
        revision_note: revisionNote.trim() || null,
        revision_log: newLog,
      })
      if (insErr) throw new Error('Lagring feilet: ' + insErr.message)

      setRevisionTarget(null)
      setRevisionNote('')
      await loadData()
    } catch(e) { alert(e.message) }
    finally { setUploading(false) }
  }

  const handleDownload = async (file) => {
    try {
      const { data, error } = await supabase.storage.from('plattform-files').download(file.file_url)
      if (error) throw error
      const url = URL.createObjectURL(data)
      const a = document.createElement('a')
      a.href = url; a.download = file.name; a.click()
      URL.revokeObjectURL(url)
    } catch(e) { alert('Feil ved nedlasting: ' + e.message) }
  }

  // Show local confirm dialog then delete
  const handleDelete = (file) => setDeleteTarget(file)

  const confirmDelete = async () => {
    const file = deleteTarget
    setDeleteTarget(null)
    try {
      try { await supabase.storage.from('plattform-files').remove([file.file_url]) } catch(_) {}
      const { error } = await supabase.from('project_files').delete().eq('id', file.id)
      if (error) { alert('Feil ved sletting: ' + error.message); return }
      await loadData()
    } catch(e) { alert('Feil ved sletting: ' + e.message) }
  }

  const toggleCat = (catId) => setExpandedCats(p => ({ ...p, [catId]: !p[catId] }))

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', display: 'flex', flexDirection: 'column', height: '100%', position: 'relative' }}
      onDragEnter={handleDragEnter}
      onDragLeave={handleDragLeave}
      onDragOver={handleDragOver}
      onDrop={handleDrop}>

      {/* Global drag-and-drop overlay */}
      {isDraggingOver && (
        <div style={{ position: 'absolute', inset: 0, zIndex: 50, background: 'rgba(5, 150, 105, 0.08)', border: '3px dashed #059669', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', pointerEvents: 'none' }}>
          <div style={{ background: 'white', borderRadius: '20px', padding: '32px 48px', boxShadow: '0 12px 40px rgba(0,0,0,0.15)', textAlign: 'center' }}>
            <div style={{ fontSize: '48px', marginBottom: '12px' }}>📂</div>
            <h3 style={{ margin: '0 0 6px', fontSize: '18px', fontWeight: '700', color: '#059669' }}>Slipp filer her</h3>
            <p style={{ margin: 0, fontSize: '14px', color: '#64748b' }}>Filene legges til i opplastingsskjemaet</p>
          </div>
        </div>
      )}
      {/* Sticky header + prosjektvelger — st\u00e5r i ro n\u00e5r man scroller i filpanelet */}
      <div style={{ position: 'sticky', top: isMob ? '52px' : '56px', zIndex: 20, background: 'white', flexShrink: 0 }}>
        {/* Header */}
        <div style={{ background: 'white', borderBottom: '1px solid #e2e8f0', padding: isMob ? '14px 16px' : '20px 32px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <h1 style={{ margin: 0, fontSize: isMob ? '18px' : '22px', fontWeight: 'bold', color: '#0f172a' }}>Prosjektfiler</h1>
          <button onClick={() => setShowUpload(true)} style={{ background: '#059669', color: 'white', border: 'none', borderRadius: '10px', padding: isMob ? '8px 14px' : '10px 18px', fontSize: isMob ? '13px' : '14px', fontWeight: '600', cursor: 'pointer' }}>
            ⬆️ {isMob ? 'Last opp' : 'Last opp fil'}
          </button>
        </div>

        {/* Project selector */}
        <div style={{ background: 'white', borderBottom: '1px solid #f1f5f9', padding: isMob ? '10px 16px' : '12px 32px' }}>
          <SearchableProjectSelect value={selectedProject} onChange={v => { setSelectedProject(v); setSelectedCategory(null); setSelectedSub(null) }} projects={projects} style={{ padding: '8px 12px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '14px', outline: 'none', background: 'white', cursor: 'pointer', fontWeight: '500', color: selectedProject === 'all' ? '#94a3b8' : '#0f172a', width: isMob ? '100%' : 'auto', minWidth: isMob ? 'auto' : '200px', boxSizing: 'border-box' }} placeholder="Velg prosjekt" emptyValue="all" />
        </div>
      </div>

      {/* MOBIL: Stacked layout */}
      {isMob ? (
        <div style={{ flex: 1, overflowY: 'auto', padding: '12px 16px' }}>
          {selectedProject === 'all' ? (
            <div style={{ textAlign: 'center', padding: '40px 16px' }}>
              <div style={{ fontSize: '40px', marginBottom: '10px' }}>🏗️</div>
              <div style={{ fontSize: '15px', fontWeight: '600', color: '#64748b' }}>Velg et prosjekt</div>
              <div style={{ fontSize: '12px', color: '#94a3b8', marginTop: '4px' }}>Velg prosjekt i feltet over</div>
            </div>
          ) : !selectedCategory ? (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
              {FILE_CATEGORIES.map(cat => {
                const catCount = countForCat(cat.id)
                const hasSubs = cat.sub.length > 0
                const isExpanded = expandedCats[cat.id]
                return (
                  <div key={cat.id}>
                    <button onClick={() => { if (hasSubs) { toggleCat(cat.id) } else { setSelectedCategory(cat.id); setSelectedSub(null); setShowArchive(false) } }}
                      style={{ width: '100%', display: 'flex', alignItems: 'center', gap: '12px', padding: '14px 16px', borderRadius: '12px', border: '1px solid #f1f5f9', background: 'white', cursor: 'pointer', textAlign: 'left' }}>
                      <div style={{ width: '36px', height: '36px', borderRadius: '10px', background: cat.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '16px', flexShrink: 0 }}>{cat.emoji}</div>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontSize: '14px', fontWeight: '600', color: '#0f172a' }}>{cat.name}</div>
                        <div style={{ fontSize: '12px', color: '#94a3b8' }}>{cat.label}</div>
                      </div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                        <span style={{ fontSize: '13px', fontWeight: '600', color: catCount > 0 ? '#059669' : '#94a3b8' }}>{catCount} fil{catCount !== 1 ? 'er' : ''}</span>
                        <span style={{ color: '#cbd5e1', fontSize: '16px' }}>{hasSubs ? (isExpanded ? '▾' : '▸') : '›'}</span>
                      </div>
                    </button>
                    {hasSubs && isExpanded && (
                      <div style={{ paddingLeft: '20px', display: 'flex', flexDirection: 'column', gap: '4px', marginTop: '4px' }}>
                        {cat.sub.map(sub => {
                          const subCount = countForSub(cat.id, sub)
                          return (
                            <button key={sub} onClick={() => { setSelectedCategory(cat.id); setSelectedSub(sub); setShowArchive(false) }}
                              style={{ width: '100%', display: 'flex', alignItems: 'center', gap: '10px', padding: '10px 14px', borderRadius: '10px', border: '1px solid #f1f5f9', background: '#f8fafc', cursor: 'pointer', textAlign: 'left' }}>
                              <span style={{ fontSize: '14px' }}>📂</span>
                              <span style={{ flex: 1, fontSize: '13px', fontWeight: '500', color: '#374151' }}>{sub}</span>
                              <span style={{ fontSize: '12px', color: '#94a3b8' }}>{subCount}</span>
                              <span style={{ color: '#cbd5e1' }}>›</span>
                            </button>
                          )
                        })}
                      </div>
                    )}
                  </div>
                )
              })}
            </div>
          ) : (
            <>
              <button onClick={() => { setSelectedCategory(null); setSelectedSub(null) }}
                style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#059669', fontSize: '13px', fontWeight: '600', padding: '0 0 10px', display: 'flex', alignItems: 'center', gap: '4px' }}>
                ← Tilbake til kategorier
              </button>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' }}>
                <div style={{ position: 'relative', flex: 1 }}>
                  <span style={{ position: 'absolute', left: '10px', top: '50%', transform: 'translateY(-50%)', color: '#94a3b8', fontSize: '13px' }}>🔍</span>
                  <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Søk etter filer..."
                    style={{ width: '100%', paddingLeft: '32px', padding: '8px 12px 8px 32px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '13px', outline: 'none', boxSizing: 'border-box' }} />
                </div>
                <button onClick={() => { setUploadForm(f => ({ ...f, category: selectedCategory, sub: selectedSub || '' })); setShowUpload(true) }}
                  style={{ padding: '8px 12px', background: '#059669', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontSize: '18px', flexShrink: 0 }}>⬆️</button>
              </div>
              {catSupportsRevision && (
                <button onClick={() => setShowArchive(v => !v)}
                  style={{ width: '100%', padding: '8px', background: showArchive ? '#f0fdf4' : 'white', color: showArchive ? '#059669' : '#64748b', border: `1px solid ${showArchive ? '#bbf7d0' : '#e2e8f0'}`, borderRadius: '10px', cursor: 'pointer', fontSize: '12px', fontWeight: '600', marginBottom: '12px' }}>
                  🗄️ {showArchive ? 'Skjul arkiverte revisjoner' : 'Vis arkiverte revisjoner'}
                </button>
              )}
              {loading ? (
                <div style={{ textAlign: 'center', padding: '40px', color: '#94a3b8' }}>Laster filer...</div>
              ) : fileGroups.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px 16px', background: 'white', borderRadius: '14px', border: '1px solid #f1f5f9' }}>
                  <div style={{ fontSize: '36px', marginBottom: '10px' }}>📭</div>
                  <div style={{ fontSize: '14px', fontWeight: '600', color: '#0f172a' }}>Ingen filer</div>
                  <button onClick={() => { setUploadForm(f => ({ ...f, category: selectedCategory, sub: selectedSub || '' })); setShowUpload(true) }}
                    style={{ marginTop: '12px', padding: '8px 18px', background: '#059669', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontSize: '13px', fontWeight: '600' }}>⬆️ Last opp</button>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                  <div style={{ fontSize: '11px', fontWeight: '700', color: '#64748b', marginBottom: '6px', letterSpacing: '0.06em' }}>DOKUMENTER ({fileGroups.length})</div>
                  {fileGroups.map(group => {
                    const current = group[0]
                    const docGroup = current.document_group || current.id
                    const archived = archivedPanelFiles.filter(f => (f.document_group || f.id) === docGroup)
                    return (
                      <div key={current.id} style={{ marginBottom: '8px' }}>
                        <FileRow file={current} isArchived={false} catBg={selectedCat?.bg} catColor={selectedCat?.color} supportsRevision={catSupportsRevision} onDownload={handleDownload} onDelete={handleDelete} onNewRevision={handleNewRevision} uploading={uploading} />
                        {showArchive && archived.map(f => (
                          <div key={f.id} style={{ marginTop: '3px', marginLeft: '12px' }}>
                            <FileRow file={f} isArchived={true} catBg="#fef2f2" catColor="#dc2626" supportsRevision={false} onDownload={handleDownload} onDelete={handleDelete} onNewRevision={null} uploading={false} />
                          </div>
                        ))}
                      </div>
                    )
                  })}
                </div>
              )}
            </>
          )}
        </div>
      ) : (
      /* DESKTOP: Two-panel layout */
      <div style={{ display: 'flex', flex: 1, overflow: 'hidden', minHeight: 0 }}>

        {/* LEFT: Category list */}
        <div style={{ width: '260px', flexShrink: 0, background: 'white', borderRight: '1px solid #e2e8f0', overflowY: 'auto', padding: '12px 0' }}>
          <div style={{ padding: '4px 16px 10px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <span style={{ fontSize: '11px', fontWeight: '700', color: '#94a3b8', letterSpacing: '0.07em' }}>KATEGORIER</span>
            <button onClick={() => setShowUpload(true)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#059669', fontSize: '20px', lineHeight: 1 }}>+</button>
          </div>
          {FILE_CATEGORIES.map(cat => {
            const catCount = countForCat(cat.id)
            const isActive = selectedCategory === cat.id && !selectedSub
            const isExpanded = expandedCats[cat.id]
            const hasSubs = cat.sub.length > 0
            return (
              <div key={cat.id}>
                <div onClick={() => { setSelectedCategory(cat.id); setSelectedSub(null); setShowArchive(false); if (hasSubs) toggleCat(cat.id) }}
                  style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '9px 16px', cursor: 'pointer',
                    background: isActive ? '#f0fdf4' : 'transparent',
                    borderLeft: isActive ? `3px solid ${cat.color}` : '3px solid transparent' }}
                  onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = '#f8fafc' }}
                  onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = 'transparent' }}>
                  <div style={{ width: '28px', height: '28px', borderRadius: '7px', background: cat.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '14px', flexShrink: 0 }}>{cat.emoji}</div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: '13px', fontWeight: isActive ? '600' : '500', color: isActive ? cat.color : '#374151', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{cat.name}</div>
                    <div style={{ fontSize: '11px', color: '#94a3b8' }}>{hasSubs ? `${cat.sub.length} undermapper` : `${catCount} fil${catCount !== 1 ? 'er' : ''}`}</div>
                  </div>
                  {hasSubs && <span style={{ fontSize: '16px', color: '#64748b', fontWeight: '700' }}>{isExpanded ? '▾' : '▸'}</span>}
                </div>
                {hasSubs && isExpanded && cat.sub.map(sub => {
                  const subCount = countForSub(cat.id, sub)
                  const isSubActive = selectedCategory === cat.id && selectedSub === sub
                  return (
                    <div key={sub} onClick={() => { setSelectedCategory(cat.id); setSelectedSub(sub); setShowArchive(false) }}
                      style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '7px 16px 7px 44px', cursor: 'pointer',
                        background: isSubActive ? '#f0fdf4' : 'transparent',
                        borderLeft: isSubActive ? `3px solid ${cat.color}` : '3px solid transparent' }}
                      onMouseEnter={e => { if (!isSubActive) e.currentTarget.style.background = '#f8fafc' }}
                      onMouseLeave={e => { if (!isSubActive) e.currentTarget.style.background = 'transparent' }}>
                      <span style={{ fontSize: '13px' }}>📂</span>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: '12px', fontWeight: isSubActive ? '600' : '400', color: isSubActive ? cat.color : '#475569' }}>{sub}</div>
                        <div style={{ fontSize: '11px', color: '#94a3b8' }}>{subCount} fil{subCount !== 1 ? 'er' : ''}</div>
                      </div>
                    </div>
                  )
                })}
              </div>
            )
          })}
        </div>

        {/* RIGHT: File panel */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '20px 28px' }}>
          {selectedProject === 'all' ? (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', minHeight: '300px' }}>
              <div style={{ fontSize: '48px', marginBottom: '12px' }}>🏗️</div>
              <div style={{ fontSize: '16px', fontWeight: '600', color: '#64748b', marginBottom: '4px' }}>Velg et prosjekt</div>
              <div style={{ fontSize: '13px', color: '#94a3b8' }}>Velg et prosjekt øverst til venstre for å se filer</div>
            </div>
          ) : !selectedCategory ? (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', minHeight: '300px' }}>
              <div style={{ fontSize: '48px', marginBottom: '12px' }}>📂</div>
              <div style={{ fontSize: '16px', fontWeight: '600', color: '#64748b', marginBottom: '4px' }}>Velg en kategori</div>
              <div style={{ fontSize: '13px', color: '#94a3b8' }}>Velg en kategori fra venstre panel for å se filer</div>
            </div>
          ) : (
            <>
              {/* Toolbar: search + archive toggle + upload */}
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px', gap: '10px', flexWrap: 'wrap' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <div style={{ position: 'relative' }}>
                    <span style={{ position: 'absolute', left: '10px', top: '50%', transform: 'translateY(-50%)', color: '#94a3b8', fontSize: '13px' }}>🔍</span>
                    <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Søk etter filer..."
                      style={{ paddingLeft: '32px', padding: '8px 12px 8px 32px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '13px', outline: 'none', width: '200px' }} />
                  </div>
                  {catSupportsRevision && (
                    <button onClick={() => setShowArchive(v => !v)}
                      style={{ padding: '8px 14px', background: showArchive ? '#f0fdf4' : 'white',
                        color: showArchive ? '#059669' : '#64748b',
                        border: `1px solid ${showArchive ? '#bbf7d0' : '#e2e8f0'}`,
                        borderRadius: '10px', cursor: 'pointer', fontSize: '13px', fontWeight: '600',
                        display: 'flex', alignItems: 'center', gap: '6px' }}>
                      🗄️ {showArchive ? 'Skjul arkiv' : 'Vis arkiverte revisjoner'}
                    </button>
                  )}
                </div>
                <button onClick={() => { setUploadForm(f => ({ ...f, category: selectedCategory, sub: selectedSub || '' })); setShowUpload(true) }}
                  style={{ padding: '8px 16px', background: '#059669', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontSize: '13px', fontWeight: '600', whiteSpace: 'nowrap' }}>
                  ⬆️ Last opp fil
                </button>
              </div>

              {loading ? (
                <div style={{ textAlign: 'center', padding: '60px', color: '#94a3b8' }}>
                  <div style={{ width: '32px', height: '32px', border: '3px solid #e2e8f0', borderTop: '3px solid #059669', borderRadius: '50%', margin: '0 auto 12px', animation: 'spin 1s linear infinite' }} />
                  Laster filer...
                </div>
              ) : fileGroups.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '60px 20px', background: 'white', borderRadius: '16px', border: '1px solid #f1f5f9' }}>
                  <div style={{ fontSize: '40px', marginBottom: '12px' }}>📭</div>
                  <div style={{ fontSize: '15px', fontWeight: '600', color: '#0f172a', marginBottom: '4px' }}>Ingen filer her ennå</div>
                  <div style={{ fontSize: '13px', color: '#94a3b8', marginBottom: '16px' }}>Last opp den første filen i denne kategorien</div>
                  <button onClick={() => { setUploadForm(f => ({ ...f, category: selectedCategory, sub: selectedSub || '' })); setShowUpload(true) }}
                    style={{ padding: '9px 20px', background: '#059669', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontSize: '13px', fontWeight: '600' }}>
                    ⬆️ Last opp fil
                  </button>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                  <div style={{ fontSize: '11px', fontWeight: '700', color: '#64748b', marginBottom: '8px', letterSpacing: '0.06em' }}>
                    DOKUMENTER ({fileGroups.length})
                  </div>
                  {/* Each group: current revision + archived revisions inline below */}
                  {fileGroups.map(group => {
                    const current = group[0]
                    const docGroup = current.document_group || current.id
                    const archived = archivedPanelFiles.filter(f => (f.document_group || f.id) === docGroup)
                      .sort((a,b) => {
                        const an = parseInt((a.revision_label||'Rev00').replace(/\D/g,''))||0
                        const bn = parseInt((b.revision_label||'Rev00').replace(/\D/g,''))||0
                        return bn - an
                      })
                    return (
                      <div key={current.id} style={{ marginBottom: '10px' }}>
                        {/* Current (active) revision — green */}
                        <FileRow file={current} isArchived={false}
                          catBg={selectedCat?.bg} catColor={selectedCat?.color}
                          supportsRevision={catSupportsRevision}
                          onDownload={handleDownload}
                          onDelete={handleDelete}
                          onNewRevision={handleNewRevision}
                          uploading={uploading} />
                        {/* Archived revisions — shown inline below when showArchive is true */}
                        {showArchive && archived.map(f => (
                          <div key={f.id} style={{ marginTop: '3px', marginLeft: '20px' }}>
                            <FileRow file={f} isArchived={true}
                              catBg="#fef2f2" catColor="#dc2626"
                              supportsRevision={false}
                              onDownload={handleDownload}
                              onDelete={handleDelete}
                              onNewRevision={null}
                              uploading={false} />
                          </div>
                        ))}
                      </div>
                    )
                  })}
                </div>
              )}
            </>
          )}
        </div>
      </div>
      )}

      {/* Local delete confirmation dialog */}
      {deleteTarget && (
        <div style={{ position:'fixed', inset:0, zIndex:9999, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px', fontFamily:'system-ui,sans-serif' }}>
          <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={() => setDeleteTarget(null)} />
          <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'420px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', overflow:'hidden' }}>
            <div style={{ padding:'24px 24px 0' }}>
              <div style={{ width:'44px', height:'44px', borderRadius:'12px', background:'#fef2f2', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'22px', marginBottom:'14px' }}>⚠️</div>
              <h3 style={{ margin:'0 0 6px', fontSize:'17px', fontWeight:'700', color:'#0f172a' }}>Slett {deleteTarget.name}?</h3>
              <p style={{ margin:'0 0 4px', fontSize:'14px', color:'#64748b' }}>Filen slettes permanent og kan ikke gjenopprettes.</p>
            </div>
            <div style={{ display:'flex', gap:'10px', padding:'20px 24px 24px', justifyContent:'flex-end' }}>
              <button onClick={() => setDeleteTarget(null)}
                style={{ padding:'10px 22px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>
                Avbryt
              </button>
              <button onClick={confirmDelete}
                style={{ padding:'10px 22px', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'14px', fontWeight:'700', color:'white', background:'#dc2626' }}>
                Slett
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── Revisjonsmerknad-modal ── */}
      {revisionTarget && (
        <>
          <div onClick={() => setRevisionTarget(null)} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.4)', zIndex:100 }} />
          <div style={{ position:'fixed', top:'50%', left:'50%', transform:'translate(-50%,-50%)', background:'white', borderRadius:'20px', width:'min(480px, calc(100vw - 32px))', zIndex:101, boxShadow:'0 20px 60px rgba(0,0,0,0.15)', fontFamily:'system-ui, sans-serif' }}>
            <div style={{ padding:'18px 24px', borderBottom:'1px solid #f1f5f9' }}>
              <h2 style={{ margin:0, fontSize:'17px', fontWeight:'700', color:'#0f172a' }}>🔄 Ny revisjon</h2>
            </div>
            <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'16px' }}>
              <div style={{ background:'#f0fdf4', borderRadius:'10px', padding:'12px 16px', border:'1px solid #bbf7d0' }}>
                <div style={{ fontSize:'13px', color:'#059669', fontWeight:'600', marginBottom:'4px' }}>{revisionTarget.baseFile.name}</div>
                <div style={{ fontSize:'12px', color:'#64748b' }}>
                  Gjeldende: {revisionTarget.baseFile.revision_label || 'Rev01'} → Ny fil: {revisionTarget.newFile.name} ({formatFileSize(revisionTarget.newFile.size)})
                </div>
              </div>
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Hva er endret? *</label>
                <textarea value={revisionNote} onChange={e => setRevisionNote(e.target.value)} placeholder="Beskriv endringene i denne revisjonen, f.eks. «Oppdatert vindusplassering i 2. etasje» eller «Ny beregning etter RIB-kommentarer»"
                  rows={3} style={{ width:'100%', padding:'10px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', resize:'vertical', boxSizing:'border-box', fontFamily:'system-ui, sans-serif' }} autoFocus />
              </div>
              <div style={{ display:'flex', justifyContent:'flex-end', gap:'10px' }}>
                <button onClick={() => setRevisionTarget(null)} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={confirmNewRevision} disabled={uploading}
                  style={{ padding:'10px 24px', background: uploading ? '#6ee7b7' : '#059669', color:'white', border:'none', borderRadius:'10px', cursor: uploading ? 'not-allowed' : 'pointer', fontSize:'14px', fontWeight:'600' }}>
                  {uploading ? 'Laster opp...' : '🔄 Last opp revisjon'}
                </button>
              </div>
            </div>
          </div>
        </>
      )}

      {/* Upload Modal */}
      {showUpload && (
        <>
          <div onClick={() => { setShowUpload(false); setUploadFiles([]) }} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', zIndex: 100 }} />
          <div style={{ position: 'fixed', top: '50%', left: '50%', transform: 'translate(-50%,-50%)', background: 'white', borderRadius: '20px', width: 'min(560px, calc(100vw - 32px))', maxHeight: '90vh', display: 'flex', flexDirection: 'column', zIndex: 101, boxShadow: '0 20px 60px rgba(0,0,0,0.15)', fontFamily: 'system-ui, sans-serif' }}>
            <div style={{ padding: '18px 24px', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <h2 style={{ margin: 0, fontSize: '17px', fontWeight: '700', color: '#0f172a' }}>Last opp filer</h2>
              <button onClick={() => { setShowUpload(false); setUploadFiles([]) }} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '22px', color: '#94a3b8' }}>×</button>
            </div>
            <form onSubmit={handleUpload} style={{ padding: '24px', display: 'flex', flexDirection: 'column', gap: '14px', overflowY: 'auto' }}>
              {/* Drag-and-drop sone */}
              <div
                onClick={() => fileInputRef.current?.click()}
                onDragOver={(e) => { e.preventDefault(); e.currentTarget.style.borderColor = '#059669'; e.currentTarget.style.background = '#f0fdf4' }}
                onDragLeave={(e) => { e.currentTarget.style.borderColor = '#e2e8f0'; e.currentTarget.style.background = '#f8fafc' }}
                onDrop={(e) => {
                  e.preventDefault(); e.stopPropagation()
                  e.currentTarget.style.borderColor = '#e2e8f0'; e.currentTarget.style.background = '#f8fafc'
                  const dropped = Array.from(e.dataTransfer?.files || [])
                  if (dropped.length > 0) setUploadFiles(prev => [...prev, ...dropped])
                }}
                style={{ border: '2px dashed #e2e8f0', borderRadius: '12px', padding: uploadFiles.length > 0 ? '16px' : '32px', textAlign: 'center', cursor: 'pointer', background: '#f8fafc', transition: 'border-color 0.2s, background 0.2s' }}>
                {uploadFiles.length === 0 ? (
                  <>
                    <div style={{ fontSize: '36px', marginBottom: '8px' }}>📂</div>
                    <p style={{ margin: '0 0 4px', color: '#0f172a', fontSize: '15px', fontWeight: '600' }}>Dra og slipp filer her</p>
                    <p style={{ margin: 0, color: '#94a3b8', fontSize: '13px' }}>eller klikk for å velge fra maskinen</p>
                  </>
                ) : (
                  <>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '6px', textAlign: 'left' }}>
                      {uploadFiles.map((f, i) => (
                        <div key={i} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: 'white', borderRadius: '8px', padding: '8px 12px', border: '1px solid #f1f5f9' }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', minWidth: 0 }}>
                            <span style={{ fontSize: '16px', flexShrink: 0 }}>{getFileEmoji(f.name)}</span>
                            <span style={{ fontSize: '13px', color: '#0f172a', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{f.name}</span>
                          </div>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexShrink: 0 }}>
                            <span style={{ fontSize: '12px', color: '#94a3b8' }}>{formatFileSize(f.size)}</span>
                            <button type="button" onClick={(e) => { e.stopPropagation(); setUploadFiles(prev => prev.filter((_, idx) => idx !== i)) }}
                              style={{ background: '#fef2f2', border: 'none', borderRadius: '6px', width: '22px', height: '22px', cursor: 'pointer', color: '#dc2626', fontSize: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>×</button>
                          </div>
                        </div>
                      ))}
                    </div>
                    <div style={{ marginTop: '10px', paddingTop: '10px', borderTop: '1px dashed #e2e8f0' }}>
                      <p style={{ margin: 0, color: '#94a3b8', fontSize: '12px' }}>
                        {uploadFiles.length} fil{uploadFiles.length > 1 ? 'er' : ''} valgt ({formatFileSize(uploadFiles.reduce((a, f) => a + f.size, 0))}) · Klikk eller dra for å legge til flere
                      </p>
                    </div>
                  </>
                )}
              </div>
              <input ref={fileInputRef} type="file" multiple style={{ display: 'none' }} onChange={e => {
                const newFiles = Array.from(e.target.files || [])
                setUploadFiles(prev => [...prev, ...newFiles])
                e.target.value = ''
              }} />
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: '600', color: '#374151', marginBottom: '4px' }}>Prosjekt *</label>
                  <SearchableProjectSelect value={uploadForm.project_id} onChange={v => (e => setUploadForm(f => ({...f, project_id: e.target.value})))({ target: { value: v } })} projects={projects} style={{ ...inp, background: 'white' }} placeholder="Velg prosjekt" />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: '600', color: '#374151', marginBottom: '4px' }}>Kategori</label>
                  <select value={uploadForm.category} onChange={e => setUploadForm(f => ({...f, category: e.target.value, sub: ''}))} style={{ ...inp, background: 'white' }}>
                    {FILE_CATEGORIES.map(c => <option key={c.id} value={c.id}>{c.emoji} {c.name}</option>)}
                  </select>
                </div>
              </div>
              {FILE_CATEGORIES.find(c => c.id === uploadForm.category)?.sub?.length > 0 && (
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: '600', color: '#374151', marginBottom: '4px' }}>Undermappe</label>
                  <select value={uploadForm.sub} onChange={e => setUploadForm(f => ({...f, sub: e.target.value}))} style={{ ...inp, background: 'white' }}>
                    <option value="">Ingen undermappe</option>
                    {FILE_CATEGORIES.find(c => c.id === uploadForm.category).sub.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
              )}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: '600', color: '#374151', marginBottom: '4px' }}>Tilgangsnivå</label>
                  <select value={uploadForm.access_level} onChange={e => setUploadForm(f => ({...f, access_level: e.target.value}))} style={{ ...inp, background: 'white' }}>
                    <option value="alle">👥 Alle brukere</option>
                    <option value="prosjektleder">🔒 Prosjektleder</option>
                    <option value="admin">🛡️ Admin</option>
                  </select>
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: '600', color: '#374151', marginBottom: '4px' }}>Beskrivelse</label>
                  <input value={uploadForm.description} onChange={e => setUploadForm(f => ({...f, description: e.target.value}))} placeholder="Valgfri..." style={inp} />
                </div>
              </div>
              <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '10px', paddingTop: '4px' }}>
                <button type="button" onClick={() => { setShowUpload(false); setUploadFiles([]) }}
                  style={{ padding: '10px 20px', border: '1px solid #e2e8f0', borderRadius: '10px', background: 'white', cursor: 'pointer', fontSize: '14px', fontWeight: '600' }}>Avbryt</button>
                <button type="submit" disabled={uploading}
                  style={{ padding: '10px 24px', background: uploading ? '#6ee7b7' : '#059669', color: 'white', border: 'none', borderRadius: '10px', cursor: uploading ? 'not-allowed' : 'pointer', fontSize: '14px', fontWeight: '600' }}>
                  {uploading ? 'Laster opp...' : 'Last opp'}
                </button>
              </div>
            </form>
          </div>
        </>
      )}
    </div>
  )
}

function FileRow({ file, isArchived, catBg, catColor, supportsRevision, onDownload, onDelete, onNewRevision, uploading }) {
  const isMobTL = typeof window !== 'undefined' && window.innerWidth < 768
  const [showPreview, setShowPreview] = useState(false)
  const [showHistory, setShowHistory] = useState(false)
  const [previewUrl, setPreviewUrl] = useState(null)
  const [previewLoading, setPreviewLoading] = useState(false)
  const [thumbUrl, setThumbUrl] = useState(null)
  const revBg    = isArchived ? '#fef2f2' : '#f0fdf4'
  const revColor = isArchived ? '#dc2626' : '#059669'
  const revBorder= isArchived ? '#fecaca' : '#bbf7d0'
  const ext = file.name?.split('.').pop()?.toLowerCase() || ''
  const isImage = ['jpg','jpeg','png','gif','webp','svg'].includes(ext)
  const isPdf = ext === 'pdf'
  const isOffice = ['doc','docx','xls','xlsx','ppt','pptx'].includes(ext)
  const isText = ['txt','csv','json','xml','md'].includes(ext)
  const canPreview = isImage || isPdf || isText
  const [zoom, setZoom] = useState(100)
  const [textContent, setTextContent] = useState(null)
  const [loadingText, setLoadingText] = useState(false)

  // Hent signert URL (fungerer med private buckets)
  const getSignedUrl = async () => {
    const { data, error } = await supabase.storage.from('plattform-files').createSignedUrl(file.file_url, 3600)
    if (error || !data?.signedUrl) return null
    return data.signedUrl
  }

  // Last thumbnail for bilder (blob-basert, fungerer alltid)
  React.useEffect(() => {
    if (!isImage || isArchived) return
    let cancelled = false
    supabase.storage.from('plattform-files').download(file.file_url).then(({ data, error }) => {
      if (!error && data && !cancelled) {
        const url = URL.createObjectURL(data)
        setThumbUrl(url)
      }
    })
    return () => { cancelled = true }
  }, [file.file_url])

  // Cleanup blob URLs
  React.useEffect(() => {
    return () => {
      if (thumbUrl) URL.revokeObjectURL(thumbUrl)
      if (previewUrl && previewUrl.startsWith('blob:')) URL.revokeObjectURL(previewUrl)
    }
  }, [])

  // Escape-tast for å lukke
  React.useEffect(() => {
    if (!showPreview) return
    const handler = (e) => { if (e.key === 'Escape') closePreview() }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [showPreview])

  // Last preview-URL når modal åpnes
  const openPreview = async () => {
    setShowPreview(true)
    setZoom(100)
    setPreviewLoading(true)

    if (isText) {
      // Tekstfiler: last innhold
      if (textContent === null) {
        try {
          const { data, error } = await supabase.storage.from('plattform-files').download(file.file_url)
          if (!error && data) setTextContent(await data.text())
        } catch(e) { console.error(e) }
      }
      setPreviewLoading(false)
    } else {
      // Bilder og PDF: prøv flere strategier
      try {
        // Strategi 1: Sjekk om file_url allerede er en full URL
        if (file.file_url?.startsWith('http')) {
          setPreviewUrl(file.file_url)
          setPreviewLoading(false)
          return
        }
        // Strategi 2: Hent public URL
        const { data: pubData } = supabase.storage.from('plattform-files').getPublicUrl(file.file_url)
        if (pubData?.publicUrl) {
          setPreviewUrl(pubData.publicUrl)
          setPreviewLoading(false)
          return
        }
        // Strategi 3: Signert URL som fallback
        const signed = await getSignedUrl()
        if (signed) {
          setPreviewUrl(signed)
          setPreviewLoading(false)
          return
        }
        // Strategi 4: Blob-download
        const { data, error } = await supabase.storage.from('plattform-files').download(file.file_url)
        if (!error && data) {
          const url = URL.createObjectURL(data)
          setPreviewUrl(url)
        }
      } catch(e) {
        console.error('Preview error:', e)
        // Siste fallback: prøv signert URL
        try {
          const signed = await getSignedUrl()
          setPreviewUrl(signed)
        } catch(e2) { console.error('Signed URL fallback error:', e2) }
      }
      setPreviewLoading(false)
    }
  }

  const closePreview = () => {
    setShowPreview(false)
    // Cleanup blob URL når modal lukkes
    if (previewUrl && previewUrl.startsWith('blob:')) {
      URL.revokeObjectURL(previewUrl)
      setPreviewUrl(null)
    }
  }

  // Klikk på filnavn: forhåndsvisning for PDF/bilder, ellers nedlasting
  const handleNameClick = () => {
    if (canPreview) openPreview()
    else onDownload(file)
  }

  const isMob = typeof window !== 'undefined' && window.innerWidth < 768

  return (
    <>
    <div style={{ background: isArchived ? '#fef9f9' : 'white', borderRadius: '12px',
      border: `1px solid ${isArchived ? '#fecaca' : '#f1f5f9'}`, padding: isMob ? '10px 12px' : '12px 16px',
      display: 'flex', flexDirection: isMob ? 'column' : 'row', alignItems: isMob ? 'stretch' : 'center', gap: isMob ? '8px' : '12px', opacity: isArchived ? 0.85 : 1 }}
      onMouseEnter={e => e.currentTarget.style.boxShadow = '0 2px 12px rgba(0,0,0,0.07)'}
      onMouseLeave={e => e.currentTarget.style.boxShadow = 'none'}>
      {/* Top row: icon + name + actions (mobil) eller alt på én rad (desktop) */}
      <div style={{ display:'flex', alignItems:'center', gap: isMob ? '8px' : '12px', minWidth:0 }}>
        {!isMob && <input type="checkbox" style={{ width: '15px', height: '15px', flexShrink: 0, cursor: 'pointer', accentColor: '#059669' }} />}
        {/* Thumbnail for bilder */}
        {isImage && thumbUrl ? (
          <div onClick={openPreview} style={{ width: isMob ? '34px' : '42px', height: isMob ? '34px' : '42px', borderRadius: '8px', overflow: 'hidden', flexShrink: 0, cursor: 'pointer', border: '1px solid #e2e8f0' }}>
            <img src={thumbUrl} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          </div>
        ) : (
          <div style={{ width: isMob ? '30px' : '36px', height: isMob ? '30px' : '36px', borderRadius: '9px', background: isArchived ? '#fef2f2' : (catBg || '#f8fafc'),
            display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: isMob ? '15px' : '18px', flexShrink: 0, cursor: canPreview ? 'pointer' : 'default' }}
            onClick={() => { if (canPreview) openPreview() }}>
            {getFileEmoji(file.name, file.file_type)}
          </div>
        )}
        <div style={{ flex: 1, minWidth: 0, overflow: 'hidden' }}>
          <div onClick={handleNameClick}
            style={{ fontWeight: '600', color: isArchived ? '#9ca3af' : (canPreview ? '#2563eb' : '#0f172a'), fontSize: isMob ? '13px' : '14px',
            overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', cursor: 'pointer' }}
            onMouseEnter={e => { if (canPreview) e.currentTarget.style.textDecoration = 'underline' }}
            onMouseLeave={e => e.currentTarget.style.textDecoration = 'none'}>
            {file.name}
          </div>
          <div style={{ display: 'flex', gap: '6px', alignItems: 'center', marginTop: '3px', flexWrap: 'wrap' }}>
            {file.revision_label && (
              <span style={{ background: revBg, color: revColor, border: `1px solid ${revBorder}`,
                borderRadius: '999px', fontSize: '10px', fontWeight: '700', padding: '1px 6px',
                display: 'flex', alignItems: 'center', gap: '3px' }}>
                {file.revision_label}
                {!isArchived && <span>✓</span>}
                {isArchived && <span>🗄️</span>}
              </span>
            )}
            <span style={{ fontSize: '11px', color: '#94a3b8' }}>
              {file.file_size ? formatFileSize(file.file_size) : ''}
              {file.file_size && '  '}
              {new Date(file.created_at).toLocaleDateString('nb-NO')}
            </span>
          </div>
        </div>
        {/* Mobil: kompakte knapper på høyre side */}
        {isMob && (
          <div style={{ display:'flex', gap:'4px', flexShrink:0 }}>
            {canPreview && <button onClick={openPreview} style={{ background:'#eff6ff', color:'#2563eb', border:'none', borderRadius:'6px', padding:'5px 8px', cursor:'pointer', fontSize:'12px' }}>👁️</button>}
            <button onClick={() => onDownload(file)} style={{ background:'#f8fafc', color:'#475569', border:'none', borderRadius:'6px', padding:'5px 8px', cursor:'pointer', fontSize:'12px' }}>⬇️</button>
          </div>
        )}
      </div>
      {/* Desktop: ekstra info og knapper */}
      {!isMob && (
        <>
          <div style={{ display: 'flex', gap: '6px', flexShrink: 0, alignItems: 'center' }}>
            {supportsRevision && !isArchived && onNewRevision && (
              <label style={{ padding: '6px 12px', background: '#f0fdf4', color: '#059669',
                border: '1px solid #bbf7d0', borderRadius: '8px', cursor: 'pointer',
                fontSize: '12px', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '5px', whiteSpace: 'nowrap' }}>
                🔄 Ny revisjon
                <input type="file" style={{ display: 'none' }} onChange={e => onNewRevision(e, file)} disabled={uploading} />
              </label>
            )}
            {canPreview && <button onClick={openPreview} title="Forhåndsvisning"
              style={{ background: '#eff6ff', color: '#2563eb', border: '1px solid #bfdbfe', borderRadius: '8px', padding: '6px 10px', cursor: 'pointer', fontSize: '14px' }}>👁️</button>}
            <button onClick={() => onDownload(file)} title="Last ned"
              style={{ background: '#f8fafc', color: '#475569', border: '1px solid #e2e8f0', borderRadius: '8px', padding: '6px 10px', cursor: 'pointer', fontSize: '14px' }}>⬇️</button>
            <button onClick={() => onDelete(file)} title="Slett"
              style={{ background: '#fef2f2', color: '#dc2626', border: 'none', borderRadius: '8px', padding: '6px 10px', cursor: 'pointer', fontSize: '14px' }}>🗑️</button>
          </div>
        </>
      )}
      {/* Mobil: revisjon + slett som egen rad */}
      {isMob && (supportsRevision && !isArchived && onNewRevision || true) && (
        <div style={{ display:'flex', gap:'6px', justifyContent:'flex-end' }}>
          {supportsRevision && !isArchived && onNewRevision && (
            <label style={{ padding:'5px 10px', background:'#f0fdf4', color:'#059669', border:'1px solid #bbf7d0', borderRadius:'6px', cursor:'pointer', fontSize:'11px', fontWeight:'600', display:'flex', alignItems:'center', gap:'4px' }}>
              🔄 Ny revisjon
              <input type="file" style={{ display:'none' }} onChange={e => onNewRevision(e, file)} disabled={uploading} />
            </label>
          )}
          <button onClick={() => onDelete(file)} style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'6px', padding:'5px 8px', cursor:'pointer', fontSize:'11px' }}>🗑️</button>
        </div>
      )}
    </div>

    {/* ── Forhåndsvisning fullskjerm-modal ── */}
    {showPreview && (
      <div style={{ position:'fixed', inset:0, zIndex:200, display:'flex', flexDirection:'column', background:'rgba(0,0,0,0.75)', fontFamily:'system-ui, sans-serif' }}>
        {/* Topplinje */}
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'12px 20px', background:'rgba(0,0,0,0.5)', backdropFilter:'blur(8px)', flexShrink:0 }}>
          <div style={{ display:'flex', alignItems:'center', gap:'12px' }}>
            <span style={{ fontSize:'18px' }}>{getFileEmoji(file.name, file.file_type)}</span>
            <div>
              <div style={{ fontWeight:'600', fontSize:'14px', color:'white' }}>{file.name}</div>
              <div style={{ fontSize:'12px', color:'rgba(255,255,255,0.6)', display:'flex', gap:'12px', marginTop:'2px' }}>
                {file.file_size && <span>{formatFileSize(file.file_size)}</span>}
                <span>{new Date(file.created_at).toLocaleDateString('nb-NO')}</span>
                {file.revision_label && <span>{file.revision_label}</span>}
                {file.description && <span>{file.description}</span>}
              </div>
            </div>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
            {/* Zoom-kontroller for bilder og PDF */}
            {(isImage || isPdf) && (
              <div style={{ display:'flex', alignItems:'center', gap:'4px', background:'rgba(255,255,255,0.15)', borderRadius:'8px', padding:'4px 8px' }}>
                <button onClick={() => setZoom(z => Math.max(25, z - 25))} style={{ background:'none', border:'none', color:'white', cursor:'pointer', fontSize:'16px', padding:'2px 6px' }}>−</button>
                <span style={{ color:'white', fontSize:'12px', fontWeight:'600', minWidth:'42px', textAlign:'center' }}>{zoom}%</span>
                <button onClick={() => setZoom(z => Math.min(300, z + 25))} style={{ background:'none', border:'none', color:'white', cursor:'pointer', fontSize:'16px', padding:'2px 6px' }}>+</button>
                <button onClick={() => setZoom(100)} style={{ background:'none', border:'none', color:'rgba(255,255,255,0.6)', cursor:'pointer', fontSize:'11px', padding:'2px 6px' }}>Reset</button>
              </div>
            )}
            <button onClick={() => onDownload(file)}
              style={{ background:'rgba(255,255,255,0.15)', border:'none', borderRadius:'8px', padding:'8px 14px', cursor:'pointer', color:'white', fontSize:'13px', fontWeight:'500', display:'flex', alignItems:'center', gap:'6px' }}>
              ⬇️ Last ned
            </button>
            <button onClick={closePreview}
              style={{ background:'rgba(255,255,255,0.15)', border:'none', borderRadius:'8px', width:'36px', height:'36px', cursor:'pointer', color:'white', fontSize:'20px', display:'flex', alignItems:'center', justifyContent:'center' }}>
              ×
            </button>
          </div>
        </div>

        {/* Innhold */}
        <div style={{ flex:1, overflow:'auto', display:'flex', alignItems:'center', justifyContent:'center', padding:'20px' }}
          onClick={(e) => { if (e.target === e.currentTarget) closePreview() }}>
          {previewLoading ? (
            <div style={{ textAlign:'center' }}>
              <div style={{ width:'40px', height:'40px', border:'3px solid rgba(255,255,255,0.2)', borderTop:'3px solid white', borderRadius:'50%', margin:'0 auto 16px', animation:'spin 1s linear infinite' }} />
              <style>{`@keyframes spin { to { transform: rotate(360deg) } }`}</style>
              <p style={{ color:'rgba(255,255,255,0.7)', fontSize:'14px' }}>Laster forhåndsvisning...</p>
            </div>
          ) : (
            <>
              {isImage && previewUrl && (
                <img src={previewUrl} alt={file.name}
                  style={{ maxWidth: `${zoom}%`, maxHeight: zoom > 100 ? 'none' : '85vh', objectFit:'contain', borderRadius:'8px', boxShadow:'0 8px 40px rgba(0,0,0,0.3)', transition:'max-width 0.2s' }} />
              )}
              {isPdf && previewUrl && (
                <iframe src={previewUrl} title={file.name}
                  style={{ width: `${Math.min(zoom, 100)}%`, maxWidth:'1200px', height:'88vh', border:'none', borderRadius:'8px', boxShadow:'0 8px 40px rgba(0,0,0,0.3)', background:'white' }} />
              )}
              {isText && (
                <div style={{ width:'90%', maxWidth:'900px', maxHeight:'85vh', overflow:'auto', background:'white', borderRadius:'12px', boxShadow:'0 8px 40px rgba(0,0,0,0.3)' }}>
                  <div style={{ padding: isMobTL ? '12px' : '20px 24px' }}>
                    <pre style={{ margin:0, fontSize:'13px', color:'#0f172a', fontFamily:'monospace', whiteSpace:'pre-wrap', wordBreak:'break-word', lineHeight:1.6 }}>{textContent || 'Kunne ikke laste filen.'}</pre>
                  </div>
                </div>
              )}
              {!previewUrl && !isText && (
                <div style={{ textAlign:'center', color:'rgba(255,255,255,0.7)' }}>
                  <p style={{ fontSize:'16px', marginBottom:'12px' }}>Kunne ikke laste forhåndsvisning</p>
                  <button onClick={() => onDownload(file)}
                    style={{ background:'white', color:'#0f172a', border:'none', borderRadius:'10px', padding:'10px 24px', fontSize:'14px', fontWeight:'600', cursor:'pointer' }}>
                    ⬇️ Last ned i stedet
                  </button>
                </div>
              )}
            </>
          )}
        </div>

        {/* Hurtigtaster-hint */}
        <div style={{ padding:'8px 20px', textAlign:'center', flexShrink:0 }}>
          <span style={{ fontSize:'11px', color:'rgba(255,255,255,0.4)' }}>Esc for å lukke · Klikk utenfor for å lukke</span>
        </div>
      </div>
    )}
    </>
  )
}

