// ─── TILBUD MODULE ────────────────────────────────────────────────────────────

const QUOTE_STATUS = {
  'Utkast':   { bg: '#f8fafc', color: '#64748b', border: '#e2e8f0', emoji: '📝' },
  'Sendt':    { bg: '#eff6ff', color: '#2563eb', border: '#bfdbfe', emoji: '📤' },
  'Akseptert':{ bg: '#f0fdf4', color: '#16a34a', border: '#bbf7d0', emoji: '✅' },
  'Avslått':  { bg: '#fef2f2', color: '#dc2626', border: '#fecaca', emoji: '❌' },
  'Erstattet':{ bg: '#f5f3ff', color: '#7c3aed', border: '#e9d5ff', emoji: '🔄' },
}

const qInp = { width: '100%', padding: '9px 12px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '14px', outline: 'none', boxSizing: 'border-box', background: 'white', color: '#0f172a', fontFamily: 'system-ui, sans-serif' }
const qCard = { background: 'white', borderRadius: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '16px', border: '1px solid #f1f5f9', padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '20px 24px', boxShadow: '0 1px 4px rgba(0,0,0,0.04)' }

function QuoteStatusBadge({ status }) {
  const cfg = QUOTE_STATUS[status] || QUOTE_STATUS['Utkast']
  return <span style={{ background: cfg.bg, color: cfg.color, border: `1px solid ${cfg.border}`, padding: '3px 10px', borderRadius: '999px', fontSize: '12px', fontWeight: '600' }}>{cfg.emoji} {status}</span>
}

function calcChapter(ch) {
  const sum = (ch.posts || []).reduce((acc, p) => acc + (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0)), 0)
  const markup = parseFloat(ch.markup) || 0
  return { sum, total: sum * (1 + markup / 100) }
}

function calcQuote(chapters, globalMarkup) {
  const subtotal = chapters.reduce((acc, ch) => acc + calcChapter(ch).sum, 0)
  const gm = parseFloat(globalMarkup) || 0
  const chapterTotals = chapters.reduce((acc, ch) => acc + calcChapter(ch).total, 0)
  return { subtotal, chapterTotals, grandTotal: chapterTotals * (1 + gm / 100) }
}

function fmt(n) { return (Math.round((parseFloat(n)||0)*100)/100).toLocaleString('nb-NO', { minimumFractionDigits: 0, maximumFractionDigits: 0 }) + ' kr' }

function TilbudPage() {
  const { user } = useAuth()
  const [quotes, setQuotes] = useState([])
  const [projects, setProjects] = useState([])
  const [loading, setLoading] = useState(true)
  const [filterStatus, setFilterStatus] = useState('alle')
  const [search, setSearch] = useState('')
  const [showNew, setShowNew] = useState(false)
  const [selected, setSelected] = useState(null)
  React.useEffect(() => {
    if (selected && window.__enterDetailView) {
      window.__enterDetailView(() => setSelected(null))
    }
  }, [selected])
  const [purringTarget, setPurringTarget] = useState(null)

  const load = async () => {
    try {
      const [q, p] = await Promise.all([
        supabase.from('quotes').select('*').order('created_at', { ascending: false }).then(r => r.data || []),
        supabase.from('projects').select('id,name,parent_id,depth,project_number').order('name').then(r => r.data || [])
      ])
      setQuotes(q); setProjects(p)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(() => { load() }, [])

  // Finn utløpte tilbud uten svar
  const expiredQuotes = quotes.filter(q => q.status === 'Sendt' && q.valid_until && new Date(q.valid_until) < new Date())

  const filtered = quotes.filter(q => {
    if (filterStatus !== 'alle' && q.status !== filterStatus) return false
    if (search && ![q.title, q.quote_number, q.customer_name].some(v => v?.toLowerCase().includes(search.toLowerCase()))) return false
    return true
  })

  const counts = Object.keys(QUOTE_STATUS).reduce((acc, s) => { acc[s] = quotes.filter(q => q.status === s).length; return acc }, {})
  const totalAkseptert = quotes.filter(q => q.status === 'Akseptert').reduce((acc, q) => acc + calcQuote(q.chapters || [], q.global_markup).grandTotal, 0)

  if (loading) return <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'60vh', fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px', height:'36px', border:'3px solid #e2e8f0', borderTop:'3px solid #059669', borderRadius:'50%', margin:'0 auto 12px', animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8', fontSize:'14px' }}>Laster tilbud...</p></div></div>

  const isMobT = typeof window !== 'undefined' && window.innerWidth < 768

  if (selected) return <TilbudDetaljer quote={selected} projects={projects} user={user} onBack={() => { setSelected(null); load() }} />

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobT ? '16px' : '24px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px' }}>
          <div>
            <h1 style={{ fontSize: isMobT ? '18px' : '22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>📋 Tilbud</h1>
            {!isMobT && <p style={{ color:'#64748b', marginTop:'4px', fontSize:'14px', marginBottom:0 }}>Opprett, send og følg opp tilbud til kunder</p>}
          </div>
          <button onClick={() => setShowNew(true)} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding: isMobT ? '9px 12px' : '11px 20px', fontSize: isMobT ? '12px' : '14px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap', flexShrink:0 }}>+ Nytt tilbud</button>
        </div>
      </div>

      <div style={{ padding: isMobT ? '12px' : '24px 32px', display:'flex', flexDirection:'column', gap: isMobT ? '12px' : '20px', overflowX:'hidden' }}>
        <div style={{ display:'grid', gridTemplateColumns: isMobT ? 'repeat(2, 1fr)' : 'repeat(4,1fr) 1.4fr', gap: isMobT ? '8px' : '12px' }}>
          {Object.entries(QUOTE_STATUS).map(([s, cfg]) => (
            <button key={s} onClick={() => setFilterStatus(filterStatus === s ? 'alle' : s)}
              style={{ background: filterStatus===s ? cfg.bg : 'white', border:`1px solid ${filterStatus===s ? cfg.border : '#f1f5f9'}`, borderRadius: isMobT ? '10px' : '14px', padding: isMobT ? '10px' : '16px', cursor:'pointer', textAlign: isMobT ? 'center' : 'left' }}>
              <div style={{ fontSize: isMobT ? '16px' : '20px', marginBottom: isMobT ? '4px' : '8px' }}>{cfg.emoji}</div>
              <div style={{ fontSize: isMobT ? '16px' : '22px', fontWeight:'800', color: filterStatus===s ? cfg.color : '#0f172a' }}>{counts[s]||0}</div>
              <div style={{ fontSize: isMobT ? '10px' : '11px', color: filterStatus===s ? cfg.color : '#94a3b8', fontWeight:'500', marginTop:'2px' }}>{s}</div>
            </button>
          ))}
          {!isMobT && <div style={{ background:'linear-gradient(135deg,#059669,#0891b2)', borderRadius:'14px', padding:'16px', color:'white' }}>
            <div style={{ fontSize:'20px', marginBottom:'8px' }}>💰</div>
            <div style={{ fontSize:'18px', fontWeight:'800' }}>{fmt(totalAkseptert)}</div>
            <div style={{ fontSize:'11px', opacity:0.85, fontWeight:'500', marginTop:'2px' }}>Total akseptert</div>
          </div>}
        </div>

        {/* Purring-banner for utløpte tilbud */}
        {expiredQuotes.length > 0 && (
          <div style={{ background:'#fef2f2', borderRadius:'14px', border:'1px solid #fecaca', padding:'16px 20px' }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom: expiredQuotes.length > 0 ? '12px' : '0' }}>
              <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
                <span style={{ fontSize:'20px' }}>⏰</span>
                <div>
                  <div style={{ fontWeight:'700', fontSize:'14px', color:'#dc2626' }}>{expiredQuotes.length} utløpte tilbud uten svar</div>
                  <div style={{ fontSize:'12px', color:'#991b1b' }}>Disse tilbudene har passert gyldighetsdato og bør følges opp</div>
                </div>
              </div>
            </div>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {expiredQuotes.slice(0, 5).map(eq => {
                const daysOverdue = Math.floor((new Date() - new Date(eq.valid_until)) / 86400000)
                const { grandTotal: eqTotal } = calcQuote(eq.chapters || [], eq.global_markup)
                return (
                  <div key={eq.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:'white', borderRadius:'10px', padding:'10px 14px', border:'1px solid #fef2f2' }}>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontWeight:'600', fontSize:'13px', color:'#0f172a' }}>{eq.title}</div>
                      <div style={{ fontSize:'11px', color:'#dc2626' }}>
                        {eq.customer_name} · Utløpt {daysOverdue} dager siden · {fmt(eqTotal)}
                        {eq.reminder_count > 0 && <span style={{ color:'#d97706', marginLeft:'8px' }}>📧 {eq.reminder_count} purring{eq.reminder_count > 1 ? 'er' : ''} sendt</span>}
                      </div>
                    </div>
                    <button onClick={(e) => { e.stopPropagation(); setPurringTarget(eq) }}
                      style={{ padding:'6px 14px', background:'#dc2626', color:'white', border:'none', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'600', whiteSpace:'nowrap' }}>
                      📧 Send purring
                    </button>
                    <button onClick={(e) => { e.stopPropagation(); setSelected(eq) }}
                      style={{ padding:'6px 14px', background:'white', color:'#374151', border:'1px solid #e2e8f0', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'600' }}>
                      Vis
                    </button>
                  </div>
                )
              })}
              {expiredQuotes.length > 5 && <p style={{ margin:'4px 0 0', fontSize:'11px', color:'#991b1b', textAlign:'center' }}>+ {expiredQuotes.length - 5} flere utløpte tilbud</p>}
            </div>
          </div>
        )}

        <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding: isMobT ? '10px' : '14px 18px', display:'flex', gap: isMobT ? '8px' : '10px', alignItems:'center', flexWrap:'wrap' }}>
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="🔍  Søk tilbud..." style={{ ...qInp, maxWidth: isMobT ? '100%' : '260px', flex: isMobT ? '1 1 100%' : '1' }} />
          {(search || filterStatus !== 'alle') && <button onClick={() => { setSearch(''); setFilterStatus('alle') }} style={{ background:'#f1f5f9', border:'none', borderRadius:'8px', padding:'9px 14px', fontSize:'13px', cursor:'pointer', color:'#64748b' }}>Nullstill</button>}
          <span style={{ marginLeft:'auto', fontSize:'13px', color:'#94a3b8' }}>{filtered.length} tilbud</span>
        </div>

        {filtered.length === 0 ? (
          <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'60px 20px', textAlign:'center' }}>
            <div style={{ fontSize:'40px', marginBottom:'12px' }}>📋</div>
            <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Ingen tilbud funnet</h3>
            <p style={{ margin:0, color:'#94a3b8', fontSize:'14px' }}>{quotes.length===0 ? 'Opprett ditt første tilbud.' : 'Prøv å endre søk eller filter.'}</p>
          </div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            {filtered.map(q => {
              const cfg = QUOTE_STATUS[q.status]
              const proj = projects.find(p => p.id === q.project_id)
              const { grandTotal } = calcQuote(q.chapters || [], q.global_markup)
              const isExpired = q.valid_until && new Date(q.valid_until) < new Date() && q.status === 'Sendt'
              return (
                <div key={q.id} onClick={() => setSelected(q)}
                  style={{ background:'white', borderRadius: isMobT ? '12px' : '14px', border:`1px solid ${isExpired ? '#fecaca' : '#f1f5f9'}`, padding: isMobT ? '12px' : '16px 20px', cursor:'pointer', display:'flex', alignItems: isMobT ? 'flex-start' : 'center', gap: isMobT ? '10px' : '16px', transition:'box-shadow 0.15s' }}
                  onMouseEnter={e => e.currentTarget.style.boxShadow='0 4px 16px rgba(0,0,0,0.08)'} onMouseLeave={e => e.currentTarget.style.boxShadow='none'}>
                  {!isMobT && <div style={{ width:'44px', height:'44px', borderRadius:'12px', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', flexShrink:0 }}>{cfg.emoji}</div>}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', alignItems:'center', gap: isMobT ? '6px' : '8px', flexWrap:'wrap', marginBottom:'4px' }}>
                      <span style={{ fontWeight:'700', color:'#0f172a', fontSize: isMobT ? '13px' : '15px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', maxWidth: isMobT ? 'calc(100vw - 130px)' : 'none' }}>{q.title}</span>
                      {!isMobT && <span style={{ fontSize:'12px', color:'#94a3b8', fontFamily:'monospace' }}>{q.quote_number}</span>}
                      <QuoteStatusBadge status={q.status} />
                      {(q.revision_number || 1) > 1 && <span style={{ background:'#f5f3ff', color:'#7c3aed', fontSize:'11px', fontWeight:'700', padding:'2px 6px', borderRadius:'4px' }}>Rev.{q.revision_number}</span>}
                      {isExpired && <span style={{ background:'#fef2f2', color:'#dc2626', fontSize:'12px', fontWeight:'600', padding:'2px 8px', borderRadius:'999px', border:'1px solid #fecaca' }}>⏰ Utløpt</span>}
                    </div>
                    <div style={{ display:'flex', gap: isMobT ? '6px' : '12px', flexWrap:'wrap' }}>
                      {q.customer_name && <span style={{ fontSize: isMobT ? '11px' : '12px', color:'#64748b' }}>👤 {q.customer_name}</span>}
                      {!isMobT && proj && <span style={{ fontSize:'12px', color:'#2563eb', fontWeight:'500' }}>🏗️ {proj.name}</span>}
                      {!isMobT && q.valid_until && <span style={{ fontSize:'12px', color:'#64748b' }}>📅 Gyldig til {q.valid_until}</span>}
                    </div>
                  </div>
                  <div style={{ textAlign:'right', flexShrink:0 }}>
                    <div style={{ fontWeight:'800', fontSize: isMobT ? '13px' : '16px', color:'#0f172a' }}>{fmt(grandTotal)}</div>
                    {!isMobT && <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>inkl. påslag</div>}
                  </div>
                  {!isMobT && <span style={{ color:'#94a3b8', fontSize:'18px' }}>›</span>}
                </div>
              )
            })}
          </div>
        )}
      </div>

      {showNew && <TilbudEditorModal projects={projects} user={user} onClose={() => setShowNew(false)} onSaved={() => { setShowNew(false); load() }} />}

      {/* Purring-modal */}
      {purringTarget && <PurringModal quote={purringTarget} user={user} onClose={() => setPurringTarget(null)} onSent={() => { setPurringTarget(null); load() }} />}
    </div>
  )
}

function TilbudDetaljer({ quote: init, projects, user, onBack }) {
  const confirm = useConfirm()
  const [q, setQ] = useState(init)
  const [editing, setEditing] = useState(false)
  const [sendingEmail, setSendingEmail] = useState(false)
  const [showSendModal, setShowSendModal] = useState(false)
  const [showNewRevision, setShowNewRevision] = useState(false)
  const [revisionNote, setRevisionNote] = useState('')
  const [revisions, setRevisions] = useState([])
  const [showRevisions, setShowRevisions] = useState(false)
  const [showPurringModal, setShowPurringModal] = useState(false)
  const cfg = QUOTE_STATUS[q.status]
  const proj = projects.find(p => p.id === q.project_id)
  const { grandTotal, chapterTotals } = calcQuote(q.chapters || [], q.global_markup)

  const refresh = async () => {
    const { data } = await supabase.from('quotes').select('*').eq('id', q.id).single()
    if (data) setQ(data)
  }

  // ── PDF-eksport ────────────────────────────────────────────────────────
  const [exportingPdf, setExportingPdf] = useState(false)
  const exportQuotePDF = async () => {
    setExportingPdf(true)
    try {
      const pdf = await createBrandedPdf()
      const { doc, pw, ph, ml, mr, cw, hex, setC, setF, setD, settings } = pdf
      pdf.drawHeader('TILBUD', q.quote_number || '')
      let y = pdf.y
      const addPage = () => { doc.addPage(); y = 14 }
      const checkSpace = (n) => { if (y + n > ph - 18) addPage() }

      // ── Tittel ──
      setC(hex('#0f172a')); doc.setFontSize(16); doc.setFont('helvetica', 'bold')
      const titleLines = doc.splitTextToSize(q.title || 'Tilbud', cw)
      doc.text(titleLines, ml, y)
      y += titleLines.length * 7 + 2

      // ── Kunde + tilbudsinfo (to-kolonne-kort) ──
      setF(hex('#f8fafc')); setD(hex('#e2e8f0'))
      const infoH = 28
      doc.roundedRect(ml, y, cw, infoH, 2, 2, 'FD')

      // Venstre: Kunde
      setC(hex('#94a3b8')); doc.setFontSize(7); doc.setFont('helvetica', 'bold')
      doc.text('KUNDE', ml + 5, y + 6)
      setC(hex('#0f172a')); doc.setFontSize(10); doc.setFont('helvetica', 'bold')
      doc.text(q.customer_name || '—', ml + 5, y + 12)
      setC(hex('#64748b')); doc.setFontSize(9); doc.setFont('helvetica', 'normal')
      const custDetails = [q.customer_address, q.customer_email, q.customer_phone].filter(Boolean)
      custDetails.slice(0, 2).forEach((line, i) => doc.text(line, ml + 5, y + 17 + i * 4))

      // Høyre: Tilbudsinfo
      const rx = ml + cw / 2 + 4
      setC(hex('#94a3b8')); doc.setFontSize(7); doc.setFont('helvetica', 'bold')
      doc.text('TILBUDSINFO', rx, y + 6)
      setC(hex('#64748b')); doc.setFontSize(9); doc.setFont('helvetica', 'normal')
      const tilbudInfo = [
        q.quote_number && `Nr.: ${q.quote_number}`,
        `Dato: ${q.created_at ? new Date(q.created_at).toLocaleDateString('nb-NO') : new Date().toLocaleDateString('nb-NO')}`,
        q.valid_until && `Gyldig til: ${new Date(q.valid_until).toLocaleDateString('nb-NO')}`,
        q.payment_terms && `Betalingsbetingelser: ${q.payment_terms}`,
        proj?.name && `Prosjekt: ${proj.name}`,
      ].filter(Boolean)
      tilbudInfo.slice(0, 4).forEach((line, i) => doc.text(line, rx, y + 12 + i * 4))
      y += infoH + 6

      // ── Introduksjon (settings.quote_intro_text) ──
      const introText = q.intro_text || settings.quote_intro_text
      if (introText) {
        checkSpace(20)
        setC(hex('#475569')); doc.setFontSize(10); doc.setFont('helvetica', 'normal')
        const iLines = doc.splitTextToSize(introText, cw)
        doc.text(iLines, ml, y)
        y += iLines.length * 5 + 6
      }

      // ── Kapitler ──
      const chapters = q.chapters || []
      chapters.forEach((ch, ci) => {
        const chCalc = calcChapter(ch)
        checkSpace(22)

        // Kapitteltittel
        setC(hex('#0f172a')); doc.setFontSize(12); doc.setFont('helvetica', 'bold')
        const chTitle = `${String(ci + 1).padStart(2, '0')}. ${ch.title || 'Uten tittel'}`
        doc.text(chTitle, ml, y)
        // Kapittel-total høyre
        setC(hex('#059669'))
        doc.text(fmt(chCalc.total), pw - mr, y, { align: 'right' })
        y += 5
        setD(hex('#e2e8f0')); doc.line(ml, y, pw - mr, y)
        y += 4

        // Postene som tabell
        const posts = ch.posts || []
        if (posts.length === 0) {
          setC(hex('#94a3b8')); doc.setFontSize(9); doc.setFont('helvetica', 'italic')
          doc.text('Ingen poster', ml + 4, y + 3)
          y += 8
        } else {
          // Header-rad
          setC(hex('#94a3b8')); doc.setFontSize(7); doc.setFont('helvetica', 'bold')
          const colX = {
            desc: ml + 4,
            qty: ml + cw * 0.50,
            unit: ml + cw * 0.58,
            work: ml + cw * 0.70,
            mat: ml + cw * 0.82,
            sum: pw - mr - 2,
          }
          doc.text('BESKRIVELSE', colX.desc, y + 2)
          doc.text('MENGDE', colX.qty, y + 2, { align: 'right' })
          doc.text('ENHET', colX.unit, y + 2, { align: 'center' })
          doc.text('ARBEID/ENH', colX.work, y + 2, { align: 'right' })
          doc.text('MATERIAL/ENH', colX.mat, y + 2, { align: 'right' })
          doc.text('SUM', colX.sum, y + 2, { align: 'right' })
          y += 4
          setD(hex('#f1f5f9')); doc.line(ml, y, pw - mr, y); y += 3

          posts.forEach(p => {
            const qty = parseFloat(p.qty) || 0
            const uw = parseFloat(p.unitPriceWork) || 0
            const um = parseFloat(p.unitPriceMaterial) || 0
            const postSum = qty * (uw + um)
            const descLines = doc.splitTextToSize(p.description || '—', cw * 0.48)
            const rowH = Math.max(descLines.length * 4 + 2, 6)
            checkSpace(rowH + 2)

            setC(hex('#0f172a')); doc.setFontSize(8.5); doc.setFont('helvetica', 'normal')
            doc.text(descLines, colX.desc, y + 3)
            setC(hex('#475569'))
            doc.text(String(qty || ''), colX.qty, y + 3, { align: 'right' })
            doc.text(p.unit || '', colX.unit, y + 3, { align: 'center' })
            doc.text(uw ? fmt(uw).replace(' kr', '') + ' kr' : '—', colX.work, y + 3, { align: 'right' })
            doc.text(um ? fmt(um).replace(' kr', '') + ' kr' : '—', colX.mat, y + 3, { align: 'right' })
            setC(hex('#0f172a')); doc.setFont('helvetica', 'bold')
            doc.text(fmt(postSum), colX.sum, y + 3, { align: 'right' })
            y += rowH
          })
        }

        // Påslag hvis relevant
        if (ch.markup && parseFloat(ch.markup) > 0) {
          setD(hex('#f1f5f9')); doc.line(ml, y, pw - mr, y); y += 3
          setC(hex('#7c3aed')); doc.setFontSize(8); doc.setFont('helvetica', 'normal')
          doc.text(`Påslag ${ch.markup}%`, ml + 4, y + 3)
          doc.text(fmt(chCalc.total - chCalc.sum), pw - mr, y + 3, { align: 'right' })
          y += 6
        }

        // Kapittel-sum
        setF(hex('#f8fafc'))
        doc.rect(ml, y, cw, 7, 'F')
        setC(hex('#0f172a')); doc.setFontSize(9); doc.setFont('helvetica', 'bold')
        doc.text('Kapittelsum', ml + 4, y + 5)
        doc.text(fmt(chCalc.total), pw - mr - 2, y + 5, { align: 'right' })
        y += 11
      })

      // ── Totaler-kort ──
      checkSpace(36)
      setF(hex('#f0fdf4')); setD(hex('#bbf7d0'))
      doc.roundedRect(ml, y, cw, 32, 2.5, 2.5, 'FD')

      const tx = ml + 6
      const tvx = pw - mr - 6
      let ty = y + 7

      setC(hex('#0f172a')); doc.setFontSize(10); doc.setFont('helvetica', 'normal')
      doc.text('Total eks. mva', tx, ty)
      doc.setFont('helvetica', 'bold'); setC(hex('#059669'))
      doc.text(fmt(grandTotal), tvx, ty, { align: 'right' })
      ty += 6

      setC(hex('#64748b')); doc.setFont('helvetica', 'normal'); doc.setFontSize(9)
      doc.text('Mva 25%', tx, ty)
      doc.text(fmt(grandTotal * 0.25), tvx, ty, { align: 'right' })
      ty += 6

      setD(hex('#bbf7d0')); doc.setLineWidth(0.3); doc.line(tx, ty - 1, tvx, ty - 1)
      ty += 3

      setC(hex('#0f172a')); doc.setFont('helvetica', 'bold'); doc.setFontSize(11)
      doc.text('Total inkl. mva', tx, ty)
      doc.text(fmt(grandTotal * 1.25), tvx, ty, { align: 'right' })
      y += 36

      // ── Avslutning ──
      const outroText = q.outro_text || settings.quote_outro_text
      if (outroText) {
        checkSpace(20)
        setC(hex('#475569')); doc.setFontSize(9); doc.setFont('helvetica', 'italic')
        const oLines = doc.splitTextToSize(outroText, cw)
        doc.text(oLines, ml, y)
        y += oLines.length * 4.5
      }

      pdf.drawFooters()

      const safeName = (q.quote_number || q.title || 'Tilbud').replace(/[^a-zA-Z0-9_-]/g, '_')
      doc.save(`Tilbud - ${safeName}.pdf`)
    } catch(e) { console.error(e); alert('Feil ved PDF: ' + e.message) }
    finally { setExportingPdf(false) }
  }

  // Hent alle revisjoner av dette tilbudet
  const loadRevisions = async () => {
    const rootId = q.parent_quote_id || q.id
    const { data } = await supabase.from('quotes').select('id, title, quote_number, revision_number, revision_note, status, total_amount, created_at')
      .or(`id.eq.${rootId},parent_quote_id.eq.${rootId}`)
      .order('revision_number', { ascending: true })
    setRevisions(data || [])
  }

  useEffect(() => { loadRevisions() }, [q.id])

  const handleDelete = async () => {
    if (!(await confirm({ message: 'Slett dette tilbudet?', subMessage: 'Tilbudet og alle tilhørende linjer slettes permanent.', danger: true }))) return
    await supabase.from('quotes').delete().eq('id', q.id)
    onBack()
  }

  const updateStatus = async (status) => {
    const updates = { status, updated_at: new Date().toISOString() }
    if (status === 'Akseptert') updates.accepted_at = new Date().toISOString()
    await supabase.from('quotes').update(updates).eq('id', q.id)
    setQ(v => ({ ...v, ...updates }))
  }

  // ── Ny revisjon ──
  const createRevision = async () => {
    try {
      const rootId = q.parent_quote_id || q.id
      // Finn høyeste revisjonsnummer
      const maxRev = revisions.length > 0 ? Math.max(...revisions.map(r => r.revision_number || 1)) : (q.revision_number || 1)
      const newRevNumber = maxRev + 1

      // Arkiver gjeldende — sett status til «Erstattet»
      await supabase.from('quotes').update({ status: 'Erstattet', updated_at: new Date().toISOString() }).eq('id', q.id)

      // Opprett ny revisjon
      const { data: existingQ } = await supabase.from('quotes').select('quote_number')
      const newPayload = {
        ...q,
        quote_number: q.quote_number, // behold samme tilbudsnummer
        revision_number: newRevNumber,
        revision_note: revisionNote.trim() || null,
        parent_quote_id: rootId,
        status: 'Utkast',
        sent_at: null,
        accepted_at: null,
        total_amount: grandTotal,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        created_by: user?.id,
      }
      delete newPayload.id
      const { data, error } = await supabase.from('quotes').insert(newPayload).select().single()
      if (error) throw error

      setShowNewRevision(false)
      setRevisionNote('')
      // Naviger til ny revisjon
      setQ(data)
      loadRevisions()
    } catch(e) { alert('Feil ved opprettelse av revisjon: ' + e.message) }
  }

  const isMobTD = typeof window !== 'undefined' && window.innerWidth < 768

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobTD ? '14px' : '20px 32px' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#64748b', fontSize:'13px', marginBottom:'10px', display:'flex', alignItems:'center', gap:'6px', padding:0 }}>← Tilbake til tilbud</button>
        <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap: isMobTD ? '8px' : '16px', flexWrap: isMobTD ? 'wrap' : 'nowrap' }}>
          <div style={{ display:'flex', alignItems:'flex-start', gap: isMobTD ? '10px' : '14px', flex:1, minWidth:0 }}>
            {!isMobTD && <div style={{ width:'52px', height:'52px', borderRadius:'14px', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px', flexShrink:0 }}>{cfg.emoji}</div>}
            <div style={{ minWidth:0 }}>
              <div style={{ display:'flex', alignItems:'center', gap: isMobTD ? '6px' : '10px', flexWrap:'wrap', marginBottom:'4px' }}>
                <h1 style={{ margin:0, fontSize: isMobTD ? '16px' : '20px', fontWeight:'bold', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace: isMobTD ? 'nowrap' : 'normal', maxWidth: isMobTD ? 'calc(100vw - 100px)' : 'none' }}>{q.title}</h1>
                {!isMobTD && <span style={{ fontSize:'13px', color:'#94a3b8', fontFamily:'monospace' }}>{q.quote_number}</span>}
                {(q.revision_number || 1) > 1 && <span style={{ background:'#eff6ff', color:'#2563eb', padding:'2px 8px', borderRadius:'6px', fontSize:'11px', fontWeight:'700' }}>Rev. {q.revision_number}</span>}
                <QuoteStatusBadge status={q.status} />
              </div>
              <div style={{ display:'flex', gap: isMobTD ? '6px' : '12px', flexWrap:'wrap' }}>
                {q.customer_name && <span style={{ fontSize: isMobTD ? '11px' : '13px', color:'#64748b' }}>👤 {q.customer_name}</span>}
                {proj && <span style={{ fontSize: isMobTD ? '11px' : '13px', color:'#2563eb', fontWeight:'500' }}>🏗️ {proj.name}</span>}
                {!isMobTD && q.revision_note && <span style={{ fontSize:'12px', color:'#7c3aed', fontStyle:'italic' }}>📝 {q.revision_note}</span>}
              </div>
            </div>
          </div>
          <div style={{ display:'flex', gap: isMobTD ? '6px' : '8px', flexShrink:0, flexWrap:'wrap' }}>
            {q.status === 'Utkast' && <button onClick={() => setShowSendModal(true)} style={{ padding: isMobTD ? '7px 10px' : '9px 16px', background:'#2563eb', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobTD ? '11px' : '13px', fontWeight:'600' }}>{isMobTD ? '📧 Send' : '📧 Send til kunde'}</button>}
            {q.status === 'Sendt' && <button onClick={() => setShowPurringModal(true)} style={{ padding: isMobTD ? '7px 10px' : '9px 16px', background:'#dc2626', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobTD ? '11px' : '13px', fontWeight:'600' }}>{isMobTD ? '📧 Purring' : '📧 Send purring'}</button>}
            {!isMobTD && <button onClick={() => setShowNewRevision(true)} style={{ padding:'9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'13px', fontWeight:'600', color:'#7c3aed' }}>🔄 Ny revisjon</button>}
            {!isMobTD && <button onClick={exportQuotePDF} disabled={exportingPdf} title="Last ned som PDF" style={{ padding:'9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor: exportingPdf?'not-allowed':'pointer', fontSize:'13px', fontWeight:'600', color:'#374151' }}>{exportingPdf ? '⏳' : '📄 PDF'}</button>}
            {q.status !== 'Akseptert' && <button onClick={() => setEditing(true)} style={{ padding: isMobTD ? '7px 10px' : '9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobTD ? '12px' : '13px' }}>✏️</button>}
            <button onClick={handleDelete} style={{ padding: isMobTD ? '7px 10px' : '9px 12px', border:'1px solid #fecaca', borderRadius:'10px', background:'white', cursor:'pointer', color:'#dc2626', fontSize: isMobTD ? '12px' : '13px' }}>🗑️</button>
          </div>
        </div>
      </div>

      <div style={{ padding: isMobTD ? '12px' : '24px 32px', display:'grid', gridTemplateColumns: isMobTD ? '1fr' : '2fr 1fr', gap: isMobTD ? '12px' : '20px' }}>
        {/* Left - print area */}
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          {/* Header info */}
          <div style={qCard}>
            <div style={{ display:'grid', gridTemplateColumns: isMobTD ? '1fr' : '1fr 1fr', gap: isMobTD ? '12px' : '16px' }}>
              <div>
                <div style={{ fontSize:'12px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom: isMobTD ? '6px' : '10px' }}>Kunde</div>
                {[['Navn', q.customer_name], ['Adresse', q.customer_address], ['Org.nr', q.customer_orgnr], ['E-post', q.customer_email]].filter(r=>r[1]).map(([k,v]) => (
                  <div key={k} style={{ marginBottom:'5px', fontSize:'13px' }}><span style={{ color:'#94a3b8' }}>{k}: </span><span style={{ color:'#0f172a', fontWeight:'500' }}>{v}</span></div>
                ))}
              </div>
              <div>
                <div style={{ fontSize:'12px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'10px' }}>Tilbudsinfo</div>
                {[['Nr.', q.quote_number], ['Dato', q.created_at?.split('T')[0]], ['Gyldig til', q.valid_until], ['Betalingsbetingelser', q.payment_terms], ['Leveringstid', q.delivery_time]].filter(r=>r[1]).map(([k,v]) => (
                  <div key={k} style={{ marginBottom:'5px', fontSize:'13px' }}><span style={{ color:'#94a3b8' }}>{k}: </span><span style={{ color:'#0f172a', fontWeight:'500' }}>{v}</span></div>
                ))}
              </div>
            </div>
            {q.intro_text && <p style={{ margin:'14px 0 0', fontSize:'14px', color:'#475569', lineHeight:1.6, borderTop:'1px solid #f1f5f9', paddingTop:'12px' }}>{q.intro_text}</p>}
          </div>

          {/* Chapters */}
          {(q.chapters || []).map((ch, ci) => {
            const { sum, total } = calcChapter(ch)
            return (
              <div key={ci} style={qCard}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom: isMobTD ? '10px' : '14px', gap:'8px' }}>
                  <h3 style={{ margin:0, fontSize: isMobTD ? '13px' : '15px', fontWeight:'700', color:'#0f172a', minWidth:0, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{String(ci+1).padStart(2,'0')}. {ch.title}</h3>
                  <div style={{ textAlign:'right' }}>
                    {ch.markup > 0 && <div style={{ fontSize:'11px', color:'#94a3b8' }}>Påslag {ch.markup}%</div>}
                    <div style={{ fontWeight:'700', color:'#059669', fontSize:'14px' }}>{fmt(total)}</div>
                  </div>
                </div>
                {isMobTD ? (
                  <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                    {(ch.posts || []).map((p, pi) => {
                      const lineSum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
                      return (
                        <div key={pi} style={{ background:'#f8fafc', borderRadius:'8px', padding:'10px 12px' }}>
                          <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'4px' }}>
                            <span style={{ fontWeight:'600', fontSize:'12px', color:'#0f172a' }}>{p.description || '—'}</span>
                            <span style={{ fontWeight:'700', fontSize:'12px', color:'#059669', whiteSpace:'nowrap', marginLeft:'8px' }}>{fmt(lineSum)}</span>
                          </div>
                          <div style={{ display:'flex', gap:'8px', fontSize:'11px', color:'#64748b' }}>
                            <span>{p.qty} {p.unit}</span>
                            {p.unitPriceWork > 0 && <span>Arb: {fmt(p.unitPriceWork)}</span>}
                            {p.unitPriceMaterial > 0 && <span>Mat: {fmt(p.unitPriceMaterial)}</span>}
                          </div>
                        </div>
                      )
                    })}
                  </div>
                ) : (
                <div style={{ overflowX:'auto', WebkitOverflowScrolling:'touch' }}>
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:'13px' }}>
                  <thead>
                    <tr style={{ background:'#f8fafc' }}>
                      {['Beskrivelse','Mengde','Enhet','Arbeid/enh','Material/enh','Sum'].map((h,hi) => (
                        <th key={hi} style={{ padding:'8px 10px', textAlign: hi>=3 ? 'right':'left', color:'#64748b', fontWeight:'600', fontSize:'11px', textTransform:'uppercase', borderBottom:'1px solid #f1f5f9' }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {(ch.posts || []).map((p, pi) => {
                      const lineSum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
                      return (
                        <tr key={pi} style={{ borderBottom:'1px solid #f8fafc' }}>
                          <td style={{ padding:'9px 10px', color:'#0f172a', fontWeight:'500' }}>{p.description || '—'}</td>
                          <td style={{ padding:'9px 10px', textAlign:'right', color:'#475569' }}>{p.qty}</td>
                          <td style={{ padding:'9px 10px', color:'#475569' }}>{p.unit}</td>
                          <td style={{ padding:'9px 10px', textAlign:'right', color:'#475569' }}>{p.unitPriceWork ? fmt(p.unitPriceWork) : '—'}</td>
                          <td style={{ padding:'9px 10px', textAlign:'right', color:'#475569' }}>{p.unitPriceMaterial ? fmt(p.unitPriceMaterial) : '—'}</td>
                          <td style={{ padding:'9px 10px', textAlign:'right', fontWeight:'700', color:'#0f172a' }}>{fmt(lineSum)}</td>
                        </tr>
                      )
                    })}
                  </tbody>
                </table>
                </div>
                )}
                {ch.description && <p style={{ margin:'10px 0 0', fontSize:'13px', color:'#94a3b8', fontStyle:'italic' }}>{ch.description}</p>}
              </div>
            )
          })}

          {/* Totals */}
          <div style={{ ...qCard, background:'#f8fafc' }}>
            <div style={{ display:'flex', flexDirection:'column', gap:'8px', maxWidth: isMobTD ? '100%' : '320px', marginLeft: isMobTD ? '0' : 'auto' }}>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', color:'#475569' }}>
                <span>Kapittelsum</span><span style={{ fontWeight:'600' }}>{fmt(chapterTotals)}</span>
              </div>
              {parseFloat(q.global_markup) > 0 && (
                <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', color:'#475569' }}>
                  <span>Generelt påslag ({q.global_markup}%)</span>
                  <span style={{ fontWeight:'600' }}>{fmt(grandTotal - chapterTotals)}</span>
                </div>
              )}
              <div style={{ display:'flex', justifyContent:'space-between', fontSize: isMobTD ? '15px' : '17px', fontWeight:'800', color:'#0f172a', borderTop:'2px solid #e2e8f0', paddingTop:'10px', marginTop:'4px' }}>
                <span>Total eks. mva</span><span style={{ color:'#059669' }}>{fmt(grandTotal)}</span>
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'13px', color:'#94a3b8' }}>
                <span>Mva 25%</span><span>{fmt(grandTotal * 0.25)}</span>
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'15px', fontWeight:'700', color:'#0f172a' }}>
                <span>Total inkl. mva</span><span>{fmt(grandTotal * 1.25)}</span>
              </div>
            </div>
          </div>

          {q.outro_text && <div style={qCard}><p style={{ margin:0, fontSize:'14px', color:'#475569', lineHeight:1.6 }}>{q.outro_text}</p></div>}
        </div>

        {/* Right sidebar */}
        <div className="no-print" style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          {/* Status */}
          <div style={qCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🔄 Status</h3>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {Object.keys(QUOTE_STATUS).map(s => (
                <button key={s} onClick={() => updateStatus(s)} disabled={q.status===s}
                  style={{ padding:'9px 14px', borderRadius:'10px', border:`1px solid ${q.status===s ? QUOTE_STATUS[s].border : '#e2e8f0'}`, background: q.status===s ? QUOTE_STATUS[s].bg : 'white', color: q.status===s ? QUOTE_STATUS[s].color : '#475569', fontWeight: q.status===s ? '700':'400', fontSize:'13px', cursor: q.status===s ? 'default':'pointer', textAlign:'left', width:'100%' }}>
                  {q.status===s ? '✓ ':''}{QUOTE_STATUS[s].emoji} {s}
                </button>
              ))}
            </div>
          </div>

          {/* Summary */}
          <div style={qCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>💰 Oppsummering</h3>
            <div style={{ background:'#f0fdf4', borderRadius:'10px', padding:'14px', textAlign:'center', border:'1px solid #bbf7d0' }}>
              <div style={{ fontSize:'11px', color:'#16a34a', fontWeight:'600', textTransform:'uppercase', marginBottom:'4px' }}>Total eks. mva</div>
              <div style={{ fontSize:'22px', fontWeight:'800', color:'#0f172a' }}>{fmt(grandTotal)}</div>
            </div>
            <div style={{ marginTop:'10px', display:'flex', flexDirection:'column', gap:'5px' }}>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'12px', color:'#94a3b8' }}><span>Mva 25%</span><span>{fmt(grandTotal*0.25)}</span></div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'13px', fontWeight:'700', color:'#0f172a' }}><span>Inkl. mva</span><span>{fmt(grandTotal*1.25)}</span></div>
            </div>
          </div>

          {/* Info */}
          <div style={qCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>ℹ️ Detaljer</h3>
            {[['Prosjekt', proj?.name], ['Revisjon', `Rev. ${q.revision_number || 1}`], ['Gyldig til', q.valid_until], ['Betalingsbetingelser', q.payment_terms], ['Leveringstid', q.delivery_time], ['Sendt', q.sent_at ? new Date(q.sent_at).toLocaleDateString('nb-NO') : null], ['Akseptert', q.accepted_at ? new Date(q.accepted_at).toLocaleDateString('nb-NO') : null]].filter(r=>r[1]).map(([k,v],i)=>(
              <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize:'13px' }}>
                <span style={{ color:'#94a3b8' }}>{k}</span><span style={{ fontWeight:'500', color:'#0f172a', textAlign:'right', maxWidth:'55%' }}>{v}</span>
              </div>
            ))}
          </div>

          {/* Revisjonshistorikk */}
          {revisions.length > 1 && (
            <div style={qCard}>
              <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>📜 Revisjoner ({revisions.length})</h3>
              <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
                {revisions.map((rev, i) => {
                  const isCurrent = rev.id === q.id
                  const revTotal = rev.total_amount || 0
                  const prevTotal = i > 0 ? (revisions[i-1].total_amount || 0) : 0
                  const diff = i > 0 ? revTotal - prevTotal : 0
                  return (
                    <div key={rev.id}
                      onClick={() => { if (!isCurrent) { setQ(null); supabase.from('quotes').select('*').eq('id', rev.id).single().then(({ data }) => { if (data) setQ(data) }) } }}
                      style={{ padding:'10px 12px', borderRadius:'10px', cursor: isCurrent ? 'default' : 'pointer',
                        background: isCurrent ? '#eff6ff' : '#f8fafc', border: `1px solid ${isCurrent ? '#bfdbfe' : '#f1f5f9'}`,
                        transition:'border-color 0.15s' }}
                      onMouseEnter={e => { if (!isCurrent) e.currentTarget.style.borderColor = '#e2e8f0' }}
                      onMouseLeave={e => { if (!isCurrent) e.currentTarget.style.borderColor = '#f1f5f9' }}>
                      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'2px' }}>
                        <div style={{ display:'flex', alignItems:'center', gap:'6px' }}>
                          <span style={{ background: isCurrent ? '#2563eb' : '#e2e8f0', color: isCurrent ? 'white' : '#64748b', fontSize:'10px', fontWeight:'700', padding:'1px 6px', borderRadius:'4px' }}>Rev. {rev.revision_number || 1}</span>
                          {isCurrent && <span style={{ fontSize:'10px', color:'#2563eb', fontWeight:'600' }}>Gjeldende</span>}
                          {rev.status === 'Erstattet' && <span style={{ fontSize:'10px', color:'#94a3b8' }}>Erstattet</span>}
                        </div>
                        <span style={{ fontSize:'12px', fontWeight:'700', color:'#0f172a' }}>{fmt(revTotal)}</span>
                      </div>
                      <div style={{ fontSize:'11px', color:'#94a3b8' }}>
                        {new Date(rev.created_at).toLocaleDateString('nb-NO')}
                        {i > 0 && diff !== 0 && (
                          <span style={{ color: diff > 0 ? '#dc2626' : '#059669', fontWeight:'600', marginLeft:'6px' }}>
                            {diff > 0 ? '▲' : '▼'} {diff > 0 ? '+' : ''}{fmt(diff)}
                          </span>
                        )}
                      </div>
                      {rev.revision_note && <div style={{ fontSize:'11px', color:'#7c3aed', marginTop:'2px', fontStyle:'italic' }}>{rev.revision_note}</div>}
                    </div>
                  )
                })}
              </div>
            </div>
          )}
        </div>
      </div>

      {editing && <TilbudEditorModal projects={projects} user={user} initial={q} onClose={() => setEditing(false)} onSaved={() => { setEditing(false); refresh() }} />}
      {showSendModal && <SendTilbudModal quote={q} user={user} onClose={() => setShowSendModal(false)} onSent={() => { setShowSendModal(false); refresh() }} />}
      {showPurringModal && <PurringModal quote={q} user={user} onClose={() => setShowPurringModal(false)} onSent={() => { setShowPurringModal(false); refresh() }} />}

      {/* Ny revisjon modal */}
      {showNewRevision && (
        <>
          <div onClick={() => setShowNewRevision(false)} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.45)', zIndex:100 }} />
          <div style={{ position:'fixed', top:'50%', left:'50%', transform:'translate(-50%,-50%)', background:'white', borderRadius:'20px', width:'min(500px, calc(100vw - 32px))', zIndex:101, boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
            <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9' }}>
              <h2 style={{ margin:0, fontSize:'17px', fontWeight:'700', color:'#0f172a' }}>🔄 Opprett ny revisjon</h2>
            </div>
            <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'16px' }}>
              <div style={{ background:'#eff6ff', borderRadius:'10px', padding:'14px 16px', border:'1px solid #bfdbfe' }}>
                <div style={{ fontSize:'12px', fontWeight:'600', color:'#2563eb', marginBottom:'4px' }}>Gjeldende tilbud</div>
                <div style={{ fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>{q.title} — Rev. {q.revision_number || 1}</div>
                <div style={{ fontSize:'13px', color:'#64748b', marginTop:'2px' }}>{q.quote_number} · {fmt(grandTotal)} eks. mva</div>
              </div>
              <div style={{ background:'#faf5ff', borderRadius:'10px', padding:'12px 16px', border:'1px solid #e9d5ff', fontSize:'13px', color:'#7c3aed', lineHeight:1.5 }}>
                En ny revisjon (Rev. {(q.revision_number || 1) + 1}) opprettes som kopi av gjeldende tilbud. Det gamle tilbudet settes til status «Erstattet». Du kan deretter redigere den nye versjonen.
              </div>
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Hva er endret? (valgfritt)</label>
                <textarea value={revisionNote} onChange={e => setRevisionNote(e.target.value)} placeholder="F.eks. «Justert pris etter tilbakemelding fra kunde» eller «Lagt til ekstra kapittel for utomhus»"
                  rows={3} style={{ width:'100%', padding:'10px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', resize:'none', fontFamily:'system-ui,sans-serif' }} autoFocus />
              </div>
              <div style={{ display:'flex', justifyContent:'flex-end', gap:'10px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
                <button onClick={() => setShowNewRevision(false)} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={createRevision} style={{ padding:'10px 24px', background:'#7c3aed', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'14px', fontWeight:'600' }}>🔄 Opprett Rev. {(q.revision_number || 1) + 1}</button>
              </div>
            </div>
          </div>
        </>
      )}
    </div>
  )
}

function TilbudEditorModal({ projects, user, initial, onClose, onSaved }) {
  const isEdit = !!initial
  const [step, setStep] = useState(1) // 1=info, 2=kapitler
  const [form, setForm] = useState({
    title: initial?.title || '',
    quote_number: initial?.quote_number || '',
    project_id: initial?.project_id || '',
    customer_name: initial?.customer_name || '',
    customer_email: initial?.customer_email || '',
    customer_address: initial?.customer_address || '',
    customer_orgnr: initial?.customer_orgnr || '',
    customer_id: initial?.customer_id || null,
    valid_until: initial?.valid_until || '',
    payment_terms: initial?.payment_terms || '30 dager netto',
    delivery_time: initial?.delivery_time || '',
    intro_text: initial?.intro_text || '',
    outro_text: initial?.outro_text || 'Vi håper tilbudet er av interesse og ser frem til et godt samarbeid.',
    global_markup: initial?.global_markup || 0,
  })
  // Generer sekvensielt nummer ved nyopprettelse
  useEffect(() => {
    if (!isEdit && !form.quote_number) {
      supabase.from('quotes').select('quote_number').then(({ data }) => {
        setForm(f => ({ ...f, quote_number: nextSequenceNumber(data || [], 'TB', 'quote_number') }))
      })
    }
  }, [])
  const [chapters, setChapters] = useState(initial?.chapters || [
    { id: Date.now(), title: 'Generelt', description: '', markup: 0, posts: [{ id: Date.now()+1, description: '', qty: 1, unit: 'stk', unitPriceWork: 0, unitPriceMaterial: 0 }] }
  ])
  const [saving, setSaving] = useState(false)
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }))

  // Chapter helpers
  const addChapter = () => setChapters(c => [...c, { id: Date.now(), title: `Kapittel ${c.length+1}`, description: '', markup: 0, posts: [{ id: Date.now()+1, description: '', qty: 1, unit: 'stk', unitPriceWork: 0, unitPriceMaterial: 0 }] }])
  const removeChapter = (id) => setChapters(c => c.filter(x => x.id !== id))
  const updateChapter = (id, f, v) => setChapters(c => c.map(x => x.id === id ? { ...x, [f]: v } : x))
  const addPost = (chId) => setChapters(c => c.map(x => x.id === chId ? { ...x, posts: [...x.posts, { id: Date.now(), description: '', qty: 1, unit: 'stk', unitPriceWork: 0, unitPriceMaterial: 0 }] } : x))
  const removePost = (chId, pId) => setChapters(c => c.map(x => x.id === chId ? { ...x, posts: x.posts.filter(p => p.id !== pId) } : x))
  const updatePost = (chId, pId, f, v) => setChapters(c => c.map(x => x.id === chId ? { ...x, posts: x.posts.map(p => p.id === pId ? { ...p, [f]: v } : p) } : x))

  const handleSave = async () => {
    if (!form.title.trim()) return alert('Tittel er påkrevd')
    setSaving(true)
    try {
      // Felles kunde-oppløsning: finner eller oppretter kunde i customers-tabellen
      const { customerId } = await resolveCustomerFromForm({
        form,
        user,
        initialCustomerId: initial?.customer_id,
        statusOnCreate: 'tilbud_sendt',
      })

      const payload = sanitizeDbPayload({ ...form, chapters, updated_at: new Date().toISOString(), project_id: form.project_id || null, customer_id: customerId })
      if (isEdit) {
        const { error } = await supabase.from('quotes').update(payload).eq('id', initial.id)
        if (error) throw error
      } else {
        const { error } = await supabase.from('quotes').insert({ ...payload, status: 'Utkast', created_by: user?.id })
        if (error) throw error
      }
      onSaved()
    } catch(e) { alert('Feil: ' + e.message) }
    finally { setSaving(false) }
  }

  const lbl = t => <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>{t}</label>
  const { grandTotal } = calcQuote(chapters, form.global_markup)
  const isMobTE = typeof window !== 'undefined' && window.innerWidth < 768

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems: isMobTE ? 'stretch' : 'center', justifyContent:'center', padding: isMobTE ? '0' : '16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius: isMobTE ? '0' : '20px', width:'100%', maxWidth: isMobTE ? '100%' : '900px', maxHeight: isMobTE ? '100vh' : '94vh', height: isMobTE ? '100vh' : 'auto', display:'flex', flexDirection:'column', boxShadow: isMobTE ? 'none' : '0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        {/* Modal header */}
        <div style={{ padding: isMobTE ? '12px 14px' : '18px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', alignItems:'center', justifyContent:'space-between', flexShrink:0, gap:'8px' }}>
          <div style={{ display:'flex', alignItems:'center', gap: isMobTE ? '8px' : '16px', flex:1, minWidth:0 }}>
            <h2 style={{ margin:0, fontSize: isMobTE ? '14px' : '18px', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>📋 {isEdit ? 'Rediger' : 'Nytt'} tilbud</h2>
            <div style={{ display:'flex', gap:'4px' }}>
              {[['1', isMobTE ? 'Info' : 'Informasjon'],['2', isMobTE ? 'Poster' : 'Kapitler & Poster']].map(([n, label]) => (
                <button key={n} onClick={() => setStep(+n)}
                  style={{ padding: isMobTE ? '4px 10px' : '6px 14px', borderRadius:'8px', border:'none', background: step===+n ? '#059669' : '#f1f5f9', color: step===+n ? 'white' : '#64748b', fontWeight: step===+n ? '700':'500', fontSize: isMobTE ? '11px' : '13px', cursor:'pointer' }}>
                  {n}. {label}
                </button>
              ))}
            </div>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap: isMobTE ? '6px' : '10px', flexShrink:0 }}>
            {!isMobTE && <span style={{ fontSize:'13px', color:'#94a3b8' }}>Total: <strong style={{ color:'#059669' }}>{fmt(grandTotal)}</strong></span>}
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
          </div>
        </div>

        <div style={{ overflowY:'auto', flex:1, padding: isMobTE ? '14px' : '24px', WebkitOverflowScrolling:'touch' }}>
          {/* STEP 1 - Info */}
          {step === 1 && (
            <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'16px' }}>
              <div style={{ gridColumn:'1/-1' }}>{lbl('Tilbudstittel *')}<input value={form.title} onChange={e=>set('title',e.target.value)} placeholder="F.eks. Tilbud betongarbeider Blokk B" style={qInp} /></div>
              <div>{lbl('Tilbudsnummer')}<input value={form.quote_number} onChange={e=>set('quote_number',e.target.value)} style={qInp} /></div>
              <div>{lbl('Knytt til prosjekt')}<SearchableProjectSelect value={form.project_id} onChange={v => set('project_id', v)} projects={projects} style={qInp} placeholder="Ingen" /></div>
              <div style={{ gridColumn:'1/-1', borderTop:'1px solid #f1f5f9', paddingTop:'16px' }}><div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', marginBottom:'12px' }}>👤 Kundeinformasjon</div></div>
              <div style={{ gridColumn:'1/-1' }}>
                {lbl('Velg eksisterende kunde')}
                <CustomerSelect
                  value={form.customer_id}
                  valueAsId
                  onChange={v => set('customer_id', v)}
                  onSelect={c => {
                    set('customer_id', c.id)
                    set('customer_name', c.name || '')
                    if (c.email) set('customer_email', c.email)
                    if (c.address) set('customer_address', c.address)
                    if (c.orgnr) set('customer_orgnr', c.orgnr)
                  }}
                  placeholder="Søk etter kunde — eller fyll ut feltene under for ny kunde"
                />
                <p style={{ margin:'4px 0 0', fontSize:'11px', color:'#94a3b8' }}>
                  Velger du en eksisterende kunde blir feltene under autofylt. Lar du være og skriver inn manuelt, opprettes en ny kunde automatisk i Kundeoversikt ved lagring.
                </p>
              </div>
              <div>{lbl('Kundenavn')}<input value={form.customer_name} onChange={e=>set('customer_name',e.target.value)} placeholder="Firmanavn eller personnavn" style={qInp} /></div>
              <div>{lbl('E-post')}<input type="email" value={form.customer_email} onChange={e=>set('customer_email',e.target.value)} placeholder="kunde@epost.no" style={qInp} /></div>
              <div>{lbl('Adresse')}<input value={form.customer_address} onChange={e=>set('customer_address',e.target.value)} placeholder="Gateadresse, postnummer sted" style={qInp} /></div>
              <div>{lbl('Org.nr / Fødselsnr')}<input value={form.customer_orgnr} onChange={e=>set('customer_orgnr',e.target.value)} placeholder="123 456 789" style={qInp} /></div>
              <div style={{ gridColumn:'1/-1', borderTop:'1px solid #f1f5f9', paddingTop:'16px' }}><div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', marginBottom:'12px' }}>📅 Betingelser</div></div>
              <div>{lbl('Gyldig til')}<input type="date" value={form.valid_until} onChange={e=>set('valid_until',e.target.value)} style={qInp} /></div>
              <div>{lbl('Betalingsbetingelser')}<input value={form.payment_terms} onChange={e=>set('payment_terms',e.target.value)} placeholder="30 dager netto" style={qInp} /></div>
              <div>{lbl('Leveringstid')}<input value={form.delivery_time} onChange={e=>set('delivery_time',e.target.value)} placeholder="F.eks. 3–4 uker" style={qInp} /></div>
              <div>{lbl('Generelt påslag (%)')}<input type="number" value={form.global_markup} onChange={e=>set('global_markup',e.target.value)} placeholder="0" min="0" max="100" style={qInp} /></div>
              <div style={{ gridColumn:'1/-1' }}>{lbl('Innledende tekst')}<textarea value={form.intro_text} onChange={e=>set('intro_text',e.target.value)} rows={3} placeholder="Takk for henvendelse. Vi tillater oss å fremme følgende tilbud..." style={{ ...qInp, resize:'none' }} /></div>
              <div style={{ gridColumn:'1/-1' }}>{lbl('Avsluttende tekst')}<textarea value={form.outro_text} onChange={e=>set('outro_text',e.target.value)} rows={2} style={{ ...qInp, resize:'none' }} /></div>
            </div>
          )}

          {/* STEP 2 - Chapters */}
          {step === 2 && (
            <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
              {chapters.map((ch, ci) => {
                const { sum, total } = calcChapter(ch)
                return (
                  <div key={ch.id} style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', overflow:'hidden', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }}>
                    {/* Chapter header */}
                    <div style={{ background:'#f8fafc', padding: isMobTE ? '10px 12px' : '14px 18px', display:'flex', alignItems:'center', gap: isMobTE ? '6px' : '12px', borderBottom:'1px solid #f1f5f9', flexWrap: isMobTE ? 'wrap' : 'nowrap' }}>
                      <span style={{ width:'24px', height:'24px', borderRadius:'50%', background:'#059669', color:'white', fontWeight:'800', fontSize:'11px', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{ci+1}</span>
                      <input value={ch.title} onChange={e=>updateChapter(ch.id,'title',e.target.value)} placeholder="Kapittelittel" style={{ ...qInp, flex:1, background:'transparent', border:'1px solid #e2e8f0', fontWeight:'700', minWidth: isMobTE ? '120px' : 'auto', fontSize: isMobTE ? '13px' : '14px' }} />
                      <input type="number" value={ch.markup} onChange={e=>updateChapter(ch.id,'markup',e.target.value)} placeholder="%" min="0" max="100" style={{ ...qInp, width: isMobTE ? '60px' : '100px', fontSize: isMobTE ? '12px' : '14px' }} title="Påslag %" />
                      <span style={{ fontWeight:'700', color:'#059669', fontSize: isMobTE ? '12px' : '14px', whiteSpace:'nowrap' }}>{fmt(total)}</span>
                      {chapters.length > 1 && <button onClick={()=>removeChapter(ch.id)} style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'8px', padding:'5px 8px', cursor:'pointer', fontSize:'12px' }}>🗑️</button>}
                    </div>
                    {/* Posts table */}
                    <div style={{ padding: isMobTE ? '10px' : '14px 18px', overflowX: isMobTE ? 'auto' : 'visible', WebkitOverflowScrolling:'touch' }}>
                      <table style={{ width:'100%', borderCollapse:'collapse', minWidth: isMobTE ? '600px' : 'auto' }}>
                        <thead>
                          <tr>
                            {['Beskrivelse','Mengde','Enhet','Arbeid kr/enh','Material kr/enh','Sum',''].map((h,i) => (
                              <th key={i} style={{ padding:'6px 8px', textAlign:i>=3&&i<=5?'right':'left', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase', borderBottom:'1px solid #f1f5f9' }}>{h}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {ch.posts.map(p => {
                            const lineSum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0))
                            return (
                              <tr key={p.id}>
                                <td style={{ padding:'6px 4px' }}><input value={p.description} onChange={e=>updatePost(ch.id,p.id,'description',e.target.value)} placeholder="Beskriv arbeid/materiale" style={{ ...qInp, minWidth:'180px' }} /></td>
                                <td style={{ padding:'6px 4px' }}><input type="number" value={p.qty} onChange={e=>updatePost(ch.id,p.id,'qty',e.target.value)} style={{ ...qInp, width:'70px', textAlign:'right' }} /></td>
                                <td style={{ padding:'6px 4px' }}><input value={p.unit} onChange={e=>updatePost(ch.id,p.id,'unit',e.target.value)} placeholder="stk" style={{ ...qInp, width:'60px' }} /></td>
                                <td style={{ padding:'6px 4px' }}><input type="number" value={p.unitPriceWork} onChange={e=>updatePost(ch.id,p.id,'unitPriceWork',e.target.value)} style={{ ...qInp, width:'110px', textAlign:'right' }} /></td>
                                <td style={{ padding:'6px 4px' }}><input type="number" value={p.unitPriceMaterial} onChange={e=>updatePost(ch.id,p.id,'unitPriceMaterial',e.target.value)} style={{ ...qInp, width:'110px', textAlign:'right' }} /></td>
                                <td style={{ padding:'6px 8px', textAlign:'right', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>{fmt(lineSum)}</td>
                                <td style={{ padding:'6px 4px' }}>{ch.posts.length>1&&<button onClick={()=>removePost(ch.id,p.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'16px' }}>×</button>}</td>
                              </tr>
                            )
                          })}
                        </tbody>
                      </table>
                      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginTop:'10px' }}>
                        <button onClick={()=>addPost(ch.id)} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>+ Legg til post</button>
                        <div style={{ fontSize:'13px', color:'#64748b' }}>Kapittelsum: <strong style={{ color:'#0f172a' }}>{fmt(sum)}</strong>{ch.markup>0?` + påslag = ${fmt(total)}`:''}</div>
                      </div>
                      {ch.description !== undefined && <textarea value={ch.description} onChange={e=>updateChapter(ch.id,'description',e.target.value)} rows={1} placeholder="Kapittelnotat (valgfritt)" style={{ ...qInp, marginTop:'8px', resize:'none', fontSize:'12px', color:'#94a3b8' }} />}
                    </div>
                  </div>
                )
              })}
              <button onClick={addChapter} style={{ background:'white', border:'2px dashed #e2e8f0', borderRadius:'14px', padding:'16px', cursor:'pointer', color:'#94a3b8', fontWeight:'600', fontSize:'14px', width:'100%' }}>+ Legg til kapittel</button>

              {/* Grand total */}
              <div style={{ background:'#f0fdf4', borderRadius:'14px', padding:'18px 24px', border:'1px solid #bbf7d0' }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                  <div>
                    <div style={{ fontSize:'13px', color:'#16a34a', fontWeight:'600' }}>Total eks. mva</div>
                    {parseFloat(form.global_markup)>0 && <div style={{ fontSize:'12px', color:'#94a3b8' }}>Inkl. generelt påslag {form.global_markup}%</div>}
                  </div>
                  <div style={{ fontSize:'24px', fontWeight:'800', color:'#0f172a' }}>{fmt(grandTotal)}</div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{ padding: isMobTE ? '12px 14px' : '16px 24px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0, gap:'8px' }}>
          <div style={{ display:'flex', gap:'8px' }}>
            {step === 2 && <button onClick={()=>setStep(1)} style={{ padding: isMobTE ? '8px 12px' : '10px 18px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobTE ? '12px' : '14px', fontWeight:'500' }}>← Tilbake</button>}
          </div>
          {isMobTE && <span style={{ fontSize:'12px', color:'#059669', fontWeight:'700' }}>{fmt(grandTotal)}</span>}
          <div style={{ display:'flex', gap: isMobTE ? '6px' : '10px' }}>
            {step === 1 && <button onClick={()=>setStep(2)} style={{ padding: isMobTE ? '8px 14px' : '10px 24px', background:'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobTE ? '12px' : '14px', fontWeight:'600' }}>{isMobTE ? 'Neste →' : 'Neste: Kapitler →'}</button>}
            {step === 2 && <button onClick={handleSave} disabled={saving} style={{ padding: isMobTE ? '8px 14px' : '10px 24px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize: isMobTE ? '12px' : '14px', fontWeight:'600' }}>{saving?'Lagrer...':isEdit?'Lagre':'Opprett'}</button>}
          </div>
        </div>
      </div>
    </div>
  )
}

function SendTilbudModal({ quote, user, onClose, onSent }) {
  const [email, setEmail] = useState(quote.customer_email || '')
  const [sending, setSending] = useState(false)
  const [sent, setSent] = useState(false)
  const { grandTotal } = calcQuote(quote.chapters || [], quote.global_markup)

  const handleSend = async () => {
    if (!email) return alert('E-postadresse er påkrevd')
    setSending(true)
    try {
      const approvalUrl = await createApprovalToken({ module: 'quote', recordId: quote.id, recipientEmail: email, createdBy: user?.id })
      const emailHtml = `
        <div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">
          <h1 style="color:#0f172a;font-size:22px;margin-bottom:8px">${quote.title}</h1>
          <p style="color:#64748b;font-size:14px">Tilbudsnummer: <strong>${quote.quote_number}</strong></p>
          ${quote.intro_text ? `<p style="color:#475569;line-height:1.6">${quote.intro_text}</p>` : ''}
          <div style="background:#f0fdf4;border-radius:12px;padding:20px;margin:20px 0;border:1px solid #bbf7d0">
            <div style="font-size:13px;color:#16a34a;font-weight:600;margin-bottom:4px">TOTALSUM EKS. MVA</div>
            <div style="font-size:28px;font-weight:800;color:#0f172a">${fmt(grandTotal)}</div>
            <div style="font-size:13px;color:#64748b;margin-top:4px">Inkl. mva: ${fmt(grandTotal*1.25)}</div>
          </div>
          ${quote.valid_until ? `<p style="color:#64748b;font-size:13px">Tilbudet er gyldig til: <strong>${quote.valid_until}</strong></p>` : ''}
          ${quote.payment_terms ? `<p style="color:#64748b;font-size:13px">Betalingsbetingelser: <strong>${quote.payment_terms}</strong></p>` : ''}
          <div style="text-align:center;margin:32px 0">
            <a href="${approvalUrl}" style="background:#059669;color:white;padding:16px 32px;border-radius:12px;text-decoration:none;font-weight:700;font-size:16px;display:inline-block">✅ Godkjenn tilbud</a>
          </div>
          ${quote.outro_text ? `<p style="color:#64748b;font-size:13px;line-height:1.6">${quote.outro_text}</p>` : ''}
          <hr style="border:none;border-top:1px solid #f1f5f9;margin:24px 0">
          <p style="color:#94a3b8;font-size:12px">Sendt via En Plattform KS-system</p>
        </div>
      `
      const fnRes = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY, 'Authorization': `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}` },
        body: JSON.stringify({ to: email, subject: `Tilbud ${quote.quote_number} – ${quote.title}`, html: emailHtml })
      })
      const fnData = await fnRes.json()
      if (!fnRes.ok || fnData?.error) throw new Error(fnData?.error || 'Sending feilet')

      await supabase.from('quotes').update({ status: 'Sendt', sent_at: new Date().toISOString(), customer_email: email }).eq('id', quote.id)
      setSent(true)
      setTimeout(() => onSent(), 1500)
    } catch(e) { alert('Kunne ikke sende: ' + e.message) }
    finally { setSending(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'480px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>📧 Send tilbud til kunde</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'16px' }}>
          {sent ? (
            <div style={{ textAlign:'center', padding:'20px 0' }}>
              <div style={{ fontSize:'48px', marginBottom:'12px' }}>✅</div>
              <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Tilbud sendt!</h3>
              <p style={{ margin:0, color:'#64748b', fontSize:'14px' }}>Kunden mottar en e-post med godkjenningsknapp</p>
            </div>
          ) : (
            <>
              <div style={{ background:'#f0fdf4', borderRadius:'12px', padding:'14px', border:'1px solid #bbf7d0' }}>
                <div style={{ fontSize:'13px', color:'#16a34a', fontWeight:'600' }}>Tilbud: {quote.title}</div>
                <div style={{ fontSize:'20px', fontWeight:'800', color:'#0f172a', marginTop:'4px' }}>{fmt(grandTotal)}</div>
              </div>
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>E-postadresse til kunde *</label>
                <input type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="kunde@epost.no" style={qInp} />
              </div>
              <div style={{ background:'#fffbeb', borderRadius:'10px', padding:'12px 14px', border:'1px solid #fde68a', fontSize:'13px', color:'#92400e' }}>
                ⚠️ Kunden mottar en e-post med en <strong>godkjenningsknapp</strong>. Når de klikker, oppdateres tilbudet automatisk til «Akseptert» og du får et varsel i systemet.
              </div>
              <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
                <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={handleSend} disabled={sending} style={{ padding:'10px 24px', background:sending?'#6ee7b7':'#2563eb', color:'white', border:'none', borderRadius:'10px', cursor:sending?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{sending?'Sender...':'📧 Send nå'}</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}

function PurringModal({ quote, user, onClose, onSent }) {
  const [sending, setSending] = useState(false)
  const [sent, setSent] = useState(false)
  const [newValidUntil, setNewValidUntil] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() + 14); return d.toISOString().split('T')[0]
  })
  const { grandTotal } = calcQuote(quote.chapters || [], quote.global_markup)
  const daysOverdue = quote.valid_until ? Math.floor((new Date() - new Date(quote.valid_until)) / 86400000) : 0
  const reminderCount = (quote.reminder_count || 0) + 1

  const handleSendPurring = async () => {
    const email = quote.customer_email
    if (!email) return alert('Ingen e-postadresse registrert for denne kunden')
    setSending(true)
    try {
      const approvalUrl = await createApprovalToken({ module: 'quote', recordId: quote.id, recipientEmail: email, createdBy: user?.id })
      const emailHtml = `
        <div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">
          <div style="background:#fef2f2;border-radius:12px;padding:16px 20px;margin-bottom:20px;border:1px solid #fecaca">
            <p style="margin:0;color:#dc2626;font-weight:600;font-size:14px">Purring — tilbud utløpt</p>
          </div>
          <h1 style="color:#0f172a;font-size:20px;margin-bottom:8px">${quote.title}</h1>
          <p style="color:#64748b;font-size:14px">Tilbudsnummer: <strong>${quote.quote_number}</strong></p>
          <p style="color:#475569;line-height:1.6;font-size:14px">Vi har sendt et tilbud som utløp ${quote.valid_until}. Vi ønsker å følge opp og høre om dere fortsatt er interessert.</p>
          <div style="background:#f0fdf4;border-radius:12px;padding:20px;margin:20px 0;border:1px solid #bbf7d0">
            <div style="font-size:13px;color:#16a34a;font-weight:600;margin-bottom:4px">TOTALSUM EKS. MVA</div>
            <div style="font-size:28px;font-weight:800;color:#0f172a">${fmt(grandTotal)}</div>
          </div>
          <p style="color:#475569;font-size:14px">Tilbudet er forlenget med ny gyldighetsdato: <strong>${newValidUntil}</strong></p>
          <div style="text-align:center;margin:32px 0">
            <a href="${approvalUrl}" style="background:#059669;color:white;padding:16px 32px;border-radius:12px;text-decoration:none;font-weight:700;font-size:16px;display:inline-block">✅ Godkjenn tilbud</a>
          </div>
          <p style="color:#94a3b8;font-size:12px">Purring ${reminderCount} — sendt via En Plattform</p>
        </div>
      `
      const fnRes = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY, 'Authorization': `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}` },
        body: JSON.stringify({ to: email, subject: `Purring: Tilbud ${quote.quote_number} – ${quote.title}`, html: emailHtml })
      })
      const fnData = await fnRes.json()
      if (!fnRes.ok || fnData?.error) throw new Error(fnData?.error || 'Sending feilet')

      // Oppdater tilbudet med ny gyldighetsdato og purreteller
      await supabase.from('quotes').update({
        valid_until: newValidUntil,
        reminder_count: reminderCount,
        last_reminder_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      }).eq('id', quote.id)

      // Intern varsling
      if (user?.id) {
        await supabase.from('notifications').insert({
          user_id: user.id,
          title: `Purring sendt: ${quote.title}`,
          message: `Purring ${reminderCount} sendt til ${email}. Ny frist: ${newValidUntil}`,
          type: 'info', link_page: 'tilbud',
        })
      }

      setSent(true)
      setTimeout(() => onSent(), 2000)
    } catch(e) { alert('Feil ved sending av purring: ' + e.message) }
    finally { setSending(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px', fontFamily:'system-ui,sans-serif' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'500px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>📧 Send purring</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'16px' }}>
          {sent ? (
            <div style={{ textAlign:'center', padding:'20px 0' }}>
              <div style={{ fontSize:'48px', marginBottom:'12px' }}>✅</div>
              <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Purring sendt!</h3>
              <p style={{ margin:0, color:'#64748b', fontSize:'14px' }}>Kunden mottar en purring med ny gyldighetsdato</p>
            </div>
          ) : (
            <>
              {/* Tilbudsinfo */}
              <div style={{ background:'#fef2f2', borderRadius:'12px', padding:'14px', border:'1px solid #fecaca' }}>
                <div style={{ fontSize:'13px', color:'#dc2626', fontWeight:'600' }}>{quote.title}</div>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginTop:'6px' }}>
                  <div style={{ fontSize:'18px', fontWeight:'800', color:'#0f172a' }}>{fmt(grandTotal)}</div>
                  <span style={{ fontSize:'12px', color:'#dc2626', fontWeight:'600' }}>⏰ Utløpt {daysOverdue > 0 ? `${daysOverdue} dager siden` : 'i dag'}</span>
                </div>
                {quote.reminder_count > 0 && (
                  <div style={{ fontSize:'12px', color:'#d97706', marginTop:'6px' }}>📧 {quote.reminder_count} purring{quote.reminder_count > 1 ? 'er' : ''} allerede sendt · Siste: {quote.last_reminder_at ? new Date(quote.last_reminder_at).toLocaleDateString('nb-NO') : '—'}</div>
                )}
              </div>

              {/* Mottaker */}
              <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px 14px' }}>
                <div style={{ fontSize:'12px', color:'#94a3b8', fontWeight:'600', marginBottom:'2px' }}>SENDES TIL</div>
                <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>{quote.customer_email || 'Ingen e-post registrert'}</div>
              </div>

              {/* Ny gyldighetsdato */}
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Ny gyldighetsdato</label>
                <input type="date" value={newValidUntil} onChange={e => setNewValidUntil(e.target.value)} style={qInp} />
                <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'4px' }}>Tilbudet forlenges med denne datoen i e-posten</div>
              </div>

              {/* Info */}
              <div style={{ background:'#fffbeb', borderRadius:'10px', padding:'12px 14px', border:'1px solid #fde68a', fontSize:'13px', color:'#92400e', lineHeight:1.5 }}>
                Kunden mottar en purrings-e-post med oppdatert gyldighetsdato og en godkjenningsknapp. Tilbudet oppdateres med ny frist og purreteller.
              </div>

              <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
                <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={handleSendPurring} disabled={sending || !quote.customer_email}
                  style={{ padding:'10px 24px', background: sending ? '#fca5a5' : '#dc2626', color:'white', border:'none', borderRadius:'10px', cursor: sending ? 'not-allowed' : 'pointer', fontSize:'14px', fontWeight:'600' }}>
                  {sending ? 'Sender...' : `📧 Send purring ${reminderCount}`}
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}

// ─── END TILBUD MODULE ────────────────────────────────────────────────────────

// ─── GODKJENNING MODULE ───────────────────────────────────────────────────────

const MODULE_CONFIG = {
  quote:        { label: 'Tilbud',          emoji: '📋', table: 'quotes',           statusField: 'status', approvedStatus: 'Akseptert', rejectedStatus: 'Avslått',  notifTitle: (r) => `Tilbud godkjent: ${r.title}`, notifTitleReject: (r) => `Tilbud avslått: ${r.title}` },
  calculation:  { label: 'Kalkulasjon',     emoji: '🧮', table: 'calculations',     statusField: 'status', approvedStatus: 'Ferdig',    rejectedStatus: 'Utkast',   notifTitle: (r) => `Tilbud godkjent: ${r.title}`, notifTitleReject: (r) => `Tilbud avslått: ${r.title}` },
  order:        { label: 'Ordre',           emoji: '📦', table: 'orders',           statusField: 'status', approvedStatus: 'Bekreftet', rejectedStatus: 'Avslått',  notifTitle: (r) => `Ordre bekreftet: ${r.title}`, notifTitleReject: (r) => `Ordre avslått: ${r.title}` },
  invoice:      { label: 'Faktura',         emoji: '🧾', table: 'invoices',         statusField: 'status', approvedStatus: 'Godkjent',  rejectedStatus: 'Avvist',   notifTitle: (r) => `Faktura godkjent: ${r.title}`, notifTitleReject: (r) => `Faktura avvist: ${r.title}` },
  change_order: { label: 'Endringsmelding', emoji: '🔄', table: 'change_orders',    statusField: 'status', approvedStatus: 'Godkjent',  rejectedStatus: 'Avslått',  notifTitle: (r) => `Endringsmelding godkjent: ${r.title}`, notifTitleReject: (r) => `Endringsmelding avslått: ${r.title}` },
  tender:       { label: 'Anbud',           emoji: '📑', table: 'tenders',          statusField: 'status', approvedStatus: 'Akseptert', rejectedStatus: 'Avslått',  notifTitle: (r) => `Anbud akseptert: ${r.title}`, notifTitleReject: (r) => `Anbud avslått: ${r.title}` },
}

function GodkjenningsPage() {
  const [token, setToken] = useState(null)
  const [tokenData, setTokenData] = useState(null)
  const [record, setRecord] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [signedName, setSignedName] = useState('')
  const [rejectComment, setRejectComment] = useState('')
  const [showReject, setShowReject] = useState(false)
  const [submitting, setSubmitting] = useState(false)
  const [done, setDone] = useState(null) // 'approved' | 'rejected'

  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const t = params.get('token')
    if (!t) { setError('Ugyldig lenke — token mangler.'); setLoading(false); return }
    setToken(t)
    loadToken(t)
  }, [])

  const loadToken = async (t) => {
    try {
      const { data: td, error: te } = await supabase.from('approval_tokens').select('*').eq('token', t).single()
      if (te || !td) throw new Error('Lenken er ugyldig eller utløpt.')
      if (td.status !== 'pending') { setDone(td.status === 'approved' ? 'approved' : 'rejected'); setTokenData(td); setLoading(false); return }

      const cfg = MODULE_CONFIG[td.module]
      if (!cfg) throw new Error('Ukjent dokumenttype.')

      const { data: rec, error: re } = await supabase.from(cfg.table).select('*').eq('id', td.record_id).single()
      if (re || !rec) throw new Error('Dokumentet ble ikke funnet.')

      setTokenData(td)
      setRecord(rec)
    } catch(e) { setError(e.message) }
    finally { setLoading(false) }
  }

  const handleApprove = async () => {
    if (!signedName.trim()) return alert('Vennligst skriv inn ditt navn for å signere.')
    setSubmitting(true)
    try {
      const cfg = MODULE_CONFIG[tokenData.module]
      const now = new Date().toISOString()

      await supabase.from('approval_tokens').update({ status: 'approved', signed_name: signedName.trim(), approved_at: now }).eq('id', tokenData.id)
      await supabase.from(cfg.table).update({ [cfg.statusField]: cfg.approvedStatus, accepted_at: now, updated_at: now }).eq('id', tokenData.record_id)

      if (tokenData.created_by) {
        await supabase.from('notifications').insert({
          user_id: tokenData.created_by,
          title: cfg.notifTitle(record),
          message: `Signert av ${signedName.trim()}${tokenData.recipient_email ? ` (${tokenData.recipient_email})` : ''}`,
          type: 'success',
          link_page: tokenData.module === 'quote' ? 'tilbud' : tokenData.module,
          link_id: tokenData.record_id,
        })
      }
      setDone('approved')
    } catch(e) { alert('Feil: ' + e.message) }
    finally { setSubmitting(false) }
  }

  const handleReject = async () => {
    setSubmitting(true)
    try {
      const cfg = MODULE_CONFIG[tokenData.module]
      const now = new Date().toISOString()

      await supabase.from('approval_tokens').update({ status: 'rejected', signed_name: signedName.trim()||null, reject_comment: rejectComment.trim()||null, rejected_at: now }).eq('id', tokenData.id)
      await supabase.from(cfg.table).update({ [cfg.statusField]: cfg.rejectedStatus, updated_at: now }).eq('id', tokenData.record_id)

      if (tokenData.created_by) {
        await supabase.from('notifications').insert({
          user_id: tokenData.created_by,
          title: cfg.notifTitleReject(record),
          message: rejectComment.trim() || `Avslått av mottaker${tokenData.recipient_email ? ` (${tokenData.recipient_email})` : ''}`,
          type: 'warning',
          link_page: tokenData.module === 'quote' ? 'tilbud' : tokenData.module,
          link_id: tokenData.record_id,
        })
      }
      setDone('rejected')
    } catch(e) { alert('Feil: ' + e.message) }
    finally { setSubmitting(false) }
  }

  const cfg = tokenData ? MODULE_CONFIG[tokenData.module] : null

  const pageStyle = { minHeight: '100vh', background: 'linear-gradient(135deg, #f0fdf4 0%, #f8fafc 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px', fontFamily: 'system-ui, sans-serif' }
  const cardStyle = { background: 'white', borderRadius: '24px', padding: '40px', maxWidth: '560px', width: '100%', boxShadow: '0 8px 40px rgba(0,0,0,0.10)', border: '1px solid #f1f5f9' }

  if (loading) return (
    <div style={pageStyle}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ width: '40px', height: '40px', border: '3px solid #e2e8f0', borderTop: '3px solid #059669', borderRadius: '50%', margin: '0 auto 16px', animation: 'spin 1s linear infinite' }} />
        <style>{`@keyframes spin { to { transform: rotate(360deg) } }`}</style>
        <p style={{ color: '#64748b' }}>Laster dokument...</p>
      </div>
    </div>
  )

  if (error) return (
    <div style={pageStyle}>
      <div style={{ ...cardStyle, textAlign: 'center' }}>
        <div style={{ fontSize: '48px', marginBottom: '16px' }}>❌</div>
        <h2 style={{ margin: '0 0 8px', color: '#0f172a' }}>Ugyldig lenke</h2>
        <p style={{ margin: 0, color: '#64748b' }}>{error}</p>
      </div>
    </div>
  )

  if (done === 'approved') return (
    <div style={pageStyle}>
      <div style={{ ...cardStyle, textAlign: 'center' }}>
        <div style={{ fontSize: '64px', marginBottom: '16px' }}>✅</div>
        <h2 style={{ margin: '0 0 8px', color: '#0f172a', fontSize: '24px' }}>Godkjent!</h2>
        <p style={{ margin: '0 0 16px', color: '#64748b', fontSize: '16px' }}>
          {cfg?.label} er godkjent{tokenData?.signed_name ? ` og signert av ${tokenData.signed_name}` : ''}.
        </p>
        <p style={{ margin: 0, color: '#94a3b8', fontSize: '14px' }}>Avsender har mottatt bekreftelse. Du kan lukke denne siden.</p>
      </div>
    </div>
  )

  if (done === 'rejected') return (
    <div style={pageStyle}>
      <div style={{ ...cardStyle, textAlign: 'center' }}>
        <div style={{ fontSize: '64px', marginBottom: '16px' }}>🙏</div>
        <h2 style={{ margin: '0 0 8px', color: '#0f172a', fontSize: '24px' }}>Tilbakemelding mottatt</h2>
        <p style={{ margin: '0 0 16px', color: '#64748b', fontSize: '16px' }}>Avsender er varslet om din beslutning.</p>
        <p style={{ margin: 0, color: '#94a3b8', fontSize: '14px' }}>Du kan lukke denne siden.</p>
      </div>
    </div>
  )

  if (!record || !cfg) return null

  const isQuote = tokenData.module === 'quote'
  const chapters = record.chapters || []
  const grandTotal = isQuote ? chapters.reduce((acc, ch) => {
    const chSum = (ch.posts||[]).reduce((a,p) => a + (parseFloat(p.qty)||0)*((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0)), 0)
    return acc + chSum * (1 + (parseFloat(ch.markup)||0)/100)
  }, 0) * (1 + (parseFloat(record.global_markup)||0)/100) : null

  return (
    <div style={pageStyle}>
      <div style={cardStyle}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '32px' }}>
          <div style={{ width: '64px', height: '64px', borderRadius: '20px', background: '#f0fdf4', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '32px', margin: '0 auto 16px' }}>{cfg.emoji}</div>
          <h1 style={{ margin: '0 0 6px', fontSize: '22px', fontWeight: '800', color: '#0f172a' }}>{record.title}</h1>
          <p style={{ margin: 0, color: '#64748b', fontSize: '14px' }}>{cfg.label} • {record.quote_number || record.order_number || record.invoice_number || ''}</p>
        </div>

        {/* Document details */}
        <div style={{ background: '#f8fafc', borderRadius: '14px', padding: '20px', marginBottom: '20px', border: '1px solid #f1f5f9' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: isQuote ? '16px' : '0' }}>
            {[
              ['Til', record.customer_name],
              ['Gyldig til', record.valid_until],
              ['Betalingsbetingelser', record.payment_terms],
              ['Leveringstid', record.delivery_time],
            ].filter(r => r[1]).map(([k, v]) => (
              <div key={k}>
                <div style={{ fontSize: '11px', color: '#94a3b8', textTransform: 'uppercase', fontWeight: '600', marginBottom: '2px' }}>{k}</div>
                <div style={{ fontSize: '13px', fontWeight: '600', color: '#0f172a' }}>{v}</div>
              </div>
            ))}
          </div>
          {isQuote && grandTotal !== null && (
            <div style={{ background: '#f0fdf4', borderRadius: '10px', padding: '14px', border: '1px solid #bbf7d0', textAlign: 'center' }}>
              <div style={{ fontSize: '11px', color: '#16a34a', fontWeight: '700', textTransform: 'uppercase', marginBottom: '4px' }}>Totalsum eks. mva</div>
              <div style={{ fontSize: '28px', fontWeight: '800', color: '#0f172a' }}>{(Math.round(grandTotal)).toLocaleString('nb-NO')} kr</div>
              <div style={{ fontSize: '13px', color: '#64748b', marginTop: '4px' }}>Inkl. mva: {(Math.round(grandTotal * 1.25)).toLocaleString('nb-NO')} kr</div>
            </div>
          )}
        </div>

        {/* Intro text */}
        {record.intro_text && <p style={{ margin: '0 0 20px', fontSize: '14px', color: '#475569', lineHeight: 1.7 }}>{record.intro_text}</p>}

        {/* Chapters summary for quote */}
        {isQuote && chapters.length > 0 && (
          <div style={{ marginBottom: '20px' }}>
            {chapters.map((ch, i) => {
              const chSum = (ch.posts||[]).reduce((a,p) => a + (parseFloat(p.qty)||0)*((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0)), 0)
              const chTotal = chSum * (1 + (parseFloat(ch.markup)||0)/100)
              return (
                <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 14px', background: i%2===0?'#f8fafc':'white', borderRadius: '8px', fontSize: '14px' }}>
                  <span style={{ color: '#374151', fontWeight: '500' }}>{String(i+1).padStart(2,'0')}. {ch.title}</span>
                  <span style={{ fontWeight: '700', color: '#0f172a' }}>{Math.round(chTotal).toLocaleString('nb-NO')} kr</span>
                </div>
              )
            })}
          </div>
        )}

        {/* Signature */}
        {!showReject && (
          <div style={{ marginBottom: '16px' }}>
            <label style={{ display: 'block', fontSize: '13px', fontWeight: '700', color: '#374151', marginBottom: '8px' }}>✍️ Ditt fulle navn (signatur)</label>
            <input value={signedName} onChange={e => setSignedName(e.target.value)} placeholder="Skriv inn ditt fulle navn..." style={{ width: '100%', padding: '12px 14px', border: '2px solid #e2e8f0', borderRadius: '12px', fontSize: '15px', outline: 'none', boxSizing: 'border-box', fontFamily: 'system-ui, sans-serif', transition: 'border 0.15s' }}
              onFocus={e => e.target.style.borderColor='#059669'} onBlur={e => e.target.style.borderColor='#e2e8f0'} />
          </div>
        )}

        {/* Reject form */}
        {showReject && (
          <div style={{ marginBottom: '16px', background: '#fef2f2', borderRadius: '12px', padding: '16px', border: '1px solid #fecaca' }}>
            <label style={{ display: 'block', fontSize: '13px', fontWeight: '700', color: '#dc2626', marginBottom: '8px' }}>❌ Årsak til avslag (valgfritt)</label>
            <textarea value={rejectComment} onChange={e => setRejectComment(e.target.value)} rows={3} placeholder="Beskriv hvorfor du avslår..." style={{ width: '100%', padding: '10px 12px', border: '1px solid #fecaca', borderRadius: '10px', fontSize: '14px', outline: 'none', resize: 'none', boxSizing: 'border-box', fontFamily: 'system-ui, sans-serif' }} />
          </div>
        )}

        {/* Action buttons */}
        {!showReject ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            <button onClick={handleApprove} disabled={submitting}
              style={{ width: '100%', padding: '16px', background: submitting ? '#6ee7b7' : '#059669', color: 'white', border: 'none', borderRadius: '14px', fontSize: '16px', fontWeight: '700', cursor: submitting ? 'not-allowed' : 'pointer', transition: 'background 0.15s' }}>
              {submitting ? 'Behandler...' : `✅ Godkjenn ${cfg.label}`}
            </button>
            <button onClick={() => setShowReject(true)}
              style={{ width: '100%', padding: '13px', background: 'white', color: '#dc2626', border: '1px solid #fecaca', borderRadius: '14px', fontSize: '14px', fontWeight: '600', cursor: 'pointer' }}>
              ❌ Avslå
            </button>
          </div>
        ) : (
          <div style={{ display: 'flex', gap: '10px' }}>
            <button onClick={() => setShowReject(false)}
              style={{ flex: 1, padding: '13px', background: 'white', color: '#64748b', border: '1px solid #e2e8f0', borderRadius: '12px', fontSize: '14px', fontWeight: '600', cursor: 'pointer' }}>
              ← Tilbake
            </button>
            <button onClick={handleReject} disabled={submitting}
              style={{ flex: 2, padding: '13px', background: submitting ? '#fca5a5' : '#dc2626', color: 'white', border: 'none', borderRadius: '12px', fontSize: '14px', fontWeight: '700', cursor: submitting ? 'not-allowed' : 'pointer' }}>
              {submitting ? 'Sender...' : 'Bekreft avslag'}
            </button>
          </div>
        )}

        {record.outro_text && <p style={{ margin: '20px 0 0', fontSize: '13px', color: '#94a3b8', lineHeight: 1.6, textAlign: 'center' }}>{record.outro_text}</p>}
        <p style={{ margin: '16px 0 0', fontSize: '12px', color: '#cbd5e1', textAlign: 'center' }}>Sendt via En Plattform KS-system • enplattform.no</p>
      </div>
    </div>
  )
}

// Helper: create approval token and return URL
async function createApprovalToken({ module, recordId, recipientEmail, createdBy }) {
  const { data, error } = await supabase.from('approval_tokens').insert({
    module, record_id: recordId, recipient_email: recipientEmail, created_by: createdBy
  }).select().single()
  if (error) throw error
  return `${window.location.origin}/godkjenn?token=${data.token}`
}

// ─── END GODKJENNING MODULE ───────────────────────────────────────────────────

// ─── UE SVAR PAGE (Offentlig — ingen innlogging) ─────────────────────────────

function UESvarPage() {
  const [foresp, setForesp] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [posterPriser, setPosterPriser] = useState({}) // {postId: pris}
  const [tidsplan, setTidsplan] = useState('')
  const [forbehold, setForbehold] = useState('')
  const [sending, setSending] = useState(false)
  const [sent, setSent] = useState(false)
  const [svarVedlegg, setSvarVedlegg] = useState([])

  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const token = params.get('token')
    if (!token) { setError('Ugyldig lenke'); setLoading(false); return }
    supabase.from('ue_foresporsler').select('*').eq('svar_token', token).single()
      .then(({ data, error: e }) => {
        if (e || !data) { setError('Forespørselen ble ikke funnet eller er utløpt'); setLoading(false); return }
        setForesp(data)
        if (data.svar_poster && data.svar_poster.length > 0) {
          const priser = {}
          data.svar_poster.forEach(p => { priser[p.id] = p.pris })
          setPosterPriser(priser)
        }
        if (data.svar_tidsplan) setTidsplan(data.svar_tidsplan)
        if (data.svar_forbehold) setForbehold(data.svar_forbehold)
        setLoading(false)
      })
  }, [])

  const totalPris = Object.values(posterPriser).reduce((s, p) => s + (parseFloat(p) || 0), 0)

  const handleSubmit = async () => {
    const poster = (foresp.poster || [])
    const prisedPoster = poster.filter(p => parseFloat(posterPriser[p.id]) > 0)
    if (prisedPoster.length === 0) return alert('Vennligst pris minst én post')
    setSending(true)
    try {
      const svarPoster = poster.map(p => ({ id: p.id, name: p.name, pris: parseFloat(posterPriser[p.id]) || 0 }))
      const { error: e } = await supabase.from('ue_foresporsler').update({
        svar_pris: totalPris, svar_poster: svarPoster, svar_tidsplan: tidsplan,
        svar_forbehold: forbehold, svar_vedlegg: svarVedlegg, svar_dato: new Date().toISOString(),
        status: 'mottatt', updated_at: new Date().toISOString(),
      }).eq('id', foresp.id)
      if (e) throw e

      // Varsel + e-post til TE
      await supabase.from('notifications').insert({
        user_id: foresp.user_id,
        title: `🤝 Nytt UE-tilbud mottatt fra ${foresp.ue_navn}`,
        message: `${foresp.ue_navn} har levert tilbud på ${Math.round(totalPris).toLocaleString('nb-NO')} kr for "${foresp.oppgave_navn}" i prosjekt ${foresp.prosjekt_navn}. Ref: ${foresp.foresporsel_nr}`,
        type: 'info', link_page: 'kalkulator'
      })
      try {
        const { data: teUser } = await supabase.from('profiles').select('email').eq('id', foresp.user_id).single()
        if (teUser?.email) {
          const posterTable = svarPoster.filter(p => p.pris > 0).map(p => `<tr><td style="padding:6px 12px;font-size:13px">${p.name}</td><td style="padding:6px 12px;text-align:right;font-weight:600">${Math.round(p.pris).toLocaleString('nb-NO')} kr</td></tr>`).join('')
          const emailHtml = `<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">
            <h1 style="color:#0f172a;font-size:20px;margin:0 0 8px">🤝 Nytt tilbud mottatt</h1>
            <p style="color:#94a3b8;font-size:13px;margin:0 0 20px">Ref: ${foresp.foresporsel_nr}</p>
            <div style="background:#eff6ff;border-radius:12px;padding:16px;margin-bottom:16px;border:1px solid #bfdbfe">
              <div style="font-size:12px;color:#2563eb;font-weight:600;margin-bottom:6px">TILBUD FRA ${foresp.ue_navn.toUpperCase()}</div>
              <table style="width:100%;border-collapse:collapse">${posterTable}
                <tr style="border-top:2px solid #0f172a"><td style="padding:10px 12px;font-weight:800;font-size:15px">TOTALT</td><td style="padding:10px 12px;text-align:right;font-weight:800;font-size:15px">${Math.round(totalPris).toLocaleString('nb-NO')} kr</td></tr>
              </table>
              ${tidsplan ? `<div style="font-size:13px;color:#64748b;margin-top:8px">📅 ${tidsplan}</div>` : ''}
              ${forbehold ? `<div style="font-size:13px;color:#92400e;margin-top:4px">⚠️ Forbehold: ${forbehold}</div>` : ''}
            </div>
            <p style="color:#475569;font-size:14px">Logg inn i En Plattform for å godkjenne eller avslå tilbudet.</p>
          </div>`
          await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY, 'Authorization': `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}` },
            body: JSON.stringify({ to: teUser.email, subject: `Nytt UE-tilbud fra ${foresp.ue_navn} – ${foresp.prosjekt_navn}`, html: emailHtml })
          })
        }
      } catch(ee) {}
      setSent(true)
    } catch(e) { alert('Feil: ' + e.message) }
    finally { setSending(false) }
  }

  if (loading) return <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'100vh', fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px', height:'36px', border:'3px solid #e2e8f0', borderTop:'3px solid #2563eb', borderRadius:'50%', margin:'0 auto 12px', animation:'spin 1s linear infinite' }} /><p style={{ color:'#94a3b8' }}>Laster forespørsel...</p></div></div>
  if (error) return <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'100vh', fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center', maxWidth:'400px', padding:'40px' }}><div style={{ fontSize:'48px', marginBottom:'12px' }}>⚠️</div><h2 style={{ color:'#0f172a', margin:'0 0 8px' }}>{error}</h2><p style={{ color:'#64748b', fontSize:'14px' }}>Kontakt oppdragsgiveren for en ny lenke.</p></div></div>
  if (sent) return <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'100vh', fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center', maxWidth:'440px', padding:'40px', background:'white', borderRadius:'20px', boxShadow:'0 4px 24px rgba(0,0,0,0.08)' }}><div style={{ width:'64px', height:'64px', borderRadius:'50%', background:'#f0fdf4', display:'flex', alignItems:'center', justifyContent:'center', margin:'0 auto 16px', fontSize:'32px' }}>✅</div><h2 style={{ color:'#0f172a', margin:'0 0 8px' }}>Tilbud sendt!</h2><p style={{ color:'#64748b', fontSize:'14px', lineHeight:1.6 }}>Takk for ditt tilbud på <strong>{Math.round(totalPris).toLocaleString('nb-NO')} kr</strong>. Oppdragsgiveren mottar svaret ditt og tar kontakt.</p></div></div>

  const poster = foresp.poster || []
  const alreadyAnswered = foresp.status === 'mottatt' || foresp.status === 'godkjent'

  return (
    <div style={{ minHeight:'100vh', background:'#f8fafc', fontFamily:'system-ui,sans-serif', padding:'20px' }}>
      <div style={{ maxWidth:'640px', margin:'0 auto' }}>
        {/* Header */}
        <div style={{ background:'white', borderRadius:'16px', padding:'24px', marginBottom:'16px', boxShadow:'0 2px 12px rgba(0,0,0,0.04)' }}>
          <div style={{ display:'flex', alignItems:'center', gap:'10px', marginBottom:'16px' }}>
            <div style={{ width:'40px', height:'40px', borderRadius:'10px', background:'#eff6ff', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px' }}>📋</div>
            <div>
              <h1 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>Tilbudsforespørsel</h1>
              <span style={{ fontSize:'12px', color:'#94a3b8' }}>{foresp.foresporsel_nr}</span>
            </div>
          </div>
          <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
            <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px' }}>
              <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', marginBottom:'4px' }}>PROSJEKT</div>
              <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>{foresp.prosjekt_navn}</div>
              {foresp.prosjekt_adresse && <div style={{ fontSize:'12px', color:'#64748b' }}>{foresp.prosjekt_adresse}</div>}
            </div>
            <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px' }}>
              <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', marginBottom:'4px' }}>OPPGAVE</div>
              <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>{foresp.oppgave_navn}</div>
              {foresp.oppgave_beskrivelse && <div style={{ fontSize:'12px', color:'#64748b' }}>{foresp.oppgave_beskrivelse}</div>}
            </div>
          </div>
          {/* Vedlegg */}
          {(foresp.vedlegg||[]).length > 0 && (
            <div style={{ marginTop:'12px', background:'#fefce8', borderRadius:'8px', padding:'10px 12px', border:'1px solid #fde68a' }}>
              <div style={{ fontSize:'11px', fontWeight:'700', color:'#92400e', marginBottom:'4px' }}>📎 VEDLAGTE TEGNINGER / DOKUMENTER</div>
              {foresp.vedlegg.map((v, i) => (
                <a key={i} href={v.url} target="_blank" rel="noopener" style={{ display:'block', fontSize:'13px', color:'#2563eb', textDecoration:'underline', marginBottom:'2px' }}>{v.name}</a>
              ))}
            </div>
          )}
        </div>

        {/* Postvis prising */}
        <div style={{ background:'white', borderRadius:'16px', padding:'24px', boxShadow:'0 2px 12px rgba(0,0,0,0.04)' }}>
          <h2 style={{ margin:'0 0 4px', fontSize:'16px', fontWeight:'700', color:'#0f172a' }}>{alreadyAnswered ? '✅ Ditt tilbud er innsendt' : 'Pris per post'}</h2>
          <p style={{ margin:'0 0 16px', fontSize:'13px', color:'#64748b' }}>Legg inn din pris for hver post nedenfor.</p>

          {/* Poster-tabell */}
          <div style={{ border:'1px solid #e2e8f0', borderRadius:'10px', overflow:'hidden', marginBottom:'16px' }}>
            <table style={{ width:'100%', borderCollapse:'collapse' }}>
              <thead><tr style={{ background:'#f8fafc' }}>
                <th style={{ padding:'8px 14px', textAlign:'left', fontSize:'12px', fontWeight:'600', color:'#94a3b8' }}>Post</th>
                <th style={{ padding:'8px 10px', textAlign:'right', fontSize:'12px', fontWeight:'600', color:'#94a3b8', width:'70px' }}>Mengde</th>
                <th style={{ padding:'8px 10px', fontSize:'12px', fontWeight:'600', color:'#94a3b8', width:'50px' }}>Enh.</th>
                <th style={{ padding:'8px 14px', textAlign:'right', fontSize:'12px', fontWeight:'600', color:'#94a3b8', width:'130px' }}>Din pris (kr)</th>
              </tr></thead>
              <tbody>
                {poster.map(p => (
                  <tr key={p.id} style={{ borderTop:'1px solid #f1f5f9' }}>
                    <td style={{ padding:'10px 14px' }}>
                      <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>{p.name}</div>
                      {p.beskrivelse && <div style={{ fontSize:'11px', color:'#94a3b8' }}>{p.beskrivelse}</div>}
                    </td>
                    <td style={{ padding:'10px 10px', textAlign:'right', fontSize:'13px', color:'#64748b' }}>{p.mengde}</td>
                    <td style={{ padding:'10px 10px', fontSize:'13px', color:'#64748b' }}>{p.enhet}</td>
                    <td style={{ padding:'6px 10px' }}>
                      <input type="number" value={posterPriser[p.id]||''} onChange={e => setPosterPriser(pp => ({ ...pp, [p.id]: e.target.value }))}
                        placeholder="0" disabled={alreadyAnswered}
                        style={{ width:'100%', padding:'8px 10px', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize:'14px', fontWeight:'600', textAlign:'right', outline:'none', boxSizing:'border-box', background: alreadyAnswered ? '#f8fafc' : 'white' }} />
                    </td>
                  </tr>
                ))}
                {/* Total row */}
                <tr style={{ borderTop:'2px solid #0f172a', background:'#f0fdf4' }}>
                  <td colSpan="3" style={{ padding:'12px 14px', fontWeight:'800', fontSize:'14px', color:'#0f172a' }}>TOTALSUM</td>
                  <td style={{ padding:'12px 14px', textAlign:'right', fontWeight:'800', fontSize:'16px', color:'#059669' }}>{Math.round(totalPris).toLocaleString('nb-NO')} kr</td>
                </tr>
              </tbody>
            </table>
          </div>

          {/* Tidsplan */}
          <div style={{ marginBottom:'12px' }}>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Tidsplan</label>
            <input value={tidsplan} onChange={e => setTidsplan(e.target.value)} placeholder="F.eks. Kan starte uke 20, ferdig innen 5 dager" disabled={alreadyAnswered}
              style={{ width:'100%', padding:'10px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box' }} />
          </div>

          {/* Forbehold */}
          <div style={{ marginBottom:'16px' }}>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Eventuelle forbehold</label>
            <textarea value={forbehold} onChange={e => setForbehold(e.target.value)} rows={3} placeholder="F.eks. Forutsetter tilgang til byggstrøm, tørt arbeidsunderlag etc." disabled={alreadyAnswered}
              style={{ width:'100%', padding:'10px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', resize:'none', fontFamily:'system-ui,sans-serif' }} />
          </div>

          {/* Vedlegg fra UE */}
          {!alreadyAnswered && (
            <div style={{ marginBottom:'16px' }}>
              <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Vedlegg (valgfritt)</label>
              <p style={{ fontSize:'12px', color:'#94a3b8', margin:'0 0 8px' }}>Last opp dokumenter, tegninger eller kalkulasjoner som støtter tilbudet ditt</p>
              <div style={{ display:'flex', gap:'6px', flexWrap:'wrap', marginBottom:'6px' }}>
                {svarVedlegg.map((v, vi) => (
                  <span key={vi} style={{ background:'#eff6ff', border:'1px solid #bfdbfe', padding:'4px 10px', borderRadius:'6px', fontSize:'12px', color:'#2563eb', display:'flex', alignItems:'center', gap:'4px' }}>
                    📎 {v.name}
                    <button onClick={() => setSvarVedlegg(prev => prev.filter((_, i) => i !== vi))} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'12px', padding:0 }}>×</button>
                  </span>
                ))}
              </div>
              <label style={{ display:'inline-block', background:'#f8fafc', border:'1px dashed #e2e8f0', borderRadius:'8px', padding:'8px 16px', fontSize:'13px', cursor:'pointer', color:'#64748b' }}>
                📎 Legg til vedlegg
                <input type="file" style={{ display:'none' }} onChange={async (e) => {
                  const file = e.target.files?.[0]; if (!file) return
                  try {
                    const path = `ue-vedlegg/${Date.now()}_${file.name}`
                    const { error } = await supabase.storage.from('project-files').upload(path, file)
                    if (error) throw error
                    const { data: urlData } = supabase.storage.from('project-files').getPublicUrl(path)
                    setSvarVedlegg(prev => [...prev, { name: file.name, url: urlData.publicUrl }])
                  } catch(err) { console.error('Upload feil:', err) }
                  e.target.value = ''
                }} />
              </label>
            </div>
          )}

          {!alreadyAnswered && (
            <button onClick={handleSubmit} disabled={sending}
              style={{ width:'100%', padding:'14px', background:sending?'#93c5fd':'#2563eb', color:'white', border:'none', borderRadius:'12px', fontSize:'16px', fontWeight:'700', cursor:sending?'not-allowed':'pointer' }}>
              {sending ? 'Sender...' : `📋 Send tilbud — ${Math.round(totalPris).toLocaleString('nb-NO')} kr`}
            </button>
          )}
          {alreadyAnswered && (
            <div style={{ textAlign:'center', padding:'12px', background:'#f0fdf4', borderRadius:'10px', border:'1px solid #bbf7d0', fontSize:'14px', color:'#16a34a', fontWeight:'600' }}>
              {foresp.status === 'godkjent' ? '✅ Ditt tilbud er godkjent!' : '📨 Tilbudet er mottatt — venter på svar fra oppdragsgiver'}
            </div>
          )}
        </div>
        <p style={{ textAlign:'center', color:'#94a3b8', fontSize:'12px', marginTop:'20px' }}>Tilbudsforespørsel via En Plattform</p>
      </div>
    </div>
  )
}

// ─── ANBUDSMODUL ──────────────────────────────────────────────────────────────

const TENDER_STATUS = {
  'Utkast':          { bg: '#f8fafc', color: '#64748b', border: '#e2e8f0', emoji: '📝' },
  'Sendt':           { bg: '#eff6ff', color: '#2563eb', border: '#bfdbfe', emoji: '📤' },
  'Mottatt':         { bg: '#f5f3ff', color: '#7c3aed', border: '#ddd6fe', emoji: '📥' },
  'Under vurdering': { bg: '#fffbeb', color: '#d97706', border: '#fde68a', emoji: '🔍' },
  'Tildelt':         { bg: '#f0fdf4', color: '#16a34a', border: '#bbf7d0', emoji: '✅' },
  'Avslått':         { bg: '#fef2f2', color: '#dc2626', border: '#fecaca', emoji: '❌' },
}

const UE_STATUS = {
  'Invitert': { bg: '#eff6ff', color: '#2563eb', border: '#bfdbfe' },
  'Åpnet':    { bg: '#fffbeb', color: '#d97706', border: '#fde68a' },
  'Priset':   { bg: '#f0fdf4', color: '#16a34a', border: '#bbf7d0' },
  'Avslått':  { bg: '#fef2f2', color: '#dc2626', border: '#fecaca' },
}

const tInp = { width: '100%', padding: '9px 12px', border: '1px solid #e2e8f0', borderRadius: '10px', fontSize: '14px', outline: 'none', boxSizing: 'border-box', background: 'white', color: '#0f172a', fontFamily: 'system-ui, sans-serif' }
const tCard = { background: 'white', borderRadius: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '16px', border: '1px solid #f1f5f9', padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '20px 24px', boxShadow: '0 1px 4px rgba(0,0,0,0.04)' }

function TenderStatusBadge({ status }) {
  const cfg = TENDER_STATUS[status] || TENDER_STATUS['Utkast']
  return <span style={{ background: cfg.bg, color: cfg.color, border: `1px solid ${cfg.border}`, padding: '3px 10px', borderRadius: '999px', fontSize: '12px', fontWeight: '600' }}>{cfg.emoji} {status}</span>
}

function calcTenderChapter(ch) {
  const sum = (ch.posts||[]).reduce((acc,p) => acc + (parseFloat(p.qty)||0)*((parseFloat(p.unitCost)||0)), 0)
  const markup = parseFloat(ch.markup)||0
  return { cost: sum, price: sum*(1+markup/100) }
}

function calcTender(chapters, globalMarkup) {
  const totalCost = chapters.reduce((acc,ch) => acc + calcTenderChapter(ch).cost, 0)
  const totalPrice = chapters.reduce((acc,ch) => acc + calcTenderChapter(ch).price, 0)
  const gm = parseFloat(globalMarkup)||0
  return { totalCost, totalPrice, grandTotal: totalPrice*(1+gm/100) }
}

function fmtT(n) { return (Math.round(parseFloat(n)||0)).toLocaleString('nb-NO') + ' kr' }

function AnbudsPage() {
  const { user } = useAuth()
  const [tenders, setTenders] = useState([])
  const [projects, setProjects] = useState([])
  const [loading, setLoading] = useState(true)
  const [filterStatus, setFilterStatus] = useState('alle')
  const [filterType, setFilterType] = useState('alle')
  const [search, setSearch] = useState('')
  const [showNew, setShowNew] = useState(false)
  const [newType, setNewType] = useState(null)
  const [selected, setSelected] = useState(null)
  React.useEffect(() => {
    if (selected && window.__enterDetailView) {
      window.__enterDetailView(() => setSelected(null))
    }
  }, [selected])

  const load = async () => {
    try {
      const [t, p] = await Promise.all([
        supabase.from('tenders').select('*').order('created_at', { ascending: false }).then(r => r.data||[]),
        supabase.from('projects').select('id,name,parent_id,depth,project_number').order('name').then(r => r.data||[])
      ])
      setTenders(t); setProjects(p)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(() => { load() }, [])

  const filtered = tenders.filter(t => {
    if (filterStatus !== 'alle' && t.status !== filterStatus) return false
    if (filterType !== 'alle' && t.type !== filterType) return false
    if (search && ![t.title, t.tender_number, t.customer_name].some(v => v?.toLowerCase().includes(search.toLowerCase()))) return false
    return true
  })

  const incoming = tenders.filter(t => t.type === 'incoming')
  const outgoing = tenders.filter(t => t.type === 'outgoing')
  const tildelt = tenders.filter(t => t.status === 'Tildelt')
  const totalTildelt = tildelt.reduce((acc,t) => acc + (t.awarded_amount||calcTender(t.chapters||[], t.global_markup).grandTotal), 0)

  const isMobA = typeof window !== 'undefined' && window.innerWidth < 768

  if (loading) return <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'60vh', fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px', height:'36px', border:'3px solid #e2e8f0', borderTop:'3px solid #059669', borderRadius:'50%', margin:'0 auto 12px', animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8', fontSize:'14px' }}>Laster anbud...</p></div></div>

  if (selected) return <AnbudDetaljer tender={selected} projects={projects} user={user} onBack={() => { setSelected(null); load() }} />

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobA ? '16px' : '24px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px' }}>
          <div>
            <h1 style={{ fontSize: isMobA ? '18px' : '22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>📑 Anbud</h1>
            {!isMobA && <p style={{ color:'#64748b', marginTop:'4px', fontSize:'14px', marginBottom:0 }}>Innkommende forespørsler, utgående anbud til UE og kalkyle</p>}
          </div>
          <div style={{ display:'flex', gap:'6px', flexShrink:0 }}>
            <button onClick={() => { setNewType('incoming'); setShowNew(true) }} style={{ background:'#7c3aed', color:'white', border:'none', borderRadius:'10px', padding: isMobA ? '9px 10px' : '10px 16px', fontSize: isMobA ? '11px' : '13px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>{isMobA ? '📥 Forespørsel' : '📥 Ny forespørsel'}</button>
            <button onClick={() => { setNewType('outgoing'); setShowNew(true) }} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding: isMobA ? '9px 10px' : '10px 16px', fontSize: isMobA ? '11px' : '13px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>{isMobA ? '📤 Til UE' : '📤 Send til UE'}</button>
          </div>
        </div>
      </div>

      <div style={{ padding: isMobA ? '12px' : '24px 32px', display:'flex', flexDirection:'column', gap: isMobA ? '12px' : '20px', overflowX:'hidden' }}>
        {/* Stats */}
        <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? 'repeat(2,1fr)' : 'repeat(4,1fr)', gap:'12px' }}>
          {[
            { label:'Innkommende', value:incoming.length, emoji:'📥', bg:'#f5f3ff', color:'#7c3aed', border:'#ddd6fe', filter:'incoming' },
            { label:'Utgående til UE', value:outgoing.length, emoji:'📤', bg:'#eff6ff', color:'#2563eb', border:'#bfdbfe', filter:'outgoing' },
            { label:'Tildelt', value:tildelt.length, emoji:'✅', bg:'#f0fdf4', color:'#16a34a', border:'#bbf7d0', filter:'Tildelt' },
          ].map(s => (
            <button key={s.label} onClick={() => s.filter === 'incoming' || s.filter === 'outgoing' ? setFilterType(filterType===s.filter?'alle':s.filter) : setFilterStatus(filterStatus===s.filter?'alle':s.filter)}
              style={{ background: (filterType===s.filter||filterStatus===s.filter)?s.bg:'white', border:`1px solid ${(filterType===s.filter||filterStatus===s.filter)?s.border:'#f1f5f9'}`, borderRadius: isMobA ? '10px' : '14px', padding: isMobA ? '10px' : '16px', cursor:'pointer', textAlign: isMobA ? 'center' : 'left' }}>
              <div style={{ fontSize: isMobA ? '16px' : '22px', marginBottom: isMobA ? '4px' : '8px' }}>{s.emoji}</div>
              <div style={{ fontSize: isMobA ? '16px' : '22px', fontWeight:'800', color:(filterType===s.filter||filterStatus===s.filter)?s.color:'#0f172a' }}>{s.value}</div>
              <div style={{ fontSize: isMobA ? '10px' : '11px', color:(filterType===s.filter||filterStatus===s.filter)?s.color:'#94a3b8', fontWeight:'500', marginTop:'2px' }}>{s.label}</div>
            </button>
          ))}
          {!isMobA && <div style={{ background:'linear-gradient(135deg,#059669,#0891b2)', borderRadius:'14px', padding:'16px', color:'white' }}>
            <div style={{ fontSize:'20px', marginBottom:'8px' }}>💰</div>
            <div style={{ fontSize:'16px', fontWeight:'800' }}>{fmtT(totalTildelt)}</div>
            <div style={{ fontSize:'11px', opacity:0.85, fontWeight:'500', marginTop:'2px' }}>Total tildelt</div>
          </div>}
        </div>

        {/* Filters */}
        <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding: isMobA ? '10px' : '14px 18px', display:'flex', gap: isMobA ? '8px' : '10px', alignItems:'center', flexWrap:'wrap' }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍  Søk..." style={{ ...tInp, maxWidth: isMobA ? '100%' : '260px', flex: isMobA ? '1 1 100%' : '1' }} />
          <select value={filterStatus} onChange={e=>setFilterStatus(e.target.value)} style={{ ...tInp, maxWidth: isMobA ? '100%' : '180px', flex: isMobA ? '1 1 100%' : 'none', fontSize: isMobA ? '13px' : '14px' }}>
            <option value="alle">Alle statuser</option>
            {Object.keys(TENDER_STATUS).map(s=><option key={s} value={s}>{s}</option>)}
          </select>
          {(search||filterStatus!=='alle'||filterType!=='alle') && <button onClick={()=>{setSearch('');setFilterStatus('alle');setFilterType('alle')}} style={{ background:'#f1f5f9', border:'none', borderRadius:'8px', padding:'9px 14px', fontSize:'13px', cursor:'pointer', color:'#64748b' }}>Nullstill</button>}
          <span style={{ marginLeft:'auto', fontSize:'13px', color:'#94a3b8' }}>{filtered.length} anbud</span>
        </div>

        {/* List */}
        {filtered.length === 0 ? (
          <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'60px 20px', textAlign:'center' }}>
            <div style={{ fontSize:'40px', marginBottom:'12px' }}>📑</div>
            <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Ingen anbud funnet</h3>
            <p style={{ margin:0, color:'#94a3b8', fontSize:'14px' }}>{tenders.length===0?'Opprett ditt første anbud.':'Prøv å endre søk eller filter.'}</p>
          </div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            {filtered.map(t => {
              const cfg = TENDER_STATUS[t.status]
              const proj = projects.find(p=>p.id===t.project_id)
              const { grandTotal } = calcTender(t.chapters||[], t.global_markup)
              const isIncoming = t.type === 'incoming'
              const deadlineDays = t.deadline ? Math.ceil((new Date(t.deadline)-new Date())/(1000*60*60*24)) : null
              return (
                <div key={t.id} onClick={()=>setSelected(t)}
                  style={{ background:'white', borderRadius: isMobA ? '12px' : '14px', border:`1px solid ${deadlineDays!==null&&deadlineDays<=3&&t.status==='Sendt'?'#fecaca':'#f1f5f9'}`, padding: isMobA ? '12px' : '16px 20px', cursor:'pointer', display:'flex', alignItems: isMobA ? 'flex-start' : 'center', gap: isMobA ? '10px' : '16px', transition:'box-shadow 0.15s' }}
                  onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 16px rgba(0,0,0,0.08)'} onMouseLeave={e=>e.currentTarget.style.boxShadow='none'}>
                  {!isMobA && <div style={{ width:'44px', height:'44px', borderRadius:'12px', background:isIncoming?'#f5f3ff':'#eff6ff', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', flexShrink:0 }}>{isIncoming?'📥':'📤'}</div>}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', alignItems:'center', gap: isMobA ? '6px' : '8px', flexWrap:'wrap', marginBottom:'4px' }}>
                      <span style={{ fontWeight:'700', color:'#0f172a', fontSize: isMobA ? '13px' : '15px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', maxWidth: isMobA ? 'calc(100vw - 120px)' : 'none' }}>{t.title}</span>
                      {!isMobA && <span style={{ fontSize:'11px', color:'#94a3b8', fontFamily:'monospace' }}>{t.tender_number}</span>}
                      <TenderStatusBadge status={t.status} />
                      <span style={{ background:isIncoming?'#f5f3ff':'#eff6ff', color:isIncoming?'#7c3aed':'#2563eb', fontSize:'11px', fontWeight:'600', padding:'2px 8px', borderRadius:'999px', border:`1px solid ${isIncoming?'#ddd6fe':'#bfdbfe'}` }}>{isIncoming?'Innkommende':'Utgående UE'}</span>
                    </div>
                    <div style={{ display:'flex', gap: isMobA ? '6px' : '12px', flexWrap:'wrap' }}>
                      {t.customer_name && <span style={{ fontSize: isMobA ? '11px' : '12px', color:'#64748b' }}>👤 {t.customer_name}</span>}
                      {!isMobA && proj && <span style={{ fontSize:'12px', color:'#2563eb', fontWeight:'500' }}>🏗️ {proj.name}</span>}
                      {!isMobA && t.deadline && <span style={{ fontSize:'12px', color:deadlineDays!==null&&deadlineDays<=3?'#dc2626':'#64748b' }}>⏰ {t.deadline}</span>}
                    </div>
                  </div>
                  <div style={{ textAlign:'right', flexShrink:0 }}>
                    <div style={{ fontWeight:'800', fontSize: isMobA ? '13px' : '15px', color:'#0f172a' }}>{fmtT(t.awarded_amount||grandTotal)}</div>
                    {!isMobA && <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>eks. mva</div>}
                  </div>
                  {!isMobA && <span style={{ color:'#94a3b8', fontSize:'18px' }}>›</span>}
                </div>
              )
            })}
          </div>
        )}
      </div>
      {showNew && <AnbudEditorModal type={newType} projects={projects} user={user} onClose={()=>setShowNew(false)} onSaved={()=>{setShowNew(false);load()}} />}
    </div>
  )
}

function AnbudDetaljer({ tender: init, projects, user, onBack }) {
  const confirm = useConfirm()
  const isMobAD = typeof window !== 'undefined' && window.innerWidth < 768
  const [t, setT] = useState(init)
  const [ues, setUes] = useState([])
  const [editing, setEditing] = useState(false)
  const [showInviteUE, setShowInviteUE] = useState(false)
  const [showAward, setShowAward] = useState(false)
  const cfg = TENDER_STATUS[t.status]
  const proj = projects.find(p=>p.id===t.project_id)
  const { totalCost, grandTotal } = calcTender(t.chapters||[], t.global_markup)
  const isIncoming = t.type === 'incoming'

  const load = async () => {
    const { data } = await supabase.from('tender_ues').select('*').eq('tender_id', t.id).order('created_at')
    setUes(data||[])
  }
  const refresh = async () => {
    const { data } = await supabase.from('tenders').select('*').eq('id', t.id).single()
    if (data) setT(data)
  }
  useEffect(() => { load() }, [])

  const updateStatus = async (status) => {
    await supabase.from('tenders').update({ status, updated_at: new Date().toISOString() }).eq('id', t.id)
    setT(v=>({...v, status}))
  }

  const handleDelete = async () => {
    if (!(await confirm({ message: 'Slett dette anbudet?', subMessage: 'Anbudet og alle tilhørende data slettes permanent.', danger: true }))) return
    await supabase.from('tenders').delete().eq('id', t.id)
    onBack()
  }

  const generateQuote = async () => {
    if (!(await confirm({ message: 'Generer tilbud fra dette anbudet?', subMessage: 'Kapitlene og postene kopieres over til et nytt tilbud.', confirmLabel: 'Generer tilbud', danger: false }))) return
    try {
      const { data: existingQuotes } = await supabase.from('quotes').select('quote_number')
      const quoteNr = nextSequenceNumber(existingQuotes || [], 'TB', 'quote_number')
      const { data, error } = await supabase.from('quotes').insert({
        title: t.title, quote_number: quoteNr,
        project_id: t.project_id||null, customer_name: t.customer_name, customer_email: t.customer_email,
        customer_address: t.customer_address, customer_orgnr: t.customer_orgnr,
        valid_until: t.valid_until, payment_terms: '30 dager netto',
        chapters: (t.chapters||[]).map(ch => ({
          ...ch,
          posts: (ch.posts||[]).map(p => ({ ...p, unitPriceWork: p.unitCost||0, unitPriceMaterial: 0 }))
        })),
        global_markup: t.global_markup||0, status: 'Utkast', created_by: user?.id,
      }).select().single()
      if (error) throw error
      await supabase.from('tenders').update({ generated_quote_id: data.id }).eq('id', t.id)
      alert('✅ Tilbud opprettet! Gå til Tilbud-modulen for å se det.')
    } catch(e) { alert('Feil: '+e.message) }
  }

  const pricedUes = ues.filter(u=>u.status==='Priset').sort((a,b)=>(a.total_amount||0)-(b.total_amount||0))

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobAD ? '14px' : '20px 32px' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#64748b', fontSize:'13px', marginBottom:'10px', display:'flex', alignItems:'center', gap:'6px', padding:0 }}>← Tilbake til anbud</button>
        <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap: isMobAD ? '8px' : '16px', flexWrap: isMobAD ? 'wrap' : 'nowrap' }}>
          <div style={{ display:'flex', alignItems:'flex-start', gap: isMobAD ? '10px' : '14px', flex:1, minWidth:0 }}>
            {!isMobAD && <div style={{ width:'52px', height:'52px', borderRadius:'14px', background:isIncoming?'#f5f3ff':'#eff6ff', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px', flexShrink:0 }}>{isIncoming?'📥':'📤'}</div>}
            <div style={{ minWidth:0 }}>
              <div style={{ display:'flex', alignItems:'center', gap: isMobAD ? '6px' : '10px', flexWrap:'wrap', marginBottom:'4px' }}>
                <h1 style={{ margin:0, fontSize: isMobAD ? '16px' : '20px', fontWeight:'bold', color:'#0f172a' }}>{t.title}</h1>
                {!isMobAD && <span style={{ fontSize:'13px', color:'#94a3b8', fontFamily:'monospace' }}>{t.tender_number}</span>}
                <TenderStatusBadge status={t.status} />
              </div>
              <div style={{ display:'flex', gap:'12px', flexWrap:'wrap' }}>
                {t.customer_name && <span style={{ fontSize:'13px', color:'#64748b' }}>👤 {t.customer_name}</span>}
                {proj && <span style={{ fontSize:'13px', color:'#2563eb', fontWeight:'500' }}>🏗️ {proj.name}</span>}
                {t.deadline && <span style={{ fontSize:'13px', color:'#64748b' }}>⏰ Frist {t.deadline}</span>}
              </div>
            </div>
          </div>
          <div style={{ display:'flex', gap: isMobAD ? '6px' : '8px', flexShrink:0, flexWrap:'wrap' }}>
            {!isIncoming && t.status==='Utkast' && <button onClick={()=>setShowInviteUE(true)} style={{ padding: isMobAD ? '7px 10px' : '9px 14px', background:'#2563eb', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobAD ? '11px' : '13px', fontWeight:'600' }}>{isMobAD ? '📧 UE' : '📧 Inviter UE'}</button>}
            {t.status==='Under vurdering' && <button onClick={()=>setShowAward(true)} style={{ padding: isMobAD ? '7px 10px' : '9px 14px', background:'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobAD ? '11px' : '13px', fontWeight:'600' }}>{isMobAD ? '🏆 Tildel' : '🏆 Tildel anbud'}</button>}
            {isIncoming && <button onClick={generateQuote} style={{ padding: isMobAD ? '7px 10px' : '9px 14px', background:'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobAD ? '11px' : '13px', fontWeight:'600' }}>{isMobAD ? '📋 Tilbud' : '📋 Generer tilbud'}</button>}
            <button onClick={()=>setEditing(true)} style={{ padding: isMobAD ? '7px 10px' : '9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobAD ? '12px' : '13px' }}>✏️</button>
            <button onClick={handleDelete} style={{ padding: isMobAD ? '7px 10px' : '9px 12px', border:'1px solid #fecaca', borderRadius:'10px', background:'white', cursor:'pointer', color:'#dc2626', fontSize: isMobAD ? '12px' : '13px' }}>🗑️</button>
          </div>
        </div>
      </div>

      <div style={{ padding: isMobAD ? '12px' : '24px 32px', display:'grid', gridTemplateColumns: isMobAD ? '1fr' : '2fr 1fr', gap: isMobAD ? '12px' : '20px' }}>
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          {/* Description */}
          {t.description && <div style={tCard}><h3 style={{ margin:'0 0 10px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📄 Beskrivelse</h3><p style={{ margin:0, fontSize:'14px', color:'#475569', lineHeight:1.6 }}>{t.description}</p></div>}

          {/* Chapters / kalkyle */}
          {(t.chapters||[]).length > 0 && (
            <div style={tCard}>
              <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📊 Kalkyle / Kapitler</h3>
              {(t.chapters||[]).map((ch,ci) => {
                const { cost, price } = calcTenderChapter(ch)
                return (
                  <div key={ci} style={{ marginBottom:'16px', background:'#f8fafc', borderRadius:'12px', padding:'14px', border:'1px solid #f1f5f9' }}>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'10px' }}>
                      <h4 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>{String(ci+1).padStart(2,'0')}. {ch.title}</h4>
                      <div style={{ textAlign:'right' }}>
                        <div style={{ fontSize:'12px', color:'#94a3b8' }}>Kostnad: {fmtT(cost)}</div>
                        {ch.markup>0 && <div style={{ fontSize:'13px', fontWeight:'700', color:'#059669' }}>Pris: {fmtT(price)}</div>}
                      </div>
                    </div>
                    {isMobAD ? (
                      <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
                        {(ch.posts||[]).map((p,pi) => {
                          const ls = (parseFloat(p.qty)||0)*(parseFloat(p.unitCost)||0)
                          return (
                            <div key={pi} style={{ background:'white', borderRadius:'8px', padding:'8px 10px' }}>
                              <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'3px' }}>
                                <span style={{ fontWeight:'600', fontSize:'12px', color:'#0f172a' }}>{p.description||'—'}</span>
                                <span style={{ fontWeight:'700', fontSize:'12px', color:'#059669', whiteSpace:'nowrap', marginLeft:'8px' }}>{fmtT(ls)}</span>
                              </div>
                              <div style={{ fontSize:'11px', color:'#64748b' }}>{p.qty} {p.unit} × {fmtT(p.unitCost)}</div>
                            </div>
                          )
                        })}
                      </div>
                    ) : (<table style={{ width:'100%', borderCollapse:'collapse', fontSize:'13px' }}>
                      <thead><tr style={{ background:'white' }}>
                        {['Beskrivelse','Mengde','Enhet','Kost/enh','Sum'].map(h=><th key={h} style={{ padding:'6px 8px', textAlign:h==='Sum'||h==='Kost/enh'?'right':'left', color:'#94a3b8', fontWeight:'600', fontSize:'11px', textTransform:'uppercase', borderBottom:'1px solid #f1f5f9' }}>{h}</th>)}
                      </tr></thead>
                      <tbody>
                        {(ch.posts||[]).map((p,pi) => {
                          const ls = (parseFloat(p.qty)||0)*(parseFloat(p.unitCost)||0)
                          return <tr key={pi} style={{ borderBottom:'1px solid #f8fafc' }}>
                            <td style={{ padding:'7px 8px', color:'#0f172a', fontWeight:'500' }}>{p.description||'—'}</td>
                            <td style={{ padding:'7px 8px', textAlign:'right', color:'#475569' }}>{p.qty}</td>
                            <td style={{ padding:'7px 8px', color:'#475569' }}>{p.unit}</td>
                            <td style={{ padding:'7px 8px', textAlign:'right', color:'#475569' }}>{fmtT(p.unitCost)}</td>
                            <td style={{ padding:'7px 8px', textAlign:'right', fontWeight:'700', color:'#0f172a' }}>{fmtT(ls)}</td>
                          </tr>
                        })}
                      </tbody>
                    </table>
                    )}
                  </div>
                )
              })}
              <div style={{ background:'#f0fdf4', borderRadius:'10px', padding:'14px 18px', border:'1px solid #bbf7d0', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div>
                  <div style={{ fontSize:'13px', color:'#16a34a', fontWeight:'600' }}>Total kalkylepris eks. mva</div>
                  {parseFloat(t.global_markup)>0 && <div style={{ fontSize:'12px', color:'#94a3b8' }}>Inkl. generelt påslag {t.global_markup}%</div>}
                </div>
                <div style={{ fontSize:'22px', fontWeight:'800', color:'#0f172a' }}>{fmtT(grandTotal)}</div>
              </div>
            </div>
          )}

          {/* UE Comparison */}
          {!isIncoming && ues.length > 0 && (
            <div style={tCard}>
              <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>🏢 UE-er og innkomne priser</h3>
              {pricedUes.length > 0 && (
                <div style={{ background:'#f0fdf4', borderRadius:'10px', padding:'12px 16px', border:'1px solid #bbf7d0', marginBottom:'14px', fontSize:'13px', color:'#16a34a', fontWeight:'600' }}>
                  🏆 Laveste pris: {pricedUes[0].company_name} — {fmtT(pricedUes[0].total_amount)}
                </div>
              )}
              <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                {ues.map(ue => {
                  const ucfg = UE_STATUS[ue.status]
                  const isLowest = pricedUes[0]?.id === ue.id
                  return (
                    <div key={ue.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:isLowest?'#f0fdf4':'#f8fafc', borderRadius:'10px', padding:'12px 16px', border:`1px solid ${isLowest?'#bbf7d0':'#f1f5f9'}` }}>
                      <div style={{ flex:1 }}>
                        <div style={{ fontWeight:'700', fontSize:'14px', color:'#0f172a' }}>{ue.company_name} {isLowest&&'🏆'}</div>
                        {ue.contact_name && <div style={{ fontSize:'12px', color:'#64748b' }}>{ue.contact_name} · {ue.email}</div>}
                        {ue.submitted_at && <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>Innlevert {new Date(ue.submitted_at).toLocaleDateString('nb-NO')}</div>}
                      </div>
                      <span style={{ background:ucfg.bg, color:ucfg.color, border:`1px solid ${ucfg.border}`, padding:'3px 10px', borderRadius:'999px', fontSize:'12px', fontWeight:'600' }}>{ue.status}</span>
                      {ue.total_amount && <div style={{ fontWeight:'800', fontSize:'15px', color:isLowest?'#16a34a':'#0f172a', minWidth:'100px', textAlign:'right' }}>{fmtT(ue.total_amount)}</div>}
                    </div>
                  )
                })}
              </div>
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          <div style={tCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🔄 Status</h3>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {Object.keys(TENDER_STATUS).map(s => (
                <button key={s} onClick={()=>updateStatus(s)} disabled={t.status===s}
                  style={{ padding:'9px 14px', borderRadius:'10px', border:`1px solid ${t.status===s?TENDER_STATUS[s].border:'#e2e8f0'}`, background:t.status===s?TENDER_STATUS[s].bg:'white', color:t.status===s?TENDER_STATUS[s].color:'#475569', fontWeight:t.status===s?'700':'400', fontSize:'13px', cursor:t.status===s?'default':'pointer', textAlign:'left', width:'100%' }}>
                  {t.status===s?'✓ ':''}{TENDER_STATUS[s].emoji} {s}
                </button>
              ))}
            </div>
          </div>
          <div style={tCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>💰 Økonomi</h3>
            <div style={{ background:isIncoming?'#f5f3ff':'#f0fdf4', borderRadius:'10px', padding:'14px', textAlign:'center', border:`1px solid ${isIncoming?'#ddd6fe':'#bbf7d0'}` }}>
              <div style={{ fontSize:'11px', color:isIncoming?'#7c3aed':'#16a34a', fontWeight:'600', textTransform:'uppercase', marginBottom:'4px' }}>Kalkylepris eks. mva</div>
              <div style={{ fontSize:'20px', fontWeight:'800', color:'#0f172a' }}>{fmtT(t.awarded_amount||grandTotal)}</div>
            </div>
            {t.awarded_ue && <div style={{ marginTop:'10px', fontSize:'13px', color:'#064748' }}><strong>Tildelt:</strong> {t.awarded_ue}</div>}
          </div>
          <div style={tCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>ℹ️ Info</h3>
            {[['Kunde/byggherre',t.customer_name],['E-post',t.customer_email],['Prosjekt',proj?.name],['Frist',t.deadline],['Gyldig til',t.valid_until]].filter(r=>r[1]).map(([k,v],i)=>(
              <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize:'13px' }}>
                <span style={{ color:'#94a3b8' }}>{k}</span><span style={{ fontWeight:'500', color:'#0f172a', textAlign:'right', maxWidth:'55%' }}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {editing && <AnbudEditorModal type={t.type} projects={projects} user={user} initial={t} onClose={()=>setEditing(false)} onSaved={()=>{setEditing(false);refresh()}} />}
      {showInviteUE && <InviterUEModal tender={t} user={user} onClose={()=>setShowInviteUE(false)} onSaved={()=>{setShowInviteUE(false);load();updateStatus('Sendt')}} />}
      {showAward && <TildelModal tender={t} ues={ues} projects={projects} user={user} onClose={()=>setShowAward(false)} onSaved={()=>{setShowAward(false);refresh()}} />}
    </div>
  )
}

function AnbudEditorModal({ type, projects, user, initial, onClose, onSaved }) {
  const isEdit = !!initial
  const isIncoming = type === 'incoming'
  const [step, setStep] = useState(1)
  const [form, setForm] = useState({
    title: initial?.title||'', tender_number: initial?.tender_number||'',
    project_id: initial?.project_id||'', customer_name: initial?.customer_name||'', customer_email: initial?.customer_email||'',
    customer_address: initial?.customer_address||'', customer_orgnr: initial?.customer_orgnr||'',
    customer_id: initial?.customer_id || null,
    deadline: initial?.deadline||'', valid_until: initial?.valid_until||'',
    description: initial?.description||'', global_markup: initial?.global_markup||0,
  })
  // Generer sekvensielt nummer ved nyopprettelse
  useEffect(() => {
    if (!isEdit && !form.tender_number) {
      supabase.from('tenders').select('tender_number').then(({ data }) => {
        setForm(f => ({ ...f, tender_number: nextSequenceNumber(data || [], 'ANB', 'tender_number') }))
      })
    }
  }, [])
  const [chapters, setChapters] = useState(initial?.chapters||[
    { id: Date.now(), title: 'Generelt', markup: 0, posts: [{ id: Date.now()+1, description:'', qty:1, unit:'stk', unitCost:0 }] }
  ])
  const [saving, setSaving] = useState(false)
  const set = (k,v) => setForm(f=>({...f,[k]:v}))

  const addChapter = () => setChapters(c=>[...c,{ id:Date.now(), title:`Kapittel ${c.length+1}`, markup:0, posts:[{id:Date.now()+1,description:'',qty:1,unit:'stk',unitCost:0}] }])
  const removeChapter = (id) => setChapters(c=>c.filter(x=>x.id!==id))
  const updateChapter = (id,f,v) => setChapters(c=>c.map(x=>x.id===id?{...x,[f]:v}:x))
  const addPost = (chId) => setChapters(c=>c.map(x=>x.id===chId?{...x,posts:[...x.posts,{id:Date.now(),description:'',qty:1,unit:'stk',unitCost:0}]}:x))
  const removePost = (chId,pId) => setChapters(c=>c.map(x=>x.id===chId?{...x,posts:x.posts.filter(p=>p.id!==pId)}:x))
  const updatePost = (chId,pId,f,v) => setChapters(c=>c.map(x=>x.id===chId?{...x,posts:x.posts.map(p=>p.id===pId?{...p,[f]:v}:p)}:x))

  const handleSave = async () => {
    if (!form.title.trim()) return alert('Tittel er påkrevd')
    setSaving(true)
    try {
      // Kundeoppløsning: for innkommende anbud er "kunde" egentlig byggherre/oppdragsgiver
      // — lagre i customers-tabellen på samme måte som for tilbud/ordre/faktura.
      const { customerId } = await resolveCustomerFromForm({
        form,
        user,
        initialCustomerId: initial?.customer_id,
        statusOnCreate: isIncoming ? 'lead' : null,
      })
      const payload = sanitizeDbPayload({ ...form, type, chapters, project_id: form.project_id||null, customer_id: customerId, updated_at: new Date().toISOString() })
      if (isEdit) { const {error}=await supabase.from('tenders').update(payload).eq('id',initial.id); if(error) throw error }
      else { const {error}=await supabase.from('tenders').insert({...payload,status:'Utkast',created_by:user?.id}); if(error) throw error }
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  const lbl = t => <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>{t}</label>
  const { grandTotal } = calcTender(chapters, form.global_markup)
  const isMobAE = typeof window !== 'undefined' && window.innerWidth < 768

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems: isMobAE ? 'stretch' : 'center', justifyContent:'center', padding: isMobAE ? '0' : '16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius: isMobAE ? '0' : '20px', width:'100%', maxWidth: isMobAE ? '100%' : '900px', maxHeight: isMobAE ? '100vh' : '94vh', height: isMobAE ? '100vh' : 'auto', display:'flex', flexDirection:'column', boxShadow: isMobAE ? 'none' : '0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding: isMobAE ? '12px 14px' : '18px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', alignItems:'center', justifyContent:'space-between', flexShrink:0, gap:'8px' }}>
          <div style={{ display:'flex', alignItems:'center', gap: isMobAE ? '8px' : '16px', flex:1, minWidth:0 }}>
            <h2 style={{ margin:0, fontSize: isMobAE ? '14px' : '18px', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>{isIncoming?'📥':'📤'} {isEdit?'Rediger':'Nytt'} {isMobAE ? 'anbud' : (isIncoming?'innkommende anbud':'utgående anbud til UE')}</h2>
            <div style={{ display:'flex', gap:'4px' }}>
              {[['1', isMobAE ? 'Info' : 'Informasjon'],['2', isMobAE ? 'Kalkyle' : 'Kalkyle / Poster']].map(([n,l])=>(
                <button key={n} onClick={()=>setStep(+n)} style={{ padding: isMobAE ? '4px 10px' : '6px 14px', borderRadius:'8px', border:'none', background:step===+n?'#059669':'#f1f5f9', color:step===+n?'white':'#64748b', fontWeight:step===+n?'700':'500', fontSize: isMobAE ? '11px' : '13px', cursor:'pointer' }}>{n}. {l}</button>
              ))}
            </div>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:'6px', flexShrink:0 }}>
            {!isMobAE && <span style={{ fontSize:'13px', color:'#94a3b8' }}>Total: <strong style={{ color:'#059669' }}>{fmtT(grandTotal)}</strong></span>}
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
          </div>
        </div>

        <div style={{ overflowY:'auto', flex:1, padding: isMobAE ? '14px' : '24px', WebkitOverflowScrolling:'touch' }}>
          {step===1 && (
            <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'14px' }}>
              <div style={{ gridColumn:'1/-1' }}>{lbl('Tittel *')}<input value={form.title} onChange={e=>set('title',e.target.value)} placeholder={isIncoming?'F.eks. Anbudsforespørsel nybygg Storgata 12':'F.eks. Grunnarbeid – UE anbud'} style={tInp} /></div>
              <div>{lbl('Anbudsnummer')}<input value={form.tender_number} onChange={e=>set('tender_number',e.target.value)} style={tInp} /></div>
              <div>{lbl('Knytt til prosjekt')}<SearchableProjectSelect value={form.project_id} onChange={v => set('project_id', v)} projects={projects} style={tInp} placeholder="Ingen" /></div>
              <div style={{ gridColumn:'1/-1', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}><div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', marginBottom:'12px' }}>👤 {isIncoming?'Byggherre / Oppdragsgiver':'Kontakt / UE-koordinator'}</div></div>
              <div style={{ gridColumn:'1/-1' }}>
                {lbl(isIncoming ? 'Velg eksisterende byggherre' : 'Velg eksisterende kontakt')}
                <CustomerSelect
                  value={form.customer_id}
                  valueAsId
                  onChange={v => set('customer_id', v)}
                  onSelect={c => {
                    set('customer_id', c.id)
                    set('customer_name', c.name || '')
                    if (c.email) set('customer_email', c.email)
                    if (c.address) set('customer_address', c.address)
                    if (c.orgnr) set('customer_orgnr', c.orgnr)
                  }}
                  placeholder={isIncoming ? 'Søk etter byggherre — eller fyll ut under' : 'Søk etter kontakt — eller fyll ut under'}
                  filterType={isIncoming ? undefined : ['ue','bedrift']}
                />
                <p style={{ margin:'4px 0 0', fontSize:'11px', color:'#94a3b8' }}>Velger du eksisterende, autofylles feltene under. Manuell utfylling oppretter ny kontakt automatisk.</p>
              </div>
              <div>{lbl(isIncoming?'Byggherre':'Kontaktnavn')}<input value={form.customer_name} onChange={e=>set('customer_name',e.target.value)} placeholder="Navn / firma" style={tInp} /></div>
              <div>{lbl('E-post')}<input type="email" value={form.customer_email} onChange={e=>set('customer_email',e.target.value)} placeholder="epost@firma.no" style={tInp} /></div>
              <div>{lbl('Adresse')}<input value={form.customer_address} onChange={e=>set('customer_address',e.target.value)} placeholder="Gateadresse" style={tInp} /></div>
              <div>{lbl('Org.nr')}<input value={form.customer_orgnr} onChange={e=>set('customer_orgnr',e.target.value)} placeholder="123 456 789" style={tInp} /></div>
              <div style={{ gridColumn:'1/-1', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}><div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', marginBottom:'12px' }}>📅 Frister og betingelser</div></div>
              <div>{lbl('Anbudsfrist')}<input type="date" value={form.deadline} onChange={e=>set('deadline',e.target.value)} style={tInp} /></div>
              <div>{lbl('Gyldig til')}<input type="date" value={form.valid_until} onChange={e=>set('valid_until',e.target.value)} style={tInp} /></div>
              <div>{lbl('Generelt påslag (%)')}<input type="number" value={form.global_markup} onChange={e=>set('global_markup',e.target.value)} placeholder="0" min="0" max="100" style={tInp} /></div>
              <div style={{ gridColumn:'1/-1' }}>{lbl('Beskrivelse / Omfang')}<textarea value={form.description} onChange={e=>set('description',e.target.value)} rows={4} placeholder="Beskriv arbeidet, omfang, krav og betingelser..." style={{ ...tInp, resize:'none' }} /></div>
            </div>
          )}
          {step===2 && (
            <div style={{ display:'flex', flexDirection:'column', gap:'14px' }}>
              {chapters.map((ch,ci) => {
                const { cost, price } = calcTenderChapter(ch)
                return (
                  <div key={ch.id} style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', overflow:'hidden' }}>
                    <div style={{ background:'#f8fafc', padding: isMobAE ? '10px 12px' : '12px 18px', display:'flex', alignItems:'center', gap: isMobAE ? '6px' : '12px', borderBottom:'1px solid #f1f5f9', flexWrap: isMobAE ? 'wrap' : 'nowrap' }}>
                      <span style={{ width:'24px', height:'24px', borderRadius:'50%', background:'#059669', color:'white', fontWeight:'800', fontSize:'11px', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{ci+1}</span>
                      <input value={ch.title} onChange={e=>updateChapter(ch.id,'title',e.target.value)} placeholder="Kapitteltittel" style={{ ...tInp, flex:1, background:'transparent', fontWeight:'700', minWidth: isMobAE ? '120px' : 'auto', fontSize: isMobAE ? '13px' : '14px' }} />
                      <input type="number" value={ch.markup} onChange={e=>updateChapter(ch.id,'markup',e.target.value)} placeholder="%" min="0" max="100" style={{ ...tInp, width: isMobAE ? '60px' : '100px', fontSize: isMobAE ? '12px' : '14px' }} title="Påslag %" />
                      <span style={{ fontWeight:'700', color:'#059669', fontSize: isMobAE ? '12px' : '14px', whiteSpace:'nowrap' }}>{fmtT(price)}</span>
                      {chapters.length>1&&<button onClick={()=>removeChapter(ch.id)} style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'8px', padding:'5px 8px', cursor:'pointer', fontSize:'12px' }}>🗑️</button>}
                    </div>
                    <div style={{ padding: isMobAE ? '10px' : '14px 18px', overflowX: isMobAE ? 'auto' : 'visible', WebkitOverflowScrolling:'touch' }}>
                      <table style={{ width:'100%', borderCollapse:'collapse', minWidth: isMobAE ? '550px' : 'auto' }}>
                        <thead><tr>{['Beskrivelse','Mengde','Enhet','Kostpris/enh','Sum',''].map((h,i)=><th key={i} style={{ padding:'6px 8px', textAlign:i>=3&&i<=4?'right':'left', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase', borderBottom:'1px solid #f1f5f9' }}>{h}</th>)}</tr></thead>
                        <tbody>
                          {ch.posts.map(p => {
                            const ls = (parseFloat(p.qty)||0)*(parseFloat(p.unitCost)||0)
                            return <tr key={p.id}>
                              <td style={{ padding:'6px 4px' }}><input value={p.description} onChange={e=>updatePost(ch.id,p.id,'description',e.target.value)} placeholder="Beskriv post" style={{ ...tInp, minWidth:'180px' }} /></td>
                              <td style={{ padding:'6px 4px' }}><input type="number" value={p.qty} onChange={e=>updatePost(ch.id,p.id,'qty',e.target.value)} style={{ ...tInp, width:'70px', textAlign:'right' }} /></td>
                              <td style={{ padding:'6px 4px' }}><input value={p.unit} onChange={e=>updatePost(ch.id,p.id,'unit',e.target.value)} placeholder="stk" style={{ ...tInp, width:'60px' }} /></td>
                              <td style={{ padding:'6px 4px' }}><input type="number" value={p.unitCost} onChange={e=>updatePost(ch.id,p.id,'unitCost',e.target.value)} style={{ ...tInp, width:'120px', textAlign:'right' }} /></td>
                              <td style={{ padding:'6px 8px', textAlign:'right', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>{fmtT(ls)}</td>
                              <td style={{ padding:'6px 4px' }}>{ch.posts.length>1&&<button onClick={()=>removePost(ch.id,p.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'16px' }}>×</button>}</td>
                            </tr>
                          })}
                        </tbody>
                      </table>
                      <div style={{ display:'flex', justifyContent:'space-between', marginTop:'10px' }}>
                        <button onClick={()=>addPost(ch.id)} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>+ Legg til post</button>
                        <div style={{ fontSize:'13px', color:'#64748b' }}>Kostnad: <strong>{fmtT(cost)}</strong>{ch.markup>0?` → Pris: ${fmtT(price)}`:''}  </div>
                      </div>
                    </div>
                  </div>
                )
              })}
              <button onClick={addChapter} style={{ background:'white', border:'2px dashed #e2e8f0', borderRadius:'14px', padding:'16px', cursor:'pointer', color:'#94a3b8', fontWeight:'600', fontSize:'14px', width:'100%' }}>+ Legg til kapittel</button>
              <div style={{ background:'#f0fdf4', borderRadius:'14px', padding:'18px 24px', border:'1px solid #bbf7d0', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div><div style={{ fontSize:'13px', color:'#16a34a', fontWeight:'600' }}>Total kalkylepris eks. mva</div>{parseFloat(form.global_markup)>0&&<div style={{ fontSize:'12px', color:'#94a3b8' }}>Inkl. generelt påslag {form.global_markup}%</div>}</div>
                <div style={{ fontSize:'24px', fontWeight:'800', color:'#0f172a' }}>{fmtT(grandTotal)}</div>
              </div>
            </div>
          )}
        </div>
        <div style={{ padding: isMobAE ? '12px 14px' : '16px 24px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0, gap:'8px' }}>
          <div>{step===2&&<button onClick={()=>setStep(1)} style={{ padding: isMobAE ? '8px 12px' : '10px 18px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobAE ? '12px' : '14px' }}>← Tilbake</button>}</div>
          {isMobAE && <span style={{ fontSize:'12px', color:'#059669', fontWeight:'700' }}>{fmtT(grandTotal)}</span>}
          <div style={{ display:'flex', gap: isMobAE ? '6px' : '10px' }}>
            {step===1&&<button onClick={()=>setStep(2)} style={{ padding: isMobAE ? '8px 14px' : '10px 24px', background:'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobAE ? '12px' : '14px', fontWeight:'600' }}>{isMobAE ? 'Neste →' : 'Neste: Kalkyle →'}</button>}
            {step===2&&<button onClick={handleSave} disabled={saving} style={{ padding: isMobAE ? '8px 14px' : '10px 24px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize: isMobAE ? '12px' : '14px', fontWeight:'600' }}>{saving?'Lagrer...':isEdit?'Lagre':'Opprett'}</button>}
          </div>
        </div>
      </div>
    </div>
  )
}

function InviterUEModal({ tender, user, onClose, onSaved }) {
  const [ues, setUes] = useState([{ id: Date.now(), company_name:'', contact_name:'', email:'', dupWarning: null, customer_id: null }])
  const [existingUes, setExistingUes] = useState([])
  const [ueKunder, setUeKunder] = useState([])
  const [sending, setSending] = useState(false)
  const [sent, setSent] = useState(false)
  const [showUEPicker, setShowUEPicker] = useState(null)
  const [ueSearch, setUeSearch] = useState('')

  useEffect(() => {
    Promise.all([
      supabase.from('tender_ues').select('company_name, email, status').eq('tender_id', tender.id).then(r => r.data || []),
      supabase.from('customers').select('id, name, email, phone, orgnr, type').in('type', ['ue', 'bedrift']).order('name').then(r => r.data || []),
    ]).then(([existing, kunder]) => { setExistingUes(existing); setUeKunder(kunder) })
  }, [])

  const addUE = () => setUes(u=>[...u,{ id:Date.now(), company_name:'', contact_name:'', email:'', dupWarning: null, customer_id: null }])
  const removeUE = (id) => setUes(u=>u.filter(x=>x.id!==id))
  const selectFromRegister = (ueId, kunde) => {
    setUes(u => u.map(x => x.id === ueId ? { ...x, company_name: kunde.name, email: kunde.email || '', contact_name: '', customer_id: kunde.id, dupWarning: null } : x))
    setShowUEPicker(null); setUeSearch('')
  }
  const updateUE = (id, f, v) => {
    setUes(u => u.map(x => {
      if (x.id !== id) return x
      const updated = { ...x, [f]: v, dupWarning: null }
      if (f === 'email' && v.trim()) {
        const dupEmail = existingUes.find(e => e.email?.toLowerCase() === v.trim().toLowerCase())
        if (dupEmail) updated.dupWarning = `${dupEmail.company_name} (${dupEmail.email}) er allerede invitert`
        const dupInForm = ues.find(other => other.id !== id && other.email?.toLowerCase() === v.trim().toLowerCase())
        if (dupInForm) updated.dupWarning = 'Denne e-posten er allerede lagt til i skjemaet'
      }
      if (f === 'company_name' && v.trim()) {
        const dupName = existingUes.find(e => e.company_name?.toLowerCase() === v.trim().toLowerCase())
        if (dupName) updated.dupWarning = `${dupName.company_name} er allerede invitert (${dupName.email})`
      }
      return updated
    }))
  }

  const handleSend = async () => {
    const valid = ues.filter(u=>u.company_name.trim()&&u.email.trim())
    if (valid.length===0) return alert('Legg til minst en UE med navn og e-post.')
    const dups = valid.filter(u => existingUes.some(e => e.email?.toLowerCase() === u.email.trim().toLowerCase()))
    if (dups.length > 0 && !window.confirm(`${dups.length} UE er allerede invitert. Sende pa nytt?`)) {
      const nonDups = valid.filter(u => !existingUes.some(e => e.email?.toLowerCase() === u.email.trim().toLowerCase()))
      if (nonDups.length === 0) return
      return sendInvitations(nonDups)
    }
    await sendInvitations(valid)
  }

  const sendInvitations = async (ueList) => {
    setSending(true)
    try {
      let createdAny = false
      for (const ue of ueList) {
        let custId = ue.customer_id
        if (!custId) {
          const existingCust = ueKunder.find(k => k.email?.toLowerCase() === ue.email.trim().toLowerCase() || k.name?.toLowerCase() === ue.company_name.trim().toLowerCase())
          if (existingCust) { custId = existingCust.id }
          else {
            // Autogenerer kundenummer for ny UE (samme mønster som Kundeoversikt)
            const { data: allCust } = await supabase.from('customers').select('customer_number')
            const customer_number = nextSequenceNumber(allCust || [], 'K', 'customer_number', { withYear: false })
            const { data: newCust } = await supabase.from('customers').insert(sanitizeDbPayload({
              customer_number,
              name: ue.company_name.trim(),
              email: ue.email.trim(),
              type: 'ue',
              created_by: user?.id,
              notes: 'Automatisk opprettet fra anbudsmodulen (UE-invitasjon)',
            })).select().single()
            if (newCust) { custId = newCust.id; createdAny = true }
          }
        }
        const { data, error } = await supabase.from('tender_ues').insert(sanitizeDbPayload({
          tender_id: tender.id,
          company_name: ue.company_name.trim(),
          contact_name: ue.contact_name.trim() || null,
          email: ue.email.trim(),
          status: 'Invitert',
          customer_id: custId || null,
        })).select().single()
        if (error) throw error
        const pricingUrl = `${window.location.origin}/anbud-pris?token=${data.token}`
        const html = `<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px"><h1 style="color:#0f172a;font-size:22px;margin-bottom:8px">Anbudsforespørsel: ${tender.title}</h1><p style="color:#64748b;font-size:14px">Anbudsnummer: <strong>${tender.tender_number}</strong></p>${tender.description?'<div style="background:#f8fafc;border-radius:12px;padding:16px;margin:16px 0"><p style="margin:0;color:#475569;line-height:1.6">'+tender.description+'</p></div>':''}${tender.deadline?'<p style="color:#dc2626;font-weight:600;font-size:14px">Anbudsfrist: '+tender.deadline+'</p>':''}<p style="color:#64748b;font-size:14px">Vi ber om at du fyller inn dine priser for folggende poster.</p><div style="text-align:center;margin:32px 0"><a href="${pricingUrl}" style="background:#2563eb;color:white;padding:16px 32px;border-radius:12px;text-decoration:none;font-weight:700;font-size:16px;display:inline-block">Fyll inn priser</a></div><hr style="border:none;border-top:1px solid #f1f5f9;margin:24px 0"><p style="color:#94a3b8;font-size:12px">Sendt via En Plattform</p></div>`
        const fnRes = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, { method:'POST', headers:{ 'Content-Type':'application/json', 'apikey':import.meta.env.VITE_SUPABASE_ANON_KEY, 'Authorization':'Bearer '+import.meta.env.VITE_SUPABASE_ANON_KEY }, body: JSON.stringify({ to: ue.email.trim(), subject:'Anbudsforespørsel: '+tender.title+' ('+tender.tender_number+')', html }) })
        if (!fnRes.ok) { const d=await fnRes.json(); throw new Error(d.error||'E-post feilet') }
      }
      if (createdAny) invalidateCustomerCache()
      setSent(true); setTimeout(()=>onSaved(), 1500)
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSending(false) }
  }

  const hasDups = ues.some(u => u.dupWarning)
  const filteredUeKunder = ueKunder.filter(k => !ueSearch || [k.name, k.email, k.orgnr].some(v => v?.toLowerCase().includes(ueSearch.toLowerCase())))

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'600px', maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>Inviter underentreprenorer</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>x</button>
        </div>
        <div style={{ overflowY:'auto', flex:1, padding:'24px', display:'flex', flexDirection:'column', gap:'14px' }}>
          {sent ? (
            <div style={{ textAlign:'center', padding:'20px' }}><div style={{ fontSize:'48px', marginBottom:'12px' }}>✅</div><h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Invitasjoner sendt!</h3><p style={{ margin:0, color:'#64748b', fontSize:'14px' }}>UE-ene mottar e-post med lenke for a fylle inn priser.</p></div>
          ) : (
            <>
              <div style={{ background:'#eff6ff', borderRadius:'10px', padding:'12px 16px', border:'1px solid #bfdbfe', fontSize:'13px', color:'#1d4ed8' }}><strong>{tender.title}</strong> — {tender.tender_number}{tender.deadline?' · Frist: '+tender.deadline:''}</div>
              {existingUes.length > 0 && (
                <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px 16px', border:'1px solid #e2e8f0' }}>
                  <div style={{ fontSize:'12px', fontWeight:'700', color:'#64748b', marginBottom:'6px' }}>Allerede inviterte ({existingUes.length})</div>
                  <div style={{ display:'flex', flexWrap:'wrap', gap:'4px' }}>{existingUes.map((e, i) => (<span key={i} style={{ fontSize:'11px', background:'white', border:'1px solid #e2e8f0', borderRadius:'6px', padding:'2px 8px', color:'#475569' }}>{e.company_name} <span style={{ color: e.status==='Priset'?'#059669':'#2563eb', fontWeight:'600' }}>({e.status})</span></span>))}</div>
                </div>
              )}
              {ues.map((ue,i)=>(
                <div key={ue.id} style={{ background: ue.dupWarning?'#fffbeb':'#f8fafc', borderRadius:'12px', padding:'14px', border:'1px solid '+(ue.dupWarning?'#fde68a':'#f1f5f9') }}>
                  <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'10px' }}>
                    <span style={{ fontWeight:'700', fontSize:'13px', color:'#64748b' }}>UE {i+1}</span>
                    <div style={{ display:'flex', gap:'6px' }}>
                      <button onClick={() => { setShowUEPicker(showUEPicker===ue.id?null:ue.id); setUeSearch('') }} style={{ background:'#fffbeb', color:'#d97706', border:'1px solid #fde68a', borderRadius:'6px', padding:'4px 10px', fontSize:'11px', cursor:'pointer', fontWeight:'600' }}>🤝 Fra register</button>
                      {ues.length>1&&<button onClick={()=>removeUE(ue.id)} style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'6px', padding:'4px 10px', fontSize:'12px', cursor:'pointer' }}>Fjern</button>}
                    </div>
                  </div>
                  {showUEPicker===ue.id && (
                    <div style={{ marginBottom:'10px', background:'white', borderRadius:'10px', border:'1px solid #e2e8f0', overflow:'hidden' }}>
                      <input value={ueSearch} onChange={e=>setUeSearch(e.target.value)} placeholder="Sok i kontaktregisteret..." autoFocus style={{ width:'100%', padding:'8px 12px', border:'none', borderBottom:'1px solid #f1f5f9', fontSize:'13px', outline:'none', boxSizing:'border-box' }} />
                      <div style={{ maxHeight:'160px', overflowY:'auto' }}>
                        {filteredUeKunder.length===0 ? <div style={{ padding:'12px', textAlign:'center', color:'#94a3b8', fontSize:'12px' }}>Ingen treff</div> :
                        filteredUeKunder.slice(0,10).map(k => (
                          <button key={k.id} onClick={()=>selectFromRegister(ue.id,k)} style={{ display:'flex', alignItems:'center', gap:'10px', width:'100%', padding:'8px 12px', border:'none', background:'transparent', cursor:'pointer', textAlign:'left', fontSize:'12px', borderBottom:'1px solid #fafafa' }} onMouseEnter={e=>e.currentTarget.style.background='#f8fafc'} onMouseLeave={e=>e.currentTarget.style.background='transparent'}>
                            <span style={{ fontSize:'14px' }}>{k.type==='ue'?'🤝':'🏢'}</span>
                            <div style={{ flex:1 }}><div style={{ fontWeight:'600', color:'#0f172a' }}>{k.name}</div><div style={{ color:'#94a3b8', fontSize:'11px' }}>{k.email||'Ingen e-post'}{k.orgnr?' · '+k.orgnr:''}</div></div>
                            {k.type==='ue'&&<span style={{ background:'#fffbeb', color:'#d97706', fontSize:'10px', fontWeight:'600', padding:'1px 6px', borderRadius:'4px' }}>UE</span>}
                          </button>
                        ))}
                      </div>
                    </div>
                  )}
                  <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'8px' }}>
                    <div style={{ gridColumn:'1/-1' }}><label style={{ display:'block', fontSize:'12px', fontWeight:'600', color:'#374151', marginBottom:'4px' }}>Firmanavn * {ue.customer_id&&<span style={{ color:'#059669', fontWeight:'500' }}>✓ Koblet</span>}</label><input value={ue.company_name} onChange={e=>updateUE(ue.id,'company_name',e.target.value)} placeholder="UE Firma AS" style={{ ...tInp, borderColor: ue.dupWarning?'#fde68a':ue.customer_id?'#bbf7d0':'#e2e8f0' }} /></div>
                    <div><label style={{ display:'block', fontSize:'12px', fontWeight:'600', color:'#374151', marginBottom:'4px' }}>Kontaktperson</label><input value={ue.contact_name} onChange={e=>updateUE(ue.id,'contact_name',e.target.value)} placeholder="Fullt navn" style={tInp} /></div>
                    <div><label style={{ display:'block', fontSize:'12px', fontWeight:'600', color:'#374151', marginBottom:'4px' }}>E-post *</label><input type="email" value={ue.email} onChange={e=>updateUE(ue.id,'email',e.target.value)} placeholder="ue@firma.no" style={{ ...tInp, borderColor: ue.dupWarning?'#fde68a':'#e2e8f0' }} /></div>
                  </div>
                  {ue.dupWarning&&<div style={{ marginTop:'8px', fontSize:'12px', color:'#d97706' }}>⚠️ {ue.dupWarning}</div>}
                </div>
              ))}
              <button onClick={addUE} style={{ background:'white', border:'2px dashed #e2e8f0', borderRadius:'12px', padding:'12px', cursor:'pointer', color:'#94a3b8', fontWeight:'600', fontSize:'13px' }}>+ Legg til flere UE-er</button>
              <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
                <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={handleSend} disabled={sending} style={{ padding:'10px 24px', background:sending?'#6ee7b7':'#2563eb', color:'white', border:'none', borderRadius:'10px', cursor:sending?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{sending?'Sender...': hasDups?'⚠️ Send (duplikater)':'📧 Send invitasjoner'}</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}

function TildelModal({ tender, ues, projects, user, onClose, onSaved }) {
  const pricedUes = ues.filter(u=>u.status==='Priset').sort((a,b)=>(a.total_amount||0)-(b.total_amount||0))
  const [selectedUE, setSelectedUE] = useState(pricedUes[0]?.id||'')
  const [projectId, setProjectId] = useState(tender.project_id||'')
  const [saving, setSaving] = useState(false)

  const handleAward = async () => {
    const ue = ues.find(u=>u.id===selectedUE)
    if (!ue) return alert('Velg en UE')
    setSaving(true)
    try {
      await supabase.from('tenders').update({ status:'Tildelt', awarded_ue:ue.company_name, awarded_amount:ue.total_amount, project_id:projectId||null, updated_at:new Date().toISOString() }).eq('id', tender.id)
      await supabase.from('tender_ues').update({ status:'Avslått' }).eq('tender_id', tender.id).neq('id', selectedUE)
      if (user?.id) {
        await supabase.from('notifications').insert({ user_id:user.id, title:`Anbud tildelt: ${tender.title}`, message:`Tildelt til ${ue.company_name} for ${fmtT(ue.total_amount||0)}`, type:'success', link_page:'anbudsmodul' })
      }
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'500px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>🏆 Tildel anbud</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'16px' }}>
          {pricedUes.length===0 ? (
            <p style={{ color:'#94a3b8', fontSize:'14px', textAlign:'center', padding:'20px 0' }}>Ingen UE-er har levert pris ennå.</p>
          ) : (
            <>
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Velg vinnende UE</label>
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {pricedUes.map((ue,i)=>(
                    <button key={ue.id} onClick={()=>setSelectedUE(ue.id)}
                      style={{ padding:'14px 16px', borderRadius:'12px', border:`2px solid ${selectedUE===ue.id?'#059669':'#e2e8f0'}`, background:selectedUE===ue.id?'#f0fdf4':'white', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                      <div style={{ textAlign:'left' }}>
                        <div style={{ fontWeight:'700', color:'#0f172a', fontSize:'14px' }}>{ue.company_name} {i===0&&'🏆'}</div>
                        {ue.contact_name&&<div style={{ fontSize:'12px', color:'#64748b' }}>{ue.contact_name}</div>}
                      </div>
                      <div style={{ fontWeight:'800', color:i===0?'#16a34a':'#0f172a', fontSize:'16px' }}>{fmtT(ue.total_amount)}</div>
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Knytt til prosjekt</label>
                <SearchableProjectSelect value={projectId} onChange={setProjectId} projects={projects} style={tInp} placeholder="Ingen" />
              </div>
              <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
                <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={handleAward} disabled={saving||!selectedUE} style={{ padding:'10px 24px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{saving?'Lagrer...':'🏆 Tildel anbud'}</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}

// ─── UE PRISINGSSIDE ──────────────────────────────────────────────────────────
function UEPrisingsPage() {
  const [token, setToken] = useState(null)
  const [ueData, setUeData] = useState(null)
  const [tender, setTender] = useState(null)
  const [chapters, setChapters] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [submitting, setSubmitting] = useState(false)
  const [done, setDone] = useState(false)

  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const t = params.get('token')
    if (!t) { setError('Ugyldig lenke.'); setLoading(false); return }
    setToken(t); loadData(t)
  }, [])

  const loadData = async (t) => {
    try {
      const { data: ue, error: ue_err } = await supabase.from('tender_ues').select('*').eq('token', t).single()
      if (ue_err||!ue) throw new Error('Lenken er ugyldig eller utløpt.')
      if (ue.status === 'Priset') { setDone(true); setLoading(false); return }
      const { data: td, error: td_err } = await supabase.from('tenders').select('*').eq('id', ue.tender_id).single()
      if (td_err||!td) throw new Error('Anbudet ble ikke funnet.')
      setUeData(ue); setTender(td)
      setChapters((td.chapters||[]).map(ch=>({ ...ch, posts:(ch.posts||[]).map(p=>({...p,uePrice:''})) })))
      await supabase.from('tender_ues').update({ status:'Åpnet' }).eq('id', ue.id)
    } catch(e) { setError(e.message) }
    finally { setLoading(false) }
  }

  const updatePrice = (chId, pId, val) => setChapters(c=>c.map(ch=>ch.id===chId?{...ch,posts:ch.posts.map(p=>p.id===pId?{...p,uePrice:val}:p)}:ch))

  const handleSubmit = async () => {
    setSubmitting(true)
    try {
      const totalAmount = chapters.reduce((acc,ch)=>acc+(ch.posts||[]).reduce((a,p)=>a+(parseFloat(p.qty)||0)*(parseFloat(p.uePrice)||0),0),0)
      await supabase.from('tender_ues').update({ status:'Priset', chapters, total_amount:totalAmount, submitted_at:new Date().toISOString() }).eq('id', ueData.id)
      if (tender.created_by) {
        await supabase.from('notifications').insert({ user_id:tender.created_by, title:`Ny anbудspris mottatt: ${tender.title}`, message:`${ueData.company_name} har levert pris: ${fmtT(totalAmount)}`, type:'success', link_page:'anbudsmodul' })
      }
      setDone(true)
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSubmitting(false) }
  }

  const pageStyle = { minHeight:'100vh', background:'linear-gradient(135deg,#eff6ff 0%,#f8fafc 100%)', display:'flex', alignItems:'flex-start', justifyContent:'center', padding:'32px 16px', fontFamily:'system-ui,sans-serif' }

  if (loading) return <div style={pageStyle}><div style={{ textAlign:'center', marginTop:'20vh' }}><div style={{ width:'40px', height:'40px', border:'3px solid #e2e8f0', borderTop:'3px solid #2563eb', borderRadius:'50%', margin:'0 auto 16px', animation:'spin 1s linear infinite' }}/><style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style><p style={{ color:'#64748b' }}>Laster anbudsforespørsel...</p></div></div>
  if (error) return <div style={pageStyle}><div style={{ background:'white', borderRadius:'20px', padding:'40px', maxWidth:'480px', width:'100%', textAlign:'center', boxShadow:'0 8px 40px rgba(0,0,0,0.1)' }}><div style={{ fontSize:'48px', marginBottom:'16px' }}>❌</div><h2 style={{ margin:'0 0 8px', color:'#0f172a' }}>Ugyldig lenke</h2><p style={{ margin:0, color:'#64748b' }}>{error}</p></div></div>
  if (done) return <div style={pageStyle}><div style={{ background:'white', borderRadius:'20px', padding:'40px', maxWidth:'480px', width:'100%', textAlign:'center', boxShadow:'0 8px 40px rgba(0,0,0,0.1)' }}><div style={{ fontSize:'64px', marginBottom:'16px' }}>✅</div><h2 style={{ margin:'0 0 8px', color:'#0f172a', fontSize:'24px' }}>Priser innlevert!</h2><p style={{ margin:'0 0 12px', color:'#64748b' }}>Oppdragsgiver er varslet og vil kontakte deg.</p><p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Du kan lukke denne siden.</p></div></div>

  const totalAmount = chapters.reduce((acc,ch)=>acc+(ch.posts||[]).reduce((a,p)=>a+(parseFloat(p.qty)||0)*(parseFloat(p.uePrice)||0),0),0)

  return (
    <div style={pageStyle}>
      <div style={{ maxWidth:'720px', width:'100%', display:'flex', flexDirection:'column', gap:'20px' }}>
        <div style={{ background:'white', borderRadius:'20px', padding:'28px 32px', boxShadow:'0 4px 24px rgba(0,0,0,0.08)', border:'1px solid #f1f5f9' }}>
          <div style={{ display:'flex', alignItems:'flex-start', gap:'14px' }}>
            <div style={{ width:'52px', height:'52px', borderRadius:'14px', background:'#eff6ff', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px', flexShrink:0 }}>📑</div>
            <div>
              <h1 style={{ margin:'0 0 4px', fontSize:'20px', fontWeight:'800', color:'#0f172a' }}>{tender.title}</h1>
              <p style={{ margin:0, color:'#64748b', fontSize:'13px' }}>Anbudsnummer: {tender.tender_number} · Invitert: {ueData.company_name}</p>
              {tender.deadline && <p style={{ margin:'6px 0 0', color:'#dc2626', fontWeight:'600', fontSize:'13px' }}>⏰ Frist: {tender.deadline}</p>}
            </div>
          </div>
          {tender.description && <p style={{ margin:'16px 0 0', fontSize:'14px', color:'#475569', lineHeight:1.6, background:'#f8fafc', borderRadius:'10px', padding:'12px 16px' }}>{tender.description}</p>}
        </div>

        {chapters.map((ch,ci)=>(
          <div key={ch.id} style={{ background:'white', borderRadius:'16px', padding:'20px 24px', boxShadow:'0 2px 12px rgba(0,0,0,0.06)', border:'1px solid #f1f5f9' }}>
            <h3 style={{ margin:'0 0 14px', fontSize:'15px', fontWeight:'700', color:'#0f172a' }}>{String(ci+1).padStart(2,'0')}. {ch.title}</h3>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:'14px' }}>
              <thead><tr style={{ background:'#f8fafc' }}>{['Beskrivelse','Mengde','Enhet','Din pris/enh','Sum'].map(h=><th key={h} style={{ padding:'8px 10px', textAlign:h==='Din pris/enh'||h==='Sum'?'right':'left', color:'#64748b', fontWeight:'600', fontSize:'12px', textTransform:'uppercase', borderBottom:'1px solid #f1f5f9' }}>{h}</th>)}</tr></thead>
              <tbody>
                {(ch.posts||[]).map(p=>{
                  const ls=(parseFloat(p.qty)||0)*(parseFloat(p.uePrice)||0)
                  return <tr key={p.id} style={{ borderBottom:'1px solid #f8fafc' }}>
                    <td style={{ padding:'10px', color:'#0f172a', fontWeight:'500' }}>{p.description||'—'}</td>
                    <td style={{ padding:'10px', textAlign:'right', color:'#475569' }}>{p.qty}</td>
                    <td style={{ padding:'10px', color:'#475569' }}>{p.unit}</td>
                    <td style={{ padding:'6px' }}><input type="number" value={p.uePrice} onChange={e=>updatePrice(ch.id,p.id,e.target.value)} placeholder="0" style={{ ...tInp, width:'120px', textAlign:'right', borderColor:'#2563eb' }} /></td>
                    <td style={{ padding:'10px', textAlign:'right', fontWeight:'700', color:'#0f172a' }}>{fmtT(ls)}</td>
                  </tr>
                })}
              </tbody>
            </table>
          </div>
        ))}

        <div style={{ background:'white', borderRadius:'16px', padding:'20px 24px', boxShadow:'0 2px 12px rgba(0,0,0,0.06)', border:'1px solid #f1f5f9' }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'20px' }}>
            <div><div style={{ fontSize:'13px', color:'#64748b', fontWeight:'600' }}>Din totalpris eks. mva</div></div>
            <div style={{ fontSize:'26px', fontWeight:'800', color:'#0f172a' }}>{fmtT(totalAmount)}</div>
          </div>
          <button onClick={handleSubmit} disabled={submitting||totalAmount===0}
            style={{ width:'100%', padding:'16px', background:submitting||totalAmount===0?'#94a3b8':'#2563eb', color:'white', border:'none', borderRadius:'14px', fontSize:'16px', fontWeight:'700', cursor:submitting||totalAmount===0?'not-allowed':'pointer' }}>
            {submitting?'Sender inn...':'📤 Lever priser'}
          </button>
          {totalAmount===0&&<p style={{ margin:'8px 0 0', fontSize:'13px', color:'#94a3b8', textAlign:'center' }}>Fyll inn priser for å levere</p>}
        </div>
        <p style={{ margin:0, fontSize:'12px', color:'#cbd5e1', textAlign:'center' }}>Sendt via En Plattform KS-system · enplattform.no</p>
      </div>
    </div>
  )
}

// ─── END ANBUDSMODUL ──────────────────────────────────────────────────────────

// ─── ORDRE MODULE ─────────────────────────────────────────────────────────────

const ORDER_STATUS = {
  'Utkast':    { bg:'#f8fafc', color:'#64748b', border:'#e2e8f0', emoji:'📝' },
  'Sendt':     { bg:'#eff6ff', color:'#2563eb', border:'#bfdbfe', emoji:'📤' },
  'Bekreftet': { bg:'#f5f3ff', color:'#7c3aed', border:'#ddd6fe', emoji:'✅' },
  'Pågår':     { bg:'#fffbeb', color:'#d97706', border:'#fde68a', emoji:'⚙️' },
  'Fullført':  { bg:'#f0fdf4', color:'#16a34a', border:'#bbf7d0', emoji:'🏁' },
  'Fakturert': { bg:'#ecfdf5', color:'#059669', border:'#a7f3d0', emoji:'🧾' },
  'Avslått':   { bg:'#fef2f2', color:'#dc2626', border:'#fecaca', emoji:'❌' },
}

const oInp = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', fontFamily:'system-ui, sans-serif' }
const oCard = { background:'white', borderRadius: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '16px', border:'1px solid #f1f5f9', padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '20px 24px', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }

function OrderStatusBadge({ status }) {
  const cfg = ORDER_STATUS[status] || ORDER_STATUS['Utkast']
  return <span style={{ background:cfg.bg, color:cfg.color, border:`1px solid ${cfg.border}`, padding:'3px 10px', borderRadius:'999px', fontSize:'12px', fontWeight:'600' }}>{cfg.emoji} {status}</span>
}

function calcOrderChapter(ch) {
  // Ordre bruker IKKE påslag — totalt = sum av poster
  const sum = (ch.posts||[]).reduce((acc,p) => acc + (parseFloat(p.qty)||0)*((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0)), 0)
  return { sum, total: sum }
}

function calcOrder(chapters, globalMarkup) {
  // Ordre bruker IKKE påslag — grandTotal = sum av alle kapitler
  // globalMarkup-parameteren beholdes for bakoverkompatibilitet men ignoreres
  const chapterTotals = chapters.reduce((acc,ch) => acc + calcOrderChapter(ch).total, 0)
  return { chapterTotals, grandTotal: chapterTotals }
}

// ─── ENDRINGSMELDINGER ────────────────────────────────────────────────────────
// Registrer tillegg/endringer fra byggeplass, send til kunde for godkjenning

const EM_STATUS = {
  'Utkast':           { bg:'#f8fafc', color:'#64748b', border:'#e2e8f0', emoji:'📝' },
  'Sendt':            { bg:'#eff6ff', color:'#2563eb', border:'#bfdbfe', emoji:'📧' },
  'Godkjent':         { bg:'#f0fdf4', color:'#16a34a', border:'#bbf7d0', emoji:'✅' },
  'Avvist':           { bg:'#fef2f2', color:'#dc2626', border:'#fecaca', emoji:'❌' },
  'Under forhandling':{ bg:'#fffbeb', color:'#d97706', border:'#fde68a', emoji:'🤝' },
  'Fakturert':        { bg:'#f5f3ff', color:'#7c3aed', border:'#ddd6fe', emoji:'🧾' },
}

function EndringsmeldingPage() {
  const isMobBild = typeof window !== 'undefined' && window.innerWidth < 768
  const { user } = useAuth()
  const appAlert = useAppAlert()
  const confirm = useConfirm()
  const [endringer, setEndringer] = useState([])

  // ── Navigasjonssystem: URL-basert historikk ──────────────────────────────
  // URL-format:
  //   #endringsmelding               → liste
  //   #endringsmelding/em_abc123     → detaljvisning av EM
  //   #endringsmelding/new           → opprett-ny skjema
  //   #endringsmelding/edit/em_abc123 → rediger EM
  const parseSubRoute = () => {
    if (typeof window === 'undefined') return { view: 'list' }
    const hash = window.location.hash.replace('#', '')
    const parts = hash.split('/').filter(Boolean)
    if (parts[0] !== 'endringsmelding') return { view: 'list' }
    if (!parts[1]) return { view: 'list' }
    if (parts[1] === 'new') return { view: 'new' }
    if (parts[1] === 'edit' && parts[2]) return { view: 'edit', id: parts[2] }
    return { view: 'detail', id: parts[1] }
  }

  const [route, setRoute] = useState(parseSubRoute)

  // Nav helpers — disse oppdaterer BÅDE URL og state
  const navList = () => {
    if (window.location.hash !== '#endringsmelding') {
      window.history.pushState({ emRoute: 'list' }, '', '#endringsmelding')
    }
    setRoute({ view: 'list' })
  }
  // Variant som erstatter siste historikk-oppføring (for lagring-flyt)
  const navListReplace = () => {
    window.history.replaceState({ emRoute: 'list' }, '', '#endringsmelding')
    setRoute({ view: 'list' })
  }
  const navDetail = (id) => {
    window.history.pushState({ emRoute: 'detail', id }, '', `#endringsmelding/${id}`)
    setRoute({ view: 'detail', id })
  }
  const navNew = () => {
    window.history.pushState({ emRoute: 'new' }, '', '#endringsmelding/new')
    setRoute({ view: 'new' })
  }
  const navEdit = (id) => {
    window.history.pushState({ emRoute: 'edit', id }, '', `#endringsmelding/edit/${id}`)
    setRoute({ view: 'edit', id })
  }

  // Lytt på tilbake/frem-navigasjon (popstate)
  useEffect(() => {
    const onPop = () => setRoute(parseSubRoute())
    window.addEventListener('popstate', onPop)
    return () => window.removeEventListener('popstate', onPop)
  }, [])

  // ESC-lukker for modaler (siden modaler ikke er i historikken)
  useEffect(() => {
    const onKey = (e) => {
      if (e.key !== 'Escape') return
      // Prioritet: viewingVersion → sendDialogEm → resendDialogEm
      if (viewingVersion) { setViewingVersion(null); return }
      if (sendDialogEm) { setSendDialogEm(null); return }
      if (resendDialogEm) { setResendDialogEm(null); return }
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  })

  const [sendDialogEm, setSendDialogEm] = useState(null) // EM for som skal sendes (åpner frist-modal)
  const [resendDialogEm, setResendDialogEm] = useState(null) // EM for re-send/revisjon/kopi
  const [viewingVersion, setViewingVersion] = useState(null) // { em, version } - viser historisk versjon
  const [showVersionsPanel, setShowVersionsPanel] = useState(false)
  const [projects, setProjects] = useState([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('all')
  const [projectFilter, setProjectFilter] = useState('all')
  const [expandedEm, setExpandedEm] = useState(null)

  // Computed "virtuelle" state basert på route — erstatter gamle viewEm/showForm/editEm
  const viewEmId = route.view === 'detail' ? route.id : null
  const viewEm = viewEmId ? endringer.find(e => e.id === viewEmId) : null
  const showForm = route.view === 'new' || route.view === 'edit'
  const editEmId = route.view === 'edit' ? route.id : null
  const editEm = editEmId ? endringer.find(e => e.id === editEmId) : null
  const f = { fontFamily:'system-ui,sans-serif' }
  const inp = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box' }

  const load = async () => {
    try {
      const [emRes, prRes] = await Promise.all([
        supabase.from('endringsmeldinger').select('*').order('created_at', { ascending: false }),
        supabase.from('projects').select('id, name, parent_id, depth, project_number').order('name'),
      ])
      setEndringer(emRes.data || [])
      setProjects(prRes.data || [])
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(() => { load() }, [])

  const filtered = endringer.filter(em => {
    if (statusFilter !== 'all' && em.status !== statusFilter) return false
    if (projectFilter !== 'all' && em.project_id !== projectFilter) return false
    if (search && !em.title?.toLowerCase().includes(search.toLowerCase()) && !em.em_number?.toLowerCase().includes(search.toLowerCase())) return false
    return true
  })

  const totalTillegg = filtered.filter(e => e.status === 'Godkjent' || e.status === 'Fakturert').reduce((s, e) => s + (parseFloat(e.amount) || 0), 0)
  const totalIkkeFakturert = filtered.filter(e => e.status === 'Godkjent').reduce((s, e) => s + (parseFloat(e.amount) || 0), 0)

  const isMobEM = typeof window !== 'undefined' && window.innerWidth < 768

  // ── PDF-rapport per prosjekt ──
  const [showPdfPicker, setShowPdfPicker] = useState(false)
  const [exportingPdf, setExportingPdf] = useState(false)

  const exportSingleEmPDF = async (em, mode = 'download') => {
    // mode: 'download' → lagrer fila (standard), 'base64' → returnerer { base64, filename }
    if (mode === 'download') setExportingPdf(true)
    try {
      const pdf = await createBrandedPdf()
      const { doc, pw, ph, ml, mr, cw, hex, setC, setF, setD } = pdf

      const proj = projects.find(p => p.id === em.project_id)

      // Slå opp brukernavn for created_by
      let createdByName = ''
      if (em.created_by) {
        try {
          const { data: up } = await supabase.from('user_profiles').select('full_name').eq('id', em.created_by).single()
          createdByName = up?.full_name || ''
        } catch(e) {/* ignore */}
      }

      pdf.drawHeader('ENDRINGSMELDING', em.em_number || em.title || '')
      let y = pdf.y
      const addPage = () => { doc.addPage(); y = 14 }
      const checkSpace = (n) => { if (y + n > ph - 18) addPage() }

      // ── Tittel ──
      setC(hex('#0f172a')); doc.setFontSize(16); doc.setFont('helvetica', 'bold')
      const titleLines = doc.splitTextToSize(em.title || 'Uten tittel', cw)
      doc.text(titleLines, ml, y)
      y += titleLines.length * 7 + 2

      // Status-pill + beløp
      const st = EM_STATUS[em.status] || EM_STATUS['Utkast']
      setF(hex(st.bg)); doc.roundedRect(ml, y - 3, doc.getTextWidth(em.status || '') + 10, 6, 1.5, 1.5, 'F')
      setC(hex(st.color)); doc.setFontSize(9); doc.setFont('helvetica', 'bold')
      doc.text(em.status || '—', ml + 5, y + 1)
      if (em.amount) {
        setC(hex('#059669')); doc.setFontSize(14); doc.setFont('helvetica', 'bold')
        doc.text(Math.round(em.amount).toLocaleString('nb-NO') + ' kr', pw - mr, y + 1, { align:'right' })
        setC(hex('#94a3b8')); doc.setFontSize(8); doc.setFont('helvetica', 'normal')
        doc.text('eks. mva', pw - mr, y + 5, { align:'right' })
      }
      y += 12

      // ── Info-kort: prosjekt, opprettet av, dato, sendt til ──
      setF(hex('#f8fafc')); setD(hex('#e2e8f0'))
      const infoH = 24
      doc.roundedRect(ml, y, cw, infoH, 2, 2, 'FD')
      const infoCols = [
        { label: 'PROSJEKT', value: proj?.name || '—' },
        { label: 'OPPRETTET AV', value: createdByName || '—' },
        { label: 'OPPRETTET', value: em.created_at ? new Date(em.created_at).toLocaleDateString('nb-NO', { day:'numeric', month:'long', year:'numeric' }) : '—' },
        { label: 'SENDT TIL', value: em.sent_to || em.customer_email || '—' },
      ]
      const colW = cw / infoCols.length
      infoCols.forEach((c, i) => {
        const cx = ml + 5 + i * colW
        setC(hex('#94a3b8')); doc.setFontSize(7); doc.setFont('helvetica', 'bold')
        doc.text(c.label, cx, y + 6)
        setC(hex('#0f172a')); doc.setFontSize(9); doc.setFont('helvetica', 'normal')
        const lines = doc.splitTextToSize(String(c.value), colW - 6)
        doc.text(lines.slice(0, 2), cx, y + 12)
      })
      y += infoH + 6

      // ── Beskrivelse ──
      if (em.description) {
        checkSpace(20)
        setC(hex('#0f172a')); doc.setFontSize(11); doc.setFont('helvetica', 'bold')
        doc.text('Beskrivelse', ml, y); y += 6
        setC(hex('#475569')); doc.setFontSize(10); doc.setFont('helvetica', 'normal')
        const dLines = doc.splitTextToSize(em.description, cw)
        doc.text(dLines, ml, y)
        y += dLines.length * 5 + 4
      }

      // ── Årsak ──
      if (em.reason) {
        checkSpace(20)
        setC(hex('#0f172a')); doc.setFontSize(11); doc.setFont('helvetica', 'bold')
        doc.text('Årsak', ml, y); y += 6
        setC(hex('#475569')); doc.setFontSize(10); doc.setFont('helvetica', 'normal')
        const rLines = doc.splitTextToSize(em.reason, cw)
        doc.text(rLines, ml, y)
        y += rLines.length * 5 + 4
      }

      // ── Poster-tabell ──
      const validPosts = Array.isArray(em.posts) ? em.posts.filter(p => p.description || parseFloat(p.qty) > 0) : []
      if (validPosts.length > 0) {
        checkSpace(30)
        setC(hex('#0f172a')); doc.setFontSize(11); doc.setFont('helvetica', 'bold')
        doc.text('Poster', ml, y); y += 7

        // Tabell-hoder
        const colW = {
          desc: cw * 0.35,
          qty: cw * 0.08,
          unit: cw * 0.10,
          work: cw * 0.15,
          mat: cw * 0.15,
          sum: cw * 0.17,
        }
        const xDesc = ml
        const xQty = xDesc + colW.desc
        const xUnit = xQty + colW.qty
        const xWork = xUnit + colW.unit
        const xMat = xWork + colW.work
        const xSum = xMat + colW.mat

        setF(hex('#f8fafc')); doc.rect(ml, y - 4, cw, 6, 'F')
        setC(hex('#475569')); doc.setFontSize(8); doc.setFont('helvetica', 'bold')
        doc.text('BESKRIVELSE', xDesc + 2, y)
        doc.text('MGD', xQty + colW.qty - 2, y, { align:'right' })
        doc.text('ENHET', xUnit + 2, y)
        doc.text('ARBEID/ENH', xWork + colW.work - 2, y, { align:'right' })
        doc.text('MAT./ENH', xMat + colW.mat - 2, y, { align:'right' })
        doc.text('SUM', xSum + colW.sum - 2, y, { align:'right' })
        y += 5

        // Rader
        setC(hex('#0f172a')); doc.setFont('helvetica', 'normal'); doc.setFontSize(9)
        validPosts.forEach(p => {
          checkSpace(7)
          const sum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
          // Desk beskrivelse kan være lang, så klipp hvis nødvendig
          const descText = String(p.description || '').length > 40 ? String(p.description).slice(0, 37) + '...' : String(p.description || '—')
          doc.text(descText, xDesc + 2, y)
          doc.text(String(p.qty || 0), xQty + colW.qty - 2, y, { align:'right' })
          doc.text(String(p.unit || 'stk'), xUnit + 2, y)
          doc.text(Math.round(parseFloat(p.unitPriceWork)||0).toLocaleString('nb-NO'), xWork + colW.work - 2, y, { align:'right' })
          doc.text(Math.round(parseFloat(p.unitPriceMaterial)||0).toLocaleString('nb-NO'), xMat + colW.mat - 2, y, { align:'right' })
          doc.setFont('helvetica', 'bold')
          doc.text(Math.round(sum).toLocaleString('nb-NO'), xSum + colW.sum - 2, y, { align:'right' })
          doc.setFont('helvetica', 'normal')
          y += 5
          // Stripe under rad
          setF(hex('#f1f5f9')); doc.rect(ml, y - 2, cw, 0.2, 'F')
        })

        // Total
        y += 3
        setC(hex('#059669')); doc.setFontSize(10); doc.setFont('helvetica', 'bold')
        doc.text('Total eks. mva: ' + Math.round(em.amount || 0).toLocaleString('nb-NO') + ' kr', pw - mr, y, { align:'right' })
        y += 8
      }

      // ── Tidskonsekvens ──
      if (em.time_consequence) {
        checkSpace(14)
        setC(hex('#0f172a')); doc.setFontSize(10); doc.setFont('helvetica', 'bold')
        doc.text('Tidskonsekvens: ', ml, y)
        setC(hex('#475569')); doc.setFont('helvetica', 'normal')
        doc.text(String(em.time_consequence), ml + doc.getTextWidth('Tidskonsekvens: '), y)
        y += 8
      }

      // ── Aktivitetslogg ──
      const log = Array.isArray(em.activity_log) ? em.activity_log : []
      if (log.length > 0) {
        checkSpace(30)
        y += 2
        setC(hex('#0f172a')); doc.setFontSize(11); doc.setFont('helvetica', 'bold')
        doc.text('Aktivitetslogg', ml, y); y += 7

        log.slice().reverse().forEach((entry, i) => {
          checkSpace(12)
          // Timeline-prikk
          const isFirst = i === 0
          setF(hex(isFirst ? '#059669' : '#cbd5e1'))
          doc.circle(ml + 2, y + 1.5, 1.5, 'F')

          setC(hex(isFirst ? '#059669' : '#0f172a')); doc.setFontSize(10); doc.setFont('helvetica', 'bold')
          doc.text(entry.action || '—', ml + 7, y + 2)
          if (entry.to) {
            setC(hex('#64748b')); doc.setFont('helvetica', 'normal')
            doc.text(`→ ${entry.to}`, ml + 7 + doc.getTextWidth((entry.action || '—') + ' '), y + 2)
          }
          setC(hex('#94a3b8')); doc.setFontSize(8); doc.setFont('helvetica', 'normal')
          const ts = entry.at ? new Date(entry.at).toLocaleString('nb-NO', { day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit' }) : ''
          const byTxt = entry.by ? `${ts} · ${entry.by}` : ts
          doc.text(byTxt, ml + 7, y + 7)
          y += 10
        })
      }

      pdf.drawFooters()

      const safeName = (em.em_number || em.title || 'EM').replace(/[^a-zA-Z0-9_-]/g, '_')
      const filename = `Endringsmelding - ${safeName}.pdf`
      if (mode === 'base64') {
        // Returner PDF som base64 (uten prefiks) for e-postvedlegg
        const dataUri = doc.output('datauristring')
        const base64 = dataUri.split(',')[1] || dataUri
        return { base64, filename }
      }
      doc.save(filename)
    } catch(e) { console.error(e); if (mode === 'download') await appAlert({ message: 'Feil ved PDF-generering', subMessage: e.message, kind: 'error' }); throw e }
    finally { if (mode === 'download') setExportingPdf(false) }
  }

  const handleDelete = async (em) => {
    if (!(await confirm({ message: 'Slett denne endringsmeldingen?', subMessage: `"${em.title}" slettes permanent. Denne handlingen kan ikke angres.`, danger: true }))) return
    await supabase.from('endringsmeldinger').delete().eq('id', em.id)
    load()
  }

  // ── Helper: Bestem type re-send basert på aktivitetslogg og status ────────
  // Returnerer: 'send' (første gang), 'resend' (uendret), 'revision' (redigert), 'copy' (godkjent/avvist)
  const getEmSendType = (em) => {
    if (em.status === 'Utkast') return 'send'
    if (em.status === 'Godkjent' || em.status === 'Avvist') return 'copy'
    if (em.status !== 'Sendt') return 'resend'

    // Status = 'Sendt': sjekk om redigert etter siste utsendelse
    const log = Array.isArray(em.activity_log) ? em.activity_log : []
    let lastSentIdx = -1
    for (let i = log.length - 1; i >= 0; i--) {
      const action = log[i].action || ''
      if (action === 'Sendt til kunde' || action.startsWith('Sendt på nytt') || action.startsWith('Sendt revisjon')) {
        lastSentIdx = i
        break
      }
    }
    if (lastSentIdx === -1) return 'resend' // Ingen send-hendelse funnet, fallback
    // Er det en "Endret"-hendelse etter siste sending?
    const editedAfterSend = log.slice(lastSentIdx + 1).some(l => (l.action || '') === 'Endret')
    return editedAfterSend ? 'revision' : 'resend'
  }

  // ── Helper: Lag snapshot av EM-tilstand for versjonshistorikk ──────────────
  const buildEmSnapshot = (em, sendType) => {
    const existingVersions = Array.isArray(em.versions) ? em.versions : []
    return {
      version_number: existingVersions.length + 1,
      sent_at: new Date().toISOString(),
      sent_type: sendType,
      sent_by: user?.email || null,
      // Selve innholdet som skal bevares
      snapshot: {
        title: em.title,
        em_number: em.em_number,
        description: em.description,
        reason: em.reason,
        amount: em.amount,
        posts: em.posts || [],
        time_consequence: em.time_consequence,
        images: em.images || [],
        vedlegg: em.vedlegg || [],
        status: em.status,
        customer_email: em.customer_email,
      },
    }
  }

  // ── Form Component ─────────────────────────────────────────────────────────
  const EmForm = ({ initial, onClose, onSaved, onSaveAndSend }) => {
    const isEdit = !!initial?.id
    const [form, setForm] = useState({
      title: initial?.title || '',
      em_number: initial?.em_number || nextSequenceNumber(endringer, 'EM', 'em_number', { withYear: false }),
      project_id: initial?.project_id || '',
      description: initial?.description || '',
      reason: initial?.reason || '',
      amount: initial?.amount || '',
      hours: initial?.hours || '',
      materials_cost: initial?.materials_cost || '',
      ue_cost: initial?.ue_cost || '',
      time_consequence: initial?.time_consequence || '',
      // Parse eksisterende fri-tekst til verdi + enhet (f.eks. "3 dager" → 3 + "dager")
      time_consequence_value: (() => {
        const tc = initial?.time_consequence || ''
        const match = tc.match(/^(\d+)\s*(dag|uke|måned)/i)
        return match ? match[1] : ''
      })(),
      time_consequence_unit: (() => {
        const tc = initial?.time_consequence || ''
        if (/måned/i.test(tc)) return 'måneder'
        if (/uke/i.test(tc)) return 'uker'
        return 'dager'
      })(),
      status: initial?.status || 'Utkast',
      customer_email: initial?.customer_email || '',
      notes: initial?.notes || '',
    })
    const [images, setImages] = useState(initial?.images || [])
    const [vedlegg, setVedlegg] = useState(initial?.vedlegg || [])
    const [internalRecipients, setInternalRecipients] = useState([])
    const [employees, setEmployees] = useState([])

    // Last inn ansatte for intern-varsling
    useEffect(() => {
      supabase.from('employees').select('first_name, last_name, email, user_id').then(({ data }) => {
        setEmployees((data || []).filter(e => e.email && e.user_id)) // Kun med brukerkonto
      })
    }, [])

    const [posts, setPosts] = useState(() => {
      // Bruk eksisterende poster hvis det finnes
      const existing = initial?.posts
      if (Array.isArray(existing) && existing.length > 0) return existing
      // Ellers start med en tom rad
      return [{ id: crypto.randomUUID(), description: '', qty: 1, unit: 'stk', unitPriceWork: '', unitPriceMaterial: '' }]
    })
    const [saving, setSaving] = useState(false)
    const set = (k, v) => setForm(f => ({ ...f, [k]: v }))

    // Post-håndtering
    const addPost = () => setPosts(p => [...p, { id: crypto.randomUUID(), description: '', qty: 1, unit: 'stk', unitPriceWork: '', unitPriceMaterial: '' }])
    const removePost = (id) => setPosts(p => p.length > 1 ? p.filter(post => post.id !== id) : p)
    const updatePost = (id, key, value) => setPosts(p => p.map(post => post.id === id ? { ...post, [key]: value } : post))

    const calcPostSum = (p) => (parseFloat(p.qty) || 0) * ((parseFloat(p.unitPriceWork) || 0) + (parseFloat(p.unitPriceMaterial) || 0))
    const calcTotal = () => posts.reduce((acc, p) => acc + calcPostSum(p), 0)

    const handleSave = async (alsoSend = false) => {
      if (!form.title.trim()) return
      setSaving(true)
      try {
        const payload = {
          title: form.title.trim(),
          em_number: form.em_number,
          project_id: form.project_id || null,
          description: form.description,
          reason: form.reason,
          amount: calcTotal() || 0,
          hours: 0, // Legacy - erstattet av posts
          materials_cost: 0, // Legacy - erstattet av posts
          ue_cost: 0, // Legacy - erstattet av posts
          posts, // Nye strukturerte poster
          time_consequence: form.time_consequence,
          status: form.status,
          customer_email: form.customer_email,
          notes: form.notes,
          images,
          vedlegg,
          updated_at: new Date().toISOString(),
        }
        let savedEm = null
        if (isEdit) {
          const { data, error } = await supabase.from('endringsmeldinger').update(payload).eq('id', initial.id).select().single()
          if (error) throw error
          savedEm = data
          // Log activity
          const log = [...(initial.activity_log || []), { action: 'Endret', by: user?.email, at: new Date().toISOString() }]
          await supabase.from('endringsmeldinger').update({ activity_log: log }).eq('id', initial.id)
        } else {
          const { data, error } = await supabase.from('endringsmeldinger').insert({
            ...payload,
            created_by: user?.id,
            activity_log: [{ action: 'Opprettet', by: user?.email, at: new Date().toISOString() }],
          }).select().single()
          if (error) throw error
          savedEm = data

          // Varsle interne mottakere (kun ved opprettelse)
          for (const r of internalRecipients) {
            if (r.user_id === user?.id) continue // Ikke varsle seg selv
            await supabase.from('notifications').insert({
              user_id: r.user_id,
              title: `📝 Endringsmelding: ${payload.title}`,
              message: `${payload.em_number} · ${Math.round(payload.amount || 0).toLocaleString('nb-NO')} kr eks. mva${payload.time_consequence ? ' · ⏱️ ' + payload.time_consequence : ''}`,
              type: 'info',
              link_page: 'endringsmelding',
            })
          }
        }
        // Hvis "Opprett og send" ble valgt, åpne send-dialog
        if (alsoSend && savedEm) {
          onSaveAndSend(savedEm)
        } else {
          onSaved()
        }
      } catch(e) { await appAlert({ message: 'Kunne ikke lagre', subMessage: e.message, kind: 'error' }) }
      finally { setSaving(false) }
    }

    const handleImageUpload = async (e) => {
      const file = e.target.files?.[0]; if (!file) return
      try {
        const path = `endringsmeldinger/${Date.now()}_${file.name}`
        const { error } = await supabase.storage.from('plattform-files').upload(path, file)
        if (error) throw error
        const { data } = supabase.storage.from('plattform-files').getPublicUrl(path)
        setImages(prev => [...prev, { name: file.name, url: data.publicUrl }])
      } catch(err) { console.error(err) }
      e.target.value = ''
    }

    const handleVedleggUpload = async (e) => {
      const file = e.target.files?.[0]; if (!file) return
      try {
        const path = `endringsmeldinger/${Date.now()}_${file.name}`
        const { error } = await supabase.storage.from('plattform-files').upload(path, file)
        if (error) throw error
        const { data } = supabase.storage.from('plattform-files').getPublicUrl(path)
        setVedlegg(prev => [...prev, { name: file.name, url: data.publicUrl }])
      } catch(err) { console.error(err) }
      e.target.value = ''
    }

    const lbl = (t) => <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'5px' }}>{t}</label>

    return (
      <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
        <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.4)' }} onClick={onClose} />
        <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'900px', maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)' }}>
          <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', flexShrink:0, display:'flex', alignItems:'center', justifyContent:'space-between' }}>
            <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700' }}>🔄 {isEdit ? 'Rediger' : 'Ny'} endringsmelding</h2>
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
          </div>
          <form onSubmit={handleSave} style={{ overflowY:'auto', flex:1, padding:'20px 24px', display:'flex', flexDirection:'column', gap:'14px' }}>
            <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
              <div style={{ gridColumn:'1/-1' }}>{lbl('Tittel *')}<input value={form.title} onChange={e=>set('title',e.target.value)} placeholder="F.eks. Tilleggsarbeid elektrisk i kjøkken" style={inp} required /></div>
              <div>{lbl('EM-nummer')}<input value={form.em_number} onChange={e=>set('em_number',e.target.value)} style={inp} /></div>
              <div>{lbl('Prosjekt')}<SearchableProjectSelect value={form.project_id} onChange={v => {
                set('project_id', v)
                // Auto-fyll kundeinfo fra prosjektet
                const proj = projects.find(p => p.id === v)
                if (proj?.customer_email && !form.customer_email) {
                  set('customer_email', proj.customer_email)
                }
              }} projects={projects} style={{ ...inp, background:'white' }} placeholder="Velg prosjekt" /></div>
            </div>

            <div>{lbl('Årsak til endring')}<select value={form.reason} onChange={e=>set('reason',e.target.value)} style={{ ...inp, background:'white' }}>
              <option value="">Velg årsak</option>
              <option value="Bestilling fra byggherre">Bestilling fra byggherre</option>
              <option value="Prosjekteringsendring">Prosjekteringsendring</option>
              <option value="Uforutsette forhold">Uforutsette forhold</option>
              <option value="Forskriftskrav">Forskriftskrav</option>
              <option value="Feil i tegninger">Feil i tegninger</option>
              <option value="Annet">Annet</option>
            </select></div>

            <div>{lbl('Beskrivelse av endringen')}<textarea value={form.description} onChange={e=>set('description',e.target.value)} rows={3} placeholder="Detaljert beskrivelse av hva som er endret fra opprinnelig kontrakt..." style={{ ...inp, resize:'vertical', fontFamily:'system-ui,sans-serif' }} /></div>

            <div style={{ background:'#f8fafc', borderRadius:'12px', padding:'14px' }}>
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'10px', flexWrap:'wrap', gap:'8px' }}>
                <div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a' }}>💰 Poster / kostnadskonsekvens</div>
                <div style={{ fontSize:'12px', color:'#64748b' }}>Total: <strong style={{ color:'#059669' }}>{Math.round(calcTotal()).toLocaleString('nb-NO')} kr eks. mva</strong></div>
              </div>

              {/* Desktop: tabell — Mobil: kort */}
              {typeof window !== 'undefined' && window.innerWidth >= 768 ? (
                <table style={{ width:'100%', borderCollapse:'collapse' }}>
                  <thead>
                    <tr>
                      {['Beskrivelse', 'Mengde', 'Enhet', 'Arbeid kr/enh', 'Material kr/enh', 'Sum', ''].map((h, i) => (
                        <th key={i} style={{ padding:'6px 8px', textAlign: i >= 3 && i <= 5 ? 'right' : 'left', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase', borderBottom:'1px solid #e2e8f0' }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {posts.map(p => {
                      const sum = calcPostSum(p)
                      return (
                        <tr key={p.id}>
                          <td style={{ padding:'6px 4px' }}>
                            <input value={p.description} onChange={e => updatePost(p.id, 'description', e.target.value)} placeholder="Beskriv post" style={{ ...inp, width:'100%', minWidth:'120px' }} />
                          </td>
                          <td style={{ padding:'6px 4px' }}>
                            <input type="number" value={p.qty} onChange={e => updatePost(p.id, 'qty', e.target.value)} style={{ ...inp, width:'70px', textAlign:'right' }} />
                          </td>
                          <td style={{ padding:'6px 4px' }}>
                            <input value={p.unit} onChange={e => updatePost(p.id, 'unit', e.target.value)} placeholder="stk" style={{ ...inp, width:'60px' }} />
                          </td>
                          <td style={{ padding:'6px 4px' }}>
                            <input type="number" value={p.unitPriceWork} onChange={e => updatePost(p.id, 'unitPriceWork', e.target.value)} placeholder="0" style={{ ...inp, width:'90px', textAlign:'right' }} />
                          </td>
                          <td style={{ padding:'6px 4px' }}>
                            <input type="number" value={p.unitPriceMaterial} onChange={e => updatePost(p.id, 'unitPriceMaterial', e.target.value)} placeholder="0" style={{ ...inp, width:'90px', textAlign:'right' }} />
                          </td>
                          <td style={{ padding:'6px 8px', textAlign:'right', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>
                            {Math.round(sum).toLocaleString('nb-NO')} kr
                          </td>
                          <td style={{ padding:'6px 4px' }}>
                            {posts.length > 1 && (
                              <button type="button" onClick={() => removePost(p.id)}
                                style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'18px', padding:'0 4px' }}>×</button>
                            )}
                          </td>
                        </tr>
                      )
                    })}
                  </tbody>
                </table>
              ) : (
                <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
                  {posts.map((p, idx) => {
                    const sum = calcPostSum(p)
                    return (
                      <div key={p.id} style={{ background:'white', borderRadius:'10px', padding:'10px', border:'1px solid #e2e8f0' }}>
                        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'8px' }}>
                          <span style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8' }}>POST {idx + 1}</span>
                          {posts.length > 1 && (
                            <button type="button" onClick={() => removePost(p.id)}
                              style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'6px', padding:'4px 10px', fontSize:'12px', fontWeight:'600', cursor:'pointer' }}>× Fjern</button>
                          )}
                        </div>

                        <div style={{ marginBottom:'8px' }}>
                          <label style={{ display:'block', fontSize:'11px', color:'#64748b', marginBottom:'3px', fontWeight:'600' }}>Beskrivelse</label>
                          <input value={p.description} onChange={e => updatePost(p.id, 'description', e.target.value)} placeholder="F.eks. Ekstra kjøkken" style={{ ...inp, width:'100%', fontSize:'14px' }} />
                        </div>

                        <div style={{ display:'grid', gridTemplateColumns:'2fr 1fr', gap:'8px', marginBottom:'8px' }}>
                          <div>
                            <label style={{ display:'block', fontSize:'11px', color:'#64748b', marginBottom:'3px', fontWeight:'600' }}>Mengde</label>
                            <input type="number" inputMode="decimal" value={p.qty} onChange={e => updatePost(p.id, 'qty', e.target.value)} style={{ ...inp, width:'100%', textAlign:'right', fontSize:'15px' }} />
                          </div>
                          <div>
                            <label style={{ display:'block', fontSize:'11px', color:'#64748b', marginBottom:'3px', fontWeight:'600' }}>Enhet</label>
                            <input value={p.unit} onChange={e => updatePost(p.id, 'unit', e.target.value)} placeholder="stk" style={{ ...inp, width:'100%', fontSize:'14px' }} />
                          </div>
                        </div>

                        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'8px', marginBottom:'10px' }}>
                          <div>
                            <label style={{ display:'block', fontSize:'11px', color:'#64748b', marginBottom:'3px', fontWeight:'600' }}>Arbeid kr/enh</label>
                            <input type="number" inputMode="decimal" value={p.unitPriceWork} onChange={e => updatePost(p.id, 'unitPriceWork', e.target.value)} placeholder="0" style={{ ...inp, width:'100%', textAlign:'right', fontSize:'15px' }} />
                          </div>
                          <div>
                            <label style={{ display:'block', fontSize:'11px', color:'#64748b', marginBottom:'3px', fontWeight:'600' }}>Material kr/enh</label>
                            <input type="number" inputMode="decimal" value={p.unitPriceMaterial} onChange={e => updatePost(p.id, 'unitPriceMaterial', e.target.value)} placeholder="0" style={{ ...inp, width:'100%', textAlign:'right', fontSize:'15px' }} />
                          </div>
                        </div>

                        <div style={{ background:'#f0fdf4', borderRadius:'8px', padding:'8px 12px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                          <span style={{ fontSize:'12px', color:'#64748b', fontWeight:'600' }}>Sum denne posten:</span>
                          <span style={{ fontSize:'16px', fontWeight:'800', color:'#059669' }}>{Math.round(sum).toLocaleString('nb-NO')} kr</span>
                        </div>
                      </div>
                    )
                  })}
                </div>
              )}

              <div style={{ display:'flex', justifyContent:'center', alignItems:'center', marginTop:'12px' }}>
                <button type="button" onClick={addPost}
                  style={{ background:'#f0fdf4', color:'#059669', border:'1px dashed #86efac', borderRadius:'10px', padding:'10px 16px', fontSize:'13px', fontWeight:'600', cursor:'pointer', width:'100%' }}>+ Legg til post</button>
              </div>
            </div>

            <div>{lbl('Tidskonsekvens')}
              <div style={{ display:'flex', gap:'8px', alignItems:'stretch' }}>
                <input type="number" min="0" step="1"
                  value={form.time_consequence_value || ''}
                  onChange={e => {
                    const val = e.target.value
                    const unit = form.time_consequence_unit || 'dager'
                    set('time_consequence_value', val)
                    set('time_consequence', val ? `${val} ${unit}` : '')
                  }}
                  placeholder="0"
                  style={{ ...inp, flex: '0 0 120px' }} />
                <select
                  value={form.time_consequence_unit || 'dager'}
                  onChange={e => {
                    const unit = e.target.value
                    const val = form.time_consequence_value || ''
                    set('time_consequence_unit', unit)
                    set('time_consequence', val ? `${val} ${unit}` : '')
                  }}
                  style={{ ...inp, flex: 1, background:'white' }}>
                  <option value="dager">dager</option>
                  <option value="uker">uker</option>
                  <option value="måneder">måneder</option>
                </select>
              </div>
              <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'4px' }}>Eksempel: 3 dager, 2 uker, 1 måned</div>
            </div>

            {/* Bilder */}
            <div>
              {lbl('📸 Bildedokumentasjon')}
              <div style={{ display:'flex', gap:'8px', flexWrap:'wrap', marginBottom:'6px' }}>
                {images.map((img, i) => (
                  <div key={i} style={{ position:'relative', width:'80px', height:'80px', borderRadius:'8px', overflow:'hidden', border:'1px solid #e2e8f0' }}>
                    <img src={img.url} alt={img.name} style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                    <button onClick={() => setImages(prev => prev.filter((_, j) => j !== i))} style={{ position:'absolute', top:'2px', right:'2px', background:'rgba(0,0,0,0.5)', color:'white', border:'none', borderRadius:'50%', width:'18px', height:'18px', cursor:'pointer', fontSize:'10px', lineHeight:1 }}>×</button>
                  </div>
                ))}
                <label style={{ width:'80px', height:'80px', borderRadius:'8px', border:'2px dashed #e2e8f0', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', color:'#94a3b8', fontSize:'24px' }}>
                  +<input type="file" accept="image/*" capture="environment" style={{ display:'none' }} onChange={handleImageUpload} />
                </label>
              </div>
            </div>

            {/* Vedlegg */}
            <div>
              {lbl('📎 Vedlegg')}
              <div style={{ display:'flex', gap:'6px', flexWrap:'wrap', marginBottom:'6px' }}>
                {vedlegg.map((v, i) => (
                  <span key={i} style={{ background:'#f1f5f9', padding:'4px 10px', borderRadius:'6px', fontSize:'12px', display:'flex', alignItems:'center', gap:'4px' }}>
                    📎 {v.name} <button onClick={() => setVedlegg(prev => prev.filter((_, j) => j !== i))} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'11px' }}>×</button>
                  </span>
                ))}
              </div>
              <label style={{ display:'inline-block', background:'#f8fafc', border:'1px dashed #e2e8f0', borderRadius:'8px', padding:'6px 14px', fontSize:'12px', cursor:'pointer', color:'#64748b' }}>
                + Legg til vedlegg<input type="file" style={{ display:'none' }} onChange={handleVedleggUpload} />
              </label>
            </div>

            <div>{lbl('Send til kunde (e-post)')}
              <CustomerSelect
                value={form.customer_email}
                onChange={v => set('customer_email', v)}
                onSelect={c => {
                  if (c.email) set('customer_email', c.email)
                }}
                placeholder="Søk kunde eller skriv inn e-post..."
              />
              <p style={{ margin:'4px 0 0', fontSize:'11px', color:'#94a3b8' }}>
                Autofylles fra prosjektet, eller søk etter eksisterende kunde. Kan også skrives inn manuelt.
              </p>
            </div>

            <div>{lbl('🔔 Varsle internt (kollegaer får varsel i bjellen)')}
              <div style={{ background:'#f8fafc', border:'1px solid #e2e8f0', borderRadius:'10px', padding:'12px' }}>
                {internalRecipients.length > 0 && (
                  <div style={{ display:'flex', flexWrap:'wrap', gap:'6px', marginBottom:'10px' }}>
                    {internalRecipients.map(r => (
                      <span key={r.user_id} style={{ background:'#dcfce7', color:'#065f46', padding:'5px 10px', borderRadius:'6px', fontSize:'12px', fontWeight:'600', display:'inline-flex', alignItems:'center', gap:'6px' }}>
                        👤 {r.name}
                        <button type="button" onClick={() => setInternalRecipients(prev => prev.filter(x => x.user_id !== r.user_id))}
                          style={{ background:'none', border:'none', cursor:'pointer', color:'#065f46', padding:0, fontSize:'14px', lineHeight:1 }}>×</button>
                      </span>
                    ))}
                  </div>
                )}
                <select
                  value=""
                  onChange={e => {
                    const selectedId = e.target.value
                    if (!selectedId) return
                    const emp = employees.find(emp => emp.user_id === selectedId)
                    if (!emp) return
                    if (internalRecipients.some(r => r.user_id === emp.user_id)) return // Allerede valgt
                    setInternalRecipients(prev => [...prev, {
                      user_id: emp.user_id,
                      name: `${emp.first_name || ''} ${emp.last_name || ''}`.trim() || emp.email,
                      email: emp.email,
                    }])
                    e.target.value = ''
                  }}
                  style={{ ...inp, background:'white', fontSize:'13px' }}>
                  <option value="">+ Velg kollega å varsle...</option>
                  {employees
                    .filter(emp => !internalRecipients.some(r => r.user_id === emp.user_id))
                    .map(emp => (
                      <option key={emp.user_id} value={emp.user_id}>
                        {`${emp.first_name || ''} ${emp.last_name || ''}`.trim() || emp.email}
                      </option>
                    ))}
                </select>
                <p style={{ margin:'6px 0 0', fontSize:'11px', color:'#94a3b8' }}>
                  Kun ansatte med brukerkonto vises. Valgte kollegaer får varsel i bjellen når endringsmeldingen lagres.
                </p>
              </div>
            </div>
            <div>{lbl('Interne notater')}<textarea value={form.notes} onChange={e=>set('notes',e.target.value)} rows={2} placeholder="Interne merknader (vises ikke for kunde)" style={{ ...inp, resize:'none', fontFamily:'system-ui,sans-serif' }} /></div>
          </form>

          <div style={{ padding:'16px 24px', borderTop:'1px solid #f1f5f9', display:'flex', gap:'8px', justifyContent:'flex-end', flexShrink:0, flexWrap:'wrap' }}>
            <button onClick={onClose} disabled={saving} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor: saving?'not-allowed':'pointer', fontSize:'14px' }}>Avbryt</button>
            <button onClick={() => handleSave(false)} disabled={saving}
              style={{ padding:'10px 20px', background: saving?'#86efac':'white', color: saving?'white':'#059669', border:'1px solid #059669', borderRadius:'10px', fontSize:'14px', fontWeight:'600', cursor: saving?'not-allowed':'pointer' }}>
              {saving ? 'Lagrer...' : isEdit ? '💾 Oppdater' : '💾 Opprett som utkast'}
            </button>
            {!isEdit && form.customer_email && (
              <button onClick={() => handleSave(true)} disabled={saving}
                style={{ padding:'10px 20px', background: saving?'#86efac':'#059669', color:'white', border:'none', borderRadius:'10px', fontSize:'14px', fontWeight:'700', cursor: saving?'not-allowed':'pointer' }}>
                {saving ? 'Lagrer...' : '📧 Opprett og send'}
              </button>
            )}
          </div>
        </div>
      </div>
    )
  }

  // ── Send til kunde ─────────────────────────────────────────────────────────
  const sendToCustomer = async (em, reminderDays = null) => {
    if (!em.customer_email) return appAlert({ message: 'Legg til kundens e-post først', kind: 'warn' })
    try {
      const proj = projects.find(p => p.id === em.project_id)

      // Generate view token if not exists
      let viewToken = em.view_token
      if (!viewToken) {
        viewToken = crypto.randomUUID()
        await supabase.from('endringsmeldinger').update({ view_token: viewToken }).eq('id', em.id)
      }

      const viewUrl = `${window.location.origin}/em-view?token=${viewToken}`
      const imgHtml = (em.images||[]).length > 0 ? '<div style="margin:16px 0">' + em.images.map(img => `<img src="${img.url}" style="max-width:280px;border-radius:8px;margin:4px" />`).join('') + '</div>' : ''
      const vedleggHtml = (em.vedlegg||[]).length > 0 ? '<div style="margin:12px 0"><strong>Vedlegg:</strong><br>' + em.vedlegg.map(v => `<a href="${v.url}" style="color:#2563eb">${v.name}</a>`).join('<br>') + '</div>' : ''

      const html = '<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">' +
        '<h1 style="color:#0f172a;font-size:20px;margin:0 0 4px">Endringsmelding</h1>' +
        '<p style="color:#94a3b8;font-size:13px;margin:0 0 20px">' + em.em_number + '</p>' +
        '<div style="background:#f8fafc;border-radius:12px;padding:16px;margin-bottom:16px">' +
          '<div style="font-size:12px;color:#64748b;margin-bottom:2px">PROSJEKT</div>' +
          '<div style="font-weight:700">' + (proj?.name || '—') + '</div>' +
        '</div>' +
        '<div style="background:#fffbeb;border-radius:12px;padding:16px;margin-bottom:16px;border:1px solid #fde68a">' +
          '<div style="font-weight:700;margin-bottom:8px">' + em.title + '</div>' +
          (em.reason ? '<div style="font-size:13px;color:#92400e;margin-bottom:8px">Årsak: ' + em.reason + '</div>' : '') +
          '<div style="font-size:14px;color:#374151">' + (em.description || '').replace(/\n/g, '<br>') + '</div>' +
          imgHtml +
        '</div>' +
        (() => {
          const validPosts = Array.isArray(em.posts) ? em.posts.filter(p => p.description || parseFloat(p.qty) > 0) : []
          if (validPosts.length === 0) return ''
          const rows = validPosts.map(p => {
            const sum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
            return '<tr style="border-bottom:1px solid #f1f5f9">' +
              '<td style="padding:8px;font-size:13px">' + (p.description || '—').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</td>' +
              '<td style="padding:8px;font-size:13px;text-align:right">' + (p.qty || 0) + ' ' + (p.unit || 'stk') + '</td>' +
              '<td style="padding:8px;font-size:13px;text-align:right">' + Math.round(parseFloat(p.unitPriceWork)||0).toLocaleString('nb-NO') + '</td>' +
              '<td style="padding:8px;font-size:13px;text-align:right">' + Math.round(parseFloat(p.unitPriceMaterial)||0).toLocaleString('nb-NO') + '</td>' +
              '<td style="padding:8px;font-size:13px;font-weight:700;text-align:right">' + Math.round(sum).toLocaleString('nb-NO') + ' kr</td>' +
            '</tr>'
          }).join('')
          return '<div style="background:white;border:1px solid #e2e8f0;border-radius:12px;padding:16px;margin-bottom:16px;overflow-x:auto">' +
            '<div style="font-size:13px;font-weight:700;color:#0f172a;margin-bottom:10px">💰 Poster</div>' +
            '<table style="width:100%;border-collapse:collapse">' +
              '<thead><tr style="border-bottom:2px solid #e2e8f0">' +
                '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:left">Beskrivelse</th>' +
                '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Mengde</th>' +
                '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Arb./enh</th>' +
                '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Mat./enh</th>' +
                '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Sum</th>' +
              '</tr></thead>' +
              '<tbody>' + rows + '</tbody>' +
            '</table>' +
          '</div>'
        })() +
        '<div style="background:#f0fdf4;border-radius:12px;padding:16px;margin-bottom:16px;border:1px solid #bbf7d0">' +
          '<div style="font-size:24px;font-weight:800;color:#059669;text-align:center">' + Math.round(em.amount || 0).toLocaleString('nb-NO') + ' kr</div>' +
          '<div style="font-size:12px;color:#64748b;text-align:center">Total eks. mva</div>' +
          (em.time_consequence ? '<div style="font-size:13px;color:#64748b;text-align:center;margin-top:4px">⏱️ ' + em.time_consequence + '</div>' : '') +
        '</div>' + vedleggHtml +
        '<div style="margin:32px 0 16px">' +
          '<p style="color:#0f172a;font-size:16px;font-weight:700;text-align:center;margin:0 0 20px">Gi ditt svar</p>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:0 auto">' +
            '<tr>' +
              '<td style="padding:0 10px">' +
                '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#059669;border-radius:12px">' +
                  '<tr><td style="padding:18px 36px;text-align:center">' +
                    '<a href="' + viewUrl + '&action=godkjent" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✓&nbsp;&nbsp;Godkjenn</a>' +
                  '</td></tr>' +
                '</table>' +
              '</td>' +
              '<td style="padding:0 10px">' +
                '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#dc2626;border-radius:12px">' +
                  '<tr><td style="padding:18px 36px;text-align:center">' +
                    '<a href="' + viewUrl + '&action=avvist" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✗&nbsp;&nbsp;Avvis</a>' +
                  '</td></tr>' +
                '</table>' +
              '</td>' +
            '</tr>' +
          '</table>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:24px auto 0">' +
            '<tr><td style="border:1px solid #cbd5e1;border-radius:10px;padding:10px 20px;text-align:center">' +
              '<a href="' + viewUrl + '" style="color:#475569;text-decoration:none;font-size:13px;font-weight:600">📄 Se full endringsmelding først</a>' +
            '</td></tr>' +
          '</table>' +
        '</div>' +
        '<p style="color:#94a3b8;font-size:12px">Endringsmelding sendt via En Plattform</p></div>'

      // Generer PDF som base64 for vedlegg
      let pdfBase64 = null
      let pdfFilename = 'Endringsmelding.pdf'
      try {
        const pdfResult = await exportSingleEmPDF(em, 'base64')
        if (pdfResult) {
          pdfBase64 = pdfResult.base64
          pdfFilename = pdfResult.filename
        }
      } catch (pdfErr) {
        console.error('PDF-generering feilet:', pdfErr)
        // Fortsett uten vedlegg om PDF feiler
      }

      const payload = {
        to: em.customer_email,
        subject: `Endringsmelding ${em.em_number} – ${em.title}`,
        html,
      }
      if (pdfBase64) {
        payload.attachments = [{ filename: pdfFilename, content: pdfBase64, type: 'application/pdf' }]
      }

      const resp = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY, 'Authorization': `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}` },
        body: JSON.stringify(payload)
      })
      if (!resp.ok) throw new Error(`E-postsending feilet (${resp.status})`)

      const log = [...(em.activity_log || []), { action: 'Sendt til kunde', by: user?.email, at: new Date().toISOString(), to: em.customer_email }]

      // Lag snapshot av nåværende tilstand for versjonshistorikk
      const newVersion = buildEmSnapshot(em, 'send')
      const versions = [...(Array.isArray(em.versions) ? em.versions : []), newVersion]

      // Beregn purringsfrist hvis bruker valgte antall dager
      const updates = { status: 'Sendt', activity_log: log, view_token: viewToken, versions, updated_at: new Date().toISOString() }
      if (reminderDays && reminderDays > 0) {
        const dueDate = new Date()
        dueDate.setDate(dueDate.getDate() + parseInt(reminderDays))
        updates.reminder_days = parseInt(reminderDays)
        updates.reminder_due_date = dueDate.toISOString()
        updates.last_reminder_sent_at = null // Nullstill hvis det er en re-send
      }

      await supabase.from('endringsmeldinger').update(updates).eq('id', em.id)
      const reminderText = reminderDays ? ` · Purring settes til ${reminderDays} dager` : ''
      await appAlert({ message: 'Endringsmelding sendt', subMessage: `Sendt til ${em.customer_email}${reminderText}`, kind: 'success' })
      load()
    } catch(e) { await appAlert({ message: 'Kunne ikke sende endringsmelding', subMessage: e.message, kind: 'error' }) }
  }

  // ── Send purring (forenklet påminnelse) ────────────────────────────────────
  const sendReminder = async (em) => {
    if (!em.customer_email) return appAlert({ message: 'Legg til kundens e-post først', kind: 'warn' })
    try {
      const proj = projects.find(p => p.id === em.project_id)
      const viewToken = em.view_token || crypto.randomUUID()
      const viewUrl = `${window.location.origin}/em-view?token=${viewToken}`

      const html = '<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">' +
        '<h1 style="color:#d97706;font-size:20px;margin:0 0 4px">⏰ Påminnelse</h1>' +
        '<p style="color:#64748b;font-size:14px;margin:0 0 20px">Vi venter fortsatt på ditt svar</p>' +
        '<div style="background:#fffbeb;border:1px solid #fde68a;border-radius:12px;padding:16px;margin-bottom:20px">' +
          '<div style="font-size:12px;color:#92400e;font-weight:700;margin-bottom:6px">ENDRINGSMELDING ' + em.em_number + '</div>' +
          '<div style="font-weight:700;font-size:15px;color:#0f172a;margin-bottom:4px">' + em.title + '</div>' +
          (proj ? '<div style="font-size:13px;color:#64748b">Prosjekt: ' + proj.name + '</div>' : '') +
        '</div>' +
        '<div style="margin:32px 0 16px">' +
          '<p style="color:#0f172a;font-size:16px;font-weight:700;text-align:center;margin:0 0 20px">Gi ditt svar nå</p>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:0 auto">' +
            '<tr>' +
              '<td style="padding:0 10px">' +
                '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#059669;border-radius:12px">' +
                  '<tr><td style="padding:18px 36px;text-align:center">' +
                    '<a href="' + viewUrl + '&action=godkjent" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✓&nbsp;&nbsp;Godkjenn</a>' +
                  '</td></tr>' +
                '</table>' +
              '</td>' +
              '<td style="padding:0 10px">' +
                '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#dc2626;border-radius:12px">' +
                  '<tr><td style="padding:18px 36px;text-align:center">' +
                    '<a href="' + viewUrl + '&action=avvist" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✗&nbsp;&nbsp;Avvis</a>' +
                  '</td></tr>' +
                '</table>' +
              '</td>' +
            '</tr>' +
          '</table>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:24px auto 0">' +
            '<tr><td style="border:1px solid #cbd5e1;border-radius:10px;padding:10px 20px;text-align:center">' +
              '<a href="' + viewUrl + '" style="color:#475569;text-decoration:none;font-size:13px;font-weight:600">📄 Se full endringsmelding først</a>' +
            '</td></tr>' +
          '</table>' +
        '</div>' +
        '<p style="color:#94a3b8;font-size:12px">Påminnelse sendt via En Plattform</p></div>'

      // Generer PDF som base64 for vedlegg
      let pdfBase64 = null
      let pdfFilename = 'Endringsmelding.pdf'
      try {
        const pdfResult = await exportSingleEmPDF(em, 'base64')
        if (pdfResult) { pdfBase64 = pdfResult.base64; pdfFilename = pdfResult.filename }
      } catch (pdfErr) { console.error('PDF-generering feilet:', pdfErr) }

      const payload = {
        to: em.customer_email,
        subject: `Påminnelse: ${em.em_number} venter på svar`,
        html,
      }
      if (pdfBase64) {
        payload.attachments = [{ filename: pdfFilename, content: pdfBase64, type: 'application/pdf' }]
      }

      const resp = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY, 'Authorization': `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}` },
        body: JSON.stringify(payload)
      })
      if (!resp.ok) throw new Error(`E-postsending feilet (${resp.status})`)

      // Oppdater last_reminder_sent_at og legg til i aktivitetslogg
      const log = [...(em.activity_log || []), { action: 'Purring sendt', by: user?.email, at: new Date().toISOString(), to: em.customer_email }]
      await supabase.from('endringsmeldinger').update({
        last_reminder_sent_at: new Date().toISOString(),
        activity_log: log,
        updated_at: new Date().toISOString(),
      }).eq('id', em.id)

      await appAlert({ message: 'Purring sendt', subMessage: `Påminnelse sendt til ${em.customer_email}`, kind: 'success' })
      load()
    } catch(e) { await appAlert({ message: 'Kunne ikke sende purring', subMessage: e.message, kind: 'error' }) }
  }

  // ── Send på nytt / Revisjon / Kopi ─────────────────────────────────────────
  const resendToCustomer = async (em, sendType, reminderDays = null) => {
    // sendType: 'resend' | 'revision' | 'copy'
    if (!em.customer_email) return appAlert({ message: 'Kundens e-post mangler', kind: 'warn' })
    try {
      const proj = projects.find(p => p.id === em.project_id)
      const viewToken = em.view_token || crypto.randomUUID()
      const viewUrl = `${window.location.origin}/em-view?token=${viewToken}`
      if (!em.view_token) await supabase.from('endringsmeldinger').update({ view_token: viewToken }).eq('id', em.id)

      // Definer banner-tekst og emne-prefiks basert på type
      const typeConfig = {
        resend: {
          bannerBg: '#fffbeb', bannerBorder: '#fde68a', bannerColor: '#92400e',
          bannerTitle: '🔄 Sendt på nytt',
          bannerText: 'Denne endringsmeldingen er sendt på nytt. Innholdet er uendret fra forrige utsendelse.',
          subjectPrefix: '[Sendt på nytt] ',
          logAction: 'Sendt på nytt',
          successMsg: 'Endringsmelding sendt på nytt',
        },
        revision: {
          bannerBg: '#eff6ff', bannerBorder: '#bfdbfe', bannerColor: '#1e40af',
          bannerTitle: '📝 Revidert versjon',
          bannerText: 'Ny versjon sendt — vennligst se vedlagt oppdatert versjon. Tidligere svar kan ha blitt erstattet.',
          subjectPrefix: '[Revidert] ',
          logAction: 'Sendt revisjon',
          successMsg: 'Revidert endringsmelding sendt',
        },
        copy: {
          bannerBg: '#f0fdf4', bannerBorder: '#bbf7d0', bannerColor: '#065f46',
          bannerTitle: '📄 Kopi til arkivering',
          bannerText: `Dette er en kopi av endringsmeldingen til din arkivering. Status: ${em.status}.`,
          subjectPrefix: '[Kopi] ',
          logAction: 'Kopi sendt',
          successMsg: 'Kopi sendt',
        },
      }
      const cfg = typeConfig[sendType] || typeConfig.resend

      const imgHtml = (em.images||[]).length > 0 ? '<div style="margin:16px 0">' + em.images.map(img => `<img src="${img.url}" style="max-width:280px;border-radius:8px;margin:4px" />`).join('') + '</div>' : ''
      const vedleggHtml = (em.vedlegg||[]).length > 0 ? '<div style="margin:12px 0"><strong>Vedlegg:</strong><br>' + em.vedlegg.map(v => `<a href="${v.url}" style="color:#2563eb">${v.name}</a>`).join('<br>') + '</div>' : ''

      // Bygg poster-tabell (samme som vanlig send)
      const postsHtml = (() => {
        const validPosts = Array.isArray(em.posts) ? em.posts.filter(p => p.description || parseFloat(p.qty) > 0) : []
        if (validPosts.length === 0) return ''
        const rows = validPosts.map(p => {
          const sum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
          return '<tr style="border-bottom:1px solid #f1f5f9">' +
            '<td style="padding:8px;font-size:13px">' + (p.description || '—').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</td>' +
            '<td style="padding:8px;font-size:13px;text-align:right">' + (p.qty || 0) + ' ' + (p.unit || 'stk') + '</td>' +
            '<td style="padding:8px;font-size:13px;text-align:right">' + Math.round(parseFloat(p.unitPriceWork)||0).toLocaleString('nb-NO') + '</td>' +
            '<td style="padding:8px;font-size:13px;text-align:right">' + Math.round(parseFloat(p.unitPriceMaterial)||0).toLocaleString('nb-NO') + '</td>' +
            '<td style="padding:8px;font-size:13px;font-weight:700;text-align:right">' + Math.round(sum).toLocaleString('nb-NO') + ' kr</td>' +
          '</tr>'
        }).join('')
        return '<div style="background:white;border:1px solid #e2e8f0;border-radius:12px;padding:16px;margin-bottom:16px;overflow-x:auto">' +
          '<div style="font-size:13px;font-weight:700;color:#0f172a;margin-bottom:10px">💰 Poster</div>' +
          '<table style="width:100%;border-collapse:collapse">' +
            '<thead><tr style="border-bottom:2px solid #e2e8f0">' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:left">Beskrivelse</th>' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Mengde</th>' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Arb./enh</th>' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Mat./enh</th>' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Sum</th>' +
            '</tr></thead>' +
            '<tbody>' + rows + '</tbody>' +
          '</table>' +
        '</div>'
      })()

      // Godkjenn/Avvis-knapper vises kun hvis ikke 'copy'
      const ctaHtml = sendType === 'copy' ? '' :
        '<div style="margin:32px 0 16px">' +
          '<p style="color:#0f172a;font-size:16px;font-weight:700;text-align:center;margin:0 0 20px">Gi ditt svar</p>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:0 auto">' +
            '<tr>' +
              '<td style="padding:0 10px">' +
                '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#059669;border-radius:12px">' +
                  '<tr><td style="padding:18px 36px;text-align:center">' +
                    '<a href="' + viewUrl + '&action=godkjent" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✓&nbsp;&nbsp;Godkjenn</a>' +
                  '</td></tr>' +
                '</table>' +
              '</td>' +
              '<td style="padding:0 10px">' +
                '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#dc2626;border-radius:12px">' +
                  '<tr><td style="padding:18px 36px;text-align:center">' +
                    '<a href="' + viewUrl + '&action=avvist" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✗&nbsp;&nbsp;Avvis</a>' +
                  '</td></tr>' +
                '</table>' +
              '</td>' +
            '</tr>' +
          '</table>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:24px auto 0">' +
            '<tr><td style="border:1px solid #cbd5e1;border-radius:10px;padding:10px 20px;text-align:center">' +
              '<a href="' + viewUrl + '" style="color:#475569;text-decoration:none;font-size:13px;font-weight:600">📄 Se full endringsmelding først</a>' +
            '</td></tr>' +
          '</table>' +
        '</div>'

      const html = '<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">' +
        // Banner øverst som viser typen
        '<div style="background:' + cfg.bannerBg + ';border:1px solid ' + cfg.bannerBorder + ';border-radius:12px;padding:14px 16px;margin-bottom:20px">' +
          '<div style="font-size:14px;font-weight:700;color:' + cfg.bannerColor + ';margin-bottom:4px">' + cfg.bannerTitle + '</div>' +
          '<div style="font-size:13px;color:' + cfg.bannerColor + '">' + cfg.bannerText + '</div>' +
        '</div>' +
        '<h1 style="color:#0f172a;font-size:20px;margin:0 0 4px">Endringsmelding</h1>' +
        '<p style="color:#94a3b8;font-size:13px;margin:0 0 20px">' + em.em_number + '</p>' +
        '<div style="background:#f8fafc;border-radius:12px;padding:16px;margin-bottom:16px">' +
          '<div style="font-size:12px;color:#64748b;margin-bottom:2px">PROSJEKT</div>' +
          '<div style="font-weight:700">' + (proj?.name || '—') + '</div>' +
        '</div>' +
        '<div style="background:#fffbeb;border:1px solid #fde68a;border-radius:12px;padding:16px;margin-bottom:16px">' +
          '<div style="font-size:13px;font-weight:700;color:#0f172a;margin-bottom:8px">' + (em.title || '') + '</div>' +
          (em.reason ? '<div style="font-size:13px;color:#92400e;margin-bottom:8px">Årsak: ' + em.reason + '</div>' : '') +
          '<div style="font-size:14px;color:#374151">' + (em.description || '').replace(/\n/g, '<br>') + '</div>' +
          imgHtml +
        '</div>' +
        postsHtml +
        '<div style="background:#f0fdf4;border-radius:12px;padding:16px;margin-bottom:16px;border:1px solid #bbf7d0">' +
          '<div style="font-size:24px;font-weight:800;color:#059669;text-align:center">' + Math.round(em.amount || 0).toLocaleString('nb-NO') + ' kr</div>' +
          '<div style="font-size:12px;color:#64748b;text-align:center">Total eks. mva</div>' +
          (em.time_consequence ? '<div style="font-size:13px;color:#64748b;text-align:center;margin-top:4px">⏱️ ' + em.time_consequence + '</div>' : '') +
        '</div>' + vedleggHtml +
        ctaHtml +
        '<p style="color:#94a3b8;font-size:12px">Endringsmelding sendt via En Plattform</p></div>'

      // Generer PDF-vedlegg
      let pdfBase64 = null
      let pdfFilename = 'Endringsmelding.pdf'
      try {
        const pdfResult = await exportSingleEmPDF(em, 'base64')
        if (pdfResult) { pdfBase64 = pdfResult.base64; pdfFilename = pdfResult.filename }
      } catch (pdfErr) { console.error('PDF-generering feilet:', pdfErr) }

      const payload = {
        to: em.customer_email,
        subject: `${cfg.subjectPrefix}Endringsmelding ${em.em_number} – ${em.title}`,
        html,
      }
      if (pdfBase64) {
        payload.attachments = [{ filename: pdfFilename, content: pdfBase64, type: 'application/pdf' }]
      }

      const resp = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': import.meta.env.VITE_SUPABASE_ANON_KEY, 'Authorization': `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}` },
        body: JSON.stringify(payload)
      })
      if (!resp.ok) throw new Error(`E-postsending feilet (${resp.status})`)

      // Oppdater aktivitetslogg + evt. ny purringsfrist (ikke for 'copy')
      const log = [...(em.activity_log || []), { action: cfg.logAction, by: user?.email, at: new Date().toISOString(), to: em.customer_email }]

      // Lag snapshot for versjonshistorikk
      const newVersion = buildEmSnapshot(em, sendType)
      const versions = [...(Array.isArray(em.versions) ? em.versions : []), newVersion]

      const updates = { activity_log: log, versions, updated_at: new Date().toISOString() }

      if (sendType !== 'copy' && reminderDays && reminderDays > 0) {
        const dueDate = new Date()
        dueDate.setDate(dueDate.getDate() + parseInt(reminderDays))
        updates.reminder_days = parseInt(reminderDays)
        updates.reminder_due_date = dueDate.toISOString()
        updates.last_reminder_sent_at = null
      }

      await supabase.from('endringsmeldinger').update(updates).eq('id', em.id)

      const reminderText = sendType !== 'copy' && reminderDays ? ` · Ny purringsfrist: ${reminderDays} dager` : ''
      await appAlert({ message: cfg.successMsg, subMessage: `Sendt til ${em.customer_email}${reminderText}`, kind: 'success' })
      load()
    } catch(e) { await appAlert({ message: 'Kunne ikke sende', subMessage: e.message, kind: 'error' }) }
  }

  // Redirect til liste hvis viewEmId finnes men EM ikke eksisterer (etter lasting)
  useEffect(() => {
    if (viewEmId && !loading && !viewEm) {
      navList()
    }
  }, [viewEmId, loading, viewEm])

  // ── Detail View ────────────────────────────────────────────────────────────
  if (viewEmId) {
    // Vis loading mens endringer lastes
    if (loading) {
      return <div style={{ padding:'60px', textAlign:'center', color:'#94a3b8', fontFamily:'system-ui, sans-serif' }}>Laster endringsmelding...</div>
    }
    // EM ikke funnet → vis feilmelding (effect over vil redirecte)
    if (!viewEm) {
      return <div style={{ padding:'60px', textAlign:'center', color:'#dc2626', fontFamily:'system-ui, sans-serif' }}>Endringsmeldingen ble ikke funnet.</div>
    }
    const em = viewEm
    const st = EM_STATUS[em.status] || EM_STATUS['Utkast']
    const proj = projects.find(p => p.id === em.project_id)
    return (
      <div style={{ ...f, overflowX:'hidden', maxWidth:'100vw' }}>
        <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobEM ? '14px' : '20px 32px' }}>
          <button onClick={() => navList()} style={{ background:'none', border:'none', cursor:'pointer', fontSize:'13px', color:'#64748b', marginBottom:'10px' }}>← Tilbake til oversikt</button>
          <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap: isMobEM ? '8px' : '16px', flexWrap: isMobEM ? 'wrap' : 'nowrap' }}>
            <div style={{ minWidth:0, flex:1 }}>
              <div style={{ display:'flex', alignItems:'center', gap: isMobEM ? '6px' : '10px', marginBottom:'4px', flexWrap:'wrap' }}>
                <h1 style={{ margin:0, fontSize: isMobEM ? '16px' : '20px', fontWeight:'bold' }}>{em.title}</h1>
                <span style={{ background:st.bg, color:st.color, border:`1px solid ${st.border}`, padding:'2px 8px', borderRadius:'999px', fontSize:'11px', fontWeight:'700' }}>{st.emoji} {em.status}</span>
              </div>
              <p style={{ margin:0, color:'#94a3b8', fontSize: isMobEM ? '11px' : '13px' }}>{em.em_number} · {proj?.name || '—'} · {new Date(em.created_at).toLocaleDateString('nb-NO')}</p>
            </div>
            <div style={{ display:'flex', gap:'6px', flexShrink:0, flexWrap:'wrap' }}>
              {em.status === 'Utkast' && <button onClick={() => setSendDialogEm(em)} style={{ background:'#2563eb', color:'white', border:'none', borderRadius:'10px', padding: isMobEM ? '7px 10px' : '10px 18px', fontSize: isMobEM ? '11px' : '14px', fontWeight:'600', cursor:'pointer' }}>{isMobEM ? '📧 Send' : '📧 Send til kunde'}</button>}
              {em.status === 'Sendt' && (() => {
                const t = getEmSendType(em)
                if (t === 'revision') {
                  return <button onClick={() => setResendDialogEm({ em, type: 'revision' })} style={{ background:'#2563eb', color:'white', border:'none', borderRadius:'10px', padding: isMobEM ? '7px 10px' : '10px 18px', fontSize: isMobEM ? '11px' : '14px', fontWeight:'600', cursor:'pointer' }}>{isMobEM ? '📝 Revisjon' : '📝 Send revisjon'}</button>
                }
                return <button onClick={() => setResendDialogEm({ em, type: 'resend' })} style={{ background:'#f1f5f9', color:'#1e293b', border:'1px solid #cbd5e1', borderRadius:'10px', padding: isMobEM ? '7px 10px' : '10px 18px', fontSize: isMobEM ? '11px' : '14px', fontWeight:'600', cursor:'pointer' }}>{isMobEM ? '🔄 På nytt' : '🔄 Send på nytt'}</button>
              })()}
              {(em.status === 'Godkjent' || em.status === 'Avvist') && (
                <button onClick={() => setResendDialogEm({ em, type: 'copy' })} style={{ background:'#f0fdf4', color:'#065f46', border:'1px solid #bbf7d0', borderRadius:'10px', padding: isMobEM ? '7px 10px' : '10px 18px', fontSize: isMobEM ? '11px' : '14px', fontWeight:'600', cursor:'pointer' }}>{isMobEM ? '📄 Kopi' : '📄 Send kopi'}</button>
              )}
              <button onClick={() => navEdit(em.id)} style={{ background:'white', border:'1px solid #e2e8f0', borderRadius:'10px', padding: isMobEM ? '7px 10px' : '10px 18px', fontSize: isMobEM ? '12px' : '14px', cursor:'pointer' }}>✏️</button>
            </div>
          </div>
        </div>
        <div style={{ padding: isMobEM ? '12px' : '24px 32px', maxWidth:'800px' }}>
          {/* Versjoner-seksjon */}
          {Array.isArray(em.versions) && em.versions.length > 0 && (
            <div style={{ background:'white', border:'1px solid #e2e8f0', borderRadius:'12px', marginBottom:'16px', overflow:'hidden' }}>
              <button onClick={() => setShowVersionsPanel(!showVersionsPanel)}
                style={{ width:'100%', padding:'12px 16px', background:'none', border:'none', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'space-between', textAlign:'left' }}>
                <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
                  <span style={{ fontSize:'14px' }}>📚</span>
                  <span style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a' }}>Versjoner ({em.versions.length})</span>
                  <span style={{ fontSize:'11px', color:'#94a3b8' }}>Nåværende versjon er v{em.versions.length}</span>
                </div>
                <span style={{ fontSize:'12px', color:'#64748b' }}>{showVersionsPanel ? '▲ Skjul' : '▼ Vis'}</span>
              </button>
              {showVersionsPanel && (
                <div style={{ borderTop:'1px solid #f1f5f9', background:'#fafbfc' }}>
                  {em.versions.slice().reverse().map((v, idx) => {
                    const isCurrent = idx === 0 // Nyeste er først etter reverse
                    const typeLabel = { send: '📧 Første utsendelse', resend: '🔄 Sendt på nytt', revision: '📝 Revisjon', copy: '📄 Kopi' }[v.sent_type] || '📧 Sendt'
                    const typeColor = { send: '#2563eb', resend: '#64748b', revision: '#1e40af', copy: '#065f46' }[v.sent_type] || '#64748b'
                    return (
                      <div key={idx} style={{ padding:'12px 16px', borderBottom: idx < em.versions.length - 1 ? '1px solid #f1f5f9' : 'none', display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px', flexWrap:'wrap' }}>
                        <div style={{ flex:1, minWidth:'200px' }}>
                          <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'2px', flexWrap:'wrap' }}>
                            <span style={{ background: isCurrent ? '#dcfce7' : '#f1f5f9', color: isCurrent ? '#065f46' : '#475569', padding:'2px 8px', borderRadius:'6px', fontSize:'11px', fontWeight:'700' }}>v{v.version_number}{isCurrent ? ' (nåværende)' : ''}</span>
                            <span style={{ color: typeColor, fontSize:'12px', fontWeight:'600' }}>{typeLabel}</span>
                          </div>
                          <div style={{ fontSize:'12px', color:'#64748b' }}>
                            {new Date(v.sent_at).toLocaleString('nb-NO', { weekday:'short', day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit' })}
                            {v.sent_by && ` · ${v.sent_by}`}
                          </div>
                          {v.snapshot && (
                            <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>
                              {Math.round(v.snapshot.amount || 0).toLocaleString('nb-NO')} kr eks. mva
                              {v.snapshot.time_consequence ? ` · ⏱️ ${v.snapshot.time_consequence}` : ''}
                            </div>
                          )}
                        </div>
                        <button onClick={() => setViewingVersion({ em, version: v })}
                          style={{ background:'#eff6ff', color:'#2563eb', border:'1px solid #bfdbfe', borderRadius:'8px', padding:'6px 12px', cursor:'pointer', fontSize:'12px', fontWeight:'600', whiteSpace:'nowrap' }}>
                          👁️ Vis versjon
                        </button>
                      </div>
                    )
                  })}
                </div>
              )}
            </div>
          )}

          {em.reason && <div style={{ background:'#fffbeb', border:'1px solid #fde68a', borderRadius:'10px', padding:'12px 16px', marginBottom:'16px', fontSize:'13px', color:'#92400e' }}>🏷️ Årsak: <strong>{em.reason}</strong></div>}
          <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'20px', marginBottom:'16px' }}>
            <h3 style={{ margin:'0 0 8px', fontSize:'14px', fontWeight:'600' }}>Beskrivelse</h3>
            <p style={{ margin:0, fontSize:'14px', color:'#374151', lineHeight:1.7, whiteSpace:'pre-wrap' }}>{em.description || '—'}</p>
          </div>
          <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px', marginBottom:'16px' }}>
            <div style={{ background:'#f0fdf4', borderRadius:'14px', padding:'16px', textAlign:'center' }}>
              <div style={{ fontSize:'22px', fontWeight:'800', color:'#059669' }}>{Math.round(em.amount || 0).toLocaleString('nb-NO')} kr</div>
              <div style={{ fontSize:'12px', color:'#64748b' }}>Totalt beløp eks. mva</div>
            </div>
            {em.time_consequence && <div style={{ background:'#fffbeb', borderRadius:'14px', padding:'16px', textAlign:'center' }}>
              <div style={{ fontSize:'14px', fontWeight:'700', color:'#d97706' }}>{em.time_consequence}</div>
              <div style={{ fontSize:'12px', color:'#64748b' }}>Tidskonsekvens</div>
            </div>}
          </div>

          {/* Poster */}
          {Array.isArray(em.posts) && em.posts.length > 0 && em.posts.some(p => p.description || parseFloat(p.qty) > 0) && (
            <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'16px', marginBottom:'16px' }}>
              <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600' }}>💰 Poster</h3>
              {!isMobEM ? (
                <table style={{ width:'100%', borderCollapse:'collapse' }}>
                  <thead>
                    <tr style={{ borderBottom:'1px solid #e2e8f0' }}>
                      <th style={{ padding:'8px', textAlign:'left', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase' }}>Beskrivelse</th>
                      <th style={{ padding:'8px', textAlign:'right', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase' }}>Mengde</th>
                      <th style={{ padding:'8px', textAlign:'left', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase' }}>Enhet</th>
                      <th style={{ padding:'8px', textAlign:'right', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase' }}>Arbeid/enh</th>
                      <th style={{ padding:'8px', textAlign:'right', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase' }}>Mat./enh</th>
                      <th style={{ padding:'8px', textAlign:'right', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase' }}>Sum</th>
                    </tr>
                  </thead>
                  <tbody>
                    {em.posts.filter(p => p.description || parseFloat(p.qty) > 0).map(p => {
                      const sum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
                      return (
                        <tr key={p.id} style={{ borderBottom:'1px solid #f1f5f9' }}>
                          <td style={{ padding:'8px', fontSize:'13px', color:'#0f172a' }}>{p.description || '—'}</td>
                          <td style={{ padding:'8px', fontSize:'13px', textAlign:'right', color:'#475569' }}>{p.qty || 0}</td>
                          <td style={{ padding:'8px', fontSize:'13px', color:'#475569' }}>{p.unit || 'stk'}</td>
                          <td style={{ padding:'8px', fontSize:'13px', textAlign:'right', color:'#475569' }}>{Math.round(parseFloat(p.unitPriceWork)||0).toLocaleString('nb-NO')} kr</td>
                          <td style={{ padding:'8px', fontSize:'13px', textAlign:'right', color:'#475569' }}>{Math.round(parseFloat(p.unitPriceMaterial)||0).toLocaleString('nb-NO')} kr</td>
                          <td style={{ padding:'8px', fontSize:'13px', textAlign:'right', fontWeight:'700', color:'#0f172a' }}>{Math.round(sum).toLocaleString('nb-NO')} kr</td>
                        </tr>
                      )
                    })}
                  </tbody>
                  <tfoot>
                    <tr>
                      <td colSpan={5} style={{ padding:'10px 8px', fontSize:'13px', fontWeight:'700', color:'#0f172a', textAlign:'right', borderTop:'2px solid #e2e8f0' }}>Total eks. mva:</td>
                      <td style={{ padding:'10px 8px', fontSize:'15px', fontWeight:'800', color:'#059669', textAlign:'right', borderTop:'2px solid #e2e8f0' }}>{Math.round(em.amount || 0).toLocaleString('nb-NO')} kr</td>
                    </tr>
                  </tfoot>
                </table>
              ) : (
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {em.posts.filter(p => p.description || parseFloat(p.qty) > 0).map(p => {
                    const sum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
                    return (
                      <div key={p.id} style={{ background:'#fafbfc', borderRadius:'8px', padding:'10px', border:'1px solid #e2e8f0' }}>
                        <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a', marginBottom:'6px' }}>{p.description || '—'}</div>
                        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'4px 10px', fontSize:'12px', color:'#475569', marginBottom:'8px' }}>
                          <div><span style={{ color:'#94a3b8' }}>Mengde: </span>{p.qty || 0} {p.unit || 'stk'}</div>
                          <div style={{ textAlign:'right' }}><span style={{ color:'#94a3b8' }}>Arbeid: </span>{Math.round(parseFloat(p.unitPriceWork)||0).toLocaleString('nb-NO')} kr/enh</div>
                          <div style={{ gridColumn:'1/-1', textAlign:'right' }}><span style={{ color:'#94a3b8' }}>Material: </span>{Math.round(parseFloat(p.unitPriceMaterial)||0).toLocaleString('nb-NO')} kr/enh</div>
                        </div>
                        <div style={{ background:'#f0fdf4', borderRadius:'6px', padding:'6px 10px', display:'flex', justifyContent:'space-between' }}>
                          <span style={{ fontSize:'11px', color:'#64748b', fontWeight:'600' }}>Sum:</span>
                          <span style={{ fontSize:'14px', fontWeight:'800', color:'#059669' }}>{Math.round(sum).toLocaleString('nb-NO')} kr</span>
                        </div>
                      </div>
                    )
                  })}
                  <div style={{ background:'#f0fdf4', border:'2px solid #86efac', borderRadius:'10px', padding:'12px', display:'flex', justifyContent:'space-between', alignItems:'center', marginTop:'4px' }}>
                    <span style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a' }}>Total eks. mva:</span>
                    <span style={{ fontSize:'17px', fontWeight:'800', color:'#059669' }}>{Math.round(em.amount || 0).toLocaleString('nb-NO')} kr</span>
                  </div>
                </div>
              )}
            </div>
          )}
          {/* Bilder */}
          {(em.images||[]).length > 0 && (
            <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'16px', marginBottom:'16px' }}>
              <h3 style={{ margin:'0 0 10px', fontSize:'14px', fontWeight:'600' }}>📸 Bilder</h3>
              <div style={{ display:'flex', gap: isMobBild ? '6px' : '8px', flexWrap:'wrap' }}>
                {em.images.map((img, i) => <img key={i} src={img.url} alt={img.name} style={{ width:'120px', height:'120px', objectFit:'cover', borderRadius:'10px', border:'1px solid #e2e8f0', cursor:'pointer' }} onClick={() => window.open(img.url, '_blank')} />)}
              </div>
            </div>
          )}
          {/* Vedlegg */}
          {(em.vedlegg||[]).length > 0 && (
            <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'16px', marginBottom:'16px' }}>
              <h3 style={{ margin:'0 0 10px', fontSize:'14px', fontWeight:'600' }}>📎 Vedlegg</h3>
              {em.vedlegg.map((v, i) => <a key={i} href={v.url} target="_blank" rel="noreferrer" style={{ display:'block', color:'#2563eb', fontSize:'13px', marginBottom:'4px' }}>📎 {v.name}</a>)}
            </div>
          )}
          {/* Aktivitetslogg */}
          <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'16px' }}>
            <h3 style={{ margin:'0 0 10px', fontSize:'14px', fontWeight:'600' }}>📋 Aktivitetslogg</h3>
            {(em.activity_log || []).slice().reverse().map((log, i) => (
              <div key={i} style={{ display:'flex', gap:'10px', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize:'13px' }}>
                <span style={{ color:'#94a3b8', fontSize: isMobEM ? '10px' : '12px', width: isMobEM ? 'auto' : '130px', flexShrink:0 }}>{new Date(log.at).toLocaleString('nb-NO', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit' })}</span>
                <span style={{ color:'#374151', fontSize: isMobEM ? '12px' : '13px' }}>{log.action}</span>
                {!isMobEM && <span style={{ color:'#94a3b8', marginLeft:'auto' }}>{log.by}</span>}
              </div>
            ))}
            {(!em.activity_log || em.activity_log.length === 0) && <p style={{ margin:0, color:'#94a3b8', fontSize:'13px' }}>Ingen aktivitet registrert</p>}
          </div>
        </div>

        {/* Modaler også i detaljvisning */}
        {sendDialogEm && (
          <SendEmDialog
            em={sendDialogEm}
            sendType="send"
            onClose={() => setSendDialogEm(null)}
            onConfirm={async (reminderDays) => {
              const em = sendDialogEm
              setSendDialogEm(null)
              await sendToCustomer(em, reminderDays)
            }}
          />
        )}
        {resendDialogEm && (
          <SendEmDialog
            em={resendDialogEm.em}
            sendType={resendDialogEm.type}
            onClose={() => setResendDialogEm(null)}
            onConfirm={async (reminderDays) => {
              const { em, type } = resendDialogEm
              setResendDialogEm(null)
              await resendToCustomer(em, type, reminderDays)
            }}
          />
        )}
        {viewingVersion && (
          <VersionViewerModal
            em={viewingVersion.em}
            version={viewingVersion.version}
            totalVersions={(viewingVersion.em.versions || []).length}
            projects={projects}
            onClose={() => setViewingVersion(null)}
          />
        )}
      </div>
    )
  }

  // ── List View ──────────────────────────────────────────────────────────────
  return (
    <div style={{ ...f, overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobEM ? '14px' : '20px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px' }}>
          <div>
            <h1 style={{ margin:0, fontSize: isMobEM ? '18px' : '22px', fontWeight:'bold', color:'#0f172a' }}>🔄 Endringsmeldinger</h1>
            {!isMobEM && <p style={{ margin:'3px 0 0', fontSize:'13px', color:'#64748b' }}>Opprett og send endringer fra byggeplassen</p>}
          </div>
          <div style={{ display:'flex', gap:'6px', flexShrink:0 }}>
            <button onClick={() => navNew()} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding: isMobEM ? '9px 12px' : '10px 20px', fontSize: isMobEM ? '12px' : '14px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>+ Ny EM</button>
          </div>
        </div>
      </div>

      {/* Statistikk — klikkbare status-kort filtrerer listen under */}
      <div style={{ padding: isMobEM ? '10px 12px' : '16px 32px', display:'grid', gridTemplateColumns: isMobEM ? 'repeat(3, 1fr)' : 'repeat(6, 1fr)', gap: isMobEM ? '6px' : '12px' }}>
        {[
          { label:'Totalt', value: endringer.length, color:'#0f172a', filter:'all' },
          { label:'Utkast', value: endringer.filter(e=>e.status==='Utkast').length, color:'#64748b', filter:'Utkast' },
          { label:'Sendt', value: endringer.filter(e=>e.status==='Sendt').length, color:'#2563eb', filter:'Sendt' },
          { label:'Godkjent', value: endringer.filter(e=>e.status==='Godkjent').length, color:'#16a34a', filter:'Godkjent' },
          { label:'Godkjent beløp', value: Math.round(totalTillegg).toLocaleString('nb-NO') + ' kr', color:'#059669', filter:null },
          { label:'Klar til fakturering', value: Math.round(totalIkkeFakturert).toLocaleString('nb-NO') + ' kr', color:'#d97706', filter:null },
        ].map((s,i) => {
          const isClickable = s.filter !== null
          const isActive = isClickable && statusFilter === s.filter
          const commonStyle = { background: isActive ? '#f0fdf4' : 'white', borderRadius: isMobEM ? '10px' : '12px', border: `1px solid ${isActive ? s.color + '66' : '#f1f5f9'}`, padding: isMobEM ? '8px' : '12px 16px', textAlign:'center', transition:'all 0.15s' }
          if (!isClickable) {
            return (
              <div key={i} style={commonStyle}>
                <div style={{ fontSize: isMobEM ? '14px' : '18px', fontWeight:'800', color:s.color }}>{s.value}</div>
                <div style={{ fontSize: isMobEM ? '9px' : '11px', color:'#94a3b8' }}>{s.label}</div>
              </div>
            )
          }
          return (
            <button key={i}
              onClick={() => { if (isActive) setStatusFilter('all'); else setStatusFilter(s.filter) }}
              style={{ ...commonStyle, cursor:'pointer', fontFamily:'inherit' }}
              onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = '#f8fafc' }}
              onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = 'white' }}>
              <div style={{ fontSize: isMobEM ? '14px' : '18px', fontWeight:'800', color:s.color }}>{s.value}</div>
              <div style={{ fontSize: isMobEM ? '9px' : '11px', color: isActive ? s.color : '#94a3b8', fontWeight: isActive ? '600' : '400' }}>{s.label}</div>
            </button>
          )
        })}
      </div>

      {/* Filtre */}
      <div style={{ padding: isMobEM ? '0 12px 10px' : '0 32px 12px', display:'flex', gap: isMobEM ? '8px' : '10px', alignItems:'center', flexWrap:'wrap' }}>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 Søk..." style={{ ...inp, maxWidth: isMobEM ? '100%' : '250px', flex: isMobEM ? '1 1 100%' : 'none' }} />
        <select value={statusFilter} onChange={e=>setStatusFilter(e.target.value)} style={{ ...inp, maxWidth: isMobEM ? '100%' : '160px', background:'white', flex: isMobEM ? '1 1 48%' : 'none', fontSize: isMobEM ? '13px' : '14px' }}>
          <option value="all">Alle statuser</option>
          {Object.keys(EM_STATUS).map(s => <option key={s} value={s}>{EM_STATUS[s].emoji} {s}</option>)}
        </select>
        <SearchableProjectSelect value={projectFilter} onChange={setProjectFilter} projects={projects} style={{ ...inp, maxWidth: isMobEM ? '100%' : '200px', background:'white', flex: isMobEM ? '1 1 48%' : 'none', fontSize: isMobEM ? '13px' : '14px' }} placeholder="Alle prosjekter" emptyValue="all" />
      </div>

      {/* Liste */}
      <div style={{ padding: isMobEM ? '0 12px 12px' : '0 32px 32px' }}>
        {loading && <div style={{ textAlign:'center', padding:'60px', color:'#94a3b8' }}>Laster...</div>}
        {!loading && filtered.length === 0 && <div style={{ textAlign:'center', padding:'60px', color:'#94a3b8' }}>Ingen endringsmeldinger funnet</div>}
        <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
          {filtered.map(em => {
            const st = EM_STATUS[em.status] || EM_STATUS['Utkast']
            const proj = projects.find(p => p.id === em.project_id)
            const isExpanded = expandedEm === em.id
            return (
              <div key={em.id} style={{ background:'white', borderRadius:'14px', border:`1px solid ${st.border}`, overflow:'hidden' }}>
                {/* Hovedrad */}
                <div style={{ padding: isMobEM ? '10px 12px' : '14px 20px', display:'flex', alignItems:'center', gap: isMobEM ? '8px' : '12px' }}>
                  {!isMobEM && <div style={{ width:'40px', height:'40px', borderRadius:'10px', background:st.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'18px', flexShrink:0 }}>{st.emoji}</div>}
                  <div style={{ flex:1, minWidth:0, cursor:'pointer' }} onClick={() => navDetail(em.id)}>
                    <div style={{ display:'flex', alignItems:'center', gap:'6px', marginBottom:'3px', flexWrap:'wrap' }}>
                      <span style={{ fontWeight:'600', fontSize: isMobEM ? '13px' : '14px', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', maxWidth: isMobEM ? 'calc(100vw - 160px)' : 'none' }}>{em.title}</span>
                      <span style={{ background:st.bg, color:st.color, border:`1px solid ${st.border}`, padding:'1px 8px', borderRadius:'999px', fontSize:'11px', fontWeight:'600' }}>{em.status}</span>
                    </div>
                    <div style={{ display:'flex', gap: isMobEM ? '4px' : '10px', flexWrap:'wrap' }}>
                      {!isMobEM && <span style={{ fontSize:'12px', color:'#94a3b8' }}>{em.em_number}</span>}
                      {proj && <span style={{ fontSize: isMobEM ? '11px' : '12px', color:'#059669' }}>🏗️ {proj.name}</span>}
                      {!isMobEM && em.reason && <span style={{ fontSize:'12px', color:'#d97706' }}>🏷️ {em.reason}</span>}
                      {!isMobEM && <span style={{ fontSize:'12px', color:'#94a3b8' }}>{new Date(em.created_at).toLocaleDateString('nb-NO')}</span>}
                    </div>
                  </div>
                  {!isMobEM && <div style={{ textAlign:'right', flexShrink:0, marginRight:'8px' }}>
                    <div style={{ fontSize:'16px', fontWeight:'700', color:'#059669' }}>{Math.round(em.amount || 0).toLocaleString('nb-NO')} kr</div>
                    <div style={{ fontSize:'10px', color:'#94a3b8' }}>eks. mva</div>
                    {em.time_consequence && <div style={{ fontSize:'11px', color:'#d97706' }}>⏱️ {em.time_consequence}</div>}
                  </div>}
                  <div style={{ display:'flex', gap:'4px', flexShrink:0, alignItems:'center' }}>
                    {/* Mobil: vis kun ÉN primær handlingsknapp basert på status */}
                    {isMobEM && (() => {
                      if (em.status === 'Utkast' || em.status === 'Under forhandling') {
                        return <button onClick={(e) => { e.stopPropagation(); setSendDialogEm(em) }} title="Send til kunde"
                          style={{ background:'#2563eb', color:'white', border:'none', borderRadius:'8px', padding:'7px 10px', cursor:'pointer', fontSize:'13px', fontWeight:'600', whiteSpace:'nowrap' }}>📧</button>
                      }
                      if (em.status === 'Sendt') {
                        const t = getEmSendType(em)
                        if (t === 'revision') {
                          return <button onClick={(e) => { e.stopPropagation(); setResendDialogEm({ em, type: 'revision' }) }} title="Send revisjon"
                            style={{ background:'#2563eb', color:'white', border:'none', borderRadius:'8px', padding:'7px 10px', cursor:'pointer', fontSize:'13px', fontWeight:'600', whiteSpace:'nowrap' }}>📝</button>
                        }
                        return <button onClick={(e) => { e.stopPropagation(); setResendDialogEm({ em, type: 'resend' }) }} title="Send på nytt"
                          style={{ background:'#f1f5f9', color:'#1e293b', border:'1px solid #cbd5e1', borderRadius:'8px', padding:'7px 10px', cursor:'pointer', fontSize:'13px', fontWeight:'600', whiteSpace:'nowrap' }}>🔄</button>
                      }
                      if (em.status === 'Godkjent' || em.status === 'Avvist') {
                        return <button onClick={(e) => { e.stopPropagation(); setResendDialogEm({ em, type: 'copy' }) }} title="Send kopi"
                          style={{ background:'#f0fdf4', color:'#065f46', border:'1px solid #bbf7d0', borderRadius:'8px', padding:'7px 10px', cursor:'pointer', fontSize:'13px', fontWeight:'600', whiteSpace:'nowrap' }}>📄</button>
                      }
                      return null
                    })()}
                    {!isMobEM && (em.status === 'Utkast' || em.status === 'Under forhandling') && (
                      <button onClick={(e) => { e.stopPropagation(); setSendDialogEm(em) }} title="Send til kunde"
                        style={{ background:'#2563eb', color:'white', border:'none', borderRadius:'8px', padding:'7px 14px', cursor:'pointer', fontSize:'12px', fontWeight:'600', display:'flex', alignItems:'center', gap:'4px', whiteSpace:'nowrap' }}>📧 Send</button>
                    )}
                    {!isMobEM && em.status === 'Sendt' && (() => {
                      const t = getEmSendType(em)
                      if (t === 'revision') {
                        return (
                          <button onClick={(e) => { e.stopPropagation(); setResendDialogEm({ em, type: 'revision' }) }} title="Send revidert versjon"
                            style={{ background:'#2563eb', color:'white', border:'none', borderRadius:'8px', padding:'7px 12px', cursor:'pointer', fontSize:'12px', fontWeight:'600', whiteSpace:'nowrap' }}>📝 Send revisjon</button>
                        )
                      }
                      return (
                        <button onClick={(e) => { e.stopPropagation(); setResendDialogEm({ em, type: 'resend' }) }} title="Send på nytt"
                          style={{ background:'#f1f5f9', color:'#1e293b', border:'1px solid #cbd5e1', borderRadius:'8px', padding:'7px 12px', cursor:'pointer', fontSize:'12px', fontWeight:'600', whiteSpace:'nowrap' }}>🔄 Send på nytt</button>
                      )
                    })()}
                    {!isMobEM && em.status === 'Sendt' && (
                      <button onClick={(e) => { e.stopPropagation(); sendReminder(em) }} title="Send påminnelse"
                        style={{ background:'#fef3c7', color:'#92400e', border:'1px solid #fde68a', borderRadius:'8px', padding:'7px 12px', cursor:'pointer', fontSize:'12px', fontWeight:'600', whiteSpace:'nowrap' }}>📩 Purr</button>
                    )}
                    {!isMobEM && (em.status === 'Godkjent' || em.status === 'Avvist') && (
                      <button onClick={(e) => { e.stopPropagation(); setResendDialogEm({ em, type: 'copy' }) }} title="Send kopi til kunde"
                        style={{ background:'#f0fdf4', color:'#065f46', border:'1px solid #bbf7d0', borderRadius:'8px', padding:'7px 12px', cursor:'pointer', fontSize:'12px', fontWeight:'600', whiteSpace:'nowrap' }}>📄 Send kopi</button>
                    )}
                    {!isMobEM && <button onClick={(e) => { e.stopPropagation(); exportSingleEmPDF(em) }} disabled={exportingPdf} title="Last ned som PDF" style={{ background:'white', border:'1px solid #e2e8f0', borderRadius:'8px', padding:'7px 10px', cursor: exportingPdf?'not-allowed':'pointer', fontSize:'13px', color:'#374151' }}>📄</button>}
                    {!isMobEM && <button onClick={(e) => { e.stopPropagation(); navEdit(em.id) }} title="Rediger" style={{ background:'#f8fafc', border:'1px solid #e2e8f0', borderRadius:'8px', padding:'7px 10px', cursor:'pointer', fontSize:'13px' }}>✏️</button>}
                    {!isMobEM && <button onClick={(e) => { e.stopPropagation(); handleDelete(em) }} title="Slett" style={{ background:'#fef2f2', border:'none', borderRadius:'8px', padding:'7px 10px', cursor:'pointer', fontSize:'13px' }}>🗑️</button>}
                    <button onClick={(e) => { e.stopPropagation(); isMobEM ? navDetail(em.id) : setExpandedEm(isExpanded ? null : em.id) }} title={isMobEM ? "Vis" : "Vis historikk"}
                      style={{ background:'none', border:'1px solid #e2e8f0', borderRadius:'8px', padding:'7px 10px', cursor:'pointer', fontSize: isMobEM ? '12px' : '14px', color:'#64748b', fontWeight:'700' }}>{isMobEM ? '›' : isExpanded ? '▲' : '▼'}</button>
                  </div>
                </div>
                {/* Utvidet: Historikk og aktivitetslogg */}
                {isExpanded && (
                  <div style={{ borderTop:'1px solid #f1f5f9', padding:'14px 20px', background:'#fafbfc' }}>
                    <div style={{ fontSize:'12px', fontWeight:'700', color:'#0f172a', marginBottom:'10px' }}>📋 Aktivitetslogg</div>
                    {(em.activity_log || []).length === 0 && <div style={{ fontSize:'12px', color:'#94a3b8' }}>Ingen aktivitet registrert</div>}
                    <div style={{ display:'flex', flexDirection:'column', gap:'0' }}>
                      {(em.activity_log || []).slice().reverse().map((log, i) => {
                        const isFirst = i === 0
                        return (
                          <div key={i} style={{ display:'flex', gap:'12px', alignItems:'flex-start', position:'relative', paddingLeft:'20px', paddingBottom:'10px' }}>
                            {/* Tidslinje */}
                            <div style={{ position:'absolute', left:'6px', top:'0', bottom:'0', width:'2px', background: isFirst ? 'transparent' : '#e2e8f0' }} />
                            <div style={{ position:'absolute', left:'0', top:'3px', width:'14px', height:'14px', borderRadius:'50%', background: isFirst ? '#059669' : '#e2e8f0', border:'2px solid white', zIndex:1 }} />
                            <div style={{ flex:1 }}>
                              <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
                                <span style={{ fontSize:'12px', fontWeight:'600', color: isFirst ? '#059669' : '#374151' }}>{log.action}</span>
                                {log.to && <span style={{ fontSize:'11px', color:'#64748b' }}>→ {log.to}</span>}
                              </div>
                              <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'1px' }}>
                                {new Date(log.at).toLocaleString('nb-NO', { day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit' })}
                                {log.by && <span> · {log.by}</span>}
                              </div>
                            </div>
                          </div>
                        )
                      })}
                    </div>
                    {/* Status-oppdatering knapper */}
                    {em.status === 'Sendt' && (
                      <div style={{ display:'flex', gap:'6px', marginTop:'10px', paddingTop:'10px', borderTop:'1px solid #e2e8f0' }}>
                        <button onClick={async () => {
                          const log = [...(em.activity_log || []), { action: 'Godkjent av kunde', by: user?.email, at: new Date().toISOString() }]
                          await supabase.from('endringsmeldinger').update({ status: 'Godkjent', activity_log: log, updated_at: new Date().toISOString() }).eq('id', em.id)
                          load()
                        }} style={{ background:'#f0fdf4', color:'#16a34a', border:'1px solid #bbf7d0', borderRadius:'8px', padding:'6px 14px', fontSize:'12px', fontWeight:'600', cursor:'pointer' }}>✅ Merk som godkjent</button>
                        <button onClick={async () => {
                          const log = [...(em.activity_log || []), { action: 'Avvist av kunde', by: user?.email, at: new Date().toISOString() }]
                          await supabase.from('endringsmeldinger').update({ status: 'Avvist', activity_log: log, updated_at: new Date().toISOString() }).eq('id', em.id)
                          load()
                        }} style={{ background:'#fef2f2', color:'#dc2626', border:'1px solid #fecaca', borderRadius:'8px', padding:'6px 14px', fontSize:'12px', fontWeight:'600', cursor:'pointer' }}>❌ Merk som avvist</button>
                        <button onClick={async () => {
                          const log = [...(em.activity_log || []), { action: 'Satt til under forhandling', by: user?.email, at: new Date().toISOString() }]
                          await supabase.from('endringsmeldinger').update({ status: 'Under forhandling', activity_log: log, updated_at: new Date().toISOString() }).eq('id', em.id)
                          load()
                        }} style={{ background:'#fffbeb', color:'#d97706', border:'1px solid #fde68a', borderRadius:'8px', padding:'6px 14px', fontSize:'12px', fontWeight:'600', cursor:'pointer' }}>🤝 Under forhandling</button>
                      </div>
                    )}
                    {em.status === 'Godkjent' && (
                      <div style={{ marginTop:'10px', paddingTop:'10px', borderTop:'1px solid #e2e8f0' }}>
                        <button onClick={async () => {
                          const log = [...(em.activity_log || []), { action: 'Merket som fakturert', by: user?.email, at: new Date().toISOString() }]
                          await supabase.from('endringsmeldinger').update({ status: 'Fakturert', activity_log: log, updated_at: new Date().toISOString() }).eq('id', em.id)
                          load()
                        }} style={{ background:'#f5f3ff', color:'#7c3aed', border:'1px solid #ddd6fe', borderRadius:'8px', padding:'6px 14px', fontSize:'12px', fontWeight:'600', cursor:'pointer' }}>🧾 Merk som fakturert</button>
                      </div>
                    )}
                  </div>
                )}
              </div>
            )
          })}
        </div>
      </div>

      {showForm && <EmForm 
        initial={editEm} 
        onClose={() => navList()} 
        onSaved={() => { navListReplace(); load() }}
        onSaveAndSend={(savedEm) => { 
          navListReplace();
          load(); 
          // Åpne send-dialog med den nylig opprettede EM-en
          setSendDialogEm(savedEm)
        }}
      />}

      {/* Send-dialog med frist-valg */}
      {sendDialogEm && (
        <SendEmDialog
          em={sendDialogEm}
          sendType="send"
          onClose={() => setSendDialogEm(null)}
          onConfirm={async (reminderDays) => {
            const em = sendDialogEm
            setSendDialogEm(null)
            await sendToCustomer(em, reminderDays)
          }}
        />
      )}

      {/* Send-på-nytt / Revisjon / Kopi dialog */}
      {resendDialogEm && (
        <SendEmDialog
          em={resendDialogEm.em}
          sendType={resendDialogEm.type}
          onClose={() => setResendDialogEm(null)}
          onConfirm={async (reminderDays) => {
            const { em, type } = resendDialogEm
            setResendDialogEm(null)
            await resendToCustomer(em, type, reminderDays)
          }}
        />
      )}

      {/* Versjon-viewer modal */}
      {viewingVersion && (
        <VersionViewerModal
          em={viewingVersion.em}
          version={viewingVersion.version}
          totalVersions={(viewingVersion.em.versions || []).length}
          projects={projects}
          onClose={() => setViewingVersion(null)}
        />
      )}
    </div>
  )
}

// ─── SEND-EM-DIALOG ───────────────────────────────────────────────────────────
function SendEmDialog({ em, onClose, onConfirm, sendType = 'send' }) {
  // sendType: 'send' (første), 'resend', 'revision', 'copy'
  const [reminderDays, setReminderDays] = useState(7) // Standard 7 dager
  const [sending, setSending] = useState(false)

  const isCopy = sendType === 'copy'
  const showReminder = !isCopy // Kopi har ikke purringsfrist

  const typeLabels = {
    send: { title: '📧 Send endringsmelding', button: '📧 Send', banner: null },
    resend: { title: '🔄 Send på nytt', button: '🔄 Send på nytt', banner: {
      bg: '#fffbeb', border: '#fde68a', color: '#92400e',
      text: 'Denne endringsmeldingen sendes på nytt med identisk innhold som forrige utsendelse.'
    }},
    revision: { title: '📝 Send revisjon', button: '📝 Send revisjon', banner: {
      bg: '#eff6ff', border: '#bfdbfe', color: '#1e40af',
      text: 'Endringsmeldingen er redigert siden forrige utsendelse. Kunden får beskjed om at dette er en revidert versjon.'
    }},
    copy: { title: '📄 Send kopi', button: '📄 Send kopi', banner: {
      bg: '#f0fdf4', border: '#bbf7d0', color: '#065f46',
      text: `Status er "${em.status}". Kunden får en kopi til arkivering — ingen svar forventes.`
    }},
  }
  const cfg = typeLabels[sendType] || typeLabels.send

  const handleConfirm = async () => {
    setSending(true)
    try { await onConfirm(showReminder ? reminderDays : null) }
    finally { setSending(false) }
  }

  const dueDate = new Date()
  dueDate.setDate(dueDate.getDate() + parseInt(reminderDays || 0))

  return (
    <div style={{ position:'fixed', inset:0, zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px', fontFamily:'system-ui, sans-serif' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'480px', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>{cfg.title}</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>

        <div style={{ padding:'20px 24px', display:'flex', flexDirection:'column', gap:'16px' }}>
          {cfg.banner && (
            <div style={{ background: cfg.banner.bg, border: `1px solid ${cfg.banner.border}`, borderRadius:'10px', padding:'12px 14px' }}>
              <div style={{ fontSize:'13px', color: cfg.banner.color, lineHeight:1.5 }}>{cfg.banner.text}</div>
            </div>
          )}

          <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px 14px' }}>
            <div style={{ fontSize:'12px', color:'#64748b', marginBottom:'4px' }}>MOTTAKER</div>
            <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>{em.customer_email || '—'}</div>
          </div>

          {showReminder && (
            <>
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>
                  Purringsfrist — hvor mange dager har kunden på å svare?
                </label>
                <div style={{ display:'grid', gridTemplateColumns:'repeat(4, 1fr)', gap:'6px', marginBottom:'8px' }}>
                  {[3, 7, 14, 30].map(d => (
                    <button key={d} type="button" onClick={() => setReminderDays(d)}
                      style={{ padding:'9px 6px', borderRadius:'10px', border: `2px solid ${parseInt(reminderDays) === d ? '#2563eb' : '#e2e8f0'}`, background: parseInt(reminderDays) === d ? '#eff6ff' : 'white', color: parseInt(reminderDays) === d ? '#2563eb' : '#64748b', fontWeight: parseInt(reminderDays) === d ? '700' : '500', fontSize:'13px', cursor:'pointer' }}>
                      {d} dager
                    </button>
                  ))}
                </div>
                <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
                  <label style={{ fontSize:'12px', color:'#64748b', flexShrink:0 }}>Egendefinert:</label>
                  <input type="number" min="1" max="365" value={reminderDays} onChange={e => setReminderDays(e.target.value)}
                    style={{ flex:1, padding:'7px 10px', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize:'13px', outline:'none', boxSizing:'border-box' }} />
                  <span style={{ fontSize:'12px', color:'#94a3b8' }}>dager</span>
                </div>
              </div>

              {reminderDays > 0 && (
                <div style={{ background:'#fffbeb', border:'1px solid #fde68a', borderRadius:'10px', padding:'10px 14px' }}>
                  <div style={{ fontSize:'12px', color:'#92400e', marginBottom:'2px' }}>⏰ PURRING TRIGGES</div>
                  <div style={{ fontSize:'13px', color:'#0f172a', fontWeight:'600' }}>
                    {dueDate.toLocaleDateString('nb-NO', { weekday:'long', day:'2-digit', month:'long', year:'numeric' })}
                  </div>
                  <div style={{ fontSize:'11px', color:'#92400e', marginTop:'4px' }}>
                    Hvis kunden ikke har svart innen denne datoen, får du varsel i bjellen og kan sende purring med ett klikk.
                  </div>
                </div>
              )}
            </>
          )}

          <div style={{ background:'#f0fdf4', borderRadius:'10px', padding:'10px 14px', fontSize:'12px', color:'#059669' }}>
            <strong>Kunde får:</strong> {isCopy
              ? 'E-post med alle detaljer og PDF-vedlegg til arkivering.'
              : 'E-post med alle detaljer, PDF-vedlegg og knapper for å godkjenne/avvise endringsmeldingen.'}
          </div>
        </div>

        <div style={{ padding:'16px 24px', borderTop:'1px solid #f1f5f9', display:'flex', gap:'10px', justifyContent:'flex-end' }}>
          <button type="button" onClick={onClose} disabled={sending} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor: sending?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
          <button type="button" onClick={handleConfirm} disabled={sending || !em.customer_email}
            style={{ padding:'10px 20px', background: sending ? '#93c5fd' : '#2563eb', color:'white', border:'none', borderRadius:'10px', cursor: sending?'not-allowed':'pointer', fontSize:'14px', fontWeight:'700' }}>
            {sending ? 'Sender...' : cfg.button}
          </button>
        </div>
      </div>
    </div>
  )
}
// ─── END SEND-EM-DIALOG ───────────────────────────────────────────────────────

// ─── VERSION-VIEWER-MODAL ─────────────────────────────────────────────────────
function VersionViewerModal({ em, version, totalVersions, projects, onClose }) {
  const isMobVV = typeof window !== 'undefined' && window.innerWidth < 768
  const s = version.snapshot || {}
  const proj = (projects || []).find(p => p.id === em.project_id)
  const isCurrent = version.version_number === totalVersions

  const typeLabel = {
    send: '📧 Første utsendelse',
    resend: '🔄 Sendt på nytt',
    revision: '📝 Revisjon',
    copy: '📄 Kopi',
  }[version.sent_type] || '📧 Sendt'

  const typeColor = {
    send: '#2563eb',
    resend: '#64748b',
    revision: '#1e40af',
    copy: '#065f46',
  }[version.sent_type] || '#64748b'

  const validPosts = Array.isArray(s.posts) ? s.posts.filter(p => p.description || parseFloat(p.qty) > 0) : []

  return (
    <div style={{ position:'fixed', inset:0, zIndex:210, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px', fontFamily:'system-ui, sans-serif' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'700px', maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.25)' }}>
        {/* Header */}
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap:'16px' }}>
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'6px', flexWrap:'wrap' }}>
              <span style={{ background: isCurrent ? '#dcfce7' : '#f1f5f9', color: isCurrent ? '#065f46' : '#475569', padding:'3px 10px', borderRadius:'6px', fontSize:'12px', fontWeight:'700' }}>
                Versjon {version.version_number}{isCurrent ? ' (nåværende)' : ' (historisk)'}
              </span>
              <span style={{ color: typeColor, fontSize:'12px', fontWeight:'600' }}>{typeLabel}</span>
            </div>
            <h2 style={{ margin:'0 0 4px', fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>{s.title || em.title}</h2>
            <div style={{ fontSize:'12px', color:'#64748b' }}>
              {s.em_number || em.em_number} · Sendt {new Date(version.sent_at).toLocaleString('nb-NO', { day:'2-digit', month:'long', year:'numeric', hour:'2-digit', minute:'2-digit' })}
              {version.sent_by && ` · av ${version.sent_by}`}
            </div>
          </div>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8', padding:0, flexShrink:0 }}>×</button>
        </div>

        {/* Scrollbart innhold */}
        <div style={{ padding:'20px 24px', overflowY:'auto', flex:1 }}>
          {!isCurrent && (
            <div style={{ background:'#fffbeb', border:'1px solid #fde68a', borderRadius:'10px', padding:'12px 14px', marginBottom:'16px' }}>
              <div style={{ fontSize:'12px', color:'#92400e' }}>
                ⚠️ Dette er en <strong>historisk versjon</strong> av endringsmeldingen. Innholdet kan være annerledes fra nåværende versjon.
              </div>
            </div>
          )}

          {/* Prosjekt */}
          <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px 14px', marginBottom:'14px' }}>
            <div style={{ fontSize:'11px', color:'#64748b', marginBottom:'2px', textTransform:'uppercase', fontWeight:'600' }}>Prosjekt</div>
            <div style={{ fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>{proj?.name || '—'}</div>
          </div>

          {/* Årsak */}
          {s.reason && (
            <div style={{ background:'#fffbeb', border:'1px solid #fde68a', borderRadius:'10px', padding:'10px 14px', marginBottom:'14px' }}>
              <div style={{ fontSize:'11px', color:'#92400e', fontWeight:'600', textTransform:'uppercase', marginBottom:'2px' }}>Årsak</div>
              <div style={{ fontSize:'13px', color:'#0f172a' }}>{s.reason}</div>
            </div>
          )}

          {/* Beskrivelse */}
          {s.description && (
            <div style={{ background:'white', border:'1px solid #f1f5f9', borderRadius:'10px', padding:'14px', marginBottom:'14px' }}>
              <div style={{ fontSize:'11px', color:'#64748b', fontWeight:'600', textTransform:'uppercase', marginBottom:'6px' }}>Beskrivelse</div>
              <div style={{ fontSize:'14px', color:'#374151', lineHeight:1.6, whiteSpace:'pre-wrap' }}>{s.description}</div>
            </div>
          )}

          {/* Poster */}
          {validPosts.length > 0 && (
            <div style={{ background:'white', border:'1px solid #f1f5f9', borderRadius:'10px', padding:'14px', marginBottom:'14px' }}>
              <div style={{ fontSize:'11px', color:'#64748b', fontWeight:'600', textTransform:'uppercase', marginBottom:'8px' }}>💰 Poster</div>
              {!isMobVV ? (
                <table style={{ width:'100%', borderCollapse:'collapse' }}>
                  <thead>
                    <tr style={{ borderBottom:'1px solid #e2e8f0' }}>
                      <th style={{ padding:'6px 8px', textAlign:'left', fontSize:'11px', color:'#94a3b8', textTransform:'uppercase' }}>Beskrivelse</th>
                      <th style={{ padding:'6px 8px', textAlign:'right', fontSize:'11px', color:'#94a3b8', textTransform:'uppercase' }}>Mengde</th>
                      <th style={{ padding:'6px 8px', textAlign:'right', fontSize:'11px', color:'#94a3b8', textTransform:'uppercase' }}>Arb./enh</th>
                      <th style={{ padding:'6px 8px', textAlign:'right', fontSize:'11px', color:'#94a3b8', textTransform:'uppercase' }}>Mat./enh</th>
                      <th style={{ padding:'6px 8px', textAlign:'right', fontSize:'11px', color:'#94a3b8', textTransform:'uppercase' }}>Sum</th>
                    </tr>
                  </thead>
                  <tbody>
                    {validPosts.map((p, idx) => {
                      const sum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
                      return (
                        <tr key={idx} style={{ borderBottom:'1px solid #f1f5f9' }}>
                          <td style={{ padding:'6px 8px', fontSize:'13px', color:'#0f172a' }}>{p.description || '—'}</td>
                          <td style={{ padding:'6px 8px', fontSize:'13px', textAlign:'right', color:'#475569' }}>{p.qty || 0} {p.unit || 'stk'}</td>
                          <td style={{ padding:'6px 8px', fontSize:'13px', textAlign:'right', color:'#475569' }}>{Math.round(parseFloat(p.unitPriceWork)||0).toLocaleString('nb-NO')}</td>
                          <td style={{ padding:'6px 8px', fontSize:'13px', textAlign:'right', color:'#475569' }}>{Math.round(parseFloat(p.unitPriceMaterial)||0).toLocaleString('nb-NO')}</td>
                          <td style={{ padding:'6px 8px', fontSize:'13px', textAlign:'right', fontWeight:'700', color:'#0f172a' }}>{Math.round(sum).toLocaleString('nb-NO')} kr</td>
                        </tr>
                      )
                    })}
                  </tbody>
                </table>
              ) : (
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {validPosts.map((p, idx) => {
                    const sum = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
                    return (
                      <div key={idx} style={{ background:'#fafbfc', borderRadius:'8px', padding:'10px', border:'1px solid #e2e8f0' }}>
                        <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a', marginBottom:'6px' }}>{p.description || '—'}</div>
                        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'6px', fontSize:'12px', color:'#475569', marginBottom:'8px' }}>
                          <div><span style={{ color:'#94a3b8' }}>Mengde: </span>{p.qty || 0} {p.unit || 'stk'}</div>
                          <div style={{ textAlign:'right' }}><span style={{ color:'#94a3b8' }}>Arbeid: </span>{Math.round(parseFloat(p.unitPriceWork)||0).toLocaleString('nb-NO')} kr/enh</div>
                          <div><span style={{ color:'#94a3b8' }}>Material: </span>{Math.round(parseFloat(p.unitPriceMaterial)||0).toLocaleString('nb-NO')} kr/enh</div>
                        </div>
                        <div style={{ background:'#f0fdf4', borderRadius:'6px', padding:'6px 10px', display:'flex', justifyContent:'space-between' }}>
                          <span style={{ fontSize:'11px', color:'#64748b', fontWeight:'600' }}>Sum:</span>
                          <span style={{ fontSize:'14px', fontWeight:'800', color:'#059669' }}>{Math.round(sum).toLocaleString('nb-NO')} kr</span>
                        </div>
                      </div>
                    )
                  })}
                </div>
              )}
            </div>
          )}

          {/* Total */}
          <div style={{ display:'grid', gridTemplateColumns: s.time_consequence ? '1fr 1fr' : '1fr', gap:'10px' }}>
            <div style={{ background:'#f0fdf4', borderRadius:'10px', padding:'14px', textAlign:'center' }}>
              <div style={{ fontSize:'20px', fontWeight:'800', color:'#059669' }}>{Math.round(s.amount || 0).toLocaleString('nb-NO')} kr</div>
              <div style={{ fontSize:'11px', color:'#64748b' }}>Total eks. mva</div>
            </div>
            {s.time_consequence && (
              <div style={{ background:'#fffbeb', borderRadius:'10px', padding:'14px', textAlign:'center' }}>
                <div style={{ fontSize:'14px', fontWeight:'700', color:'#d97706' }}>{s.time_consequence}</div>
                <div style={{ fontSize:'11px', color:'#64748b' }}>Tidskonsekvens</div>
              </div>
            )}
          </div>

          {/* Bilder hvis finnes */}
          {Array.isArray(s.images) && s.images.length > 0 && (
            <div style={{ marginTop:'14px', background:'white', border:'1px solid #f1f5f9', borderRadius:'10px', padding:'14px' }}>
              <div style={{ fontSize:'11px', color:'#64748b', fontWeight:'600', textTransform:'uppercase', marginBottom:'8px' }}>📸 Bilder</div>
              <div style={{ display:'flex', gap:'8px', flexWrap:'wrap' }}>
                {s.images.map((img, i) => (
                  <img key={i} src={img.url} alt={img.name} style={{ width:'80px', height:'80px', objectFit:'cover', borderRadius:'8px', border:'1px solid #e2e8f0', cursor:'pointer' }} onClick={() => window.open(img.url, '_blank')} />
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{ padding:'14px 24px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'flex-end', flexShrink:0 }}>
          <button onClick={onClose} style={{ padding:'9px 20px', background:'#f1f5f9', color:'#0f172a', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'13px', fontWeight:'600' }}>Lukk</button>
        </div>
      </div>
    </div>
  )
}
// ─── END VERSION-VIEWER-MODAL ─────────────────────────────────────────────────

function fmtO(n) { return (Math.round(parseFloat(n)||0)).toLocaleString('nb-NO') + ' kr' }

// Global PDF-eksport for ordrer — kan kalles fra hvor som helst
async function exportOrderPDFGlobal(order, projects = [], mode = 'download') {
  const pdf = await createBrandedPdf()
  const { doc, pw, ph, ml, mr, cw, hex, setC, setF, setD } = pdf
  const projOrder = (projects || []).find(p => p.id === order.project_id)

  pdf.drawHeader('ORDREBEKREFTELSE', order.order_number || order.title || '')
  let y = pdf.y
  const addPage = () => { doc.addPage(); y = 14 }
  const checkSpace = (n) => { if (y + n > ph - 18) addPage() }

  setC(hex('#0f172a')); doc.setFontSize(16); doc.setFont('helvetica', 'bold')
  const titleLines = doc.splitTextToSize(order.title || 'Uten tittel', cw)
  doc.text(titleLines, ml, y)
  y += titleLines.length * 7 + 2

  const { grandTotal: gt } = calcOrder(order.chapters || [], order.global_markup)
  const st = ORDER_STATUS[order.status] || ORDER_STATUS['Utkast']
  setF(hex(st.bg)); doc.roundedRect(ml, y - 3, doc.getTextWidth(order.status || '') + 10, 6, 1.5, 1.5, 'F')
  setC(hex(st.color)); doc.setFontSize(9); doc.setFont('helvetica', 'bold')
  doc.text(order.status || '—', ml + 5, y + 1)
  if (gt) {
    setC(hex('#059669')); doc.setFontSize(14); doc.setFont('helvetica', 'bold')
    doc.text(Math.round(gt).toLocaleString('nb-NO') + ' kr', pw - mr, y + 1, { align: 'right' })
    setC(hex('#94a3b8')); doc.setFontSize(8); doc.setFont('helvetica', 'normal')
    doc.text('eks. mva', pw - mr, y + 5, { align: 'right' })
  }
  y += 12

  setF(hex('#f8fafc')); setD(hex('#e2e8f0'))
  const infoH = 30
  doc.roundedRect(ml, y, cw, infoH, 2, 2, 'FD')
  setC(hex('#64748b')); doc.setFontSize(8); doc.setFont('helvetica', 'bold')
  doc.text('KUNDE', ml + 4, y + 5)
  setC(hex('#0f172a')); doc.setFontSize(9); doc.setFont('helvetica', 'normal')
  doc.text(order.customer_name || '—', ml + 4, y + 10)
  if (order.customer_address) doc.text(order.customer_address, ml + 4, y + 14)
  if (order.customer_email) doc.text(order.customer_email, ml + 4, y + 18)

  setC(hex('#64748b')); doc.setFontSize(8); doc.setFont('helvetica', 'bold')
  doc.text('PROSJEKT', ml + cw/2 + 2, y + 5)
  setC(hex('#0f172a')); doc.setFontSize(9); doc.setFont('helvetica', 'normal')
  doc.text(projOrder?.name || '—', ml + cw/2 + 2, y + 10)
  if (order.delivery_date) doc.text(`Levering: ${order.delivery_date}`, ml + cw/2 + 2, y + 14)
  if (order.payment_terms) doc.text(`Bet.vilkår: ${order.payment_terms}`, ml + cw/2 + 2, y + 18)
  y += infoH + 6

  if (order.intro_text) {
    checkSpace(20)
    setC(hex('#0f172a')); doc.setFontSize(9); doc.setFont('helvetica', 'bold')
    doc.text('BESKRIVELSE', ml, y); y += 5
    setC(hex('#374151')); doc.setFontSize(9); doc.setFont('helvetica', 'normal')
    const introLines = doc.splitTextToSize(order.intro_text, cw)
    doc.text(introLines, ml, y)
    y += introLines.length * 4 + 6
  }

  ;(order.chapters || []).forEach((ch, chIdx) => {
    checkSpace(14)
    setC(hex('#0f172a')); doc.setFontSize(11); doc.setFont('helvetica', 'bold')
    doc.text(`${String(chIdx + 1).padStart(2, '0')}. ${ch.name || 'Kapittel'}`, ml, y); y += 5

    setC(hex('#94a3b8')); doc.setFontSize(7); doc.setFont('helvetica', 'bold')
    doc.text('BESKRIVELSE', ml, y)
    doc.text('MENGDE', ml + cw * 0.55, y, { align:'right' })
    doc.text('ENH', ml + cw * 0.62, y)
    doc.text('ARB.', ml + cw * 0.75, y, { align:'right' })
    doc.text('MAT.', ml + cw * 0.88, y, { align:'right' })
    doc.text('SUM', ml + cw, y, { align:'right' })
    y += 4
    setD(hex('#e2e8f0')); doc.line(ml, y, ml + cw, y); y += 2

    ;(ch.posts || []).forEach(p => {
      checkSpace(6)
      const qty = parseFloat(p.qty) || 0
      const pw2 = parseFloat(p.unitPriceWork) || 0
      const pm = parseFloat(p.unitPriceMaterial) || 0
      const sum = qty * (pw2 + pm)
      setC(hex('#0f172a')); doc.setFontSize(8); doc.setFont('helvetica', 'normal')
      const descLines = doc.splitTextToSize(p.description || '—', cw * 0.5)
      doc.text(descLines, ml, y + 3)
      doc.text(String(qty), ml + cw * 0.55, y + 3, { align:'right' })
      doc.text(p.unit || 'stk', ml + cw * 0.62, y + 3)
      doc.text(Math.round(pw2).toLocaleString('nb-NO'), ml + cw * 0.75, y + 3, { align:'right' })
      doc.text(Math.round(pm).toLocaleString('nb-NO'), ml + cw * 0.88, y + 3, { align:'right' })
      setC(hex('#059669')); doc.setFont('helvetica', 'bold')
      doc.text(Math.round(sum).toLocaleString('nb-NO') + ' kr', ml + cw, y + 3, { align:'right' })
      y += Math.max(descLines.length * 3, 5) + 1
    })
    y += 4
  })

  checkSpace(14)
  setD(hex('#059669')); doc.line(ml, y, ml + cw, y); y += 5
  setC(hex('#0f172a')); doc.setFontSize(11); doc.setFont('helvetica', 'bold')
  doc.text('Total eks. mva:', ml, y)
  setC(hex('#059669')); doc.setFontSize(13)
  doc.text(Math.round(gt).toLocaleString('nb-NO') + ' kr', ml + cw, y, { align:'right' })
  y += 6
  setC(hex('#64748b')); doc.setFontSize(9); doc.setFont('helvetica', 'normal')
  doc.text('Inkl. 25% mva:', ml, y)
  doc.text(Math.round(gt * 1.25).toLocaleString('nb-NO') + ' kr', ml + cw, y, { align:'right' })

  pdf.drawFooters()
  const safeTitle = (order.title || 'ordre').replace(/[^\wæøåÆØÅ-]/g, '_').substring(0, 40)
  const filename = `${order.order_number || 'Ordre'}_${safeTitle}.pdf`
  if (mode === 'base64') {
    const dataUri = doc.output('datauristring')
    const base64 = dataUri.split(',')[1] || dataUri
    return { base64, filename }
  }
  doc.save(filename)
}

// ── MAIN PAGE ─────────────────────────────────────────────────────────────────
function OrdrePage() {
  const { user } = useAuth()
  const [orders, setOrders] = useState([])
  const [quotes, setQuotes] = useState([])
  const [projects, setProjects] = useState([])
  const [loading, setLoading] = useState(true)
  const [filterStatus, setFilterStatus] = useState('alle')
  const [search, setSearch] = useState('')
  const [showNew, setShowNew] = useState(false)
  const [showFromQuote, setShowFromQuote] = useState(false)
  const [sendAfterSaveOrder, setSendAfterSaveOrder] = useState(null) // Ordre som skal sendes etter lagring
  const [selected, setSelected] = useState(null)
  React.useEffect(() => {
    if (selected && window.__enterDetailView) {
      window.__enterDetailView(() => setSelected(null))
    }
  }, [selected])

  const load = async () => {
    try {
      const [o, q, p] = await Promise.all([
        supabase.from('orders').select('*').order('created_at', { ascending:false }).then(r=>r.data||[]),
        supabase.from('quotes').select('*').eq('status','Akseptert').order('created_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('projects').select('id,name,parent_id,depth,project_number').order('name').then(r=>r.data||[])
      ])
      setOrders(o); setQuotes(q); setProjects(p)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(() => { load() }, [])

  const filtered = orders.filter(o => {
    if (filterStatus !== 'alle' && o.status !== filterStatus) return false
    if (search && ![o.title,o.order_number,o.customer_name].some(v=>v?.toLowerCase().includes(search.toLowerCase()))) return false
    return true
  })

  const counts = Object.keys(ORDER_STATUS).reduce((acc,s) => { acc[s]=orders.filter(o=>o.status===s).length; return acc }, {})
  const totalFullfort = orders.filter(o=>o.status==='Fullført').reduce((acc,o)=>acc+calcOrder(o.chapters||[],o.global_markup).grandTotal,0)

  const isMobO = typeof window !== 'undefined' && window.innerWidth < 768

  if (loading) return <div style={{ display:'flex',alignItems:'center',justifyContent:'center',minHeight:'60vh',fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px',height:'36px',border:'3px solid #e2e8f0',borderTop:'3px solid #059669',borderRadius:'50%',margin:'0 auto 12px',animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8',fontSize:'14px' }}>Laster ordrer...</p></div></div>
  if (selected) return <OrdreDetaljer order={selected} projects={projects} user={user} onBack={()=>{setSelected(null);load()}} />

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobO ? '16px' : '24px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px' }}>
          <div>
            <h1 style={{ fontSize: isMobO ? '18px' : '22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>📦 Ordre</h1>
            {!isMobO && <p style={{ color:'#64748b', marginTop:'4px', fontSize:'14px', marginBottom:0 }}>Ordrebehandling, bekreftelser og endringsmeldinger</p>}
          </div>
          <div style={{ display:'flex', gap:'6px', flexShrink:0 }}>
            {quotes.length > 0 && <button onClick={()=>setShowFromQuote(true)} style={{ background:'#7c3aed', color:'white', border:'none', borderRadius:'10px', padding: isMobO ? '9px 10px' : '10px 16px', fontSize: isMobO ? '11px' : '13px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>{isMobO ? '📋 Tilbud' : '📋 Fra tilbud'}</button>}
            <button onClick={()=>setShowNew(true)} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding: isMobO ? '9px 12px' : '11px 20px', fontSize: isMobO ? '12px' : '14px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>+ Ny ordre</button>
          </div>
        </div>
      </div>

      <div style={{ padding: isMobO ? '12px' : '24px 32px', display:'flex', flexDirection:'column', gap: isMobO ? '12px' : '20px', overflowX:'hidden' }}>
        {/* Stats */}
        <div style={{ display:'grid', gridTemplateColumns: isMobO ? 'repeat(3, 1fr)' : 'repeat(5,1fr) 1.3fr', gap: isMobO ? '8px' : '12px' }}>
          {['Utkast','Sendt','Bekreftet','Pågår','Fullført'].map(s => {
            const cfg = ORDER_STATUS[s]
            return (
              <button key={s} onClick={()=>setFilterStatus(filterStatus===s?'alle':s)}
                style={{ background:filterStatus===s?cfg.bg:'white', border:`1px solid ${filterStatus===s?cfg.border:'#f1f5f9'}`, borderRadius: isMobO ? '10px' : '14px', padding: isMobO ? '10px' : '14px', cursor:'pointer', textAlign: isMobO ? 'center' : 'left' }}>
                <div style={{ fontSize: isMobO ? '16px' : '20px', marginBottom: isMobO ? '4px' : '6px' }}>{cfg.emoji}</div>
                <div style={{ fontSize: isMobO ? '16px' : '20px', fontWeight:'800', color:filterStatus===s?cfg.color:'#0f172a' }}>{counts[s]||0}</div>
                <div style={{ fontSize: isMobO ? '10px' : '11px', color:filterStatus===s?cfg.color:'#94a3b8', fontWeight:'500', marginTop:'2px' }}>{s}</div>
              </button>
            )
          })}
          {!isMobO && <div style={{ background:'linear-gradient(135deg,#059669,#0891b2)', borderRadius:'14px', padding:'14px', color:'white' }}>
            <div style={{ fontSize:'20px', marginBottom:'6px' }}>💰</div>
            <div style={{ fontSize:'16px', fontWeight:'800' }}>{fmtO(totalFullfort)}</div>
            <div style={{ fontSize:'11px', opacity:0.85, fontWeight:'500', marginTop:'2px' }}>Fullført totalt</div>
          </div>}
        </div>

        {/* Filters */}
        <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding: isMobO ? '10px' : '14px 18px', display:'flex', gap: isMobO ? '8px' : '10px', alignItems:'center', flexWrap:'wrap' }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍  Søk..." style={{ ...oInp, maxWidth: isMobO ? '100%' : '260px', flex: isMobO ? '1 1 100%' : '1' }} />
          {(search||filterStatus!=='alle') && <button onClick={()=>{setSearch('');setFilterStatus('alle')}} style={{ background:'#f1f5f9', border:'none', borderRadius:'8px', padding:'9px 14px', fontSize:'13px', cursor:'pointer', color:'#64748b' }}>Nullstill</button>}
          <span style={{ marginLeft:'auto', fontSize:'13px', color:'#94a3b8' }}>{filtered.length} ordrer</span>
        </div>

        {/* List */}
        {filtered.length === 0 ? (
          <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'60px 20px', textAlign:'center' }}>
            <div style={{ fontSize:'40px', marginBottom:'12px' }}>📦</div>
            <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Ingen ordrer funnet</h3>
            <p style={{ margin:0, color:'#94a3b8', fontSize:'14px' }}>{orders.length===0?'Opprett din første ordre.':'Prøv å endre søk eller filter.'}</p>
          </div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            {filtered.map(o => {
              const cfg = ORDER_STATUS[o.status] || ORDER_STATUS['Utkast']
              const proj = projects.find(p=>p.id===o.project_id)
              const { grandTotal } = calcOrder(o.chapters||[], o.global_markup)
              return (
                <div key={o.id} onClick={()=>setSelected(o)}
                  style={{ background:'white', borderRadius: isMobO ? '12px' : '14px', border:'1px solid #f1f5f9', padding: isMobO ? '12px' : '16px 20px', cursor:'pointer', display:'flex', alignItems: isMobO ? 'flex-start' : 'center', gap: isMobO ? '10px' : '16px', transition:'box-shadow 0.15s' }}
                  onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 16px rgba(0,0,0,0.08)'} onMouseLeave={e=>e.currentTarget.style.boxShadow='none'}>
                  {!isMobO && <div style={{ width:'44px', height:'44px', borderRadius:'12px', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', flexShrink:0 }}>{cfg.emoji}</div>}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', alignItems:'center', gap: isMobO ? '6px' : '8px', flexWrap:'wrap', marginBottom:'4px' }}>
                      <span style={{ fontWeight:'700', color:'#0f172a', fontSize: isMobO ? '13px' : '15px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', maxWidth: isMobO ? 'calc(100vw - 120px)' : 'none' }}>{o.title}</span>
                      {!isMobO && <span style={{ fontSize:'12px', color:'#94a3b8', fontFamily:'monospace' }}>{o.order_number}</span>}
                      <OrderStatusBadge status={o.status} />
                      {o.quote_id && <span style={{ background:'#f5f3ff', color:'#7c3aed', fontSize:'11px', fontWeight:'600', padding:'2px 8px', borderRadius:'999px', border:'1px solid #ddd6fe' }}>Fra tilbud</span>}
                      {o.status === 'Sendt' && o.reminder_due_date && new Date(o.reminder_due_date) <= new Date() && (
                        <span title="Purring-frist passert" style={{ background:'#fef2f2', color:'#dc2626', fontSize:'11px', fontWeight:'700', padding:'2px 8px', borderRadius:'999px', border:'1px solid #fecaca' }}>⏰ Forfalt</span>
                      )}
                    </div>
                    <div style={{ display:'flex', gap: isMobO ? '6px' : '12px', flexWrap:'wrap' }}>
                      {o.customer_name && <span style={{ fontSize: isMobO ? '11px' : '12px', color:'#64748b' }}>👤 {o.customer_name}</span>}
                      {!isMobO && proj && <span style={{ fontSize:'12px', color:'#2563eb', fontWeight:'500' }}>🏗️ {proj.name}</span>}
                      {!isMobO && o.delivery_date && <span style={{ fontSize:'12px', color:'#64748b' }}>📅 {o.delivery_date}</span>}
                    </div>
                  </div>
                  <div style={{ textAlign:'right', flexShrink:0 }}>
                    <div style={{ fontWeight:'800', fontSize: isMobO ? '13px' : '15px', color:'#0f172a' }}>{fmtO(grandTotal)}</div>
                    {!isMobO && <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>eks. mva</div>}
                  </div>
                  {!isMobO && <span style={{ color:'#94a3b8', fontSize:'18px' }}>›</span>}
                </div>
              )
            })}
          </div>
        )}
      </div>

      {showNew && <OrdreEditorModal projects={projects} user={user} onClose={()=>setShowNew(false)} onSaved={(savedOrder, alsoSend)=>{
        setShowNew(false)
        load()
        if (alsoSend && savedOrder) {
          setSendAfterSaveOrder(savedOrder)
        }
      }} />}
      {sendAfterSaveOrder && <SendOrdreModal order={sendAfterSaveOrder} user={user} getPdfBase64={(ord) => exportOrderPDFGlobal(ord, projects, 'base64')} onClose={()=>setSendAfterSaveOrder(null)} onSent={()=>{setSendAfterSaveOrder(null);load()}} />}
      {showFromQuote && <FraIlbudModal quotes={quotes} projects={projects} user={user} onClose={()=>setShowFromQuote(false)} onSaved={()=>{setShowFromQuote(false);load()}} />}
    </div>
  )
}

function OrdreDetaljer({ order: init, projects, user, onBack }) {
  const confirm = useConfirm()
  const appAlert = useAppAlert()
  const [o, setO] = useState(init)
  const [changes, setChanges] = useState([])
  const [editing, setEditing] = useState(false)
  const [showSend, setShowSend] = useState(false)
  const [showReminder, setShowReminder] = useState(false)
  const [showResend, setShowResend] = useState(false)
  const [showNewChange, setShowNewChange] = useState(false)
  const cfg = ORDER_STATUS[o.status] || ORDER_STATUS['Utkast']
  const proj = projects.find(p=>p.id===o.project_id)
  const { grandTotal, chapterTotals } = calcOrder(o.chapters||[], o.global_markup)
  const changesTotal = changes.filter(c=>c.status==='Godkjent').reduce((acc,c)=>acc+(c.amount||0),0)

  const loadChanges = async () => {
    const { data } = await supabase.from('order_changes').select('*').eq('order_id',o.id).order('created_at')
    setChanges(data||[])
  }
  const refresh = async () => {
    const { data } = await supabase.from('orders').select('*').eq('id',o.id).single()
    if (data) setO(data)
  }
  useEffect(() => { loadChanges() }, [])

  const updateStatus = async (status) => {
    const existingLog = Array.isArray(o.activity_log) ? o.activity_log : []
    const newLog = [...existingLog, { action: `Status endret til ${status}`, by: user?.email, at: new Date().toISOString() }]
    const updates = { status, activity_log: newLog, updated_at: new Date().toISOString() }
    if (status==='Bekreftet') updates.confirmed_at = new Date().toISOString()
    if (status==='Fullført') updates.completed_at = new Date().toISOString()
    await supabase.from('orders').update(updates).eq('id',o.id)
    setO(v=>({...v,...updates}))
  }

  const handleDelete = async () => {
    if (!(await confirm({ message: 'Slett denne ordren?', subMessage: 'Ordren og alle endringsmeldinger slettes permanent.', danger: true }))) return
    await supabase.from('orders').delete().eq('id',o.id)
    onBack()
  }

  // ── PDF-eksport ────────────────────────────────────────────────────────────
  const [exportingPdf, setExportingPdf] = useState(false)
  const exportOrderPDF = async (order, mode = 'download') => {
    if (mode === 'download') setExportingPdf(true)
    try {
      return await exportOrderPDFGlobal(order, projects, mode)
    } catch(e) {
      console.error(e)
      if (mode === 'download') await appAlert({ message: 'Feil ved PDF-generering', subMessage: e.message, kind: 'error' })
      throw e
    } finally {
      if (mode === 'download') setExportingPdf(false)
    }
  }

  const [showUpsellInvoice, setShowUpsellInvoice] = useState(false)
  const [creatingInvoice, setCreatingInvoice] = useState(false)

  const createInvoice = async () => {
    try {
      // Sjekk om faktura-modulen er aktivert
      const { data: settings } = await supabase.from('company_settings').select('active_modules, subscription_status, trial_ends_at').limit(1).single()
      const activeModules = settings?.active_modules || []
      const fakturaInModules = activeModules.includes('faktura')
      const isTrialActive = settings?.subscription_status === 'trial' && settings?.trial_ends_at && new Date(settings.trial_ends_at) > new Date()
      const isAdmin = user?.email?.endsWith('@enplattform.no') || false
      const hasAccess = fakturaInModules || isTrialActive || isAdmin

      if (!hasAccess) {
        setShowUpsellInvoice(true)
        return
      }

      // Bekreftelsesdialog hvis ordren ikke er fullført
      if (o.status !== 'Fullført') {
        const ok = await confirm({
          message: 'Fakturere før ordren er fullført?',
          subMessage: `Ordren har status "${o.status}". Vanligvis sendes faktura etter at arbeidet er utført. Vil du fortsette med faktureringen likevel?`,
          confirmText: 'Ja, fakturer',
          cancelText: 'Avbryt',
        })
        if (!ok) return
      }

      setCreatingInvoice(true)

      // Hent eksisterende fakturaer for å generere nytt nummer
      const { data: existingInvoices } = await supabase.from('invoices').select('invoice_number')
      const newInvoiceNumber = nextInvoiceNumber(existingInvoices || [])

      // Bygg fakturalinjer fra ordrens kapitler
      // MERK: Ordrer bruker ch.posts (ikke ch.lines)
      console.log('[createInvoice] Ordrens chapters:', o.chapters)
      const lines = []
      ;(o.chapters || []).forEach((ch, chIdx) => {
        // Støtt både 'posts' (ny struktur) og 'lines' (evt. gammel struktur) — bakoverkompatibelt
        const items = ch.posts || ch.lines || []
        console.log(`[createInvoice] Kapittel ${chIdx} "${ch.name || ch.title || ''}" har ${items.length} linjer`)
        items.forEach((p, pIdx) => {
          const qty = parseFloat(p.qty) || 0
          const priceWork = parseFloat(p.unitPriceWork ?? p.unit_price_work) || 0
          const priceMat = parseFloat(p.unitPriceMaterial ?? p.unit_price_material) || 0
          const unitPrice = priceWork + priceMat
          console.log(`[createInvoice]   Post ${pIdx}: qty=${qty}, work=${priceWork}, mat=${priceMat}, total=${unitPrice}`, p)

          // Legg til linjen selv om pris er 0 — bruker kan justere i fakturautkastet
          if (p.description || qty > 0 || unitPrice > 0) {
            const chapterLabel = ch.name || ch.title || ''
            lines.push({
              description: (chapterLabel ? `[${chapterLabel}] ` : '') + (p.description || 'Uten beskrivelse'),
              qty: qty || 1,
              unit: p.unit || 'stk',
              unitPrice: unitPrice, // MERK: invoice-koden bruker camelCase (l.unitPrice)
              mvaRate: 0.25, // MERK: mvaRate lagres som desimal (0.25), ikke prosent (25)
            })
          }
        })
      })
      console.log('[createInvoice] Bygde', lines.length, 'fakturalinjer fra ordren:', lines)

      // Hent selskapsinfo — gjør dette feiltolerant for å unngå at manglende kolonner
      // sprengaerhele createInvoice-flyten
      let cs = null
      try {
        const { data } = await supabase.from('company_settings').select('*').limit(1).single()
        cs = data
      } catch(settingsErr) {
        console.warn('[createInvoice] Kunne ikke hente company_settings:', settingsErr)
      }

      const today = new Date().toISOString().split('T')[0]
      const dueDate = new Date()
      dueDate.setDate(dueDate.getDate() + 14)

      // Opprett faktura som Utkast — med kobling til ordren
      const { data: newInvoice, error } = await supabase.from('invoices').insert({
        title: o.title || `Faktura for ${o.order_number}`,
        invoice_number: newInvoiceNumber,
        project_id: o.project_id,
        customer_id: o.customer_id || null,
        customer_name: o.customer_name,
        customer_email: o.customer_email,
        customer_address: o.customer_address,
        customer_orgnr: o.customer_orgnr,
        our_name: cs?.name || '',
        our_address: cs?.address || '',
        our_orgnr: cs?.orgnr || '',
        bank_account: cs?.bank_account || '',
        invoice_date: today,
        due_date: dueDate.toISOString().split('T')[0],
        payment_terms: o.payment_terms || '14 dager netto',
        lines,
        notes: `Faktura basert på ordre ${o.order_number}`,
        status: 'Utkast',
        from_order_id: o.id,
        from_order_number: o.order_number,
        created_by: user?.id,
      }).select().single()

      if (error) throw error

      // Bruk sessionStorage som "drop-off": FakturaPage leser dette når den mounter
      sessionStorage.setItem('openInvoiceId', newInvoice.id)

      // Naviger til faktura-modulen via den globale navigate-funksjonen
      // Denne rydder opp detail-cleanup og setter page korrekt
      if (window.__navigate) {
        window.__navigate('faktura')
      } else {
        // Fallback hvis navigate ikke er tilgjengelig
        window.history.pushState({ page: 'faktura' }, '', '#faktura')
        window.dispatchEvent(new PopStateEvent('popstate', { state: { page: 'faktura' } }))
      }

      // Gi FakturaPage tid til å mount og lese sessionStorage
      await new Promise(resolve => setTimeout(resolve, 300))

      // Vis popup — brukeren ser fakturautkastet BAK popupen
      await appAlert({
        message: 'Faktura opprettet som utkast',
        subMessage: `Faktura ${newInvoiceNumber} er klar til gjennomgang. Ordrestatus oppdateres først når fakturaen er sendt.`,
        kind: 'success',
      })
    } catch(e) {
      console.error('[createInvoice] Feil:', e)
      await appAlert({ message: 'Kunne ikke opprette faktura', subMessage: e.message, kind: 'error' })
    } finally {
      setCreatingInvoice(false)
    }
  }

  const isMobOD = typeof window !== 'undefined' && window.innerWidth < 768

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <style>{`@media print { .no-print{display:none!important} }`}</style>
      <div className="no-print" style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobOD ? '14px' : '20px 32px' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#64748b', fontSize:'13px', marginBottom:'10px', display:'flex', alignItems:'center', gap:'6px', padding:0 }}>← Tilbake til ordrer</button>
        <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap: isMobOD ? '8px' : '16px', flexWrap: isMobOD ? 'wrap' : 'nowrap' }}>
          <div style={{ display:'flex', alignItems:'flex-start', gap: isMobOD ? '10px' : '14px', flex:1, minWidth:0 }}>
            {!isMobOD && <div style={{ width:'52px', height:'52px', borderRadius:'14px', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px', flexShrink:0 }}>{cfg.emoji}</div>}
            <div style={{ minWidth:0 }}>
              <div style={{ display:'flex', alignItems:'center', gap: isMobOD ? '6px' : '10px', flexWrap:'wrap', marginBottom:'4px' }}>
                <h1 style={{ margin:0, fontSize: isMobOD ? '16px' : '20px', fontWeight:'bold', color:'#0f172a' }}>{o.title}</h1>
                {!isMobOD && <span style={{ fontSize:'13px', color:'#94a3b8', fontFamily:'monospace' }}>{o.order_number}</span>}
                <OrderStatusBadge status={o.status} />
              </div>
              <div style={{ display:'flex', gap:'12px', flexWrap:'wrap' }}>
                {o.customer_name && <span style={{ fontSize:'13px', color:'#64748b' }}>👤 {o.customer_name}</span>}
                {proj && <span style={{ fontSize:'13px', color:'#2563eb', fontWeight:'500' }}>🏗️ {proj.name}</span>}
              </div>
            </div>
          </div>
          <div style={{ display:'flex', gap: isMobOD ? '6px' : '8px', flexShrink:0, flexWrap:'wrap' }}>
            {o.status==='Utkast' && <button onClick={()=>setShowSend(true)} style={{ padding: isMobOD ? '7px 10px' : '9px 14px', background:'#2563eb', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobOD ? '11px' : '13px', fontWeight:'600' }}>{isMobOD ? '📧 Send' : '📧 Send bekreftelse'}</button>}
            {o.status === 'Sendt' && (() => {
              const isOverdue = o.reminder_due_date && new Date(o.reminder_due_date) <= new Date()
              return (
                <>
                  {isOverdue && <button onClick={()=>setShowReminder(true)} style={{ padding: isMobOD ? '7px 10px' : '9px 14px', background:'#dc2626', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobOD ? '11px' : '13px', fontWeight:'600' }}>{isMobOD ? '⚠️ Purr' : '⚠️ Send purring'}</button>}
                  <button onClick={()=>setShowResend(true)} style={{ padding: isMobOD ? '7px 10px' : '9px 14px', background:'#7c3aed', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobOD ? '11px' : '13px', fontWeight:'600' }}>{isMobOD ? '🔁 Ny' : '🔁 Send på nytt'}</button>
                </>
              )
            })()}
            {o.status !== 'Fakturert' && o.status !== 'Avslått' && <button onClick={createInvoice} disabled={creatingInvoice} style={{ padding: isMobOD ? '7px 10px' : '9px 14px', background: creatingInvoice ? '#86efac' : '#059669', color:'white', border:'none', borderRadius:'10px', cursor: creatingInvoice ? 'wait' : 'pointer', fontSize: isMobOD ? '11px' : '13px', fontWeight:'600' }}>{creatingInvoice ? '⏳' : (isMobOD ? '🧾 Faktura' : '🧾 Send til faktura')}</button>}
            <button onClick={()=>setEditing(true)} style={{ padding: isMobOD ? '7px 10px' : '9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobOD ? '12px' : '13px' }}>✏️</button>
            <button onClick={handleDelete} style={{ padding: isMobOD ? '7px 10px' : '9px 12px', border:'1px solid #fecaca', borderRadius:'10px', background:'white', cursor:'pointer', color:'#dc2626', fontSize: isMobOD ? '12px' : '13px' }}>🗑️</button>
          </div>
        </div>
      </div>

      <div style={{ padding: isMobOD ? '12px' : '24px 32px', display:'grid', gridTemplateColumns: isMobOD ? '1fr' : '2fr 1fr', gap: isMobOD ? '12px' : '20px' }}>
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          {/* Header info */}
          <div style={oCard}>
            <div style={{ display:'grid', gridTemplateColumns: isMobOD ? '1fr' : '1fr 1fr', gap: isMobOD ? '12px' : '16px' }}>
              <div>
                <div style={{ fontSize:'12px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'10px' }}>Kunde</div>
                {[['Navn',o.customer_name],['Adresse',o.customer_address],['Org.nr',o.customer_orgnr],['E-post',o.customer_email]].filter(r=>r[1]).map(([k,v])=>(
                  <div key={k} style={{ marginBottom:'5px', fontSize:'13px' }}><span style={{ color:'#94a3b8' }}>{k}: </span><span style={{ color:'#0f172a', fontWeight:'500' }}>{v}</span></div>
                ))}
              </div>
              <div>
                <div style={{ fontSize:'12px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'10px' }}>Ordreinfo</div>
                {[['Ordrenr.',o.order_number],['Dato',o.created_at?.split('T')[0]],['Levering',o.delivery_date],['Betalingsbetingelser',o.payment_terms]].filter(r=>r[1]).map(([k,v])=>(
                  <div key={k} style={{ marginBottom:'5px', fontSize:'13px' }}><span style={{ color:'#94a3b8' }}>{k}: </span><span style={{ color:'#0f172a', fontWeight:'500' }}>{v}</span></div>
                ))}
              </div>
            </div>
            {o.intro_text && <p style={{ margin:'14px 0 0', fontSize:'14px', color:'#475569', lineHeight:1.6, borderTop:'1px solid #f1f5f9', paddingTop:'12px' }}>{o.intro_text}</p>}
          </div>

          {/* Chapters */}
          {(o.chapters||[]).map((ch,ci) => {
            const { sum, total } = calcOrderChapter(ch)
            return (
              <div key={ci} style={oCard}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom: isMobOD ? '10px' : '14px', gap:'8px' }}>
                  <h3 style={{ margin:0, fontSize: isMobOD ? '13px' : '15px', fontWeight:'700', color:'#0f172a', minWidth:0, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{String(ci+1).padStart(2,'0')}. {ch.title}</h3>
                  <div style={{ textAlign:'right' }}>
                    {ch.markup>0 && <div style={{ fontSize:'11px', color:'#94a3b8' }}>Påslag {ch.markup}%</div>}
                    <div style={{ fontWeight:'700', color:'#059669', fontSize:'14px' }}>{fmtO(total)}</div>
                  </div>
                </div>
                {isMobOD ? (
                  <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                    {(ch.posts||[]).map((p,pi) => {
                      const ls=(parseFloat(p.qty)||0)*((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0))
                      return (
                        <div key={pi} style={{ background:'#f8fafc', borderRadius:'8px', padding:'10px 12px' }}>
                          <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'4px' }}>
                            <span style={{ fontWeight:'600', fontSize:'12px', color:'#0f172a' }}>{p.description||'—'}</span>
                            <span style={{ fontWeight:'700', fontSize:'12px', color:'#059669', whiteSpace:'nowrap', marginLeft:'8px' }}>{fmtO(ls)}</span>
                          </div>
                          <div style={{ display:'flex', gap:'8px', fontSize:'11px', color:'#64748b' }}>
                            <span>{p.qty} {p.unit}</span>
                            {p.unitPriceWork>0 && <span>Arb: {fmtO(p.unitPriceWork)}</span>}
                            {p.unitPriceMaterial>0 && <span>Mat: {fmtO(p.unitPriceMaterial)}</span>}
                          </div>
                        </div>
                      )
                    })}
                  </div>
                ) : (
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:'13px' }}>
                  <thead><tr style={{ background:'#f8fafc' }}>
                    {['Beskrivelse','Mengde','Enhet','Arbeid/enh','Material/enh','Sum'].map(h=><th key={h} style={{ padding:'8px 10px', textAlign:['Arbeid/enh','Material/enh','Sum'].includes(h)?'right':'left', color:'#64748b', fontWeight:'600', fontSize:'11px', textTransform:'uppercase', borderBottom:'1px solid #f1f5f9' }}>{h}</th>)}
                  </tr></thead>
                  <tbody>
                    {(ch.posts||[]).map((p,pi) => {
                      const ls=(parseFloat(p.qty)||0)*((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0))
                      return <tr key={pi} style={{ borderBottom:'1px solid #f8fafc' }}>
                        <td style={{ padding:'9px 10px', color:'#0f172a', fontWeight:'500' }}>{p.description||'—'}</td>
                        <td style={{ padding:'9px 10px', textAlign:'right', color:'#475569' }}>{p.qty}</td>
                        <td style={{ padding:'9px 10px', color:'#475569' }}>{p.unit}</td>
                        <td style={{ padding:'9px 10px', textAlign:'right', color:'#475569' }}>{p.unitPriceWork?fmtO(p.unitPriceWork):'—'}</td>
                        <td style={{ padding:'9px 10px', textAlign:'right', color:'#475569' }}>{p.unitPriceMaterial?fmtO(p.unitPriceMaterial):'—'}</td>
                        <td style={{ padding:'9px 10px', textAlign:'right', fontWeight:'700', color:'#0f172a' }}>{fmtO(ls)}</td>
                      </tr>
                    })}
                  </tbody>
                </table>
                )}
              </div>
            )
          })}

          {/* Totals */}
          <div style={{ ...oCard, background:'#f8fafc' }}>
            <div style={{ display:'flex', flexDirection:'column', gap:'8px', maxWidth: isMobOD ? '100%' : '320px', marginLeft: isMobOD ? '0' : 'auto' }}>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', color:'#475569' }}><span>Ordresum</span><span style={{ fontWeight:'600' }}>{fmtO(chapterTotals)}</span></div>
              {changes.filter(c=>c.status==='Godkjent').length>0 && <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', color:'#d97706' }}><span>Endringsmeldinger</span><span style={{ fontWeight:'600' }}>+{fmtO(changesTotal)}</span></div>}
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'17px', fontWeight:'800', color:'#0f172a', borderTop:'2px solid #e2e8f0', paddingTop:'10px' }}><span>Total eks. mva</span><span style={{ color:'#059669' }}>{fmtO(grandTotal+changesTotal)}</span></div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'13px', color:'#94a3b8' }}><span>Mva 25%</span><span>{fmtO((grandTotal+changesTotal)*0.25)}</span></div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'15px', fontWeight:'700', color:'#0f172a' }}><span>Total inkl. mva</span><span>{fmtO((grandTotal+changesTotal)*1.25)}</span></div>
            </div>
          </div>

          {/* Endringsmeldinger */}
          {changes.length > 0 && (
            <div style={oCard}>
              <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>🔄 Endringsmeldinger ({changes.length})</h3>
              <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                {changes.map(c => {
                  const sCfg = c.status==='Godkjent'?{bg:'#f0fdf4',color:'#16a34a',border:'#bbf7d0'}:c.status==='Sendt'?{bg:'#eff6ff',color:'#2563eb',border:'#bfdbfe'}:c.status==='Avslått'?{bg:'#fef2f2',color:'#dc2626',border:'#fecaca'}:{bg:'#f8fafc',color:'#64748b',border:'#e2e8f0'}
                  return (
                    <div key={c.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:'#f8fafc', borderRadius:'10px', padding:'12px 16px', border:'1px solid #f1f5f9' }}>
                      <div style={{ flex:1 }}>
                        <div style={{ fontWeight:'700', fontSize:'13px', color:'#0f172a' }}>{c.change_number} – {c.title}</div>
                        {c.description && <div style={{ fontSize:'12px', color:'#64748b', marginTop:'2px' }}>{c.description}</div>}
                      </div>
                      <span style={{ background:sCfg.bg, color:sCfg.color, border:`1px solid ${sCfg.border}`, padding:'3px 10px', borderRadius:'999px', fontSize:'12px', fontWeight:'600' }}>{c.status}</span>
                      <span style={{ fontWeight:'800', color:'#0f172a', fontSize:'14px', minWidth:'80px', textAlign:'right' }}>+{fmtO(c.amount)}</span>
                    </div>
                  )
                })}
              </div>
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="no-print" style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          <div style={oCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🔄 Status</h3>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {Object.keys(ORDER_STATUS).map(s=>(
                <button key={s} onClick={()=>updateStatus(s)} disabled={o.status===s}
                  style={{ padding:'9px 14px', borderRadius:'10px', border:`1px solid ${o.status===s?ORDER_STATUS[s].border:'#e2e8f0'}`, background:o.status===s?ORDER_STATUS[s].bg:'white', color:o.status===s?ORDER_STATUS[s].color:'#475569', fontWeight:o.status===s?'700':'400', fontSize:'13px', cursor:o.status===s?'default':'pointer', textAlign:'left', width:'100%' }}>
                  {o.status===s?'✓ ':''}{ORDER_STATUS[s].emoji} {s}
                </button>
              ))}
            </div>
          </div>
          <div style={oCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>💰 Oppsummering</h3>
            <div style={{ background:'#f0fdf4', borderRadius:'10px', padding:'14px', textAlign:'center', border:'1px solid #bbf7d0' }}>
              <div style={{ fontSize:'11px', color:'#16a34a', fontWeight:'600', textTransform:'uppercase', marginBottom:'4px' }}>Total eks. mva</div>
              <div style={{ fontSize:'22px', fontWeight:'800', color:'#0f172a' }}>{fmtO(grandTotal+changesTotal)}</div>
            </div>
            <div style={{ marginTop:'10px', display:'flex', flexDirection:'column', gap:'4px' }}>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'12px', color:'#94a3b8' }}><span>Mva 25%</span><span>{fmtO((grandTotal+changesTotal)*0.25)}</span></div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'13px', fontWeight:'700', color:'#0f172a' }}><span>Inkl. mva</span><span>{fmtO((grandTotal+changesTotal)*1.25)}</span></div>
            </div>
          </div>
          <div style={oCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>ℹ️ Detaljer</h3>
            {[['Prosjekt',proj?.name],['Levering',o.delivery_date],['Betaling',o.payment_terms],['Bekreftet',o.confirmed_at?new Date(o.confirmed_at).toLocaleDateString('nb-NO'):null],['Fullført',o.completed_at?new Date(o.completed_at).toLocaleDateString('nb-NO'):null]].filter(r=>r[1]).map(([k,v],i)=>(
              <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize:'13px' }}>
                <span style={{ color:'#94a3b8' }}>{k}</span><span style={{ fontWeight:'500', color:'#0f172a', textAlign:'right', maxWidth:'55%' }}>{v}</span>
              </div>
            ))}
          </div>

          {/* Aktivitetslogg */}
          <div style={oCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>📋 Aktivitetslogg</h3>
            {Array.isArray(o.activity_log) && o.activity_log.length > 0 ? (
              <div style={{ display:'flex', flexDirection:'column', gap:'2px', maxHeight:'280px', overflowY:'auto' }}>
                {[...o.activity_log].reverse().map((log, i) => (
                  <div key={i} style={{ padding:'8px 10px', borderBottom: i < o.activity_log.length - 1 ? '1px solid #f8fafc' : 'none', fontSize:'13px' }}>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', gap:'8px', flexWrap:'wrap' }}>
                      <span style={{ color:'#0f172a', fontWeight:'500' }}>{log.action}</span>
                      <span style={{ color:'#94a3b8', fontSize:'11px', whiteSpace:'nowrap' }}>
                        {new Date(log.at).toLocaleString('nb-NO', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit' })}
                      </span>
                    </div>
                    {(log.by || log.to) && (
                      <div style={{ fontSize:'11px', color:'#64748b', marginTop:'2px' }}>
                        {log.by && <span>{log.by}</span>}
                        {log.to && <span> → {log.to}</span>}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            ) : (
              <p style={{ margin:0, fontSize:'13px', color:'#94a3b8' }}>Ingen aktivitet registrert</p>
            )}
          </div>
        </div>
      </div>

      {editing && <OrdreEditorModal projects={projects} user={user} initial={o} onClose={()=>setEditing(false)} onSaved={(_savedOrder, alsoSend)=>{
        setEditing(false)
        refresh()
        if (alsoSend) {
          setShowSend(true)
        }
      }} />}
      {showSend && <SendOrdreModal order={o} user={user} getPdfBase64={(ord) => exportOrderPDF(ord, 'base64')} onClose={()=>setShowSend(false)} onSent={()=>{setShowSend(false);refresh()}} />}
      {showReminder && <SendOrderReminderModal order={o} user={user} getPdfBase64={(ord) => exportOrderPDF(ord, 'base64')} onClose={()=>setShowReminder(false)} onSent={()=>{setShowReminder(false);refresh()}} />}
      {showResend && <ResendOrderModal order={o} user={user} getPdfBase64={(ord) => exportOrderPDF(ord, 'base64')} onClose={()=>setShowResend(false)} onSent={()=>{setShowResend(false);refresh()}} />}
      {showNewChange && <EndringsmeldingModal order={o} user={user} existingCount={changes.length} onClose={()=>setShowNewChange(false)} onSaved={()=>{setShowNewChange(false);loadChanges()}} />}
      {showUpsellInvoice && <FakturaUpsellModal onClose={()=>setShowUpsellInvoice(false)} />}
    </div>
  )
}

// ─── FAKTURA UPSELL MODAL ────────────────────────────────────────────────────
function FakturaUpsellModal({ onClose }) {
  const isMob = typeof window !== 'undefined' && window.innerWidth < 768
  return (
    <div style={{ position:'fixed', inset:0, zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px', fontFamily:'system-ui, sans-serif' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'520px', maxHeight:'90vh', overflowY:'auto', boxShadow:'0 20px 60px rgba(0,0,0,0.25)' }}>
        {/* Header med gradient */}
        <div style={{ background:'linear-gradient(135deg, #059669 0%, #10b981 100%)', padding: isMob ? '24px 20px' : '32px 28px', color:'white', borderRadius:'20px 20px 0 0' }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'14px' }}>
            <div style={{ fontSize:'36px' }}>🧾</div>
            <button onClick={onClose} style={{ background:'rgba(255,255,255,0.2)', border:'none', color:'white', fontSize:'18px', cursor:'pointer', width:'32px', height:'32px', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center' }}>×</button>
          </div>
          <h2 style={{ margin:'0 0 8px', fontSize: isMob ? '20px' : '24px', fontWeight:'800' }}>Lås opp Faktura-modulen</h2>
          <p style={{ margin:0, fontSize:'14px', opacity:0.95, lineHeight:1.5 }}>
            Få ordre til faktura med ett klikk — ingen manuell inntasting, ingen glemte detaljer.
          </p>
        </div>

        {/* Fordeler */}
        <div style={{ padding: isMob ? '20px' : '28px' }}>
          <div style={{ fontSize:'13px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'14px' }}>Hva du får</div>
          <div style={{ display:'flex', flexDirection:'column', gap:'14px', marginBottom:'24px' }}>
            {[
              { icon:'⚡', title:'Ett-klikks fakturering', text:'Send ordre og endringsmeldinger direkte til faktura — alle data overføres automatisk' },
              { icon:'📋', title:'Profesjonelle fakturaer', text:'KID-nummer, bankkonto, forfallsdatoer og betalingsbetingelser ferdig utfylt' },
              { icon:'🔔', title:'Automatisk purring', text:'Få varsel ved forfall og send purring med ett trykk' },
              { icon:'📊', title:'Full oversikt', text:'Se utestående, purrede og betalte fakturaer i én oversikt' },
              { icon:'💳', title:'Kreditnotaer', text:'Opprett kreditnota direkte fra en eksisterende faktura hvis noe må justeres' },
            ].map((f, i) => (
              <div key={i} style={{ display:'flex', gap:'12px', alignItems:'flex-start' }}>
                <div style={{ fontSize:'20px', flexShrink:0, width:'36px', height:'36px', background:'#f0fdf4', borderRadius:'10px', display:'flex', alignItems:'center', justifyContent:'center' }}>{f.icon}</div>
                <div>
                  <div style={{ fontSize:'14px', fontWeight:'700', color:'#0f172a', marginBottom:'2px' }}>{f.title}</div>
                  <div style={{ fontSize:'13px', color:'#64748b', lineHeight:1.5 }}>{f.text}</div>
                </div>
              </div>
            ))}
          </div>

          {/* CTA-knapper */}
          <div style={{ display:'flex', flexDirection: isMob ? 'column' : 'row', gap:'10px' }}>
            <button onClick={() => { onClose(); window.location.hash = '#minbedrift' }}
              style={{ flex:1, padding:'14px 20px', background:'#059669', color:'white', border:'none', borderRadius:'12px', fontSize:'15px', fontWeight:'700', cursor:'pointer', boxShadow:'0 4px 12px rgba(5,150,105,0.25)' }}>
              Aktiver Faktura-modulen →
            </button>
            <button onClick={onClose}
              style={{ padding:'14px 20px', background:'white', color:'#64748b', border:'1px solid #e2e8f0', borderRadius:'12px', fontSize:'14px', fontWeight:'600', cursor:'pointer' }}>
              Ikke nå
            </button>
          </div>

          <div style={{ marginTop:'16px', textAlign:'center', fontSize:'12px', color:'#94a3b8' }}>
            💡 Alle moduler kan prøves gratis i prøveperioden
          </div>
        </div>
      </div>
    </div>
  )
}
// ─── END FAKTURA UPSELL MODAL ────────────────────────────────────────────────

function OrdreEditorModal({ projects, user, initial, onClose, onSaved }) {
  const isEdit = !!initial
  const [step, setStep] = useState(1)
  const [form, setForm] = useState({
    title: initial?.title||'', order_number: initial?.order_number||'',
    project_id: initial?.project_id||'', customer_name: initial?.customer_name||'', customer_email: initial?.customer_email||'',
    customer_address: initial?.customer_address||'', customer_orgnr: initial?.customer_orgnr||'',
    customer_id: initial?.customer_id || null,
    delivery_date: initial?.delivery_date||'', payment_terms: initial?.payment_terms||'30 dager netto',
    intro_text: initial?.intro_text||'', outro_text: initial?.outro_text||'',
    global_markup: initial?.global_markup||0,
  })
  // Generer sekvensielt nummer ved nyopprettelse
  useEffect(() => {
    if (!isEdit && !form.order_number) {
      supabase.from('orders').select('order_number').then(({ data }) => {
        setForm(f => ({ ...f, order_number: nextSequenceNumber(data || [], 'ORD', 'order_number') }))
      })
    }
  }, [])
  const [chapters, setChapters] = useState(initial?.chapters||[
    { id:Date.now(), title:'Generelt', markup:0, posts:[{id:Date.now()+1,description:'',qty:1,unit:'stk',unitPriceWork:0,unitPriceMaterial:0}] }
  ])
  const [saving, setSaving] = useState(false)
  const set = (k,v) => setForm(f=>({...f,[k]:v}))

  const addChapter = () => setChapters(c=>[...c,{id:Date.now(),title:`Kapittel ${c.length+1}`,markup:0,posts:[{id:Date.now()+1,description:'',qty:1,unit:'stk',unitPriceWork:0,unitPriceMaterial:0}]}])
  const removeChapter = (id) => setChapters(c=>c.filter(x=>x.id!==id))
  const updateChapter = (id,f,v) => setChapters(c=>c.map(x=>x.id===id?{...x,[f]:v}:x))
  const addPost = (chId) => setChapters(c=>c.map(x=>x.id===chId?{...x,posts:[...x.posts,{id:Date.now(),description:'',qty:1,unit:'stk',unitPriceWork:0,unitPriceMaterial:0}]}:x))
  const removePost = (chId,pId) => setChapters(c=>c.map(x=>x.id===chId?{...x,posts:x.posts.filter(p=>p.id!==pId)}:x))
  const updatePost = (chId,pId,f,v) => setChapters(c=>c.map(x=>x.id===chId?{...x,posts:x.posts.map(p=>p.id===pId?{...p,[f]:v}:p)}:x))

  const handleSave = async (alsoSend = false) => {
    if (!form.title.trim()) return alert('Tittel er påkrevd')
    setSaving(true)
    try {
      const { customerId } = await resolveCustomerFromForm({
        form,
        user,
        initialCustomerId: initial?.customer_id,
        statusOnCreate: 'ordre_bekreftet',
      })
      const payload = sanitizeDbPayload({ ...form, chapters, project_id:form.project_id||null, customer_id: customerId, updated_at:new Date().toISOString() })

      let savedOrder = null
      if (isEdit) {
        const existingLog = Array.isArray(initial.activity_log) ? initial.activity_log : []
        const newLog = [...existingLog, { action: 'Endret', by: user?.email, at: new Date().toISOString() }]
        const { data, error } = await supabase.from('orders').update({ ...payload, activity_log: newLog }).eq('id', initial.id).select().single()
        if (error) throw error
        savedOrder = data
      } else {
        const createdLog = [{ action: 'Opprettet', by: user?.email, at: new Date().toISOString() }]
        const { data, error } = await supabase.from('orders').insert({
          ...payload,
          status: 'Utkast',
          activity_log: createdLog,
          created_by: user?.id,
        }).select().single()
        if (error) throw error
        savedOrder = data
      }
      onSaved(savedOrder, alsoSend)
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  const lbl = t => <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>{t}</label>
  const { grandTotal } = calcOrder(chapters, form.global_markup)
  const isMobOE = typeof window !== 'undefined' && window.innerWidth < 768

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems: isMobOE ? 'stretch' : 'center', justifyContent:'center', padding: isMobOE ? '0' : '16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius: isMobOE ? '0' : '20px', width:'100%', maxWidth: isMobOE ? '100%' : '900px', maxHeight: isMobOE ? '100vh' : '94vh', height: isMobOE ? '100vh' : 'auto', display:'flex', flexDirection:'column', boxShadow: isMobOE ? 'none' : '0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding: isMobOE ? '12px 14px' : '18px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', alignItems:'center', justifyContent:'space-between', flexShrink:0, gap:'8px' }}>
          <div style={{ display:'flex', alignItems:'center', gap: isMobOE ? '8px' : '16px', flex:1, minWidth:0 }}>
            <h2 style={{ margin:0, fontSize: isMobOE ? '14px' : '18px', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>📦 {isEdit?'Rediger':'Ny'} ordre</h2>
            <div style={{ display:'flex', gap:'4px' }}>
              {[['1', isMobOE ? 'Info' : 'Informasjon'],['2', isMobOE ? 'Poster' : 'Linjer & Poster']].map(([n,l])=>(
                <button key={n} onClick={()=>setStep(+n)} style={{ padding: isMobOE ? '4px 10px' : '6px 14px', borderRadius:'8px', border:'none', background:step===+n?'#059669':'#f1f5f9', color:step===+n?'white':'#64748b', fontWeight:step===+n?'700':'500', fontSize: isMobOE ? '11px' : '13px', cursor:'pointer' }}>{n}. {l}</button>
              ))}
            </div>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap: isMobOE ? '6px' : '10px', flexShrink:0 }}>
            {!isMobOE && <span style={{ fontSize:'13px', color:'#94a3b8' }}>Total: <strong style={{ color:'#059669' }}>{fmtO(grandTotal)}</strong></span>}
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
          </div>
        </div>

        <div style={{ overflowY:'auto', flex:1, padding: isMobOE ? '14px' : '24px', WebkitOverflowScrolling:'touch' }}>
          {step===1 && (
            <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'14px' }}>
              <div style={{ gridColumn:'1/-1' }}>{lbl('Tittel *')}<input value={form.title} onChange={e=>set('title',e.target.value)} placeholder="F.eks. Orden betongarbeider Blokk B" style={oInp} /></div>
              <div>{lbl('Ordrenummer')}<input value={form.order_number} onChange={e=>set('order_number',e.target.value)} style={oInp} /></div>
              <div>{lbl('Knytt til prosjekt')}<SearchableProjectSelect value={form.project_id} onChange={v => set('project_id', v)} projects={projects} style={oInp} placeholder="Ingen" /></div>
              <div style={{ gridColumn:'1/-1', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}><div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', marginBottom:'12px' }}>👤 Kundeinformasjon</div></div>
              <div style={{ gridColumn:'1/-1' }}>
                {lbl('Velg eksisterende kunde')}
                <CustomerSelect
                  value={form.customer_id}
                  valueAsId
                  onChange={v => set('customer_id', v)}
                  onSelect={c => {
                    set('customer_id', c.id)
                    set('customer_name', c.name || '')
                    if (c.email) set('customer_email', c.email)
                    if (c.address) set('customer_address', c.address)
                    if (c.orgnr) set('customer_orgnr', c.orgnr)
                  }}
                  placeholder="Søk etter kunde — eller fyll ut feltene under for ny kunde"
                />
                <p style={{ margin:'4px 0 0', fontSize:'11px', color:'#94a3b8' }}>Velger du eksisterende kunde, autofylles feltene under. Manuell utfylling oppretter ny kunde automatisk.</p>
              </div>
              <div>{lbl('Kundenavn')}<input value={form.customer_name} onChange={e=>set('customer_name',e.target.value)} placeholder="Navn / firma" style={oInp} /></div>
              <div>{lbl('E-post')}<input type="email" value={form.customer_email} onChange={e=>set('customer_email',e.target.value)} placeholder="kunde@epost.no" style={oInp} /></div>
              <div>{lbl('Adresse')}<input value={form.customer_address} onChange={e=>set('customer_address',e.target.value)} placeholder="Gateadresse" style={oInp} /></div>
              <div>{lbl('Org.nr')}<input value={form.customer_orgnr} onChange={e=>set('customer_orgnr',e.target.value)} placeholder="123 456 789" style={oInp} /></div>
              <div style={{ gridColumn:'1/-1', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}><div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', marginBottom:'12px' }}>📅 Betingelser</div></div>
              <div>{lbl('Leveringsdato')}<input type="date" value={form.delivery_date} onChange={e=>set('delivery_date',e.target.value)} style={oInp} /></div>
              <div>{lbl('Betalingsbetingelser')}<input value={form.payment_terms} onChange={e=>set('payment_terms',e.target.value)} placeholder="30 dager netto" style={oInp} /></div>
              <div style={{ gridColumn:'1/-1' }}>{lbl('Innledende tekst')}<textarea value={form.intro_text} onChange={e=>set('intro_text',e.target.value)} rows={3} placeholder="Ordrebekreftelse for..." style={{ ...oInp, resize:'none' }} /></div>
            </div>
          )}
          {step===2 && (
            <div style={{ display:'flex', flexDirection:'column', gap:'14px' }}>
              {chapters.map((ch,ci) => {
                const { sum, total } = calcOrderChapter(ch)
                return (
                  <div key={ch.id} style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', overflow:'hidden' }}>
                    <div style={{ background:'#f8fafc', padding: isMobOE ? '10px 12px' : '12px 18px', display:'flex', alignItems:'center', gap: isMobOE ? '6px' : '12px', borderBottom:'1px solid #f1f5f9', flexWrap: isMobOE ? 'wrap' : 'nowrap' }}>
                      <span style={{ width:'24px', height:'24px', borderRadius:'50%', background:'#059669', color:'white', fontWeight:'800', fontSize:'11px', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{ci+1}</span>
                      <input value={ch.title} onChange={e=>updateChapter(ch.id,'title',e.target.value)} placeholder="Kapitteltittel" style={{ ...oInp, flex:1, background:'transparent', fontWeight:'700', minWidth: isMobOE ? '120px' : 'auto', fontSize: isMobOE ? '13px' : '14px' }} />
                      <span style={{ fontWeight:'700', color:'#059669', fontSize: isMobOE ? '12px' : '14px', whiteSpace:'nowrap' }}>{fmtO(sum)}</span>
                      {chapters.length>1&&<button onClick={()=>removeChapter(ch.id)} style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'8px', padding:'5px 8px', cursor:'pointer', fontSize:'12px' }}>🗑️</button>}
                    </div>
                    <div style={{ padding: isMobOE ? '10px' : '14px 18px' }}>
                      {isMobOE ? (
                        // ─── Mobil: kort-basert layout for hver post ─────
                        <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
                          {ch.posts.map(p => {
                            const ls = (parseFloat(p.qty)||0) * ((parseFloat(p.unitPriceWork)||0) + (parseFloat(p.unitPriceMaterial)||0))
                            return (
                              <div key={p.id} style={{ background:'#f8fafc', borderRadius:'10px', padding:'10px', border:'1px solid #f1f5f9' }}>
                                {/* Beskrivelse + slett-knapp */}
                                <div style={{ display:'flex', gap:'6px', alignItems:'center', marginBottom:'8px' }}>
                                  <input value={p.description} onChange={e=>updatePost(ch.id,p.id,'description',e.target.value)} placeholder="Beskriv post" style={{ ...oInp, flex:1, fontWeight:'600' }} />
                                  {ch.posts.length>1 && <button onClick={()=>removePost(ch.id,p.id)} style={{ background:'#fef2f2', border:'none', borderRadius:'8px', padding:'8px 10px', cursor:'pointer', color:'#dc2626', fontSize:'14px', flexShrink:0 }}>🗑️</button>}
                                </div>
                                {/* Mengde + Enhet på samme rad */}
                                <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'8px', marginBottom:'8px' }}>
                                  <div>
                                    <label style={{ display:'block', fontSize:'10px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'3px' }}>Mengde</label>
                                    <input type="number" inputMode="decimal" value={p.qty} onChange={e=>updatePost(ch.id,p.id,'qty',e.target.value)} style={{ ...oInp, width:'100%', textAlign:'right' }} />
                                  </div>
                                  <div>
                                    <label style={{ display:'block', fontSize:'10px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'3px' }}>Enhet</label>
                                    <input value={p.unit} onChange={e=>updatePost(ch.id,p.id,'unit',e.target.value)} placeholder="stk" style={{ ...oInp, width:'100%' }} />
                                  </div>
                                </div>
                                {/* Arbeid + Material på samme rad */}
                                <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'8px', marginBottom:'8px' }}>
                                  <div>
                                    <label style={{ display:'block', fontSize:'10px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'3px' }}>Arbeid kr/enh</label>
                                    <input type="number" inputMode="decimal" value={p.unitPriceWork} onChange={e=>updatePost(ch.id,p.id,'unitPriceWork',e.target.value)} style={{ ...oInp, width:'100%', textAlign:'right' }} />
                                  </div>
                                  <div>
                                    <label style={{ display:'block', fontSize:'10px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'3px' }}>Material kr/enh</label>
                                    <input type="number" inputMode="decimal" value={p.unitPriceMaterial} onChange={e=>updatePost(ch.id,p.id,'unitPriceMaterial',e.target.value)} style={{ ...oInp, width:'100%', textAlign:'right' }} />
                                  </div>
                                </div>
                                {/* Sum-rad */}
                                <div style={{ background:'#f0fdf4', borderRadius:'8px', padding:'8px 12px', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                                  <span style={{ fontSize:'11px', fontWeight:'700', color:'#16a34a', textTransform:'uppercase' }}>Sum</span>
                                  <span style={{ fontSize:'15px', fontWeight:'800', color:'#059669' }}>{fmtO(ls)}</span>
                                </div>
                              </div>
                            )
                          })}
                        </div>
                      ) : (
                        // ─── Desktop: tabell-layout (som før) ─────
                        <table style={{ width:'100%', borderCollapse:'collapse' }}>
                          <thead><tr>{['Beskrivelse','Mengde','Enhet','Arbeid kr/enh','Material kr/enh','Sum',''].map((h,i)=><th key={i} style={{ padding:'6px 8px', textAlign:i>=3&&i<=5?'right':'left', fontSize:'11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase', borderBottom:'1px solid #f1f5f9' }}>{h}</th>)}</tr></thead>
                          <tbody>
                            {ch.posts.map(p => {
                              const ls=(parseFloat(p.qty)||0)*((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0))
                              return <tr key={p.id}>
                                <td style={{ padding:'6px 4px' }}><input value={p.description} onChange={e=>updatePost(ch.id,p.id,'description',e.target.value)} placeholder="Beskriv post" style={{ ...oInp, minWidth:'160px' }} /></td>
                                <td style={{ padding:'6px 4px' }}><input type="number" value={p.qty} onChange={e=>updatePost(ch.id,p.id,'qty',e.target.value)} style={{ ...oInp, width:'70px', textAlign:'right' }} /></td>
                                <td style={{ padding:'6px 4px' }}><input value={p.unit} onChange={e=>updatePost(ch.id,p.id,'unit',e.target.value)} placeholder="stk" style={{ ...oInp, width:'55px' }} /></td>
                                <td style={{ padding:'6px 4px' }}><input type="number" value={p.unitPriceWork} onChange={e=>updatePost(ch.id,p.id,'unitPriceWork',e.target.value)} style={{ ...oInp, width:'100px', textAlign:'right' }} /></td>
                                <td style={{ padding:'6px 4px' }}><input type="number" value={p.unitPriceMaterial} onChange={e=>updatePost(ch.id,p.id,'unitPriceMaterial',e.target.value)} style={{ ...oInp, width:'100px', textAlign:'right' }} /></td>
                                <td style={{ padding:'6px 8px', textAlign:'right', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>{fmtO(ls)}</td>
                                <td style={{ padding:'6px 4px' }}>{ch.posts.length>1&&<button onClick={()=>removePost(ch.id,p.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'16px' }}>×</button>}</td>
                              </tr>
                            })}
                          </tbody>
                        </table>
                      )}
                      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginTop:'12px', flexWrap:'wrap', gap:'8px' }}>
                        <button onClick={()=>addPost(ch.id)} style={{ background:'#f0fdf4', color:'#059669', border:'1px solid #bbf7d0', borderRadius:'10px', padding: isMobOE ? '10px 14px' : '7px 14px', fontSize:'13px', fontWeight:'700', cursor:'pointer' }}>+ Legg til post</button>
                        <div style={{ fontSize:'13px', color:'#64748b' }}>Kapittelsum: <strong style={{ color:'#0f172a' }}>{fmtO(sum)}</strong></div>
                      </div>
                    </div>
                  </div>
                )
              })}
              <button onClick={addChapter} style={{ background:'white', border:'2px dashed #e2e8f0', borderRadius:'14px', padding:'16px', cursor:'pointer', color:'#94a3b8', fontWeight:'600', fontSize:'14px', width:'100%' }}>+ Legg til kapittel</button>
              <div style={{ background:'#f0fdf4', borderRadius:'14px', padding:'18px 24px', border:'1px solid #bbf7d0', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div><div style={{ fontSize:'13px', color:'#16a34a', fontWeight:'600' }}>Total eks. mva</div></div>
                <div style={{ fontSize:'24px', fontWeight:'800', color:'#0f172a' }}>{fmtO(grandTotal)}</div>
              </div>
            </div>
          )}
        </div>
        <div style={{ padding: isMobOE ? '12px 14px' : '16px 24px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0, gap:'8px' }}>
          <div>{step===2&&<button onClick={()=>setStep(1)} style={{ padding: isMobOE ? '8px 12px' : '10px 18px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobOE ? '12px' : '14px' }}>← Tilbake</button>}</div>
          {isMobOE && <span style={{ fontSize:'12px', color:'#059669', fontWeight:'700' }}>{fmtO(grandTotal)}</span>}
          <div style={{ display:'flex', gap: isMobOE ? '6px' : '10px' }}>
            {step===1&&<button onClick={()=>setStep(2)} style={{ padding: isMobOE ? '8px 14px' : '10px 24px', background:'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobOE ? '12px' : '14px', fontWeight:'600' }}>{isMobOE ? 'Neste →' : 'Neste: Linjer →'}</button>}
            {step===2&&<button onClick={()=>handleSave(false)} disabled={saving} style={{ padding: isMobOE ? '8px 14px' : '10px 20px', background:saving?'#6ee7b7':'white', color: saving ? 'white' : '#059669', border: saving ? 'none' : '1px solid #059669', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize: isMobOE ? '12px' : '14px', fontWeight:'600' }}>{saving?'Lagrer...':(isEdit?'💾 Lagre':'💾 Lagre utkast')}</button>}
            {step===2 && form.customer_email && <button onClick={()=>handleSave(true)} disabled={saving} style={{ padding: isMobOE ? '8px 14px' : '10px 20px', background:saving?'#93c5fd':'#2563eb', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize: isMobOE ? '12px' : '14px', fontWeight:'600' }}>{saving?'...':(isMobOE?'📧 Send':'📧 Lagre og send til kunde')}</button>}
          </div>
        </div>
      </div>
    </div>
  )
}

function FraIlbudModal({ quotes, projects, user, onClose, onSaved }) {
  const [selectedQuote, setSelectedQuote] = useState('')
  const [saving, setSaving] = useState(false)

  const handleCreate = async () => {
    const q = quotes.find(x=>x.id===selectedQuote)
    if (!q) return alert('Velg et tilbud')
    setSaving(true)
    try {
      const { data: existingOrders } = await supabase.from('orders').select('order_number')
      const orderNumber = nextSequenceNumber(existingOrders || [], 'ORD', 'order_number')
      const { error } = await supabase.from('orders').insert({
        title: q.title, order_number: orderNumber,
        project_id: q.project_id||null, quote_id: q.id,
        customer_name: q.customer_name, customer_email: q.customer_email,
        customer_address: q.customer_address, customer_orgnr: q.customer_orgnr,
        payment_terms: q.payment_terms||'30 dager netto',
        intro_text: q.intro_text, outro_text: q.outro_text,
        chapters: q.chapters, global_markup: q.global_markup||0,
        status: 'Utkast', created_by: user?.id,
      })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems: typeof window !== 'undefined' && window.innerWidth < 768 ? 'stretch' : 'center', justifyContent:'center', padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '0' : '16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius: typeof window !== 'undefined' && window.innerWidth < 768 ? '0' : '20px', width:'100%', maxWidth: typeof window !== 'undefined' && window.innerWidth < 768 ? '100%' : '500px', maxHeight: typeof window !== 'undefined' && window.innerWidth < 768 ? '100vh' : '90vh', height: typeof window !== 'undefined' && window.innerWidth < 768 ? '100vh' : 'auto', boxShadow: typeof window !== 'undefined' && window.innerWidth < 768 ? 'none' : '0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', display:'flex', flexDirection:'column' }}>
        <div style={{ padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '14px 16px' : '20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize: typeof window !== 'undefined' && window.innerWidth < 768 ? '15px' : '18px', fontWeight:'700', color:'#0f172a' }}>📋 Ordre fra tilbud</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '16px' : '24px', display:'flex', flexDirection:'column', gap:'16px', overflowY:'auto', flex:1, WebkitOverflowScrolling:'touch' }}>
          <p style={{ margin:0, fontSize:'14px', color:'#64748b' }}>Velg et akseptert tilbud. Alle kapitler og poster kopieres automatisk til ordren.</p>
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            {quotes.map(q => {
              const { grandTotal } = calcOrder(q.chapters||[], q.global_markup)
              const proj = projects.find(p=>p.id===q.project_id)
              return (
                <button key={q.id} onClick={()=>setSelectedQuote(q.id)}
                  style={{ padding:'14px 16px', borderRadius:'12px', border:`2px solid ${selectedQuote===q.id?'#059669':'#e2e8f0'}`, background:selectedQuote===q.id?'#f0fdf4':'white', cursor:'pointer', textAlign:'left', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                  <div>
                    <div style={{ fontWeight:'700', color:'#0f172a', fontSize:'14px' }}>{q.title}</div>
                    <div style={{ fontSize:'12px', color:'#64748b', marginTop:'2px' }}>{q.quote_number}{proj?` · ${proj.name}`:''}{q.customer_name?` · ${q.customer_name}`:''}</div>
                  </div>
                  <div style={{ fontWeight:'800', color:selectedQuote===q.id?'#059669':'#0f172a', fontSize:'15px' }}>{fmtO(grandTotal)}</div>
                </button>
              )
            })}
          </div>
          <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={handleCreate} disabled={saving||!selectedQuote} style={{ padding:'10px 24px', background:saving||!selectedQuote?'#94a3b8':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving||!selectedQuote?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600', width: typeof window !== 'undefined' && window.innerWidth < 768 ? '100%' : 'auto' }}>{saving?'Oppretter...':'Opprett ordre'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

function SendOrdreModal({ order, user, getPdfBase64, onClose, onSent }) {
  const appAlert = useAppAlert()
  const [email, setEmail] = useState(order.customer_email||'')
  const [ccEmails, setCcEmails] = useState('') // komma-separert liste
  const [showCc, setShowCc] = useState(false)
  const [reminderDays, setReminderDays] = useState(order.reminder_days || 7) // default 7 dager
  const [sending, setSending] = useState(false)
  const [sent, setSent] = useState(false)
  const isMobSO = typeof window !== 'undefined' && window.innerWidth < 768
  const { grandTotal } = calcOrder(order.chapters||[], order.global_markup)

  const handleSend = async () => {
    if (!email) return appAlert({ message: 'E-postadresse er påkrevd', kind: 'warn' })
    setSending(true)
    try {
      // Hent eller lag view_token for "Se full ordre"-lenken
      const viewToken = order.view_token || crypto.randomUUID()
      const viewUrl = `${window.location.origin}/ordre-view?token=${viewToken}`
      if (!order.view_token) {
        await supabase.from('orders').update({ view_token: viewToken }).eq('id', order.id)
      }

      // Bygg poster-tabell for e-post
      const postsHtml = (() => {
        const rows = []
        ;(order.chapters || []).forEach((ch, chIdx) => {
          ;(ch.posts || []).forEach(p => {
            const qty = parseFloat(p.qty) || 0
            const pw = parseFloat(p.unitPriceWork) || 0
            const pm = parseFloat(p.unitPriceMaterial) || 0
            const sum = qty * (pw + pm)
            if (qty > 0 || p.description) {
              rows.push('<tr style="border-bottom:1px solid #f1f5f9">' +
                '<td style="padding:8px;font-size:13px">' +
                  (ch.name ? `<span style="color:#94a3b8;font-size:11px">[${ch.name}]</span> ` : '') +
                  (p.description || '—').replace(/</g,'&lt;').replace(/>/g,'&gt;') +
                '</td>' +
                '<td style="padding:8px;font-size:13px;text-align:right">' + qty + ' ' + (p.unit || 'stk') + '</td>' +
                '<td style="padding:8px;font-size:13px;text-align:right">' + Math.round(pw).toLocaleString('nb-NO') + '</td>' +
                '<td style="padding:8px;font-size:13px;text-align:right">' + Math.round(pm).toLocaleString('nb-NO') + '</td>' +
                '<td style="padding:8px;font-size:13px;font-weight:700;text-align:right">' + Math.round(sum).toLocaleString('nb-NO') + ' kr</td>' +
              '</tr>')
            }
          })
        })
        if (rows.length === 0) return ''
        return '<div style="background:white;border:1px solid #e2e8f0;border-radius:12px;padding:16px;margin-bottom:16px;overflow-x:auto">' +
          '<div style="font-size:13px;font-weight:700;color:#0f172a;margin-bottom:10px">📋 Poster</div>' +
          '<table style="width:100%;border-collapse:collapse">' +
            '<thead><tr style="border-bottom:2px solid #e2e8f0">' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:left">Beskrivelse</th>' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Mengde</th>' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Arb./enh</th>' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Mat./enh</th>' +
              '<th style="padding:8px;font-size:11px;font-weight:600;color:#94a3b8;text-transform:uppercase;text-align:right">Sum</th>' +
            '</tr></thead>' +
            '<tbody>' + rows.join('') + '</tbody>' +
          '</table>' +
        '</div>'
      })()

      const html = '<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">' +
        '<h1 style="color:#0f172a;font-size:20px;margin:0 0 4px">Ordrebekreftelse</h1>' +
        '<p style="color:#94a3b8;font-size:13px;margin:0 0 20px">' + order.order_number + '</p>' +
        '<div style="background:#fffbeb;border:1px solid #fde68a;border-radius:12px;padding:16px;margin-bottom:16px">' +
          '<div style="font-size:13px;font-weight:700;color:#0f172a;margin-bottom:8px">' + (order.title || '') + '</div>' +
          (order.intro_text ? '<div style="font-size:14px;color:#374151">' + String(order.intro_text).replace(/\n/g, '<br>') + '</div>' : '') +
        '</div>' +
        postsHtml +
        '<div style="background:#f0fdf4;border-radius:12px;padding:16px;margin-bottom:16px;border:1px solid #bbf7d0">' +
          '<div style="font-size:24px;font-weight:800;color:#059669;text-align:center">' + Math.round(grandTotal || 0).toLocaleString('nb-NO') + ' kr</div>' +
          '<div style="font-size:12px;color:#64748b;text-align:center">Total eks. mva</div>' +
          '<div style="font-size:12px;color:#64748b;text-align:center;margin-top:4px">Inkl. mva: ' + Math.round(grandTotal * 1.25).toLocaleString('nb-NO') + ' kr</div>' +
        '</div>' +
        (order.delivery_date ? '<div style="background:#f8fafc;border-radius:10px;padding:10px 14px;margin-bottom:10px;font-size:13px;color:#475569"><strong>Leveringsdato:</strong> ' + order.delivery_date + '</div>' : '') +
        (order.payment_terms ? '<div style="background:#f8fafc;border-radius:10px;padding:10px 14px;margin-bottom:10px;font-size:13px;color:#475569"><strong>Betalingsbetingelser:</strong> ' + order.payment_terms + '</div>' : '') +
        // CTA-knapper (Godkjenn/Avvis) — Outlook-kompatibel struktur
        '<div style="margin:32px 0 16px">' +
          '<p style="color:#0f172a;font-size:16px;font-weight:700;text-align:center;margin:0 0 20px">Gi ditt svar</p>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:0 auto">' +
            '<tr>' +
              '<td style="padding:0 10px">' +
                '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#059669;border-radius:12px">' +
                  '<tr><td style="padding:18px 36px;text-align:center">' +
                    '<a href="' + viewUrl + '&action=godkjent" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✓&nbsp;&nbsp;Godkjenn</a>' +
                  '</td></tr>' +
                '</table>' +
              '</td>' +
              '<td style="padding:0 10px">' +
                '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#dc2626;border-radius:12px">' +
                  '<tr><td style="padding:18px 36px;text-align:center">' +
                    '<a href="' + viewUrl + '&action=avvist" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✗&nbsp;&nbsp;Avvis</a>' +
                  '</td></tr>' +
                '</table>' +
              '</td>' +
            '</tr>' +
          '</table>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:24px auto 0">' +
            '<tr><td style="border:1px solid #cbd5e1;border-radius:10px;padding:10px 20px;text-align:center">' +
              '<a href="' + viewUrl + '" style="color:#475569;text-decoration:none;font-size:13px;font-weight:600">📄 Se full ordre først</a>' +
            '</td></tr>' +
          '</table>' +
        '</div>' +
        '<p style="color:#94a3b8;font-size:12px">Ordrebekreftelse sendt via En Plattform</p>' +
      '</div>'

      // Generer PDF-vedlegg
      let pdfBase64 = null
      let pdfFilename = 'Ordrebekreftelse.pdf'
      if (getPdfBase64) {
        try {
          const pdfResult = await getPdfBase64(order)
          if (pdfResult) { pdfBase64 = pdfResult.base64; pdfFilename = pdfResult.filename }
        } catch (pdfErr) { console.error('PDF-generering feilet:', pdfErr) }
      }

      // Parse kopi-mottakere (komma-separert)
      const ccList = ccEmails
        .split(/[,;]/)
        .map(e => e.trim())
        .filter(e => e && e.includes('@'))

      const allRecipients = [email, ...ccList]

      const payload = {
        to: email,
        subject: `Ordrebekreftelse ${order.order_number} – ${order.title}`,
        html,
      }
      if (ccList.length > 0) payload.cc = ccList
      if (pdfBase64) {
        payload.attachments = [{ filename: pdfFilename, content: pdfBase64, type: 'application/pdf' }]
      }

      const fnRes = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method:'POST',
        headers:{'Content-Type':'application/json','apikey':import.meta.env.VITE_SUPABASE_ANON_KEY,'Authorization':`Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`},
        body: JSON.stringify(payload)
      })
      if (!fnRes.ok) { const d = await fnRes.json().catch(() => ({})); throw new Error(d?.error || `Sending feilet (${fnRes.status})`) }

      // Beregn reminder_due_date basert på valgte dager
      const now = new Date()
      const reminderDue = new Date(now)
      reminderDue.setDate(reminderDue.getDate() + (parseInt(reminderDays) || 7))

      // Oppdater aktivitetslogg med send-hendelse
      const existingLog = Array.isArray(order.activity_log) ? order.activity_log : []
      const sendActionLabel = ccList.length > 0 ? 'Sendt til kunde (med kopi)' : 'Sendt til kunde'
      const newLog = [...existingLog, {
        action: sendActionLabel,
        by: user?.email,
        at: now.toISOString(),
        to: email,
        cc: ccList.length > 0 ? ccList : undefined,
      }]

      // Prøv først med Fase B-felter (reminder_days, reminder_due_date, sent_to)
      // Hvis kolonnene ikke finnes (Fase B-migrasjon ikke kjørt), fall tilbake til basisfelter
      const fullUpdate = {
        status: 'Sendt',
        customer_email: email,
        activity_log: newLog,
        view_token: viewToken,
        sent_to: allRecipients,
        reminder_days: parseInt(reminderDays) || 7,
        reminder_due_date: reminderDue.toISOString().split('T')[0],
        updated_at: new Date().toISOString(),
      }
      let { error: updErr } = await supabase.from('orders').update(fullUpdate).eq('id', order.id)
      if (updErr) {
        console.warn('[SendOrdreModal] Fullt update feilet, prøver basisfelter:', updErr.message)
        const basicUpdate = {
          status: 'Sendt',
          customer_email: email,
          activity_log: newLog,
          view_token: viewToken,
          updated_at: new Date().toISOString(),
        }
        const { error: basicErr } = await supabase.from('orders').update(basicUpdate).eq('id', order.id)
        if (basicErr) throw basicErr
      }

      setSent(true)
      setTimeout(async () => {
        onClose()
        await appAlert({
          message: 'Ordrebekreftelse sendt',
          subMessage: `Sendt til ${email}. Kunden får PDF-vedlegg + knapper for å godkjenne/avvise.`,
          kind: 'success',
        })
        onSent()
      }, 600)
    } catch(e) {
      await appAlert({ message: 'Kunne ikke sende', subMessage: e.message, kind: 'error' })
    }
    finally { setSending(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems: isMobSO ? 'stretch' : 'center', justifyContent:'center', padding: isMobSO ? '0' : '16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius: isMobSO ? '0' : '20px', width:'100%', maxWidth: isMobSO ? '100%' : '480px', maxHeight: isMobSO ? '100vh' : '94vh', height: isMobSO ? '100vh' : 'auto', display:'flex', flexDirection:'column', boxShadow: isMobSO ? 'none' : '0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding: isMobSO ? '14px 16px' : '20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize: isMobSO ? '16px' : '18px', fontWeight:'700', color:'#0f172a' }}>📧 Send ordrebekreftelse</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'24px', cursor:'pointer', color:'#94a3b8', padding:'4px 8px' }}>×</button>
        </div>
        <div style={{ padding: isMobSO ? '16px' : '24px', display:'flex', flexDirection:'column', gap: isMobSO ? '14px' : '16px', overflowY:'auto', flex:1 }}>
          {sent ? (
            <div style={{ textAlign:'center', padding:'20px 0' }}>
              <div style={{ fontSize:'48px', marginBottom:'12px' }}>✅</div>
              <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Ordrebekreftelse sendt!</h3>
              <p style={{ margin:0, color:'#64748b', fontSize:'14px' }}>Kunden mottar e-post med bekreftelsesknapp</p>
            </div>
          ) : (
            <>
              <div style={{ background:'#f0fdf4', borderRadius:'12px', padding:'14px', border:'1px solid #bbf7d0' }}>
                <div style={{ fontSize:'13px', color:'#16a34a', fontWeight:'600' }}>Ordre: {order.title}</div>
                <div style={{ fontSize:'20px', fontWeight:'800', color:'#0f172a', marginTop:'4px' }}>{fmtO(grandTotal)}</div>
              </div>
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>E-postadresse til kunde *</label>
                <input type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="kunde@epost.no" style={oInp} />
              </div>

              {/* Send kopi */}
              {!showCc ? (
                <button type="button" onClick={() => setShowCc(true)} style={{ background:'none', border:'none', color:'#2563eb', fontSize:'13px', fontWeight:'600', cursor:'pointer', padding:0, textAlign:'left' }}>
                  + Send kopi til andre
                </button>
              ) : (
                <div>
                  <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>
                    Send kopi til (komma-separert)
                    <button type="button" onClick={() => { setShowCc(false); setCcEmails('') }} style={{ marginLeft:'8px', background:'none', border:'none', color:'#94a3b8', fontSize:'12px', cursor:'pointer', padding:0 }}>fjern</button>
                  </label>
                  <input type="text" value={ccEmails} onChange={e => setCcEmails(e.target.value)} placeholder="prosjektleder@..., bokføring@..." style={oInp} />
                  <p style={{ margin:'4px 0 0', fontSize:'11px', color:'#94a3b8' }}>Kopi-mottakere ser samme e-post, men kan også klikke Godkjenn/Avvis</p>
                </div>
              )}

              {/* Påminnelses-frist */}
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>
                  Varsle meg hvis ikke besvart innen
                </label>
                <div style={{ display:'flex', gap:'6px', flexWrap:'wrap' }}>
                  {[3, 7, 14, 30].map(d => (
                    <button key={d} type="button" onClick={() => setReminderDays(d)} style={{
                      padding:'8px 14px',
                      borderRadius:'10px',
                      border: reminderDays === d ? '2px solid #059669' : '1px solid #e2e8f0',
                      background: reminderDays === d ? '#f0fdf4' : 'white',
                      color: reminderDays === d ? '#059669' : '#374151',
                      fontSize:'13px',
                      fontWeight:'600',
                      cursor:'pointer',
                    }}>
                      {d} dager
                    </button>
                  ))}
                  <input type="number" min="1" max="365" value={reminderDays} onChange={e => setReminderDays(parseInt(e.target.value) || 1)} style={{ width:'80px', padding:'8px 10px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'13px' }} />
                </div>
                <p style={{ margin:'6px 0 0', fontSize:'11px', color:'#94a3b8' }}>
                  Etter {reminderDays} dager får du en Purr-knapp i ordre-detaljene
                </p>
              </div>

              <div style={{ background:'#fffbeb', borderRadius:'10px', padding:'12px 14px', border:'1px solid #fde68a', fontSize:'13px', color:'#92400e' }}>
                ⚠️ Kunden mottar en e-post med <strong>Godkjenn/Avvis-knapper</strong> og PDF-vedlegg.
              </div>

              <div style={{ display:'flex', justifyContent: isMobSO ? 'stretch' : 'flex-end', flexDirection: isMobSO ? 'column-reverse' : 'row', gap: isMobSO ? '10px' : '12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
                <button onClick={onClose} style={{ padding: isMobSO ? '12px 20px' : '10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobSO ? '15px' : '14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={handleSend} disabled={sending} style={{ padding: isMobSO ? '14px 24px' : '10px 24px', background:sending?'#6ee7b7':'#2563eb', color:'white', border:'none', borderRadius:'10px', cursor:sending?'not-allowed':'pointer', fontSize: isMobSO ? '15px' : '14px', fontWeight:'700' }}>{sending?'Sender...':'📧 Send nå'}</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════════
// SendOrderReminderModal — Send purring til kunde som ikke har svart
// ═══════════════════════════════════════════════════════════════════
function SendOrderReminderModal({ order, user, getPdfBase64, onClose, onSent }) {
  const appAlert = useAppAlert()
  const [email, setEmail] = useState(order.customer_email || '')
  const [customMessage, setCustomMessage] = useState('')
  const [extendDays, setExtendDays] = useState(7)
  const [sending, setSending] = useState(false)
  const isMobSR = typeof window !== 'undefined' && window.innerWidth < 768
  const { grandTotal } = calcOrder(order.chapters || [], order.global_markup)

  // Beregn hvor mange dager siden første sending
  const lastSent = order.activity_log?.filter(l => l.action?.includes('Sendt'))?.pop()?.at
  const daysSince = lastSent ? Math.floor((Date.now() - new Date(lastSent).getTime()) / (1000 * 60 * 60 * 24)) : null

  const handleSend = async () => {
    if (!email) return appAlert({ message: 'E-postadresse er påkrevd', kind: 'warn' })
    setSending(true)
    try {
      const viewToken = order.view_token || crypto.randomUUID()
      const viewUrl = `${window.location.origin}/ordre-view?token=${viewToken}`
      if (!order.view_token) await supabase.from('orders').update({ view_token: viewToken }).eq('id', order.id)

      const html = '<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">' +
        '<div style="background:#fef3c7;border:2px solid #fbbf24;border-radius:12px;padding:16px;margin-bottom:20px;text-align:center">' +
          '<div style="font-size:24px;margin-bottom:4px">⏰</div>' +
          '<div style="font-size:16px;font-weight:700;color:#92400e">Påminnelse</div>' +
          '<div style="font-size:13px;color:#92400e;margin-top:4px">Vi mangler fortsatt svar fra deg på ordren under</div>' +
        '</div>' +
        '<h1 style="color:#0f172a;font-size:20px;margin:0 0 4px">Ordrebekreftelse</h1>' +
        '<p style="color:#94a3b8;font-size:13px;margin:0 0 20px">' + order.order_number + '</p>' +
        '<div style="background:#f8fafc;border-radius:12px;padding:16px;margin-bottom:16px">' +
          '<div style="font-size:13px;font-weight:700;color:#0f172a;margin-bottom:8px">' + (order.title || '') + '</div>' +
          '<div style="font-size:20px;font-weight:800;color:#059669">' + Math.round(grandTotal || 0).toLocaleString('nb-NO') + ' kr</div>' +
          '<div style="font-size:11px;color:#64748b;margin-top:2px">Total eks. mva</div>' +
        '</div>' +
        (customMessage ? '<div style="background:#fffbeb;border:1px solid #fde68a;border-radius:10px;padding:12px 16px;margin-bottom:16px;font-size:14px;color:#374151;white-space:pre-wrap">' + String(customMessage).replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</div>' : '') +
        '<div style="margin:32px 0 16px">' +
          '<p style="color:#0f172a;font-size:16px;font-weight:700;text-align:center;margin:0 0 20px">Vennligst gi ditt svar</p>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:0 auto"><tr>' +
            '<td style="padding:0 10px"><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#059669;border-radius:12px"><tr><td style="padding:18px 36px;text-align:center">' +
              '<a href="' + viewUrl + '&action=godkjent" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✓&nbsp;&nbsp;Godkjenn</a>' +
            '</td></tr></table></td>' +
            '<td style="padding:0 10px"><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#dc2626;border-radius:12px"><tr><td style="padding:18px 36px;text-align:center">' +
              '<a href="' + viewUrl + '&action=avvist" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✗&nbsp;&nbsp;Avvis</a>' +
            '</td></tr></table></td>' +
          '</tr></table>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:24px auto 0">' +
            '<tr><td style="border:1px solid #cbd5e1;border-radius:10px;padding:10px 20px;text-align:center">' +
              '<a href="' + viewUrl + '" style="color:#475569;text-decoration:none;font-size:13px;font-weight:600">📄 Se full ordre</a>' +
            '</td></tr>' +
          '</table>' +
        '</div>' +
        '<p style="color:#94a3b8;font-size:12px;text-align:center">Påminnelse sendt via En Plattform</p>' +
      '</div>'

      let pdfBase64 = null, pdfFilename = 'Ordrebekreftelse.pdf'
      if (getPdfBase64) {
        try {
          const pdfResult = await getPdfBase64(order)
          if (pdfResult) { pdfBase64 = pdfResult.base64; pdfFilename = pdfResult.filename }
        } catch(e) { console.error('PDF-gen feilet:', e) }
      }

      const payload = {
        to: email,
        subject: `Påminnelse: Ordre ${order.order_number} venter på svar`,
        html,
      }
      if (pdfBase64) payload.attachments = [{ filename: pdfFilename, content: pdfBase64, type: 'application/pdf' }]

      const fnRes = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method:'POST',
        headers:{'Content-Type':'application/json','apikey':import.meta.env.VITE_SUPABASE_ANON_KEY,'Authorization':`Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`},
        body: JSON.stringify(payload)
      })
      if (!fnRes.ok) { const d = await fnRes.json().catch(()=>({})); throw new Error(d?.error || `Sending feilet (${fnRes.status})`) }

      // Ny frist = i dag + extendDays
      const newDue = new Date()
      newDue.setDate(newDue.getDate() + (parseInt(extendDays) || 7))

      const existingLog = Array.isArray(order.activity_log) ? order.activity_log : []
      const newLog = [...existingLog, {
        action: 'Purring sendt',
        by: user?.email,
        at: new Date().toISOString(),
        to: email,
        message: customMessage || undefined,
      }]

      await supabase.from('orders').update({
        activity_log: newLog,
        last_reminder_sent_at: new Date().toISOString(),
        reminder_due_date: newDue.toISOString().split('T')[0],
        view_token: viewToken,
        updated_at: new Date().toISOString(),
      }).eq('id', order.id)

      onClose()
      await appAlert({ message: 'Purring sendt', subMessage: `Sendt til ${email}. Ny frist: ${newDue.toLocaleDateString('nb-NO')}`, kind: 'success' })
      onSent()
    } catch(e) {
      await appAlert({ message: 'Kunne ikke sende purring', subMessage: e.message, kind: 'error' })
    } finally { setSending(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems: isMobSR ? 'stretch' : 'center', justifyContent:'center', padding: isMobSR ? '0' : '16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius: isMobSR ? '0' : '20px', width:'100%', maxWidth: isMobSR ? '100%' : '520px', maxHeight: isMobSR ? '100vh' : '90vh', height: isMobSR ? '100vh' : 'auto', display:'flex', flexDirection:'column', boxShadow: isMobSR ? 'none' : '0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding: isMobSR ? '14px 16px' : '20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize: isMobSR ? '16px' : '18px', fontWeight:'700', color:'#0f172a' }}>⚠️ Send purring</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'24px', cursor:'pointer', color:'#94a3b8', padding:'4px 8px' }}>×</button>
        </div>
        <div style={{ padding: isMobSR ? '16px' : '24px', display:'flex', flexDirection:'column', gap: isMobSR ? '14px' : '14px', overflowY:'auto', flex:1 }}>
          <div style={{ background:'#fef3c7', border:'1px solid #fbbf24', borderRadius:'10px', padding:'12px 14px', fontSize:'13px', color:'#92400e' }}>
            {daysSince !== null
              ? `Sist sendt for ${daysSince} dager siden. Purring inneholder samme innhold som opprinnelig ordre.`
              : `Purring inneholder samme innhold som opprinnelig ordre.`
            }
          </div>

          <div>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Send til</label>
            <input type="email" value={email} onChange={e => setEmail(e.target.value)} style={oInp} />
          </div>

          <div>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Personlig melding (valgfritt)</label>
            <textarea value={customMessage} onChange={e => setCustomMessage(e.target.value)} placeholder="Hei, vi venter fortsatt på svar fra deg på ordren..." style={{ ...oInp, minHeight:'80px', fontFamily:'inherit', resize:'vertical' }} />
          </div>

          <div>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Ny frist (dager)</label>
            <div style={{ display:'flex', gap:'6px', flexWrap:'wrap' }}>
              {[3, 7, 14].map(d => (
                <button key={d} type="button" onClick={() => setExtendDays(d)} style={{
                  padding:'8px 14px',
                  borderRadius:'10px',
                  border: extendDays === d ? '2px solid #059669' : '1px solid #e2e8f0',
                  background: extendDays === d ? '#f0fdf4' : 'white',
                  color: extendDays === d ? '#059669' : '#374151',
                  fontSize:'13px',
                  fontWeight:'600',
                  cursor:'pointer',
                }}>{d} dager</button>
              ))}
              <input type="number" min="1" max="365" value={extendDays} onChange={e => setExtendDays(parseInt(e.target.value) || 1)} style={{ width:'80px', padding:'8px 10px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'13px' }} />
            </div>
          </div>

          <div style={{ display:'flex', justifyContent: isMobSR ? 'stretch' : 'flex-end', flexDirection: isMobSR ? 'column-reverse' : 'row', gap: isMobSR ? '10px' : '12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding: isMobSR ? '12px 20px' : '10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobSR ? '15px' : '14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSend} disabled={sending} style={{ padding: isMobSR ? '14px 24px' : '10px 24px', background:sending?'#fca5a5':'#dc2626', color:'white', border:'none', borderRadius:'10px', cursor:sending?'not-allowed':'pointer', fontSize: isMobSR ? '15px' : '14px', fontWeight:'700' }}>{sending?'Sender...':'⚠️ Send purring'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════════
// ResendOrderModal — Send ordre på nytt (samme innhold) til samme/ny mottaker
// ═══════════════════════════════════════════════════════════════════
function ResendOrderModal({ order, user, getPdfBase64, onClose, onSent }) {
  const appAlert = useAppAlert()
  const [email, setEmail] = useState(order.customer_email || '')
  const [reason, setReason] = useState('') // f.eks. "Kunde mistet forrige e-post"
  const [sending, setSending] = useState(false)
  const isMobRO = typeof window !== 'undefined' && window.innerWidth < 768
  const { grandTotal } = calcOrder(order.chapters || [], order.global_markup)

  const handleSend = async () => {
    if (!email) return appAlert({ message: 'E-postadresse er påkrevd', kind: 'warn' })
    setSending(true)
    try {
      const viewToken = order.view_token || crypto.randomUUID()
      const viewUrl = `${window.location.origin}/ordre-view?token=${viewToken}`
      if (!order.view_token) await supabase.from('orders').update({ view_token: viewToken }).eq('id', order.id)

      const html = '<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">' +
        '<div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:12px;padding:14px;margin-bottom:16px;text-align:center">' +
          '<div style="font-size:14px;font-weight:700;color:#1e40af">🔁 Sendt på nytt</div>' +
          (reason ? '<div style="font-size:12px;color:#475569;margin-top:4px">' + String(reason).replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</div>' : '') +
        '</div>' +
        '<h1 style="color:#0f172a;font-size:20px;margin:0 0 4px">Ordrebekreftelse</h1>' +
        '<p style="color:#94a3b8;font-size:13px;margin:0 0 20px">' + order.order_number + '</p>' +
        '<div style="background:#f8fafc;border-radius:12px;padding:16px;margin-bottom:16px">' +
          '<div style="font-size:13px;font-weight:700;color:#0f172a;margin-bottom:8px">' + (order.title || '') + '</div>' +
          '<div style="font-size:20px;font-weight:800;color:#059669">' + Math.round(grandTotal || 0).toLocaleString('nb-NO') + ' kr</div>' +
          '<div style="font-size:11px;color:#64748b;margin-top:2px">Total eks. mva</div>' +
        '</div>' +
        '<div style="margin:32px 0 16px">' +
          '<p style="color:#0f172a;font-size:16px;font-weight:700;text-align:center;margin:0 0 20px">Gi ditt svar</p>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:0 auto"><tr>' +
            '<td style="padding:0 10px"><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#059669;border-radius:12px"><tr><td style="padding:18px 36px;text-align:center">' +
              '<a href="' + viewUrl + '&action=godkjent" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✓&nbsp;&nbsp;Godkjenn</a>' +
            '</td></tr></table></td>' +
            '<td style="padding:0 10px"><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="background:#dc2626;border-radius:12px"><tr><td style="padding:18px 36px;text-align:center">' +
              '<a href="' + viewUrl + '&action=avvist" style="color:#ffffff;text-decoration:none;font-weight:700;font-size:18px;display:block;white-space:nowrap">✗&nbsp;&nbsp;Avvis</a>' +
            '</td></tr></table></td>' +
          '</tr></table>' +
          '<table role="presentation" cellspacing="0" cellpadding="0" border="0" style="margin:24px auto 0">' +
            '<tr><td style="border:1px solid #cbd5e1;border-radius:10px;padding:10px 20px;text-align:center">' +
              '<a href="' + viewUrl + '" style="color:#475569;text-decoration:none;font-size:13px;font-weight:600">📄 Se full ordre</a>' +
            '</td></tr>' +
          '</table>' +
        '</div>' +
        '<p style="color:#94a3b8;font-size:12px;text-align:center">Sendt på nytt via En Plattform</p>' +
      '</div>'

      let pdfBase64 = null, pdfFilename = 'Ordrebekreftelse.pdf'
      if (getPdfBase64) {
        try {
          const pdfResult = await getPdfBase64(order)
          if (pdfResult) { pdfBase64 = pdfResult.base64; pdfFilename = pdfResult.filename }
        } catch(e) { console.error('PDF-gen feilet:', e) }
      }

      const payload = {
        to: email,
        subject: `Ordrebekreftelse ${order.order_number} (sendt på nytt)`,
        html,
      }
      if (pdfBase64) payload.attachments = [{ filename: pdfFilename, content: pdfBase64, type: 'application/pdf' }]

      const fnRes = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method:'POST',
        headers:{'Content-Type':'application/json','apikey':import.meta.env.VITE_SUPABASE_ANON_KEY,'Authorization':`Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`},
        body: JSON.stringify(payload)
      })
      if (!fnRes.ok) { const d = await fnRes.json().catch(()=>({})); throw new Error(d?.error || `Sending feilet (${fnRes.status})`) }

      const existingLog = Array.isArray(order.activity_log) ? order.activity_log : []
      const newLog = [...existingLog, {
        action: 'Sendt på nytt',
        by: user?.email,
        at: new Date().toISOString(),
        to: email,
        reason: reason || undefined,
      }]

      // Forleng reminder_due_date — telles fra nå
      const newDue = new Date()
      newDue.setDate(newDue.getDate() + (order.reminder_days || 7))

      await supabase.from('orders').update({
        customer_email: email,
        activity_log: newLog,
        view_token: viewToken,
        reminder_due_date: newDue.toISOString().split('T')[0],
        updated_at: new Date().toISOString(),
      }).eq('id', order.id)

      onClose()
      await appAlert({ message: 'Ordre sendt på nytt', subMessage: `Sendt til ${email}`, kind: 'success' })
      onSent()
    } catch(e) {
      await appAlert({ message: 'Kunne ikke sende', subMessage: e.message, kind: 'error' })
    } finally { setSending(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems: isMobRO ? 'stretch' : 'center', justifyContent:'center', padding: isMobRO ? '0' : '16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius: isMobRO ? '0' : '20px', width:'100%', maxWidth: isMobRO ? '100%' : '480px', maxHeight: isMobRO ? '100vh' : '90vh', height: isMobRO ? '100vh' : 'auto', display:'flex', flexDirection:'column', boxShadow: isMobRO ? 'none' : '0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding: isMobRO ? '14px 16px' : '20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize: isMobRO ? '16px' : '18px', fontWeight:'700', color:'#0f172a' }}>🔁 Send på nytt</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'24px', cursor:'pointer', color:'#94a3b8', padding:'4px 8px' }}>×</button>
        </div>
        <div style={{ padding: isMobRO ? '16px' : '24px', display:'flex', flexDirection:'column', gap:'14px', overflowY:'auto', flex:1 }}>
          <div style={{ background:'#eff6ff', border:'1px solid #bfdbfe', borderRadius:'10px', padding:'12px 14px', fontSize:'13px', color:'#1e40af' }}>
            Sender samme ordre på nytt. Innholdet er uendret. Godkjenn/Avvis-knappene fungerer som før.
          </div>

          <div>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Send til</label>
            <input type="email" value={email} onChange={e => setEmail(e.target.value)} style={oInp} />
          </div>

          <div>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Grunn for resend (valgfritt)</label>
            <input type="text" value={reason} onChange={e => setReason(e.target.value)} placeholder="F.eks. 'Opprinnelig e-post ble ikke mottatt'" style={oInp} />
          </div>

          <div style={{ display:'flex', justifyContent: isMobRO ? 'stretch' : 'flex-end', flexDirection: isMobRO ? 'column-reverse' : 'row', gap: isMobRO ? '10px' : '12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding: isMobRO ? '12px 20px' : '10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobRO ? '15px' : '14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSend} disabled={sending} style={{ padding: isMobRO ? '14px 24px' : '10px 24px', background:sending?'#c4b5fd':'#7c3aed', color:'white', border:'none', borderRadius:'10px', cursor:sending?'not-allowed':'pointer', fontSize: isMobRO ? '15px' : '14px', fontWeight:'700' }}>{sending?'Sender...':'🔁 Send på nytt'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

function EndringsmeldingModal({ order, user, existingCount, onClose, onSaved }) {
  const [form, setForm] = useState({ title:'', description:'', amount:0 })
  const [saving, setSaving] = useState(false)
  const set = (k,v) => setForm(f=>({...f,[k]:v}))

  const handleSave = async () => {
    if (!form.title.trim()) return alert('Tittel er påkrevd')
    setSaving(true)
    try {
      const { data: existingChanges } = await supabase.from('order_changes').select('change_number').eq('order_id', order.id)
      const change_number = nextSequenceNumber(existingChanges || [], 'EM', 'change_number', { withYear: false })
      const { error } = await supabase.from('order_changes').insert({ order_id:order.id, change_number, title:form.title.trim(), description:form.description||null, amount:parseFloat(form.amount)||0, status:'Utkast', created_by:user?.id })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'480px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>🔄 Ny endringsmelding</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'14px' }}>
          <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Tittel *</label><input value={form.title} onChange={e=>set('title',e.target.value)} placeholder="F.eks. Tilleggsarbeid drensgrøft" style={oInp} /></div>
          <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Beskrivelse</label><textarea value={form.description} onChange={e=>set('description',e.target.value)} rows={3} placeholder="Beskriv endringen..." style={{ ...oInp, resize:'none' }} /></div>
          <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Beløp eks. mva (kr)</label><input type="number" value={form.amount} onChange={e=>set('amount',e.target.value)} placeholder="0" style={oInp} /></div>
          <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSave} disabled={saving} style={{ padding:'10px 24px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{saving?'Lagrer...':'Opprett endringsmelding'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ─── END ORDRE MODULE ─────────────────────────────────────────────────────────

// ─── FAKTURA MODULE ───────────────────────────────────────────────────────────

const INV_STATUS = {
  'Utkast':    { bg:'#f8fafc', color:'#64748b', border:'#e2e8f0', emoji:'📝' },
  'Sendt':     { bg:'#eff6ff', color:'#2563eb', border:'#bfdbfe', emoji:'📤' },
  'Betalt':    { bg:'#f0fdf4', color:'#16a34a', border:'#bbf7d0', emoji:'✅' },
  'Purret':    { bg:'#fef2f2', color:'#dc2626', border:'#fecaca', emoji:'⚠️' },
  'Kreditert': { bg:'#f1f5f9', color:'#475569', border:'#cbd5e1', emoji:'↩️' },
}

const MVA_RATES = [{ label:'25% (standard)', rate:0.25 },{ label:'15% (næringsmidler)', rate:0.15 },{ label:'12% (transport/kino)', rate:0.12 },{ label:'0% (fritatt)', rate:0 }]

const iInp = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', fontFamily:'system-ui, sans-serif' }
const iCard = { background:'white', borderRadius: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '16px', border:'1px solid #f1f5f9', padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '20px 24px', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }

function InvStatusBadge({ status }) {
  const cfg = INV_STATUS[status]||INV_STATUS['Utkast']
  return <span style={{ background:cfg.bg, color:cfg.color, border:`1px solid ${cfg.border}`, padding:'3px 10px', borderRadius:'999px', fontSize:'12px', fontWeight:'600' }}>{cfg.emoji} {status}</span>
}

function calcLines(lines) {
  return (lines||[]).reduce((acc,l) => {
    const net = (parseFloat(l.qty)||0)*(parseFloat(l.unitPrice)||0)
    const mva = net*(parseFloat(l.mvaRate)||0)
    return { net:acc.net+net, mva:acc.mva+mva, gross:acc.gross+net+mva }
  }, { net:0, mva:0, gross:0 })
}

function fmtI(n) { return (Math.round(parseFloat(n)||0)).toLocaleString('nb-NO')+' kr' }

function addDays(dateStr, days) {
  const d = new Date(dateStr||new Date())
  d.setDate(d.getDate()+days)
  return d.toISOString().split('T')[0]
}

function paymentDays(terms) {
  const m = terms?.match(/(\d+)/)
  return m ? parseInt(m[1]) : 30
}

function isOverdue(inv) {
  return inv.due_date && new Date(inv.due_date) < new Date() && inv.status === 'Sendt'
}

// ── MAIN PAGE ─────────────────────────────────────────────────────────────────
function FakturaPage() {
  const { user } = useAuth()
  const [invoices, setInvoices] = useState([])
  const [orders, setOrders] = useState([])
  const [quotes, setQuotes] = useState([])
  const [projects, setProjects] = useState([])
  const [loading, setLoading] = useState(true)
  const [filterStatus, setFilterStatus] = useState('alle')
  const [search, setSearch] = useState('')
  const [showNew, setShowNew] = useState(null) // null|'manual'|'order'|'quote'|'partial'|'changes'|'kalkulation'
  const [selected, setSelected] = useState(null)
  React.useEffect(() => {
    if (selected && window.__enterDetailView) {
      window.__enterDetailView(() => setSelected(null))
    }
  }, [selected])

  // Lytt på event fra andre moduler som vil åpne en spesifikk faktura direkte
  // (f.eks. når bruker klikker "Send til faktura" på en ordre)
  React.useEffect(() => {
    const openInvoiceById = async (invoiceId) => {
      if (!invoiceId) return
      if (selected?.id === invoiceId) return
      try {
        const { data } = await supabase.from('invoices').select('*').eq('id', invoiceId).single()
        if (data) setSelected(data)
      } catch(err) { console.error('Kunne ikke åpne faktura:', err) }
    }

    // Sjekk sessionStorage ved mount — dette fanger opp ordre→faktura-flyt
    const pendingInvoiceId = sessionStorage.getItem('openInvoiceId')
    if (pendingInvoiceId) {
      sessionStorage.removeItem('openInvoiceId') // fjern etter bruk
      openInvoiceById(pendingInvoiceId)
    }

    const onOpenInvoice = async (e) => {
      const invoiceId = e.detail?.invoiceId
      if (invoiceId) openInvoiceById(invoiceId)
    }
    window.addEventListener('openInvoice', onOpenInvoice)
    return () => window.removeEventListener('openInvoice', onOpenInvoice)
  }, [selected?.id])
  const [calculations, setCalculations] = useState([])

  const load = async () => {
    try {
      const [inv, ord, q, p, kalks] = await Promise.all([
        supabase.from('invoices').select('*').order('created_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('orders').select('*').order('created_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('quotes').select('*').eq('status','Akseptert').then(r=>r.data||[]),
        supabase.from('projects').select('id,name,parent_id,depth,project_number').order('name').then(r=>r.data||[]),
        supabase.from('calculations').select('id, title, kalk_number, kalkyler, faktorer, total_ex_mva, customer_name, project_id').eq('is_template', false).order('created_at',{ascending:false}).then(r=>r.data||[]),
      ])
      setInvoices(inv); setOrders(ord); setQuotes(q); setProjects(p); setCalculations(kalks)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(()=>{ load() },[])

  // Forfalt-fakturaer for purring
  const overdueInvoices = invoices.filter(i => isOverdue(i) || (i.status === 'Purret' && i.due_date && new Date(i.due_date) < new Date()))

  const filtered = invoices.filter(i => {
    if (filterStatus!=='alle'&&i.status!==filterStatus) return false
    if (search&&![i.title,i.invoice_number,i.customer_name].some(v=>v?.toLowerCase().includes(search.toLowerCase()))) return false
    return true
  })

  const counts = Object.keys(INV_STATUS).reduce((acc,s)=>{ acc[s]=invoices.filter(i=>i.status===s).length; return acc },{})
  const totalSendt = invoices.filter(i=>i.status==='Sendt').reduce((acc,i)=>acc+calcLines(i.lines).net,0)
  const totalBetalt = invoices.filter(i=>i.status==='Betalt').reduce((acc,i)=>acc+calcLines(i.lines).net,0)
  const totalPurret = invoices.filter(i=>i.status==='Purret').reduce((acc,i)=>acc+calcLines(i.lines).net,0)
  const overdueCount = invoices.filter(i=>isOverdue(i)).length

  // ── MVA-rapport state ──
  const [showMvaReport, setShowMvaReport] = useState(false)
  const [mvaPeriod, setMvaPeriod] = useState(() => {
    const now = new Date()
    const q = Math.floor(now.getMonth() / 2) // Termin (2-mnd)
    const startMonth = q * 2
    const start = new Date(now.getFullYear(), startMonth, 1)
    const end = new Date(now.getFullYear(), startMonth + 2, 0)
    return { from: start.toISOString().split('T')[0], to: end.toISOString().split('T')[0], label: `${q+1}. termin ${now.getFullYear()}` }
  })

  const isMobF = typeof window !== 'undefined' && window.innerWidth < 768

  if (loading) return <div style={{ display:'flex',alignItems:'center',justifyContent:'center',minHeight:'60vh',fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px',height:'36px',border:'3px solid #e2e8f0',borderTop:'3px solid #059669',borderRadius:'50%',margin:'0 auto 12px',animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8',fontSize:'14px' }}>Laster fakturaer...</p></div></div>
  if (selected) return <FakturaDetaljer invoice={selected} projects={projects} orders={orders} user={user} onBack={()=>{setSelected(null);load()}} />

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobF ? '16px' : '24px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px' }}>
          <div>
            <h1 style={{ fontSize: isMobF ? '18px' : '22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>🧾 Faktura</h1>
            {!isMobF && <p style={{ color:'#64748b', marginTop:'4px', fontSize:'14px', marginBottom:0 }}>Fakturering, oversikt og utestående beløp</p>}
          </div>
          <div style={{ display:'flex', gap:'6px', alignItems:'center', flexShrink:0 }}>
            <button onClick={() => setShowMvaReport(!showMvaReport)} style={{ background: showMvaReport ? '#7c3aed' : 'white', border: showMvaReport ? '1px solid #7c3aed' : '1px solid #e2e8f0', borderRadius:'10px', padding: isMobF ? '9px 10px' : '11px 18px', fontSize: isMobF ? '11px' : '14px', fontWeight:'600', cursor:'pointer', color: showMvaReport ? 'white' : '#374151', whiteSpace:'nowrap' }}>{showMvaReport ? (isMobF ? '📊 Lukk MVA' : '📊 Lukk MVA-rapport') : (isMobF ? '📊 MVA' : '📊 MVA-rapport')}</button>
            <div style={{ position:'relative' }}>
              <button onClick={()=>setShowNew(showNew?null:'menu')} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding: isMobF ? '9px 12px' : '11px 20px', fontSize: isMobF ? '12px' : '14px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>{isMobF ? '+ Faktura ▾' : '+ Ny faktura ▾'}</button>
            {showNew==='menu' && (
              <>
                <div style={{ position:'fixed', inset:0, zIndex:50 }} onClick={()=>setShowNew(null)} />
                <div style={{ position:'absolute', top:'110%', right:0, background:'white', border:'1px solid #e2e8f0', borderRadius:'14px', boxShadow:'0 8px 32px rgba(0,0,0,0.12)', zIndex:60, minWidth:'240px', padding:'8px' }}>
                  {[
                    { key:'order', emoji:'📦', label:'Fra ordre', desc:'Kopier linjer fra ordre' },
                    { key:'quote', emoji:'📋', label:'Fra tilbud', desc:'Fra akseptert tilbud' },
                    { key:'kalkulation', emoji:'🧮', label:'Fra kalkulasjon', desc:'Velg poster og delfakturer' },
                    { key:'partial', emoji:'✂️', label:'Delfakturering', desc:'Fakturere % av en ordre' },
                    { key:'changes', emoji:'🔄', label:'Endringsmeldinger', desc:'Fakturere endringsmeldinger' },
                    { key:'manual', emoji:'✏️', label:'Manuell faktura', desc:'Lag fra bunnen av' },
                  ].map(opt=>(
                    <button key={opt.key} onClick={()=>setShowNew(opt.key)}
                      style={{ width:'100%', display:'flex', alignItems:'center', gap:'12px', padding:'11px 14px', border:'none', borderRadius:'10px', background:'transparent', cursor:'pointer', textAlign:'left' }}
                      onMouseEnter={e=>e.currentTarget.style.background='#f8fafc'} onMouseLeave={e=>e.currentTarget.style.background='transparent'}>
                      <span style={{ fontSize:'20px', width:'32px', textAlign:'center' }}>{opt.emoji}</span>
                      <div><div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>{opt.label}</div><div style={{ fontSize:'11px', color:'#94a3b8' }}>{opt.desc}</div></div>
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>
          </div>{/* end flex button group */}
        </div>
      </div>

      <div style={{ padding: isMobF ? '12px' : '24px 32px', display:'flex', flexDirection:'column', gap: isMobF ? '12px' : '20px', overflowX:'hidden' }}>
        {/* Stats */}
        <div style={{ display:'grid', gridTemplateColumns: isMobF ? 'repeat(2, 1fr)' : 'repeat(3,1fr) 1fr 1fr', gap: isMobF ? '8px' : '12px' }}>
          {[
            { label:'Utestående', value:fmtI(totalSendt+totalPurret), sub:`${counts['Sendt']||0} sendt, ${counts['Purret']||0} purret`, bg:'#eff6ff', color:'#2563eb', emoji:'📊' },
            { label:'Betalt', value:fmtI(totalBetalt), sub:`${counts['Betalt']||0} fakturaer`, bg:'#f0fdf4', color:'#16a34a', emoji:'✅' },
            { label:'Forfalt', value:overdueCount > 0 ? `${overdueCount} faktura${overdueCount>1?'er':''}` : 'Ingen', sub:overdueCount>0?'Krever oppfølging':'Alle à jour', bg:overdueCount>0?'#fef2f2':'#f8fafc', color:overdueCount>0?'#dc2626':'#64748b', emoji:overdueCount>0?'🚨':'👍' },
          ].map(s=>(
            <div key={s.label} style={{ background:s.bg, borderRadius: isMobF ? '10px' : '14px', padding: isMobF ? '10px' : '16px 20px', border:`1px solid ${s.bg}` }}>
              <div style={{ display:'flex', alignItems:'center', gap:'6px', marginBottom: isMobF ? '4px' : '6px' }}><span style={{ fontSize: isMobF ? '14px' : '18px' }}>{s.emoji}</span><span style={{ fontSize: isMobF ? '10px' : '12px', fontWeight:'700', color:s.color, textTransform:'uppercase' }}>{s.label}</span></div>
              <div style={{ fontSize: isMobF ? '14px' : '18px', fontWeight:'800', color:'#0f172a' }}>{s.value}</div>
              {!isMobF && <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>{s.sub}</div>}
            </div>
          ))}
          {['Utkast','Betalt'].map(s=>{
            const cfg=INV_STATUS[s]
            return (
              <button key={s} onClick={()=>setFilterStatus(filterStatus===s?'alle':s)}
                style={{ background:filterStatus===s?cfg.bg:'white', border:`1px solid ${filterStatus===s?cfg.border:'#f1f5f9'}`, borderRadius: isMobF ? '10px' : '14px', padding: isMobF ? '10px' : '16px', cursor:'pointer', textAlign: isMobF ? 'center' : 'left' }}>
                <div style={{ fontSize: isMobF ? '16px' : '20px', marginBottom: isMobF ? '4px' : '6px' }}>{cfg.emoji}</div>
                <div style={{ fontSize: isMobF ? '16px' : '20px', fontWeight:'800', color:filterStatus===s?cfg.color:'#0f172a' }}>{counts[s]||0}</div>
                <div style={{ fontSize: isMobF ? '10px' : '11px', color:filterStatus===s?cfg.color:'#94a3b8', fontWeight:'500', marginTop:'2px' }}>{s}</div>
              </button>
            )
          })}
        </div>

        {/* Purring-banner for forfalt fakturaer */}
        {overdueInvoices.length > 0 && (
          <div style={{ background:'#fef2f2', borderRadius:'14px', border:'1px solid #fecaca', padding:'16px 20px' }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'12px' }}>
              <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
                <span style={{ fontSize:'20px' }}>🚨</span>
                <div>
                  <div style={{ fontWeight:'700', fontSize:'14px', color:'#dc2626' }}>{overdueInvoices.length} forfalt{overdueInvoices.length > 1 ? 'e' : ''} faktura{overdueInvoices.length > 1 ? 'er' : ''}</div>
                  <div style={{ fontSize:'12px', color:'#991b1b' }}>Totalt utestående: {fmtI(overdueInvoices.reduce((s,i) => s + calcLines(i.lines).gross, 0))}</div>
                </div>
              </div>
            </div>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {overdueInvoices.slice(0, 5).map(oi => {
                const daysOver = Math.floor((new Date() - new Date(oi.due_date)) / 86400000)
                const { gross: oiGross } = calcLines(oi.lines)
                return (
                  <div key={oi.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:'white', borderRadius:'10px', padding:'10px 14px' }}>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontWeight:'600', fontSize:'13px', color:'#0f172a' }}>{oi.title}</div>
                      <div style={{ fontSize:'11px', color:'#dc2626' }}>
                        {oi.customer_name} · {oi.invoice_number} · Forfalt {daysOver} dager · {fmtI(oiGross)}
                        {oi.reminder_count > 0 && <span style={{ color:'#d97706', marginLeft:'6px' }}>{oi.reminder_count} purring{oi.reminder_count > 1 ? 'er' : ''}</span>}
                      </div>
                    </div>
                    <button onClick={async (e) => {
                      e.stopPropagation()
                      if (!oi.customer_email) { alert('Ingen e-post registrert'); return }
                      if (!window.confirm(`Send purring til ${oi.customer_email}?`)) return
                      try {
                        const { gross: g } = calcLines(oi.lines)
                        const reminderNum = (oi.reminder_count || 0) + 1
                        const html = `<div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px"><div style="background:#fef2f2;border-radius:12px;padding:16px;border:1px solid #fecaca;margin-bottom:20px"><h2 style="margin:0;color:#dc2626;font-size:18px">Purring ${reminderNum} – Ubetalt faktura</h2><p style="margin:4px 0 0;color:#dc2626;font-size:13px">Forfallsdato: <strong>${oi.due_date}</strong></p></div><h1 style="color:#0f172a;font-size:20px">${oi.title}</h1><p style="color:#64748b">Fakturanummer: <strong>${oi.invoice_number}</strong></p><div style="background:#f8fafc;border-radius:12px;padding:20px;margin:16px 0"><div style="font-size:28px;font-weight:800;color:#0f172a">${fmtI(g)}</div></div>${oi.bank_account?'<p style="color:#374151">Kontonr: <strong>'+oi.bank_account+'</strong></p>':''}${oi.kid?'<p style="color:#374151">KID: <strong>'+oi.kid+'</strong></p>':''}<p style="color:#64748b;font-size:13px">Vennligst betal snarest.</p><hr style="border:none;border-top:1px solid #f1f5f9;margin:24px 0"><p style="color:#94a3b8;font-size:12px">Purring ${reminderNum} — En Plattform</p></div>`
                        await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
                          method:'POST', headers:{'Content-Type':'application/json','apikey':import.meta.env.VITE_SUPABASE_ANON_KEY,'Authorization':'Bearer '+import.meta.env.VITE_SUPABASE_ANON_KEY},
                          body: JSON.stringify({ to:oi.customer_email, subject:`PURRING ${reminderNum} – Faktura ${oi.invoice_number}`, html })
                        })
                        await supabase.from('invoices').update({ status:'Purret', reminder_count:reminderNum, last_reminder_at:new Date().toISOString(), updated_at:new Date().toISOString() }).eq('id', oi.id)
                        load()
                      } catch(err) { alert('Feil: '+err.message) }
                    }} style={{ padding:'6px 14px', background:'#dc2626', color:'white', border:'none', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'600', whiteSpace:'nowrap' }}>
                      📧 Purring {(oi.reminder_count||0)+1}
                    </button>
                  </div>
                )
              })}
            </div>
          </div>
        )}

        {/* MVA-rapport */}
        {showMvaReport && (() => {
          const periodInvoices = invoices.filter(i => {
            if (i.status === 'Utkast') return false
            const d = i.invoice_date || i.created_at?.split('T')[0]
            return d >= mvaPeriod.from && d <= mvaPeriod.to
          })
          const creditNotes = periodInvoices.filter(i => i.is_credit_note)
          const regularInv = periodInvoices.filter(i => !i.is_credit_note)
          const mvaByRate = {}
          periodInvoices.forEach(inv => {
            ;(inv.lines || []).forEach(l => {
              const rate = parseFloat(l.mvaRate) || 0
              const lineNet = (parseFloat(l.qty)||0) * (parseFloat(l.unitPrice)||0)
              if (!mvaByRate[rate]) mvaByRate[rate] = { net: 0, mva: 0, count: 0 }
              mvaByRate[rate].net += lineNet
              mvaByRate[rate].mva += lineNet * rate
              mvaByRate[rate].count++
            })
          })
          const totalNet = Object.values(mvaByRate).reduce((s, v) => s + v.net, 0)
          const totalMva = Object.values(mvaByRate).reduce((s, v) => s + v.mva, 0)
          const totalGross = totalNet + totalMva
          const perioder = []
          const now = new Date()
          for (let y = now.getFullYear(); y >= now.getFullYear() - 1; y--) {
            for (let t = 5; t >= 0; t--) {
              const sm = t * 2, start = new Date(y, sm, 1), end = new Date(y, sm + 2, 0)
              if (start <= now) perioder.push({ from: start.toISOString().split('T')[0], to: end.toISOString().split('T')[0], label: `${t+1}. termin ${y} (${start.toLocaleDateString('nb-NO',{month:'short'})}\u2013${end.toLocaleDateString('nb-NO',{month:'short'})})` })
            }
          }
          return (
            <div style={{ background:'white', borderRadius:'14px', border:'1px solid #e9d5ff', padding:'20px', boxShadow:'0 2px 8px rgba(124,58,237,0.08)' }}>
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'16px' }}>
                <h3 style={{ margin:0, fontSize:'16px', fontWeight:'700', color:'#0f172a' }}>📊 MVA-rapport</h3>
                <div style={{ display:'flex', gap:'8px', alignItems:'center' }}>
                  <select value={mvaPeriod.from} onChange={e => { const p = perioder.find(pp => pp.from === e.target.value); if (p) setMvaPeriod(p) }} style={{ ...iInp, maxWidth:'280px', fontSize:'13px' }}>
                    {perioder.map(p => <option key={p.from} value={p.from}>{p.label}</option>)}
                  </select>
                  <button onClick={() => setShowMvaReport(false)} style={{ background:'none', border:'none', fontSize:'18px', cursor:'pointer', color:'#94a3b8' }}>×</button>
                </div>
              </div>
              {periodInvoices.length === 0 ? (
                <div style={{ textAlign:'center', padding:'24px', color:'#94a3b8', fontSize:'14px' }}>Ingen fakturaer i valgt periode</div>
              ) : (<>
                <div style={{ display:'grid', gridTemplateColumns:'repeat(4, 1fr)', gap:'10px', marginBottom:'16px' }}>
                  {[
                    { label:'Fakturaer', value: String(regularInv.length), color:'#0f172a', bg:'#f8fafc' },
                    { label:'Omsetning (netto)', value: fmtI(totalNet), color:'#2563eb', bg:'#eff6ff' },
                    { label:'Utgående MVA', value: fmtI(totalMva), color:'#dc2626', bg:'#fef2f2' },
                    { label:'Brutto', value: fmtI(totalGross), color:'#059669', bg:'#f0fdf4' },
                  ].map(s => (
                    <div key={s.label} style={{ background:s.bg, borderRadius:'10px', padding:'12px', textAlign:'center' }}>
                      <div style={{ fontSize:'16px', fontWeight:'800', color:s.color }}>{s.value}</div>
                      <div style={{ fontSize:'10px', color:'#94a3b8', marginTop:'2px' }}>{s.label}</div>
                    </div>
                  ))}
                </div>
                <div style={{ marginBottom:'16px' }}>
                  <div style={{ fontSize:'12px', fontWeight:'700', color:'#64748b', marginBottom:'8px', textTransform:'uppercase' }}>Fordelt per MVA-sats</div>
                  <div style={{ background:'#f8fafc', borderRadius:'10px', overflow:'hidden', border:'1px solid #f1f5f9' }}>
                    <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', padding:'8px 14px', background:'#f1f5f9' }}>
                      {['MVA-sats','Grunnlag','MVA-bel\u00F8p','Linjer'].map(h => <div key={h} style={{ fontSize:'10px', fontWeight:'700', color:'#64748b', textTransform:'uppercase' }}>{h}</div>)}
                    </div>
                    {Object.entries(mvaByRate).sort(([a],[b]) => parseFloat(b)-parseFloat(a)).map(([rate, data]) => (
                      <div key={rate} style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', padding:'10px 14px', borderTop:'1px solid #f1f5f9', fontSize:'13px' }}>
                        <div style={{ fontWeight:'700', color:'#0f172a' }}>{(parseFloat(rate)*100).toFixed(0)}%</div>
                        <div style={{ color:'#374151' }}>{fmtI(data.net)}</div>
                        <div style={{ color:'#dc2626', fontWeight:'600' }}>{fmtI(data.mva)}</div>
                        <div style={{ color:'#94a3b8' }}>{data.count}</div>
                      </div>
                    ))}
                    <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', padding: isMobF ? '8px 10px' : '10px 14px', borderTop:'2px solid #e2e8f0', fontSize: isMobF ? '12px' : '13px', fontWeight:'700' }}>
                      <div>Totalt</div><div>{fmtI(totalNet)}</div><div style={{ color:'#dc2626' }}>{fmtI(totalMva)}</div><div style={{ color:'#94a3b8' }}>{periodInvoices.reduce((s,i) => s + (i.lines||[]).length, 0)}</div>
                    </div>
                  </div>
                </div>
                {creditNotes.length > 0 && (
                  <div style={{ marginBottom:'16px' }}>
                    <div style={{ fontSize:'12px', fontWeight:'700', color:'#7c3aed', marginBottom:'6px' }}>↩️ Kreditnotaer i perioden ({creditNotes.length})</div>
                    {creditNotes.map(cn => { const { net: cnNet } = calcLines(cn.lines); return (
                      <div key={cn.id} style={{ display:'flex', justifyContent:'space-between', padding:'6px 10px', background:'#f5f3ff', borderRadius:'6px', fontSize:'12px', marginBottom:'4px' }}>
                        <span style={{ color:'#374151' }}>{cn.invoice_number} \u2014 {cn.title}</span>
                        <span style={{ color:'#dc2626', fontWeight:'600' }}>{fmtI(cnNet)}</span>
                      </div>
                    )})}
                  </div>
                )}
                <details style={{ cursor:'pointer' }}>
                  <summary style={{ fontSize:'12px', fontWeight:'700', color:'#64748b', userSelect:'none' }}>Fakturaer i perioden ({regularInv.length})</summary>
                  <div style={{ display:'flex', flexDirection:'column', gap:'4px', marginTop:'6px' }}>
                    {regularInv.map(pi => { const { net: piNet, mva: piMva } = calcLines(pi.lines); return (
                      <div key={pi.id} style={{ display:'flex', alignItems:'center', gap: isMobF ? '6px' : '10px', padding:'6px 10px', background:'#fafafa', borderRadius:'6px', fontSize: isMobF ? '11px' : '12px', flexWrap: isMobF ? 'wrap' : 'nowrap' }}>
                        {!isMobF && <span style={{ color:'#94a3b8', fontFamily:'monospace', fontSize:'11px', flexShrink:0 }}>{pi.invoice_number}</span>}
                        <span style={{ color:'#0f172a', fontWeight:'500', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', flex:1, minWidth:0 }}>{pi.title}</span>
                        <span style={{ color:'#374151', flexShrink:0 }}>{fmtI(piNet)}</span>
                        {!isMobF && <span style={{ color:'#dc2626', flexShrink:0 }}>{fmtI(piMva)}</span>}
                        <InvStatusBadge status={pi.status} />
                      </div>
                    )})}
                  </div>
                </details>
              </>)}
            </div>
          )
        })()}


        {/* Filters */}
        <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding: isMobF ? '10px' : '14px 18px', display:'flex', gap: isMobF ? '8px' : '10px', alignItems:'center', flexWrap:'wrap' }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍  Søk..." style={{ ...iInp, maxWidth: isMobF ? '100%' : '260px', flex: isMobF ? '1 1 100%' : '1' }} />
          <select value={filterStatus} onChange={e=>setFilterStatus(e.target.value)} style={{ ...iInp, maxWidth: isMobF ? '100%' : '160px', flex: isMobF ? '1 1 100%' : 'none', fontSize: isMobF ? '13px' : '14px' }}>
            <option value="alle">Alle statuser</option>
            {Object.keys(INV_STATUS).map(s=><option key={s} value={s}>{s}</option>)}
          </select>
          {(search||filterStatus!=='alle') && <button onClick={()=>{setSearch('');setFilterStatus('alle')}} style={{ background:'#f1f5f9', border:'none', borderRadius:'8px', padding:'9px 14px', fontSize:'13px', cursor:'pointer', color:'#64748b' }}>Nullstill</button>}
          <span style={{ marginLeft:'auto', fontSize:'13px', color:'#94a3b8' }}>{filtered.length} fakturaer</span>
        </div>

        {/* List */}
        {filtered.length===0 ? (
          <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'60px 20px', textAlign:'center' }}>
            <div style={{ fontSize:'40px', marginBottom:'12px' }}>🧾</div>
            <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Ingen fakturaer funnet</h3>
            <p style={{ margin:0, color:'#94a3b8', fontSize:'14px' }}>{invoices.length===0?'Opprett din første faktura.':'Prøv å endre søk eller filter.'}</p>
          </div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            {filtered.map(inv => {
              const cfg=INV_STATUS[inv.status] || INV_STATUS['Utkast']
              const { net, gross } = calcLines(inv.lines)
              const overdue = isOverdue(inv)
              const proj = projects.find(p=>p.id===inv.project_id)
              return (
                <div key={inv.id} onClick={()=>setSelected(inv)}
                  style={{ background:'white', borderRadius: isMobF ? '12px' : '14px', border:`1px solid ${overdue?'#fecaca':'#f1f5f9'}`, padding: isMobF ? '12px' : '16px 20px', cursor:'pointer', display:'flex', alignItems: isMobF ? 'flex-start' : 'center', gap: isMobF ? '10px' : '16px', transition:'box-shadow 0.15s' }}
                  onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 16px rgba(0,0,0,0.08)'} onMouseLeave={e=>e.currentTarget.style.boxShadow='none'}>
                  {!isMobF && <div style={{ width:'44px', height:'44px', borderRadius:'12px', background:overdue?'#fef2f2':cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', flexShrink:0 }}>{overdue?'🚨':cfg.emoji}</div>}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', alignItems:'center', gap: isMobF ? '6px' : '8px', flexWrap:'wrap', marginBottom:'4px' }}>
                      <span style={{ fontWeight:'700', color:'#0f172a', fontSize: isMobF ? '13px' : '15px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', maxWidth: isMobF ? 'calc(100vw - 130px)' : 'none' }}>{inv.title}</span>
                      {!isMobF && <span style={{ fontSize:'12px', color:'#94a3b8', fontFamily:'monospace' }}>{inv.invoice_number}</span>}
                      <InvStatusBadge status={inv.status} />
                      {overdue && <span style={{ background:'#fef2f2', color:'#dc2626', fontSize:'11px', fontWeight:'700', padding:'2px 8px', borderRadius:'999px', border:'1px solid #fecaca' }}>FORFALT</span>}
                    </div>
                    <div style={{ display:'flex', gap: isMobF ? '6px' : '12px', flexWrap:'wrap' }}>
                      {inv.customer_name&&<span style={{ fontSize: isMobF ? '11px' : '12px', color:'#64748b' }}>👤 {inv.customer_name}</span>}
                      {!isMobF && proj&&<span style={{ fontSize:'12px', color:'#2563eb', fontWeight:'500' }}>🏗️ {proj.name}</span>}
                      {!isMobF && inv.due_date&&<span style={{ fontSize:'12px', color:overdue?'#dc2626':'#64748b', fontWeight:overdue?'700':'400' }}>📅 {inv.due_date}</span>}
                    </div>
                  </div>
                  <div style={{ textAlign:'right', flexShrink:0 }}>
                    <div style={{ fontWeight:'800', fontSize: isMobF ? '13px' : '15px', color:'#0f172a' }}>{fmtI(net)}</div>
                    {!isMobF && <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>+mva {fmtI(gross)}</div>}
                  </div>
                  {!isMobF && <span style={{ color:'#94a3b8', fontSize:'18px' }}>›</span>}
                </div>
              )
            })}
          </div>
        )}
      </div>

      {showNew==='manual'   && <FakturaEditorModal projects={projects} user={user} onClose={()=>setShowNew(null)} onSaved={()=>{setShowNew(null);load()}} />}
      {showNew==='order'    && <FakturaFraOrdreModal orders={orders} projects={projects} user={user} mode="full" onClose={()=>setShowNew(null)} onSaved={()=>{setShowNew(null);load()}} />}
      {showNew==='quote'    && <FakturaFraTilbudModal quotes={quotes} projects={projects} user={user} onClose={()=>setShowNew(null)} onSaved={()=>{setShowNew(null);load()}} />}
      {showNew==='partial'  && <FakturaFraOrdreModal orders={orders} projects={projects} user={user} mode="partial" onClose={()=>setShowNew(null)} onSaved={()=>{setShowNew(null);load()}} />}
      {showNew==='changes'  && <FakturaEndringsModal orders={orders} projects={projects} user={user} onClose={()=>setShowNew(null)} onSaved={()=>{setShowNew(null);load()}} />}
      {showNew==='kalkulation' && <FakturaFraKalkModal calculations={calculations} projects={projects} invoices={invoices} user={user} onClose={()=>setShowNew(null)} onSaved={()=>{setShowNew(null);load()}} />}
    </div>
  )
}

function FakturaDetaljer({ invoice: init, projects, orders, user, onBack }) {
  const confirm = useConfirm()
  const isMobFD = typeof window !== 'undefined' && window.innerWidth < 768
  const [inv, setInv] = useState(init)
  const [editing, setEditing] = useState(false)
  const [showSend, setShowSend] = useState(false)
  const [showKreditnota, setShowKreditnota] = useState(false)
  const [kreditReason, setKreditReason] = useState('')
  const [kreditLines, setKreditLines] = useState([]) // hvilke linjer å kreditere
  const [kreditMode, setKreditMode] = useState('full') // 'full' | 'partial'
  const cfg = INV_STATUS[inv.status] || INV_STATUS['Utkast']
  const proj = projects.find(p=>p.id===inv.project_id)
  const ord = orders.find(o=>o.id===inv.order_id)
  const { net, mva, gross } = calcLines(inv.lines)
  const overdue = isOverdue(inv)

  const refresh = async () => { const {data}=await supabase.from('invoices').select('*').eq('id',inv.id).single(); if(data) setInv(data) }

  const updateStatus = async (status) => {
    const updates = { status, updated_at:new Date().toISOString() }
    if (status==='Betalt') updates.paid_at = new Date().toISOString()
    await supabase.from('invoices').update(updates).eq('id',inv.id)
    setInv(v=>({...v,...updates}))
  }

  const handleDelete = async () => {
    if (!(await confirm({ message: 'Slett denne fakturaen?', subMessage: 'Fakturaen slettes permanent.', danger: true }))) return
    await supabase.from('invoices').delete().eq('id',inv.id)
    onBack()
  }

  const sendPurring = async () => {
    if (!inv.customer_email) return alert('Ingen e-postadresse på fakturaen')
    if (!(await confirm({ message: `Send purring til ${inv.customer_email}?`, subMessage: 'Kunden mottar en purring på e-post.', confirmLabel: 'Send purring', danger: false }))) return
    try {
      const html = `
        <div style="font-family:system-ui,sans-serif;max-width:600px;margin:0 auto;padding:32px 20px">
          <div style="background:#fef2f2;border-radius:12px;padding:16px;border:1px solid #fecaca;margin-bottom:20px">
            <h2 style="margin:0 0 4px;color:#dc2626;font-size:18px">⚠️ Purring – Ubetalt faktura</h2>
            <p style="margin:0;color:#dc2626;font-size:13px">Forfallsdato: <strong>${inv.due_date}</strong></p>
          </div>
          <h1 style="color:#0f172a;font-size:20px">${inv.title}</h1>
          <p style="color:#64748b">Fakturanummer: <strong>${inv.invoice_number}</strong></p>
          <div style="background:#f8fafc;border-radius:12px;padding:20px;margin:16px 0">
            <div style="font-size:13px;color:#64748b;margin-bottom:4px">UTESTÅENDE BELØP INKL. MVA</div>
            <div style="font-size:28px;font-weight:800;color:#0f172a">${fmtI(gross)}</div>
          </div>
          ${inv.bank_account?`<p style="color:#374151;font-size:14px">Bankkontonummer: <strong>${inv.bank_account}</strong></p>`:''}
          ${inv.kid?`<p style="color:#374151;font-size:14px">KID: <strong>${inv.kid}</strong></p>`:''}
          <p style="color:#64748b;font-size:13px">Vennligst betal snarest for å unngå ytterligere purregebyr.</p>
          <hr style="border:none;border-top:1px solid #f1f5f9;margin:24px 0">
          <p style="color:#94a3b8;font-size:12px">Sendt via En Plattform KS-system</p>
        </div>`
      const fnRes = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`,{
        method:'POST',headers:{'Content-Type':'application/json','apikey':import.meta.env.VITE_SUPABASE_ANON_KEY,'Authorization':`Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`},
        body:JSON.stringify({to:inv.customer_email,subject:`PURRING – Faktura ${inv.invoice_number} – ${inv.title}`,html})
      })
      if (!fnRes.ok) throw new Error('Sending feilet')
      await supabase.from('invoices').update({status:'Purret',updated_at:new Date().toISOString()}).eq('id',inv.id)
      setInv(v=>({...v,status:'Purret'}))
      alert('Purring sendt!')
    } catch(e) { alert('Feil: '+e.message) }
  }

  // ── Kreditnota ──
  const createKreditnota = async () => {
    try {
      const { data: existingInv } = await supabase.from('invoices').select('invoice_number')
      const creditNr = nextSequenceNumber(existingInv || [], 'F', 'invoice_number')

      // Bestem kreditlinjer
      let creditLines
      if (kreditMode === 'full') {
        creditLines = (inv.lines || []).map(l => ({
          ...l, id: Date.now() + Math.random() * 1000,
          description: `Kreditering: ${l.description}`,
          unitPrice: -(Math.abs(parseFloat(l.unitPrice) || 0)),
        }))
      } else {
        creditLines = kreditLines.filter(l => l._selected).map(l => ({
          ...l, id: Date.now() + Math.random() * 1000,
          description: `Kreditering: ${l.description}`,
          unitPrice: -(Math.abs(parseFloat(l.unitPrice) || 0)) * (l._creditPct / 100),
          _selected: undefined, _creditPct: undefined,
        }))
      }

      if (creditLines.length === 0) return alert('Ingen linjer valgt for kreditering')

      const { error } = await supabase.from('invoices').insert({
        title: `Kreditnota – ${inv.title}`,
        invoice_number: creditNr,
        project_id: inv.project_id,
        customer_name: inv.customer_name,
        customer_email: inv.customer_email,
        customer_address: inv.customer_address,
        customer_orgnr: inv.customer_orgnr,
        our_name: inv.our_name, our_address: inv.our_address, our_orgnr: inv.our_orgnr,
        invoice_date: new Date().toISOString().split('T')[0],
        due_date: addDays(new Date().toISOString(), 14),
        payment_terms: inv.payment_terms,
        bank_account: inv.bank_account, kid: inv.kid,
        lines: creditLines,
        is_credit_note: true,
        credit_for_invoice_id: inv.id,
        credit_for_invoice_number: inv.invoice_number,
        credit_reason: kreditReason.trim() || null,
        notes: `Kreditnota for faktura ${inv.invoice_number}${kreditReason ? '. Årsak: ' + kreditReason : ''}`,
        status: 'Sendt',
        created_by: user?.id,
      })
      if (error) throw error

      // Oppdater original faktura
      await supabase.from('invoices').update({ status: 'Kreditert', updated_at: new Date().toISOString() }).eq('id', inv.id)
      setInv(v => ({ ...v, status: 'Kreditert' }))
      setShowKreditnota(false)
      alert('Kreditnota opprettet og original faktura kreditert.')
      onBack()
    } catch(e) { alert('Feil: ' + e.message) }
  }

  // Group lines by mva rate for summary
  const mvaGroups = (inv.lines||[]).reduce((acc,l)=>{
    const r=parseFloat(l.mvaRate)||0
    const net=(parseFloat(l.qty)||0)*(parseFloat(l.unitPrice)||0)
    acc[r]=(acc[r]||0)+net
    return acc
  },{})

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <style>{`@media print{.no-print{display:none!important} body{background:white} .print-area{padding:40px!important}}`}</style>
      <div className="no-print" style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobFD ? '14px' : '20px 32px' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#64748b', fontSize:'13px', marginBottom:'10px', display:'flex', alignItems:'center', gap:'6px', padding:0 }}>← Tilbake til fakturaer</button>
        <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap: isMobFD ? '8px' : '16px', flexWrap: isMobFD ? 'wrap' : 'nowrap' }}>
          <div style={{ display:'flex', alignItems:'flex-start', gap: isMobFD ? '10px' : '14px', flex:1, minWidth:0 }}>
            {!isMobFD && <div style={{ width:'52px', height:'52px', borderRadius:'14px', background:overdue?'#fef2f2':cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px', flexShrink:0 }}>{overdue?'🚨':cfg.emoji}</div>}
            <div style={{ minWidth:0 }}>
              <div style={{ display:'flex', alignItems:'center', gap: isMobFD ? '6px' : '10px', flexWrap:'wrap', marginBottom:'4px' }}>
                <h1 style={{ margin:0, fontSize: isMobFD ? '16px' : '20px', fontWeight:'bold', color:'#0f172a' }}>{inv.title}</h1>
                {!isMobFD && <span style={{ fontSize:'13px', color:'#94a3b8', fontFamily:'monospace' }}>{inv.invoice_number}</span>}
                <InvStatusBadge status={inv.status} />
                {inv.is_credit_note&&<span style={{ background:'#f5f3ff', color:'#7c3aed', fontSize:'12px', fontWeight:'700', padding:'3px 10px', borderRadius:'999px', border:'1px solid #e9d5ff' }}>↩️ Kreditnota</span>}
                {inv.credit_for_invoice_number&&<span style={{ fontSize:'12px', color:'#7c3aed' }}>Krediterer: {inv.credit_for_invoice_number}</span>}
                {overdue&&<span style={{ background:'#fef2f2', color:'#dc2626', fontSize:'12px', fontWeight:'700', padding:'3px 10px', borderRadius:'999px', border:'1px solid #fecaca' }}>FORFALT</span>}
              </div>
              <div style={{ display:'flex', gap:'12px', flexWrap:'wrap' }}>
                {inv.customer_name&&<span style={{ fontSize:'13px', color:'#64748b' }}>👤 {inv.customer_name}</span>}
                {proj&&<span style={{ fontSize:'13px', color:'#2563eb', fontWeight:'500' }}>🏗️ {proj.name}</span>}
                {ord&&<span style={{ fontSize:'13px', color:'#64748b' }}>📦 {ord.order_number}</span>}
              </div>
            </div>
          </div>
          <div style={{ display:'flex', gap: isMobFD ? '6px' : '8px', flexShrink:0, flexWrap:'wrap' }}>
            {inv.status==='Utkast'&&<button onClick={()=>setShowSend(true)} style={{ padding: isMobFD ? '7px 10px' : '9px 14px', background:'#2563eb', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobFD ? '11px' : '13px', fontWeight:'600' }}>{isMobFD ? '📧 Send' : '📧 Send faktura'}</button>}
            {(inv.status==='Sendt'||overdue)&&<button onClick={sendPurring} style={{ padding: isMobFD ? '7px 10px' : '9px 14px', background:'#dc2626', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobFD ? '11px' : '13px', fontWeight:'600' }}>{isMobFD ? '⚠️ Purr' : '⚠️ Send purring'}</button>}
            {!isMobFD && inv.status!=='Kreditert'&&inv.status!=='Utkast'&&!inv.is_credit_note&&<button onClick={()=>{setShowKreditnota(true);setKreditMode('full');setKreditReason('');setKreditLines((inv.lines||[]).map(l=>({...l,_selected:true,_creditPct:100})))}} style={{ padding:'9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'13px', color:'#7c3aed', fontWeight:'600' }}>↩️ Kredit</button>}
            {inv.status!=='Betalt'&&<button onClick={()=>setEditing(true)} style={{ padding: isMobFD ? '7px 10px' : '9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobFD ? '12px' : '13px' }}>✏️</button>}
            <button onClick={handleDelete} style={{ padding: isMobFD ? '7px 10px' : '9px 12px', border:'1px solid #fecaca', borderRadius:'10px', background:'white', cursor:'pointer', color:'#dc2626', fontSize: isMobFD ? '12px' : '13px' }}>🗑️</button>
          </div>
        </div>
      </div>

      <div style={{ padding: isMobFD ? '12px' : '24px 32px', display:'grid', gridTemplateColumns: isMobFD ? '1fr' : '2fr 1fr', gap: isMobFD ? '12px' : '20px' }}>
        <div className="print-area" style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          {/* Faktura header */}
          <div style={iCard}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:'20px' }}>
              <div>
                <div style={{ fontSize:'24px', fontWeight:'800', color:'#0f172a', marginBottom:'4px' }}>FAKTURA</div>
                <div style={{ fontSize:'13px', color:'#94a3b8', fontFamily:'monospace' }}>{inv.invoice_number}</div>
              </div>
              <div style={{ textAlign:'right' }}>
                {inv.our_name&&<div style={{ fontWeight:'700', color:'#0f172a', fontSize:'15px' }}>{inv.our_name}</div>}
                {inv.our_address&&<div style={{ fontSize:'13px', color:'#64748b' }}>{inv.our_address}</div>}
                {inv.our_orgnr&&<div style={{ fontSize:'13px', color:'#64748b' }}>Org.nr: {inv.our_orgnr}</div>}
              </div>
            </div>
            <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'20px', marginBottom:'16px' }}>
              <div>
                <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'8px' }}>Fakturert til</div>
                {[inv.customer_name,inv.customer_address,inv.customer_orgnr?`Org.nr: ${inv.customer_orgnr}`:null,inv.customer_email].filter(Boolean).map((v,i)=><div key={i} style={{ fontSize:'14px', color:'#0f172a', marginBottom:'2px' }}>{v}</div>)}
              </div>
              <div>
                <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', marginBottom:'8px' }}>Fakturadetaljer</div>
                {[['Fakturadato',inv.invoice_date],['Forfallsdato',inv.due_date],['Betalingsbetingelser',inv.payment_terms],['KID',inv.kid],['Konto',inv.bank_account]].filter(r=>r[1]).map(([k,v])=>(
                  <div key={k} style={{ display:'flex', justifyContent:'space-between', fontSize:'13px', marginBottom:'3px' }}><span style={{ color:'#94a3b8' }}>{k}:</span><span style={{ color:'#0f172a', fontWeight:'500' }}>{v}</span></div>
                ))}
              </div>
            </div>
          </div>

          {/* Lines */}
          <div style={iCard}>
            {isMobFD ? (
              <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                {(inv.lines||[]).map((l,i)=>{
                  const lineNet=(parseFloat(l.qty)||0)*(parseFloat(l.unitPrice)||0)
                  const lineMva=lineNet*(parseFloat(l.mvaRate)||0)
                  return (
                    <div key={i} style={{ background:'#f8fafc', borderRadius:'8px', padding:'10px 12px' }}>
                      <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'4px' }}>
                        <span style={{ fontWeight:'600', fontSize:'12px', color:'#0f172a' }}>{l.description||'—'}</span>
                        <span style={{ fontWeight:'700', fontSize:'12px', color:'#059669', whiteSpace:'nowrap', marginLeft:'8px' }}>{fmtI(lineNet+lineMva)}</span>
                      </div>
                      <div style={{ display:'flex', gap:'8px', fontSize:'11px', color:'#64748b', flexWrap:'wrap' }}>
                        <span>{l.qty} {l.unit} × {fmtI(l.unitPrice)}</span>
                        <span>MVA {Math.round((parseFloat(l.mvaRate)||0)*100)}%</span>
                        <span>Netto: {fmtI(lineNet)}</span>
                      </div>
                    </div>
                  )
                })}
              </div>
            ) : (
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:'13px' }}>
              <thead><tr style={{ background:'#f8fafc' }}>
                {['Beskrivelse','Mengde','Enhet','Enhetspris','MVA%','Netto','MVA','Brutto'].map(h=>(
                  <th key={h} style={{ padding:'9px 10px', textAlign:['Mengde','Enhetspris','MVA%','Netto','MVA','Brutto'].includes(h)?'right':'left', color:'#64748b', fontWeight:'600', fontSize:'11px', textTransform:'uppercase', borderBottom:'2px solid #f1f5f9' }}>{h}</th>
                ))}
              </tr></thead>
              <tbody>
                {(inv.lines||[]).map((l,i)=>{
                  const lineNet=(parseFloat(l.qty)||0)*(parseFloat(l.unitPrice)||0)
                  const lineMva=lineNet*(parseFloat(l.mvaRate)||0)
                  return <tr key={i} style={{ borderBottom:'1px solid #f8fafc' }}>
                    <td style={{ padding:'10px', color:'#0f172a', fontWeight:'500' }}>{l.description||'—'}</td>
                    <td style={{ padding:'10px', textAlign:'right', color:'#475569' }}>{l.qty}</td>
                    <td style={{ padding:'10px', color:'#475569' }}>{l.unit}</td>
                    <td style={{ padding:'10px', textAlign:'right', color:'#475569' }}>{fmtI(l.unitPrice)}</td>
                    <td style={{ padding:'10px', textAlign:'right', color:'#475569' }}>{Math.round((parseFloat(l.mvaRate)||0)*100)}%</td>
                    <td style={{ padding:'10px', textAlign:'right', color:'#0f172a' }}>{fmtI(lineNet)}</td>
                    <td style={{ padding:'10px', textAlign:'right', color:'#64748b' }}>{fmtI(lineMva)}</td>
                    <td style={{ padding:'10px', textAlign:'right', fontWeight:'700', color:'#0f172a' }}>{fmtI(lineNet+lineMva)}</td>
                  </tr>
                })}
              </tbody>
            </table>
            )}
          </div>

          {/* Totals */}
          <div style={{ ...iCard, background:'#f8fafc' }}>
            <div style={{ maxWidth: isMobFD ? '100%' : '320px', marginLeft: isMobFD ? '0' : 'auto', display:'flex', flexDirection:'column', gap:'6px' }}>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', color:'#475569' }}><span>Netto</span><span style={{ fontWeight:'600' }}>{fmtI(net)}</span></div>
              {Object.entries(mvaGroups).map(([rate,base])=>(
                <div key={rate} style={{ display:'flex', justifyContent:'space-between', fontSize:'13px', color:'#64748b' }}>
                  <span>MVA {Math.round(parseFloat(rate)*100)}% av {fmtI(base)}</span>
                  <span>{fmtI(base*parseFloat(rate))}</span>
                </div>
              ))}
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'18px', fontWeight:'800', color:'#0f172a', borderTop:'2px solid #e2e8f0', paddingTop:'10px', marginTop:'4px' }}><span>Å betale</span><span style={{ color:'#059669' }}>{fmtI(gross)}</span></div>
              {inv.bank_account&&<div style={{ fontSize:'13px', color:'#64748b', marginTop:'6px' }}>Bankkontonummer: <strong style={{ color:'#0f172a' }}>{inv.bank_account}</strong></div>}
              {inv.kid&&<div style={{ fontSize:'13px', color:'#64748b' }}>KID-nummer: <strong style={{ color:'#0f172a' }}>{inv.kid}</strong></div>}
            </div>
          </div>

          {inv.notes&&<div style={iCard}><p style={{ margin:0, fontSize:'14px', color:'#475569', lineHeight:1.6 }}>{inv.notes}</p></div>}
        </div>

        {/* Sidebar */}
        <div className="no-print" style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          <div style={iCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🔄 Status</h3>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {Object.keys(INV_STATUS).map(s=>(
                <button key={s} onClick={()=>updateStatus(s)} disabled={inv.status===s}
                  style={{ padding:'9px 14px', borderRadius:'10px', border:`1px solid ${inv.status===s?INV_STATUS[s].border:'#e2e8f0'}`, background:inv.status===s?INV_STATUS[s].bg:'white', color:inv.status===s?INV_STATUS[s].color:'#475569', fontWeight:inv.status===s?'700':'400', fontSize:'13px', cursor:inv.status===s?'default':'pointer', textAlign:'left', width:'100%' }}>
                  {inv.status===s?'✓ ':''}{INV_STATUS[s].emoji} {s}
                </button>
              ))}
            </div>
          </div>
          <div style={iCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>💰 Beløp</h3>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {[['Netto',fmtI(net)],['MVA',fmtI(mva)],['Å betale',fmtI(gross),true]].map(([k,v,bold])=>(
                <div key={k} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize:bold?'15px':'13px', fontWeight:bold?'800':'400' }}>
                  <span style={{ color:'#94a3b8' }}>{k}</span><span style={{ color:bold?'#059669':'#0f172a', fontWeight:bold?'800':'500' }}>{v}</span>
                </div>
              ))}
            </div>
          </div>
          <div style={iCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>ℹ️ Detaljer</h3>
            {[['Fakturadato',inv.invoice_date],['Forfallsdato',inv.due_date],['Betalt',inv.paid_at?new Date(inv.paid_at).toLocaleDateString('nb-NO'):null],['Sendt',inv.sent_at?new Date(inv.sent_at).toLocaleDateString('nb-NO'):null]].filter(r=>r[1]).map(([k,v],i)=>(
              <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize:'13px' }}>
                <span style={{ color:'#94a3b8' }}>{k}</span><span style={{ fontWeight:'500', color:'#0f172a' }}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {editing&&<FakturaEditorModal projects={projects} user={user} initial={inv} onClose={()=>setEditing(false)} onSaved={()=>{setEditing(false);refresh()}} />}
      {showSend&&<SendFakturaModal invoice={inv} user={user} onClose={()=>setShowSend(false)} onSent={()=>{setShowSend(false);refresh()}} />}

      {/* Kreditnota-modal */}
      {showKreditnota && (
        <>
          <div onClick={() => setShowKreditnota(false)} style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.45)', zIndex:100 }} />
          <div style={{ position:'fixed', top:'50%', left:'50%', transform:'translate(-50%,-50%)', background:'white', borderRadius:'20px', width:'min(600px, calc(100vw - 32px))', maxHeight:'85vh', display:'flex', flexDirection:'column', zIndex:101, boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
            <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', flexShrink:0 }}>
              <h2 style={{ margin:0, fontSize:'17px', fontWeight:'700', color:'#0f172a' }}>↩️ Opprett kreditnota</h2>
            </div>
            <div style={{ padding:'24px', overflowY:'auto', flex:1, display:'flex', flexDirection:'column', gap:'16px' }}>
              {/* Original faktura info */}
              <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'14px 16px', border:'1px solid #e2e8f0' }}>
                <div style={{ fontSize:'12px', fontWeight:'700', color:'#64748b', marginBottom:'4px' }}>KREDITERER FAKTURA</div>
                <div style={{ fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>{inv.title} — {inv.invoice_number}</div>
                <div style={{ fontSize:'13px', color:'#64748b', marginTop:'2px' }}>{inv.customer_name} · {fmtI(gross)} inkl. mva</div>
              </div>

              {/* Type kreditering */}
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Type kreditering</label>
                <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'8px' }}>
                  <button onClick={() => { setKreditMode('full'); setKreditLines((inv.lines||[]).map(l=>({...l,_selected:true,_creditPct:100}))) }}
                    style={{ padding:'12px', borderRadius:'12px', border:`2px solid ${kreditMode==='full'?'#7c3aed':'#e2e8f0'}`, background:kreditMode==='full'?'#f5f3ff':'white', cursor:'pointer', textAlign:'center' }}>
                    <div style={{ fontWeight:'700', fontSize:'13px', color:kreditMode==='full'?'#7c3aed':'#475569' }}>Full kreditering</div>
                    <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>Krediter hele fakturaen</div>
                  </button>
                  <button onClick={() => { setKreditMode('partial'); setKreditLines((inv.lines||[]).map(l=>({...l,_selected:false,_creditPct:100}))) }}
                    style={{ padding:'12px', borderRadius:'12px', border:`2px solid ${kreditMode==='partial'?'#7c3aed':'#e2e8f0'}`, background:kreditMode==='partial'?'#f5f3ff':'white', cursor:'pointer', textAlign:'center' }}>
                    <div style={{ fontWeight:'700', fontSize:'13px', color:kreditMode==='partial'?'#7c3aed':'#475569' }}>Delvis kreditering</div>
                    <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>Velg linjer og prosent</div>
                  </button>
                </div>
              </div>

              {/* Velg linjer ved delvis */}
              {kreditMode === 'partial' && (
                <div>
                  <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Velg linjer å kreditere</label>
                  <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
                    {kreditLines.map((line, i) => {
                      const lineNet = (parseFloat(line.qty)||0) * Math.abs(parseFloat(line.unitPrice)||0)
                      return (
                        <div key={i} style={{ display:'flex', alignItems:'center', gap:'10px', padding:'10px 12px', borderRadius:'10px', background: line._selected ? '#f5f3ff' : '#f8fafc', border:`1px solid ${line._selected ? '#e9d5ff' : '#f1f5f9'}` }}>
                          <input type="checkbox" checked={line._selected} onChange={e => {
                            const nl = [...kreditLines]; nl[i] = { ...nl[i], _selected: e.target.checked }; setKreditLines(nl)
                          }} style={{ accentColor:'#7c3aed' }} />
                          <div style={{ flex:1, minWidth:0 }}>
                            <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>{line.description}</div>
                            <div style={{ fontSize:'11px', color:'#94a3b8' }}>{line.qty} {line.unit} × {fmtI(Math.abs(line.unitPrice))} = {fmtI(lineNet)}</div>
                          </div>
                          {line._selected && (
                            <div style={{ display:'flex', alignItems:'center', gap:'4px', flexShrink:0 }}>
                              <input type="number" value={line._creditPct} min={1} max={100} onChange={e => {
                                const nl = [...kreditLines]; nl[i] = { ...nl[i], _creditPct: Math.min(100, Math.max(1, parseInt(e.target.value)||100)) }; setKreditLines(nl)
                              }} style={{ width:'50px', padding:'4px 6px', border:'1px solid #e2e8f0', borderRadius:'6px', fontSize:'12px', textAlign:'center' }} />
                              <span style={{ fontSize:'11px', color:'#64748b' }}>%</span>
                              <span style={{ fontSize:'11px', color:'#7c3aed', fontWeight:'600', marginLeft:'4px' }}>-{fmtI(lineNet * line._creditPct / 100)}</span>
                            </div>
                          )}
                        </div>
                      )
                    })}
                  </div>
                </div>
              )}

              {/* Kreditbeløp */}
              <div style={{ background:'#fef2f2', borderRadius:'10px', padding:'14px', border:'1px solid #fecaca', textAlign:'center' }}>
                <div style={{ fontSize:'11px', color:'#dc2626', fontWeight:'600', marginBottom:'2px' }}>KREDITBELØP (NETTO)</div>
                <div style={{ fontSize:'22px', fontWeight:'800', color:'#dc2626' }}>
                  -{fmtI(kreditMode === 'full' ? net : kreditLines.filter(l => l._selected).reduce((s, l) => s + Math.abs((parseFloat(l.qty)||0) * (parseFloat(l.unitPrice)||0)) * (l._creditPct / 100), 0))}
                </div>
              </div>

              {/* Årsak */}
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Årsak for kreditering</label>
                <textarea value={kreditReason} onChange={e => setKreditReason(e.target.value)} placeholder="Beskriv årsaken, f.eks. «Feil pris på linje 3» eller «Kansellert arbeid»"
                  rows={3} style={{ ...iInp, resize:'none' }} />
              </div>

              {/* Info */}
              <div style={{ background:'#fffbeb', borderRadius:'10px', padding:'12px 14px', border:'1px solid #fde68a', fontSize:'13px', color:'#92400e', lineHeight:1.5 }}>
                En kreditnota opprettes som en ny faktura med negative beløp. Original faktura settes til status «Kreditert». Kreditnotaen kan sendes til kunden som vanlig.
              </div>
            </div>
            <div style={{ padding:'16px 24px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'flex-end', gap:'10px', flexShrink:0 }}>
              <button onClick={() => setShowKreditnota(false)} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
              <button onClick={createKreditnota} style={{ padding:'10px 24px', background:'#7c3aed', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'14px', fontWeight:'600' }}>↩️ Opprett kreditnota</button>
            </div>
          </div>
        </>
      )}
    </div>
  )
}

function nextInvoiceNumber(invoices) {
  return nextSequenceNumber(invoices, 'F', 'invoice_number')
}

function FakturaEditorModal({ projects, user, initial, invoices=[], onClose, onSaved }) {
  const isEdit = !!initial
  const [form, setForm] = useState({
    title: initial?.title||'',
    invoice_number: initial?.invoice_number||nextInvoiceNumber(invoices||[]),
    project_id: initial?.project_id||'',
    customer_name: initial?.customer_name||'', customer_email: initial?.customer_email||'',
    customer_address: initial?.customer_address||'', customer_orgnr: initial?.customer_orgnr||'',
    customer_id: initial?.customer_id || null,
    our_name: initial?.our_name||'', our_address: initial?.our_address||'', our_orgnr: initial?.our_orgnr||'',
    invoice_date: initial?.invoice_date||new Date().toISOString().split('T')[0],
    payment_terms: initial?.payment_terms||'30 dager netto',
    due_date: initial?.due_date||addDays(new Date().toISOString().split('T')[0],30),
    kid: initial?.kid||'', bank_account: initial?.bank_account||'', notes: initial?.notes||'',
  })
  const [lines, setLines] = useState(initial?.lines||[{ id:Date.now(), description:'', qty:1, unit:'stk', unitPrice:0, mvaRate:0.25 }])
  const [saving, setSaving] = useState(false)
  const set = (k,v) => setForm(f=>({...f,[k]:v}))

  // Auto-calc due date when payment terms change
  const setPaymentTerms = (v) => { set('payment_terms',v); set('due_date', addDays(form.invoice_date, paymentDays(v))) }

  const addLine = () => setLines(l=>[...l,{id:Date.now(),description:'',qty:1,unit:'stk',unitPrice:0,mvaRate:0.25}])
  const removeLine = (id) => setLines(l=>l.filter(x=>x.id!==id))
  const updateLine = (id,f,v) => setLines(l=>l.map(x=>x.id===id?{...x,[f]:v}:x))

  const handleSave = async () => {
    if (!form.title.trim()) return alert('Tittel er påkrevd')
    setSaving(true)
    try {
      const { customerId } = await resolveCustomerFromForm({
        form,
        user,
        initialCustomerId: initial?.customer_id,
        statusOnCreate: 'faktura_sendt',
      })
      const payload = sanitizeDbPayload({ ...form, lines, project_id:form.project_id||null, customer_id: customerId, updated_at:new Date().toISOString() })
      if (isEdit) { const {error}=await supabase.from('invoices').update(payload).eq('id',initial.id); if(error) throw error }
      else { const {error}=await supabase.from('invoices').insert({...payload,status:'Utkast',created_by:user?.id}); if(error) throw error }
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  const lbl = t => <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>{t}</label>
  const { net, mva, gross } = calcLines(lines)

  const isMobFE = typeof window !== 'undefined' && window.innerWidth < 768

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems: isMobFE ? 'stretch' : 'center', justifyContent:'center', padding: isMobFE ? '0' : '16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius: isMobFE ? '0' : '20px', width:'100%', maxWidth: isMobFE ? '100%' : '960px', maxHeight: isMobFE ? '100vh' : '94vh', height: isMobFE ? '100vh' : 'auto', display:'flex', flexDirection:'column', boxShadow: isMobFE ? 'none' : '0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding: isMobFE ? '12px 14px' : '18px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', alignItems:'center', justifyContent:'space-between', flexShrink:0, gap:'8px' }}>
          <h2 style={{ margin:0, fontSize: isMobFE ? '14px' : '18px', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>🧾 {isEdit?'Rediger':'Ny'} faktura</h2>
          <div style={{ display:'flex', alignItems:'center', gap:'6px' }}>
            <button onClick={handleSave} disabled={saving} style={{ padding: isMobFE ? '7px 12px' : '8px 20px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize: isMobFE ? '12px' : '14px', fontWeight:'700', whiteSpace:'nowrap' }}>{saving?'Lagrer...':isEdit?'Lagre':'Opprett faktura'}</button>
            {!isMobFE && <span style={{ fontSize:'13px', color:'#94a3b8' }}>Å betale: <strong style={{ color:'#059669', fontSize:'15px' }}>{fmtI(gross)}</strong></span>}
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
          </div>
        </div>
        <div style={{ overflowY:'auto', flex:1, padding: isMobFE ? '14px' : '24px', display:'flex', flexDirection:'column', gap: isMobFE ? '14px' : '20px', WebkitOverflowScrolling:'touch' }}>
          {/* Info */}
          <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr 1fr', gap:'12px' }}>
            <div style={{ gridColumn:'1/-1' }}>{lbl('Tittel *')}<input value={form.title} onChange={e=>set('title',e.target.value)} placeholder="F.eks. Faktura betongarbeider Blokk B" style={iInp} /></div>
            <div>{lbl('Fakturanummer')}<input value={form.invoice_number} onChange={e=>set('invoice_number',e.target.value)} style={iInp} /></div>
            <div>{lbl('Fakturadato')}<input type="date" value={form.invoice_date} onChange={e=>set('invoice_date',e.target.value)} style={iInp} /></div>
            <div>{lbl('Betalingsbetingelser')}<input value={form.payment_terms} onChange={e=>setPaymentTerms(e.target.value)} placeholder="30 dager netto" style={iInp} /></div>
            <div>{lbl('Forfallsdato')}<input type="date" value={form.due_date} onChange={e=>set('due_date',e.target.value)} style={iInp} /></div>
            <div>{lbl('KID-nummer')}<input value={form.kid} onChange={e=>set('kid',e.target.value)} placeholder="KID / betalingsreferanse" style={iInp} /></div>
            <div>{lbl('Bankkonto')}<input value={form.bank_account} onChange={e=>set('bank_account',e.target.value)} placeholder="1234.56.78901" style={iInp} /></div>
            <div>{lbl('Knytt til prosjekt')}<SearchableProjectSelect value={form.project_id} onChange={v => set('project_id', v)} projects={projects} style={iInp} placeholder="Ingen" /></div>
          </div>
          <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'20px' }}>
            <div>
              <div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', marginBottom:'10px' }}>👤 Fakturert til (kunde)</div>
              <div style={{ marginBottom:'10px' }}>
                {lbl('Velg eksisterende kunde')}
                <CustomerSelect
                  value={form.customer_id}
                  valueAsId
                  onChange={v => set('customer_id', v)}
                  onSelect={c => {
                    set('customer_id', c.id)
                    set('customer_name', c.name || '')
                    if (c.email) set('customer_email', c.email)
                    if (c.address) set('customer_address', c.address)
                    if (c.orgnr) set('customer_orgnr', c.orgnr)
                  }}
                  placeholder="Søk — eller fyll ut under for ny"
                />
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                {[['customer_name','Kundenavn','Firma / personnavn'],['customer_email','E-post','kunde@epost.no'],['customer_address','Adresse','Gateadresse, postnr sted'],['customer_orgnr','Org.nr','123 456 789']].map(([k,l,ph])=>(
                  <div key={k}>{lbl(l)}<input value={form[k]} onChange={e=>set(k,e.target.value)} placeholder={ph} style={iInp} /></div>
                ))}
              </div>
            </div>
            <div>
              <div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', marginBottom:'10px' }}>🏢 Fakturert fra (oss)</div>
              <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                {[['our_name','Firmanavn','Ditt firma AS'],['our_address','Adresse','Gateadresse, postnr sted'],['our_orgnr','Org.nr MVA','123 456 789 MVA']].map(([k,l,ph])=>(
                  <div key={k}>{lbl(l)}<input value={form[k]} onChange={e=>set(k,e.target.value)} placeholder={ph} style={iInp} /></div>
                ))}
              </div>
            </div>
          </div>

          {/* Lines */}
          <div>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'12px' }}>
              <div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a' }}>📋 Fakturalinjer</div>
              <button onClick={addLine} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>+ Legg til linje</button>
            </div>
            <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', overflow:'hidden' }}>
              <div style={{ overflowX: isMobFE ? 'auto' : 'visible', WebkitOverflowScrolling:'touch' }}>
              <table style={{ width:'100%', borderCollapse:'collapse', minWidth: isMobFE ? '600px' : 'auto' }}>
                <thead><tr style={{ background:'#f8fafc' }}>
                  {['Beskrivelse','Mengde','Enhet','Enhetspris','MVA','Netto',''].map((h,i)=><th key={i} style={{ padding: isMobFE ? '6px 4px' : '9px 8px', textAlign:i>=3&&i<=5?'right':'left', fontSize: isMobFE ? '9px' : '11px', fontWeight:'600', color:'#94a3b8', textTransform:'uppercase', borderBottom:'1px solid #f1f5f9' }}>{h}</th>)}
                </tr></thead>
                <tbody>
                  {lines.map(l => {
                    const lineNet=(parseFloat(l.qty)||0)*(parseFloat(l.unitPrice)||0)
                    return <tr key={l.id} style={{ borderBottom:'1px solid #f8fafc' }}>
                      <td style={{ padding:'6px 4px' }}><input value={l.description} onChange={e=>updateLine(l.id,'description',e.target.value)} placeholder="Beskrivelse" style={{ ...iInp, minWidth:'180px' }} /></td>
                      <td style={{ padding:'6px 4px' }}><input type="number" value={l.qty} onChange={e=>updateLine(l.id,'qty',e.target.value)} style={{ ...iInp, width:'70px', textAlign:'right' }} /></td>
                      <td style={{ padding:'6px 4px' }}><input value={l.unit} onChange={e=>updateLine(l.id,'unit',e.target.value)} placeholder="stk" style={{ ...iInp, width:'60px' }} /></td>
                      <td style={{ padding:'6px 4px' }}><input type="number" value={l.unitPrice} onChange={e=>updateLine(l.id,'unitPrice',e.target.value)} style={{ ...iInp, width:'110px', textAlign:'right' }} /></td>
                      <td style={{ padding:'6px 4px' }}>
                        <select value={l.mvaRate} onChange={e=>updateLine(l.id,'mvaRate',e.target.value)} style={{ ...iInp, width:'80px' }}>
                          {MVA_RATES.map(r=><option key={r.rate} value={r.rate}>{Math.round(r.rate*100)}%</option>)}
                        </select>
                      </td>
                      <td style={{ padding:'6px 8px', textAlign:'right', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>{fmtI(lineNet)}</td>
                      <td style={{ padding:'6px 4px' }}>{lines.length>1&&<button onClick={()=>removeLine(l.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'16px' }}>×</button>}</td>
                    </tr>
                  })}
                </tbody>
              </table>
              </div>
              <div style={{ padding: isMobFE ? '10px 12px' : '12px 16px', background:'#f8fafc', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent: isMobFE ? 'space-between' : 'flex-end', gap: isMobFE ? '8px' : '20px' }}>
                {[['Netto',fmtI(net)],['MVA',fmtI(mva)],['Å betale',fmtI(gross)]].map(([k,v],i)=>(
                  <div key={k} style={{ textAlign: isMobFE ? 'center' : 'right' }}>
                    <div style={{ fontSize: isMobFE ? '9px' : '11px', color:'#94a3b8', textTransform:'uppercase', fontWeight:'600' }}>{k}</div>
                    <div style={{ fontSize: isMobFE ? (i===2?'14px':'12px') : (i===2?'16px':'14px'), fontWeight:i===2?'800':'600', color:i===2?'#059669':'#0f172a' }}>{v}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div>{lbl('Merknader / Betalingsinformasjon')}<textarea value={form.notes} onChange={e=>set('notes',e.target.value)} rows={2} placeholder="Eventuelle merknader til fakturaen..." style={{ ...iInp, resize:'none' }} /></div>
        </div>

      </div>
    </div>
  )
}

function FakturaFraOrdreModal({ orders, projects, user, mode, onClose, onSaved }) {
  const [selectedOrder, setSelectedOrder] = useState('')
  const [partialPct, setPartialPct] = useState(50)
  const [saving, setSaving] = useState(false)

  const ord = orders.find(o=>o.id===selectedOrder)
  const { grandTotal } = ord ? calcOrder(ord.chapters||[], ord.global_markup) : { grandTotal:0 }
  const invoiceAmount = mode==='partial' ? grandTotal * (partialPct/100) : grandTotal

  const handleCreate = async () => {
    if (!ord) return alert('Velg en ordre')
    setSaving(true)
    try {
      const lines = mode==='partial'
        ? [{ id:Date.now(), description:`${ord.title} – ${partialPct}% delfakturering`, qty:1, unit:'stk', unitPrice:Math.round(invoiceAmount), mvaRate:0.25 }]
        : (ord.chapters||[]).flatMap(ch=>(ch.posts||[]).map(p=>({
            id:Date.now()+Math.random(), description:p.description,
            qty:parseFloat(p.qty)||1, unit:p.unit||'stk',
            unitPrice:((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0))*(1+(parseFloat(ch.markup)||0)/100),
            mvaRate:0.25
          })))
      const { data: existingInv } = await supabase.from('invoices').select('invoice_number')
      const nextInvNr = nextSequenceNumber(existingInv || [], 'F', 'invoice_number')
      const { error } = await supabase.from('invoices').insert({
        title:`${ord.title}${mode==='partial'?` – ${partialPct}% delfaktura`:''}`,
        invoice_number: nextInvNr,
        order_id:ord.id, project_id:ord.project_id||null,
        customer_name:ord.customer_name, customer_email:ord.customer_email,
        customer_address:ord.customer_address, customer_orgnr:ord.customer_orgnr,
        payment_terms:ord.payment_terms||'30 dager netto',
        invoice_date:new Date().toISOString().split('T')[0],
        due_date:addDays(new Date().toISOString().split('T')[0],paymentDays(ord.payment_terms)),
        partial_percent:mode==='partial'?partialPct:null,
        lines, status:'Utkast', created_by:user?.id,
      })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'540px', maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>{mode==='partial'?'✂️ Delfakturering':'📦 Faktura fra ordre'}</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ overflowY:'auto', flex:1, padding:'24px', display:'flex', flexDirection:'column', gap:'14px' }}>
          <div>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Velg ordre</label>
            <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
              {orders.filter(o=>o.status!=='Avslått').map(o=>{
                const proj = projects.find(p=>p.id===o.project_id)
                const {grandTotal:gt} = calcOrder(o.chapters||[],o.global_markup)
                return (
                  <button key={o.id} onClick={()=>setSelectedOrder(o.id)}
                    style={{ padding:'12px 16px', borderRadius:'12px', border:`2px solid ${selectedOrder===o.id?'#059669':'#e2e8f0'}`, background:selectedOrder===o.id?'#f0fdf4':'white', cursor:'pointer', display:'flex', justifyContent:'space-between', alignItems:'center', textAlign:'left' }}>
                    <div>
                      <div style={{ fontWeight:'700', color:'#0f172a', fontSize:'14px' }}>{o.title}</div>
                      <div style={{ fontSize:'12px', color:'#64748b', marginTop:'2px' }}>{o.order_number}{proj?` · ${proj.name}`:''}</div>
                    </div>
                    <div style={{ fontWeight:'800', color:selectedOrder===o.id?'#059669':'#0f172a', fontSize:'15px' }}>{fmtI(gt)}</div>
                  </button>
                )
              })}
            </div>
          </div>
          {mode==='partial' && ord && (
            <div style={{ background:'#f8fafc', borderRadius:'12px', padding:'16px', border:'1px solid #f1f5f9' }}>
              <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Fakturér <strong style={{ color:'#059669' }}>{partialPct}%</strong> av {fmtI(grandTotal)}</label>
              <input type="range" min="1" max="100" value={partialPct} onChange={e=>setPartialPct(+e.target.value)} style={{ width:'100%', accentColor:'#059669', marginBottom:'8px' }} />
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:'13px', color:'#64748b' }}>
                <span>1%</span><span style={{ fontWeight:'700', color:'#059669', fontSize:'16px' }}>{fmtI(invoiceAmount)}</span><span>100%</span>
              </div>
            </div>
          )}
          <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleCreate} disabled={saving||!selectedOrder} style={{ padding:'10px 24px', background:saving||!selectedOrder?'#94a3b8':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving||!selectedOrder?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{saving?'Oppretter...':'Opprett faktura'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

function FakturaFraTilbudModal({ quotes, projects, user, onClose, onSaved }) {
  const [selectedQuote, setSelectedQuote] = useState('')
  const [saving, setSaving] = useState(false)

  const handleCreate = async () => {
    const q = quotes.find(x=>x.id===selectedQuote)
    if (!q) return alert('Velg et tilbud')
    setSaving(true)
    try {
      const lines = (q.chapters||[]).flatMap(ch=>(ch.posts||[]).map(p=>({
        id:Date.now()+Math.random(), description:p.description,
        qty:parseFloat(p.qty)||1, unit:p.unit||'stk',
        unitPrice:((parseFloat(p.unitPriceWork)||0)+(parseFloat(p.unitPriceMaterial)||0))*(1+(parseFloat(ch.markup)||0)/100),
        mvaRate:0.25
      })))
      const { data: existingInv2 } = await supabase.from('invoices').select('invoice_number')
      const nextInvNr2 = nextSequenceNumber(existingInv2 || [], 'F', 'invoice_number')
      const { error } = await supabase.from('invoices').insert({
        title:q.title, invoice_number: nextInvNr2,
        quote_id:q.id, project_id:q.project_id||null,
        customer_name:q.customer_name, customer_email:q.customer_email,
        customer_address:q.customer_address, customer_orgnr:q.customer_orgnr,
        payment_terms:q.payment_terms||'30 dager netto',
        invoice_date:new Date().toISOString().split('T')[0],
        due_date:addDays(new Date().toISOString().split('T')[0],paymentDays(q.payment_terms)),
        lines, status:'Utkast', created_by:user?.id,
      })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'500px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>📋 Faktura fra tilbud</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'14px' }}>
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            {quotes.map(q=>{
              const proj=projects.find(p=>p.id===q.project_id)
              const {grandTotal:gt}=calcOrder(q.chapters||[],q.global_markup)
              return (
                <button key={q.id} onClick={()=>setSelectedQuote(q.id)}
                  style={{ padding:'12px 16px', borderRadius:'12px', border:`2px solid ${selectedQuote===q.id?'#059669':'#e2e8f0'}`, background:selectedQuote===q.id?'#f0fdf4':'white', cursor:'pointer', display:'flex', justifyContent:'space-between', alignItems:'center', textAlign:'left' }}>
                  <div>
                    <div style={{ fontWeight:'700', color:'#0f172a', fontSize:'14px' }}>{q.title}</div>
                    <div style={{ fontSize:'12px', color:'#64748b', marginTop:'2px' }}>{q.quote_number}{proj?` · ${proj.name}`:''}</div>
                  </div>
                  <div style={{ fontWeight:'800', color:selectedQuote===q.id?'#059669':'#0f172a', fontSize:'15px' }}>{fmtI(gt)}</div>
                </button>
              )
            })}
          </div>
          <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleCreate} disabled={saving||!selectedQuote} style={{ padding:'10px 24px', background:saving||!selectedQuote?'#94a3b8':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving||!selectedQuote?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{saving?'Oppretter...':'Opprett faktura'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

function FakturaEndringsModal({ orders, projects, user, onClose, onSaved }) {
  const [selectedOrder, setSelectedOrder] = useState('')
  const [changes, setChanges] = useState([])
  const [selectedChanges, setSelectedChanges] = useState([])
  const [saving, setSaving] = useState(false)

  const loadChanges = async (orderId) => {
    const { data } = await supabase.from('order_changes').select('*').eq('order_id',orderId).eq('status','Godkjent')
    setChanges(data||[])
    setSelectedChanges((data||[]).map(c=>c.id))
  }

  const toggleChange = (id) => setSelectedChanges(s=>s.includes(id)?s.filter(x=>x!==id):[...s,id])

  const handleCreate = async () => {
    const ord = orders.find(o=>o.id===selectedOrder)
    if (!ord||selectedChanges.length===0) return alert('Velg ordre og minst én endringsmelding')
    setSaving(true)
    try {
      const selChanges = changes.filter(c=>selectedChanges.includes(c.id))
      const lines = selChanges.map(c=>({ id:Date.now()+Math.random(), description:`${c.change_number} – ${c.title}`, qty:1, unit:'stk', unitPrice:c.amount||0, mvaRate:0.25 }))
      const { data: existingInv3 } = await supabase.from('invoices').select('invoice_number')
      const nextInvNr3 = nextSequenceNumber(existingInv3 || [], 'F', 'invoice_number')
      const { error } = await supabase.from('invoices').insert({
        title:`Endringsmeldinger – ${ord.title}`, invoice_number: nextInvNr3,
        order_id:ord.id, project_id:ord.project_id||null,
        customer_name:ord.customer_name, customer_email:ord.customer_email,
        payment_terms:ord.payment_terms||'30 dager netto',
        invoice_date:new Date().toISOString().split('T')[0],
        due_date:addDays(new Date().toISOString().split('T')[0],paymentDays(ord.payment_terms)),
        lines, status:'Utkast', created_by:user?.id,
      })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'540px', maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>🔄 Faktura fra endringsmeldinger</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ overflowY:'auto', flex:1, padding:'24px', display:'flex', flexDirection:'column', gap:'14px' }}>
          <div>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Velg ordre</label>
            <select value={selectedOrder} onChange={e=>{ setSelectedOrder(e.target.value); if(e.target.value) loadChanges(e.target.value) }} style={iInp}>
              <option value="">Velg ordre...</option>
              {orders.map(o=><option key={o.id} value={o.id}>{o.order_number} – {o.title}</option>)}
            </select>
          </div>
          {changes.length>0 && (
            <div>
              <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Godkjente endringsmeldinger</label>
              {changes.map(c=>(
                <div key={c.id} onClick={()=>toggleChange(c.id)}
                  style={{ display:'flex', alignItems:'center', gap:'12px', padding:'12px 14px', background:selectedChanges.includes(c.id)?'#f0fdf4':'#f8fafc', borderRadius:'10px', border:`1px solid ${selectedChanges.includes(c.id)?'#bbf7d0':'#f1f5f9'}`, cursor:'pointer', marginBottom:'6px' }}>
                  <input type="checkbox" checked={selectedChanges.includes(c.id)} readOnly style={{ width:'16px', height:'16px', accentColor:'#059669' }} />
                  <div style={{ flex:1 }}>
                    <div style={{ fontWeight:'600', fontSize:'13px', color:'#0f172a' }}>{c.change_number} – {c.title}</div>
                    {c.description&&<div style={{ fontSize:'12px', color:'#64748b' }}>{c.description}</div>}
                  </div>
                  <div style={{ fontWeight:'800', color:'#059669', fontSize:'14px' }}>{fmtI(c.amount)}</div>
                </div>
              ))}
              {selectedChanges.length>0&&<div style={{ background:'#f0fdf4', borderRadius:'10px', padding:'10px 14px', border:'1px solid #bbf7d0', textAlign:'right', fontSize:'14px', fontWeight:'700', color:'#059669' }}>Total: {fmtI(changes.filter(c=>selectedChanges.includes(c.id)).reduce((a,c)=>a+(c.amount||0),0))}</div>}
            </div>
          )}
          {selectedOrder&&changes.length===0&&<p style={{ color:'#94a3b8', fontSize:'14px', textAlign:'center' }}>Ingen godkjente endringsmeldinger på denne ordren.</p>}
          <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleCreate} disabled={saving||!selectedOrder||selectedChanges.length===0} style={{ padding:'10px 24px', background:saving||!selectedOrder||selectedChanges.length===0?'#94a3b8':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'14px', fontWeight:'600' }}>{saving?'Oppretter...':'Opprett faktura'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

function FakturaFraKalkModal({ calculations, projects, invoices, user, onClose, onSaved }) {
  const [step, setStep] = useState(1) // 1=velg kalk, 2=velg poster
  const [selectedKalk, setSelectedKalk] = useState(null)
  const [selectedBds, setSelectedBds] = useState({}) // { bdId: { checked, pct } }
  const [saving, setSaving] = useState(false)

  // Beregn hva som allerede er fakturert for valgt kalkulasjon
  const previousInvoices = selectedKalk ? invoices.filter(i => i.source_calculation_id === selectedKalk.id) : []
  const previouslyInvoicedBds = previousInvoices.reduce((acc, inv) => {
    ;(inv.invoiced_bds || []).forEach(bd => { acc[bd.bd_id] = (acc[bd.bd_id] || 0) + (bd.percent || 100) })
    return acc
  }, {})

  const toggleBd = (kalkId, bdId) => {
    setSelectedBds(prev => {
      const key = `${kalkId}_${bdId}`
      if (prev[key]) { const { [key]: _, ...rest } = prev; return rest }
      return { ...prev, [key]: { checked: true, pct: 100 - (previouslyInvoicedBds[bdId] || 0) } }
    })
  }

  const setPct = (kalkId, bdId, pct) => {
    const key = `${kalkId}_${bdId}`
    setSelectedBds(prev => ({ ...prev, [key]: { ...prev[key], pct: Math.min(Math.max(0, pct), 100 - (previouslyInvoicedBds[bdId] || 0)) } }))
  }

  const handleCreate = async () => {
    const entries = Object.entries(selectedBds).filter(([_, v]) => v.checked && v.pct > 0)
    if (entries.length === 0) return alert('Velg minst en post')
    setSaving(true)
    try {
      const k = selectedKalk
      const alleFaktorer = k.faktorer || {}
      const lines = []; const invoicedBds = []

      entries.forEach(([key, val]) => {
        const [kalkIdStr, bdId] = key.split('_')
        const kalkId = parseInt(kalkIdStr)
        const kalkyle = (k.kalkyler || []).find(kl => kl.id === kalkId)
        if (!kalkyle) return
        const bd = (kalkyle.bygningsdeler || []).find(b => b.id === parseInt(bdId))
        if (!bd) return
        const fakt = alleFaktorer[kalkyle.fag] || getDefaultFaktorer(kalkyle.fag)
        const bdRes = beregnBygningsdel(bd, fakt)
        const amount = Math.round(bdRes.totalMedFortjeneste * val.pct / 100)
        const fag = getFaggruppe(kalkyle.fag)
        lines.push({ id: Date.now() + Math.random() * 1000, description: `${fag.emoji} ${bd.name} (${val.pct}%)`, qty: 1, unit: 'stk', unitPrice: amount, mvaRate: 0.25 })
        invoicedBds.push({ bd_id: bdId, kalkyle_id: kalkId, bd_name: bd.name, fag: kalkyle.fag, percent: val.pct })
      })

      const { net } = calcLines(lines)
      const proj = projects.find(p => p.id === k.project_id)
      const { data: existingInv } = await supabase.from('invoices').select('invoice_number')
      const invNr = nextSequenceNumber(existingInv || [], 'F', 'invoice_number')

      const { error } = await supabase.from('invoices').insert({
        title: `Delfaktura – ${k.title}`,
        invoice_number: invNr,
        project_id: k.project_id || null,
        customer_name: k.customer_name || proj?.name || '',
        lines, invoiced_bds: invoicedBds,
        source_calculation_id: k.id,
        payment_terms: '30 dager netto',
        due_date: addDays(new Date().toISOString(), 30),
        status: 'Utkast',
        created_by: user?.id,
      })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: ' + e.message) }
    finally { setSaving(false) }
  }

  const selectedCount = Object.values(selectedBds).filter(v => v.checked && v.pct > 0).length

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px', fontFamily:'system-ui,sans-serif' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'680px', maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>🧮 Delfaktura fra kalkulasjon</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ overflowY:'auto', flex:1, padding:'24px' }}>
          {step === 1 ? (
            <>
              <p style={{ margin:'0 0 14px', fontSize:'13px', color:'#64748b' }}>Velg kalkulasjon å delfakturere fra:</p>
              <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                {calculations.filter(c => !c.is_template).map(c => {
                  const kalkyler = c.kalkyler || []
                  const bdCount = kalkyler.reduce((s, kl) => s + (kl.bygningsdeler||[]).length, 0)
                  return (
                    <button key={c.id} onClick={() => { setSelectedKalk(c); setStep(2); setSelectedBds({}) }}
                      style={{ display:'flex', alignItems:'center', gap:'14px', width:'100%', padding:'14px 16px', borderRadius:'12px', border:'1px solid #f1f5f9', background:'white', cursor:'pointer', textAlign:'left' }}
                      onMouseEnter={e => e.currentTarget.style.borderColor='#059669'} onMouseLeave={e => e.currentTarget.style.borderColor='#f1f5f9'}>
                      <div style={{ width:'40px', height:'40px', borderRadius:'10px', background:'#eff6ff', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'18px', flexShrink:0 }}>🧮</div>
                      <div style={{ flex:1 }}>
                        <div style={{ fontWeight:'700', fontSize:'14px', color:'#0f172a' }}>{c.title}</div>
                        <div style={{ fontSize:'12px', color:'#94a3b8' }}>{c.kalk_number} · {kalkyler.length} fag · {bdCount} poster</div>
                      </div>
                      <div style={{ fontWeight:'700', color:'#059669', fontSize:'14px', flexShrink:0 }}>{fmtI(c.total_ex_mva)}</div>
                    </button>
                  )
                })}
                {calculations.length === 0 && <p style={{ color:'#94a3b8', fontSize:'13px', textAlign:'center', padding:'20px' }}>Ingen kalkulasjoner funnet</p>}
              </div>
            </>
          ) : (
            <>
              <button onClick={() => setStep(1)} style={{ background:'none', border:'none', cursor:'pointer', color:'#64748b', fontSize:'13px', marginBottom:'12px', padding:0 }}>← Velg annen kalkulasjon</button>
              <div style={{ background:'#eff6ff', borderRadius:'10px', padding:'12px 16px', border:'1px solid #bfdbfe', marginBottom:'16px' }}>
                <div style={{ fontSize:'13px', fontWeight:'700', color:'#1e40af' }}>{selectedKalk.title}</div>
                <div style={{ fontSize:'12px', color:'#64748b' }}>{selectedKalk.kalk_number} · {fmtI(selectedKalk.total_ex_mva)}</div>
              </div>

              <p style={{ margin:'0 0 10px', fontSize:'13px', fontWeight:'600', color:'#374151' }}>Velg bygningsdeler og prosent å fakturere:</p>

              {(selectedKalk.kalkyler || []).map(kalkyle => {
                const fag = getFaggruppe(kalkyle.fag)
                const fakt = (selectedKalk.faktorer || {})[kalkyle.fag] || getDefaultFaktorer(kalkyle.fag)
                return (
                  <div key={kalkyle.id} style={{ marginBottom:'14px' }}>
                    <div style={{ fontWeight:'700', fontSize:'13px', color:'#0f172a', marginBottom:'6px' }}>{fag.emoji} {kalkyle.name}</div>
                    <div style={{ display:'flex', flexDirection:'column', gap:'4px' }}>
                      {(kalkyle.bygningsdeler || []).map(bd => {
                        const key = `${kalkyle.id}_${bd.id}`
                        const sel = selectedBds[key]
                        const bdRes = beregnBygningsdel(bd, fakt)
                        const prevPct = previouslyInvoicedBds[bd.id] || 0
                        const remaining = 100 - prevPct
                        const isFullyInvoiced = remaining <= 0
                        return (
                          <div key={bd.id} style={{ display:'flex', alignItems:'center', gap:'10px', padding:'8px 10px', borderRadius:'8px', background: sel?.checked ? '#ecfdf5' : isFullyInvoiced ? '#f8fafc' : 'white', border:`1px solid ${sel?.checked ? '#a7f3d0' : '#f1f5f9'}`, opacity: isFullyInvoiced ? 0.5 : 1 }}>
                            <input type="checkbox" checked={!!sel?.checked} disabled={isFullyInvoiced} onChange={() => toggleBd(kalkyle.id, bd.id)} style={{ accentColor:'#059669' }} />
                            <div style={{ flex:1, minWidth:0 }}>
                              <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>{bd.name}</div>
                              <div style={{ fontSize:'11px', color:'#94a3b8' }}>{bd.mengde} {bd.enhet} · {fmtI(bdRes.totalMedFortjeneste)}{prevPct > 0 ? ` · ${prevPct}% fakturert` : ''}</div>
                            </div>
                            {sel?.checked && !isFullyInvoiced && (
                              <div style={{ display:'flex', alignItems:'center', gap:'4px', flexShrink:0 }}>
                                <input type="number" value={sel.pct} onChange={e => setPct(kalkyle.id, bd.id, parseInt(e.target.value) || 0)} min={0} max={remaining}
                                  style={{ width:'50px', padding:'4px 6px', border:'1px solid #e2e8f0', borderRadius:'6px', fontSize:'12px', textAlign:'center' }} />
                                <span style={{ fontSize:'11px', color:'#64748b' }}>%</span>
                                <span style={{ fontSize:'11px', color:'#059669', fontWeight:'600', marginLeft:'4px' }}>{fmtI(bdRes.totalMedFortjeneste * sel.pct / 100)}</span>
                              </div>
                            )}
                            {isFullyInvoiced && <span style={{ fontSize:'10px', color:'#059669', fontWeight:'600' }}>✓ Fullført</span>}
                          </div>
                        )
                      })}
                    </div>
                  </div>
                )
              })}
            </>
          )}
        </div>
        {step === 2 && (
          <div style={{ padding:'16px 24px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
            <span style={{ fontSize:'13px', color:'#64748b' }}>{selectedCount} poster valgt</span>
            <div style={{ display:'flex', gap:'10px' }}>
              <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
              <button onClick={handleCreate} disabled={saving || selectedCount === 0}
                style={{ padding:'10px 24px', background: saving ? '#6ee7b7' : '#059669', color:'white', border:'none', borderRadius:'10px', cursor: saving ? 'not-allowed' : 'pointer', fontSize:'14px', fontWeight:'600' }}>
                {saving ? 'Oppretter...' : `🧾 Opprett delfaktura (${selectedCount} poster)`}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

function SendFakturaModal({ invoice, user, onClose, onSent }) {
  const [email, setEmail] = useState(invoice.customer_email||'')
  const [sending, setSending] = useState(false)
  const [sent, setSent] = useState(false)
  const { net, gross } = calcLines(invoice.lines)

  const handleSend = async () => {
    if (!email) return alert('E-postadresse er påkrevd')
    setSending(true)
    try {
      const html = `
        <div style="font-family:system-ui,sans-serif;max-width:640px;margin:0 auto;padding:32px 20px">
          <h1 style="color:#0f172a;font-size:22px;margin-bottom:4px">Faktura: ${invoice.title}</h1>
          <p style="color:#64748b;font-size:13px;margin-bottom:20px">Fakturanummer: <strong>${invoice.invoice_number}</strong></p>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;background:#f8fafc;border-radius:12px;padding:20px;margin-bottom:20px">
            <div><div style="font-size:11px;color:#94a3b8;text-transform:uppercase;font-weight:600;margin-bottom:4px">Fakturadato</div><div style="font-weight:600;color:#0f172a">${invoice.invoice_date||'—'}</div></div>
            <div><div style="font-size:11px;color:#94a3b8;text-transform:uppercase;font-weight:600;margin-bottom:4px">Forfallsdato</div><div style="font-weight:700;color:#dc2626">${invoice.due_date||'—'}</div></div>
          </div>
          <div style="background:#f0fdf4;border-radius:12px;padding:20px;margin-bottom:20px;border:1px solid #bbf7d0;text-align:center">
            <div style="font-size:13px;color:#16a34a;font-weight:600;margin-bottom:4px">Å BETALE (INKL. MVA)</div>
            <div style="font-size:32px;font-weight:800;color:#0f172a">${fmtI(gross)}</div>
            <div style="font-size:13px;color:#64748b;margin-top:4px">Netto: ${fmtI(net)}</div>
          </div>
          ${invoice.bank_account?`<div style="background:#f8fafc;border-radius:10px;padding:14px 16px;margin-bottom:12px"><span style="color:#64748b;font-size:13px">Kontonummer: </span><strong style="color:#0f172a;font-size:14px">${invoice.bank_account}</strong></div>`:''}
          ${invoice.kid?`<div style="background:#f8fafc;border-radius:10px;padding:14px 16px;margin-bottom:20px"><span style="color:#64748b;font-size:13px">KID-nummer: </span><strong style="color:#0f172a;font-size:14px">${invoice.kid}</strong></div>`:''}
          ${invoice.notes?`<p style="color:#475569;font-size:13px;line-height:1.6">${invoice.notes}</p>`:''}
          <hr style="border:none;border-top:1px solid #f1f5f9;margin:24px 0">
          <p style="color:#94a3b8;font-size:12px">Sendt via En Plattform KS-system · enplattform.no</p>
        </div>`
      const fnRes = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`,{
        method:'POST',headers:{'Content-Type':'application/json','apikey':import.meta.env.VITE_SUPABASE_ANON_KEY,'Authorization':`Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`},
        body:JSON.stringify({to:email,subject:`Faktura ${invoice.invoice_number} – ${invoice.title}`,html})
      })
      const d = await fnRes.json()
      if (!fnRes.ok||d?.error) throw new Error(d?.error||'Sending feilet')
      await supabase.from('invoices').update({status:'Sendt',sent_at:new Date().toISOString(),customer_email:email,updated_at:new Date().toISOString()}).eq('id',invoice.id)

      // Hvis denne fakturaen ble opprettet fra en ordre, oppdater ordrestatus til 'Fakturert' nå
      if (invoice.from_order_id) {
        // Prøv først med alle koblings-felter, fall tilbake til bare status hvis noen kolonner mangler
        const fullUpdate = {
          status: 'Fakturert',
          invoiced_at: new Date().toISOString(),
          invoice_id: invoice.id,
          updated_at: new Date().toISOString(),
        }
        let { error: ordErr } = await supabase.from('orders').update(fullUpdate).eq('id', invoice.from_order_id)
        if (ordErr) {
          console.warn('[Send faktura] Full ordre-oppdatering feilet, prøver bare status:', ordErr.message)
          const basicUpdate = { status: 'Fakturert', updated_at: new Date().toISOString() }
          const { error: basicOrdErr } = await supabase.from('orders').update(basicUpdate).eq('id', invoice.from_order_id)
          if (basicOrdErr) {
            console.error('[Send faktura] Kunne ikke oppdatere ordrestatus:', basicOrdErr)
          } else {
            console.log('[Send faktura] Ordrestatus satt til Fakturert (uten kobling)')
          }
        } else {
          console.log('[Send faktura] Ordre oppdatert med kobling + status Fakturert')
        }
      }

      if (user?.id) await supabase.from('notifications').insert({user_id:user.id,title:`Faktura sendt: ${invoice.title}`,message:`Sendt til ${email}`,type:'info',link_page:'faktura'})
      setSent(true); setTimeout(()=>onSent(),1500)
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSending(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'480px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>📧 Send faktura</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'16px' }}>
          {sent ? (
            <div style={{ textAlign:'center', padding:'20px 0' }}>
              <div style={{ fontSize:'48px', marginBottom:'12px' }}>✅</div>
              <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Faktura sendt!</h3>
              <p style={{ margin:0, color:'#64748b', fontSize:'14px' }}>Kunden mottar faktura på e-post</p>
            </div>
          ) : (
            <>
              <div style={{ background:'#f0fdf4', borderRadius:'12px', padding:'14px', border:'1px solid #bbf7d0' }}>
                <div style={{ fontSize:'13px', color:'#16a34a', fontWeight:'600' }}>{invoice.title} · {invoice.invoice_number}</div>
                <div style={{ fontSize:'20px', fontWeight:'800', color:'#0f172a', marginTop:'4px' }}>{fmtI(gross)} inkl. mva</div>
                {invoice.due_date&&<div style={{ fontSize:'12px', color:'#64748b', marginTop:'4px' }}>Forfallsdato: {invoice.due_date}</div>}
              </div>
              <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>E-postadresse til kunde *</label><input type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="kunde@epost.no" style={iInp} /></div>
              <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
                <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                <button onClick={handleSend} disabled={sending} style={{ padding:'10px 24px', background:sending?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:sending?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{sending?'Sender...':'📧 Send faktura'}</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}

// ─── END FAKTURA MODULE ───────────────────────────────────────────────────────

// ─── ANSATTE MODULE ───────────────────────────────────────────────────────────

const EMP_STATUS = {
  'Aktiv':      { bg:'#f0fdf4', color:'#16a34a', border:'#bbf7d0', emoji:'✅' },
  'Permisjon':  { bg:'#fffbeb', color:'#d97706', border:'#fde68a', emoji:'⏸️' },
  'Sluttet':    { bg:'#fef2f2', color:'#dc2626', border:'#fecaca', emoji:'🚪' },
  'Reaktivert': { bg:'#eff6ff', color:'#2563eb', border:'#bfdbfe', emoji:'🔄' },
}

const CONTRACT_TYPES = ['Fast','Deltid','Vikar','Læring','Konsulent']

const DEPARTMENTS = ['Ledelse','Prosjekt','Anlegg','Betong','Elektro','Rør','Tømrer','Administrasjon','Økonomi','Annet']

const CERT_TYPES = ['HMS-kort','Kranførerbevis','Truck-sertifikat','Stillaskurs','Fallsikring','Sveisesertifikat','Elektrosertifikat','Førstehjelp','Maskinførerbevis','Annet']

const eInp = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', fontFamily:'system-ui, sans-serif' }
const eCard = { background:'white', borderRadius: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '16px', border:'1px solid #f1f5f9', padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '20px 24px', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }

function EmpStatusBadge({ status }) {
  const cfg = EMP_STATUS[status]||EMP_STATUS['Aktiv']
  return <span style={{ background:cfg.bg, color:cfg.color, border:`1px solid ${cfg.border}`, padding:'3px 10px', borderRadius:'999px', fontSize:'12px', fontWeight:'600' }}>{cfg.emoji} {status}</span>
}

function certDaysLeft(expiry) {
  if (!expiry) return null
  return Math.ceil((new Date(expiry)-new Date())/(1000*60*60*24))
}

function CertBadge({ expiry }) {
  if (!expiry) return null
  const days = certDaysLeft(expiry)
  if (days > 60) return null
  let bg='#fef2f2', color='#dc2626', label=days<0?`Utløpt ${Math.abs(days)}d siden`:`Utløper om ${days}d`
  if (days > 30) { bg='#fffbeb'; color='#d97706' }
  return <span style={{ background:bg, color, fontSize:'11px', fontWeight:'700', padding:'2px 8px', borderRadius:'999px' }}>⚠️ {label}</span>
}

function fmtE(n) { return (Math.round(parseFloat(n)||0)).toLocaleString('nb-NO') }

// ── MAIN PAGE ─────────────────────────────────────────────────────────────────
function AnsattePage() {
  const { user } = useAuth()
  const [employees, setEmployees] = useState([])
  const [projects, setProjects] = useState([])
  const [loading, setLoading] = useState(true)
  const [filterStatus, setFilterStatus] = useState('Aktiv')
  const [filterDept, setFilterDept] = useState('alle')
  const [search, setSearch] = useState('')
  const [showNew, setShowNew] = useState(false)
  const [showImport, setShowImport] = useState(false)
  const [selected, setSelected] = useState(null)
  React.useEffect(() => {
    if (selected && window.__enterDetailView) {
      window.__enterDetailView(() => setSelected(null))
    }
  }, [selected])
  const [visning, setVisning] = useState('liste')

  const load = async () => {
    try {
      const [e, p] = await Promise.all([
        supabase.from('employees').select('*, employee_certifications(*)').order('last_name').then(r=>r.data||[]),
        supabase.from('projects').select('id,name,parent_id,depth,project_number').order('name').then(r=>r.data||[])
      ])
      setEmployees(e); setProjects(p)
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(()=>{ load() },[])

  // Check cert expiry and create notifications
  useEffect(()=>{
    if (!user||employees.length===0) return
    employees.forEach(emp=>{
      (emp.employee_certifications||[]).forEach(async cert=>{
        const days = certDaysLeft(cert.expiry_date)
        if (days!==null && days<=30 && days>=-7) {
          // Check if notification already exists today
          const today = new Date().toISOString().split('T')[0]
          const { data } = await supabase.from('notifications').select('id').eq('user_id',user.id).ilike('title',`%${cert.name}%${emp.first_name}%`).gte('created_at',today+'T00:00:00').limit(1)
          if (!data||data.length===0) {
            await supabase.from('notifications').insert({
              user_id:user.id,
              title:`${cert.name} utløper snart: ${emp.first_name} ${emp.last_name}`,
              message:days<0?`Sertifikatet utløp for ${Math.abs(days)} dager siden`:`Utløper om ${days} dager (${cert.expiry_date})`,
              type: days<0?'warning':'info',
              link_page:'ansatte'
            })
          }
        }
      })
    })
  },[employees])

  const filtered = employees.filter(e=>{
    if (filterStatus!=='alle'&&e.status!==filterStatus) return false
    if (filterDept!=='alle'&&e.department!==filterDept) return false
    if (search&&![e.first_name,e.last_name,e.position,e.email,e.phone].some(v=>v?.toLowerCase().includes(search.toLowerCase()))) return false
    return true
  })

  const counts = Object.keys(EMP_STATUS).reduce((acc,s)=>{ acc[s]=employees.filter(e=>e.status===s).length; return acc },{})
  const expiringCerts = employees.flatMap(e=>(e.employee_certifications||[]).filter(c=>{ const d=certDaysLeft(c.expiry_date); return d!==null&&d<=30 }))

  const isMobE = typeof window !== 'undefined' && window.innerWidth < 768

  if (loading) return <div style={{ display:'flex',alignItems:'center',justifyContent:'center',minHeight:'60vh',fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px',height:'36px',border:'3px solid #e2e8f0',borderTop:'3px solid #059669',borderRadius:'50%',margin:'0 auto 12px',animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8',fontSize:'14px' }}>Laster ansatte...</p></div></div>
  if (selected) return <AnsattDetaljer employee={selected} projects={projects} user={user} onBack={()=>{setSelected(null);load()}} />

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobE ? '16px' : '24px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:'10px' }}>
          <div>
            <h1 style={{ fontSize: isMobE ? '18px' : '22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>👷 Ansatte</h1>
            {!isMobE && <p style={{ color:'#64748b', marginTop:'4px', fontSize:'14px', marginBottom:0 }}>Register, sertifikater, prosjekttilknytning og historikk</p>}
          </div>
          <div style={{ display:'flex', gap:'6px', flexShrink:0 }}>
            {!isMobE && <button onClick={()=>setShowImport(true)} style={{ background:'white', color:'#475569', border:'1px solid #e2e8f0', borderRadius:'10px', padding:'10px 16px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>📥 Import</button>}
            <button onClick={()=>setShowNew(true)} style={{ background:'#059669', color:'white', border:'none', borderRadius:'10px', padding: isMobE ? '9px 12px' : '11px 20px', fontSize: isMobE ? '12px' : '14px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>+ Ny ansatt</button>
          </div>
        </div>
      </div>

      <div style={{ padding: isMobE ? '12px' : '24px 32px', display:'flex', flexDirection:'column', gap: isMobE ? '12px' : '20px', overflowX:'hidden' }}>
        {/* Stats */}
        <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? 'repeat(2,1fr)' : 'repeat(4,1fr)', gap:'12px' }}>
          {Object.entries(EMP_STATUS).map(([s,cfg])=>(
            <button key={s} onClick={()=>setFilterStatus(filterStatus===s?'alle':s)}
              style={{ background:filterStatus===s?cfg.bg:'white', border:`1px solid ${filterStatus===s?cfg.border:'#f1f5f9'}`, borderRadius: isMobE ? '10px' : '14px', padding: isMobE ? '10px' : '16px', cursor:'pointer', textAlign: isMobE ? 'center' : 'left' }}>
              <div style={{ fontSize: isMobE ? '16px' : '22px', marginBottom: isMobE ? '4px' : '8px' }}>{cfg.emoji}</div>
              <div style={{ fontSize: isMobE ? '16px' : '22px', fontWeight:'800', color:filterStatus===s?cfg.color:'#0f172a' }}>{counts[s]||0}</div>
              <div style={{ fontSize: isMobE ? '10px' : '11px', color:filterStatus===s?cfg.color:'#94a3b8', fontWeight:'500', marginTop:'2px' }}>{s}</div>
            </button>
          ))}
        </div>

        {/* Cert expiry warning */}
        {expiringCerts.length>0 && (
          <div style={{ background:'#fffbeb', borderRadius:'12px', padding:'14px 18px', border:'1px solid #fde68a' }}>
            <div style={{ display:'flex', alignItems:'center', gap:'10px', marginBottom:'8px' }}>
              <span style={{ fontSize:'18px' }}>⚠️</span>
              <span style={{ fontSize:'14px', fontWeight:'700', color:'#92400e' }}>{expiringCerts.length} sertifikat{expiringCerts.length>1?'er':''} utløper innen 30 dager</span>
            </div>
            <div style={{ display:'flex', gap:'8px', flexWrap:'wrap' }}>
              {expiringCerts.slice(0,4).map((c,i)=>{
                const emp = employees.find(e=>(e.employee_certifications||[]).some(x=>x.id===c.id))
                const days = certDaysLeft(c.expiry_date)
                return <span key={i} style={{ background:'white', border:'1px solid #fde68a', borderRadius:'8px', padding:'4px 10px', fontSize:'12px', color:'#92400e' }}>{emp?.first_name} {emp?.last_name} – {c.name} ({days<0?'Utløpt':days+'d'})</span>
              })}
            </div>
          </div>
        )}

        {/* Filters */}
        <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding: isMobE ? '10px' : '14px 18px', display:'flex', gap: isMobE ? '8px' : '10px', alignItems:'center', flexWrap:'wrap' }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍  Søk..." style={{ ...eInp, maxWidth: isMobE ? '100%' : '240px', flex: isMobE ? '1 1 100%' : '1' }} />
          <select value={filterDept} onChange={e=>setFilterDept(e.target.value)} style={{ ...eInp, maxWidth: isMobE ? '100%' : '180px', flex: isMobE ? '1 1 48%' : 'none', fontSize: isMobE ? '13px' : '14px' }}>
            <option value="alle">Alle avdelinger</option>
            {DEPARTMENTS.map(d=><option key={d} value={d}>{d}</option>)}
          </select>
          {(search||filterStatus!=='alle'||filterDept!=='alle') && <button onClick={()=>{setSearch('');setFilterDept('alle')}} style={{ background:'#f1f5f9', border:'none', borderRadius:'8px', padding:'9px 14px', fontSize:'13px', cursor:'pointer', color:'#64748b' }}>Nullstill</button>}
          <span style={{ marginLeft:'auto', fontSize:'13px', color:'#94a3b8' }}>{filtered.length} ansatte</span>
          <div style={{ display:'flex', border:'1px solid #e2e8f0', borderRadius:'10px', overflow:'hidden' }}>
            <button onClick={()=>setVisning('liste')} style={{ padding:'8px 14px', border:'none', background:visning==='liste'?'#f1f5f9':'white', cursor:'pointer', fontSize:'16px', color:visning==='liste'?'#059669':'#94a3b8' }}>☰</button>
            <button onClick={()=>setVisning('kort')} style={{ padding:'8px 14px', border:'none', borderLeft:'1px solid #e2e8f0', background:visning==='kort'?'#f1f5f9':'white', cursor:'pointer', fontSize:'16px', color:visning==='kort'?'#059669':'#94a3b8' }}>⊞</button>
          </div>
        </div>

        {/* Empty */}
        {filtered.length===0 && (
          <div style={{ background:'white', borderRadius:'14px', border:'1px solid #f1f5f9', padding:'60px 20px', textAlign:'center' }}>
            <div style={{ fontSize:'40px', marginBottom:'12px' }}>👷</div>
            <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Ingen ansatte funnet</h3>
            <p style={{ margin:0, color:'#94a3b8', fontSize:'14px' }}>{employees.length===0?'Legg til din første ansatt.':'Prøv å endre søk eller filter.'}</p>
          </div>
        )}

        {/* LIST VIEW */}
        {visning==='liste' && filtered.length>0 && (
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            {filtered.map(emp=>{
              const expiring = (emp.employee_certifications||[]).filter(c=>{ const d=certDaysLeft(c.expiry_date); return d!==null&&d<=30 })
              const cfg = EMP_STATUS[emp.status]
              return (
                <div key={emp.id} onClick={()=>setSelected(emp)}
                  style={{ background:'white', borderRadius: isMobE ? '12px' : '14px', border:`1px solid ${expiring.length>0?'#fde68a':'#f1f5f9'}`, padding: isMobE ? '12px' : '14px 20px', cursor:'pointer', display:'flex', alignItems:'center', gap: isMobE ? '10px' : '16px', transition:'box-shadow 0.15s' }}
                  onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 16px rgba(0,0,0,0.08)'} onMouseLeave={e=>e.currentTarget.style.boxShadow='none'}>
                  <div style={{ width: isMobE ? '36px' : '44px', height: isMobE ? '36px' : '44px', borderRadius:'50%', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize: isMobE ? '14px' : '18px', fontWeight:'800', color:cfg.color, flexShrink:0 }}>
                    {emp.first_name?.[0]}{emp.last_name?.[0]}
                  </div>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', alignItems:'center', gap:'6px', flexWrap:'wrap', marginBottom:'3px' }}>
                      <span style={{ fontWeight:'700', color:'#0f172a', fontSize: isMobE ? '13px' : '15px' }}>{emp.first_name} {emp.last_name}</span>
                      <EmpStatusBadge status={emp.status} />
                      {expiring.length>0 && <span style={{ background:'#fffbeb', color:'#d97706', fontSize:'11px', fontWeight:'700', padding:'2px 8px', borderRadius:'999px', border:'1px solid #fde68a' }}>⚠️ {expiring.length} sertifikat</span>}
                    </div>
                    <div style={{ display:'flex', gap: isMobE ? '6px' : '12px', flexWrap:'wrap' }}>
                      {emp.position && <span style={{ fontSize: isMobE ? '11px' : '12px', color:'#64748b' }}>💼 {emp.position}</span>}
                      {!isMobE && emp.department && <span style={{ fontSize:'12px', color:'#64748b' }}>🏢 {emp.department}</span>}
                      {emp.phone && <span style={{ fontSize: isMobE ? '11px' : '12px', color:'#64748b' }}>📞 {emp.phone}</span>}
                      {!isMobE && emp.contract_type && <span style={{ fontSize:'12px', color:'#64748b' }}>📄 {emp.contract_type}</span>}
                    </div>
                  </div>
                  {!isMobE && emp.hourly_rate && <div style={{ textAlign:'right', flexShrink:0 }}><div style={{ fontWeight:'700', fontSize:'13px', color:'#0f172a' }}>{fmtE(emp.hourly_rate)} kr/t</div></div>}
                  {!isMobE && <span style={{ color:'#94a3b8', fontSize:'18px' }}>›</span>}
                </div>
              )
            })}
          </div>
        )}

        {/* KORT VIEW */}
        {visning==='kort' && filtered.length>0 && (
          <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(220px,1fr))', gap:'12px' }}>
            {filtered.map(emp=>{
              const expiring=(emp.employee_certifications||[]).filter(c=>{ const d=certDaysLeft(c.expiry_date); return d!==null&&d<=30 })
              const cfg=EMP_STATUS[emp.status]
              return (
                <div key={emp.id} onClick={()=>setSelected(emp)}
                  style={{ background:'white', borderRadius:'16px', border:`1px solid ${expiring.length>0?'#fde68a':'#f1f5f9'}`, padding:'20px', cursor:'pointer', display:'flex', flexDirection:'column', gap:'12px', transition:'box-shadow 0.15s' }}
                  onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 20px rgba(0,0,0,0.1)'} onMouseLeave={e=>e.currentTarget.style.boxShadow='none'}>
                  <div style={{ display:'flex', alignItems:'center', gap:'12px' }}>
                    <div style={{ width:'48px', height:'48px', borderRadius:'50%', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'18px', fontWeight:'800', color:cfg.color, flexShrink:0 }}>{emp.first_name?.[0]}{emp.last_name?.[0]}</div>
                    <div>
                      <div style={{ fontWeight:'700', color:'#0f172a', fontSize:'14px' }}>{emp.first_name} {emp.last_name}</div>
                      {emp.position&&<div style={{ fontSize:'12px', color:'#64748b' }}>{emp.position}</div>}
                    </div>
                  </div>
                  <div style={{ display:'flex', flexDirection:'column', gap:'4px' }}>
                    <EmpStatusBadge status={emp.status} />
                    {emp.department&&<span style={{ fontSize:'12px', color:'#64748b' }}>🏢 {emp.department}</span>}
                    {emp.phone&&<span style={{ fontSize:'12px', color:'#64748b' }}>📞 {emp.phone}</span>}
                  </div>
                  {expiring.length>0&&<span style={{ background:'#fffbeb', color:'#d97706', fontSize:'11px', fontWeight:'700', padding:'4px 10px', borderRadius:'8px', border:'1px solid #fde68a' }}>⚠️ {expiring.length} sertifikat utløper</span>}
                </div>
              )
            })}
          </div>
        )}
      </div>

      {showNew && <AnsattEditorModal projects={projects} user={user} onClose={()=>setShowNew(false)} onSaved={()=>{setShowNew(false);load()}} />}
      {showImport && <ImportCSVModal user={user} onClose={()=>setShowImport(false)} onSaved={()=>{setShowImport(false);load()}} />}
    </div>
  )
}

function AnsattDetaljer({ employee: init, projects, user, onBack }) {
  const confirm = useConfirm()
  const [emp, setEmp] = useState(init)
  const [certs, setCerts] = useState([])
  const [empProjects, setEmpProjects] = useState([])
  const [skills, setSkills] = useState([])
  const [editing, setEditing] = useState(false)
  const [showAddCert, setShowAddCert] = useState(false)
  const [showAddProject, setShowAddProject] = useState(false)
  const [activeTab, setActiveTab] = useState('info')
  const cfg = EMP_STATUS[emp.status]

  const loadDetails = async () => {
    const [c, ep, sk] = await Promise.all([
      supabase.from('employee_certifications').select('*').eq('employee_id',emp.id).order('expiry_date').then(r=>r.data||[]),
      supabase.from('employee_projects').select('*, projects(name)').eq('employee_id',emp.id).order('from_date',{ascending:false}).then(r=>r.data||[]),
      supabase.from('employee_skills').select('*').eq('employee_id',emp.id).order('skill').then(r=>r.data||[])
    ])
    setCerts(c); setEmpProjects(ep); setSkills(sk)
  }
  const refresh = async () => {
    const {data}=await supabase.from('employees').select('*').eq('id',emp.id).single()
    if (data) setEmp(data)
  }
  useEffect(()=>{ loadDetails() },[])

  const updateStatus = async (status) => {
    const updates = { status, updated_at:new Date().toISOString() }
    if (status==='Reaktivert') updates.end_date = null
    await supabase.from('employees').update(updates).eq('id',emp.id)
    invalidateEmployeeCache()
    setEmp(v=>({...v,...updates}))
  }

  const handleDelete = async () => {
    if (!(await confirm({ message: 'Slett denne ansatte?', subMessage: 'Den ansatte og all historikk slettes permanent. Dette kan ikke angres.', danger: true }))) return
    await supabase.from('employees').delete().eq('id',emp.id)
    invalidateEmployeeCache()
    onBack()
  }

  const deleteCert = async (id) => {
    if (!(await confirm({ message: 'Slett sertifikat?', subMessage: 'Sertifikatet slettes permanent.', danger: true }))) return
    await supabase.from('employee_certifications').delete().eq('id',id)
    loadDetails()
  }

  const removeProject = async (id) => {
    await supabase.from('employee_projects').delete().eq('id',id)
    loadDetails()
  }

  const tabs = [
    { id:'info', label:'Informasjon', emoji:'👤' },
    { id:'skills', label:'Kompetanser', emoji:'🎯' },
    { id:'certs', label:`Sertifikater (${certs.length})`, emoji:'📜' },
    { id:'projects', label:`Prosjekter (${empProjects.length})`, emoji:'🏗️' },
    { id:'salary', label:'Lønn', emoji:'💰' },
  ]

  const isMobED = typeof window !== 'undefined' && window.innerWidth < 768

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobED ? '14px' : '20px 32px' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#64748b', fontSize:'13px', marginBottom:'10px', display:'flex', alignItems:'center', gap:'6px', padding:0 }}>← Tilbake til ansatte</button>
        <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap: isMobED ? '8px' : '16px', flexWrap: isMobED ? 'wrap' : 'nowrap' }}>
          <div style={{ display:'flex', alignItems:'flex-start', gap: isMobED ? '10px' : '16px', flex:1, minWidth:0 }}>
            {!isMobED && <div style={{ width:'64px', height:'64px', borderRadius:'50%', background:cfg.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'22px', fontWeight:'800', color:cfg.color, flexShrink:0 }}>{emp.first_name?.[0]}{emp.last_name?.[0]}</div>}
            <div style={{ minWidth:0 }}>
              <div style={{ display:'flex', alignItems:'center', gap: isMobED ? '6px' : '10px', flexWrap:'wrap', marginBottom:'6px' }}>
                <h1 style={{ margin:0, fontSize: isMobED ? '16px' : '22px', fontWeight:'bold', color:'#0f172a' }}>{emp.first_name} {emp.last_name}</h1>
                {emp.employee_number&&<span style={{ fontSize:'13px', color:'#94a3b8', fontFamily:'monospace' }}>#{emp.employee_number}</span>}
                <EmpStatusBadge status={emp.status} />
              </div>
              <div style={{ display:'flex', gap: isMobED ? '6px' : '12px', flexWrap:'wrap' }}>
                {emp.position&&<span style={{ fontSize: isMobED ? '11px' : '13px', color:'#64748b' }}>💼 {emp.position}</span>}
                {!isMobED && emp.department&&<span style={{ fontSize:'13px', color:'#64748b' }}>🏢 {emp.department}</span>}
                {!isMobED && emp.contract_type&&<span style={{ fontSize:'13px', color:'#64748b' }}>📄 {emp.contract_type}</span>}
                {emp.phone&&<span style={{ fontSize: isMobED ? '11px' : '13px', color:'#64748b' }}>📞 {emp.phone}</span>}
              </div>
            </div>
          </div>
          <div style={{ display:'flex', gap:'6px', flexShrink:0 }}>
            <button onClick={()=>setEditing(true)} style={{ padding: isMobED ? '7px 10px' : '9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize: isMobED ? '12px' : '13px' }}>✏️</button>
            <button onClick={handleDelete} style={{ padding: isMobED ? '7px 10px' : '9px 12px', border:'1px solid #fecaca', borderRadius:'10px', background:'white', cursor:'pointer', color:'#dc2626', fontSize: isMobED ? '12px' : '13px' }}>🗑️</button>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:'flex', gap:'4px', marginTop: isMobED ? '14px' : '20px', overflowX:'auto', WebkitOverflowScrolling:'touch' }}>
          {tabs.map(t=>(
            <button key={t.id} onClick={()=>setActiveTab(t.id)}
              style={{ padding: isMobED ? '7px 10px' : '8px 16px', borderRadius:'10px', border:'none', background:activeTab===t.id?'#059669':'#f8fafc', color:activeTab===t.id?'white':'#64748b', fontWeight:activeTab===t.id?'700':'500', fontSize: isMobED ? '11px' : '13px', cursor:'pointer', whiteSpace:'nowrap' }}>
              {t.emoji} {isMobED ? t.label.replace('Informasjon','Info').replace('Kompetanser','Komp.').replace('Sertifikater','Sert.').replace('Prosjekter','Prosj.') : t.label}
            </button>
          ))}
        </div>
      </div>

      <div style={{ padding: isMobED ? '12px' : '24px 32px', display:'grid', gridTemplateColumns: isMobED ? '1fr' : '2fr 1fr', gap: isMobED ? '12px' : '20px' }}>
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>

          {/* INFO TAB */}
          {activeTab==='info' && (
            <>
              <div style={eCard}>
                <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>👤 Personopplysninger</h3>
                <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'8px' }}>
                  {[['Fullt navn',`${emp.first_name} ${emp.last_name}`],['Stilling',emp.position],['Avdeling',emp.department],['Kontraktstype',emp.contract_type],['E-post',emp.email],['Telefon',emp.phone],['Adresse',emp.address],['Fødselsdato',emp.birth_date],['Ansattdato',emp.hired_date],['Sluttdato',emp.end_date]].filter(r=>r[1]).map(([k,v])=>(
                    <div key={k} style={{ background:'#f8fafc', borderRadius:'8px', padding:'9px 12px' }}>
                      <div style={{ fontSize:'11px', color:'#94a3b8', textTransform:'uppercase', fontWeight:'600' }}>{k}</div>
                      <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a', marginTop:'2px' }}>{v}</div>
                    </div>
                  ))}
                </div>
              </div>
              {(emp.emergency_contact_name||emp.emergency_contact_phone) && (
                <div style={{ ...eCard, background:'#fff7ed', border:'1px solid #fed7aa' }}>
                  <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'700', color:'#ea580c' }}>🚨 Nødkontakt</h3>
                  <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr 1fr', gap:'8px' }}>
                    {[['Navn',emp.emergency_contact_name],['Telefon',emp.emergency_contact_phone],['Relasjon',emp.emergency_contact_relation]].filter(r=>r[1]).map(([k,v])=>(
                      <div key={k}><div style={{ fontSize:'11px', color:'#94a3b8', fontWeight:'600', marginBottom:'2px' }}>{k}</div><div style={{ fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>{v}</div></div>
                    ))}
                  </div>
                </div>
              )}
              {emp.notes && <div style={eCard}><h3 style={{ margin:'0 0 8px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📝 Notater</h3><p style={{ margin:0, fontSize:'14px', color:'#475569', lineHeight:1.6 }}>{emp.notes}</p></div>}
            </>
          )}


          {/* SKILLS TAB */}
          {activeTab==='skills' && (
            <SkillsTab employeeId={emp.id} skills={skills} onRefresh={loadDetails} />
          )}

          {/* CERTS TAB */}
          {activeTab==='certs' && (
            <div style={eCard}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'16px' }}>
                <h3 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📜 Sertifikater og kompetanse</h3>
                <button onClick={()=>setShowAddCert(true)} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>+ Legg til</button>
              </div>
              {certs.length===0 ? <p style={{ color:'#94a3b8', fontSize:'14px', fontStyle:'italic' }}>Ingen sertifikater registrert</p> : (
                <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
                  {certs.map(c=>{
                    const days=certDaysLeft(c.expiry_date)
                    const expired=days!==null&&days<0
                    const expiring=days!==null&&days>=0&&days<=30
                    return (
                      <div key={c.id} style={{ background:expired?'#fef2f2':expiring?'#fffbeb':'#f8fafc', borderRadius:'12px', padding:'14px 16px', border:`1px solid ${expired?'#fecaca':expiring?'#fde68a':'#f1f5f9'}` }}>
                        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
                          <div style={{ flex:1 }}>
                            <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'4px' }}>
                              <span style={{ fontWeight:'700', color:'#0f172a', fontSize:'14px' }}>{c.name}</span>
                              <CertBadge expiry={c.expiry_date} />
                            </div>
                            <div style={{ display:'flex', gap:'12px', flexWrap:'wrap', fontSize:'12px', color:'#64748b' }}>
                              {c.issuer&&<span>Utstedt av: {c.issuer}</span>}
                              {c.certificate_number&&<span>Nr: {c.certificate_number}</span>}
                              {c.issued_date&&<span>Utstedt: {c.issued_date}</span>}
                              {c.expiry_date&&<span style={{ color:expired?'#dc2626':expiring?'#d97706':'#64748b', fontWeight:expired||expiring?'700':'400' }}>Utløper: {c.expiry_date}</span>}
                            </div>
                            {c.notes&&<p style={{ margin:'6px 0 0', fontSize:'12px', color:'#94a3b8' }}>{c.notes}</p>}
                          </div>
                          <button onClick={()=>deleteCert(c.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'16px', marginLeft:'8px' }}>×</button>
                        </div>
                      </div>
                    )
                  })}
                </div>
              )}
            </div>
          )}

          {/* PROJECTS TAB */}
          {activeTab==='projects' && (
            <div style={eCard}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'16px' }}>
                <h3 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>🏗️ Prosjekttilknytning</h3>
                <button onClick={()=>setShowAddProject(true)} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>+ Tilordne prosjekt</button>
              </div>
              {empProjects.length===0 ? <p style={{ color:'#94a3b8', fontSize:'14px', fontStyle:'italic' }}>Ikke tilordnet noen prosjekter</p> : (
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {empProjects.map(ep=>(
                    <div key={ep.id} style={{ display:'flex', alignItems:'center', gap:'12px', background:'#f8fafc', borderRadius:'10px', padding:'12px 16px', border:'1px solid #f1f5f9' }}>
                      <div style={{ flex:1 }}>
                        <div style={{ fontWeight:'700', fontSize:'14px', color:'#0f172a' }}>{ep.projects?.name||'—'}</div>
                        <div style={{ display:'flex', gap:'10px', fontSize:'12px', color:'#64748b', marginTop:'2px' }}>
                          {ep.role&&<span>Rolle: {ep.role}</span>}
                          {ep.from_date&&<span>Fra: {ep.from_date}</span>}
                          {ep.to_date&&<span>Til: {ep.to_date}</span>}
                        </div>
                      </div>
                      <button onClick={()=>removeProject(ep.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#dc2626', fontSize:'16px' }}>×</button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* SALARY TAB */}
          {activeTab==='salary' && (
            <div style={eCard}>
              <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>💰 Lønn og satser (intern)</h3>
              <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
                {emp.hourly_rate && (
                  <div style={{ background:'#f0fdf4', borderRadius:'12px', padding:'16px', border:'1px solid #bbf7d0', textAlign:'center' }}>
                    <div style={{ fontSize:'11px', color:'#16a34a', fontWeight:'600', textTransform:'uppercase', marginBottom:'4px' }}>Timesats</div>
                    <div style={{ fontSize:'24px', fontWeight:'800', color:'#0f172a' }}>{fmtE(emp.hourly_rate)} kr</div>
                  </div>
                )}
                {emp.monthly_salary && (
                  <div style={{ background:'#eff6ff', borderRadius:'12px', padding:'16px', border:'1px solid #bfdbfe', textAlign:'center' }}>
                    <div style={{ fontSize:'11px', color:'#2563eb', fontWeight:'600', textTransform:'uppercase', marginBottom:'4px' }}>Månedslønn</div>
                    <div style={{ fontSize:'24px', fontWeight:'800', color:'#0f172a' }}>{fmtE(emp.monthly_salary)} kr</div>
                  </div>
                )}
              </div>
              {!emp.hourly_rate&&!emp.monthly_salary&&<p style={{ color:'#94a3b8', fontSize:'14px', fontStyle:'italic' }}>Ingen lønnsinfo registrert. Rediger ansatt for å legge til.</p>}
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div style={{ display:'flex', flexDirection:'column', gap:'16px' }}>
          <div style={eCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>🔄 Status</h3>
            <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
              {Object.keys(EMP_STATUS).map(s=>(
                <button key={s} onClick={()=>updateStatus(s)} disabled={emp.status===s}
                  style={{ padding:'9px 14px', borderRadius:'10px', border:`1px solid ${emp.status===s?EMP_STATUS[s].border:'#e2e8f0'}`, background:emp.status===s?EMP_STATUS[s].bg:'white', color:emp.status===s?EMP_STATUS[s].color:'#475569', fontWeight:emp.status===s?'700':'400', fontSize:'13px', cursor:emp.status===s?'default':'pointer', textAlign:'left', width:'100%' }}>
                  {emp.status===s?'✓ ':''}{EMP_STATUS[s].emoji} {s}
                </button>
              ))}
            </div>
          </div>
          <div style={eCard}>
            <h3 style={{ margin:'0 0 12px', fontSize:'14px', fontWeight:'600', color:'#0f172a' }}>📊 Oversikt</h3>
            {[['Ansatt',emp.hired_date],['Avdeling',emp.department],['Kontrakt',emp.contract_type],['Sertifikater',certs.length+' stk'],['Prosjekter',empProjects.length+' stk']].filter(r=>r[1]).map(([k,v],i)=>(
              <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #f8fafc', fontSize:'13px' }}>
                <span style={{ color:'#94a3b8' }}>{k}</span><span style={{ fontWeight:'500', color:'#0f172a' }}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {editing&&<AnsattEditorModal projects={projects} user={user} initial={emp} onClose={()=>setEditing(false)} onSaved={()=>{setEditing(false);refresh();loadDetails()}} />}
      {showAddCert&&<LeggTilSertifikatModal employeeId={emp.id} onClose={()=>setShowAddCert(false)} onSaved={()=>{setShowAddCert(false);loadDetails()}} />}
      {showAddProject&&<LeggTilProsjektModal employeeId={emp.id} projects={projects} existingIds={empProjects.map(ep=>ep.project_id)} onClose={()=>setShowAddProject(false)} onSaved={()=>{setShowAddProject(false);loadDetails()}} />}
    </div>
  )
}

function AnsattEditorModal({ projects, user, initial, onClose, onSaved }) {
  const isEdit = !!initial
  const [form, setForm] = useState({
    first_name:initial?.first_name||'', last_name:initial?.last_name||'',
    employee_number:initial?.employee_number||'', position:initial?.position||'',
    department:initial?.department||'', contract_type:initial?.contract_type||'Fast',
    email:initial?.email||'', phone:initial?.phone||'', address:initial?.address||'',
    birth_date:initial?.birth_date||'', hired_date:initial?.hired_date||new Date().toISOString().split('T')[0],
    end_date:initial?.end_date||'',
    hourly_rate:initial?.hourly_rate||'', monthly_salary:initial?.monthly_salary||'',
    emergency_contact_name:initial?.emergency_contact_name||'',
    emergency_contact_phone:initial?.emergency_contact_phone||'',
    emergency_contact_relation:initial?.emergency_contact_relation||'',
    notes:initial?.notes||'',
  })
  const [saving, setSaving] = useState(false)
  const set = (k,v) => setForm(f=>({...f,[k]:v}))

  const handleSave = async () => {
    if (!form.first_name.trim()||!form.last_name.trim()) return alert('For- og etternavn er påkrevd')
    setSaving(true)
    try {
      const payload = {
        ...form,
        hourly_rate: form.hourly_rate?parseFloat(form.hourly_rate):null,
        monthly_salary: form.monthly_salary?parseFloat(form.monthly_salary):null,
        birth_date:form.birth_date||null, end_date:form.end_date||null,
        updated_at:new Date().toISOString()
      }
      if (isEdit) { const {error}=await supabase.from('employees').update(payload).eq('id',initial.id); if(error) throw error }
      else { const {error}=await supabase.from('employees').insert({...payload,status:'Aktiv',created_by:user?.id}); if(error) throw error }
      invalidateEmployeeCache()
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  const lbl = t => <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>{t}</label>
  const sec = t => <div style={{ gridColumn:'1/-1', fontSize:'13px', fontWeight:'700', color:'#0f172a', borderTop:'1px solid #f1f5f9', paddingTop:'14px', marginTop:'4px' }}>{t}</div>

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'720px', maxHeight:'94vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a', whiteSpace:'nowrap' }}>👷 {isEdit?'Rediger ansatt':'Ny ansatt'}</h2>
          <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
            <button onClick={handleSave} disabled={saving} style={{ padding:'8px 20px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize:'14px', fontWeight:'700' }}>{saving?'Lagrer...':isEdit?'Lagre':'Registrer ansatt'}</button>
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8', marginLeft:'4px' }}>×</button>
          </div>
        </div>
        <div style={{ overflowY:'auto', flex:1, padding:'24px', display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
          {sec('👤 Personopplysninger')}
          <div>{lbl('Fornavn *')}<input value={form.first_name} onChange={e=>set('first_name',e.target.value)} placeholder="Fornavn" style={eInp} /></div>
          <div>{lbl('Etternavn *')}<input value={form.last_name} onChange={e=>set('last_name',e.target.value)} placeholder="Etternavn" style={eInp} /></div>
          <div>{lbl('Ansattnummer')}<input value={form.employee_number} onChange={e=>set('employee_number',e.target.value)} placeholder="001" style={eInp} /></div>
          <div>{lbl('Fødselsdato')}<input type="date" value={form.birth_date} onChange={e=>set('birth_date',e.target.value)} style={eInp} /></div>
          <div>{lbl('E-post')}<input type="email" value={form.email} onChange={e=>set('email',e.target.value)} placeholder="epost@firma.no" style={eInp} /></div>
          <div>{lbl('Telefon')}<input value={form.phone} onChange={e=>set('phone',e.target.value)} placeholder="+47 xxx xx xxx" style={eInp} /></div>
          <div style={{ gridColumn:'1/-1' }}>{lbl('Adresse')}<input value={form.address} onChange={e=>set('address',e.target.value)} placeholder="Gateadresse, postnr sted" style={eInp} /></div>

          {sec('💼 Ansettelsesinfo')}
          <div>{lbl('Stilling')}<input value={form.position} onChange={e=>set('position',e.target.value)} placeholder="F.eks. Anleggsleder" style={eInp} /></div>
          <div>{lbl('Avdeling')}<select value={form.department} onChange={e=>set('department',e.target.value)} style={eInp}><option value="">Velg...</option>{DEPARTMENTS.map(d=><option key={d} value={d}>{d}</option>)}</select></div>
          <div>{lbl('Kontraktstype')}<select value={form.contract_type} onChange={e=>set('contract_type',e.target.value)} style={eInp}>{CONTRACT_TYPES.map(t=><option key={t} value={t}>{t}</option>)}</select></div>
          <div>{lbl('Ansettelsesdato')}<input type="date" value={form.hired_date} onChange={e=>set('hired_date',e.target.value)} style={eInp} /></div>
          <div>{lbl('Sluttdato (ved avgang)')}<input type="date" value={form.end_date} onChange={e=>set('end_date',e.target.value)} style={eInp} /></div>

          {sec('💰 Lønn (intern)')}
          <div>{lbl('Timesats (kr)')}<input type="number" value={form.hourly_rate} onChange={e=>set('hourly_rate',e.target.value)} placeholder="0" style={eInp} /></div>
          <div>{lbl('Månedslønn (kr)')}<input type="number" value={form.monthly_salary} onChange={e=>set('monthly_salary',e.target.value)} placeholder="0" style={eInp} /></div>

          {sec('🚨 Nødkontakt')}
          <div>{lbl('Navn')}<input value={form.emergency_contact_name} onChange={e=>set('emergency_contact_name',e.target.value)} placeholder="Fullt navn" style={eInp} /></div>
          <div>{lbl('Telefon')}<input value={form.emergency_contact_phone} onChange={e=>set('emergency_contact_phone',e.target.value)} placeholder="+47 xxx xx xxx" style={eInp} /></div>
          <div>{lbl('Relasjon')}<input value={form.emergency_contact_relation} onChange={e=>set('emergency_contact_relation',e.target.value)} placeholder="F.eks. Ektefelle, forelder" style={eInp} /></div>

          <div style={{ gridColumn:'1/-1', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>{lbl('Notater / Interne merknader')}<textarea value={form.notes} onChange={e=>set('notes',e.target.value)} rows={3} style={{ ...eInp, resize:'none' }} placeholder="Interne notater om den ansatte..." /></div>
        </div>

      </div>
    </div>
  )
}

function LeggTilSertifikatModal({ employeeId, onClose, onSaved }) {
  const [form, setForm] = useState({ name:'', issuer:'', issued_date:'', expiry_date:'', certificate_number:'', notes:'' })
  const [saving, setSaving] = useState(false)
  const set = (k,v) => setForm(f=>({...f,[k]:v}))

  const handleSave = async () => {
    if (!form.name.trim()) return alert('Navn er påkrevd')
    setSaving(true)
    try {
      const {error}=await supabase.from('employee_certifications').insert({ employee_id:employeeId, ...form, issued_date:form.issued_date||null, expiry_date:form.expiry_date||null })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'500px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>📜 Legg til sertifikat</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'24px', display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
          <div style={{ gridColumn:'1/-1' }}>
            <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Sertifikattype *</label>
            <select value={form.name} onChange={e=>set('name',e.target.value)} style={eInp}>
              <option value="">Velg type...</option>
              {CERT_TYPES.map(t=><option key={t} value={t}>{t}</option>)}
            </select>
            {form.name==='Annet'&&<input value={form.name} onChange={e=>set('name',e.target.value)} placeholder="Beskriv sertifikat" style={{ ...eInp, marginTop:'8px' }} />}
          </div>
          {[['issuer','Utstedende organ','F.eks. Arbeidstilsynet'],['certificate_number','Sertifikatnummer','Nr.'],].map(([k,l,ph])=>(
            <div key={k}><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>{l}</label><input value={form[k]} onChange={e=>set(k,e.target.value)} placeholder={ph} style={eInp} /></div>
          ))}
          <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Utstedelsesdato</label><input type="date" value={form.issued_date} onChange={e=>set('issued_date',e.target.value)} style={eInp} /></div>
          <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Utløpsdato</label><input type="date" value={form.expiry_date} onChange={e=>set('expiry_date',e.target.value)} style={eInp} /></div>
          <div style={{ gridColumn:'1/-1' }}><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Merknad</label><textarea value={form.notes} onChange={e=>set('notes',e.target.value)} rows={2} style={{ ...eInp, resize:'none' }} /></div>
          <div style={{ gridColumn:'1/-1', display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSave} disabled={saving} style={{ padding:'10px 24px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{saving?'Lagrer...':'Legg til'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

function LeggTilProsjektModal({ employeeId, projects, existingIds, onClose, onSaved }) {
  const [form, setForm] = useState({ project_id:'', role:'', from_date:'', to_date:'' })
  const [saving, setSaving] = useState(false)
  const available = projects.filter(p=>!existingIds.includes(p.id))

  const handleSave = async () => {
    if (!form.project_id) return alert('Velg et prosjekt')
    setSaving(true)
    try {
      const {error}=await supabase.from('employee_projects').insert({ employee_id:employeeId, ...form, from_date:form.from_date||null, to_date:form.to_date||null })
      if (error) throw error
      onSaved()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:110, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'440px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif', overflow:'hidden' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>🏗️ Tilordne prosjekt</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ padding:'24px', display:'flex', flexDirection:'column', gap:'12px' }}>
          <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Prosjekt *</label>
            <select value={form.project_id} onChange={e=>setForm(f=>({...f,project_id:e.target.value}))} style={eInp}>
              <option value="">Velg prosjekt...</option>
              {available.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>
          <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Rolle på prosjektet</label><input value={form.role} onChange={e=>setForm(f=>({...f,role:e.target.value}))} placeholder="F.eks. Anleggsleder, Fagarbeider" style={eInp} /></div>
          <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'10px' }}>
            <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Fra dato</label><input type="date" value={form.from_date} onChange={e=>setForm(f=>({...f,from_date:e.target.value}))} style={eInp} /></div>
            <div><label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Til dato</label><input type="date" value={form.to_date} onChange={e=>setForm(f=>({...f,to_date:e.target.value}))} style={eInp} /></div>
          </div>
          <div style={{ display:'flex', justifyContent:'flex-end', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
            <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
            <button onClick={handleSave} disabled={saving} style={{ padding:'10px 24px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:saving?'not-allowed':'pointer', fontSize:'14px', fontWeight:'600' }}>{saving?'Lagrer...':'Tilordne'}</button>
          </div>
        </div>
      </div>
    </div>
  )
}

function ImportCSVModal({ user, onClose, onSaved }) {
  const [csvText, setCsvText] = useState('')
  const [preview, setPreview] = useState([])
  const [importing, setImporting] = useState(false)
  const [done, setDone] = useState(false)

  const parseCSV = (text) => {
    const lines = text.trim().split('\n').filter(l=>l.trim())
    if (lines.length<2) return []
    const headers = lines[0].split(';').map(h=>h.trim().toLowerCase())
    return lines.slice(1).map(line=>{
      const vals = line.split(';').map(v=>v.trim())
      const obj = {}
      headers.forEach((h,i)=>{ obj[h]=vals[i]||'' })
      return obj
    })
  }

  const handlePreview = () => {
    const rows = parseCSV(csvText)
    setPreview(rows.slice(0,5))
  }

  const handleImport = async () => {
    const rows = parseCSV(csvText)
    if (rows.length===0) return alert('Ingen gyldige rader funnet')
    setImporting(true)
    try {
      const employees = rows.map(r=>({
        first_name: r.fornavn||r.first_name||r['first name']||'',
        last_name: r.etternavn||r.last_name||r['last name']||'',
        position: r.stilling||r.position||'',
        department: r.avdeling||r.department||'',
        email: r.epost||r.email||'',
        phone: r.telefon||r.phone||'',
        contract_type: r.kontrakt||r.contract_type||'Fast',
        hired_date: r.ansattdato||r.hired_date||new Date().toISOString().split('T')[0],
        hourly_rate: r.timesats||r.hourly_rate?parseFloat(r.timesats||r.hourly_rate)||null:null,
        status: 'Aktiv', created_by: user?.id
      })).filter(e=>e.first_name&&e.last_name)
      const { error } = await supabase.from('employees').insert(employees)
      if (error) throw error
      invalidateEmployeeCache()
      setDone(true)
      setTimeout(()=>onSaved(), 1500)
    } catch(e) { alert('Feil: '+e.message) }
    finally { setImporting(false) }
  }

  return (
    <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'640px', maxHeight:'90vh', display:'flex', flexDirection:'column', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ margin:0, fontSize:'18px', fontWeight:'700', color:'#0f172a' }}>📥 Importer ansatte fra CSV</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'22px', cursor:'pointer', color:'#94a3b8' }}>×</button>
        </div>
        <div style={{ overflowY:'auto', flex:1, padding:'24px', display:'flex', flexDirection:'column', gap:'16px' }}>
          {done ? (
            <div style={{ textAlign:'center', padding:'20px' }}>
              <div style={{ fontSize:'48px', marginBottom:'12px' }}>✅</div>
              <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>Ansatte importert!</h3>
            </div>
          ) : (
            <>
              <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'14px 16px', border:'1px solid #f1f5f9', fontSize:'13px', color:'#475569', lineHeight:1.6 }}>
                <strong>Format (semikolon-separert):</strong><br/>
                <code style={{ fontSize:'12px', color:'#059669' }}>fornavn;etternavn;stilling;avdeling;epost;telefon;kontrakt;ansattdato;timesats</code><br/>
                <code style={{ fontSize:'12px', color:'#64748b' }}>Ola;Nordmann;Anleggsleder;Anlegg;ola@firma.no;+47 123 45 678;Fast;2024-01-01;450</code>
              </div>
              <div>
                <label style={{ display:'block', fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'6px' }}>Lim inn CSV-data</label>
                <textarea value={csvText} onChange={e=>setCsvText(e.target.value)} rows={8} placeholder="fornavn;etternavn;stilling;avdeling;epost;telefon..." style={{ ...eInp, resize:'vertical', fontFamily:'monospace', fontSize:'12px' }} />
              </div>
              {preview.length>0 && (
                <div>
                  <div style={{ fontSize:'13px', fontWeight:'600', color:'#374151', marginBottom:'8px' }}>Forhåndsvisning ({preview.length} av {parseCSV(csvText).length} rader):</div>
                  <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px', overflow:'auto' }}>
                    {preview.map((r,i)=><div key={i} style={{ fontSize:'12px', color:'#475569', padding:'4px 0', borderBottom:'1px solid #f1f5f9' }}>{r.fornavn||r.first_name} {r.etternavn||r.last_name} – {r.stilling||r.position||'—'} – {r.avdeling||r.department||'—'}</div>)}
                  </div>
                </div>
              )}
              <div style={{ display:'flex', justifyContent:'space-between', gap:'12px', borderTop:'1px solid #f1f5f9', paddingTop:'14px' }}>
                <button onClick={handlePreview} disabled={!csvText.trim()} style={{ padding:'10px 18px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'500' }}>👁️ Forhåndsvis</button>
                <div style={{ display:'flex', gap:'10px' }}>
                  <button onClick={onClose} style={{ padding:'10px 20px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
                  <button onClick={handleImport} disabled={importing||!csvText.trim()} style={{ padding:'10px 24px', background:importing||!csvText.trim()?'#94a3b8':'#059669', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'14px', fontWeight:'600' }}>{importing?'Importerer...':'📥 Importer'}</button>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  )
}


const ALL_SKILLS = [
  'Graving','Sprengning','Betong','Armering','Stål/Sveis','Tømrer','Rørlegger','Elektro',
  'Stillas','Asfalt','Maskinføring','Kran','Truck','Fallsikring','HMS-ansvarlig',
  'Prosjektledelse','BIM/Tegning','Anleggsmaskin','Rigg','Kvalitetskontroll','Annet'
]

const SKILL_LEVELS = {
  basis:   { label:'Basis',   color:'#64748b', bg:'#f8fafc' },
  erfaren: { label:'Erfaren', color:'#d97706', bg:'#fffbeb' },
  ekspert: { label:'Ekspert', color:'#059669', bg:'#f0fdf4' },
}

function SkillsTab({ employeeId, skills, onRefresh }) {
  const [adding, setAdding] = useState(false)
  const [newSkill, setNewSkill] = useState('')
  const [newLevel, setNewLevel] = useState('basis')
  const [saving, setSaving] = useState(false)
  const [customSkill, setCustomSkill] = useState('')

  const handleAdd = async () => {
    const skillName = newSkill==='Annet' ? customSkill.trim() : newSkill
    if (!skillName) return alert('Velg eller skriv inn kompetanse')
    setSaving(true)
    try {
      const {error} = await supabase.from('employee_skills').insert({ employee_id:employeeId, skill:skillName, level:newLevel })
      if (error&&error.code==='23505') { alert('Denne kompetansen er allerede lagt til') }
      else if (error) throw error
      else { setAdding(false); setNewSkill(''); setCustomSkill(''); onRefresh() }
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  const handleDelete = async (id) => {
    await supabase.from('employee_skills').delete().eq('id',id)
    onRefresh()
  }

  const updateLevel = async (id, level) => {
    await supabase.from('employee_skills').update({level}).eq('id',id)
    onRefresh()
  }

  const existing = skills.map(s=>s.skill)

  return (
    <div style={{ background:'white', borderRadius:'16px', border:'1px solid #f1f5f9', padding:'20px 24px', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'16px' }}>
        <h3 style={{ margin:0, fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>🎯 Kompetanser og ferdigheter</h3>
        <button onClick={()=>setAdding(v=>!v)} style={{ background:'#f0fdf4', color:'#059669', border:'none', borderRadius:'8px', padding:'7px 14px', fontSize:'13px', fontWeight:'600', cursor:'pointer' }}>+ Legg til</button>
      </div>

      {adding && (
        <div style={{ background:'#f8fafc', borderRadius:'12px', padding:'14px', border:'1px solid #f1f5f9', marginBottom:'16px', display:'flex', flexDirection:'column', gap:'10px' }}>
          <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'10px' }}>
            <div>
              <label style={{ display:'block', fontSize:'12px', fontWeight:'600', color:'#374151', marginBottom:'5px' }}>Kompetanse</label>
              <select value={newSkill} onChange={e=>setNewSkill(e.target.value)} style={{ width:'100%', padding:'8px 12px', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize:'13px', outline:'none', background:'white' }}>
                <option value="">Velg kompetanse...</option>
                {ALL_SKILLS.filter(s=>!existing.includes(s)).map(s=><option key={s} value={s}>{s}</option>)}
              </select>
              {newSkill==='Annet'&&<input value={customSkill} onChange={e=>setCustomSkill(e.target.value)} placeholder="Beskriv kompetanse..." style={{ width:'100%', padding:'8px 12px', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize:'13px', outline:'none', marginTop:'6px', boxSizing:'border-box' }} />}
            </div>
            <div>
              <label style={{ display:'block', fontSize:'12px', fontWeight:'600', color:'#374151', marginBottom:'5px' }}>Nivå</label>
              <div style={{ display:'flex', gap:'6px' }}>
                {Object.entries(SKILL_LEVELS).map(([k,v])=>(
                  <button key={k} onClick={()=>setNewLevel(k)}
                    style={{ flex:1, padding:'8px 4px', borderRadius:'8px', border:`2px solid ${newLevel===k?v.color:'#e2e8f0'}`, background:newLevel===k?v.bg:'white', color:newLevel===k?v.color:'#64748b', fontWeight:newLevel===k?'700':'400', fontSize:'12px', cursor:'pointer' }}>
                    {v.label}
                  </button>
                ))}
              </div>
            </div>
          </div>
          <div style={{ display:'flex', justifyContent:'flex-end', gap:'8px' }}>
            <button onClick={()=>setAdding(false)} style={{ padding:'7px 14px', border:'1px solid #e2e8f0', borderRadius:'8px', background:'white', cursor:'pointer', fontSize:'13px', color:'#64748b' }}>Avbryt</button>
            <button onClick={handleAdd} disabled={saving||!newSkill} style={{ padding:'7px 14px', background:saving||!newSkill?'#94a3b8':'#059669', color:'white', border:'none', borderRadius:'8px', cursor:'pointer', fontSize:'13px', fontWeight:'600' }}>{saving?'Lagrer...':'Legg til'}</button>
          </div>
        </div>
      )}

      {skills.length===0&&!adding ? (
        <p style={{ color:'#94a3b8', fontSize:'14px', fontStyle:'italic' }}>Ingen kompetanser registrert ennå</p>
      ) : (
        <div style={{ display:'flex', flexWrap:'wrap', gap:'8px' }}>
          {skills.map(s=>{
            const lvl = SKILL_LEVELS[s.level]||SKILL_LEVELS.basis
            return (
              <div key={s.id} style={{ display:'flex', alignItems:'center', gap:'6px', background:lvl.bg, border:`1px solid ${lvl.color}30`, borderRadius:'10px', padding:'6px 12px' }}>
                <span style={{ fontSize:'13px', fontWeight:'600', color:lvl.color }}>🎯 {s.skill}</span>
                <select value={s.level} onChange={e=>updateLevel(s.id,e.target.value)} style={{ fontSize:'11px', border:'none', background:'transparent', color:lvl.color, fontWeight:'700', cursor:'pointer', outline:'none' }}>
                  {Object.entries(SKILL_LEVELS).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
                </select>
                <button onClick={()=>handleDelete(s.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#94a3b8', fontSize:'14px', padding:0, lineHeight:1 }}>×</button>
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

