// ═══════════════════════════════════════════════════════════════════════
// SUPERADMIN — Platform Owner Control Panel
// ═══════════════════════════════════════════════════════════════════════
function SuperAdminPage() {
  const { user } = useAuth()
  const [companies, setCompanies] = useState([])
  const [allUsers, setAllUsers] = useState([])
  const [loading, setLoading] = useState(true)
  const [tab, setTab] = useState('oversikt')
  const [selectedCompany, setSelectedCompany] = useState(null)
  const [notifications, setNotifications] = useState([])
  const [saSearch, setSaSearch] = useState('')
  const [saFilter, setSaFilter] = useState('alle')
  const [editNote, setEditNote] = useState(null) // { companyId, note }
  const [emailModal, setEmailModal] = useState(null) // { to, companyName, subject, body }
  const [sendingEmail, setSendingEmail] = useState(false)
  const [paymentModal, setPaymentModal] = useState(null) // { companyId }
  const [storageInfo, setStorageInfo] = useState(null)
  const [mrrSnapshots, setMrrSnapshots] = useState([])
  const [churnAlerts, setChurnAlerts] = useState([])
  const [savingNote, setSavingNote] = useState(false)
  const [isMobSA, setIsMobSA] = useState(typeof window !== 'undefined' && window.innerWidth < 640)
  useEffect(() => {
    const onResize = () => setIsMobSA(window.innerWidth < 640)
    window.addEventListener('resize', onResize)
    window.addEventListener('orientationchange', onResize)
    return () => {
      window.removeEventListener('resize', onResize)
      window.removeEventListener('orientationchange', onResize)
    }
  }, [])

  const savePayment = async (companyId, paymentDate) => {
    try {
      const comp = companies.find(c=>c.id===companyId)
      const history = comp?.payment_history || []
      history.push({ date: paymentDate, recorded_at: new Date().toISOString() })
      const nextDue = new Date(paymentDate)
      nextDue.setMonth(nextDue.getMonth()+1)
      await supabase.from('company_settings').update({
        last_payment_date: paymentDate,
        next_due_date: nextDue.toISOString().split('T')[0],
        payment_history: history,
        updated_at: new Date().toISOString()
      }).eq('id', companyId)
      setPaymentModal(null)
      load()
    } catch(e) { alert('Feil: '+e.message) }
  }

  const sendEmail = async () => {
    if (!emailModal) return
    setSendingEmail(true)
    try {
      const mailto = `mailto:${encodeURIComponent(emailModal.to)}?subject=${encodeURIComponent(emailModal.subject||'')}&body=${encodeURIComponent(emailModal.body||'')}`
      window.location.href = mailto
      // Logg hendelsen
      const compId = companies.find(c=>c.email===emailModal.to)?.id
      if (compId) {
        try { await addTimelineEvent(compId, { type:'note', label: `E-post sendt: ${emailModal.subject||'(uten emne)'}` }) } catch(e) {}
      }
      setEmailModal(null)
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSendingEmail(false) }
  }

  const addTimelineEvent = async (companyId, event) => {
    const comp = companies.find(c=>c.id===companyId)
    const timeline = comp?.timeline || []
    timeline.push({ ...event, timestamp: new Date().toISOString() })
    try { await supabase.from('company_settings').update({ timeline, updated_at: new Date().toISOString() }).eq('id', companyId) } catch(e) {}
  }

  const setCompanyStatus = async (companyId, status) => {
    await supabase.from('company_settings').update({ subscription_status: status }).eq('id', companyId)
    try { await addTimelineEvent(companyId, { type:'status', label: status==='active'?'Aktivert':status==='cancelled'?'Kansellert':'Statusendring: '+status }) } catch(e) {}
    load()
  }

  const saveCompanyNote = async (companyId, note) => {
    setSavingNote(true)
    try {
      await supabase.from('company_settings').update({ admin_notes: note, updated_at: new Date().toISOString() }).eq('id', companyId)
      setEditNote(null)
      load()
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSavingNote(false) }
  }

  const exportCSV = () => {
    const headers = ['Bedrift','Status','E-post','Telefon','Org.nr','Brukere','Moduler','MRR','Registrert','Trial slutt','Notater']
    const rows = companies.map(c => {
      const mods = c.active_modules||[]
      let mrr = 0
      if (c.subscription_status==='active') {
        if (mods.includes('grunnpakke')) mrr += 199*(c.num_users||1)
        MODULE_CATALOG.filter(m=>!m.required&&m.id!=='grunnpakke'&&mods.includes(m.id)).forEach(m=>{mrr+=m.price||0})
      }
      return [c.name||'', c.subscription_status||'', c.email||'', c.phone||'', c.org_number||'', c.num_users||1, mods.join('; '), mrr, c.created_at?new Date(c.created_at).toLocaleDateString('nb-NO'):'', c.trial_ends_at?new Date(c.trial_ends_at).toLocaleDateString('nb-NO'):'', (c.admin_notes||'').replace(/[\n,]/g,' ')]
    })
    const csv = [headers.join(','), ...rows.map(r=>r.map(v=>'"'+v+'"').join(','))].join('\n')
    const blob = new Blob([csv], {type:'text/csv;charset=utf-8;'})
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a'); a.href=url; a.download=`kunder_${new Date().toISOString().split('T')[0]}.csv`; a.click()
    URL.revokeObjectURL(url)
  }

  const load = async () => {
    try {
      const [comp, users, notifs] = await Promise.all([
        supabase.from('company_settings').select('*').order('created_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('user_profiles').select('*').order('created_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('notifications').select('*').eq('type','system').order('created_at',{ascending:false}).limit(50).then(r=>r.data||[]),
      ])
      setCompanies(comp); setAllUsers(users); setNotifications(notifs)

      // Storage check — estimate file storage usage
      try {
        const { data: files } = await supabase.from('project_files').select('file_size')
        let imgFiles = []; try { const r = await supabase.from('image_docs').select('file_size'); imgFiles = r.data||[] } catch(e){}
        const totalFileBytes = (files||[]).reduce((s,f)=>s+(f.file_size||0),0) + (imgFiles||[]).reduce((s,f)=>s+(f.file_size||0),0)
        // Database size — estimate from row counts
        const tables = ['projects','checklists','inspections','endringsmeldinger','resource_plans','invoices','orders','quotes','tenders','employees','timesheets','machines','notifications']
        let totalRows = 0
        for (const t of tables) {
          try {
            const { count } = await supabase.from(t).select('id', { count:'exact', head:true })
            totalRows += count || 0
          } catch(e) {}
        }
        const estDbSizeMB = Math.max(1, totalRows * 0.002) // ~2KB per row estimate
        setStorageInfo({
          fileSizeMB: Math.round(totalFileBytes / 1024 / 1024 * 10) / 10,
          fileSizeGB: Math.round(totalFileBytes / 1024 / 1024 / 1024 * 100) / 100,
          fileCount: (files||[]).length + (imgFiles||[]).length,
          dbRows: totalRows,
          dbSizeMB: Math.round(estDbSizeMB * 10) / 10,
        })
      } catch(e) { console.error('Storage check error:', e) }

      // Load MRR snapshots (table may not exist yet)
      try {
        const { data: snapshots, error: snapErr } = await supabase.from('mrr_snapshots').select('*').order('snapshot_date',{ascending:true}).limit(365)
        if (!snapErr) {
          setMrrSnapshots(snapshots||[])
          // Log today's snapshot
          const today = new Date().toISOString().split('T')[0]
          if (!(snapshots||[]).some(s=>s.snapshot_date===today)) {
            const activeComps = comp.filter(c=>c.subscription_status==='active')
            let todayMRR = 0
            activeComps.forEach(c=>{
              const mods = c.active_modules||[]
              if (mods.includes('grunnpakke')) todayMRR += 199 * (c.num_users||1)
              MODULE_CATALOG.filter(m=>!m.required&&m.id!=='grunnpakke'&&mods.includes(m.id)).forEach(m=>{ todayMRR += m.price||0 })
            })
            try { await supabase.from('mrr_snapshots').insert({ snapshot_date:today, mrr:todayMRR, active_customers:activeComps.length, trial_customers:comp.filter(c=>c.subscription_status==='trial').length, total_users:users.length, churned_customers:comp.filter(c=>c.subscription_status==='cancelled'||c.subscription_status==='expired').length }) } catch(e){}
          }
        }
      } catch(e) { /* table may not exist yet */ }

      // Churn detection
      try {
        const alerts = []
        // 1. Active customers who haven't logged in for 14+ days
        const twoWeeksAgo = new Date(Date.now() - 14*24*60*60*1000)
        users.filter(u=>u.status==='aktiv'&&u.last_seen&&new Date(u.last_seen)<twoWeeksAgo).forEach(u=>{
          const daysAgo = Math.floor((Date.now()-new Date(u.last_seen))/86400000)
          alerts.push({ type:'inactive', severity: daysAgo>30?'high':'medium', title:`${u.full_name||u.email} ikke logget inn`, sub:`${daysAgo} dager siden siste innlogging`, email:u.email })
        })
        // 2. Trial users who registered but never logged in (no last_seen)
        users.filter(u=>!u.last_seen&&u.created_at).forEach(u=>{
          const daysAgo = Math.floor((Date.now()-new Date(u.created_at))/86400000)
          if (daysAgo >= 2) alerts.push({ type:'never_logged', severity:'medium', title:`${u.full_name||u.email} aldri logget inn`, sub:`Registrert for ${daysAgo} dager siden`, email:u.email })
        })
        // 3. Customers with overdue payments
        comp.filter(c=>c.subscription_status==='active'&&c.next_due_date&&new Date(c.next_due_date)<new Date()).forEach(c=>{
          const daysOverdue = Math.floor((Date.now()-new Date(c.next_due_date))/86400000)
          alerts.push({ type:'overdue', severity: daysOverdue>14?'high':'medium', title:`${c.name} — forfalt betaling`, sub:`${daysOverdue} dager over forfall`, companyId:c.id })
        })
        // 4. Recently cancelled
        comp.filter(c=>c.subscription_status==='cancelled').forEach(c=>{
          alerts.push({ type:'cancelled', severity:'high', title:`${c.name} har kansellert`, sub:'Kontakt for å finne årsak', companyId:c.id })
        })
        setChurnAlerts(alerts.sort((a,b)=>a.severity==='high'?-1:b.severity==='high'?1:0))
      } catch(e) { console.error('Churn detection error:', e) }
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(()=>{ load() },[])

  // Calculations
  const trialCompanies = companies.filter(c=>c.subscription_status==='trial')
  const activeCompanies = companies.filter(c=>c.subscription_status==='active')
  const expiredCompanies = companies.filter(c=>c.subscription_status==='expired'||c.subscription_status==='cancelled')
  
  const totalMRR = companies.filter(c=>c.subscription_status==='active').reduce((acc,c)=>{
    const mods = c.active_modules||[]
    let cost = 0
    if (mods.includes('grunnpakke')) cost += 199 * (c.num_users||1)
    MODULE_CATALOG.filter(m=>!m.required&&m.id!=='grunnpakke'&&mods.includes(m.id)).forEach(m=>{
      cost += m.price||0
    })
    return acc + cost
  }, 0)

  const potentialMRR = trialCompanies.reduce((acc,c)=>{
    const mods = c.active_modules||[]
    let cost = 199 * (c.num_users||1)
    MODULE_CATALOG.filter(m=>!m.required&&m.id!=='grunnpakke').forEach(m=>{ cost += m.price||0 })
    return acc + cost
  }, 0)

  // Module popularity
  const modulePop = {}
  companies.filter(c=>c.subscription_status==='active').forEach(c=>{
    (c.active_modules||[]).forEach(m=>{ modulePop[m]=(modulePop[m]||0)+1 })
  })

  const extendTrial = async (companyId, days) => {
    const comp = companies.find(c=>c.id===companyId)
    if (!comp) return
    const newEnd = new Date(comp.trial_ends_at || Date.now())
    newEnd.setDate(newEnd.getDate() + days)
    await supabase.from('company_settings').update({ trial_ends_at: newEnd.toISOString(), subscription_status:'trial' }).eq('id', companyId)
    await addTimelineEvent(companyId, { type:'trial_extend', label: `Trial forlenget med ${days} dager` })
    load()
  }


  const saCard = { background:'white', borderRadius: isMobSA ? '12px' : '16px', border:'1px solid #f1f5f9', padding: isMobSA ? '12px' : '20px 24px', boxShadow:'0 1px 4px rgba(0,0,0,0.04)' }
  const fmt = v => Math.round(v).toLocaleString('nb-NO')

  if (loading) return <div style={{ display:'flex',alignItems:'center',justifyContent:'center',minHeight:'60vh',fontFamily:'system-ui,sans-serif' }}><div style={{ textAlign:'center' }}><div style={{ width:'36px',height:'36px',border:'3px solid #e2e8f0',borderTop:'3px solid #7c3aed',borderRadius:'50%',margin:'0 auto 12px',animation:'spin 1s linear infinite' }}/><p style={{ color:'#94a3b8',fontSize:'14px' }}>Laster kontrollpanel...</p></div></div>

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      {/* Header */}
      <div style={{ background:'linear-gradient(135deg,#1e1b4b,#312e81)', padding: isMobSA ? '12px 14px' : '20px 32px', color:'white' }}>
        <h1 style={{ fontSize: isMobSA ? '17px' : '22px', fontWeight:'800', margin:0, display:'flex', alignItems:'center', gap:'8px' }}>
          <span>👑</span><span>Kontrollpanel</span>
        </h1>
        <p style={{ margin:'2px 0 0', fontSize: isMobSA ? '11px' : '13px', opacity:0.7 }}>Plattformadministrasjon — En Plattform</p>
      </div>

      {/* Tabs */}
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobSA ? '0 8px' : '0 24px', display:'flex', gap:'0', overflowX:'auto', position: isMobSA ? 'sticky' : 'static', top: 0, zIndex: 10, WebkitOverflowScrolling:'touch', scrollbarWidth:'none' }}>
        {[['oversikt','📊','Oversikt'],['grafer','📈','Utvikling'],['churn','⚠️',`Churn${churnAlerts.filter(a=>a.severity==='high').length>0?' ('+churnAlerts.filter(a=>a.severity==='high').length+')':''}`],['kunder','🏢','Kunder'],['brukere','👤','Brukere'],['varsler','🔔','Hendelser']].map(([id,icon,label])=>(
          <button key={id} onClick={()=>setTab(id)} style={{ padding: isMobSA ? '10px 14px' : '12px 18px', border:'none', borderBottom: tab===id ? '3px solid #7c3aed' : '3px solid transparent', background:'transparent', cursor:'pointer', fontSize: isMobSA ? '12px' : '13px', fontWeight: tab===id?'700':'500', color: tab===id?'#7c3aed':'#64748b', whiteSpace:'nowrap', minHeight: isMobSA ? '44px' : 'auto', display:'flex', alignItems:'center', gap:'6px', flexShrink:0 }}>
            <span>{icon}</span><span>{label}</span>
          </button>
        ))}
      </div>

      <div style={{ padding: isMobSA ? '12px' : '24px 32px', display:'flex', flexDirection:'column', gap: isMobSA ? '12px' : '20px' }}>

        {/* OVERSIKT TAB */}
        {tab==='oversikt' && (
          <>
            {/* KPI cards */}
            <div style={{ display:'grid', gridTemplateColumns: isMobSA ? 'repeat(2,1fr)' : 'repeat(4,1fr)', gap:'12px' }}>
              {[
                { label:'MRR', value:`${fmt(totalMRR)} kr`, sub:'Månedlig inntekt', color:'#059669', bg:'#f0fdf4', border:'#bbf7d0' },
                { label:'Aktive kunder', value:activeCompanies.length, sub:`${allUsers.filter(u=>u.status==='aktiv').length} brukere totalt`, color:'#2563eb', bg:'#eff6ff', border:'#bfdbfe' },
                { label:'I prøveperiode', value:trialCompanies.length, sub:`Potensiell MRR: ${fmt(potentialMRR)} kr`, color:'#d97706', bg:'#fffbeb', border:'#fde68a' },
                { label:'Utløpt/Kansellert', value:expiredCompanies.length, sub:'Trenger oppfølging', color:'#dc2626', bg:'#fef2f2', border:'#fecaca' },
              ].map((kpi,i)=>(
                <div key={i} style={{ background:kpi.bg, borderRadius:'14px', border:`1px solid ${kpi.border}`, padding: isMobSA ? '12px' : '18px' }}>
                  <div style={{ fontSize:'11px', fontWeight:'700', color:kpi.color, textTransform:'uppercase', marginBottom:'6px' }}>{kpi.label}</div>
                  <div style={{ fontSize: isMobSA ? '20px' : '26px', fontWeight:'800', color:'#0f172a' }}>{kpi.value}</div>
                  <div style={{ fontSize:'11px', color:'#64748b', marginTop:'4px' }}>{kpi.sub}</div>
                </div>
              ))}
            </div>

            {/* Lagringsstatus */}
            {storageInfo && (
              <div style={saCard}>
                <h3 style={{ margin:'0 0 14px', fontSize:'15px', fontWeight:'700' }}>💾 Lagringsstatus (Supabase)</h3>
                <div style={{ display:'grid', gridTemplateColumns: isMobSA ? '1fr' : '1fr 1fr', gap:'14px' }}>
                  {/* Fillagring */}
                  <div>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'8px' }}>
                      <span style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>📁 Fillagring</span>
                      <span style={{ fontSize:'13px', fontWeight:'700', color: storageInfo.fileSizeGB > 0.8 ? '#dc2626' : storageInfo.fileSizeGB > 0.5 ? '#d97706' : '#059669' }}>
                        {storageInfo.fileSizeMB > 1000 ? `${storageInfo.fileSizeGB} GB` : `${storageInfo.fileSizeMB} MB`}
                      </span>
                    </div>
                    <div style={{ height:'10px', background:'#f1f5f9', borderRadius:'5px', overflow:'hidden', marginBottom:'6px' }}>
                      <div style={{ height:'100%', borderRadius:'5px', transition:'width 0.5s',
                        width: `${Math.min(100, storageInfo.fileSizeGB / 1 * 100)}%`,
                        background: storageInfo.fileSizeGB > 0.8 ? '#dc2626' : storageInfo.fileSizeGB > 0.5 ? '#d97706' : '#059669'
                      }}/>
                    </div>
                    <div style={{ display:'flex', justifyContent:'space-between', fontSize:'11px', color:'#94a3b8' }}>
                      <span>{storageInfo.fileCount} filer</span>
                      <span>1 GB inkludert (Free)</span>
                    </div>
                  </div>
                  {/* Database */}
                  <div>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'8px' }}>
                      <span style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>🗃️ Database</span>
                      <span style={{ fontSize:'13px', fontWeight:'700', color: storageInfo.dbSizeMB > 400 ? '#dc2626' : storageInfo.dbSizeMB > 250 ? '#d97706' : '#059669' }}>
                        ~{storageInfo.dbSizeMB} MB
                      </span>
                    </div>
                    <div style={{ height:'10px', background:'#f1f5f9', borderRadius:'5px', overflow:'hidden', marginBottom:'6px' }}>
                      <div style={{ height:'100%', borderRadius:'5px', transition:'width 0.5s',
                        width: `${Math.min(100, storageInfo.dbSizeMB / 500 * 100)}%`,
                        background: storageInfo.dbSizeMB > 400 ? '#dc2626' : storageInfo.dbSizeMB > 250 ? '#d97706' : '#059669'
                      }}/>
                    </div>
                    <div style={{ display:'flex', justifyContent:'space-between', fontSize:'11px', color:'#94a3b8' }}>
                      <span>~{storageInfo.dbRows.toLocaleString('nb-NO')} rader</span>
                      <span>500 MB inkludert (Free)</span>
                    </div>
                  </div>
                </div>
                {(storageInfo.fileSizeGB > 0.7 || storageInfo.dbSizeMB > 350) && (
                  <div style={{ marginTop:'12px', padding:'10px 14px', background:'#fffbeb', borderRadius:'10px', border:'1px solid #fde68a', display:'flex', alignItems:'center', gap:'8px' }}>
                    <span style={{ fontSize:'16px' }}>⚠️</span>
                    <div style={{ fontSize:'12px', color:'#92400e' }}>
                      <strong>Nærmer seg grensen!</strong> Vurder å oppgradere til Supabase Pro (25 USD/mnd) for 8 GB database + 100 GB fillagring.
                    </div>
                  </div>
                )}
                {storageInfo.fileSizeGB <= 0.7 && storageInfo.dbSizeMB <= 350 && (
                  <div style={{ marginTop:'12px', padding:'10px 14px', background:'#f0fdf4', borderRadius:'10px', border:'1px solid #bbf7d0', display:'flex', alignItems:'center', gap:'8px' }}>
                    <span style={{ fontSize:'16px' }}>✅</span>
                    <span style={{ fontSize:'12px', color:'#059669', fontWeight:'600' }}>Lagring OK — god kapasitet tilgjengelig</span>
                  </div>
                )}
              </div>
            )}

            {/* Populære moduler */}
            <div style={saCard}>
              <h3 style={{ margin:'0 0 14px', fontSize:'15px', fontWeight:'700' }}>📦 Modulpopularitet (aktive kunder)</h3>
              <div style={{ display:'flex', flexDirection:'column', gap: isMobSA ? '10px' : '8px' }}>
                {Object.entries(modulePop).sort((a,b)=>b[1]-a[1]).map(([modId,count])=>{
                  const mod = MODULE_CATALOG.find(m=>m.id===modId)
                  const pct = activeCompanies.length > 0 ? Math.round(count/activeCompanies.length*100) : 0
                  return (
                    <div key={modId} style={{ display:'flex', alignItems:'center', gap: isMobSA ? '8px' : '10px', flexWrap: isMobSA ? 'wrap' : 'nowrap' }}>
                      <span style={{ fontSize:'16px', width:'24px', textAlign:'center', flexShrink:0 }}>{mod?.emoji||'📦'}</span>
                      <span style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a', width: isMobSA ? 'auto' : '140px', flex: isMobSA ? '1 1 auto' : '0 0 140px', minWidth:0, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{mod?.name||modId}</span>
                      <div style={{ flex:1, height:'8px', background:'#f1f5f9', borderRadius:'4px', overflow:'hidden', order: isMobSA ? 3 : 0, width: isMobSA ? '100%' : 'auto', minWidth: isMobSA ? '100%' : 0 }}>
                        <div style={{ height:'100%', borderRadius:'4px', background:'#7c3aed', width:`${pct}%`, transition:'width 0.3s' }}/>
                      </div>
                      <span style={{ fontSize:'12px', fontWeight:'700', color:'#7c3aed', width: isMobSA ? 'auto' : '50px', textAlign:'right', flexShrink:0 }}>{count} ({pct}%)</span>
                    </div>
                  )
                })}
              </div>
            </div>

            {/* Inntekt per modul */}
            <div style={saCard}>
              <h3 style={{ margin:'0 0 14px', fontSize:'15px', fontWeight:'700' }}>💰 Inntekt per modul</h3>
              <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
                {(() => {
                  const modRevenue = {}
                  companies.filter(c=>c.subscription_status==='active').forEach(c=>{
                    const mods = c.active_modules||[]
                    if (mods.includes('grunnpakke')) {
                      modRevenue['grunnpakke'] = (modRevenue['grunnpakke']||0) + 199 * (c.num_users||1)
                    }
                    MODULE_CATALOG.filter(m=>!m.required&&m.id!=='grunnpakke'&&mods.includes(m.id)).forEach(m=>{
                      modRevenue[m.id] = (modRevenue[m.id]||0) + (m.price||0)
                    })
                  })
                  return Object.entries(modRevenue).sort((a,b)=>b[1]-a[1]).map(([modId,rev])=>{
                    const mod = MODULE_CATALOG.find(m=>m.id===modId)
                    return (
                      <div key={modId} style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'8px 12px', background:'#f8fafc', borderRadius:'8px' }}>
                        <div style={{ display:'flex', alignItems:'center', gap:'8px' }}>
                          <span style={{ fontSize:'14px' }}>{mod?.emoji||'📦'}</span>
                          <span style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>{mod?.name||modId}</span>
                          {mod?.perCompany && <span style={{ fontSize:'9px', color:'#94a3b8', background:'#f1f5f9', padding:'1px 6px', borderRadius:'4px' }}>per bedrift</span>}
                        </div>
                        <span style={{ fontSize:'14px', fontWeight:'800', color:'#059669' }}>{fmt(rev)} kr/mnd</span>
                      </div>
                    )
                  })
                })()}
                <div style={{ display:'flex', justifyContent:'space-between', padding:'10px 12px', borderTop:'2px solid #e2e8f0', marginTop:'4px', fontWeight:'800' }}>
                  <span style={{ color:'#0f172a' }}>Total MRR</span>
                  <span style={{ color:'#059669', fontSize:'16px' }}>{fmt(totalMRR)} kr/mnd</span>
                </div>
              </div>
            </div>

            {/* Konvertering + Nøkkeltall */}
            <div style={{ display:'grid', gridTemplateColumns: isMobSA ? '1fr' : '1fr 1fr', gap:'12px' }}>
              <div style={saCard}>
                <h3 style={{ margin:'0 0 14px', fontSize:'15px', fontWeight:'700' }}>📈 Konvertering</h3>
                {(() => {
                  const totalSignups = companies.length
                  const converted = activeCompanies.length
                  const convRate = totalSignups > 0 ? Math.round(converted/totalSignups*100) : 0
                  const avgUsersPerCompany = activeCompanies.length > 0 ? (activeCompanies.reduce((s,c)=>s+(c.num_users||1),0)/activeCompanies.length).toFixed(1) : '0'
                  const avgRevenuePerCustomer = activeCompanies.length > 0 ? Math.round(totalMRR/activeCompanies.length) : 0
                  const totalUsers = allUsers.length
                  return (
                    <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                      {[
                        ['Konverteringsrate', `${convRate}%`, `${converted} av ${totalSignups} registrerte`],
                        ['Snitt brukere/kunde', avgUsersPerCompany, 'aktive kunder'],
                        ['Snitt MRR/kunde', `${fmt(avgRevenuePerCustomer)} kr`, 'per aktiv kunde'],
                        ['ARR (årlig)', `${fmt(totalMRR*12)} kr`, 'basert på nåværende MRR'],
                        ['Totalt brukere', totalUsers, `${allUsers.filter(u=>u.status==='aktiv').length} aktive`],
                      ].map(([label,value,sub],i)=>(
                        <div key={i} style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'6px 0', borderBottom:'1px solid #f8fafc' }}>
                          <div>
                            <div style={{ fontSize:'12px', color:'#64748b' }}>{label}</div>
                            {sub && <div style={{ fontSize:'10px', color:'#94a3b8' }}>{sub}</div>}
                          </div>
                          <span style={{ fontSize:'15px', fontWeight:'800', color:'#0f172a' }}>{value}</span>
                        </div>
                      ))}
                    </div>
                  )
                })()}
              </div>

              <div style={saCard}>
                <h3 style={{ margin:'0 0 14px', fontSize:'15px', fontWeight:'700' }}>⚠️ Trenger oppfølging</h3>
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {/* Trials som utløper snart */}
                  {trialCompanies.filter(c=>{
                    const daysLeft = c.trial_ends_at ? Math.ceil((new Date(c.trial_ends_at)-new Date())/86400000) : null
                    return daysLeft !== null && daysLeft <= 5
                  }).map(c=>{
                    const daysLeft = Math.ceil((new Date(c.trial_ends_at)-new Date())/86400000)
                    return (
                      <div key={c.id} style={{ display:'flex', alignItems:'center', gap:'8px', padding:'8px 10px', background: daysLeft <= 1 ? '#fef2f2' : '#fffbeb', borderRadius:'8px', border:`1px solid ${daysLeft<=1?'#fecaca':'#fde68a'}` }}>
                        <span style={{ fontSize:'14px' }}>{daysLeft <= 1 ? '🔴' : '🟡'}</span>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ fontSize:'12px', fontWeight:'600', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{c.name}</div>
                          <div style={{ fontSize:'10px', color: daysLeft<=1?'#dc2626':'#d97706' }}>{daysLeft <= 0 ? 'Utløpt i dag!' : `${daysLeft} dager igjen`}</div>
                        </div>
                        <button onClick={()=>{setTab('kunder');setSelectedCompany(c)}} style={{ background:'white', border:'1px solid #e2e8f0', borderRadius:'6px', padding:'3px 8px', fontSize:'10px', cursor:'pointer', color:'#64748b', fontWeight:'600' }}>Vis</button>
                      </div>
                    )
                  })}
                  {/* Utløpte som ikke har kjøpt */}
                  {expiredCompanies.slice(0,3).map(c=>(
                    <div key={c.id} style={{ display:'flex', alignItems:'center', gap:'8px', padding:'8px 10px', background:'#f8fafc', borderRadius:'8px', border:'1px solid #f1f5f9' }}>
                      <span style={{ fontSize:'14px' }}>💤</span>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:'12px', fontWeight:'600', color:'#0f172a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{c.name}</div>
                        <div style={{ fontSize:'10px', color:'#94a3b8' }}>Utløpt — ingen kjøp</div>
                      </div>
                      <button onClick={()=>{setTab('kunder');setSelectedCompany(c)}} style={{ background:'white', border:'1px solid #e2e8f0', borderRadius:'6px', padding:'3px 8px', fontSize:'10px', cursor:'pointer', color:'#64748b', fontWeight:'600' }}>Vis</button>
                    </div>
                  ))}
                  {trialCompanies.filter(c=>{ const d=c.trial_ends_at?Math.ceil((new Date(c.trial_ends_at)-new Date())/86400000):null; return d!==null&&d<=5 }).length===0 && expiredCompanies.length===0 && (
                    <p style={{ color:'#94a3b8', fontSize:'13px', textAlign:'center', padding:'12px' }}>Ingen oppfølgingspunkter nå</p>
                  )}
                </div>
              </div>
            </div>

            {/* Siste registreringer */}
            <div style={saCard}>
              <h3 style={{ margin:'0 0 14px', fontSize:'15px', fontWeight:'700' }}>🆕 Siste registreringer</h3>
              {companies.length === 0 ? <p style={{ color:'#94a3b8', fontSize:'13px', textAlign:'center', padding:'20px' }}>Ingen registreringer ennå</p> :
              companies.slice(0,8).map(c=>{
                const daysAgo = Math.floor((Date.now()-new Date(c.created_at||Date.now()))/86400000)
                const trialEnd = c.trial_ends_at ? new Date(c.trial_ends_at) : null
                const daysLeft = trialEnd ? Math.ceil((trialEnd-new Date())/86400000) : null
                const mods = c.active_modules||[]
                let mrr = 0
                if (c.subscription_status==='active') {
                  if (mods.includes('grunnpakke')) mrr += 199 * (c.num_users||1)
                  MODULE_CATALOG.filter(m=>!m.required&&m.id!=='grunnpakke'&&mods.includes(m.id)).forEach(m=>{ mrr += m.price||0 })
                }
                return (
                  <div key={c.id} style={{ display:'flex', alignItems:'center', gap:'12px', padding:'10px 0', borderBottom:'1px solid #f8fafc', cursor:'pointer' }}
                    onClick={()=>{setTab('kunder');setSelectedCompany(c)}}>
                    <div style={{ width:'36px', height:'36px', borderRadius:'50%', background:'linear-gradient(135deg,#e0e7ff,#c7d2fe)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'14px', fontWeight:'700', color:'#4338ca' }}>{(c.name?.[0]||'?').toUpperCase()}</div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontWeight:'600', fontSize:'13px', color:'#0f172a' }}>{c.name||'Uten navn'}</div>
                      <div style={{ fontSize:'11px', color:'#94a3b8' }}>{daysAgo===0?'I dag':daysAgo===1?'I går':`${daysAgo}d siden`} · {c.num_users||1} bruker{(c.num_users||1)>1?'e':''} · {mods.length} moduler</div>
                    </div>
                    {c.subscription_status==='active' && <span style={{ fontSize:'12px', fontWeight:'700', color:'#059669' }}>{fmt(mrr)} kr</span>}
                    <span style={{ padding:'3px 10px', borderRadius:'999px', fontSize:'11px', fontWeight:'700',
                      background: c.subscription_status==='active'?'#f0fdf4':c.subscription_status==='trial'?'#fffbeb':'#fef2f2',
                      color: c.subscription_status==='active'?'#059669':c.subscription_status==='trial'?'#d97706':'#dc2626',
                      border: `1px solid ${c.subscription_status==='active'?'#bbf7d0':c.subscription_status==='trial'?'#fde68a':'#fecaca'}`
                    }}>{c.subscription_status==='active'?'Aktiv':c.subscription_status==='trial'?(daysLeft!==null?`${daysLeft}d igjen`:'Prøve'):'Utløpt'}</span>
                  </div>
                )
              })}
            </div>
          </>
        )}

        {/* GRAFER TAB */}
        {tab==='grafer' && (
          <>
            {mrrSnapshots.length < 2 ? (
              <div style={saCard}>
                <div style={{ textAlign:'center', padding:'40px 20px' }}>
                  <div style={{ fontSize:'48px', marginBottom:'12px' }}>📈</div>
                  <h3 style={{ margin:'0 0 8px', fontSize:'16px', fontWeight:'700', color:'#0f172a' }}>Data samles inn</h3>
                  <p style={{ margin:0, fontSize:'13px', color:'#94a3b8', lineHeight:1.6 }}>MRR-grafen vil vise data etter noen dager med aktivitet. Systemet tar et øyeblikksbilde av inntekt og kundetall hver dag automatisk.</p>
                </div>
              </div>
            ) : (
              <>
                {/* MRR graf */}
                <div style={saCard}>
                  <h3 style={{ margin:'0 0 16px', fontSize:'15px', fontWeight:'700' }}>💰 MRR-utvikling</h3>
                  <div style={{ position:'relative', height: isMobSA ? '160px' : '200px', background:'#f8fafc', borderRadius:'12px', padding:'12px', overflow:'hidden' }}>
                    {(()=>{
                      const data = mrrSnapshots.slice(-90)
                      const maxMRR = Math.max(...data.map(d=>d.mrr||0), 1)
                      const w = 100 / Math.max(data.length-1, 1)
                      const points = data.map((d,i)=>({ x: i*w, y: 100-((d.mrr||0)/maxMRR*85), mrr: d.mrr, date: d.snapshot_date }))
                      const pathD = points.map((p,i)=>`${i===0?'M':'L'} ${p.x}% ${p.y}%`).join(' ')
                      const areaD = pathD + ` L ${points[points.length-1]?.x||0}% 100% L 0% 100% Z`
                      return (
                        <svg viewBox="0 0 100 100" preserveAspectRatio="none" style={{ width:'100%', height:'100%' }}>
                          <defs><linearGradient id="mrrGrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#059669" stopOpacity="0.3"/><stop offset="100%" stopColor="#059669" stopOpacity="0.02"/></linearGradient></defs>
                          <path d={areaD} fill="url(#mrrGrad)"/>
                          <path d={pathD} fill="none" stroke="#059669" strokeWidth="0.5" strokeLinecap="round" strokeLinejoin="round"/>
                          {points.filter((_,i)=>i===0||i===points.length-1).map((p,i)=>(
                            <circle key={i} cx={`${p.x}%`} cy={`${p.y}%`} r="1" fill="#059669"/>
                          ))}
                        </svg>
                      )
                    })()}
                  </div>
                  <div style={{ display:'flex', justifyContent:'space-between', marginTop:'8px', fontSize: isMobSA ? '10px' : '11px', color:'#94a3b8', flexWrap: isMobSA ? 'wrap' : 'nowrap', gap:'4px' }}>
                    <span>{mrrSnapshots[0]?.snapshot_date ? new Date(mrrSnapshots[0].snapshot_date).toLocaleDateString('nb-NO') : ''}</span>
                    <span style={{ fontWeight:'700', color:'#059669', order: isMobSA ? -1 : 0, width: isMobSA ? '100%' : 'auto', textAlign:'center' }}>Nå: {fmt(mrrSnapshots[mrrSnapshots.length-1]?.mrr||0)} kr/mnd</span>
                    <span>{mrrSnapshots[mrrSnapshots.length-1]?.snapshot_date ? new Date(mrrSnapshots[mrrSnapshots.length-1].snapshot_date).toLocaleDateString('nb-NO') : ''}</span>
                  </div>
                </div>

                {/* Kundevekst graf */}
                <div style={saCard}>
                  <h3 style={{ margin:'0 0 16px', fontSize:'15px', fontWeight:'700' }}>👥 Kundevekst</h3>
                  <div style={{ position:'relative', height: isMobSA ? '140px' : '160px', background:'#f8fafc', borderRadius:'12px', padding:'12px', overflow:'hidden' }}>
                    {(()=>{
                      const data = mrrSnapshots.slice(-90)
                      const maxC = Math.max(...data.map(d=>(d.active_customers||0)+(d.trial_customers||0)), 1)
                      const w = 100 / Math.max(data.length-1, 1)
                      return (
                        <svg viewBox="0 0 100 100" preserveAspectRatio="none" style={{ width:'100%', height:'100%' }}>
                          {/* Active line */}
                          <path d={data.map((d,i)=>`${i===0?'M':'L'} ${i*w}% ${100-((d.active_customers||0)/maxC*80)}%`).join(' ')} fill="none" stroke="#2563eb" strokeWidth="0.5"/>
                          {/* Trial line */}
                          <path d={data.map((d,i)=>`${i===0?'M':'L'} ${i*w}% ${100-((d.trial_customers||0)/maxC*80)}%`).join(' ')} fill="none" stroke="#d97706" strokeWidth="0.5" strokeDasharray="1,1"/>
                          {/* Churned line */}
                          <path d={data.map((d,i)=>`${i===0?'M':'L'} ${i*w}% ${100-((d.churned_customers||0)/maxC*80)}%`).join(' ')} fill="none" stroke="#dc2626" strokeWidth="0.4" strokeDasharray="0.5,1"/>
                        </svg>
                      )
                    })()}
                  </div>
                  <div style={{ display:'flex', gap:'16px', marginTop:'8px', justifyContent:'center' }}>
                    {[['Aktive','#2563eb','—'],['Trial','#d97706','- -'],['Churned','#dc2626','···']].map(([l,c,dash])=>(
                      <div key={l} style={{ display:'flex', alignItems:'center', gap:'6px', fontSize:'11px', color:'#64748b' }}>
                        <div style={{ width:'16px', height:'2px', background:c, borderRadius:'1px' }}/>{l}
                      </div>
                    ))}
                  </div>
                </div>

                {/* Datatabell */}
                <div style={saCard}>
                  <h3 style={{ margin:'0 0 12px', fontSize:'15px', fontWeight:'700' }}>📋 Historikk (siste 30 dager)</h3>
                  {isMobSA ? (
                    <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
                      {mrrSnapshots.slice(-30).reverse().map((s,i)=>(
                        <div key={i} style={{ background:'#f8fafc', borderRadius:'8px', padding:'10px 12px' }}>
                          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'4px' }}>
                            <span style={{ fontSize:'12px', fontWeight:'600', color:'#0f172a' }}>{new Date(s.snapshot_date).toLocaleDateString('nb-NO')}</span>
                            <span style={{ fontSize:'13px', fontWeight:'700', color:'#059669' }}>{fmt(s.mrr||0)} kr</span>
                          </div>
                          <div style={{ display:'flex', gap:'10px', fontSize:'10px', flexWrap:'wrap' }}>
                            <span style={{ color:'#2563eb' }}>Aktive: <strong>{s.active_customers||0}</strong></span>
                            <span style={{ color:'#d97706' }}>Trial: <strong>{s.trial_customers||0}</strong></span>
                            <span style={{ color:'#dc2626' }}>Churned: <strong>{s.churned_customers||0}</strong></span>
                            <span style={{ color:'#64748b' }}>Brukere: <strong>{s.total_users||0}</strong></span>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div style={{ overflowX:'auto' }}>
                      <table style={{ width:'100%', borderCollapse:'collapse', fontSize:'12px' }}>
                        <thead>
                          <tr style={{ borderBottom:'2px solid #e2e8f0' }}>
                            {['Dato','MRR','Aktive','Trial','Churned','Brukere'].map(h=>(
                              <th key={h} style={{ padding:'8px 10px', textAlign:'left', fontWeight:'700', color:'#64748b', fontSize:'11px' }}>{h}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {mrrSnapshots.slice(-30).reverse().map((s,i)=>(
                            <tr key={i} style={{ borderBottom:'1px solid #f8fafc' }}>
                              <td style={{ padding:'6px 10px', color:'#0f172a', fontWeight:'500' }}>{new Date(s.snapshot_date).toLocaleDateString('nb-NO')}</td>
                              <td style={{ padding:'6px 10px', color:'#059669', fontWeight:'700' }}>{fmt(s.mrr||0)} kr</td>
                              <td style={{ padding:'6px 10px', color:'#2563eb' }}>{s.active_customers||0}</td>
                              <td style={{ padding:'6px 10px', color:'#d97706' }}>{s.trial_customers||0}</td>
                              <td style={{ padding:'6px 10px', color:'#dc2626' }}>{s.churned_customers||0}</td>
                              <td style={{ padding:'6px 10px', color:'#64748b' }}>{s.total_users||0}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
              </>
            )}
          </>
        )}

        {/* CHURN TAB */}
        {tab==='churn' && (
          <>
            {/* Churn KPIs */}
            <div style={{ display:'grid', gridTemplateColumns: isMobSA ? '1fr 1fr' : 'repeat(3,1fr)', gap:'12px' }}>
              {(()=>{
                const highAlerts = churnAlerts.filter(a=>a.severity==='high').length
                const medAlerts = churnAlerts.filter(a=>a.severity==='medium').length
                const cancelledCount = companies.filter(c=>c.subscription_status==='cancelled').length
                return [
                  { label:'Kritiske varsler', value:highAlerts, icon:'🔴', bg:'#fef2f2', border:'#fecaca', color:'#dc2626' },
                  { label:'Moderate varsler', value:medAlerts, icon:'🟡', bg:'#fffbeb', border:'#fde68a', color:'#d97706' },
                  { label:'Kansellerte kunder', value:cancelledCount, icon:'💔', bg:'#f8fafc', border:'#e2e8f0', color:'#64748b' },
                ].map((k,i)=>(
                  <div key={i} style={{ background:k.bg, borderRadius:'14px', border:`1px solid ${k.border}`, padding:'16px' }}>
                    <div style={{ fontSize:'11px', fontWeight:'700', color:k.color, marginBottom:'4px' }}>{k.icon} {k.label}</div>
                    <div style={{ fontSize:'28px', fontWeight:'800', color:'#0f172a' }}>{k.value}</div>
                  </div>
                ))
              })()}
            </div>

            {/* Alerts list */}
            <div style={saCard}>
              <h3 style={{ margin:'0 0 14px', fontSize:'15px', fontWeight:'700' }}>🚨 Churn-varsler</h3>
              {churnAlerts.length === 0 ? (
                <div style={{ textAlign:'center', padding:'40px', color:'#94a3b8' }}>
                  <div style={{ fontSize:'36px', marginBottom:'8px' }}>✅</div>
                  <p style={{ fontSize:'14px', margin:0 }}>Ingen churn-varsler — alle kunder ser bra ut!</p>
                </div>
              ) : (
                <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
                  {churnAlerts.map((alert,i)=>(
                    <div key={i} style={{ display:'flex', alignItems: isMobSA ? 'flex-start' : 'center', gap: isMobSA ? '10px' : '12px', padding: isMobSA ? '10px 12px' : '12px 14px', borderRadius:'10px', flexWrap: isMobSA ? 'wrap' : 'nowrap',
                      background: alert.severity==='high'?'#fef2f2':'#fffbeb',
                      border: `1px solid ${alert.severity==='high'?'#fecaca':'#fde68a'}` }}>
                      <span style={{ fontSize:'20px', flexShrink:0 }}>
                        {alert.type==='inactive'?'😴':alert.type==='never_logged'?'👻':alert.type==='overdue'?'💳':alert.type==='cancelled'?'💔':'⚠️'}
                      </span>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:'13px', fontWeight:'700', color:'#0f172a', wordBreak:'break-word' }}>{alert.title}</div>
                        <div style={{ fontSize:'11px', color: alert.severity==='high'?'#dc2626':'#d97706', marginTop:'2px' }}>{alert.sub}</div>
                      </div>
                      <div style={{ display:'flex', gap:'6px', flexShrink:0, width: isMobSA ? '100%' : 'auto', marginLeft: isMobSA ? '30px' : '0' }}>
                        {alert.email && (
                          <button onClick={()=>setEmailModal({
                            to: alert.email,
                            companyName: '',
                            subject: alert.type==='inactive' ? 'Vi savner deg på En Plattform' : alert.type==='never_logged' ? 'Trenger du hjelp med å komme i gang?' : 'Oppdatering fra En Plattform',
                            body: alert.type==='inactive'
                              ? `Hei!\n\nVi la merke til at du ikke har logget inn på En Plattform på en stund. Er det noe vi kan hjelpe med?\n\nVi er her for å sikre at du får mest mulig ut av systemet.\n\nMvh\nEn Plattform`
                              : alert.type==='never_logged'
                              ? `Hei!\n\nVi ser at du nylig registrerte deg på En Plattform, men ikke har logget inn ennå. Trenger du hjelp med å komme i gang?\n\nVi tilbyr gjerne en kort gjennomgang av systemet.\n\nMvh\nEn Plattform`
                              : `Hei!\n\n\n\nMvh\nEn Plattform`
                          })} style={{ padding: isMobSA ? '8px 12px' : '6px 12px', background:'white', border:'1px solid #e2e8f0', borderRadius:'6px', cursor:'pointer', fontSize:'11px', fontWeight:'600', color:'#7c3aed', flex: isMobSA ? 1 : 'none', minHeight: isMobSA ? '36px' : 'auto' }}>✉️ Kontakt</button>
                        )}
                        {alert.companyId && (
                          <button onClick={()=>{setTab('kunder');setSelectedCompany(companies.find(c=>c.id===alert.companyId))}}
                            style={{ padding: isMobSA ? '8px 12px' : '6px 12px', background:'white', border:'1px solid #e2e8f0', borderRadius:'6px', cursor:'pointer', fontSize:'11px', fontWeight:'600', color:'#475569', flex: isMobSA ? 1 : 'none', minHeight: isMobSA ? '36px' : 'auto' }}>Vis</button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Churn-rate over tid */}
            {mrrSnapshots.length >= 7 && (
              <div style={saCard}>
                <h3 style={{ margin:'0 0 12px', fontSize:'15px', fontWeight:'700' }}>📉 Churn-rate utvikling</h3>
                <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
                  {(()=>{
                    const weeks = []
                    const snaps = mrrSnapshots.slice(-28)
                    for (let i=0; i<snaps.length; i+=7) {
                      const week = snaps.slice(i, i+7)
                      if (week.length===0) continue
                      const last = week[week.length-1]
                      const first = week[0]
                      const churnRate = first.active_customers > 0 ? Math.round((first.active_customers - (last.active_customers||0)) / first.active_customers * 100) : 0
                      weeks.push({ date: last.snapshot_date, rate: Math.max(0, churnRate), active: last.active_customers })
                    }
                    return weeks.reverse().map((w,i)=>(
                      <div key={i} style={{ display:'flex', alignItems:'center', gap: isMobSA ? '8px' : '12px', padding: isMobSA ? '8px 10px' : '8px 12px', background:'#f8fafc', borderRadius:'8px', flexWrap: isMobSA ? 'wrap' : 'nowrap' }}>
                        <span style={{ fontSize: isMobSA ? '11px' : '12px', color:'#64748b', width: isMobSA ? 'auto' : '80px', fontWeight: isMobSA ? '600' : '400' }}>Uke {new Date(w.date).toLocaleDateString('nb-NO',{day:'2-digit',month:'short'})}</span>
                        <div style={{ flex:1, height:'6px', background:'#f1f5f9', borderRadius:'3px', overflow:'hidden', order: isMobSA ? 3 : 0, width: isMobSA ? '100%' : 'auto', minWidth: isMobSA ? '100%' : 0 }}>
                          <div style={{ height:'100%', borderRadius:'3px', background: w.rate>5?'#dc2626':w.rate>0?'#d97706':'#059669', width:`${Math.min(100,w.rate*10)}%` }}/>
                        </div>
                        <span style={{ fontSize:'12px', fontWeight:'700', color: w.rate>5?'#dc2626':w.rate>0?'#d97706':'#059669', width: isMobSA ? 'auto' : '40px', textAlign:'right', marginLeft: isMobSA ? 'auto' : 0 }}>{w.rate}%</span>
                        <span style={{ fontSize:'11px', color:'#94a3b8', width: isMobSA ? 'auto' : '50px', textAlign:'right' }}>{w.active} aktive</span>
                      </div>
                    ))
                  })()}
                </div>
              </div>
            )}
          </>
        )}

        {/* KUNDER TAB */}
        {tab==='kunder' && (
          <>
            {/* Search + filter + export */}
            <div style={{ display:'flex', gap:'8px', flexWrap:'wrap', alignItems:'center' }}>
              <input value={saSearch} onChange={e=>setSaSearch(e.target.value)} placeholder="🔍 Søk bedrift, e-post, org.nr..." style={{ flex: isMobSA ? '1 1 100%' : '1 1 200px', padding: isMobSA ? '11px 14px' : '9px 14px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize: isMobSA ? '14px' : '13px', outline:'none', background:'white', minHeight: isMobSA ? '44px' : 'auto' }} />
              <select value={saFilter} onChange={e=>setSaFilter(e.target.value)} style={{ padding: isMobSA ? '11px 14px' : '9px 14px', border:`2px solid ${saFilter!=='alle'?'#7c3aed':'#e2e8f0'}`, borderRadius:'10px', fontSize: isMobSA ? '14px' : '13px', outline:'none', background:'white', color:saFilter!=='alle'?'#7c3aed':'#475569', fontWeight:saFilter!=='alle'?'700':'400', cursor:'pointer', flex: isMobSA ? '1 1 auto' : 'none', minHeight: isMobSA ? '44px' : 'auto' }}>
                <option value="alle">Alle ({companies.length})</option>
                <option value="trial">Prøveperiode ({trialCompanies.length})</option>
                <option value="active">Aktive ({activeCompanies.length})</option>
                <option value="expired">Utløpt ({expiredCompanies.length})</option>
              </select>
              <button onClick={exportCSV} style={{ padding: isMobSA ? '11px 14px' : '9px 14px', background:'#f8fafc', border:'1px solid #e2e8f0', borderRadius:'10px', cursor:'pointer', fontSize:'12px', fontWeight:'600', color:'#475569', display:'flex', alignItems:'center', gap:'6px', minHeight: isMobSA ? '44px' : 'auto', whiteSpace:'nowrap' }}>📥 {isMobSA ? 'CSV' : 'Eksporter CSV'}</button>
              <span style={{ fontSize:'12px', color:'#94a3b8', marginLeft: isMobSA ? '0' : 'auto', width: isMobSA ? '100%' : 'auto', textAlign: isMobSA ? 'center' : 'right' }}>
                {companies.filter(c=>{
                  if (saFilter!=='alle'&&c.subscription_status!==saFilter) return false
                  if (saSearch&&![c.name,c.email,c.org_number,c.phone].some(v=>v?.toLowerCase().includes(saSearch.toLowerCase()))) return false
                  return true
                }).length} treff
              </span>
            </div>

            <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
              {companies.filter(c=>{
                if (saFilter!=='alle'&&c.subscription_status!==saFilter) return false
                if (saSearch&&![c.name,c.email,c.org_number,c.phone].some(v=>v?.toLowerCase().includes(saSearch.toLowerCase()))) return false
                return true
              }).map(c=>{
                const users = allUsers.filter(u=>u.email) // TODO: filter by company when multi-tenant
                const mods = c.active_modules||[]
                const trialEnd = c.trial_ends_at ? new Date(c.trial_ends_at) : null
                const daysLeft = trialEnd ? Math.ceil((trialEnd-new Date())/86400000) : null
                let mrr = 0
                if (mods.includes('grunnpakke')) mrr += 199 * (c.num_users||1)
                MODULE_CATALOG.filter(m=>!m.required&&m.id!=='grunnpakke'&&mods.includes(m.id)).forEach(m=>{ mrr += m.price||0 })
                return (
                  <div key={c.id} style={{ ...saCard, cursor:'pointer' }}
                    onClick={()=>setSelectedCompany(selectedCompany?.id===c.id?null:c)}>
                    <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap: isMobSA ? '8px' : '12px', flexWrap:'wrap' }}>
                      <div style={{ display:'flex', alignItems:'center', gap:'10px', flex:1, minWidth:0 }}>
                        <div style={{ width: isMobSA ? '36px' : '40px', height: isMobSA ? '36px' : '40px', borderRadius:'12px', background:'linear-gradient(135deg,#e0e7ff,#c7d2fe)', display:'flex', alignItems:'center', justifyContent:'center', fontSize: isMobSA ? '14px' : '16px', fontWeight:'700', color:'#4338ca', flexShrink:0 }}>{(c.name?.[0]||'?').toUpperCase()}</div>
                        <div style={{ minWidth:0, flex:1 }}>
                          <div style={{ fontWeight:'700', fontSize: isMobSA ? '13px' : '14px', color:'#0f172a', wordBreak:'break-word' }}>{c.name||'Uten navn'}</div>
                          <div style={{ fontSize:'11px', color:'#94a3b8', wordBreak:'break-word' }}>
                            {isMobSA ? (
                              <>{c.email || c.phone || '—'}<br/>{c.num_users||1} brukere · {mods.length} moduler</>
                            ) : (
                              <>{c.email||''}{c.phone?' · '+c.phone:''} · {c.num_users||1} brukere · {mods.length} moduler</>
                            )}
                          </div>
                        </div>
                      </div>
                      <div style={{ display:'flex', alignItems:'center', gap:'8px', flexWrap:'wrap', width: isMobSA ? '100%' : 'auto', justifyContent: isMobSA ? 'space-between' : 'flex-end' }}>
                        {c.subscription_status==='active' && <span style={{ fontWeight:'800', fontSize:'14px', color:'#059669' }}>{fmt(mrr)} kr/mnd</span>}
                        <span style={{ padding:'3px 10px', borderRadius:'999px', fontSize:'11px', fontWeight:'700',
                          background: c.subscription_status==='active'?'#f0fdf4':c.subscription_status==='trial'?'#fffbeb':'#fef2f2',
                          color: c.subscription_status==='active'?'#059669':c.subscription_status==='trial'?'#d97706':'#dc2626'
                        }}>{c.subscription_status==='trial'?`Prøve (${daysLeft||0}d)`:c.subscription_status==='active'?'Aktiv':'Utløpt'}</span>
                        {c.admin_notes && <span title={c.admin_notes} style={{ fontSize:'14px', cursor:'help' }}>📝</span>}
                      </div>
                    </div>
                    {/* Expanded details */}
                    {selectedCompany?.id===c.id && (
                      <div style={{ marginTop:'14px', paddingTop:'14px', borderTop:'1px solid #f1f5f9' }}>
                        <div style={{ display:'grid', gridTemplateColumns: isMobSA ? '1fr' : '1fr 1fr 1fr', gap:'10px', marginBottom:'14px' }}>
                          {[['Org.nr',c.org_number],['Telefon',c.phone],['Adresse',c.address],['Registrert',c.created_at?new Date(c.created_at).toLocaleDateString('nb-NO'):'—'],['Trial start',c.trial_start_date?new Date(c.trial_start_date).toLocaleDateString('nb-NO'):'—'],['Trial slutt',c.trial_ends_at?new Date(c.trial_ends_at).toLocaleDateString('nb-NO'):'—']].filter(r=>r[1]).map(([k,v])=>(
                            <div key={k} style={{ background:'#f8fafc', borderRadius:'8px', padding:'8px 12px' }}>
                              <div style={{ fontSize:'10px', color:'#94a3b8', fontWeight:'600', textTransform:'uppercase' }}>{k}</div>
                              <div style={{ fontSize:'13px', fontWeight:'600', color:'#0f172a', marginTop:'2px', wordBreak:'break-word' }}>{v}</div>
                            </div>
                          ))}
                        </div>

                        {/* Betalingsstatus */}
                        {c.subscription_status==='active' && (
                          <div style={{ marginBottom:'12px' }}>
                            <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', marginBottom:'6px' }}>BETALING</div>
                            <div style={{ display:'flex', gap:'8px', flexWrap:'wrap', alignItems:'center' }}>
                              <div style={{ background: c.next_due_date && new Date(c.next_due_date) < new Date() ? '#fef2f2' : '#f8fafc', borderRadius:'8px', padding:'8px 12px', border: c.next_due_date && new Date(c.next_due_date) < new Date() ? '1px solid #fecaca' : '1px solid #f1f5f9', flex: isMobSA ? '1 1 100%' : '1 1 140px' }}>
                                <div style={{ fontSize:'10px', color:'#94a3b8', fontWeight:'600' }}>SISTE BETALING</div>
                                <div style={{ fontSize:'13px', fontWeight:'700', color: c.last_payment_date ? '#059669' : '#dc2626', marginTop:'2px' }}>
                                  {c.last_payment_date ? new Date(c.last_payment_date).toLocaleDateString('nb-NO') : 'Ingen registrert'}
                                </div>
                              </div>
                              <div style={{ background: c.next_due_date && new Date(c.next_due_date) < new Date() ? '#fef2f2' : '#f8fafc', borderRadius:'8px', padding:'8px 12px', border: c.next_due_date && new Date(c.next_due_date) < new Date() ? '1px solid #fecaca' : '1px solid #f1f5f9', flex: isMobSA ? '1 1 100%' : '1 1 140px' }}>
                                <div style={{ fontSize:'10px', color:'#94a3b8', fontWeight:'600' }}>NESTE FORFALL</div>
                                <div style={{ fontSize:'13px', fontWeight:'700', color: c.next_due_date && new Date(c.next_due_date) < new Date() ? '#dc2626' : '#0f172a', marginTop:'2px' }}>
                                  {c.next_due_date ? new Date(c.next_due_date).toLocaleDateString('nb-NO') : '—'}
                                  {c.next_due_date && new Date(c.next_due_date) < new Date() && <span style={{ color:'#dc2626', fontSize:'10px', fontWeight:'700', marginLeft:'6px' }}>FORFALT</span>}
                                </div>
                              </div>
                              <button onClick={(e)=>{e.stopPropagation();setPaymentModal({companyId:c.id, date: new Date().toISOString().split('T')[0]})}}
                                style={{ padding: isMobSA ? '12px 14px' : '8px 14px', background:'#059669', color:'white', border:'none', borderRadius:'8px', cursor:'pointer', fontSize: isMobSA ? '13px' : '12px', fontWeight:'700', whiteSpace:'nowrap', width: isMobSA ? '100%' : 'auto', minHeight: isMobSA ? '44px' : 'auto' }}>💳 Registrer betaling</button>
                            </div>
                          </div>
                        )}

                        {/* Tidslinje */}
                        <div style={{ marginBottom:'12px' }}>
                          <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', marginBottom:'6px' }}>TIDSLINJE</div>
                          <div style={{ position:'relative', paddingLeft:'20px' }}>
                            <div style={{ position:'absolute', left:'6px', top:'4px', bottom:'4px', width:'2px', background:'#e2e8f0' }}/>
                            {[
                              // Auto-generated events
                              c.created_at && { ts: c.created_at, icon:'🆕', label:'Registrert', color:'#2563eb' },
                              c.trial_start_date && { ts: c.trial_start_date, icon:'🎉', label:'Prøveperiode startet', color:'#d97706' },
                              c.trial_ends_at && c.subscription_status==='trial' && { ts: c.trial_ends_at, icon:'⏰', label:'Prøveperiode utløper', color:'#dc2626', future: new Date(c.trial_ends_at)>new Date() },
                              c.last_payment_date && { ts: c.last_payment_date, icon:'💳', label:'Betaling registrert', color:'#059669' },
                              // Manual timeline events
                              ...(c.timeline||[]).map(e=>({ ts: e.timestamp, icon: e.type==='status'?'🔄':e.type==='trial_extend'?'📅':e.type==='note'?'📝':'📌', label: e.label, color:'#7c3aed' })),
                            ].filter(Boolean).sort((a,b)=>new Date(b.ts)-new Date(a.ts)).slice(0,10).map((evt,i)=>(
                              <div key={i} style={{ display:'flex', alignItems:'flex-start', gap:'10px', marginBottom:'8px', position:'relative' }}>
                                <div style={{ width:'14px', height:'14px', borderRadius:'50%', background: evt.future ? '#f8fafc' : (evt.color+'15'), border: `2px solid ${evt.color}`, flexShrink:0, zIndex:1, marginTop:'1px' }}/>
                                <div style={{ flex:1 }}>
                                  <div style={{ display:'flex', justifyContent:'space-between', gap:'8px' }}>
                                    <span style={{ fontSize:'12px', fontWeight:'600', color:'#0f172a' }}>{evt.icon} {evt.label}</span>
                                    <span style={{ fontSize:'10px', color:'#94a3b8', flexShrink:0 }}>{new Date(evt.ts).toLocaleDateString('nb-NO')}{evt.future?' (planlagt)':''}</span>
                                  </div>
                                </div>
                              </div>
                            ))}
                          </div>
                        </div>
                        <div style={{ marginBottom:'12px' }}>
                          <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', marginBottom:'6px' }}>AKTIVE MODULER</div>
                          <div style={{ display:'flex', gap:'6px', flexWrap:'wrap' }}>
                            {mods.map(m=>{
                              const mod=MODULE_CATALOG.find(x=>x.id===m)
                              return <span key={m} style={{ background:'#f0fdf4', color:'#059669', border:'1px solid #bbf7d0', borderRadius:'999px', padding:'2px 10px', fontSize:'11px', fontWeight:'600' }}>{mod?.emoji||''} {mod?.name||m}</span>
                            })}
                          </div>
                        </div>
                        {/* Kontaktinfo — klikkbar */}
                        {(c.email||c.phone) && (
                          <div style={{ marginBottom:'12px' }}>
                            <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', marginBottom:'6px' }}>KONTAKT</div>
                            <div style={{ display:'flex', gap:'8px', flexWrap:'wrap' }}>
                              {c.email && <a href={`mailto:${c.email}`} onClick={e=>e.stopPropagation()} style={{ display:'flex', alignItems:'center', gap:'6px', padding: isMobSA ? '10px 14px' : '8px 14px', background:'#eff6ff', borderRadius:'8px', border:'1px solid #bfdbfe', textDecoration:'none', fontSize:'12px', fontWeight:'600', color:'#2563eb', minHeight: isMobSA ? '44px' : 'auto', wordBreak:'break-all', flex: isMobSA ? '1 1 100%' : 'none' }}>✉️ {c.email}</a>}
                              {c.phone && <a href={`tel:${c.phone}`} onClick={e=>e.stopPropagation()} style={{ display:'flex', alignItems:'center', gap:'6px', padding: isMobSA ? '10px 14px' : '8px 14px', background:'#f0fdf4', borderRadius:'8px', border:'1px solid #bbf7d0', textDecoration:'none', fontSize:'12px', fontWeight:'600', color:'#059669', minHeight: isMobSA ? '44px' : 'auto', flex: isMobSA ? '1 1 auto' : 'none' }}>📞 {c.phone}</a>}
                              {c.email && <button onClick={(e)=>{e.stopPropagation();setEmailModal({
                                to: c.email,
                                companyName: c.name||'',
                                subject: c.subscription_status==='trial' ? `Din prøveperiode på En Plattform` : `Oppdatering fra En Plattform`,
                                body: c.subscription_status==='trial'
                                  ? `Hei ${c.name||''}!\n\nVi ser at du tester En Plattform. Prøveperioden din ${c.trial_ends_at ? 'utløper '+new Date(c.trial_ends_at).toLocaleDateString('nb-NO') : 'er aktiv'}.\n\nHar du spørsmål om systemet? Vi hjelper gjerne!\n\nMvh\nEn Plattform`
                                  : `Hei ${c.name||''}!\n\n\n\nMvh\nEn Plattform`
                              })}} style={{ display:'flex', alignItems:'center', gap:'6px', padding: isMobSA ? '10px 14px' : '8px 14px', background:'#faf5ff', borderRadius:'8px', border:'1px solid #e9d5ff', cursor:'pointer', fontSize:'12px', fontWeight:'600', color:'#7c3aed', minHeight: isMobSA ? '44px' : 'auto', flex: isMobSA ? '1 1 auto' : 'none', justifyContent: isMobSA ? 'center' : 'flex-start' }}>✍️ Send e-post</button>}
                            </div>
                          </div>
                        )}

                        {/* Interne notater */}
                        <div style={{ marginBottom:'12px' }}>
                          <div style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', marginBottom:'6px' }}>INTERNE NOTATER</div>
                          {editNote?.companyId===c.id ? (
                            <div onClick={e=>e.stopPropagation()}>
                              <textarea value={editNote.note} onChange={e=>setEditNote({...editNote,note:e.target.value})} rows={isMobSA ? 4 : 3}
                                style={{ width:'100%', padding: isMobSA ? '12px 14px' : '10px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize: isMobSA ? '14px' : '13px', outline:'none', resize:'vertical', boxSizing:'border-box', fontFamily:'system-ui,sans-serif' }}
                                placeholder="Skriv interne notater om denne kunden..." />
                              <div style={{ display:'flex', gap:'6px', marginTop:'6px' }}>
                                <button onClick={()=>saveCompanyNote(c.id,editNote.note)} disabled={savingNote}
                                  style={{ padding: isMobSA ? '10px 14px' : '6px 14px', background:'#059669', color:'white', border:'none', borderRadius:'6px', cursor:'pointer', fontSize:'11px', fontWeight:'700', minHeight: isMobSA ? '40px' : 'auto', flex: isMobSA ? 1 : 'none' }}>{savingNote?'Lagrer...':'Lagre'}</button>
                                <button onClick={()=>setEditNote(null)}
                                  style={{ padding: isMobSA ? '10px 14px' : '6px 14px', background:'#f1f5f9', border:'none', borderRadius:'6px', cursor:'pointer', fontSize:'11px', color:'#64748b', minHeight: isMobSA ? '40px' : 'auto', flex: isMobSA ? 1 : 'none' }}>Avbryt</button>
                              </div>
                            </div>
                          ) : (
                            <div onClick={e=>{e.stopPropagation();setEditNote({companyId:c.id,note:c.admin_notes||''})}}
                              style={{ background:'#fefce8', borderRadius:'8px', padding: isMobSA ? '12px 14px' : '10px 12px', border:'1px solid #fde68a', cursor:'pointer', minHeight: isMobSA ? '44px' : '40px' }}>
                              {c.admin_notes ? (
                                <div style={{ fontSize:'12px', color:'#92400e', whiteSpace:'pre-wrap', lineHeight:1.5 }}>{c.admin_notes}</div>
                              ) : (
                                <div style={{ fontSize:'12px', color:'#d4a574', fontStyle:'italic' }}>Klikk for å legge til notater...</div>
                              )}
                            </div>
                          )}
                        </div>

                        {/* Handlingsknapper */}
                        <div style={{ display:'flex', gap:'8px', flexWrap:'wrap' }}>
                          {c.subscription_status==='trial' && <>
                            <button onClick={(e)=>{e.stopPropagation();extendTrial(c.id,7)}} style={{ padding: isMobSA ? '10px 14px' : '8px 14px', background:'#eff6ff', color:'#2563eb', border:'1px solid #bfdbfe', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'600', minHeight: isMobSA ? '40px' : 'auto', flex: isMobSA ? '1 1 auto' : 'none' }}>+7 dager</button>
                            <button onClick={(e)=>{e.stopPropagation();extendTrial(c.id,15)}} style={{ padding: isMobSA ? '10px 14px' : '8px 14px', background:'#eff6ff', color:'#2563eb', border:'1px solid #bfdbfe', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'600', minHeight: isMobSA ? '40px' : 'auto', flex: isMobSA ? '1 1 auto' : 'none' }}>+15 dager</button>
                            <button onClick={(e)=>{e.stopPropagation();setCompanyStatus(c.id,'active')}} style={{ padding: isMobSA ? '10px 14px' : '8px 14px', background:'#059669', color:'white', border:'none', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'700', minHeight: isMobSA ? '40px' : 'auto', flex: isMobSA ? '1 1 100%' : 'none' }}>✓ Aktiver</button>
                          </>}
                          {c.subscription_status==='expired' && <>
                            <button onClick={(e)=>{e.stopPropagation();extendTrial(c.id,15)}} style={{ padding: isMobSA ? '10px 14px' : '8px 14px', background:'#eff6ff', color:'#2563eb', border:'1px solid #bfdbfe', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'600', minHeight: isMobSA ? '40px' : 'auto', flex: isMobSA ? '1 1 auto' : 'none' }}>Ny prøveperiode</button>
                            <button onClick={(e)=>{e.stopPropagation();setCompanyStatus(c.id,'active')}} style={{ padding: isMobSA ? '10px 14px' : '8px 14px', background:'#059669', color:'white', border:'none', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'700', minHeight: isMobSA ? '40px' : 'auto', flex: isMobSA ? '1 1 auto' : 'none' }}>✓ Aktiver</button>
                          </>}
                          {c.subscription_status==='active' && <>
                            <button onClick={(e)=>{e.stopPropagation();setCompanyStatus(c.id,'cancelled')}} style={{ padding: isMobSA ? '10px 14px' : '8px 14px', background:'#fef2f2', color:'#dc2626', border:'1px solid #fecaca', borderRadius:'8px', cursor:'pointer', fontSize:'12px', fontWeight:'600', minHeight: isMobSA ? '40px' : 'auto', flex: isMobSA ? '1 1 100%' : 'none' }}>Kanseller</button>
                          </>}
                        </div>
                      </div>
                    )}
                  </div>
                )
              })}
            </div>
          </>
        )}

        {/* BRUKERE TAB */}
        {tab==='brukere' && (
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            <div style={{ fontSize:'13px', color:'#64748b', marginBottom:'4px' }}>{allUsers.length} brukere totalt</div>
            {allUsers.map(u=>(
              <div key={u.id} style={{ ...saCard, padding: isMobSA ? '10px 12px' : '12px 16px', display:'flex', alignItems:'center', gap: isMobSA ? '10px' : '12px' }}>
                <div style={{ width:'32px', height:'32px', borderRadius:'50%', background:'#f1f5f9', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'13px', fontWeight:'700', color:'#475569', flexShrink:0 }}>{(u.full_name?.[0]||u.email?.[0]||'?').toUpperCase()}</div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontWeight:'600', fontSize:'13px', color:'#0f172a', wordBreak: isMobSA ? 'break-word' : 'normal', overflow: isMobSA ? 'visible' : 'hidden', textOverflow: isMobSA ? 'clip' : 'ellipsis', whiteSpace: isMobSA ? 'normal' : 'nowrap' }}>{u.full_name||u.email}</div>
                  <div style={{ fontSize:'11px', color:'#94a3b8', wordBreak: isMobSA ? 'break-all' : 'normal' }}>{u.email} · {u.role} · {u.status}</div>
                </div>
                <div style={{ fontSize:'11px', color:'#64748b', flexShrink:0, textAlign:'right' }}>
                  {u.last_seen ? new Date(u.last_seen).toLocaleDateString('nb-NO') : 'Aldri'}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* HENDELSER TAB */}
        {tab==='varsler' && (
          <div style={{ display:'flex', flexDirection:'column', gap:'8px' }}>
            <div style={{ fontSize:'13px', color:'#64748b', marginBottom:'4px' }}>Systemhendelser og varsler</div>
            {notifications.length===0 ? <p style={{ color:'#94a3b8', textAlign:'center', padding:'40px', fontSize:'14px' }}>Ingen hendelser ennå</p> :
              notifications.map(n=>(
                <div key={n.id} style={{ ...saCard, padding: isMobSA ? '10px 12px' : '12px 16px', display:'flex', alignItems:'flex-start', gap:'10px' }}>
                  <span style={{ fontSize:'18px', flexShrink:0, marginTop:'2px' }}>{n.title?.includes('registrert')?'🆕':n.title?.includes('kjøpt')?'💰':'🔔'}</span>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontWeight:'600', fontSize:'13px', color:'#0f172a', wordBreak:'break-word' }}>{n.title}</div>
                    <div style={{ fontSize:'12px', color:'#64748b', marginTop:'2px', wordBreak:'break-word' }}>{n.message}</div>
                    <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'4px' }}>{new Date(n.created_at).toLocaleString('nb-NO')}</div>
                  </div>
                </div>
              ))
            }
          </div>
        )}
      </div>

      {/* EMAIL MODAL */}
      {emailModal && (
        <div onClick={()=>setEmailModal(null)} style={{ position:'fixed', inset:0, background:'rgba(15,23,42,0.5)', display:'flex', alignItems: isMobSA ? 'flex-end' : 'center', justifyContent:'center', zIndex:1000, padding: isMobSA ? 0 : '20px' }}>
          <div onClick={e=>e.stopPropagation()} style={{ background:'white', borderRadius: isMobSA ? '16px 16px 0 0' : '16px', padding: isMobSA ? '16px' : '24px', width:'100%', maxWidth: isMobSA ? '100%' : '560px', maxHeight: isMobSA ? '90vh' : '85vh', overflowY:'auto', boxShadow:'0 20px 50px rgba(0,0,0,0.2)', boxSizing:'border-box' }}>
            {isMobSA && <div style={{ width:'40px', height:'4px', background:'#e2e8f0', borderRadius:'2px', margin:'0 auto 14px' }}/>}
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'16px' }}>
              <h3 style={{ margin:0, fontSize: isMobSA ? '16px' : '18px', fontWeight:'700', color:'#0f172a' }}>✉️ Send e-post</h3>
              <button onClick={()=>setEmailModal(null)} style={{ background:'#f1f5f9', border:'none', borderRadius:'8px', width:'32px', height:'32px', cursor:'pointer', fontSize:'16px', color:'#64748b' }}>✕</button>
            </div>
            <div style={{ display:'flex', flexDirection:'column', gap:'10px' }}>
              <div>
                <label style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase' }}>Til</label>
                <input value={emailModal.to} onChange={e=>setEmailModal({...emailModal,to:e.target.value})}
                  style={{ width:'100%', padding: isMobSA ? '12px 14px' : '10px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize: isMobSA ? '14px' : '13px', outline:'none', boxSizing:'border-box', marginTop:'4px', minHeight: isMobSA ? '44px' : 'auto' }} />
              </div>
              <div>
                <label style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase' }}>Emne</label>
                <input value={emailModal.subject} onChange={e=>setEmailModal({...emailModal,subject:e.target.value})}
                  style={{ width:'100%', padding: isMobSA ? '12px 14px' : '10px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize: isMobSA ? '14px' : '13px', outline:'none', boxSizing:'border-box', marginTop:'4px', minHeight: isMobSA ? '44px' : 'auto' }} />
              </div>
              <div>
                <label style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase' }}>Melding</label>
                <textarea value={emailModal.body} onChange={e=>setEmailModal({...emailModal,body:e.target.value})} rows={isMobSA ? 8 : 10}
                  style={{ width:'100%', padding: isMobSA ? '12px 14px' : '10px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize: isMobSA ? '14px' : '13px', outline:'none', resize:'vertical', boxSizing:'border-box', marginTop:'4px', fontFamily:'system-ui,sans-serif', lineHeight:1.5 }} />
              </div>
              <div style={{ display:'flex', gap:'8px', marginTop:'6px', flexDirection: isMobSA ? 'column-reverse' : 'row' }}>
                <button onClick={()=>setEmailModal(null)}
                  style={{ padding: isMobSA ? '12px 16px' : '10px 16px', background:'#f1f5f9', color:'#64748b', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobSA ? '14px' : '13px', fontWeight:'600', minHeight: isMobSA ? '44px' : 'auto', flex: isMobSA ? 'none' : 'none' }}>Avbryt</button>
                <button onClick={sendEmail} disabled={sendingEmail||!emailModal.to}
                  style={{ padding: isMobSA ? '12px 16px' : '10px 16px', background: (sendingEmail||!emailModal.to) ? '#cbd5e1' : '#7c3aed', color:'white', border:'none', borderRadius:'10px', cursor: (sendingEmail||!emailModal.to) ? 'not-allowed' : 'pointer', fontSize: isMobSA ? '14px' : '13px', fontWeight:'700', minHeight: isMobSA ? '44px' : 'auto', flex:1 }}>{sendingEmail?'Åpner...':'📧 Åpne i e-postklient'}</button>
              </div>
              <div style={{ fontSize:'11px', color:'#94a3b8', textAlign:'center', marginTop:'4px', lineHeight:1.5 }}>
                Åpner din e-postklient med forhåndsutfylt melding. Send derfra.
              </div>
            </div>
          </div>
        </div>
      )}

      {/* PAYMENT MODAL */}
      {paymentModal && (
        <div onClick={()=>setPaymentModal(null)} style={{ position:'fixed', inset:0, background:'rgba(15,23,42,0.5)', display:'flex', alignItems: isMobSA ? 'flex-end' : 'center', justifyContent:'center', zIndex:1000, padding: isMobSA ? 0 : '20px' }}>
          <div onClick={e=>e.stopPropagation()} style={{ background:'white', borderRadius: isMobSA ? '16px 16px 0 0' : '16px', padding: isMobSA ? '16px' : '24px', width:'100%', maxWidth: isMobSA ? '100%' : '420px', boxShadow:'0 20px 50px rgba(0,0,0,0.2)', boxSizing:'border-box' }}>
            {isMobSA && <div style={{ width:'40px', height:'4px', background:'#e2e8f0', borderRadius:'2px', margin:'0 auto 14px' }}/>}
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'16px' }}>
              <h3 style={{ margin:0, fontSize: isMobSA ? '16px' : '18px', fontWeight:'700', color:'#0f172a' }}>💳 Registrer betaling</h3>
              <button onClick={()=>setPaymentModal(null)} style={{ background:'#f1f5f9', border:'none', borderRadius:'8px', width:'32px', height:'32px', cursor:'pointer', fontSize:'16px', color:'#64748b' }}>✕</button>
            </div>
            {(() => {
              const comp = companies.find(c=>c.id===paymentModal.companyId)
              return (
                <>
                  {comp && (
                    <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'12px', marginBottom:'14px' }}>
                      <div style={{ fontSize:'11px', color:'#94a3b8', fontWeight:'600', textTransform:'uppercase' }}>Kunde</div>
                      <div style={{ fontSize:'14px', fontWeight:'700', color:'#0f172a', marginTop:'2px' }}>{comp.name||'Uten navn'}</div>
                      {comp.email && <div style={{ fontSize:'11px', color:'#64748b', marginTop:'2px', wordBreak:'break-all' }}>{comp.email}</div>}
                    </div>
                  )}
                  <div style={{ marginBottom:'14px' }}>
                    <label style={{ fontSize:'11px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase' }}>Betalingsdato</label>
                    <input type="date" value={paymentModal.date} onChange={e=>setPaymentModal({...paymentModal,date:e.target.value})}
                      style={{ width:'100%', padding: isMobSA ? '12px 14px' : '10px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize: isMobSA ? '14px' : '13px', outline:'none', boxSizing:'border-box', marginTop:'4px', minHeight: isMobSA ? '44px' : 'auto', fontFamily:'system-ui,sans-serif' }} />
                    {paymentModal.date && (
                      <div style={{ fontSize:'11px', color:'#64748b', marginTop:'6px' }}>
                        Neste forfall blir: <strong style={{ color:'#0f172a' }}>{(() => { const d = new Date(paymentModal.date); d.setMonth(d.getMonth()+1); return d.toLocaleDateString('nb-NO') })()}</strong>
                      </div>
                    )}
                  </div>
                  <div style={{ display:'flex', gap:'8px', flexDirection: isMobSA ? 'column-reverse' : 'row' }}>
                    <button onClick={()=>setPaymentModal(null)}
                      style={{ padding: isMobSA ? '12px 16px' : '10px 16px', background:'#f1f5f9', color:'#64748b', border:'none', borderRadius:'10px', cursor:'pointer', fontSize: isMobSA ? '14px' : '13px', fontWeight:'600', minHeight: isMobSA ? '44px' : 'auto' }}>Avbryt</button>
                    <button onClick={()=>savePayment(paymentModal.companyId, paymentModal.date)} disabled={!paymentModal.date}
                      style={{ padding: isMobSA ? '12px 16px' : '10px 16px', background: !paymentModal.date ? '#cbd5e1' : '#059669', color:'white', border:'none', borderRadius:'10px', cursor: !paymentModal.date ? 'not-allowed' : 'pointer', fontSize: isMobSA ? '14px' : '13px', fontWeight:'700', minHeight: isMobSA ? '44px' : 'auto', flex:1 }}>✓ Lagre betaling</button>
                  </div>
                </>
              )
            })()}
          </div>
        </div>
      )}
    </div>
  )
}

function MinBedriftPage() {
  const { user } = useAuth()
  const appAlert = useAppAlert()
  const [tab, setTab] = useState('info')
  const [settings, setSettings] = useState(null)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [logoUploading, setLogoUploading] = useState(false)
  const [activeModules, setActiveModules] = useState(['grunnpakke'])
  const [numUsers, setNumUsers] = useState(1)
  const [confirmModule, setConfirmModule] = useState(null) // {mod, action: 'add'|'remove'}
  const fileInputRef = React.useRef(null)

  const load = async () => {
    try {
      const { data } = await supabase.from('company_settings').select('*').limit(1).single()
      if (data) {
        setSettings(data)
        setActiveModules(data.active_modules || ['grunnpakke'])
        setNumUsers(data.num_users || 1)
      }
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(() => { load() }, [])

  const handleSaveInfo = async () => {
    if (!settings) return
    setSaving(true)
    try {
      const payload = { ...settings, updated_at: new Date().toISOString() }
      if (settings.id) {
        const { error } = await supabase.from('company_settings').update(payload).eq('id', settings.id)
        if (error) throw error
      } else {
        const { error } = await supabase.from('company_settings').insert(payload)
        if (error) throw error
      }
      invalidateBrandCache() // Sikre at nye PDFer får oppdatert logo/info
      appAlert({ message: 'Bedriftsinformasjon lagret', kind: 'success' })
    } catch(e) { appAlert({ message: 'Kunne ikke lagre', subMessage: e.message, kind: 'error' }) }
    finally { setSaving(false) }
  }

  const uploadLogo = async (e) => {
    const file = e.target.files?.[0]; if (!file) return
    setLogoUploading(true)
    try {
      const path = `logos/${Date.now()}_${file.name}`
      const { error: upErr } = await supabase.storage.from('plattform-files').upload(path, file)
      if (upErr) throw upErr
      const { data: { publicUrl } } = supabase.storage.from('plattform-files').getPublicUrl(path)
      setSettings(s => ({ ...s, logo_url: publicUrl }))
    } catch(e) { appAlert({ message: 'Kunne ikke laste opp logo', subMessage: e.message, kind: 'error' }) }
    finally { setLogoUploading(false); e.target.value = '' }
  }

  const toggleModule = async (modId, action) => {
    let newModules = action === 'add'
      ? [...activeModules, modId]
      : activeModules.filter(m => m !== modId)

    // ── BIM-Kalkyle avhengighetslogikk ──────────────────────────────────────
    // 1. Aktivering av bim_kalkyle krever at kalkulator også er aktivt
    if (action === 'add' && modId === 'bim_kalkyle' && !newModules.includes('kalkulator')) {
      newModules = [...newModules, 'kalkulator']
      appAlert({ message: 'Kalkulasjon (basis) ble også aktivert', subMessage: 'BIM-Kalkyle krever basis Kalkulasjon. Begge er nå aktive.', kind: 'info' })
    }
    // 2. Deaktivering av kalkulator deaktiverer automatisk bim_kalkyle
    if (action === 'remove' && modId === 'kalkulator' && newModules.includes('bim_kalkyle')) {
      newModules = newModules.filter(m => m !== 'bim_kalkyle')
      appAlert({ message: 'BIM-Kalkyle ble også deaktivert', subMessage: 'BIM-Kalkyle krever basis Kalkulasjon og kan ikke kjøres alene.', kind: 'info' })
    }

    setActiveModules(newModules)
    try {
      // If first module purchase during trial, upgrade to active
      const updates = { active_modules: newModules, updated_at: new Date().toISOString() }
      if (settings.subscription_status === 'trial' && action === 'add') {
        updates.subscription_status = 'active'
      }
      await supabase.from('company_settings').update(updates).eq('id', settings.id)
      // Notify platform owner about purchase
      if (action === 'add') {
        const mod = MODULE_CATALOG.find(m=>m.id===modId)
        try {
          const { data: owners } = await supabase.from('user_profiles').select('id').eq('platform_role','platform_owner')
          if (owners?.length) {
            for (const owner of owners) {
              await supabase.from('notifications').insert({
                user_id: owner.id,
                title: '💰 Ny modulkjøp',
                message: `${settings.name} har kjøpt ${mod?.name||modId} (${mod?.perCompany?mod.price+' kr/mnd bedrift':(mod?.price||0)+' kr/mnd'})`,
                type: 'system',
              })
            }
          }
        } catch(e) { console.error(e) }
      }
    } catch(e) { appAlert({ message: 'Kunne ikke oppdatere modul', subMessage: e.message, kind: 'error' }); setActiveModules(activeModules) }
    setConfirmModule(null)
  }

  const saveNumUsers = async (n) => {
    const num = Math.max(1, parseInt(n) || 1)
    setNumUsers(num)
    try {
      await supabase.from('company_settings').update({ num_users: num, updated_at: new Date().toISOString() }).eq('id', settings.id)
    } catch(e) { console.error(e) }
  }

  const set = (k, v) => setSettings(s => ({ ...s, [k]: v }))

  // Cost calculation
  const grunnpakke = MODULE_CATALOG.find(m => m.id === 'grunnpakke')
  const grunnpakkeCost = (grunnpakke?.pricePerUser || 199) * numUsers
  const tilleggCost = MODULE_CATALOG
    .filter(m => !m.required && activeModules.includes(m.id))
    .reduce((acc, m) => acc + (m.price || 0), 0)
  const totalCost = grunnpakkeCost + tilleggCost
  const activeAddons = MODULE_CATALOG.filter(m => !m.required && m.id !== 'grunnpakke' && activeModules.includes(m.id))

  const isMobMB = typeof window !== 'undefined' && window.innerWidth < 768

  if (loading) return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'60vh', fontFamily:'system-ui,sans-serif' }}>
      <div style={{ textAlign:'center' }}>
        <div style={{ width:'36px', height:'36px', border:'3px solid #e2e8f0', borderTop:'3px solid #059669', borderRadius:'50%', margin:'0 auto 12px', animation:'spin 1s linear infinite' }} />
        <p style={{ color:'#94a3b8', fontSize:'14px' }}>Laster bedriftsinnstillinger...</p>
      </div>
    </div>
  )

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      {/* Header */}
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding: isMobMB ? '14px' : '20px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom: isMobMB ? '10px' : '16px', gap:'10px' }}>
          <div style={{ display:'flex', alignItems:'center', gap: isMobMB ? '10px' : '14px', flex:1, minWidth:0 }}>
            {!isMobMB && (settings?.logo_url
              ? <img src={settings.logo_url} alt="Logo" style={{ width:'52px', height:'52px', borderRadius:'12px', objectFit:'contain', border:'1px solid #f1f5f9', background:'white' }} />
              : <div style={{ width:'52px', height:'52px', borderRadius:'12px', background:'#f0fdf4', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'26px' }}>🏢</div>
            )}
            <div style={{ minWidth:0 }}>
              <h1 style={{ fontSize: isMobMB ? '18px' : '22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>{settings?.name || 'Min bedrift'}</h1>
              {!isMobMB && <p style={{ color:'#64748b', marginTop:'2px', fontSize:'13px', marginBottom:0 }}>{settings?.org_number ? `Org.nr: ${settings.org_number}` : 'Legg til bedriftsinformasjon'}</p>}
            </div>
          </div>
          <div style={{ textAlign:'right', flexShrink:0 }}>
            {!isMobMB && <div style={{ fontSize:'13px', color:'#64748b', marginBottom:'2px' }}>Månedlig kostnad</div>}
            <div style={{ fontSize: isMobMB ? '16px' : '22px', fontWeight:'800', color:'#059669' }}>{totalCost.toLocaleString('nb-NO')} kr</div>
            <div style={{ fontSize: isMobMB ? '10px' : '11px', color:'#94a3b8' }}>{isMobMB ? '/mnd' : 'eks. mva · '+numUsers+' bruker'+(numUsers>1?'e':'')}</div>
          </div>
        </div>
        <div style={{ display:'flex', gap:'4px' }}>
          {[['info', isMobMB ? '🏢 Info' : '🏢 Bedriftsinformasjon'],['moduler', isMobMB ? '📦 Moduler' : '📦 Moduler og priser']].map(([id, label]) => (
            <button key={id} onClick={() => setTab(id)}
              style={{ padding: isMobMB ? '7px 12px' : '8px 18px', borderRadius:'10px', border:'none', background:tab===id?'#059669':'#f8fafc', color:tab===id?'white':'#64748b', fontWeight:tab===id?'700':'500', fontSize: isMobMB ? '12px' : '13px', cursor:'pointer' }}>{label}</button>
          ))}
        </div>
      </div>

      <div style={{ padding: isMobMB ? '12px' : '24px 32px', display:'flex', flexDirection:'column', gap: isMobMB ? '12px' : '20px', maxWidth:'900px' }}>

        {/* TAB: BEDRIFTSINFORMASJON */}
        {tab === 'info' && (
          <>
            {/* Logo */}
            <div style={mbCard}>
              {mbSec('Firmalogo')}
              <div style={{ display:'flex', alignItems:'center', gap: isMobMB ? '12px' : '20px', flexWrap: isMobMB ? 'wrap' : 'nowrap' }}>
                {settings?.logo_url
                  ? <img src={settings.logo_url} alt="Logo" style={{ width: isMobMB ? '60px' : '80px', height: isMobMB ? '60px' : '80px', objectFit:'contain', borderRadius:'12px', border:'1px solid #f1f5f9' }} />
                  : <div style={{ width: isMobMB ? '60px' : '80px', height: isMobMB ? '60px' : '80px', borderRadius:'12px', background:'#f8fafc', border:'2px dashed #e2e8f0', display:'flex', alignItems:'center', justifyContent:'center', fontSize: isMobMB ? '22px' : '28px' }}>🏢</div>
                }
                <div>
                  <div style={{ fontSize:'13px', color:'#475569', marginBottom:'10px' }}>Logoen brukes på tilbud, fakturaer og e-poster til kunder.</div>
                  <button onClick={() => fileInputRef.current?.click()} disabled={logoUploading}
                    style={{ padding:'8px 16px', background:'#f0fdf4', color:'#059669', border:'1px solid #bbf7d0', borderRadius:'8px', cursor:'pointer', fontSize:'13px', fontWeight:'600' }}>
                    {logoUploading ? 'Laster opp...' : '📸 Last opp logo'}
                  </button>
                  <input ref={fileInputRef} type="file" style={{ display:'none' }} onChange={uploadLogo} accept="image/*" capture="environment" />
                  {settings?.logo_url && <button onClick={() => set('logo_url', null)} style={{ marginLeft:'8px', padding:'8px 14px', background:'white', color:'#dc2626', border:'1px solid #fecaca', borderRadius:'8px', cursor:'pointer', fontSize:'13px' }}>Fjern</button>}
                </div>
              </div>
            </div>

            {/* Firmainfo */}
            <div style={mbCard}>
              {mbSec('Firmainfo')}
              <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
                <div style={{ gridColumn:'1/-1' }}>{mbLbl('Firmanavn *')}<input value={settings?.name||''} onChange={e=>set('name',e.target.value)} placeholder="Bedriftens offisielle navn" style={mbInp} /></div>
                <div>{mbLbl('Org.nr')}<input value={settings?.org_number||''} onChange={e=>set('org_number',e.target.value)} placeholder="123 456 789" style={mbInp} /></div>
                <div>{mbLbl('MVA-nummer')}<input value={settings?.vat_number||''} onChange={e=>set('vat_number',e.target.value)} placeholder="NO 123 456 789 MVA" style={mbInp} /></div>
                <div style={{ gridColumn:'1/-1' }}>{mbLbl('Adresse')}<input value={settings?.address||''} onChange={e=>set('address',e.target.value)} placeholder="Gateadresse og nummer" style={mbInp} /></div>
                <div>{mbLbl('Postnummer')}<input value={settings?.postal_code||''} onChange={e=>set('postal_code',e.target.value)} placeholder="0000" style={mbInp} /></div>
                <div>{mbLbl('Poststed')}<input value={settings?.city||''} onChange={e=>set('city',e.target.value)} placeholder="By" style={mbInp} /></div>
                <div>{mbLbl('Telefon')}<input value={settings?.phone||''} onChange={e=>set('phone',e.target.value)} placeholder="+47 xxx xx xxx" style={mbInp} /></div>
                <div>{mbLbl('E-post')}<input type="email" value={settings?.email||''} onChange={e=>set('email',e.target.value)} placeholder="post@bedrift.no" style={mbInp} /></div>
                <div style={{ gridColumn:'1/-1' }}>{mbLbl('Nettside')}<input value={settings?.website||''} onChange={e=>set('website',e.target.value)} placeholder="www.bedrift.no" style={mbInp} /></div>
              </div>
            </div>

            {/* Økonomi */}
            <div style={mbCard}>
              {mbSec('Økonomiinnstillinger')}
              <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
                <div>{mbLbl('Bankkontonummer')}<input value={settings?.bank_account||''} onChange={e=>set('bank_account',e.target.value)} placeholder="xxxx.xx.xxxxx" style={mbInp} /></div>
                <div>{mbLbl('Standard betalingsbetingelser')}<input value={settings?.default_payment_terms||''} onChange={e=>set('default_payment_terms',e.target.value)} placeholder="30 dager netto" style={mbInp} /></div>
                <div>{mbLbl('Standard MVA-sats (%)')}<input type="number" value={settings?.default_vat_rate||25} onChange={e=>set('default_vat_rate',e.target.value)} placeholder="25" style={mbInp} /></div>
              </div>
            </div>

            {/* Standardtekster */}
            <div style={mbCard}>
              {mbSec('Standardtekster for tilbud og fakturaer')}
              <div style={{ display:'flex', flexDirection:'column', gap:'12px' }}>
                <div>{mbLbl('Innledning på tilbud')}<textarea value={settings?.quote_intro_text||''} onChange={e=>set('quote_intro_text',e.target.value)} rows={3} placeholder="Takk for henvendelse. Vi tillater oss å fremme følgende tilbud..." style={{ ...mbInp, resize:'none' }} /></div>
                <div>{mbLbl('Avslutning på tilbud')}<textarea value={settings?.quote_outro_text||''} onChange={e=>set('quote_outro_text',e.target.value)} rows={2} placeholder="Vi håper tilbudet er av interesse og ser frem til et godt samarbeid." style={{ ...mbInp, resize:'none' }} /></div>
                <div>{mbLbl('Bunntekst på faktura')}<textarea value={settings?.invoice_footer||''} onChange={e=>set('invoice_footer',e.target.value)} rows={2} placeholder="Kontonummer: xxxx.xx.xxxxx · Purregebyr ved forsinket betaling" style={{ ...mbInp, resize:'none' }} /></div>
              </div>
            </div>

            {/* Nøkkelpersoner */}
            <div style={mbCard}>
              {mbSec('Nøkkelpersoner')}
              <div style={{ display:'grid', gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr', gap:'12px' }}>
                <div>{mbLbl('Daglig leder')}<EmployeeNameSelect value={settings?.contact_ceo||''} onChange={v=>set('contact_ceo',v)} onSelect={emp => set('contact_ceo', `${emp.first_name||''} ${emp.last_name||''}`.trim())} placeholder="Velg daglig leder" style={{ padding:'8px 10px', fontSize:'13px' }} /></div>
                <div>{mbLbl('HMS-ansvarlig')}<EmployeeNameSelect value={settings?.contact_hms||''} onChange={v=>set('contact_hms',v)} onSelect={emp => set('contact_hms', `${emp.first_name||''} ${emp.last_name||''}`.trim())} placeholder="Velg HMS-ansvarlig" style={{ padding:'8px 10px', fontSize:'13px' }} /></div>
                <div>{mbLbl('Regnskapsfører')}<input value={settings?.contact_accountant||''} onChange={e=>set('contact_accountant',e.target.value)} placeholder="Navn og kontakt" style={mbInp} /></div>
              </div>
            </div>

            <div style={{ display:'flex', justifyContent:'flex-end' }}>
              <button onClick={handleSaveInfo} disabled={saving}
                style={{ padding: isMobMB ? '12px' : '12px 28px', background:saving?'#6ee7b7':'#059669', color:'white', border:'none', borderRadius:'12px', cursor:saving?'not-allowed':'pointer', fontSize: isMobMB ? '14px' : '15px', fontWeight:'700', width: isMobMB ? '100%' : 'auto' }}>
                {saving ? 'Lagrer...' : isMobMB ? '✅ Lagre' : '✅ Lagre bedriftsinformasjon'}
              </button>
            </div>
          </>
        )}

        {/* TAB: MODULER OG PRISER */}
        {tab === 'moduler' && (
          <>
            {/* Brukere */}
            <div style={{ ...mbCard, background:'#f0fdf4', border:'1px solid #bbf7d0' }}>
              <div style={{ display:'flex', alignItems: isMobMB ? 'flex-start' : 'center', justifyContent:'space-between', gap: isMobMB ? '12px' : '20px', flexDirection: isMobMB ? 'column' : 'row' }}>
                <div>
                  <div style={{ display:'flex', alignItems:'center', gap:'10px', marginBottom:'4px' }}>
                    <span style={{ fontSize:'18px' }}>🔹</span>
                    <h3 style={{ margin:0, fontSize:'16px', fontWeight:'800', color:'#0f172a' }}>Grunnpakke</h3>
                    <span style={{ background:'#059669', color:'white', fontSize:'11px', fontWeight:'700', padding:'2px 8px', borderRadius:'999px' }}>Alltid inkludert</span>
                  </div>
                  <p style={{ margin:'0 0 8px', fontSize:'13px', color:'#475569' }}>Alle grunnleggende moduler for prosjektstyring og kvalitetssikring</p>
                  <div style={{ display:'flex', gap:'6px', flexWrap:'wrap' }}>
                    {['Dashboard','Prosjekter','Prosjektfiler','Sjekklister','Avvik','HMS & Risiko','Maskiner','Ansatte','Kundeoversikt','Varsler'].map(m => (
                      <span key={m} style={{ background:'white', color:'#059669', border:'1px solid #bbf7d0', fontSize:'11px', fontWeight:'600', padding:'2px 8px', borderRadius:'999px' }}>✓ {m}</span>
                    ))}
                  </div>
                </div>
                <div style={{ textAlign:'right', flexShrink:0 }}>
                  <div style={{ fontSize:'13px', color:'#64748b', marginBottom:'4px' }}>199 kr/bruker/mnd eks. mva</div>
                  <div style={{ display:'flex', alignItems:'center', gap:'8px', justifyContent:'flex-end' }}>
                    <label style={{ fontSize:'13px', color:'#475569', fontWeight:'600' }}>Antall brukere:</label>
                    <input type="number" value={numUsers} min="1" max="100"
                      onChange={e => saveNumUsers(e.target.value)}
                      style={{ width:'64px', padding:'6px 10px', border:'1px solid #bbf7d0', borderRadius:'8px', fontSize:'14px', fontWeight:'700', textAlign:'center', outline:'none', background:'white' }} />
                  </div>
                  <div style={{ fontSize:'18px', fontWeight:'800', color:'#059669', marginTop:'6px' }}>{grunnpakkeCost.toLocaleString('nb-NO')} kr/mnd</div>
                </div>
              </div>
            </div>

            {/* Tilleggsmoduler header */}
            <div style={{ display:'flex', alignItems: isMobMB ? 'flex-start' : 'center', justifyContent:'space-between', marginTop:'8px', flexDirection: isMobMB ? 'column' : 'row', gap: isMobMB ? '8px' : '0' }}>
              <div>
                <h2 style={{ margin:'0 0 2px', fontSize: isMobMB ? '15px' : '16px', fontWeight:'700', color:'#0f172a' }}>Tilleggsmoduler</h2>
                {!isMobMB && <p style={{ margin:0, fontSize:'13px', color:'#94a3b8' }}>Legg til moduler etter behov. Alle priser per måned, eks. mva.</p>}
              </div>
              <div style={{ textAlign: isMobMB ? 'left' : 'right' }}>
                <div style={{ fontSize:'12px', color:'#64748b' }}>Total</div>
                <div style={{ fontSize: isMobMB ? '16px' : '20px', fontWeight:'800', color:'#0f172a' }}>{totalCost.toLocaleString('nb-NO')} kr/mnd</div>
              </div>
            </div>

            {/* Module grid */}
            <div style={{ display:'grid', gridTemplateColumns: isMobMB ? '1fr' : 'repeat(auto-fill, minmax(280px, 1fr))', gap:'12px' }}>
              {MODULE_CATALOG.filter(m => !m.required && m.id !== 'grunnpakke').map(mod => {
                const isActive = activeModules.includes(mod.id)
                return (
                  <div key={mod.id}
                    style={{ background:'white', borderRadius:'14px', border:`2px solid ${isActive?'#059669':'#f1f5f9'}`, padding:'16px 18px', display:'flex', flexDirection:'column', gap:'10px', position:'relative', transition:'border-color 0.15s' }}>
                    {isActive && (
                      <div style={{ position:'absolute', top:'12px', right:'12px', background:'#059669', color:'white', fontSize:'10px', fontWeight:'700', padding:'2px 8px', borderRadius:'999px' }}>Aktiv</div>
                    )}
                    <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
                      <div style={{ width:'40px', height:'40px', borderRadius:'10px', background:isActive?'#f0fdf4':'#f8fafc', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', flexShrink:0 }}>{mod.emoji}</div>
                      <div>
                        <div style={{ fontWeight:'700', fontSize:'14px', color:'#0f172a' }}>{mod.name}</div>
                        <div style={{ fontSize:'12px', color:'#64748b', marginTop:'1px' }}>{mod.desc}</div>
                      </div>
                    </div>
                    <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginTop:'4px' }}>
                      <div style={{ fontSize:'16px', fontWeight:'800', color:isActive?'#059669':'#0f172a' }}>{mod.price.toLocaleString('nb-NO')} kr/mnd</div>
                      {mod.perCompany && <div style={{ fontSize:'10px', color:'#94a3b8', marginTop:'1px' }}>per bedrift, uavhengig av antall brukere</div>}
                      <button
                        onClick={() => setConfirmModule({ mod, action: isActive ? 'remove' : 'add' })}
                        style={{ padding:'7px 16px', borderRadius:'8px', border:'none', background:isActive?'#fef2f2':'#059669', color:isActive?'#dc2626':'white', fontWeight:'700', fontSize:'12px', cursor:'pointer' }}>
                        {isActive ? 'Avslutt' : 'Bestill'}
                      </button>
                    </div>
                  </div>
                )
              })}
            </div>

            {/* Active addons summary */}
            {activeAddons.length > 0 && (
              <div style={mbCard}>
                <h3 style={{ margin:'0 0 14px', fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>📦 Aktive tilleggsmoduler ({activeAddons.length})</h3>
                {activeAddons.map(mod => (
                  <div key={mod.id} style={{ display:'flex', alignItems:'center', gap:'10px', padding:'8px 0', borderBottom:'1px solid #f8fafc' }}>
                    <span style={{ fontSize:'16px' }}>{mod.emoji}</span>
                    <span style={{ flex:1, fontSize:'13px', fontWeight:'600', color:'#0f172a' }}>{mod.name}</span>
                    <span style={{ fontSize:'13px', color:'#64748b' }}>{mod.price.toLocaleString('nb-NO')} kr/mnd{mod.perCompany?' (bedrift)':''}</span>
                    <button onClick={() => setConfirmModule({ mod, action:'remove' })}
                      style={{ background:'#fef2f2', color:'#dc2626', border:'none', borderRadius:'6px', padding:'4px 10px', fontSize:'12px', cursor:'pointer', fontWeight:'600' }}>Avslutt</button>
                  </div>
                ))}
                <div style={{ display:'flex', justifyContent:'space-between', padding:'12px 0 0', borderTop:'1px solid #f1f5f9', marginTop:'8px' }}>
                  <span style={{ fontSize:'14px', fontWeight:'700', color:'#0f172a' }}>Totalt per måned</span>
                  <span style={{ fontSize:'16px', fontWeight:'800', color:'#059669' }}>{totalCost.toLocaleString('nb-NO')} kr</span>
                </div>
              </div>
            )}
          </>
        )}
      </div>

      {/* Confirm modal */}
      {confirmModule && (
        <div style={{ position:'fixed', inset:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'center', padding:'16px' }}>
          <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.45)' }} onClick={() => setConfirmModule(null)} />
          <div style={{ position:'relative', background:'white', borderRadius:'20px', width:'100%', maxWidth:'420px', padding:'28px', boxShadow:'0 20px 60px rgba(0,0,0,0.2)', fontFamily:'system-ui,sans-serif' }}>
            <div style={{ textAlign:'center', marginBottom:'20px' }}>
              <div style={{ fontSize:'44px', marginBottom:'10px' }}>{confirmModule.action === 'add' ? '✅' : '⚠️'}</div>
              <h2 style={{ margin:'0 0 8px', fontSize:'18px', fontWeight:'800', color:'#0f172a' }}>
                {confirmModule.action === 'add' ? `Bestill ${confirmModule.mod.name}?` : `Avslutt ${confirmModule.mod.name}?`}
              </h2>
              <p style={{ margin:0, fontSize:'14px', color:'#64748b', lineHeight:1.6 }}>
                {confirmModule.action === 'add'
                  ? `Du legger til ${confirmModule.mod.name} for ${confirmModule.mod.price} kr/mnd. Modulen aktiveres umiddelbart.`
                  : `Du avslutter ${confirmModule.mod.name}. Modulen deaktiveres umiddelbart og fjernes fra faktureringen.`
                }
              </p>
            </div>
            {confirmModule.action === 'add' && (
              <div style={{ background:'#f0fdf4', borderRadius:'12px', padding:'14px 16px', border:'1px solid #bbf7d0', marginBottom:'16px' }}>
                <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', marginBottom:'4px' }}>
                  <span style={{ color:'#475569' }}>Nåværende kostnad</span>
                  <span style={{ fontWeight:'600', color:'#0f172a' }}>{totalCost.toLocaleString('nb-NO')} kr/mnd</span>
                </div>
                <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', marginBottom:'4px' }}>
                  <span style={{ color:'#475569' }}>+ {confirmModule.mod.name}</span>
                  <span style={{ fontWeight:'600', color:'#059669' }}>+ {confirmModule.mod.price} kr/mnd</span>
                </div>
                <div style={{ display:'flex', justifyContent:'space-between', fontSize:'16px', fontWeight:'800', color:'#0f172a', borderTop:'1px solid #bbf7d0', paddingTop:'8px', marginTop:'8px' }}>
                  <span>Ny kostnad</span>
                  <span style={{ color:'#059669' }}>{(totalCost + confirmModule.mod.price).toLocaleString('nb-NO')} kr/mnd</span>
                </div>
              </div>
            )}
            {confirmModule.action === 'remove' && (
              <div style={{ background:'#fef2f2', borderRadius:'12px', padding:'14px 16px', border:'1px solid #fecaca', marginBottom:'16px' }}>
                <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', marginBottom:'4px' }}>
                  <span style={{ color:'#475569' }}>Nåværende kostnad</span>
                  <span style={{ fontWeight:'600', color:'#0f172a' }}>{totalCost.toLocaleString('nb-NO')} kr/mnd</span>
                </div>
                <div style={{ display:'flex', justifyContent:'space-between', fontSize:'14px', marginBottom:'4px' }}>
                  <span style={{ color:'#475569' }}>- {confirmModule.mod.name}</span>
                  <span style={{ fontWeight:'600', color:'#dc2626' }}>- {confirmModule.mod.price} kr/mnd</span>
                </div>
                <div style={{ display:'flex', justifyContent:'space-between', fontSize:'16px', fontWeight:'800', color:'#0f172a', borderTop:'1px solid #fecaca', paddingTop:'8px', marginTop:'8px' }}>
                  <span>Ny kostnad</span>
                  <span>{(totalCost - confirmModule.mod.price).toLocaleString('nb-NO')} kr/mnd</span>
                </div>
              </div>
            )}
            <div style={{ display:'flex', gap:'10px' }}>
              <button onClick={() => setConfirmModule(null)}
                style={{ flex:1, padding:'12px', border:'1px solid #e2e8f0', borderRadius:'10px', background:'white', cursor:'pointer', fontSize:'14px', fontWeight:'600', color:'#374151' }}>Avbryt</button>
              <button onClick={() => toggleModule(confirmModule.mod.id, confirmModule.action)}
                style={{ flex:2, padding:'12px', background:confirmModule.action==='add'?'#059669':'#dc2626', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontSize:'14px', fontWeight:'700' }}>
                {confirmModule.action === 'add' ? '✅ Bestill nå' : '⚠️ Avslutt modul'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

// ─── END MIN BEDRIFT MODULE ───────────────────────────────────────────────────


// ─── BRUKERADMIN MODULE ───────────────────────────────────────────────────────

const USER_ROLES = {
  superadmin: { label:'Superadmin', emoji:'👑', color:'#7c3aed', bg:'#f5f3ff', border:'#ddd6fe', desc:'Full tilgang til alt, inkl. brukerstyring' },
  admin:      { label:'Admin',      emoji:'🔑', color:'#2563eb', bg:'#eff6ff', border:'#bfdbfe', desc:'Kan administrere de fleste funksjoner' },
  leder:      { label:'Leder',      emoji:'🏗️', color:'#059669', bg:'#f0fdf4', border:'#bbf7d0', desc:'Kan se og redigere prosjekter og team' },
  ansatt:     { label:'Ansatt',     emoji:'👷', color:'#d97706', bg:'#fffbeb', border:'#fde68a', desc:'Standard tilgang til tildelte moduler' },
  les:        { label:'Les-only',   emoji:'👁️', color:'#64748b', bg:'#f8fafc', border:'#e2e8f0', desc:'Kan kun se, ikke redigere' },
}

const ALL_MODULES_LIST = [
  { id:'prosjekter',   label:'Prosjekter',        emoji:'🏗️' },
  { id:'prosjektfiler',label:'Prosjektfiler',      emoji:'📁' },
  { id:'sjekklister',  label:'Sjekklister',        emoji:'✅' },
  { id:'avvik',        label:'Avvik',              emoji:'⚠️' },
  { id:'hms',          label:'HMS & Risiko',       emoji:'🛡️' },
  { id:'maskiner',     label:'Maskiner',           emoji:'🚜' },
  { id:'tilbud',       label:'Tilbud',             emoji:'📋' },
  { id:'kalkulator',   label:'Kalkulasjon',        emoji:'🧮' },
  { id:'anbudsmodul',  label:'Anbudsmodul',        emoji:'⚖️' },
  { id:'ordre',        label:'Ordre',              emoji:'📝' },
  { id:'faktura',      label:'Faktura',            emoji:'🧾' },
  { id:'ansatte',      label:'Ansatte',            emoji:'👷' },
  { id:'timelister',   label:'Timelister',         emoji:'⏱️' },
  { id:'ressursplan',  label:'Ressursplanlegger',  emoji:'📌' },
  { id:'kalender',     label:'Kalender',           emoji:'📆' },
  { id:'chat',         label:'Intern Chat',        emoji:'💬' },
  { id:'befaring',     label:'Befaring',           emoji:'🔍' },
  { id:'bildedok',     label:'Bildedokumentasjon', emoji:'📷' },
  { id:'fdv',          label:'FDV',                emoji:'🏛️' },
  { id:'crm',          label:'CRM',                emoji:'📊' },
]

const baInp = { width:'100%', padding:'9px 12px', border:'1px solid #e2e8f0', borderRadius:'10px', fontSize:'14px', outline:'none', boxSizing:'border-box', background:'white', color:'#0f172a', fontFamily:'system-ui,sans-serif' }

function BrukeradminPage() {
  const { user } = useAuth()
  const [users, setUsers] = useState([])
  const [invitations, setInvitations] = useState([])
  const [companyModules, setCompanyModules] = useState([])
  const [loading, setLoading] = useState(true)
  const [selectedUser, setSelectedUser] = useState(null)
  React.useEffect(() => {
    if (selectedUser && window.__enterDetailView) {
      window.__enterDetailView(() => setSelectedUser(null))
    }
  }, [selectedUser])
  const [showInvite, setShowInvite] = useState(false)
  const [search, setSearch] = useState('')
  const [filterRole, setFilterRole] = useState('alle')

  const load = async () => {
    try {
      const [uData, iData, cData] = await Promise.all([
        supabase.from('user_profiles').select('*').order('created_at').then(r=>r.data||[]),
        supabase.from('user_invitations').select('*').is('accepted_at',null).gt('expires_at',new Date().toISOString()).order('created_at',{ascending:false}).then(r=>r.data||[]),
        supabase.from('company_settings').select('active_modules,name').limit(1).single().then(r=>r.data||{})
      ])
      setUsers(uData)
      setInvitations(iData)
      setCompanyModules(cData.active_modules || [])
    } catch(e) { console.error(e) }
    finally { setLoading(false) }
  }
  useEffect(()=>{ load() },[])

  // Ensure current user has a profile
  useEffect(()=>{
    if (!user) return
    const syncProfile = async () => {
      const { data } = await supabase.from('user_profiles').select('id').eq('id',user.id).single()
      if (!data) {
        await supabase.from('user_profiles').insert({
          id: user.id,
          email: user.email,
          role: 'superadmin',
          status: 'aktiv',
          module_access: ALL_MODULES_LIST.map(m=>m.id)
        })
        load()
      }
    }
    syncProfile()
  },[user])

  const filtered = users.filter(u => {
    if (filterRole !== 'alle' && u.role !== filterRole) return false
    if (search && ![u.email,u.full_name].some(v=>v?.toLowerCase().includes(search.toLowerCase()))) return false
    return true
  })

  const activeCount = users.filter(u=>u.status==='aktiv').length

  const isMobBA = typeof window !== 'undefined' && window.innerWidth < 768

  if (loading) return (
    <div style={{ display:'flex',alignItems:'center',justifyContent:'center',minHeight:'60vh',fontFamily:'system-ui,sans-serif' }}>
      <div style={{ textAlign:'center' }}>
        <div style={{ width:'36px',height:'36px',border:'3px solid #e2e8f0',borderTop:'3px solid #059669',borderRadius:'50%',margin:'0 auto 12px',animation:'spin 1s linear infinite' }}/>
        <p style={{ color:'#94a3b8',fontSize:'14px' }}>Laster brukere...</p>
      </div>
    </div>
  )

  if (selectedUser) return (
    <UserDetaljer
      userProfile={selectedUser}
      currentUser={user}
      companyModules={companyModules}
      onBack={()=>{ setSelectedUser(null); load() }}
    />
  )

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      {/* Header */}
      <div style={{ background:'white',borderBottom:'1px solid #e2e8f0',padding: isMobBA ? '14px' : '20px 32px' }}>
        <div style={{ display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom: isMobBA ? '10px' : '16px', gap:'10px' }}>
          <div>
            <h1 style={{ fontSize: isMobBA ? '18px' : '22px',fontWeight:'bold',color:'#0f172a',margin:0 }}>{isMobBA ? '👤 Brukere' : '👤 Brukere og tilgang'}</h1>
            {!isMobBA && <p style={{ color:'#64748b',marginTop:'4px',fontSize:'14px',marginBottom:0 }}>Administrer brukere, roller og modultilgang</p>}
          </div>
          <button onClick={()=>setShowInvite(true)}
            style={{ padding: isMobBA ? '9px 12px' : '10px 20px',background:'#059669',color:'white',border:'none',borderRadius:'10px',cursor:'pointer',fontSize: isMobBA ? '12px' : '14px',fontWeight:'700',whiteSpace:'nowrap',flexShrink:0 }}>
            {isMobBA ? '+ Inviter' : '+ Inviter bruker'}
          </button>
        </div>

        {/* Stats */}
        <div style={{ display:'grid',gridTemplateColumns: isMobBA ? 'repeat(3,1fr)' : 'repeat(5,1fr)',gap: isMobBA ? '8px' : '10px' }}>
          {[
            { label:'Totalt', value:users.length, emoji:'👥', bg:'#f8fafc', color:'#0f172a' },
            { label:'Aktive', value:activeCount, emoji:'✅', bg:'#f0fdf4', color:'#16a34a' },
            { label:'Invitert', value:invitations.length, emoji:'📧', bg:'#eff6ff', color:'#2563eb' },
            { label:'Admin', value:users.filter(u=>u.role==='admin'||u.role==='superadmin').length, emoji:'🔑', bg:'#f5f3ff', color:'#7c3aed' },
            { label:'Inaktive', value:users.filter(u=>u.status==='inaktiv').length, emoji:'🔒', bg:'#fef2f2', color:'#dc2626' },
          ].map(s=>(
            <div key={s.label} style={{ background:s.bg,borderRadius: isMobBA ? '10px' : '12px',padding: isMobBA ? '8px 10px' : '12px 14px' }}>
              <div style={{ fontSize: isMobBA ? '14px' : '18px',marginBottom: isMobBA ? '2px' : '4px' }}>{s.emoji}</div>
              <div style={{ fontSize: isMobBA ? '16px' : '20px',fontWeight:'800',color:s.color }}>{s.value}</div>
              <div style={{ fontSize: isMobBA ? '9px' : '11px',color:'#94a3b8',fontWeight:'600',textTransform:'uppercase' }}>{s.label}</div>
            </div>
          ))}
        </div>
      </div>

      <div style={{ padding: isMobBA ? '12px' : '20px 32px',display:'flex',flexDirection:'column',gap: isMobBA ? '12px' : '16px' }}>
        {/* Filters */}
        <div style={{ background:'white',borderRadius:'14px',border:'1px solid #f1f5f9',padding: isMobBA ? '10px' : '14px 18px',display:'flex',gap: isMobBA ? '8px' : '10px',flexWrap:'wrap',alignItems:'center' }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 Søk..." style={{ ...baInp,maxWidth: isMobBA ? '100%' : '220px',flex: isMobBA ? '1 1 100%' : '1' }} />
          <select value={filterRole} onChange={e=>setFilterRole(e.target.value)} style={{ ...baInp,maxWidth: isMobBA ? '100%' : '160px',flex: isMobBA ? '1 1 100%' : 'none' }}>
            <option value="alle">Alle roller</option>
            {Object.entries(USER_ROLES).map(([k,v])=><option key={k} value={k}>{v.emoji} {v.label}</option>)}
          </select>
          {(search||filterRole!=='alle')&&<button onClick={()=>{setSearch('');setFilterRole('alle')}} style={{ background:'#f1f5f9',border:'none',borderRadius:'8px',padding:'9px 14px',fontSize:'13px',cursor:'pointer',color:'#64748b' }}>Nullstill</button>}
          <span style={{ marginLeft:'auto',fontSize:'13px',color:'#94a3b8' }}>{filtered.length} brukere</span>
        </div>

        {/* Pending invitations */}
        {invitations.length>0&&(
          <div style={{ background:'#eff6ff',borderRadius:'14px',border:'1px solid #bfdbfe',padding:'16px 20px' }}>
            <div style={{ fontSize:'13px',fontWeight:'700',color:'#2563eb',marginBottom:'10px' }}>📧 Ventende invitasjoner ({invitations.length})</div>
            {invitations.map(inv=>(
              <div key={inv.id} style={{ display:'flex',alignItems:'center',gap:'12px',padding:'8px 0',borderBottom:'1px solid #bfdbfe30' }}>
                <div style={{ width:'32px',height:'32px',borderRadius:'50%',background:'#bfdbfe',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'14px' }}>📧</div>
                <div style={{ flex:1 }}>
                  <div style={{ fontWeight:'600',fontSize:'13px',color:'#1e3a8a' }}>{inv.email}</div>
                  <div style={{ fontSize:'11px',color:'#3b82f6' }}>{USER_ROLES[inv.role]?.label||'Ansatt'} · Utløper {new Date(inv.expires_at).toLocaleDateString('nb-NO')}</div>
                </div>
                <button onClick={async()=>{ await supabase.from('user_invitations').delete().eq('id',inv.id); load() }}
                  style={{ background:'#fef2f2',color:'#dc2626',border:'none',borderRadius:'6px',padding:'4px 10px',fontSize:'12px',cursor:'pointer',fontWeight:'600' }}>
                  Trekk tilbake
                </button>
              </div>
            ))}
          </div>
        )}

        {/* User list */}
        {filtered.length===0 ? (
          <div style={{ background:'white',borderRadius:'14px',border:'1px solid #f1f5f9',padding:'60px 20px',textAlign:'center' }}>
            <div style={{ fontSize:'40px',marginBottom:'12px' }}>👤</div>
            <h3 style={{ margin:'0 0 6px',color:'#0f172a' }}>Ingen brukere funnet</h3>
            <p style={{ margin:0,color:'#94a3b8',fontSize:'14px' }}>{users.length===0?'Inviter din første bruker.':'Prøv å endre filter.'}</p>
          </div>
        ) : (
          <div style={{ display:'flex',flexDirection:'column',gap:'8px' }}>
            {filtered.map(u=>{
              const cfg=USER_ROLES[u.role]||USER_ROLES.ansatt
              const isCurrentUser = u.id===user?.id
              const modCount=(u.module_access||[]).length
              return (
                <div key={u.id} onClick={()=>setSelectedUser(u)}
                  style={{ background:'white',borderRadius: isMobBA ? '12px' : '14px',border:`1px solid ${u.status==='inaktiv'?'#fecaca':'#f1f5f9'}`,padding: isMobBA ? '12px' : '16px 20px',cursor:'pointer',display:'flex',alignItems: isMobBA ? 'flex-start' : 'center',gap: isMobBA ? '10px' : '16px',transition:'box-shadow 0.15s',opacity:u.status==='inaktiv'?0.7:1 }}
                  onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 16px rgba(0,0,0,0.08)'}
                  onMouseLeave={e=>e.currentTarget.style.boxShadow='none'}>
                  {/* Avatar */}
                  <div style={{ width: isMobBA ? '36px' : '44px',height: isMobBA ? '36px' : '44px',borderRadius:'50%',background:cfg.bg,border:`2px solid ${cfg.border}`,display:'flex',alignItems:'center',justifyContent:'center',fontSize: isMobBA ? '14px' : '18px',flexShrink:0 }}>
                    {u.avatar_url ? <img src={u.avatar_url} alt="" style={{ width:'100%',height:'100%',borderRadius:'50%',objectFit:'cover' }} /> : (u.full_name?.[0]||u.email?.[0]||'?').toUpperCase()}
                  </div>
                  <div style={{ flex:1,minWidth:0 }}>
                    <div style={{ display:'flex',alignItems:'center',gap:'6px',marginBottom:'4px',flexWrap:'wrap' }}>
                      <span style={{ fontWeight:'700',color:'#0f172a',fontSize: isMobBA ? '13px' : '15px' }}>{u.full_name||u.email}</span>
                      {isCurrentUser&&<span style={{ background:'#f0fdf4',color:'#059669',fontSize:'11px',fontWeight:'700',padding:'1px 8px',borderRadius:'999px',border:'1px solid #bbf7d0' }}>Deg</span>}
                      <span style={{ background:cfg.bg,color:cfg.color,border:`1px solid ${cfg.border}`,padding:'2px 8px',borderRadius:'999px',fontSize:'11px',fontWeight:'700' }}>{cfg.emoji} {cfg.label}</span>
                      {u.status==='inaktiv'&&<span style={{ background:'#fef2f2',color:'#dc2626',border:'1px solid #fecaca',padding:'2px 8px',borderRadius:'999px',fontSize:'11px',fontWeight:'700' }}>🔒 Inaktiv</span>}
                    </div>
                    <div style={{ display:'flex',gap: isMobBA ? '6px' : '12px',flexWrap:'wrap',fontSize: isMobBA ? '11px' : '12px',color:'#64748b' }}>
                      {!isMobBA && u.full_name&&<span>✉️ {u.email}</span>}
                      {!isMobBA && u.phone&&<span>📞 {u.phone}</span>}
                      <span>🔩 {modCount} moduler</span>
                      {!isMobBA && u.last_seen&&<span>🕐 {new Date(u.last_seen).toLocaleDateString('nb-NO')}</span>}
                    </div>
                  </div>
                  {!isMobBA && <span style={{ color:'#94a3b8',fontSize:'18px' }}>›</span>}
                </div>
              )
            })}
          </div>
        )}
      </div>

      {showInvite&&<InviterBrukerModal currentUser={user} companyModules={companyModules} onClose={()=>setShowInvite(false)} onSaved={()=>{setShowInvite(false);load()}} />}
    </div>
  )
}

// ── USER DETAIL PAGE ─────────────────────────────────────────────────────────
function UserDetaljer({ userProfile: init, currentUser, companyModules, onBack }) {
  const confirm = useConfirm()
  const [u, setU] = useState(init)
  const [saving, setSaving] = useState(false)
  const [tab, setTab] = useState('profil')
  const cfg = USER_ROLES[u.role]||USER_ROLES.ansatt
  const isCurrentUser = u.id===currentUser?.id
  const isSuperAdmin = u.role==='superadmin'

  const save = async (updates) => {
    setSaving(true)
    try {
      const { error } = await supabase.from('user_profiles').update({ ...updates, updated_at:new Date().toISOString() }).eq('id',u.id)
      if (error) throw error
      setU(v=>({...v,...updates}))
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  const toggleModule = async (modId) => {
    const current = u.module_access||[]
    const next = current.includes(modId) ? current.filter(m=>m!==modId) : [...current,modId]
    await save({ module_access: next })
  }

  const giveAllModules = () => save({ module_access: companyModules })
  const removeAllModules = () => save({ module_access: [] })

  const handleDeactivate = async () => {
    if (isCurrentUser) return alert('Du kan ikke deaktivere din egen bruker.')
    if (!(await confirm({ message: `${u.status==='aktiv'?'Deaktiver':'Aktiver'} bruker?`, subMessage: `${u.full_name||u.email} vil bli ${u.status==='aktiv'?'deaktivert':'aktivert'}.`, confirmLabel: u.status==='aktiv'?'Deaktiver':'Aktiver', danger: u.status==='aktiv' }))) return
    await save({ status: u.status==='aktiv'?'inaktiv':'aktiv' })
  }

  const handleDelete = async () => {
    if (isCurrentUser) return alert('Du kan ikke slette din egen bruker.')
    if (isSuperAdmin) return alert('Superadmin kan ikke slettes.')
    if (!(await confirm({ message: `Slett ${u.full_name||u.email}?`, subMessage: 'Brukeren slettes permanent og kan ikke gjenopprettes.', danger: true }))) return
    await supabase.from('user_profiles').delete().eq('id',u.id)
    onBack()
  }

  const activeCompanyModules = ALL_MODULES_LIST.filter(m=>companyModules.includes(m.id))
  const userModules = u.module_access||[]

  return (
    <div style={{ fontFamily:'system-ui,sans-serif', overflowX:'hidden', maxWidth:'100vw' }}>
      {/* Header */}
      <div style={{ background:'white',borderBottom:'1px solid #e2e8f0',padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '14px' : '20px 32px' }}>
        <button onClick={onBack} style={{ background:'none',border:'none',cursor:'pointer',color:'#64748b',fontSize:'13px',marginBottom:'10px',display:'flex',alignItems:'center',gap:'6px',padding:0 }}>← Tilbake</button>
        <div style={{ display:'flex',alignItems:'flex-start',justifyContent:'space-between',gap: typeof window !== 'undefined' && window.innerWidth < 768 ? '8px' : '16px', flexWrap: typeof window !== 'undefined' && window.innerWidth < 768 ? 'wrap' : 'nowrap' }}>
          <div style={{ display:'flex',alignItems:'flex-start',gap: typeof window !== 'undefined' && window.innerWidth < 768 ? '10px' : '14px', flex:1, minWidth:0 }}>
            {!(typeof window !== 'undefined' && window.innerWidth < 768) && <div style={{ width:'56px',height:'56px',borderRadius:'50%',background:cfg.bg,border:`2px solid ${cfg.border}`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:'22px',fontWeight:'800',color:cfg.color,flexShrink:0 }}>
              {(u.full_name?.[0]||u.email?.[0]||'?').toUpperCase()}
            </div>}
            <div style={{ minWidth:0 }}>
              <div style={{ display:'flex',alignItems:'center',gap:'6px',flexWrap:'wrap',marginBottom:'6px' }}>
                <h1 style={{ margin:0,fontSize: typeof window !== 'undefined' && window.innerWidth < 768 ? '16px' : '20px',fontWeight:'800',color:'#0f172a' }}>{u.full_name||u.email}</h1>
                {isCurrentUser&&<span style={{ background:'#f0fdf4',color:'#059669',fontSize:'11px',fontWeight:'700',padding:'2px 8px',borderRadius:'999px',border:'1px solid #bbf7d0' }}>Deg</span>}
                <span style={{ background:cfg.bg,color:cfg.color,border:`1px solid ${cfg.border}`,padding:'3px 10px',borderRadius:'999px',fontSize:'12px',fontWeight:'700' }}>{cfg.emoji} {cfg.label}</span>
                {u.status==='inaktiv'&&<span style={{ background:'#fef2f2',color:'#dc2626',border:'1px solid #fecaca',padding:'3px 10px',borderRadius:'999px',fontSize:'12px',fontWeight:'700' }}>🔒 Inaktiv</span>}
              </div>
              <div style={{ fontSize:'13px',color:'#64748b' }}>{u.email}{u.phone?` · ${u.phone}`:''}</div>
            </div>
          </div>
          {!isCurrentUser&&!isSuperAdmin&&(
            <div style={{ display:'flex',gap:'8px',flexShrink:0 }}>
              <button onClick={handleDeactivate}
                style={{ padding:'9px 14px',border:`1px solid ${u.status==='aktiv'?'#fde68a':'#bbf7d0'}`,borderRadius:'10px',background:'white',cursor:'pointer',fontSize:'13px',fontWeight:'600',color:u.status==='aktiv'?'#d97706':'#059669' }}>
                {u.status==='aktiv'?'🔒 Deaktiver':'✅ Aktiver'}
              </button>
              <button onClick={handleDelete} style={{ padding:'9px 12px',border:'1px solid #fecaca',borderRadius:'10px',background:'white',cursor:'pointer',color:'#dc2626',fontSize:'13px' }}>🗑️</button>
            </div>
          )}
        </div>
        <div style={{ display:'flex',gap:'4px',marginTop: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '16px', overflowX:'auto', WebkitOverflowScrolling:'touch' }}>
          {[['profil','👤 Profil'],['rolle','🔑 Rolle'],['moduler', typeof window !== 'undefined' && window.innerWidth < 768 ? '🔩 Moduler' : '🔩 Modultilgang']].map(([id,l])=>(
            <button key={id} onClick={()=>setTab(id)} style={{ padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '7px 12px' : '8px 16px',borderRadius:'10px',border:'none',background:tab===id?'#059669':'#f8fafc',color:tab===id?'white':'#64748b',fontWeight:tab===id?'700':'500',fontSize: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '13px',cursor:'pointer',whiteSpace:'nowrap' }}>{l}</button>
          ))}
        </div>
      </div>

      <div style={{ padding: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '24px 32px',display:'grid',gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '2fr 1fr',gap: typeof window !== 'undefined' && window.innerWidth < 768 ? '12px' : '20px' }}>
        <div style={{ display:'flex',flexDirection:'column',gap:'16px' }}>

          {/* PROFIL TAB */}
          {tab==='profil'&&(
            <div style={{ background:'white',borderRadius:'16px',border:'1px solid #f1f5f9',padding:'20px 24px' }}>
              <h3 style={{ margin:'0 0 16px',fontSize:'14px',fontWeight:'700',color:'#0f172a' }}>👤 Profilinformasjon</h3>
              <div style={{ display:'grid',gridTemplateColumns: typeof window !== 'undefined' && window.innerWidth < 768 ? '1fr' : '1fr 1fr',gap:'12px' }}>
                <div><label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'5px' }}>Fullt navn</label>
                  <input defaultValue={u.full_name||''} onBlur={e=>save({full_name:e.target.value})} style={baInp} placeholder="For- og etternavn" /></div>
                <div><label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'5px' }}>Telefon</label>
                  <input defaultValue={u.phone||''} onBlur={e=>save({phone:e.target.value})} style={baInp} placeholder="+47 xxx xx xxx" /></div>
                <div style={{ gridColumn:'1/-1' }}><label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'5px' }}>E-post</label>
                  <input value={u.email||''} readOnly style={{ ...baInp,background:'#f8fafc',color:'#94a3b8' }} /></div>
              </div>
            </div>
          )}

          {/* ROLLE TAB */}
          {tab==='rolle'&&(
            <div style={{ background:'white',borderRadius:'16px',border:'1px solid #f1f5f9',padding:'20px 24px' }}>
              <h3 style={{ margin:'0 0 16px',fontSize:'14px',fontWeight:'700',color:'#0f172a' }}>🔑 Tilgangsrolle</h3>
              {isSuperAdmin ? (
                <div style={{ background:'#f5f3ff',borderRadius:'12px',padding:'16px',border:'1px solid #ddd6fe' }}>
                  <div style={{ fontSize:'14px',fontWeight:'700',color:'#7c3aed' }}>👑 Superadmin</div>
                  <div style={{ fontSize:'13px',color:'#6d28d9',marginTop:'4px' }}>Superadmin-rollen kan ikke endres. Eieren av kontoen har alltid full tilgang til alt.</div>
                </div>
              ) : (
                <div style={{ display:'flex',flexDirection:'column',gap:'10px' }}>
                  {Object.entries(USER_ROLES).filter(([k])=>k!=='superadmin').map(([key,cfg])=>(
                    <button key={key} onClick={()=>save({role:key})} disabled={isCurrentUser}
                      style={{ display:'flex',alignItems:'center',gap:'14px',padding:'14px 16px',borderRadius:'12px',border:`2px solid ${u.role===key?cfg.border:'#f1f5f9'}`,background:u.role===key?cfg.bg:'white',cursor:isCurrentUser?'default':'pointer',textAlign:'left',transition:'all 0.15s' }}>
                      <div style={{ width:'40px',height:'40px',borderRadius:'10px',background:u.role===key?'white':cfg.bg,display:'flex',alignItems:'center',justifyContent:'center',fontSize:'20px',flexShrink:0 }}>{cfg.emoji}</div>
                      <div style={{ flex:1 }}>
                        <div style={{ fontWeight:'700',fontSize:'14px',color:u.role===key?cfg.color:'#0f172a' }}>{cfg.label}</div>
                        <div style={{ fontSize:'12px',color:'#64748b',marginTop:'2px' }}>{cfg.desc}</div>
                      </div>
                      {u.role===key&&<span style={{ fontSize:'18px',color:cfg.color }}>✓</span>}
                    </button>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* MODULER TAB */}
          {tab==='moduler'&&(
            <div style={{ background:'white',borderRadius:'16px',border:'1px solid #f1f5f9',padding:'20px 24px' }}>
              <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'16px' }}>
                <h3 style={{ margin:0,fontSize:'14px',fontWeight:'700',color:'#0f172a' }}>🔩 Modultilgang</h3>
                <div style={{ display:'flex',gap:'6px' }}>
                  <button onClick={giveAllModules} style={{ padding:'6px 12px',background:'#f0fdf4',color:'#059669',border:'1px solid #bbf7d0',borderRadius:'8px',cursor:'pointer',fontSize:'12px',fontWeight:'600' }}>Alle moduler</button>
                  <button onClick={removeAllModules} style={{ padding:'6px 12px',background:'#fef2f2',color:'#dc2626',border:'1px solid #fecaca',borderRadius:'8px',cursor:'pointer',fontSize:'12px',fontWeight:'600' }}>Ingen tilgang</button>
                </div>
              </div>
              {activeCompanyModules.length===0 ? (
                <p style={{ color:'#94a3b8',fontSize:'13px',fontStyle:'italic' }}>Bedriften har ikke aktivert noen tilleggsmoduler i «Min bedrift».</p>
              ) : (
                <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:'8px' }}>
                  {activeCompanyModules.map(mod=>{
                    const hasAccess=userModules.includes(mod.id)
                    return (
                      <button key={mod.id} onClick={()=>toggleModule(mod.id)}
                        style={{ display:'flex',alignItems:'center',gap:'10px',padding:'10px 14px',borderRadius:'10px',border:`2px solid ${hasAccess?'#059669':'#e2e8f0'}`,background:hasAccess?'#f0fdf4':'white',cursor:'pointer',textAlign:'left',transition:'all 0.15s' }}>
                        <span style={{ fontSize:'18px' }}>{mod.emoji}</span>
                        <span style={{ flex:1,fontSize:'13px',fontWeight:'600',color:hasAccess?'#059669':'#475569' }}>{mod.label}</span>
                        <span style={{ fontSize:'16px',color:hasAccess?'#059669':'#cbd5e1' }}>{hasAccess?'✓':'○'}</span>
                      </button>
                    )
                  })}
                </div>
              )}
              <div style={{ marginTop:'14px',background:'#eff6ff',borderRadius:'10px',padding:'10px 14px',border:'1px solid #bfdbfe',fontSize:'12px',color:'#2563eb' }}>
                ℹ️ Brukeren har tilgang til {userModules.length} av {activeCompanyModules.length} aktive moduler i bedriften.
              </div>
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div style={{ display:'flex',flexDirection:'column',gap:'14px' }}>
          <div style={{ background:'white',borderRadius:'14px',border:'1px solid #f1f5f9',padding:'18px 20px' }}>
            <h3 style={{ margin:'0 0 12px',fontSize:'13px',fontWeight:'700',color:'#0f172a' }}>📊 Oppsummering</h3>
            {[['Rolle',`${cfg.emoji} ${cfg.label}`],['Status',u.status==='aktiv'?'✅ Aktiv':'🔒 Inaktiv'],['Moduler',`${userModules.length} stk`],['Opprettet',new Date(u.created_at).toLocaleDateString('nb-NO')]].map(([k,v])=>(
              <div key={k} style={{ display:'flex',justifyContent:'space-between',padding:'6px 0',borderBottom:'1px solid #f8fafc',fontSize:'13px' }}>
                <span style={{ color:'#94a3b8' }}>{k}</span>
                <span style={{ fontWeight:'600',color:'#0f172a' }}>{v}</span>
              </div>
            ))}
          </div>
          <div style={{ background:'white',borderRadius:'14px',border:'1px solid #f1f5f9',padding:'18px 20px' }}>
            <h3 style={{ margin:'0 0 10px',fontSize:'13px',fontWeight:'700',color:'#0f172a' }}>🔩 Aktive moduler</h3>
            <div style={{ display:'flex',flexWrap:'wrap',gap:'5px' }}>
              {userModules.length===0 ? <span style={{ fontSize:'12px',color:'#94a3b8',fontStyle:'italic' }}>Ingen moduler</span>
                : ALL_MODULES_LIST.filter(m=>userModules.includes(m.id)).map(m=>(
                  <span key={m.id} style={{ background:'#f0fdf4',color:'#059669',border:'1px solid #bbf7d0',fontSize:'11px',fontWeight:'600',padding:'2px 8px',borderRadius:'999px' }}>{m.emoji} {m.label}</span>
                ))
              }
            </div>
          </div>
          {saving&&<div style={{ background:'#fffbeb',borderRadius:'10px',padding:'10px 14px',border:'1px solid #fde68a',fontSize:'13px',color:'#92400e',fontWeight:'600',textAlign:'center' }}>Lagrer endringer...</div>}
        </div>
      </div>
    </div>
  )
}

// ── INVITER BRUKER MODAL ─────────────────────────────────────────────────────
function InviterBrukerModal({ currentUser, companyModules, onClose, onSaved }) {
  const [form, setForm] = useState({ email:'', role:'ansatt', full_name:'' })
  const [selectedModules, setSelectedModules] = useState([])
  const [step, setStep] = useState(1)
  const [saving, setSaving] = useState(false)
  const [sent, setSent] = useState(false)
  const set=(k,v)=>setForm(f=>({...f,[k]:v}))

  const activeCompanyModules = ALL_MODULES_LIST.filter(m=>companyModules.includes(m.id))
  const toggleMod = (id) => setSelectedModules(s=>s.includes(id)?s.filter(x=>x!==id):[...s,id])

  // Preset modules based on role
  const applyRolePreset = (role) => {
    set('role',role)
    if (role==='admin') setSelectedModules(companyModules)
    else if (role==='les') setSelectedModules([])
    // others: keep current selection
  }

  const handleSend = async () => {
    if (!form.email.trim()) return alert('E-post er påkrevd')
    setSaving(true)
    try {
      // Check if already exists
      const { data: existing } = await supabase.from('user_invitations').select('id').eq('email',form.email.trim()).single()
      if (existing) {
        await supabase.from('user_invitations').delete().eq('email',form.email.trim())
      }

      const { data: inv, error } = await supabase.from('user_invitations').insert({
        email: form.email.trim(),
        role: form.role,
        module_access: selectedModules,
        invited_by: currentUser?.id
      }).select().single()
      if (error) throw error

      // Send invite email via Edge Function
      const inviteUrl = `${window.location.origin}?invite=${inv.token}`
      const roleCfg = USER_ROLES[form.role]||USER_ROLES.ansatt
      const html = `
        <div style="font-family:system-ui,sans-serif;max-width:560px;margin:0 auto;padding:32px 20px">
          <div style="text-align:center;margin-bottom:28px">
            <div style="width:60px;height:60px;background:#059669;border-radius:16px;display:flex;align-items:center;justify-content:center;margin:0 auto 12px;font-size:28px">🏢</div>
            <h1 style="color:#0f172a;font-size:22px;margin:0">Du er invitert til En Plattform</h1>
          </div>
          <div style="background:#f8fafc;border-radius:12px;padding:20px;margin-bottom:20px">
            <p style="margin:0 0 8px;font-size:14px;color:#475569">Du er invitert med rolle:</p>
            <div style="font-size:18px;font-weight:700;color:#0f172a">${roleCfg.emoji} ${roleCfg.label}</div>
            ${selectedModules.length>0?`<p style="margin:12px 0 6px;font-size:13px;color:#64748b">Du får tilgang til ${selectedModules.length} moduler.</p>`:''}
          </div>
          <div style="text-align:center;margin:28px 0">
            <a href="${inviteUrl}" style="background:#059669;color:white;padding:16px 32px;border-radius:12px;text-decoration:none;font-weight:700;font-size:16px;display:inline-block">
              ✅ Aksepter invitasjon
            </a>
          </div>
          <p style="color:#94a3b8;font-size:12px;text-align:center">Lenken er gyldig i 7 dager · Sendt via En Plattform KS-system</p>
        </div>`

      await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/send-quote`, {
        method:'POST',
        headers:{ 'Content-Type':'application/json', 'apikey':import.meta.env.VITE_SUPABASE_ANON_KEY, 'Authorization':`Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}` },
        body: JSON.stringify({ to:form.email.trim(), subject:'Du er invitert til En Plattform KS-system', html })
      })

      setSent(true)
      setTimeout(()=>onSaved(), 2000)
    } catch(e) { alert('Feil: '+e.message) }
    finally { setSaving(false) }
  }

  return (
    <div style={{ position:'fixed',inset:0,zIndex:100,display:'flex',alignItems:'center',justifyContent:'center',padding:'16px' }}>
      <div style={{ position:'absolute',inset:0,background:'rgba(0,0,0,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative',background:'white',borderRadius:'20px',width:'100%',maxWidth:'560px',maxHeight:'90vh',display:'flex',flexDirection:'column',boxShadow:'0 20px 60px rgba(0,0,0,0.2)',fontFamily:'system-ui,sans-serif' }}>
        <div style={{ padding:'18px 24px',borderBottom:'1px solid #f1f5f9',display:'flex',justifyContent:'space-between',alignItems:'center',flexShrink:0 }}>
          <div>
            <h2 style={{ margin:'0 0 4px',fontSize:'18px',fontWeight:'700',color:'#0f172a' }}>+ Inviter ny bruker</h2>
            <div style={{ display:'flex',gap:'6px' }}>
              {['E-post og info','Rolle','Modultilgang'].map((l,i)=>(
                <div key={i} style={{ display:'flex',alignItems:'center',gap:'4px' }}>
                  <div style={{ width:'18px',height:'18px',borderRadius:'50%',background:step>i?'#059669':step===i+1?'#059669':'#e2e8f0',color:'white',fontSize:'10px',fontWeight:'800',display:'flex',alignItems:'center',justifyContent:'center' }}>{i+1}</div>
                  <span style={{ fontSize:'11px',color:step===i+1?'#059669':'#94a3b8',fontWeight:step===i+1?'700':'400' }}>{l}</span>
                  {i<2&&<span style={{ color:'#e2e8f0',fontSize:'11px' }}>›</span>}
                </div>
              ))}
            </div>
          </div>
          <button onClick={onClose} style={{ background:'none',border:'none',fontSize:'22px',cursor:'pointer',color:'#94a3b8' }}>×</button>
        </div>

        <div style={{ overflowY:'auto',flex:1,padding:'20px 24px' }}>
          {sent ? (
            <div style={{ textAlign:'center',padding:'20px' }}>
              <div style={{ fontSize:'56px',marginBottom:'12px' }}>✅</div>
              <h3 style={{ margin:'0 0 8px',fontSize:'18px',color:'#0f172a' }}>Invitasjon sendt!</h3>
              <p style={{ margin:0,color:'#64748b',fontSize:'14px' }}>{form.email} mottar e-post med invitasjonslenke.</p>
            </div>
          ) : step===1 ? (
            <div style={{ display:'flex',flexDirection:'column',gap:'14px' }}>
              <div><label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'6px' }}>E-postadresse *</label>
                <input type="email" value={form.email} onChange={e=>set('email',e.target.value)} placeholder="bruker@bedrift.no" style={baInp} /></div>
              <div><label style={{ display:'block',fontSize:'13px',fontWeight:'600',color:'#374151',marginBottom:'6px' }}>Fullt navn (valgfritt)</label>
                <input value={form.full_name} onChange={e=>set('full_name',e.target.value)} placeholder="For- og etternavn" style={baInp} /></div>
              <div style={{ background:'#f8fafc',borderRadius:'10px',padding:'14px',border:'1px solid #f1f5f9',fontSize:'13px',color:'#475569' }}>
                📧 Brukeren mottar en e-post med en invitasjonslenke som er gyldig i 7 dager.
              </div>
            </div>
          ) : step===2 ? (
            <div style={{ display:'flex',flexDirection:'column',gap:'10px' }}>
              <p style={{ margin:'0 0 8px',fontSize:'13px',color:'#64748b' }}>Velg rolle for brukeren. Rollen kan endres senere.</p>
              {Object.entries(USER_ROLES).filter(([k])=>k!=='superadmin').map(([key,cfg])=>(
                <button key={key} onClick={()=>applyRolePreset(key)}
                  style={{ display:'flex',alignItems:'center',gap:'14px',padding:'14px 16px',borderRadius:'12px',border:`2px solid ${form.role===key?cfg.border:'#f1f5f9'}`,background:form.role===key?cfg.bg:'white',cursor:'pointer',textAlign:'left' }}>
                  <div style={{ width:'40px',height:'40px',borderRadius:'10px',background:form.role===key?'white':cfg.bg,display:'flex',alignItems:'center',justifyContent:'center',fontSize:'20px',flexShrink:0 }}>{cfg.emoji}</div>
                  <div style={{ flex:1 }}>
                    <div style={{ fontWeight:'700',fontSize:'14px',color:form.role===key?cfg.color:'#0f172a' }}>{cfg.label}</div>
                    <div style={{ fontSize:'12px',color:'#64748b',marginTop:'2px' }}>{cfg.desc}</div>
                  </div>
                  {form.role===key&&<span style={{ fontSize:'18px',color:cfg.color }}>✓</span>}
                </button>
              ))}
            </div>
          ) : (
            <div style={{ display:'flex',flexDirection:'column',gap:'10px' }}>
              <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'4px' }}>
                <p style={{ margin:0,fontSize:'13px',color:'#64748b' }}>Velg hvilke moduler brukeren skal ha tilgang til.</p>
                <div style={{ display:'flex',gap:'6px' }}>
                  <button onClick={()=>setSelectedModules(companyModules)} style={{ padding:'5px 10px',background:'#f0fdf4',color:'#059669',border:'1px solid #bbf7d0',borderRadius:'6px',cursor:'pointer',fontSize:'11px',fontWeight:'600' }}>Alle</button>
                  <button onClick={()=>setSelectedModules([])} style={{ padding:'5px 10px',background:'#fef2f2',color:'#dc2626',border:'1px solid #fecaca',borderRadius:'6px',cursor:'pointer',fontSize:'11px',fontWeight:'600' }}>Ingen</button>
                </div>
              </div>
              {activeCompanyModules.length===0 ? (
                <p style={{ color:'#94a3b8',fontSize:'13px',fontStyle:'italic' }}>Bedriften har ikke aktivert tilleggsmoduler ennå.</p>
              ) : (
                <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:'8px' }}>
                  {activeCompanyModules.map(mod=>{
                    const has=selectedModules.includes(mod.id)
                    return (
                      <button key={mod.id} onClick={()=>toggleMod(mod.id)}
                        style={{ display:'flex',alignItems:'center',gap:'8px',padding:'10px 12px',borderRadius:'10px',border:`2px solid ${has?'#059669':'#e2e8f0'}`,background:has?'#f0fdf4':'white',cursor:'pointer',textAlign:'left' }}>
                        <span style={{ fontSize:'16px' }}>{mod.emoji}</span>
                        <span style={{ flex:1,fontSize:'12px',fontWeight:'600',color:has?'#059669':'#475569' }}>{mod.label}</span>
                        <span style={{ fontSize:'14px',color:has?'#059669':'#cbd5e1' }}>{has?'✓':'○'}</span>
                      </button>
                    )
                  })}
                </div>
              )}
            </div>
          )}
        </div>

        {!sent&&(
          <div style={{ padding:'16px 24px',borderTop:'1px solid #f1f5f9',display:'flex',justifyContent:'space-between',flexShrink:0 }}>
            <div>{step>1&&<button onClick={()=>setStep(s=>s-1)} style={{ padding:'10px 18px',border:'1px solid #e2e8f0',borderRadius:'10px',background:'white',cursor:'pointer',fontSize:'14px',fontWeight:'600',color:'#374151' }}>← Tilbake</button>}</div>
            <div style={{ display:'flex',gap:'10px' }}>
              <button onClick={onClose} style={{ padding:'10px 20px',border:'1px solid #e2e8f0',borderRadius:'10px',background:'white',cursor:'pointer',fontSize:'14px',fontWeight:'600',color:'#374151' }}>Avbryt</button>
              {step<3&&<button onClick={()=>{ if(step===1&&!form.email.trim()) return alert('E-post er påkrevd'); setStep(s=>s+1) }} style={{ padding:'10px 24px',background:'#059669',color:'white',border:'none',borderRadius:'10px',cursor:'pointer',fontSize:'14px',fontWeight:'700' }}>Neste →</button>}
              {step===3&&<button onClick={handleSend} disabled={saving} style={{ padding:'10px 24px',background:saving?'#6ee7b7':'#059669',color:'white',border:'none',borderRadius:'10px',cursor:saving?'not-allowed':'pointer',fontSize:'14px',fontWeight:'700' }}>{saving?'Sender...':'📧 Send invitasjon'}</button>}
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

// ─── END BRUKERADMIN MODULE ───────────────────────────────────────────────────


// ─── VARSLER PAGE ─────────────────────────────────────────────────────────────

function VarslerPage({ onNavigate }) {
  const confirm = useConfirm()
  const { notifs, unread, markRead, markAllRead, load } = useNotif()
  const [filter, setFilter] = useState('alle')
  const { user } = useAuth()

  const typeIcon = (type) => ({ info:'ℹ️', success:'✅', warning:'⚠️', quote:'📋', error:'❌' }[type] || 'ℹ️')
  const typeName = (type) => ({ info:'Info', success:'Fullført', warning:'Advarsel', quote:'Tilbud', error:'Feil' }[type] || 'Info')

  const filtered = notifs.filter(n => {
    if (filter === 'ulest') return !n.read
    if (filter !== 'alle') return n.type === filter
    return true
  })

  const deleteNotif = async (id, e) => {
    e.stopPropagation()
    await supabase.from('notifications').delete().eq('id', id)
    load()
  }

  const deleteAll = async () => {
    if (!(await confirm({ message: 'Slett alle varsler?', subMessage: 'Alle varsler slettes permanent.', danger: true }))) return
    await supabase.from('notifications').delete().eq('user_id', user?.id)
    load()
  }

  const groupByDate = (items) => {
    const groups = {}
    items.forEach(n => {
      const d = new Date(n.created_at)
      const today = new Date()
      const yesterday = new Date(today); yesterday.setDate(yesterday.getDate()-1)
      let key
      if (d.toDateString()===today.toDateString()) key='I dag'
      else if (d.toDateString()===yesterday.toDateString()) key='I går'
      else key = d.toLocaleDateString('nb-NO',{weekday:'long',day:'numeric',month:'long'})
      if (!groups[key]) groups[key]=[]
      groups[key].push(n)
    })
    return groups
  }

  const grouped = groupByDate(filtered)

  return (
    <div style={{ fontFamily:'system-ui,sans-serif' }}>
      <div style={{ background:'white', borderBottom:'1px solid #e2e8f0', padding:'20px 32px' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'16px' }}>
          <div>
            <h1 style={{ fontSize:'22px', fontWeight:'bold', color:'#0f172a', margin:0 }}>🔔 Varsler</h1>
            <p style={{ color:'#64748b', marginTop:'4px', fontSize:'14px', marginBottom:0 }}>
              {unread > 0 ? `${unread} uleste varsler` : 'Alle varsler er lest'}
            </p>
          </div>
          <div style={{ display:'flex', gap:'8px' }}>
            {unread > 0 && (
              <button onClick={markAllRead}
                style={{ padding:'9px 16px', border:'1px solid #bbf7d0', borderRadius:'10px', background:'#f0fdf4', color:'#059669', cursor:'pointer', fontSize:'13px', fontWeight:'600' }}>
                ✓ Merk alle lest
              </button>
            )}
            {notifs.length > 0 && (
              <button onClick={deleteAll}
                style={{ padding:'9px 14px', border:'1px solid #fecaca', borderRadius:'10px', background:'white', color:'#dc2626', cursor:'pointer', fontSize:'13px', fontWeight:'600' }}>
                🗑️ Slett alle
              </button>
            )}
          </div>
        </div>
        {/* Filter tabs */}
        <div style={{ display:'flex', gap:'4px', flexWrap:'wrap' }}>
          {[
            ['alle','📋 Alle', notifs.length],
            ['ulest','🔵 Ulest', unread],
            ['success','✅ Fullført', notifs.filter(n=>n.type==='success').length],
            ['warning','⚠️ Advarsel', notifs.filter(n=>n.type==='warning').length],
            ['info','ℹ️ Info', notifs.filter(n=>n.type==='info').length],
          ].map(([id, label, count]) => (
            <button key={id} onClick={() => setFilter(id)}
              style={{ padding:'7px 14px', borderRadius:'10px', border:'none', background:filter===id?'#059669':'#f8fafc', color:filter===id?'white':'#64748b', fontWeight:filter===id?'700':'500', fontSize:'13px', cursor:'pointer', display:'flex', alignItems:'center', gap:'5px' }}>
              {label}
              {count > 0 && <span style={{ background:filter===id?'rgba(255,255,255,0.3)':'#e2e8f0', color:filter===id?'white':'#475569', fontSize:'11px', fontWeight:'700', padding:'1px 6px', borderRadius:'999px' }}>{count}</span>}
            </button>
          ))}
        </div>
      </div>

      <div style={{ padding:'20px 32px', maxWidth:'760px' }}>
        {filtered.length === 0 ? (
          <div style={{ background:'white', borderRadius:'16px', border:'1px solid #f1f5f9', padding:'60px 20px', textAlign:'center' }}>
            <div style={{ fontSize:'48px', marginBottom:'12px' }}>🔔</div>
            <h3 style={{ margin:'0 0 6px', color:'#0f172a' }}>{filter==='ulest'?'Ingen uleste varsler':'Ingen varsler'}</h3>
            <p style={{ margin:0, color:'#94a3b8', fontSize:'14px' }}>
              {filter==='ulest' ? 'Du er helt oppdatert!' : 'Varsler fra systemet vises her automatisk.'}
            </p>
          </div>
        ) : (
          <div style={{ display:'flex', flexDirection:'column', gap:'24px' }}>
            {Object.entries(grouped).map(([date, items]) => (
              <div key={date}>
                <div style={{ fontSize:'12px', fontWeight:'700', color:'#94a3b8', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:'10px', display:'flex', alignItems:'center', gap:'8px' }}>
                  {date}
                  <div style={{ flex:1, height:'1px', background:'#f1f5f9' }} />
                </div>
                <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
                  {items.map(n => (
                    <div key={n.id}
                      onClick={() => {
                        markRead(n.id)
                        if (n.link_page && onNavigate) onNavigate(n.link_page)
                      }}
                      style={{ background:n.read?'white':'#f0fdf4', borderRadius:'12px', border:`1px solid ${n.read?'#f1f5f9':'#bbf7d0'}`, padding:'14px 16px', cursor:'pointer', display:'flex', alignItems:'flex-start', gap:'12px', transition:'background 0.15s' }}
                      onMouseEnter={e=>{ if(n.read) e.currentTarget.style.background='#f8fafc' }}
                      onMouseLeave={e=>{ e.currentTarget.style.background=n.read?'white':'#f0fdf4' }}>
                      <div style={{ width:'36px', height:'36px', borderRadius:'10px', background:n.read?'#f8fafc':'white', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'18px', flexShrink:0, border:`1px solid ${n.read?'#f1f5f9':'#bbf7d0'}` }}>
                        {typeIcon(n.type)}
                      </div>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'3px', flexWrap:'wrap' }}>
                          <span style={{ fontWeight:n.read?'600':'800', fontSize:'14px', color:'#0f172a' }}>{n.title}</span>
                          {!n.read && <span style={{ width:'7px', height:'7px', borderRadius:'50%', background:'#059669', flexShrink:0, display:'inline-block' }} />}
                        </div>
                        {n.message && <div style={{ fontSize:'13px', color:'#64748b', lineHeight:1.5, marginBottom:'4px' }}>{n.message}</div>}
                        <div style={{ fontSize:'11px', color:'#cbd5e1' }}>
                          {new Date(n.created_at).toLocaleTimeString('nb-NO',{hour:'2-digit',minute:'2-digit'})}
                          {' · '}
                          <span style={{ color:'#94a3b8' }}>{typeName(n.type)}</span>
                          {n.link_page && (
                            <>
                              {' · '}
                              <span style={{ color:'#2563eb', fontWeight:'600' }}>Klikk for å åpne →</span>
                            </>
                          )}
                        </div>
                      </div>
                      <button onClick={(e) => deleteNotif(n.id, e)}
                        style={{ background:'none', border:'none', cursor:'pointer', color:'#cbd5e1', fontSize:'16px', padding:'2px', flexShrink:0, lineHeight:1 }}
                        onMouseEnter={e=>e.currentTarget.style.color='#dc2626'}
                        onMouseLeave={e=>e.currentTarget.style.color='#cbd5e1'}>×</button>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

// ─── END VARSLER PAGE ─────────────────────────────────────────────────────────

// ─── LOCKED MODULE UPSELL PAGE ───────────────────────────────────────────────
function LockedModulePage({ pageId, onNavigate }) {
  const navItem = navItems.find(n => n?.id === pageId)
  const modDef = MODULE_CATALOG.find(m => m.navId === pageId || m.id === pageId)
  const emoji = navItem?.emoji || modDef?.emoji || '🔒'
  const label = navItem?.label || modDef?.name || pageId
  const desc = modDef?.desc || ''
  const price = modDef?.price || modDef?.pricePerUser || 0

  // Features preview for common modules
  const featurePreviews = {
    kalkulator: ['Kostnadskalkulasjon med kapitler og poster', 'Automatisk påslag og fortjenesteberegning', 'Generer tilbud direkte fra kalkulasjon', 'Maler for rask gjenbruk', 'Budsjett vs. faktisk oppfølging', 'Rapporter og statistikk'],
    tilbud: ['Profesjonelle tilbud med PDF-generering', 'Send tilbud direkte til kunder', 'Kundeportal med digital godkjenning', 'Tilbudshistorikk og statusoppfølging'],
    faktura: ['Fakturering med EHF-støtte', 'Automatisk purring', 'Betalingsoversikt', 'Integrasjon med regnskap'],
    timelister: ['Timeføring per prosjekt', 'Godkjenningsflyt', 'Overtidsberegning', 'Eksport til lønnssystem'],
    ansatte: ['Personalregister', 'Kompetanseoversikt', 'Sertifikat-varsler', 'Organisasjonskart'],
    crm: ['Salgspipeline', 'Kundeoppfølging', 'Aktivitetslogg', 'Rapport og innsikt'],
  }
  const features = featurePreviews[pageId] || [desc]

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', minHeight: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '32px' }}>
      <div style={{ maxWidth: '560px', width: '100%', textAlign: 'center' }}>
        {/* Lock icon */}
        <div style={{ width: '80px', height: '80px', borderRadius: '24px', background: 'linear-gradient(135deg, #f8fafc, #e2e8f0)', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 24px', fontSize: '36px' }}>
          🔒
        </div>

        <h1 style={{ fontSize: '26px', fontWeight: '800', color: '#0f172a', margin: '0 0 8px' }}>{emoji} {label}</h1>
        <p style={{ color: '#64748b', fontSize: '15px', margin: '0 0 32px', lineHeight: 1.6 }}>
          Denne modulen er ikke inkludert i ditt nåværende abonnement. Aktiver den for å få tilgang til alle funksjonene.
        </p>

        {/* Feature list */}
        <div style={{ background: 'white', borderRadius: '16px', border: '1px solid #f1f5f9', padding: '24px', textAlign: 'left', marginBottom: '24px', boxShadow: '0 2px 12px rgba(0,0,0,0.04)' }}>
          <div style={{ fontSize: '13px', fontWeight: '700', color: '#0f172a', marginBottom: '16px', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Hva du får tilgang til:</div>
          {features.map((f, i) => (
            <div key={i} style={{ display: 'flex', alignItems: 'flex-start', gap: '10px', marginBottom: '12px' }}>
              <span style={{ color: '#059669', fontSize: '16px', flexShrink: 0, marginTop: '1px' }}>✓</span>
              <span style={{ color: '#374151', fontSize: '14px', lineHeight: 1.5 }}>{f}</span>
            </div>
          ))}
        </div>

        {/* Price */}
        {price > 0 && (
          <div style={{ background: 'linear-gradient(135deg, #059669, #0891b2)', borderRadius: '16px', padding: '20px 28px', color: 'white', marginBottom: '20px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <div style={{ textAlign: 'left' }}>
              <div style={{ fontSize: '13px', opacity: 0.9 }}>Fra kun</div>
              <div style={{ fontSize: '28px', fontWeight: '800' }}>{price} kr<span style={{ fontSize: '14px', fontWeight: '400', opacity: 0.8 }}>/mnd</span></div>
            </div>
            <div style={{ fontSize: '12px', opacity: 0.85, textAlign: 'right', lineHeight: 1.6 }}>Ubegrenset<br/>brukere</div>
          </div>
        )}

        {/* CTA */}
        <button onClick={() => onNavigate('minbedrift')}
          style={{ background: '#059669', color: 'white', border: 'none', borderRadius: '12px', padding: '14px 32px', fontSize: '15px', fontWeight: '700', cursor: 'pointer', width: '100%', marginBottom: '12px', boxShadow: '0 4px 14px rgba(5,150,105,0.3)' }}>
          Aktiver {label} →
        </button>
        <button onClick={() => onNavigate('dashboard')}
          style={{ background: 'transparent', color: '#64748b', border: 'none', fontSize: '13px', cursor: 'pointer', padding: '8px' }}>
          ← Tilbake til dashboard
        </button>
      </div>
    </div>
  )
}

